-- Row 3: Marta Magalhães
INSERT IGNORE INTO users (id, email, password, role) VALUES ('367e57b5-3ce7-44b9-b926-c1128f377c9d', 'wix-367e57b5@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('28fbbd28-2f76-47d8-916e-e44bf452c0c8', '367e57b5-3ce7-44b9-b926-c1128f377c9d', 'marta-magalhaes', 'Marta Magalhães', 'Marta', '931713746', '1995-06-20', 'Portugal', 'Portugal', 'Carregosa - Oliveira de Azeméis', 'Rua Padre Joaquim Aguiar nº 626, 3720-012 Carregosa', 'Rua Padre Joaquim Aguiar nº 626, 3720-012 Carregosa', '3720-012', 'Mezzo-Soprano', '"O canto é o espelho da alma"', 'https://static.wixstatic.com/media/367e57_0cc8ce3cfe0a46408bddd86275c0dd73~mv2.jpg', 'wix:document://v1/367e57_b8bd63a305a045ca9a30ee874a0ad448.pdf/curriculo%20completo.pdf', 'https://www.facebook.com/marta.magalhaes.58118', NULL, NULL, NULL, 'https://www.youtube.com/@martamagalhaes6223', 'https://static.wixstatic.com/mp3/367e57_8d4cdf8e91a64fe4bd779f2ff2eea3de.mp3', NULL, NULL, 'https://youtu.be/h5O3laFPIg0?si=yCfRqJN2O5sm_z_N', 'https://youtu.be/Zfazkqzrb30?si=yvdxqA2IrCLUaSkX', 'https://youtu.be/rM3TLOurALY?si=LBzqeyFTxW4-Syua', 'https://youtu.be/7VOFQzINwXM?si=hkQTGbqjbOw4je28', NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8">Iniciou os seus estudos aos 7 anos, na Escola da Banda de Música de Carregosa, com o instrumento trompete. É licenciada em canto, mestrado em ensino da música e mestrado em música (performance) especialização em canto, pela Escola Superior de Artes Aplicadas de Castelo Branco, com as professoras Elisabete Matos e Dora Rodrigues. Trabalhou com os professores: Ângela Alves, Palmira Troufa, Isabel Alcobia, Saioa Hernández, Francesco Pio Galasso, Enza Ferrari, Christian Hills, Susanne Rydén, Marina Bartoli, Bárbara Barradas, Cátia Moreso e Roberta Invernezzi. Foi bolseira para o curso de verão ABA 2018 (Austria Barock Akademie). Foi premiada com uma bolsa de jovem talento para o ABA 2019 e ainda uma bolsa para um concerto em Viena, no curso ABA 2019. Atualmente trabalha regularmente com a soprano Elisabete Matos e com o repertorista Cristóvão Luíz.</p>
<p class="font_8"><br></p>
<p class="font_8">Como solista interpretou <em>Missa em Ré Maior</em> de A. Dvorak, <em>Glória em Ré Maior</em> de A. Vivaldi, <em>Dorabella</em> da ópera <em>Così fan tutte</em> de W. A. Mozart, <em>Volpino</em> em <em>Lo Speziale</em> de J. Haydn (<em>A persistência dos sintomas</em>), <em>Requiem em Ré menor</em> de W. A. Mozart, <em>Qual per ignoto calle</em> de A. Vivaldi, <em>Te Deum</em> de Eugénio Amorim, <em>Fantasia Coral, op. 80</em> de L. Beethoven, <em>Oratório de Natal</em> de Camille Saint-Saëns, <em>Stabat Mater</em> de Pergolesi, Contralto no Octeto Vocal da ópera <em>Blimunda</em> de Azio Corghi, entre outros.</p>
<p class="font_8"><br></p>
<p class="font_8">Trabalhou com os maestros Nelson Jesus, Bruno Martins, Valter Palma, Rui Pinheiro, José Eduardo Gomes, Osvaldo Ferreira, Gonçalo Lourenço, Vitor Matos, João Paulo Santos, entre outros. Em julho de 2016, obteve o 3º lugar no nível IV do 17º concurso internacional cidade do Fundão e ainda o prémio de melhor interpretação de peça portuguesa. Em junho de 2019, obteve o 1º lugar ex-aequo no concurso nacional da cidade de Gaia no escalão C. Foi semifinalista no concurso prémio jovens músicos (2020/2021) e semifinalista na 2º edição do Concurso Internacional de Lousada (2023).</p>
<p class="font_8">&nbsp;</p>', NULL, NULL, NULL, 'https://static.wixstatic.com/media/367e57_45b6d75d32db4679b60d49b20da059a1~mv2.jpg', NULL, 'https://static.wixstatic.com/media/367e57_88db2650f6984239a6e6bf0a4057efb4~mv2.jpg', NULL, 'https://static.wixstatic.com/media/367e57_3b261dab46504ddcbc296cb9579dc6f2~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/367e57_e99f11534a934bbe96d9587e37a0a151~mv2.jpg', NULL, 'https://static.wixstatic.com/media/367e57_dd34cd62234f423cae987317ab9824ef~mv2.jpg', NULL, 'https://static.wixstatic.com/media/367e57_58d491a358fd454294c68031504b035e~mv2.jpg', NULL, 'https://static.wixstatic.com/media/367e57_dec906ba27274a7bb02e4cdfd31d282c~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 4: Carlos Guilherme
INSERT IGNORE INTO users (id, email, password, role) VALUES ('2bf8ea92-6b69-4d73-ac57-b24e8ad1fda4', 'wix-2bf8ea92@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('b4073447-2983-42ca-9901-ea604dab35c9', '2bf8ea92-6b69-4d73-ac57-b24e8ad1fda4', 'carlos-guilherme', 'Carlos Guilherme', 'Carlos', '999999999', '1954-07-01', 'Portugal', 'Portugal', 'Lisboa', 'xxx xxx x  xxx', NULL, '1800', 'Tenor', '"Só me reformo se deixar de ter voz."', 'https://static.wixstatic.com/media/2bf8ea_cc66110dbfd24153b34f5fa2f93b04a7~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/2bf8ea_00dc522506db48e2b94aca18c7140b6a.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=3_9o6_Ph2bA', 'https://www.youtube.com/watch?v=u7EIcxK59YI', 'https://www.youtube.com/watch?v=qAGnGml2Nfc', 'https://www.youtube.com/watch?v=asv9QqZKMPU', 'https://www.youtube.com/watch?v=RnnGR2JlNHg', NULL, NULL, NULL, NULL, NULL, '<p class="font_8" style="text-align: justify">Com mais de <strong>40 anos de carreira</strong> e um somatório de <strong>91 óperas</strong>, <strong>Carlos Guilherme</strong> é o mais estimado cantor lírico português e com a mais longa carreira ainda no ativo.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">O nome Carlos Guilherme é sinónimo de excelência na música lírica, sendo reverenciado como o <strong>mais famoso tenor português da atualidade</strong>. Figura de referência no canto lírico, tem conquistado plateias em todo o mundo com a sua voz insuperável e interpretações cativantes.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Após uma <strong>longa e consistente carreira</strong>, continua a cativar o público, que o acolhe com entusiasmo fervoroso a cada apresentação. A ligação de Carlos Guilherme com os seus admiradores é tão profunda que ele se sente "mimado" por eles, emocionando-se com demonstrações de carinho como as efusivas salvas de palmas que antecedem as suas performances.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Aos 79 anos, o tenor Carlos Guilherme <strong>continua a deslumbrar</strong> com sua voz poderosa e técnica impecável. Um verdadeiro feito para alguém que em 2024 estreou a sua <strong>nonagésima primeira ópera</strong> - "Felizmente Há Luar!", com música e libretto de Alexandre Delgado.</p>', '<h3 style="text-align:justify">&quot;Nesta fase da minha carreira, é encantador partilhar o palco com cantores que têm quase meio século a menos do que eu. Sinto-me rejuvenescido. Enquanto tiver garganta para cantar, vou continuar a subir ao palco.&quot; Carlos Guilherme</h3><h3 style="text-align:justify"> </h3><p style="text-align:justify">Carlos Guilherme nasceu em 1945 na cidade de Lourenço Marques, atual Maputo, em Moçambique. Descendente de uma avó espanhola pianista, cresceu imerso na rica cultura musical da então colónia portuguesa. A sua paixão pelo canto despertou cedo, aos sete anos, quando interpretou um fado de Coimbra na sua terra natal. No entanto, foi apenas aos 14 anos que retomou verdadeiramente os estudos vocais, uma pausa que, segundo ele, acabou por &quot;salvar&quot; a sua voz lírica.</p><p> </p><p style="text-align:justify">Durante a adolescência, frequentou o Liceu Pêro de Anaia, na Beira, Moçambique, onde se destacava em concursos de canto. Começou a participar em programas de imitações na rádio, imitando o famoso artista João Maria Tudela a tocar harmónica. Mais tarde, foi consagrado &quot;<span style="font-weight:bold">Rei da Rádio</span>&quot;, em 1970, quando lançou o primeiro single pela editora Alfabeta, numa época em que se limitava à música ligeira, por ainda não ter a &quot;estaleca para cantar a clássica&quot;, como o próprio admite.</p><p> </p><p style="text-align:justify">Após cumprir o serviço militar em Moçambique, Guilherme teve aulas de canto com <span style="font-weight:bold">Greta Muir</span>, na antiga Rodésia, hoje Zimbabué. Foi lá que fez a sua estreia operística, no papel de Riccardo em &quot;Um Baile de Máscaras&quot;, de Verdi, pela Companhia de Ópera de Salisbury. Um marco que abriria as portas para uma carreira brilhante nos palcos líricos.</p><p> </p><p style="text-align:justify">Em 1975, o talento de Carlos Guilherme foi reconhecido quando venceu o <span style="font-weight:bold">Concurso Internacional de Eisteddfod</span>. No ano seguinte, mudou-se para Portugal, onde se tornou <span style="font-weight:bold">aluno de John Labarge no Conservatório Regional do Algarve</span>, aprimorando a sua formação. Também melhorou a sua técnica vocal com <span style="font-weight:bold">Marimi del Pozo, Gino Becchi, Campogalliano, Claude Thiolass e Regina Resnik</span>.</p><p> </p><p style="text-align:justify">Em 1980, deu o grande passo rumo à consagração, tornando-se <span style="font-weight:bold">artista residente do Teatro Nacional de São Carlos</span>, em Lisboa, até 1992. Estreou-se com a ópera &quot;Macbeth&quot;, abrindo caminho para dezenas de papéis principais em óperas como &quot;A Flauta Mágica&quot;, &quot;Don Giovanni&quot; e &quot;O Rapto do Serralho&quot;.</p><p> </p><p style="text-align:justify">Desde então, Carlos Guilherme tem dividido o seu talento entre a <span style="font-weight:bold">música erudita e a música ligeira</span>, democratizando o acesso à ópera e cativando públicos diversos. O seu repertório inclui mais de 40 papéis principais em cerca de 90 óperas, mas também vários recitais e concertos, <span style="font-weight:bold">tendo colaborado com as principais orquestras portuguesas e outras internacionais</span>, como a Orquestra de Câmara de Pádua, do Comunal de Bolonha, Filarmónica de Moscovo e Sinfónicas de Budapeste, de São Francisco, de Israel de Pequim e de Shangai.</p><p> </p><p style="text-align:justify">A sua <span style="font-weight:bold">trajetória artística, que se estende por mais de quatro décadas</span>, fundamenta-se numa paixão profunda pela música clássica e pela ópera, mas também pela música ligeira, dada a sua capacidade para transitar entre géneros musicais com maestria. Considerado um <span style="font-weight:bold">artista &quot;sem barreiras&quot;</span>, entre os seus êxitos mais estrondosos, destacam-se as canções de música ligeira &quot;Quando Um Coração Chora De Amor&quot;, &quot;Granada&quot; e &quot;O Meu Alentejo&quot;.</p><p> </p><p style="text-align:justify">Desde 1970, gravou cerca de 15 álbuns, e em 2022, celebrou 40 anos de carreira.</p>', '<p style="text-align:justify">Carlos Guilherme atuou em centenas de palcos nacionais e internacionais. Depois da turneé com a Companhia de Ópera de Florença, em 1987, interpretandoo papel de Almaviva em &quot;O Barbeiro de Sevilha&quot;, recebeu um convite para ficar em Florença, mas foi em Portugal que consolidou a sua carreira de cantor lírico.</p><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">COLABORAÇÕES E PARCERIAS</span></h3><h3> </h3><ul><li style="text-align:justify">Mariza (dueto em &quot;Tudo Isto É Fado&quot; com a Banda da Força Aérea em 2002)</li><li style="text-align:justify">Duo Romeu e Julieta</li><li style="text-align:justify">UHF (no tema &quot;Ser Benfiquista&quot; do álbum &quot;Sou Benfica - As Canções da Águia&quot; em 2003)</li><li style="text-align:justify">Anabela (álbum &quot;Encontro&quot; em 2006)</li><li style="text-align:justify">Contratempo (duo com violoncelo e guitarra clássica em 2006)</li></ul><h3 style="text-align:justify"> </h3><h3><span style="font-weight:bold">ATUAÇÕES MEMORÁVEIS</span></h3><h3> </h3><ul><li style="text-align:justify">Estreia como artista residente no Teatro Nacional de São Carlos em 1980 com &quot;Macbeth&quot;.</li><li style="text-align:justify">Abertura da temporada comemorativa dos 200 anos do Teatro São Carlos em 1993 com &quot;Eugene Onegin&quot;.</li><li style="text-align:justify">Estreia da ópera &quot;O Doido e a Morte&quot; de Alexandre Delgado em 1994.</li></ul><h3 style="text-align:justify"> </h3><h3><span style="font-weight:bold">PRÉMIOS</span></h3><h3> </h3><ul><li style="text-align:justify">Prémio Tomas Alcaide em 1984</li><li style="text-align:justify">4 prémios &quot;Nova Gente&quot; (votação dos leitores)</li><li style="text-align:justify">Estreia em &quot;Il Trionfo di Clelia&quot; no Teatro Rossini, Itália (2001).</li><li style="text-align:justify">Concerto com José Carreras em Coimbra (2003).</li><li style="text-align:justify">Concerto de celebração dos 30 anos de carreira no Centro Cultural de Belém em 2011, Concerto de celebração dos 30 anos de carreira no Centro Cultural de Belém, com as participações de Elisabete Matos, João Marino, António Pinto Basto e Telmo Miranda.</li><li style="text-align:justify">Recital em Roma como parte de uma Mostra de Arte Portuguesa (2016).</li><li style="text-align:justify">Concertos em comemoração aos 40 anos de carreira em 2023, na Figueira da Foz e em Carnaxide.</li></ul><p style="text-align:justify"> </p><h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p> </p><p style="text-align:justify"><span style="font-weight:bold">2024 </span>- Estreou-se na sua 91ª ópera no papel de Principal Sousa na ópera &quot;Felizmente Há Luar!&quot;, com música e libretto de Alexandre Delgado.</p><p style="text-align:justify"><span style="font-weight:bold">2023 </span>- Comemorou 40 anos de carreira com concertos no Centro de Artes e Espetáculos da Figueira da Foz e na Sociedade Filarmónica Fraternidade Carnaxide.</p><p style="text-align:justify"><span style="font-weight:bold">2016 </span>- Em Roma, apresentou recital integrado a uma Mostra de Arte Portuguesa, com repertório de compositores lusitanos, acompanhado pelo maestro Armando Vidal.</p><p style="text-align:justify"><span style="font-weight:bold">2011 </span>- Apresentou concerto especial no Centro Cultural de Belém, Lisboa, para celebrar 30 anos de carreira.</p><p style="text-align:justify"><span style="font-weight:bold">2006 </span>- Lançou &quot;Cantar Portugal&quot; e um álbum em parceria com Contratempo, mesclando música erudita e popular. Também lançou &quot;Encontro&quot; em duo com Anabela.</p><p style="text-align:justify"><span style="font-weight:bold">2005 </span>- Retornou à Itália para atuar em &quot;Ariadne auf Naxos&quot; nos Teatros Comunais de Ferrara e Modena.</p><p style="text-align:justify"><span style="font-weight:bold">2003 </span>- Atuou em concerto com o lendário tenor José Carreras em Coimbra. Lançou o álbum &quot;Sou Benfica - As Canções da Águia&quot; com participação nos UHF.</p><p style="text-align:justify"><span style="font-weight:bold">2002 </span>- Colaborou com a Banda da Força Aérea Portuguesa, incluindo um dueto com Mariza em &quot;Tudo Isto É Fado&quot;.</p><p style="text-align:justify"><span style="font-weight:bold">2001 </span>- Protagonizou &quot;Il Trionfo di Clelia&quot; de Gluck no Teatro Rossini na Itália, marcando sua estreia naquele país.</p><p style="text-align:justify"><span style="font-weight:bold">2000 </span>- Gravou o CD natalino &quot;É Natal&quot; com o pianista João Balula Cid. Também interpretou papéis em óperas como &quot;The English Cat&quot; de Henze e &quot;Stabat Mater&quot; de Rossini em Ponta Delgada.</p><p style="text-align:justify"><span style="font-weight:bold">1999 </span>- Protagonizou &quot;La Borghesina&quot; de Augusto Machado e interpretou Mercúrio em &quot;Orphée aux Enfers&quot; de Offenbach, ambas no Teatro Nacional de São Carlos.</p><p style="text-align:justify"><span style="font-weight:bold">1997 </span>- Fez sua estreia no papel de Rodolfo em &quot;La Bohème&quot;, encerrando colaboração com a Ópera de Câmara do Real Teatro de Queluz.</p><p style="text-align:justify"><span style="font-weight:bold">1994 </span>- Estreou a ópera &quot;O Doido e a Morte&quot; de Alexandre Delgado, em Lisboa, Capital Europeia da Cultura naquele ano.</p><p style="text-align:justify"><span style="font-weight:bold">1993 </span>- Lançou o disco &quot;Canções em Português&quot;. Também abriu a temporada comemorativa dos 200 anos do Teatro Nacional de São Carlos, cantando na ópera &quot;Eugene Onegin&quot; de Tchaikovsky.</p><p style="text-align:justify"><span style="font-weight:bold">1991 </span>- Lançou o álbum &quot;Histórias de Amor&quot;, produzido por Jorge Quintela, além de regravar &quot;Quando o Coração Chora&quot; com a cantora Dulce Pontes.</p><p style="text-align:justify"><span style="font-weight:bold">1990 </span>- Lançou seu primeiro álbum solo, intitulado &quot;Canções de Amor&quot;, relembrando clássicos dos anos 40 e 50.</p><p style="text-align:justify"><span style="font-weight:bold">1987 </span>- Expandiu seus horizontes, sendo convidado para cantar em outros países como Estados Unidos, Brasil, Moçambique, Bélgica, França, Espanha e Israel. Neste ano, com a Companhia de Ópera de Florença, interpretou o papel de Almaviva em &quot;O Barbeiro de Sevilha&quot; e foi Truffaldino em &quot;O Amor das Três Laranjas&quot; a convite da Nova Ópera de Telavive.</p><p style="text-align:justify"><span style="font-weight:bold">1984 </span>- Recebeu o Prémio Tomas Alcaide, em reconhecimento a seu talento.</p><p style="text-align:justify"><span style="font-weight:bold">1980-1992 </span>- Atuou como cantor residente do Teatro Nacional de São Carlos, período em que interpretou diversos papéis principais.</p><p style="text-align:justify"><span style="font-weight:bold">1980 </span>- Tornou-se artista residente do Teatro Nacional de São Carlos em Lisboa, estreando na ópera &quot;Macbeth&quot;.</p><p style="text-align:justify"><span style="font-weight:bold">1976 </span>- Mudou-se para Portugal, tornando-se aluno de John Labarge no Conservatório Regional do Algarve, onde aprimorou sua formação.</p><p style="text-align:justify"><span style="font-weight:bold">1975 </span>- Venceu o prestigiado Concurso Internacional de Eisteddfod, na antiga Rodésia (hoje Zimbábue).</p><p style="text-align:justify"><span style="font-weight:bold">1970 </span>- Lançou seu primeiro single pela editora Alfabeta em Moçambique e foi consagrado &quot;Rei da Rádio&quot; do país.</p>', '<h3><span style="font-weight:bold">DISCOGRAFIA</span></h3><ul><li>Carlos Guilherme (Single, Alfabeta, 1970)</li><li>Quando o Coração Chora (Single, Edisom, 1983) - como Duo Romeu &amp; Julieta</li><li>Sonhos de Verão (Single, Edisom, 1983)</li><li>Certo Ou Errado (Single, Dacapo, 1985)</li><li>Canções de Amor (LP, Edisom, 1990)</li><li>Histórias de Amor (LP, Edisom)</li><li>Canções Em Português (LP, Edisom, 1992)</li><li>Serenata (CCD-Digital/Strauss, 1997)</li><li>A Canção Portuguesa (CD, Numérica, 1998)</li><li>Clássicos da Renascença nº 64 (CD, Movieplay, 2000)</li><li>É Natal (CD, 2000) - com João Balula Cid</li><li>Cantar Portugal (CD, Ovação, 2006)</li><li>Carlos Guilherme &amp; Contratempo (CD, Ovação, 2006) - com Contratempo</li><li>Encontro (CD, Zona Música, 2006) - com Anabela</li><li>Canções Da República (CD, 2010) - com João Balula Cid</li></ul><p><span style="font-weight:bold">Participações</span></p><ul><li>Casablanca: os êxitos da Broadway (êxito Estudio, 1998)</li><li>Banda da Força Aérea (2002)</li><li>UHF (2003)</li></ul><h3><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h3><h3> </h3><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://sic.pt/sic/carlos-guilherme-a-eterna-voz-de-quando-o-coracao-chora-de-amor/ target=_blank>SIC (2024)</a></span></span></span> - Carlos Guilherme, a eterna voz de “Quando o Coração Chora de Amor”</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.jornaldenegocios.pt/weekend/detalhe/carlos-guilherme-so-me-reformo-se-deixar-de-ter-voz target=_blank>Jornal de Negócios (2023)</a></span></span></span> - Carlos Guilherme - “Só me reformo se deixar de ter voz”</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://arquivos.rtp.pt/conteudos/carlos-guilherme/ target=_blank>RTP (1985)</a></span></span></span> - Carlos Guilherme entrevistado por Eunice Munöz</p><h2> </h2><h2>Quer saber mais?</h2><h2>Entre em contacto connosco!</h2>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 5: Voces Caelestes
INSERT IGNORE INTO users (id, email, password, role) VALUES ('ae5bab0a-943f-4e67-ac1d-f8989f9ae7b4', 'wix-ae5bab0a@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('4e96f5d0-7f97-45c8-b11f-1e35d8d3904d', 'ae5bab0a-943f-4e67-ac1d-f8989f9ae7b4', 'voces-caelestes', 'Voces Caelestes', 'Voces', '351966317847', '1997-09-06', 'Portugal', 'Portugal', 'Lisboa', 'Rua dos Lusíadas, 110, 1.º Dto.', NULL, '1300-374', 'Coro', 'Cantar, mais do que a nossa profissão, é a nossa paixão.', 'https://static.wixstatic.com/media/ae5bab_26a80e9bd9ae4b088436e99ec3c449d5~mv2.jpeg', 'wix:document://v1/ae5bab_5ea37a38b8734bc08188dfa285079fe1.pdf/Voces%20Caelestes%20-%20Portugu%C3%AAs%20.pdf', 'https://www.facebook.com/vocescaelestes/?locale=pt_PT', 'https://www.instagram.com/vocescaelestes/', NULL, 'https://open.spotify.com/artist/01w678r4WmxgliCzTn9Z2B', 'https://www.youtube.com/channel/UC6p-x_0Bq_RcuwGQ92I1rzA', NULL, NULL, NULL, 'https://youtu.be/YO6IcIv5qjA?si=X9fcoongsC40740V', 'https://youtu.be/2FSjQqGlGag?si=MJYt0ouGhzfJPkS-', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8">Voces Caelestes é um grupo vocal de constituição variável, de acordo com as exigências das obras a interpretar. Esta característica, aliada à vasta experiência dos cantores que o integram – que se estende da música medieval à criação musical contemporânea –, permite às Voces Caelestes abordar um extenso repertório.</p>', '<p>Desde a sua estreia, em Setembro de 1997, as Voces Caelestes têm interpretado obras de Machaut, Ciconia, Lantins, Dufay, Josquin, Lasso, Victoria, Gesualdo, Monteverdi, Allegri, Buxtehude, Bach, Händel, Vivaldi, Scarlatti, Haydn, Schubert, Beethoven, Brahms, Debussy, Ravel, Franck, Grieg, Stanford, Britten, Lloyd Webber e Lopes-Graça, entre outros.</p><p> </p><p>Paralelamente, têm feito incursões esporádicas nos domínios da ópera e de outros espectáculos multidisciplinares, tendo participado nas produções de <span style="font-style:italic">Platée</span> (Rameau), <span style="font-style:italic">Cenas do Fausto de Goethe</span> (Schumann), <span style="font-style:italic">A Flauta Mágica</span>, <span style="font-style:italic">As Bodas de Fígaro</span> (Mozart), <span style="font-style:italic">A Filha do Regimento</span> (Donizetti), <span style="font-style:italic">Sonho de uma Noite de Verão</span> (Mendelssohn), <span style="font-style:italic">Peter Pan</span> (Bernstein) e <span style="font-style:italic">Rigoletto</span> (Verdi) encenadas por Tito Celestino da Costa e nos espectáculos <span style="font-style:italic">Deus. Pátria. Revolução</span> (Luís Bragança Gil/Luísa Costa Gomes), <span style="font-style:italic">Crioulo</span> - <span style="font-style:italic">uma ópera cabo-verdiana</span> (António Tavares/Vasco Martins), <span style="font-style:italic">Le Carnaval et la Folie</span> (Destouches), <span style="font-style:italic">Paride ed Elena</span> (Gluck), <span style="font-style:italic">Armida </span>(Mysliveček) e <span style="font-style:italic">Don Giovanni</span> (Mozart).</p><p> </p><p>A par do seu empenhamento na divulgação da música antiga portuguesa – traduzido, até agora, na apresentação de obras de Duarte Lobo, Filipe de Magalhães, Frei Manuel Cardoso, Estêvão Lopes Morago, Diogo Dias Melgaz, Francisco Martins, António Teixeira, Carlos Seixas, Francisco António de Almeida, João Rodrigues Esteves e Pedro António Avondano –, as Voces Caelestes têm dedicado especial atenção à música contemporânea. Neste âmbito, estrearam em Portugal as <span style="font-style:italic">Street Songs</span>, de Steve Martland, e apresentaram em estreia mundial obras de Alain Bioteau (<span style="font-style:italic">Vat 69</span>), Pedro Amaral (<span style="font-style:italic">Os Jogadores de Xadrez</span>), Pedro Carneiro (… <span style="font-style:italic">ni mots, ni signes</span>…), Tiago Derriça (<span style="font-style:italic">Alma</span>) e Vito Zuraj (O magnum mysterium).</p>', '<p>As Voces Caelestes têm-se apresentado em diversos auditórios de Lisboa (Centro Cultural de Belém, Culturgest, Fundação Calouste Gulbenkian, Teatro Municipal de São Luiz, Teatro Nacional de São Carlos, Teatro Thalia, Museu Nacional de Arte Antiga, Jardim Botânico e Palácio Nacional da Ajuda, Sé Patriarcal, Basílica dos Mártires, Igreja de S. Nicolau, Igreja de S. Roque, Igreja de S. Vicente de Fora, Convento do Beato e Convento da Encarnação), bem como noutras localidades (Cascais, Castelo Branco, Caxias, Coimbra, Évora, Fátima, Guimarães, Mértola, Óbidos, Portimão, Porto, Santarém, Santiago do Cacém, Setúbal, Sintra, Tavira), no âmbito de algumas das mais prestigiadas manifestações musicais (Festival de Sintra, Festival Estoril Lisboa, Terras sem Sombra - Festival de Música Sacra do Baixo Alentejo, Cistermúsica, Festival Internacional de Música de Coimbra, Primavera Musical - Festival Internacional de Música de Castelo Branco, Guimarães 2012 - Capital Europeia da Cultura, Jornadas Internacionais &quot;Escola de Música da Sé de Évora&quot;, Comemorações dos 250 Anos do Nascimento da Cantora Luísa Todi, Música em São Roque, Festival Internacional de Órgão de Lisboa, Festival Rota dos Monumentos, Festival das Artes). Em Agosto de 2006, as Voces Caelestes fizeram a sua estreia internacional, participando, com grande sucesso, no prestigiado Festival Internacional de Música Antiga de Daroca (Espanha). O grupo participou na gravação do CD de música sacra <span style="font-style:italic">Alleluia</span>, da soprano Teresa Cardoso de Menezes, gravou para a RTP excertos do <span style="font-style:italic">Te Deum</span> de Frei José Marques e Silva e colaborou com o agrupamento Os Músicos do Tejo na primeira gravação mundial da obra <span style="font-style:italic">Il Trionfo d&#x27;Amore</span>, de Francisco António de Almeida.</p><p> </p><p>As Voces Caelestes têm-se apresentado <span style="font-style:italic">a cappella</span> e em colaboração com instrumentistas como a cravista Ana Mafalda Castro, a harpista Stéphanie Manzo, a pianista Ana Telles, a contrabaixista Marta Vicente, os organistas António Duarte, António Esteireiro, David Paccetti, Isabel Albergaria, João Vaz, Margarida Oliveira, Rui Paiva e Sérgio Silva, os violoncelistas Paulo Gaio Lima e Miguel Ivo Cruz e os percussionistas Abel Cardoso, Pedro Carneiro e Jean-François Lézé, e agrupamentos como Camerata Academica Salzburg, Orquestra de Câmara Portuguesa, Orquestra Gulbenkian, Orquestra Metropolitana de Lisboa, orquestra barroca Capela Real, Divino Sospiro, Ludovice Ensemble, Os Músicos do Tejo, Orquestra Aldrabófona, Quarteto ArtZen, Segréis de Lisboa e Sete Lágrimas, sob a direcção dos maestros Pedro Amaral, Stephen Barlow, Martyn Brabbins, Luís Bragança Gil, Pedro Carneiro, Harry Christophers, Laurence Cummings, Christian Curnyn, Osvaldo Ferreira, Sérgio Fontão, Alexander Frey, Leonardo García Alarcón, Manuel Ivo Cruz, Fernando Miguel Jalôto, Nicholas Kraemer, Marcos Magalhães, Massimo Mazzeo, Manuel Morais, Pedro Neves, Elio Orciuolo, Jean-Bernard Pommier, João Paulo Santos, Peter Schreier, Garry Walker e Michael Zilm.</p>', '<p class="font_8"><strong>Outras apresentações em vídeo</strong></p>
<p class="font_8"><br></p>
<p class="font_8">Da Penitência à Redenção - Voces Caelestes &amp; Real Câmara</p>
<p class="font_8">Cistermúsica 2022</p>
<p class="font_8">Assista <a href="https://www.rtp.pt/play/palco/p12069/da-penitencia-a-redencao-voces-caelestes"><u>aqui</u></a></p>
<p class="font_8"><br></p>
<p class="font_8">Bach, Pai e Filho: Magnificat x2</p>
<p class="font_8">Orquestra Metropolitana de Lisboa com Coro Voces Caelestes</p>
<p class="font_8">Assista <a href="https://www.rtp.pt/play/palco/p7118/bach-pai-filho"><u>aqui</u></a></p>
<p class="font_8"><br></p>
<p class="font_8">Integral das Sinfonias de Beethoven</p>
<p class="font_8">Assista <a href="https://www.rtp.pt/play/palco/p6932/e513346/integral-das-sinfonias-de-beethoven"><u>aqui</u></a></p>
<p class="font_8"><br></p>
<p class="font_8">Joly Braga Santos - Sinfonia n.º 4</p>
<p class="font_8">No centenário de Joly Braga Santos, figura de proa da música portuguesa do século XX, recordamos a versão coral-sinfónica da sua extraordinária Sinfonia n.º 4. Pedro Neves dirige a OJ .COM (Orquestra de Jovens dos Conservatórios Oficiais de Música) e o coro Voces Caelestes. Gravado ao vivo no <a href="https://www.facebook.com/centroculturaldebelem?__tn__=-]K">Centro Cultural de Belém</a>, a 28 de Abril de 2017.</p>
<p class="font_8">Assista <a href="https://www.facebook.com/watch/?v=1421216135940017"><u>aqui</u></a></p>
<p class="font_8">&nbsp;</p>', 'https://static.wixstatic.com/media/ae5bab_0e6cb34b869841c285098bb4f28c2558~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/ae5bab_af86322968f1459baa584e985616ac78~mv2.jpeg', 'Voces Caelestes no Grande Auditório do CCB', 'https://static.wixstatic.com/media/ae5bab_dda24a511155469c9db84847c617e0cf~mv2.jpeg', 'Voces Caelestes no Chalet da Condessa d’Edla', 'https://static.wixstatic.com/media/ae5bab_a410661a9b534112bedf82d3be4e2194~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/ae5bab_09ff2b0f31fd4177ac5b525848a5ef6f~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/ae5bab_09673c165a104e378013fd0bed08022d~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/ae5bab_b4951f53d6714e86b166827f0d8e6d68~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/ae5bab_700fced409eb4582a3a679ab60e52adf~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/ae5bab_2343c5286c6b466aa11720dfc452c786~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/ae5bab_5fc5547903f34e35b81e9171a0cd6d34~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/ae5bab_2fbf0b56b6d840feb218cb430ae4a1de~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/ae5bab_90c1adcbb672459ba1b9b3bf8d1d9515~mv2.jpeg', NULL, 1, 0, 0);

