-- Row 7: Susana Teixeira
INSERT IGNORE INTO users (id, email, password, role) VALUES ('0a564487-fcfa-498c-a7ea-a8472db1eead', 'wix-0a564487@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('b60332b0-1c10-472d-aeca-076076e8c347', '0a564487-fcfa-498c-a7ea-a8472db1eead', 'Susana-Teixeira', 'Susana Teixeira', 'Susana', '965736329', '1964-08-30', 'Portugal', 'Portugal', 'Monte -Estoril', 'Rua Conde Moser, 289, 2ºDto', NULL, '2765-428', 'Cantora', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 8: Pedro Ribeiro
INSERT IGNORE INTO users (id, email, password, role) VALUES ('9a92c904-4b22-4b52-a0d5-28e725ff2916', 'wix-9a92c904@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('e8ba04c8-efa7-440e-8246-2ef421de8c5d', '9a92c904-4b22-4b52-a0d5-28e725ff2916', 'pedro-ribeiro', 'Pedro Ribeiro', 'Pedro', '962013792', '2024-08-01', 'Rua do Bonjardim 586 A, 2º', 'Portugal', 'Porto', 'Rua do Bonjardim 586 A, 2º', NULL, '4000-118', 'Encenador e Designer', '“A arte de saber contar histórias em palco.”', 'https://static.wixstatic.com/media/9a92c9_889f1689ce9b4600930333a494ed108b~mv2.jpg', 'wix:document://v1/ugd/7b859e_210bdeee2cfc47cc80d8f98bb6211ef7.pdf/Bio_PRibeiro_Proart_PTG.pdf', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.youtube.com/watch?v=TG87paK893c', 'https://www.youtube.com/watch?v=EQ26Y_vIj4I', 'https://www.youtube.com/watch?v=yOLMelk07yw', 'https://www.youtube.com/watch?v=INmCynTPYJA', 'https://www.youtube.com/watch?v=YSXhpgfvFDs&t=177s', 'https://www.youtube.com/watch?v=TG87paK893c', 'https://www.youtube.com/watch?v=EQ26Y_vIj4I', 'https://www.youtube.com/watch?v=yOLMelk07yw', 'https://www.youtube.com/watch?v=INmCynTPYJA', 'https://www.youtube.com/watch?v=YSXhpgfvFDs&t=177s', '<p class="font_8"><strong>“Nos labirintos criativos do teatro e da ópera, emergem figuras cuja visão redefine o espetro das possibilidades artísticas e molda o futuro das artes performativas.</strong></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>O encenador e designer </strong><a href="https://stagedirector.net/">Pedro Ribeiro</a><strong> é um desses visionários, cuja multifacetada jornada artística revela um talento raro capaz de entrelaçar diferentes formas de arte e de criar experiências que transcendem o convencional e cativam tanto o público quanto a crítica.</strong></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Ao longo da sua formação e carreira, tem demonstrado uma versatilidade e um compromisso excecionais com a sua vocação. Este empenho, aliado à sua dedicação inabalável e ao seu perfeccionismo meticuloso, são características que definem a sua genialidade criativa e a sua capacidade de executar visões artísticas com uma precisão ímpar. A paixão e o rigor com que aborda cada projeto tornam a sua obra inconfundível, à qual ninguém fica indiferente.”</strong></p>
<p class="font_8"><br></p>
<p class="font_8"><em>Por Joana Patacas (Entrevista Proart Março | 2024)</em></p>', '<p><span style="font-weight:bold">Nasceu no Porto. Concluiu a Licenciatura em Estudos Teatrais/Interpretação na Escola Superior de Música e das Artes do Espectáculo; o Curso de Encenação de Ópera da Fundação Calouste Gulbenkian e o Curso Geral de Artes Visuais da Escola especializada em ensino artístico Soares dos Reis. Possui uma carreira premiada como encenador, cenógrafo e figurinista e um percurso de docente extenso em disciplinas ligadas ao teatro, teatro musical e ópera, tendo leccionado em Portugal, Inglaterra, Áustria, França, Itália e Dinamarca.</span></p><p><br/></p><p><span style="font-weight:bold">De 2004 a 2011 trabalhou com a companhia Teatro de Marionetas do Porto como figurinista, designer gráfico e assistente de encenação de João Paulo Seara Cardoso. Foi com o João Paulo que trabalhou na sua primeira incursão pelo teatro de ópera na obra <span style="font-style:italic">Encantos de Medeia</span> de António José da Silva e a ele lhe deve o incentivo para seguir uma carreira na encenação de espectáculos multidisciplinares. Desde então dirige produções que vão da ópera ao teatro e do teatro musical a peças “site-specific” entre uma miríade de autores portugueses e estrangeiros.</span></p><p><br/></p><p><span style="font-weight:bold">É desde 2007 Director Artístico da Companhia de Teatro Os Quatro Ventos, uma companhia de reportório especializada em &quot;empurrar&quot; a dramaturgia portuguesa para o século XXI e para o público jovem.</span></p><p><br/></p><p><span style="font-weight:bold">Em 2011 foi seleccionado a nível mundial como o encenador residente no prestigiado programa Jette Parker Young Artists Programme (JPYAP) da Royal Opera House – Londres. Na ROH criou novas encenações para os palcos principal e secundário, recebendo excelentes críticas da imprensa inglesa, destacando a do jornal The Times que refere a sua produção de Montsalvagte - <span style="font-style:italic">El Gato Con Botas</span> como “hipnotizante”.</span></p><p><br/></p><p><span style="font-weight:bold">Foi assistente dos maiores encenadores mundiais como Kasper Holten, Robert Carsen, Laurent Pelly, Danielle Abbado, John Copley, John Fuljames, Jonathan Kent e trabalhou com cantores como Aigul Akhmetshina, Ambrogio Maestri, Angela Gheorghiu, Bryan Hymel, Charles Castronovo, Daniela Barcellona, Ermonela Jaho, Erwin Schrott, Jonas Kaufmann, Juan Diego Flórez, Krassimira Stoyanova, Leo Nucci, Liudmyla Monastyrska, Lisette Oropesa, Michael Spyres, Patrizia Ciofi, Placido Domingo, Roberto Alagna, Simon Keenlyside, Piotr Beczala, Vittorio Grigolo, entre outros. Actualmente trabalha para a ROH como encenador freelancer em reposições do reportório da casa.</span></p><p><br/></p><p><span style="font-weight:bold">Entre 2012 e 2017 foi assessor nos <span style="font-style:italic">Off West End Awards</span> nomeando espectáculos e artistas para os prémios <span style="font-style:italic">OFFIES</span> que galardoam o que de melhor se apresenta nos teatros Londrinos.</span></p><p> </p><p><span style="font-weight:bold">Através da European Network of Opera Academies encena na Gulbenkian um lab de uma nova ópera <span style="font-style:italic">Outra Margem </span>(N.Rocha/R.Fernandes), foi o encenador convidado para a residência <span style="font-style:italic">Landscape of new music theatre and opera – New Staging Languages</span>, LOD (Gent) / Théâtre Royal de la Monnaie (Bruxelas) e participa no curso <span style="font-style:italic">3D Mapping for Opera</span> para cenografia e encenação na Academia de Ópera de Verona, Itália.</span></p><p><br/></p><p><span style="font-weight:bold">Das suas mais recentes produções destacam-se espectáculos onde é encenador e designer: <span style="font-style:italic">An Account Of The State Of That Place</span> projecto vencedor do TW Puppetry Festival; <span style="font-style:italic">A Paixão</span> | J.S.Bach no CCVF; <span style="font-style:italic">Goldilocks &amp; The Three Pigs</span> para a Opera Story; o musical <span style="font-style:italic">A Caminho</span> para a AMGD; <span style="font-style:italic">La Cambiale di Matrimonio</span> e <span style="font-style:italic">Elisir d’Amore</span> para a All’Opera; <span style="font-style:italic">Fígados de Tigre</span> e <span style="font-style:italic">António Marinheiro </span>e <span style="font-style:italic">A Rapariga Normal e a Ervilha</span> para a CT4V; <span style="font-style:italic">O Fantasma da Ópera</span> no Coliseu do Porto e Campo Pequeno; Música no Coração no SBArena e AltArena; e as reposições de <span style="font-style:italic">Rigoletto, Falstaff, Nabucco, Barbiere di Siviglia, Manon Lescaut, Carmen</span> e <span style="font-style:italic">La Traviata</span> no palco principal da ROH.</span></p><p><br/></p><p><span style="font-weight:bold">+ info e amostras do seu trabalho em: <span style="text-decoration:underline"><a href=http://www.stagedirector.net/ target=null>www.stagedirector.net</a></span> | <span style="text-decoration:underline"><a href=https://www.operabase.com/pedro-ribeiro-a30796/en target=null>Operabase</a></span></span></p>', '<p class="font_8" style="text-align: center"><strong>“Staging by Pedro Ribeiro – minimal, but always to the point.”</strong></p>
<p class="font_8" style="text-align: center">THE GUARDIAN</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8" style="text-align: center"><strong>“Simply but strikingly staged by director and designer Pedro Ribeiro.”</strong></p>
<p class="font_8" style="text-align: center">OPERA MAGAZINE</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8" style="text-align: center"><strong>“It was spellbinding.”</strong></p>
<p class="font_8" style="text-align: center">BACHTRACK</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8" style="text-align: center"><strong>“Restrained but poetic minimalism.”</strong></p>
<p class="font_8" style="text-align: center">OPERA TODAY</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8" style="text-align: center"><strong>“It’s an imaginative staging.”</strong></p>
<p class="font_8" style="text-align: center">WHAT’S ON STAGE</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8" style="text-align: center"><strong>“The staging was visually powerful.”</strong></p>
<p class="font_8" style="text-align: center">CLASSICAL SOURCE</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8" style="text-align: center"><strong>“Mr. Ribeiro’s astute production”</strong></p>
<p class="font_8" style="text-align: center">OPERA BRITANNIA</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8" style="text-align: center"><strong>“Feels epic.”</strong></p>
<p class="font_8" style="text-align: center">THE GUARDIAN</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8" style="text-align: center"><strong>“Stunning staging by Pedro Ribeiro”</strong></p>
<p class="font_8" style="text-align: center">BROADWAYWORLD</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8" style="text-align: center"><strong>“Ribeiro is careful to tell the story deftly and clearly.</strong></p>
<p class="font_8" style="text-align: center"><strong>Children will be mesmerised but so will adults.”</strong></p>
<p class="font_8" style="text-align: center">THE TIMES</p>
<p class="font_8" style="text-align: center"><br></p>
<p class="font_8"><strong>“Pedro Ribeiro</strong><em><strong> </strong></em><strong>brought just enough drama to the staging</strong><em> –</em><strong> the result was surprisingly successful and dramatically involving…”</strong><em><strong> </strong></em><em>(Viaggio a Reims) Robert Hugill | Opera Today</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"Ribeiro, however, is careful to tell the story deftly and clearly…</strong><em> </em><strong>Children will be mesmerised but so will adults”</strong><em><strong> </strong></em><em>(El Gato con Botas) Richard Morrison | The Times ****</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"Pedro Ribeiro’s direction is fantastically imaginative, and indeed it had to be. This is the sort of show that adults should not enjoy, but do. There were laugh-out-loud moments. There were also intakes of breath at transforming sets and unexpected costumes”</strong><em><strong> </strong></em><em>(El Gato con Botas) Hannah Sander | Classical Source</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"The playful design is by Pedro Ribeiro, who also directs, and it suits an evening that is, in part, a bold experiment with scale – the opera lasts little more than an hour yet feels epic… a swinish pearl of an opera</strong>.<strong>” </strong><em>(Goldilocks and the Tree Little Pigs) Kate Kellaway | The Guardian</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"simply but strikingly staged by director-designer Pedro Ribeiro… it is a subtle and beautifully achieved piece of work" </strong><em>(Mozart and Salieri)</em><em><strong> </strong></em><em>George Hall | Opera Magazine</em></p>
<p class="font_8"><br></p>
<p class="font_8"><em><strong>“Aided by Rustioni’s conducting and Ribeiro’s discreetly effective staging this was a sparkling evening in the theatre…” </strong></em><em>(Viaggio a Reims) Robert Hugill | Opera Today</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"Director Pedro Ribeiro succeeded in impressing upon his audience the beauty and pain of death, life and love”</strong><em> (Les Nuits d’Ete) Katy S Austin | Bachtrack</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"By creating a believable ‘lie’ the ‘truth’ of each piece came shining through in every gesture and clearly-enunciated word, establishing an immediate bond with the performers.</strong> (…) <strong>La Boheme was shatteringly engrossing and (I was glad to see that I was not the only one in tears when it ended).”</strong><em>Clive Burton | Theatre World Internet Magazine</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"Mozart and Salieri had also never had a previous showing in Covent Garden. Mr. Ribeiro’s astute production has given it a strong introduction.”</strong> <em>(Mozart and Salieri)</em><em><strong> </strong></em>John E de Wald | Opera Britannia ****</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"The premiere of the Portuguese version of Bach’s St John Passion enraptured the audience of Guimaraes. In a superb show with stage direction of Pedro Ribeiro the audience surrendered completely to the multifaceted spectacle, which had on stage more than a hundred artists”</strong> <em>P.Peixoto | GuimaraesDigital</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"Ribeiro’s production – suits and black, with excellent lighting giving the right sense of melodrama, shadows and darkness – seemed to me to capture very nicely this haunting little piece.”</strong> <em>(Mozart and Salieri)</em><em><strong> </strong></em><em>Opera Notes</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“In this stupendous revival the stamp of the director Pedro Ribeiro, is much in evidence.”</strong> <em>(La Traviata)</em> Rivka Jacobson | PlaysToSee *****</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Stunning staging by Pedro Ribeiro. Critics agree this show has proven Portugal’s ability to stage huge productions.”</strong> <em>(The Phantom of the Opera) | Broadwayworld</em></p>
<p class="font_8"><br></p>
<p class="font_8"><em><strong>"Pedro Ribeiro’s slightly surreal production conveyed a twilight take on fairytale.(…) El Gato con Botas has to be seen to be fully enjoyed and appreciated. Truth is, I hardly stopped smiling all the way through.” </strong></em><em>&gt; Colin Clarke | Seen &amp; Heard International</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“The Lisbon audience surrendered to the charms of this concert version of Phantom of the Opera (…) despite being a concert version, the acting, the musicians, the staging are so well put together and engaging that we often forget that it is not the actual staged version we are watching. Not to be missed.”</strong> <em>| Elsa Furtado, C&amp;H Online Magazine</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“simple but excellent production by Pedro Ribeiro. Not to be missed</strong>.” <em>(Mozart and Salieri)</em> Mark Ronan</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“In the hands of a good revival director – this time Pedro Ribeiro – Eyre’s show still can make us weep, the stage pulsates with life…”</strong> <em>(La Traviata)</em> Michael Church | INews ****</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“This concert version is actually brilliant, rivalling with the staged version that immortalized this musical in London. (…) a spectacle of this magnitude is not made simply with the artists who step on the stage, so I leave a special word to the director Pedro Ribeiro (another who saw his talent recognized in 2011 when he went to work for the prestigious ROH) with the hope we can see his work more often in Portugal.”</strong> (The Phantom of the Opera) | <em>TeatroEmPortugal</em></p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>[VERSÃO EM PORTUGUÊS]</strong></p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Encenação de Pedro Ribeiro – minimal, mas sempre objetiva.”</strong></p>
<p class="font_8">THE GUARDIAN</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“De forma simples, mas marcante, é posta em cena pelo encenador e designer Pedro Ribeiro.”</strong></p>
<p class="font_8">OPERA MAGAZINE</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Foi encantadora.”</strong></p>
<p class="font_8">BACHTRACK</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Um minimalismo contido, mas poético.”</strong></p>
<p class="font_8">OPERA TODAY</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“É uma encenação imaginativa.”</strong></p>
<p class="font_8">WHAT’S ON STAGE</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“A encenação foi visualmente poderosa.”</strong></p>
<p class="font_8">CLASSICAL SOURCE</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"Uma produção astuta do Sr. Ribeiro”</strong></p>
<p class="font_8">OPERA BRITANNIA</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Parece épico.”</strong></p>
<p class="font_8">THE GUARDIAN</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Encenação deslumbrante de Pedro Ribeiro”</strong></p>
<p class="font_8">BROADWAYWORLD</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Ribeiro tem o cuidado de contar a história com habilidade e clareza.</strong></p>
<p class="font_8"><strong>As crianças ficarão hipnotizadas, mas os adultos também.”</strong></p>
<p class="font_8">THE TIMES</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Pedro Ribeiro trouxe drama suficiente à encenação – o resultado foi surpreendentemente bem-sucedido e dramaticamente envolvente…”</strong> <em>(Viaggio a Reims) Robert Hugill | Opera Today</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"A estreia da versão portuguesa da Paixão de São João de Bach arrebatou o público vimaranense. Num espectáculo soberbo com encenação de Pedro Ribeiro o público rendeu-se por completo ao espectáculo multifacetado, que teve em palco mais de uma centena de artistas”</strong> P.Peixoto | GuimarãesDigital</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“A encenação de Pedro Ribeiro é fantasticamente imaginativa, e tinha mesmo de ser. (…) Este é o tipo de espetáculo que os adultos não devem gostar, mas que gostam. Houve momentos de gargalhadas altas. Também houve inspirações ao transformar cenários e figurinos de forma inesperada”</strong> <em>(El Gato con Botas) Hannah Sander | Classical Source</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Esta versão concerto é realmente brilhante, rivalizando com a versão encenada que imortalizou este musical em Londres. (…) um espectáculo desta envergadura não se faz simplesmente com os artistas que sobem ao palco, pelo que deixo uma palavra especial ao encenador Pedro Ribeiro (outro que viu o seu talento reconhecido em 2011 quando foi trabalhar para a prestigiada ROH) com a esperança de podermos ver o seu trabalho com mais frequência em Portugal.”</strong> <em>| TeatroEmPortugal</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Esta reposição de Eyre nas mãos de um bom encenador – desta vez Pedro Ribeiro – ainda nos faz chorar, o palco pulsa de vida…”</strong> <em>(La Traviata) Michael Church | Notícias ****</em></p>
<p class="font_8"><strong>A produção ligeiramente surreal de Pedro Ribeiro transmitiu uma visão crepuscular do conto de fadas.(…) El Gato con Botas tem de ser visto para ser plenamente apreciado e apreciado. A verdade é que quase não deixei de sorrir o tempo todo.”</strong> <em>Colin Clarke |</em> <em>Seen &amp; Heard International</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>O design lúdico é da autoria de Pedro Ribeiro, que também dirige, e adapta-se a uma noite que é, em parte, uma ousada experiência de escala – a ópera dura pouco mais de uma hora mas parece épica… uma ópera que é uma pérola.”</strong> <em>(Goldilocks and the Tree Little Pigs) Kate Kellaway | The Guardian</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Encenada de uma forma simples mas marcante pelo realizador-designer Pedro Ribeiro… é uma obra subtil e bem conseguida“</strong> <em>(Mozart e Salieri)</em> George Hall | Opera Magazine</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Ribeiro, no entanto, tem o cuidado de contar a história com habilidade e clareza… As crianças ficarão hipnotizadas, mas os adultos também”</strong> (El Gato com Botas) Richard Morrison | The Times ****</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Auxiliada pela regência de Rustioni e pela encenação discreta e eficaz de Ribeiro, esta foi uma noite brilhante no teatro…”</strong> <em>(Viaggio a Reims) Robert Hugill | Opera Today</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“O encenador Pedro Ribeiro conseguiu impressionar o seu público com a beleza e a dor da morte, da vida e do amor”</strong> <em>(Les Nuits d’Ete) Katy S Austin | Bachtrack</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Ao criar uma “mentira” credível, a “verdade” de cada peça transpareceu em cada gesto e palavra claramente enunciada, estabelecendo um vínculo imediato com os intérpretes. La Boheme foi extremamente envolvente e (fiquei feliz por ver que não fui o único a chorar quando terminou).”</strong> <em>Clive Burton | Theatre World Internet Magazine</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“A ópera Mozart e Salieri nunca tinha sido apresentada em Covent Garden. A produção astuta do Sr. Ribeiro deu-lhe uma forte introdução.”</strong> <em>John E de Wald | Ópera Britânia ****</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“O público lisboeta rendeu-se aos encantos desta versão do Fantasma da Ópera (…) apesar de ser uma versão concerto, a interpretação, os músicos, a encenação foram tão bem dirigidos e envolventes que muitas vezes nos esquecemos que não é a versão original encenada a que estamos a assistir. A não perder.”</strong> <em>| Elsa Furtado, Revista Online C&amp;H</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Uma produção simples mas excelente de Pedro Ribeiro. (…) A não perder.”</strong> <em>(Mozart e Salieri) Mark Ronan | markronan . wordpress</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Nesta estupenda reposição a marca do encenador Pedro Ribeiro, está bem em evidência.”</strong> <em>(La Traviata) Rivka Jacobson | PlaysToSee *****</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>"A produção de Ribeiro – fatos e preto, com uma excelente iluminação dando a sensação certa de melodrama, sombras e escuridão – pareceu-me captar muito bem esta pequena peça assustadora.”</strong> <em>(Mozart e Salieri) | Notas de Ópera</em></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>“Uma encenação deslumbrante de Pedro Ribeiro. Os críticos concordam que este espetáculo provou a capacidade de Portugal para encenar grandes produções.”</strong> <em>(O Fantasma da Ópera) | Broadwayworld</em></p>', '<p class="font_8"><a href="https://www.operabase.com/pedro-ribeiro-a30796/en"><strong>OPERABASE PROFILE</strong></a></p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>
<p class="font_8"><a href="https://stagedirector.net/"><strong>PORTFOLIO ONLINE</strong></a></p>
<p class="font_8"><br></p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

