-- Row 10: André Cunha Leal
INSERT IGNORE INTO users (id, email, password, role) VALUES ('e7a69a0a-b248-4494-91f3-fc4bc1a98839', 'wix-e7a69a0a@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('1e106280-7a1f-4e90-aeb5-286e0daca7d7', 'e7a69a0a-b248-4494-91f3-fc4bc1a98839', 'andre-cunha-leal', 'André Cunha Leal', 'André', '961253909', '1980-03-29', 'Portugal', 'Portugal', 'Lisboa', 'Av. João Paulo II 9, R/C A', NULL, '1950-153', 'Diretor Artístico e Produtor', 'A Direção Artística é a arte de orquestrar visões, construir pontes, transformar ideias em experiências que nos tocam e inspiram.', 'https://static.wixstatic.com/media/7b859e_72c7d2828d6140638e3f5e34244990aa~mv2.jpg', 'wix:document://v1/e7a69a_8b2a146aee2b4dbcadbbb3da6229d7aa.pdf/C%C3%B3pia%20de%20CV%20andr%C3%A9%20cunha%20leal.pdf', 'https://www.facebook.com/andre.leal', 'https://www.instagram.com/andrecunhaleal/', 'https://www.proart.art', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8">No meu percurso já fiz um pouco de tudo, sempre ligado à música: trabalhei no Gabinete de Actividades Culturais da Reitoria da Universidade de Lisboa, ajudei a produzir espetáculos e temporadas, voltei a uma loja de música, fui aprender canto, cantei como coralista em grupos de câmara, em grandes obras corais-sinfónicas e em óperas e, entretanto, cheguei à Antena 2, onde também já fiz um pouco de tudo e à qual me tenho dedicado desde 2003/2004, rodeado de música e de pessoas que gostam de música.&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">Desde Setembro de 2012 que dei mais uma passo nesta vida ligada à música ao ter sido <strong>convidado para consultor da Administração do Centro Cultural de Belém para a música erudita e depois para o lugar de programador</strong>, o que me permitiu desde então estreitar laços com a comunidade musical e, ao mesmo tempo, aprofundar toda a minha experiência de trabalho com a música no campo da programação.&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">Fiz a direção Artísica dos Dias da Música que muito me encheram de alegria e, a partir daí, chegaram novos convites: Direção Artística do Cistermusica, do Festival de Castelo de Vide e do Festival de Ópera de Óbidos. Na RTP colaboro com uma equipe maravilhosa, responsável por um dos projetos mais importantes em que pude trabalhar e que é a RTP Palco, plataforma digital dedicada à cultura e que nasceu em plena pandemia.&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">E por fim, tudo parece ter-se encaminhado na vida para chegar ao meu grande desafio do momento que é <strong>a Direção Artística da ProART </strong>que assumi em 2023 com a ambição de tornar este num projeto único e singular para edificar pontes e fomentar colaborações entre os agentes artísticos, envolvendo artistas, instituições culturais e educativas, produtores, patrocinadores e mecenas.</p>', '<p>Recuando no tempo, até ao início dos anos 80, uma das minhas primeiras memórias tem precisamente que ver com música. Não devia ter mais de três anos. Já na altura o meu pai contava-me histórias onde o solista do “Poème” de Chausson seria o protagonista de uma qualquer aventura imaginada por ele. Mas não é do “Poème” que resulta essa memória tão longínqua. Lembro-me que estava na sala e os meus pais estavam a ouvir um disco com os grandes coros de ópera. Fiquei absolutamente fascinado pela bigorna do “Trovador”, pela marcha triunfal da “Aida”, pelo coro à boca fechada de “Madama Butterfly” e pelos coros empolgantes do “Navio Fantasma”. Mais tarde, ainda na infância, fiz outra grande descoberta: a Carmen de Bizet cantada pela meio-soprano Grace Bumbry. Foi uma paixão tal, que gastei o vinil de tanto o ouvir.</p><p> </p><p>Paralelamente a isto, cresci a ver os grandes musicais americanos na televisão. Se as canções que marcavam estes filmes me transmitiam uma enorme sensação de felicidade, terá sido também com estes musicais que acabaria por descobrir o poder narrativo da música sem palavras – tudo fazia sentido no “Americano em Paris” dançado por Gene Kelly.</p><p> </p><p>Começava então a desenvolver as minhas primeiras noções musicais, confirmadas por Leonard Bernstein nos seus concertos comentados. Na minha família, crescia sob a influência de todo o género de músicas: o meu avô Artur ficava horas nos seus banhos de imersão a ouvir os discos com o José Carreras; a minha avó Ester na biblioteca a ouvir a música orquestral de Wagner, Beethoven e Mahler; o meu pai com a sua paixão dividida entre a música clássica e o jazz, mas também a bossa nova que me chegava através de uma cassete de um concerto da Maria Bethânia com o Caetano Veloso, o Chico Buarque e a Nara Leão; a música típica da Beira-Baixa que me chegava da Vila de Aranhas, que é a terra da Lurdes que tomava conta de mim; a minha mãe que me mostrava também através da música a minha herança luso-cabo-verdiana com as mornas do Bana e com os Fados da Amália. Um dia que nunca mais me esquecerei, a minha mãe e as minhas tias, emocionadas, cantavam uma morna do meu bisavô e assim descobria com alguma emoção que também havia quem tivesse escrito música na minha família.</p><p> </p><p>Foi no meio de tudo isto que fui construindo aquela que é a minha personalidade. Entretanto fui aprender (mal) Piano… Aos 12 anos descobri a Temporada de Música da Fundação Calouste Gulbenkian com um “Elias” apresentado na Basílica da Estrela. O Fascínio foi tal que me tornei num adepto, quase bairrista da Orquestra Gulbenkian, para o jovem André, “a melhor orquestra do mundo”. Em 1994 comprei o meu primeiro CD: “O Barbeiro de Sevilha” com Maria Callas. Estávamos em plena ascensão do mercado dos CD e lembro-me de um dia ir a caminho da casa da minha avó Guta e do meu avô Luís a pensar que através dos CD, que comprava ali na Valentim de Carvalho do Fonte Nova, poderia realizar <span style="font-weight:bold">um desejo que entretanto se tinha apossado de mim durante a escuta de um programa de rádio: ter acesso a todas as músicas e todos os compositores de todo o mundo. </span>Mal sabia no que me estava a meter! Daí a deixar de lanchar na escola para poupar o dinheiro que a minha mãe me dava para comer, para comprar CD, foi apenas uma questão de semanas – hoje, sei que jamais chegarei a rico dado o meu apetite voraz por música. Enfim… aspiro a outras riquezas.</p><p> </p><p>Mas 94 foi também muito importante por causa da “Lisboa 94, Capital Europeia da Cultura”, onde pude ver as primeiras óperas representadas e, ainda por cima, portuguesas: “O Doido e a Morte” de Alexandre Delgado e “As Damas Trocadas” de Marcos de Portugal. Começava aí uma nova paixão: a da música portuguesa. Desde então alimento o sonho de algum dia poder vir a colaborar para uma definitiva consagração dos nossos compositores e das nossas obras. Mas esse ano foi mais do que descobrir os compositores portugueses: <span style="font-weight:bold">esse ano passaria por mim deixando uma profunda admiração pelos artistas portugueses.</span></p><p> </p><p>Em 1995 entrei no <span style="font-weight:bold">liceu D. Pedro V</span> que seria crucial para o desenvolvimento desta paixão pela música. Apesar de estar no liceu para estudar ciências, as melhores recordações que tenho desses anos, foi o tempo que passei no Coro dirigido pelo professor João. Se já tinha a experiencia do piano, no liceu D. Pedro V descobria o prazer de fazer música em conjunto, algo que ainda hoje considero inultrapassável. Foi no liceu, e graças ao coro, que pude trabalhar pela primeira vez com uma orquestra e pisar um “palco a sério”. Para além do coro, o liceu D. Pedro V tinha outra vantagem: dava para ir a pé até à Fundação Calouste Gulbenkian. A partir daí tornava-me num ávido consumidor de concertos, não faltando a nenhum: Terças e Sextas na Gulbenkian ao que acrescentei os da Metropolitana na Aula Magna e no Palácio de Queluz e as óperas do São Carlos. <span style="font-weight:bold">Fazia planos na cabeça para grandes festivais com todos os músicos portugueses….</span></p><p> </p><p>A entrada na Faculdade foi também mais um passo em direção à música: entrava no <span style="font-weight:bold">Coro da Universidade de Lisboa</span>. Para além do reportório que trabalhei com os maestros José Robert e Pedro Teixeira, fiquei a conhecer uma outra face da música, ou melhor, do espetáculo: logo no primeiro ano ajudei a montar e a produzir uma série de concertos e espetáculos para serem apresentados na Aula Magna. Nascia assim uma nova paixão: a da produção – <span style="font-weight:bold">ter uma ideia, trabalhá-la e envolver as pessoas numa permanente construção (e às vezes desconstrução) até ao momento do aplauso final, resulta numa sensação avassaladora</span>. Nesse ano, em 1999, enquanto estudava começava também a trabalhar na para a FNAC do Colombo, na altura essencialmente uma loja de livros e discos.</p><p> </p><p><span style="font-weight:bold">Desde então tenho feito um pouco de tudo, sempre à volta da música: trabalhei no Gabinete de Actividades Culturais da Reitoria da Universidade de Lisboa, ajudei a produzir espetáculos e temporadas, voltei a uma loja de música, fui aprender canto, cantei como coralista em grupos de câmara, em grandes obras corais-sinfónicas e em óperas e, entretanto, cheguei à Antena 2, onde também já fiz um pouco de tudo e à qual me tenho dedicado desde 2003/2004, rodeado de música e de pessoas que gostam de música. </span>Desde Setembro de 2012 que dei mais uma passo nesta vida ligada à música ao ter sido <span style="font-weight:bold">convidado para consultor da Administração do Centro Cultural de Belém para a música erudita e depois para o lugar de programador</span>, o que me permitiu desde então estreitar laços com a comunidade musical e, ao mesmo tempo, aprofundar toda a minha experiência de trabalho com a música no campo da programação. <span style="font-weight:bold">Fiz a direção Artísica dos Dias da Música que muito me encheram de alegria e, a partir daí, chegaram novos convites: Direção Artística do Cistermusica, do Festival de Castelo de Vide e do Festival de Ópera de Óbidos.</span></p><p> </p><p><span style="font-weight:bold">Na RTP colaboro com uma equipe maravilhosa, responsável por um dos projetos mais importantes em que pude trabalhar e que é a RTP Palco, plataforma digital dedicada à cultura e que nasceu em plena pandemia.</span></p><p> </p><p>E por fim, tudo parece ter-se encaminhado na vida para chegar ao meu grande desafio do momento que é <span style="font-weight:bold">a Direção Artística da ProART que assumi em 2023 com a ambição de tornar este num projeto único e singular para edificar pontes e fomentar colaborações entre os agentes artísticos, envolvendo artistas, instituições culturais e educativas, produtores, patrocinadores e mecenas.</span></p>', '<p>Diretor Artístico da ProART desde 2023, Programador de Música Clássica e Diretor Artístico do Festival “Dias da Música em Belém” no Centro Cultural de Belém entre 2012 e 2022, Autor e Realizador da Antena 2 desde 2003, Curador de conteúdos da plataforma on-line RTP Palcos desde 2020, e Diretor Artístico do Festival de Alcobaça, também entre 2020 e 2024, André Cunha Leal trabalha em produção e programação desde 1999, tendo tido a sua primeira experiência na área da produção ainda enquanto membro do Coro da Universidade de Lisboa e que resultou na apresentação de uma grande Cantata Cénica, encenada e coreografada, durante 4 noites seguidas na Aula Magna da Universidade de Lisboa.</p><p> </p><p>Esta experiência no Coro da Universidade de Lisboa, permitiu-lhe ficar a trabalhar no Gabinete de Atividades da Universidade de Lisboa durante dois anos. Em 2003 é convidado para colaborar na Antena 2 como coautor do programa “Que Música é Esta?”, programa que o levou a ficar efetivamente ligado à Antena 2 como responsável dos programas de ópera (Diretos e Gravados), e pelos programas de concertos ao vivo, primeiro como parte da equipe do “Concerto Aberto” e depois como responsável pelos “Concertos Antena 2”.</p><p> </p><p>Só no âmbito dos Concertos para a Antena 2, André Cunha Leal programou e produziu mais de 800 concertos desde que começou a trabalhar nos Concertos da Antena 2. Todo este trabalho possibilitou-lhe contactar com centenas de artistas e dezenas de instituições de norte a sul do país, com os quais estabeleceu protocolos, desde Teatros a Universidades, passando por Museus, Autarquias, Escolas e Conservatórios.</p><p> </p><p>A Antena 2 permitiu-lhe igualmente trabalhar em alguns dos mais importantes Festivais do Mundo, como o Festival de Salzburgo, o Festival de Bayreuth, os PROMS da BBC e a Folle Journée de Nantes. Através da União Europeia de Rádio (EBU), pôde ainda participar em sessões de trabalho no Metropolitan Opera House de Nova Iorque, tendo tido a oportunidade de acompanhar através dos vários grupos de trabalho as principais áreas de trabalho daquela ópera: programação, produção, marketing e comunicação, arquivo e departamento educativo. Este trabalho rendeu-lhe o convite para ficar a coordenar o sub-grupo de Ópera da EBU em 2020.</p><p> </p><p>Ainda na RTP, foi convidado para integrar uma nova equipa para o desenvolvimento de uma plataforma digital dedicada às Artes Performativas em Portugal, passando a desempenhar a função de Curador de conteúdos dessa mesma plataforma, a RTP Palco. Foi o trabalho desenvolvido na Antena 2 que o levou a ser convidado em 2012 primeiro para o lugar de consultor da Administração do CCB para a música erudita e depois para o lugar de programador, tendo como responsabilidade a temporada de Música Erudita que inclui as Temporadas da Orquestra Sinfónica Portuguesa e da Orquestra Metropolitana de Lisboa e a direção artística do Festival “Dias da Música em Belém”.</p><p> </p><p>André Cunha Leal chegou a cantar como coralista em várias obras corais-sinfónicas, coros de câmara e diversas produções de ópera independentes. Como reconhecimento do seu trabalho na Antena 2 e no CCB, tem sido frequentemente convidado para integrar júris de concursos de música em Portugal e Espanha. Tem igualmente desenvolvido uma série de conferências e viagens temáticas em parceria com o Centro Nacional de Cultura e o Circulo Richard Wagner.</p><p> </p><p>Em 2020 foi convidado para assumir a Direcção Artística do Festival de Alcobaça -  Cistermúsica, sucedendo assim a Alexandre delgado nessa função, em 2021 para assumir a Direção Artística do Festival de Castelo de Vide e em 2023 o Festival de Ópera de Óbidos.</p><p> </p><p>Segue-se agora o grande desafio de assumir a Direção Artística da ProART, uma organização que surgiu em 2023  para edificar pontes e fomentar colaborações entre os agentes artísticos, envolvendo artistas, instituições culturais e educativas, produtores, patrocinadores e mecenas. Pretendemos desenvolver um ecossistema vibrante, criativo e inovador, capaz de ultrapassar os desafios artísticos de forma inteligente e de promover um ambiente próspero para todos, sempre comprometidos a apoiar os artistas e parceiros a vencer obstáculos, tecer redes de contactos essenciais ao seu desenvolvimento, proporcionando simultaneamente às instituições e mecenas a oportunidade de investir em procjetos artísticos relevantes e transformadores que enriquecem a sociedade e inspiram a mudança.</p>', NULL, 'https://static.wixstatic.com/media/e7a69a_c48ff4b8930b4768887608ff692ac910~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_b12823f7497b40d781ed14d820748565~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_750b1a1432ec47a080f0bdd38bf595c7~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_5b32c45cbb4448b7a005b17849fbee92~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_dd8057a8ce2346d8b2359156ece9cfdb~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_d8e5bafaa4e449f89309fd4a079f65ae~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_a65aa27c432f44fabe5ba025bb06fa21~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_b6be1c14a6e9476a95d0bbca72fc9be8~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_5b33dc36547e416faa73d4cfcb8de42c~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_f3ae59041f274ec49f165f26689c0991~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_7acb4013123a4936a42c11a3b70bbd30~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/e7a69a_bd499951cb5840bea15c29433a231e19~mv2.jpeg', NULL, 1, 0, 0);

-- Row 11: Rita Raposo
INSERT IGNORE INTO users (id, email, password, role) VALUES ('a8c01641-ba74-48c1-9752-b8da25b711c4', 'wix-a8c01641@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('7eb6ff0d-a9cd-4497-adba-772be6b05b36', 'a8c01641-ba74-48c1-9752-b8da25b711c4', 'mezzo-rita', 'Rita Raposo', 'Rita', '''+34644552358', NULL, 'Portugal', 'Spain', 'Toledo', 'Calle Arroyo 11 Bloque 3 1ºF', 'Rua do Mercado, 177 Arcozelo Vila Nova de Gaia', '45400', 'Mezzosoprano', NULL, 'https://static.wixstatic.com/media/7b859e_c91642f87bb34d6ea4309a85e2fbc402~mv2.jpg', 'wix:document://v1/a8c016_bc08e8045c1e47cdb9baa0858fa37f6b.pdf/BIO%20PT.pdf', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://youtu.be/XBvS84sZDBA', 'https://youtu.be/4nQFQpOHLJQ', 'https://youtu.be/jHY4Tah9skU', 'https://youtu.be/qGGBV0UUBxo', 'https://youtube.com/shorts/zpCmWrgOQAA', 'https://youtu.be/Uw-CT4ivY8s', NULL, NULL, NULL, NULL, '<p>Rita Raposo é uma talentosa mezzosoprano portuguesa, nascida no Porto em 1997. Formada pela Universidad Alfonso X el Sabio em Madrid, onde concluiu o mestrado em Interpretação e Investigação Performativa na vertente de canto lírico, sob orientação de professores renomados.</p><p> </p><p>A sua voz cativante já brilhou em palcos prestigiados de Portugal, Espanha e outros países, interpretando desde árias e fragmentos operísticos até recitais a solo. Destaque para sua atuação em &quot;Carmen&quot; de Bizet com orquestra e o &quot;Stabat Mater&quot; de Pergolesi.</p><p> </p><p>Colaborando ativamente com projetos musicais, Rita também integra, como reforço,  o coro do Teatro Nacional de São Carlos em Lisboa, consolidando a sua trajetória ascendente no universo lírico.</p><p> </p><p>No apartado <span style="font-style:italic">Carreira</span> é possível seguir os seus próximos compromissos. </p><p> </p>', '<p>Rita Raposo é uma mezzosoprano natural do Porto, Portugal. Desde muito jovem que é apaixonada pela música, presenteando a sua família e amigos desde pequena com fados e músicas do cancioneiro português.</p><p> </p><p>Aos 4 anos de idade começou a estudar música numa Academia perto da sua residência e aos 6 anos escolheu como seu instrumento o violino. Este instrumento acompanhou-a durante muitos anos, tendo estudado na Escola Profissional de Música de Espinho e mais tarde feito a sua Licenciatura em Madrid, Espanha.</p><p> </p><p>O seu primeiro contacto com o canto lírico foi em 2016, no seu último ano em Espinho. Para além do seu desejo em aprender a cantar, a sua curiosidade estava em entender o que queriam dizer os seus professores com a frase &quot;tens de tocar como um cantor&quot;.</p><p> </p><p>Após os seus estudos superiores, ingressa na Universidad Alfonso X el Sabio no Mestrado de Interpretação e Investigação Performativa, na variante de canto lírico, com o professor Francisco Santiago.</p><p> </p><p>Atualmente, trabalha como reforço no Coro do Teatro Nacional de São Carlos e colabora com várias produtoras de ópera e zarzuela espanholas. </p><p> </p>', '<h2><span style="font-weight:bold">Linha do Tempo</span></h2><h2> </h2><p>2017 - Estreia como solista, <span style="font-style:italic">Erbarme dich mein Gott. </span>Direção de Roberto Valdés, Portugal.</p><p>2019 - Seleção de árias de <span style="font-style:italic">Carmen</span> de Bizet, Espanha.</p><p>2021 - <span style="font-style:italic">Stabat Mater </span>de Pergolesi, Espanha.</p><p>2023 - Concerto Candlelight, <span style="font-style:italic">De la Zarzuela a Rosalía. </span>Recital no Casino Militar de Gran Vía, Madrid. Incorpora o coro da companha Clásicos de la Lírica e o coro da Producciones Telón, Espanha. Ganha uma das vagas de reforço para o Coro do Teatro Nacional de São Carlos, Portugal.</p><p>2024 - Tour por Espanha com a produção de <span style="font-style:italic">Nabucco</span> de Producciones Telón. Apresentação do seu projeto <span style="font-style:italic">Rêves d&#x27;Amour</span> com a jovem pianista premiada, Noelia Navas em Murcia. Concierto <span style="font-style:italic">De la Verbena a la Gran Vía, </span>Espanha. Debut dos papéis Ines, em Il Trovatore e Flora em La Traviata, de Verdi, em Portugal e Espanha.</p><p>2025 - Admitida na Belcanto Academy Opera Studio Trentino, em Itália. Debut de Mercedes, em Carmen, em Portugal e Espanha.</p><p> </p><h2><span style="font-weight:bold">Próximos compromissos:</span></h2><p> </p><p><span style="font-weight:bold">2024</span></p><p><span style="font-weight:bold">Inez, <span style="font-style:italic">Il Trovatore</span></span> no Centro de Artes e Congressos, Águeda (12/10); no Casino do Estoril (13/10); no Coliseu AGEAS Porto (14/10) e no Coliseu dos Recreios Lisboa (15/10) - Portugal.</p><p><span style="font-weight:bold">Flora, <span style="font-style:italic">La Traviata</span></span> em Majadahonda (25/10); em Andújar (26/10) e em La Eliana (27/10) - Espanha.</p><p><span style="font-weight:bold">Concerto de Natal </span>com Sapere Aude Ensemble em Ajalvir (19/12) e em Alcalá de Henares (20/12) - Espanha.</p><p> </p><p> </p><p><span style="font-weight:bold">Clásicos de la Lírica:</span></p><p>maio 2023 - <span style="font-style:italic">Marina</span> de E. Arrieta</p><p>agosto 2023 - <span style="font-style:italic">La Revoltosa</span> de R. Chapí</p><p>outubro 2023 - <span style="font-style:italic">La Tabernera del Puerto</span> de P. Sorozábal</p><p> </p><p><span style="font-weight:bold">Producciones Telón:</span></p><p>novembro 2023 a abril de 2024 - <span style="font-style:italic">Nabucco</span> de G. Verdi</p><p>agosto 2024 - <span style="font-style:italic">La Traviata</span> de G. Verdi</p><p> </p><p><span style="font-weight:bold">Teatro Nacional de São Carlos:</span></p><p>fevereiro 2024 - 9º Sinfonia de L. van Beethoven</p><p>abril 2024 - Requiem Pelas Vítimas do Fascismo de F. Lopes-Graça</p><p>maio 2024 - 4ª Sinfonia de J. Braga Santos</p><p>junho 2024 - <span style="font-style:italic">Trilogia das Barcas</span> de J. Braga Santos</p><p>setembro 2024 - 8ª Sinfonia de G. Mahler</p><p> </p><p> </p><h2><span style="font-weight:bold">Formação complementar</span></h2><p> </p><p>Recebeu conselhos dos professores e cantores Isabel Alcobia, Laura Ballestrinos, Francisco Santiago, Carlos Álvarez, Celsa Tamayo, entre outros.</p><p> </p>', NULL, 'https://static.wixstatic.com/media/a8c016_5f2eb738a9124292b0d400344ebf7bb0~mv2.jpg', '''@apfilmsprodutora', 'https://static.wixstatic.com/media/a8c016_87fd3bd9914c406699fd42b6e6dfe512~mv2.jpg', 'Recital Casino de Águilas', 'https://static.wixstatic.com/media/a8c016_7ab21d70e83b49ba9ff443f756ea01ea~mv2.jpg', '''@apfilmsprodutora', NULL, NULL, 'https://static.wixstatic.com/media/a8c016_c5288c58aecb4109a7842594d7d7fbe2~mv2.jpg', '''@apfilmsprodutora', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1);

-- Row 12: Alexandre Delgado
INSERT IGNORE INTO users (id, email, password, role) VALUES ('2871f0ad-eb49-4fce-ba13-5e6c7b381552', 'wix-2871f0ad@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('c6ec5b33-152b-49bb-9027-1cad6ccfc6a8', '2871f0ad-eb49-4fce-ba13-5e6c7b381552', 'alexandre-delgado', 'Alexandre Delgado', 'Alexandre', '999999999', '1994-07-02', 'Portugal', 'Portugal', 'Lisboa', 'xxxx xxxxx', NULL, '1800107', 'Compositor e Violetista', 'A música deve ter a capacidade de contar uma história, com temas e personagens que fiquem na memória', 'https://static.wixstatic.com/media/2871f0_c9ef579d2cc5493a96075f5c265fed66~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/2871f0_bf13ed8a70544b3bb330666fd0048697.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=fhwKIHgo_7s', 'https://www.youtube.com/watch?v=8ej8YL9Fre8', 'https://www.youtube.com/watch?v=nmVAHTYuJFE', 'https://www.youtube.com/watch?v=nibnvREyiw8', 'https://www.youtube.com/watch?v=zv8NfK_fD_M', 'https://www.youtube.com/watch?v=fz9Zwzncg-Y', 'https://www.youtube.com/watch?v=pPzSGL44fas', NULL, NULL, NULL, '<p class="font_8" style="text-align: justify">Alexandre Delgado é um dos compositores portugueses mais proeminentes e criativos da atualidade. O seu trabalho audacioso tem expandido os caminhos da música erudita contemporânea, numa fusão entre a <strong>tradição tonal</strong> e uma <strong>linguagem contrapontística e moderna</strong>.</p>
<p class="font_8"><br>
Para Alexandre Delgado, a <strong>melodia ocupa um lugar central</strong> na sua conceção musical, sendo de preferência memorizável e cantável. Gosta de compor sobrepondo várias <strong>linhas melódicas que se interligam</strong>, criando <strong>obras com forte caráter temático e narrativo</strong>.</p>
<p class="font_8"><br></p>
<p class="font_8">O seu repertório abrange desde obras de música de câmara a grandes obras vocais e orquestrais, com destaque para as óperas de câmara <em><strong>O Doido e a Morte</strong></em><strong> (1993)</strong> e <em><strong>A Rainha Louca</strong></em><strong> (2009)</strong>, aclamadas pela crítica e levadas à cena múltiplas vezes em Portugal e no Brasil.</p>
<p class="font_8" style="text-align: justify"><br></p>
<p class="font_8">Em 2014, no âmbito da comemoração dos 25 anos do 25 de Abril, estreou a <strong>ópera </strong><em><strong>Felizmente Há Luar!</strong></em>, que a revista <a href="https://operawire.com/teatro-sao-luiz-2024-felizmente-ha-luar/" target="_blank"><u><strong>OperaWire</strong></u></a> classificou como "<strong>uma extraordinária nova ópera</strong>".</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">"Alexandre Delgado tem um profundo conhecimento e prazer pela composição instrumental, cujo rigor e eficácia revelam uma dimensão estruturada e apaixonada que determina o seu «pensamento» de compositor.” José Ribeiro da Fonte</p>', '<p class="font_8" style="text-align: justify">"O que sinto intuitivamente desde que aprendi música é que a música, de todas as artes, é aquela que mais diretamente exprime milhões de coisas." Alexandre Delgado</p>
<p class="font_8"><br></p>
<p class="font_8">Alexandre Delgado nasceu em Lisboa em 1965 e desde tenra idade revelou um profundo interesse pela música. Foi uma professora da escola preparatória, a pianista <strong>Fátima Fraga</strong>, quem o incentivou a ingressar na <strong>Fundação Musical dos Amigos das Crianças</strong> quanto tinha 12 anos, aí começando os seus estudos de violino. A experiência de tocar num concerto da orquestra da escola, apenas um ano depois, foi decisiva para que desejasse seguir a carreira musical.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Paralelamente às aulas de música, começou a compor de forma intuitiva, encorajado pela sua professora de solfejo, <strong>Deodata Henriques</strong>. As suas primeiras peças, escritas sem conhecimentos formais de composição, eram interpretadas pelos colegas e uma delas chamou a atenção do compositor Joly Braga Santos, com quem estudou como aluno particular entre 1981 e 1986.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Sob a orientação de Joly, desenvolveu as bases tradicionais da composição, estreando em 1982 <em><strong>Prelúdio para Cordas</strong></em>, de cunho modal, e em 1984 <em><strong>Três Momentos para Orquestra</strong></em>, com laivos dodecafónicos. Após completar o curso geral do Conservatório de Lisboa, obteve uma bolsa da Secretaria de Estado da Cultura para estudar em França, entre 1986 e 1989, com <strong>Jacques Charpentier</strong>, compositor que contribuiu para enriquecer a sua linguagem. Este período de expansão viu nascer obras como o <em><strong>Concerto para Flauta</strong></em>, de cunho impressionista e neoclássico, e <em><strong>Evoluções na Paisagem</strong></em> para orquestra, ponto extremo de abstração atonal na sua produção, que lhe valeu o 1º Prémio de Composição do Conservatório de Nice em 1990 e o Prémio João de Freitas Branco / Fidelidade em 1992.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">A partir de 1990 Delgado desenvolveu uma escrita mais idiomática para cada instrumento, conjugando cromatismo e liberdade rítmica com a utilização de notas pivô ou centros tonais. Duas obras desse período, <a href="https://open.spotify.com/album/4hbpfAdOFE6ZTwXugBXZyi?si=ymUBXp1OSLyccL1D11fKYw" target="_blank"><u><em><strong>Langará</strong></em></u></a> para clarinete e <a href="https://open.spotify.com/album/1zU0QXAmM5Ol68Vp8cdix7?si=Uq8FyLSrS0SNl0WpX_JY3w" target="_blank"><u><em><strong>The Panic Flirt</strong></em></u></a> para flauta, tornaram-se parte do reportório desses instrumentos a nível internacional, com numerosas gravações em CD. Essa fase culminou na ópera de câmara <a href="https://open.spotify.com/album/1QVvdvJ55RPa8kUTyxKvfu?si=xdIUhYasS1a6O1-RveF_tg" target="_blank"><u><em><strong>O Doido e a Morte</strong></em></u></a>, estreada em Lisboa em 1994, farsa tragi-cómica em que revelou a sua veia teatral, explorando ao máximo a independência das vozes. Ópera em forma de variações, é construída a partir de um pequeno motivo melódico de cinco notas, de acordo com o seu princípio de desenvolver cada obra organicamente a partir de uma célula primordial.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">O <em><strong>Concerto para Viola e Orquestra</strong></em><strong> </strong>marca, no ano 2000, a sua transição para uma linguagem menos dissonante e mais harmónica, que oscila livremente entre o tonal, o modal e o cromático, conservando a essência contrapontística, a primazia melódica e a pulsão rítmica que lhe são características. Além da ópera <em><strong>A Rainha Louca</strong></em><strong> </strong>(2009)<em>,</em> podem destacar-se obras como <em><strong>Poema de Deus e do Diabo</strong></em> para baixo e grupo instrumental (2001), <em><strong>Canteto</strong></em><strong> </strong>para quinteto com contrabaixo (2007), <em><strong>Santo Asinha</strong></em> para barítono e orquestra (2010), <a href="https://open.spotify.com/album/0QdWkptl2B5ez78K3BrTgw?si=jnGkzm4iSiKxBbtS60O03A" target="_blank"><u><em><strong>Trio Camoniano</strong></em></u></a><strong> </strong>para voz e/ou trio com piano (2012), <em><strong>Sonata ‘Adamastor’</strong></em><strong> </strong>para tuba e piano (2017), <em><strong>Samambaia</strong></em> para acordeão e <a href="https://open.spotify.com/album/2vnR7QTdLxKy9GCKPS8J7N?si=V3XdxngqQCW7TJG8rOzceQ" target="_blank"><u><em><strong>Quarteto de Cordas</strong></em></u></a> (2019), <em><strong>Vida e Milagres de Dona Isabel</strong></em><strong> </strong>para soprano e orquestra (2019) e uma versão musico-teatral de <em><strong>Rei Lear </strong></em>para quinteto, tenor e cinco atores (2019), entre muitas outras obras.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Várias partituras para orquestras e coros de crianças que compôs a partir de 2014 revelam uma particular sintonia com o universo infantil, com destaque para as cantatas <em><strong>O Pequeno Abeto</strong></em> e <em><strong>O Soldadinho de Chumbo</strong></em><em>, </em>baseadas em Andersen, e para a cantata <em><strong>Balada dos Quatro Cantos</strong></em>, que compôs em 2023 para um coro multi-étnico de 100 crianças de um bairro social da Amadora.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Com encomendas regulares de Portugal e do estrangeiro, Alexandre Delgado dedica-se hoje sobretudo à composição mas, ao longo de quatro décadas, também foi ativo como instrumentista, maestro, radialista, divulgador, musicólogo, programador e tradutor de libretos.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify"><strong>Aluno em violeta de Barbara Friedhoff</strong>, terminou o curso do instrumento em França e venceu o Prémio Jovens Músicos em 1987. Foi membro da Orquestra de Jovens da União Europeia, onde tocou sob a direção de Claudio Abbado e Zubin Mehta. Fez parte da <strong>Orquestra Gulbenkian</strong>, do <strong>Quarteto Lacerda</strong> e do <strong>Quarteto com Piano de Moscovo</strong>, com o qual realizou centenas de concertos entre 2005 e 2019. Estreou como solista o concerto <em><strong>The vigil of the angels</strong></em><em> </em>de Ivan Moody, que lhe é dedicado, bem como o seu concerto para viola e orquestra, que tocou em Portugal, em Espanha e na Holanda.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Como <strong>maestro</strong>, começou aos 18 an<strong>os a dirigir a Orquestra de Iniciados da FMAC</strong> <strong>e dirige atualmente as duas orquestras da Academia de Música de Lisboa</strong>. Além de muitos concertos com obras de sua autoria, dirigiu várias produções da ópera <em>O Doido e a Morte </em>em Portugal, na Alemanha e no Brasil, a mais recente delas no Rio de Janeiro, onde a Sala Cecília Meirelles lhe dedicou um concerto monográfico em 2022.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Como <strong>radialista e divulgador</strong>, assina desde 1996 o programa “<strong>A Propósito da Música</strong>” na Antena 2, dedicado à vida e às obras dos compositores mais importantes da tradição ocidental. É também convidado regularmente como palestrante e comentador de concertos.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Como <strong>musicólogo</strong>, deve-se-lhe a <strong>coordenação </strong>e a <strong>co-autoria do livro "Luís de Freitas Branco” (2005)</strong>, primeira obra de fundo dedicada ao introdutor do modernismo musical em Portugal, sobre o qual fez conferências em Itália e Espanha. É também autor dos livros <em><strong>A Sinfonia em Portugal</strong></em><strong> </strong>e <em><strong>A Culpa é do Maestro</strong></em><strong>,</strong> compilação de críticas musicais que assinou no <em>Diário de Lisboa </em>e no <em>Público</em> entre 1990 e 2001.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Como programador, foi <strong>diretor artístico do Cistermúsica / Festival de Música de Alcobaça</strong> entre 2002 e 2019, concebeu ciclos de música de câmara para a Artemrede e para as câmaras de Oeiras e de Cascais e programou o <strong>Festival Luís de Freitas Branco</strong>, com a 1ª audição integral da obra desse compositor. Como tradutor, assinou aclamadas versões portuguesas das óperas <em>Hansel e Gretel, A Flauta Mágica</em>, <em>A Bela Adormecida, O Pequeno Limpa-Chaminés </em>e <em>La Serva Padrona. </em>Neto do general Humberto Delgado, Alexandre Delgado é bisneto de Carlos de Andrade (1884-1930), compositor modernista cuja obra deu a conhecer através de uma monografia e de um concerto realizado no CCB em 2000.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">A obra musical de Alexandre Delgado encontra-se publicada pela <strong>AvA Editions</strong>.</p>', '<p style="text-align:justify">Ao longo da sua carreira, Alexandre Delgado desenvolveu uma linguagem única que combina tradição e modernidade. O seu estilo baseia-se em linhas melódicas independentes e coerência orgânica, sendo atualmente considerado um dos grandes nomes da música erudita contemporânea portuguesa.</p><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">PRÉMIOS</span></h3><p style="text-align:justify"> </p><ul><li>1º Prémio do Curso Superior de Violeta do Conservatório de Cannes (1987)</li><li style="text-align:justify">1º Prémio Jovens Músicos da RDP (Violeta - Nível Médio) (1987)</li><li style="text-align:justify">1ª medalha do 2º ano do Curso de Composição do Conservatório de Nice (1989)</li><li style="text-align:justify">1º Prémio de Composição do Conservatório de Nice  (1990)</li><li style="text-align:justify">Prémio João Freitas Branco / Fidelidade (1992) (Prémio do Júri e Prémio da Assistência)</li><li style="text-align:justify">Medalha de Mérito do Concelho de Alcobaça (2010)</li></ul><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p> </p><p style="text-align:justify"><span style="font-weight:bold">2024 </span>– Faz a orquestração da ópera <span style="font-style:italic">Felizmente Há Luar</span>, que é estreada na Guarda e levada à cena em Lisboa, Castelo Branco, Évora, Coimbra, Braga, Faro e Santa Maria da Feira (direção de Osvaldo Ferreira, encenação de Allex Aguilera).</p><p style="text-align:justify"><span style="font-weight:bold">2023 </span>– Organiza com Salmo Faria o Festival “Se Essa Rua Fosse Minha — 1º Festival de Música e Teatro do Casal do Silva”, onde dirige a estreia da <span style="font-weight:bold"><span style="font-style:italic">Balada dos Quatro Cantos </span></span>com um coro multi-étnico de 100 crianças e se dá a estreia da sua versão portuguesa da ópera <span style="font-style:italic">La Serva Padrona</span>. Escreve o libreto e compõe a versão para canto e piano da ópera <span style="font-style:italic"><span style="font-weight:bold">Felizmente Há Luar</span>, </span>encomendada pela Orquestra Filarmónica Portuguesa. É convidado a ser professor das duas orquestras da Academia de Música de Lisboa. Execuções de <span style="font-weight:bold"><span style="font-style:italic">O Soldadinho de Chumbo</span></span> no Teatro do Campo Alegre, no Porto.</p><p style="text-align:justify"><span style="font-weight:bold">2022 </span>–  Compõe a <span style="font-weight:bold"><span style="font-style:italic">Balada dos Quatro Cantos</span></span> para um projeto apoiado pelo programa Interculturalidades da DGArtes. Estreia de <span style="font-weight:bold"><span style="font-style:italic">Tocarola</span></span> para saxofone e da <span style="font-weight:bold"><span style="font-style:italic">Suite ‘O Doido e a Morte’ </span></span>em versão para saxofone, por João Pedro Silva, no Convento dos Capuchos.</p><p style="text-align:justify"><span style="font-weight:bold">2021 </span>– Compõe <span style="font-weight:bold"><span style="font-style:italic">Melopeia</span></span> para o Ensemble Lusitanus, que faz a estreia nas Caldas da Rainha e grava a obra em CD, e <span style="font-weight:bold">Os<span style="font-style:italic"> Ingleses Fumam Cachimbo</span></span> para o Grupo de Música Contemporânea de Lisboa, que estreia a obra em Badajoz e na Nazaré. Dirige <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> na Sala Cecília Meirelles no Rio de Janeiro (encenação de Salmo Faria), no âmbito de um concerto monográfico que inclui <span style="font-weight:bold"><span style="font-style:italic">Tríptico Camoniano</span></span>, <span style="font-weight:bold"><span style="font-style:italic">Es Lisboa una Octava Maravilla </span></span>e a estreia de <span style="font-weight:bold"><span style="font-style:italic">Ciclo Quinhentista</span></span> em versão com quinteto de cordas. O Cistermúsica presta-lhe homenagem incluindo, além desse programa, a estreia da versão revista do <span style="font-weight:bold"><span style="font-style:italic">Concerto para Viola </span></span>e <span style="font-weight:bold"><span style="font-style:italic">Rei Lear </span></span>em versão declamada.</p><p style="text-align:justify"><span style="font-weight:bold">2020 –</span> Compõe o quinteto <span style="font-weight:bold"><span style="font-style:italic">Samambaia </span></span>para o João Roiz Ensemble, que faz a estreia em Castelo Branco e grava a obra em CD. Durante o confinamento devido à pandemia, faz uma revisão do <span style="font-weight:bold"><span style="font-style:italic">Concerto</span></span> <span style="font-weight:bold"><span style="font-style:italic">para viola</span></span> e adapta <span style="font-weight:bold"><span style="font-style:italic">Es Lisboa una octava maravilla</span></span> para coro e orquestra. <span style="font-weight:bold"><span style="font-style:italic">Langará</span></span> é uma das obras escolhidas para a Semifinal do 16th International Clarinet Competition Salverio Mercadante em Bari (Itália).</p><p style="text-align:justify"><span style="font-weight:bold">2019 –</span> Compõe <span style="font-weight:bold"><span style="font-style:italic">Rei Lear </span></span>para o CCB, <span style="font-weight:bold"><span style="font-style:italic">Es Lisboa una octava maravilla </span></span>para o Festival da Póvoa do Varzim (ambas destinadas ao Toy Ensemble) e <span style="font-weight:bold"><span style="font-style:italic">Vida e Milagres de Dona Isabel </span></span>para a Orquestra de Coimbra (que estreia a obra no Convento de São Francisco). <span style="font-weight:bold"><span style="font-style:italic">The Panic Flirt</span></span> é uma das obras escolhidas para o Concurso Internacional de Flauta Maxence Larrieu, em Nice.  Dirige a estreia da cantata “Frei João” de Tiago Derriça num concerto da AMAC. Última edição como diretor artístico do Cistermúsica.</p><p style="text-align:justify"><span style="font-weight:bold">2018 –</span> Termina <span style="font-weight:bold"><span style="font-style:italic">O Soldadinho de Chumbo </span></span>e dirige a estreia com o coro e as orquestras da AMAC no Tivoli e na Casa da Música. Compõe <span style="font-weight:bold"><span style="font-style:italic">O Romance da Raposa</span></span> para um espetáculo de Teresa Gafeira no Teatro de Almada. Dirige a estreia no Brasil de <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span>, no Theatro da Paz em Belém do Pará (encenação de Salmo Faria). Programa a ópera <span style="font-style:italic">Guerras de Alecrim e Mangerona</span> no Cistermúsica. Estreia do <span style="font-weight:bold"><span style="font-style:italic">Trio com Piano</span></span> na Casa da Música. Lançamento em CD de <span style="font-style:italic"><span style="font-weight:bold">O Doido e Morte</span>.</span></p><p style="text-align:justify"><span style="font-weight:bold">2017 –</span> Termina <span style="font-weight:bold"><span style="font-style:italic">O Pequeno Abeto </span></span>e dirige a estreia com o coro e as orquestras da AMAC, no Tivoli. Compõe <span style="font-weight:bold"><span style="font-style:italic">Tocarola </span></span>para saxofone e <span style="font-weight:bold"><span style="font-style:italic">O Soldadinho de Chumbo</span></span>. Revê o <span style="font-weight:bold"><span style="font-style:italic">Tríptico Camoniano</span></span> e faz versão alternativa como trio com piano, para um CD do Trio Pangea. Compõe a <span style="font-weight:bold"><span style="font-style:italic">Sonata Adamastor</span></span> para um CD do tubista Sérgio Carolino. Dirige <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> em versão de concerto, num concerto do Toy Ensemble que inclui <span style="font-weight:bold"><span style="font-style:italic">Poema de Deus e o Diabo </span>e <span style="font-style:italic">Tríptico Camoniano</span></span>, no CCB. Faz palestra sobre ópera portuguesa no Centre Gulbenkian em Paris. Estreia do <span style="font-weight:bold"><span style="font-style:italic">Quarteto Breve </span></span>para percussão na Universidade de Aveiro. O <span style="font-weight:bold"><span style="font-style:italic">Concerto para Flauta</span></span> é tocado por Nuno Inácio com a Orquestra Gulbenkian no Grande Auditório Gulbenkian. Programa a estreia moderna da ópera <span style="font-style:italic">Inês de Castro</span> de Giuseppe Giordani no Cistermúsica.</p><p style="text-align:justify"><span style="font-weight:bold">2016 </span> <span style="font-weight:bold">–</span>  Retoma as emissões do “A Propósito da Música” na Antena 2, analisando a integral da obra de Bach ao longo de quatro anos. Compõe <span style="font-weight:bold"><span style="font-style:italic">Instrumentário </span></span>e dirige a estreia com o coro e as orquestras da AMAC, no Tivoli. Dirige <span style="font-style:italic">O Doido e a Morte </span>em versão de concerto e<span style="font-style:italic"> Dumbarton Oaks </span>de Stravinsky com a Orquestra Metropolitana da Lisboa, no Teatro Thalia.  Dirige a estreia de <span style="font-weight:bold"><span style="font-style:italic">A Rainha Louca</span></span> no Brasil, no Festival Internacional de Música de Belém do Pará (encenação de Salmo Faria). Começa a compor <span style="font-style:italic"><span style="font-weight:bold">O Pequeno Abeto</span>.</span></p><p style="text-align:justify"><span style="font-weight:bold">2015</span> <span style="font-weight:bold">–</span> Termina <span style="font-weight:bold"><span style="font-style:italic">Baila</span></span> <span style="font-weight:bold"><span style="font-style:italic">Bailarino </span></span>e dirige a estreia no CCB, com o coro e as orquestras da AMAC.  Toca o <span style="font-weight:bold"><span style="font-style:italic">Concerto para Viola </span></span>com a Orquestra Metropolitana de Lisboa (dir. Pedro Neves).  Começa a compor <span style="font-style:italic"><span style="font-weight:bold">O Pequeno Abeto</span>. </span>É convidado a lecionar violeta na Escola Profissional da Metropolitana, onde permanece durante dois anos letivos.</p><p style="text-align:justify"><span style="font-weight:bold">2014</span> <span style="font-weight:bold">–</span> Compõe os dois primeiros números de <span style="font-style:italic"><span style="font-weight:bold">Baila Bailarino</span>. Estreia</span> de <span style="font-weight:bold"><span style="font-style:italic">Verdiana </span></span>pela Orquestra Sinfónica Portuguesa em Lisboa e do <span style="font-weight:bold"><span style="font-style:italic">Tríptico Camoniano</span></span> em Aveiro.  Dirige uma nova produção de <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> no Teatro Municipal de Almada (encenação de Rodrigo Francisco) e grava a obra para CD.  Toca o <span style="font-weight:bold"><span style="font-style:italic">Concerto para Viola</span></span> com a Filarmonia das Beiras. Programa a ópera <span style="font-style:italic">Il Mondo della luna</span> de Avondano no Cistermúsica.</p><p style="text-align:justify"><span style="font-weight:bold">2013 –</span> Compõe <span style="font-weight:bold"><span style="font-style:italic">Tríptico Camoniano</span></span> para o Ensemble Performa. Compõe <span style="font-weight:bold"><span style="font-style:italic">Verdiana</span></span> para o CCB.   Devido à crise financeira, dá-se uma interrupção de dois anos e meio no programa “A Propósito da Música” da Antena 2 e passa a dirigir a Orquestra Juvenil da AMAC (antiga FMAC), onde permanecerá como professor até 2021.</p><p style="text-align:justify"><span style="font-weight:bold">2012 – </span>Faz com o MPQ a 1ª gravação mundial em CD dos quartetos com piano de Napravnik e Rubinstein. Apresenta a integral das sinfonias de Mozart numa maratona de nove concertos dirigida por Martin André no TNSC.</p><p style="text-align:justify"><span style="font-weight:bold">2011 –</span> Compõe o <span style="font-weight:bold"><span style="font-style:italic">Ciclo Quinhentista</span></span> para o Festival Terras Sem Sombra, onde a obra é estreada pela soprano Maria Bayo com a orquestra Divino Sospiro. Dirige a Orquestra Clássica da Madeira no Funchal. Dirige a estreia da ópera <span style="font-weight:bold"><span style="font-style:italic">A Rainha Louca</span></span> no CCB.</p><p style="text-align:justify"><span style="font-weight:bold">2010 </span>- Compõe <span style="font-weight:bold"><span style="font-style:italic">Santo Asinha</span></span> para a Orquestra do Algarve, cuja estreia dirige em Albufeira. Recebe a Medalha de Mérito do Concelho de Alcobaça. Programa um “Ciclo de Música de Câmara” para a Câmara de Oeiras. Promove a estreia moderna de <span style="font-style:italic">L’Angelica </span>de João de Sousa Carvalho em Alcobaça.</p><p style="text-align:justify"><span style="font-weight:bold">2009 –  </span>Termina a ópera <span style="font-style:italic"><span style="font-weight:bold">A Rainha Louca</span>. </span>Faz recital e conferência sobre Frederico de Freitas em Roma. Toca metade dos 64 quartetos de Haydn na integral promovida pela Antena 2. Doa à Biblioteca Nacional do espólio Luís de Freitas Branco que herdou de Maria Helena de Freitas e Nuno Barreiros. Nova produção de <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> no Teatro de Almada (direção de Fernando Fontes, encenação de Joaquim Benite). Estreia das suas versões portuguesas das óperas <span style="font-style:italic">The</span> <span style="font-style:italic">Little Sweep </span>de Britten (na Gulbenkian) e  <span style="font-style:italic">La bella dormente nel bosque</span> de Respighi (no TNSC).</p><p style="text-align:justify"><span style="font-weight:bold">2008  – </span> Estreia da <span style="font-weight:bold"><span style="font-style:italic">Abertura ‘A Rainha Louca’</span></span> no festival «Prazské premiéry 2008» em Praga, dedicado às estreias europeias mais relevantes ocorridas entre 2002 e 2007. Estreia de <span style="font-weight:bold"><span style="font-style:italic">O Papagaio e a Galinha </span></span>pela OML no Zambujal. Dirige a Orquestra da Madeira e toca o <span style="font-style:italic"><span style="font-weight:bold">Concerto para Viola</span>. </span> Conferência sobre Luís de Freitas Branco no festival <span style="font-style:italic">Pórtico do Paraíso</span> em Ourense. Concertos com o MPQ em Menorca e Maiorca. Últimos concertos com o Quarteto Lacerda.</p><p style="text-align:justify"><span style="font-weight:bold">2007 –</span> Compõe <span style="font-weight:bold"><span style="font-style:italic">Canteto</span></span> para o festival Cameralia de Santiago de Compostela e <span style="font-weight:bold"><span style="font-style:italic">Sintonia</span></span> para a flautista Ana Cavaleiro. Faz a música do documentário «Camilo Pessanha: um poeta ao longe» de Francisco Manso. Programa e comenta um «Ciclo de Música Portuguesa» da Orquestra do Algarve. Recital com Bruno Belthoise em Rennes. O <span style="font-weight:bold"><span style="font-style:italic">Concerto para Violeta </span></span>é tocado por Jano Lisboa na Gulbenkian. Publicação do livro &quot;Luís de Freitas Branco&quot; (Editorial Caminho).</p><p style="text-align:justify"><span style="font-weight:bold">2006 – </span>Compõe <span style="font-weight:bold"><span style="font-style:italic">Mistério</span></span> para mezzo e piano. Programa com Guenrikh Elessine o festival «Noites de Inverno» em Cascais. Estreia da versão portuguesa d’<span style="font-style:italic">A  Flauta Mágica</span> na Gulbenkian. Inaugura o novo formato de concertos comentados da Orquestra Gulbenkian e de palestras pré-récita no TNSC. Faz a música para o documentário “Meu Pai, Humberto Delgado”, de Francisco Manso.</p><p style="text-align:justify"><span style="font-weight:bold">2005 –</span> Integra o Conselho Editorial da coleção Portugalsom (até 2006) e promove a execução e a gravação da ópera <span style="font-style:italic">As Variedades de Proteu.</span> Programa o ciclo <span style="font-style:italic">Mil Anos de Música </span>para a Artemrede. Concertos com o Quarteto Lacerda em França e Itália. Torna-se membro do Quarteto com Piano de Moscovo, com o qual fará uma média de 30 concertos anuais até 2019. Dirige a Orquestra do Norte, tocando o seu <span style="font-weight:bold"><span style="font-style:italic">Concerto para Viola</span></span>. Récita de <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> no Museu do Carro Eléctrico no Porto. Organiza o Festival Luís de Freitas Branco com a audição integral da obra do compositor.</p><p style="text-align:justify"><span style="font-weight:bold">2004 – </span>Compõe a <span style="font-weight:bold"><span style="font-style:italic">Abertura ‘A Rainha Louca’ </span></span>para a Orquestra Sinfónica Portuguesa e termina o 1º ato da ópera. Toca <span style="font-style:italic">Lachrimae</span> de Britten com a OSP. Estreia de nova produção de <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> no Teatro Efémero em Aveiro (direção de António Saiote, encenação de Jane W. Davidson). Promove a estreia moderna da <span style="font-style:italic">Escena de la Ines de Castro</span> de Boccherini e de <span style="font-style:italic">Fantasia e Grandes Variações </span>de Bomtempo no Cistermúsica.</p><p style="text-align:justify"><span style="font-weight:bold">2003 –</span> Compõe <span style="font-weight:bold"><span style="font-style:italic">O Papagaio e a Galinha </span></span>para a soprano Catarina Molder. Toca o <span style="font-weight:bold"><span style="font-style:italic">Concerto para Viola e Orquestra </span></span>com a Orquesta de Extremadura em Badajoz e Cáceres.  Faz a 1ª gravação mundial do <span style="font-style:italic">Quarteto em Sol Maior </span>de Viana da Mota para um CD do Quarteto Lacerda. Promove a estreia em Portugal de <span style="font-style:italic">O Aniversário da Infanta </span>de Franz Schreker, no âmbito do Cistermúsica. Estreia da sua versão portuguesa de <span style="font-style:italic">Hansel und Gretel</span> no Teatro da Trindade. Publicação do livro &quot;A Culpa é do Maestro&quot;. Publicação do catálogo do Museu da Música com ensaio sobre a obra de Frederico de Freitas.</p><p style="text-align:justify"><span style="font-weight:bold">2002 –</span> Estreia com o Quarteto Lacerda o <span style="font-style:italic">Quarteto nº 2 </span>(incompleto) de Frederico de Freitas. Torna-se diretor artístico do Cistermúsica / Festival de Música de Alcobaça, que será programado por si ao longo de 18 edições e abre nesse ano com a estreia mundial da abertura <span style="font-style:italic">Inês de Castro</span> de Viana da Mota.  Estreia como solista o concerto <span style="font-style:italic">The vigil of the angels</span>, de Ivan Moody, que lhe é dedicado.  Faz recitais com Álvaro Lopes Ferreira e conferências sobre a sinfonia em Portugal em Roma e L’Aquila. Começa a compor a ópera <span style="font-style:italic"><span style="font-weight:bold">A Rainha Louca</span>. </span>2ª edição do livro <span style="font-style:italic">A Sinfonia em Portugal </span>(Editorial Caminho).</p><p style="text-align:justify"><span style="font-weight:bold">2001 </span>–  Inaugura com o Quarteto Lacerda a nova fórmula de concertos comentados do CCB. É compositor convidado no Festival de Maastricht, onde se executam sete obras suas, incluindo o <span style="font-weight:bold"><span style="font-style:italic">Concerto para Viola</span></span>, que toca como solista. Atua com Bruno Belthoise no Centre Gulbenkian em Paris.  Toca o <span style="font-weight:bold"><span style="font-style:italic">Concerto para Violeta e Orquestra </span></span>com a Orquestra Sinfónica Portuguesa. Compõe <span style="font-weight:bold"><span style="font-style:italic">Poema de Deus e do Diabo</span></span> para o Grupo de Música Contemporânea de Lisboa. Grava em Paris a <span style="font-style:italic">Sonatina </span> de Armando José Fernandes, com o pianista Bruno Belthoise. 1ª edição do livro <span style="font-style:italic">A Sinfonia em Portugal, </span>promovida pelo Ministério da Cultura.</p><p style="text-align:justify"><span style="font-weight:bold">2000 –</span> Revela a existência do compositor modernista Carlos de Andrade (seu bisavô) através de um concerto no CCB. Estreia <span style="font-style:italic">Penélope no Cais da Rocha </span>de Eugénio Rodrigues. Compõe <span style="font-weight:bold"><span style="font-style:italic">Pequena Suite Laurissilva </span></span>para um CD comemorativo da classificação da Floresta Laurissilva da Madeira pela UNESCO. Compõe o <span style="font-weight:bold"><span style="font-style:italic">Concerto para Viola e Orquestra </span></span>para o Festival de Coimbra, estreando-o como solista com a Orquestra Gulbenkian. Compõe <span style="font-weight:bold"><span style="font-style:italic">Peças Fáceis</span></span> para a FMAC, <span style="font-weight:bold"><span style="font-style:italic">Bamboleio </span></span>para piano solo e <span style="font-weight:bold"><span style="font-style:italic">Cansonâncias</span></span> para o Coro do Teatro Nacional de São Carlos.</p><p style="text-align:justify"><span style="font-weight:bold">1999 –</span> Compõe <span style="font-weight:bold"><span style="font-style:italic">Tresvariações</span></span> para a Orquestra Gulbenkian e <span style="font-weight:bold"><span style="font-style:italic">Suite ‘A Varanda do Frangipani’</span></span> para um espetáculo do Teatro Meridional. Realiza conferência sobre Luís de Freitas Branco em Roma. Escreve ensaio sobre <span style="font-style:italic">A Lenda dos Bailarins</span> de Frederico de Freitas. Digressão do Quarteto Lacerda nos Açores. Estreia dos <span style="font-style:italic"><span style="font-weight:bold">Dois Poemas de Camões</span>. </span>O Quarteto Arditti grava o seu <span style="font-weight:bold"><span style="font-style:italic">Quarteto de Cordas</span></span>.</p><p style="text-align:justify"><span style="font-weight:bold">1998 –</span> Atua com o Quarteto Lacerda em Madrid, tocando o seu <span style="font-weight:bold"><span style="font-style:italic">Quarteto de Cordas</span>.</span> Estreia <span style="font-style:italic">Alap-jor-jhala-gat </span>de João Pedro Oliveira.  O TNSC dedica-lhe um concerto monográfico no Salão Nobre.</p><p style="text-align:justify"><span style="font-weight:bold">1997 –</span> Compõe <span style="font-weight:bold"><span style="font-style:italic">Dueto para Cravo e Marimba</span></span> para os Encontros Gulbenkian. Compõe <span style="font-weight:bold"><span style="font-style:italic">Burlesca</span></span> para o Duo Contracello, que a grava em CD. Atua com o Quarteto Lacerda em Londres. <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> é levado à cena na Bienal de Cascais e no Festival da Póvoa do Varzim (direção de António Saiote, encenação de Pedro Wilson).</p><p style="text-align:justify"><span style="font-weight:bold">1996 </span>- Compõe <span style="font-weight:bold"><span style="font-style:italic">Quién Me Libra...</span></span> para guitarra. Inicia nova série do &quot;A Propósito da Música&quot;, como colaborador da Antena 2. Termina o curso médio de alemão do Goethe Institut (10º grau). Dirige  <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> e <span style="font-style:italic">Savitri</span> de Gustav Holst numa produção em inglês da companhia NeueOpernbühne em Berlim (encenação de Alexander Paeffgen).</p><p style="text-align:justify"><span style="font-weight:bold">1995 </span>- Rescinde do contrato como viola tutti da Orquestra Gulbenkian. Compõe a <span style="font-weight:bold"><span style="font-style:italic">Suite &#x27;O Doido e a Morte’</span></span> para flauta e marimba e <span style="font-weight:bold"><span style="font-style:italic">Pequena Obsessão Compulsiva</span></span> para piano solo. Frequenta um seminário para  agentes culturais em Weimar, a convite do Goethe Institut.</p><p style="text-align:justify"><span style="font-weight:bold">1994 –</span> Dirige a estreia de <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> no Teatro Nacional de São Carlos (encenação de Pedro Wilson). <span style="font-weight:bold"><span style="font-style:italic">Langará</span></span> é peça obrigatória no Concurso Internacional de Música para a Juventude. Compõe <span style="font-weight:bold"><span style="font-style:italic">Escaramuça</span></span> para a Clerkenwell Music Series, a cuja estreia assiste em Londres.</p><p style="text-align:justify"><span style="font-weight:bold">1993 –</span> Completa o curso básico de alemão do Goethe Institut (6º grau). É convidado com Jorge Peixinho a representar a delegação portuguesa de SIMC nos World Music Days no México, onde é executada <span style="font-weight:bold"><span style="font-style:italic">Antagonia</span></span>. Compõe a ópera de câmara <span style="font-weight:bold"><span style="font-style:italic">O Doido e a Morte</span></span> para Lisboa 94, durante uma licença sem vencimento da Orquestra Gulbenkian.</p><p style="text-align:justify"><span style="font-weight:bold">1992 </span>-  Vence o Prémio João de Freitas Branco / Fidelidade com <span style="font-style:italic">Evoluções na Paisagem, </span>incluindo o prémio do júri e o prémio votado pela assistência. Compôõe <span style="font-weight:bold"><span style="font-style:italic">Langará</span></span> para clarinete. Compõe <span style="font-weight:bold"><span style="font-style:italic">The Panic Flirt</span></span> para flauta, a cuja estreia assiste no Festival de Presteigne (País de Gales). Rescinde o contrato como realizador do quadro da RDP.</p><p style="text-align:justify"><span style="font-weight:bold">1991 –</span> Compõe o <span style="font-style:italic"><span style="font-weight:bold">Quarteto para Contrabaixos</span>, </span>estreado num concerto monográfico promovido pelo Clube Português de Artes e Ideias. Compõe o <span style="font-weight:bold"><span style="font-style:italic">Quarteto de Cordas </span></span>com uma bolsa do Centro Nacional de Cultura. É ppromovido a realizador da Antena 2. Ingressa na Orquestra Gulbenkian como viola tutti. É convidado, com João Pedro Oliveira, a assistir ao festival &quot;Outono de Varsóvia&quot;.</p><p style="text-align:justify"><span style="font-weight:bold">1990 </span>- Compõe <span style="font-weight:bold"><span style="font-style:italic">Antagonia </span></span>para violoncelo solo e diploma-se com o 1º Prémio de Composição do Conservatório de Nice. Inicia a 1ª série do programa “A Propósito da Música” na Antena 2. Estreia de <span style="font-weight:bold"><span style="font-style:italic">Turbilhão</span></span> nos Encontros Gulbenkian. Frequenta o 35º Curso de Darmstadt, onde ouve conferências de John Cage e Iannis Xenákis e toca o <span style="font-weight:bold"><span style="font-style:italic">Duo para Viola e Clarinete.</span></span> Organiza com Nuno Barreiros, na RDP, o ciclo “Luís de Freitas Branco”, comemorativo do centenário do nascimento do compositor.</p><p style="text-align:justify"><span style="font-weight:bold">1989 </span>- Compõe <span style="font-weight:bold"><span style="font-style:italic">Evoluções na Paisagem </span></span>para orquestra. Estreia do <span style="font-weight:bold"><span style="font-style:italic">Concerto para Flauta e Orquestra</span></span> pela Orquestra Filarmónica de Nice e recebe a 1ª medalha do 2º ano do curso de composição. Toca com Ravi Shankar na Índia, sob a direção de Zubin Mehta, numa digressão da ECYO. É convidado a lecionar composição no Conservatório Nacional e a ser assistente musical da RDP, optando por entrar para a rádio.</p><p style="text-align:justify"><span style="font-weight:bold">1988 </span>-  Compõe o <span style="font-weight:bold"><span style="font-style:italic">Concerto para Flauta e Orquestra</span></span>. Integra a Orquestra Juvenil da Comunidade Europeia, tocando <span style="font-style:italic">Gurrelieder</span> em Berlim sob a direção de Claudio Abbado.</p><p style="text-align:justify"><span style="font-weight:bold">1987 – </span>Compõe <span style="font-weight:bold"><span style="font-style:italic">Os Nossos Dias</span></span> para quarteto de sopros, <span style="font-style:italic"><span style="font-weight:bold">Duo para Violeta e Clarinete</span>, <span style="font-weight:bold">Quarteto para Percussão</span></span> e <span style="font-weight:bold"><span style="font-style:italic">Turbilhão</span></span> para baixo e quarteto de cordas.  Vence o Prémio Jovens Músicos como violetista e diploma-se em viola com o 1º Prémio do Conservatório de Cannes.</p><p style="text-align:justify"><span style="font-weight:bold">1986 –</span> Decide trocar o violino pela viola, estudando com Barbara Friedhoff. Como bolseiro da Secretaria de Estado da Cultura, parte para Nice, onde estuda composição com Jacques Charpentier até 1989. Primeiro artigo publicado na imprensa (<span style="font-style:italic">A Capital</span>, 15/12/1986).</p><p style="text-align:justify"><span style="font-weight:bold">1985 </span>- Compõe <span style="font-weight:bold"><span style="font-style:italic">Concerto para Metais</span></span>. Estuda violino com Vasco Barbosa. Toca pela primeira vez como profissional, num concerto da Orquestra Sinfónica da RDP.</p><p style="text-align:justify"><span style="font-weight:bold">1984 –</span> Compõe <span style="font-weight:bold"><span style="font-style:italic">Três Momentos para Orquestra</span></span>, que são estreados pela Orquestra do Teatro Nacional de São Carlos. Abandona o curso de Ciências Musicais.</p><p style="text-align:justify"><span style="font-weight:bold">1983 – </span>Digressão à Alemanha com a Orquestra Juvenil da FMAC, incluindo execuções de <span style="font-weight:bold"><span style="font-style:italic">Prelúdio para Cordas</span></span>  em Bonn, Mainz, Freiburg e Siegburg. Conclui o curso geral do Conservatório Nacional como aluno externo (Composição, Violino, Educação Musical, Acústica e História da Música). Conclui o 12º ano no  Liceu D. Pedro V. Frequenta o 1º ano do Curso de Ciências Musicais da Universidade Nova, onde tem como professores com João de Freitas Branco (Estética) e Constança Capdeville (Análise e Técnicas de Composição IV). Inicia estudos de alemão no Goethe Institut.</p><p style="text-align:justify"><span style="font-weight:bold">1982 –</span> Compõe <span style="font-weight:bold"><span style="font-style:italic">Prelúdio para Cordas</span></span>, estreado pela Orquestra Sinfónica da RDP no Teatro de São Luiz. Frequenta pela 1ª vez o Curso de Música de Barroca da Casa de Mateus, onde estudou com Marie Leonhardt em cada verão até 1985.</p><p style="text-align:justify"><span style="font-weight:bold">1981  - </span>Inicia aulas particulares de composição com Joly Braga Santos, que se prolongam até 1986.  Compõe <span style="font-weight:bold"><span style="font-style:italic">Dois Poemas de Camões </span></span>para voz e piano. Torna-se professor da Orquestra de Iniciados da FMAC, que dirige até 1986 e para a qual compõe diversas peças simples.</p><p style="text-align:justify"><span style="font-weight:bold">1980 </span>- Estreia de <span style="font-weight:bold"><span style="font-style:italic">Versato</span></span> para  cordas pela Orquestra Juvenil da FMAC, sob a direção de Leonardo de Barros.</p><p style="text-align:justify"><span style="font-weight:bold">1978 – </span>Primeiro concerto com a Orquestra de Iniciados da FMAC, na Aula Magna.</p><p style="text-align:justify"><span style="font-weight:bold">1977 –</span> Inicia os estudos de violino na Fundação Musical dos Amigos das Crianças, incentivado pela pianista Fátima Fraga. Começa a compor de forma intuitiva, incentivado pela professora de solfejo, Deodata Henriques.</p>', '<h3><span style="font-weight:bold">ÓPERAS</span></h3><p> </p><p><span style="font-weight:bold">&quot;Felizmente Há Luar&quot; (2023-2024)</span></p><p> </p><p>Esta nova ópera de Alexandre Delgado baseia-se na aclamada peça &quot;Felizmente Há Luar!&quot; de Luís de Sttau Monteiro, escrita em 1961. A obra retrata de forma alegórica a resistência contra a ditadura do Estado Novo. Inspirada na figura histórica do general Gomes Freire de Andrade, que foi condenado à morte pelo regime absolutista, a peça faz uma crítica velada ao regime salazarista, abordando temas universais como a liberdade, o poder, a coragem e a luta contra a opressão. A ópera foi encomendada pela Orquestra Filarmónica Portuguesa para assinalar os 50 anos do 25 de Abril de 1974, a revolução que derrubou a ditadura e restaurou a democracia em Portugal. Ao transpor este texto fundamental do teatro português para a linguagem operática, Delgado pretendeu celebrar não só o legado artístico de Sttau Monteiro, como também homenagear o próprio 25 de Abril e os ideais de liberdade que este representou. O compositor combina tradição e técnicas contemporâneas para captar a profundidade emocional da narrativa. Estreada em maio de 2024 no Teatro da Guarda e no Teatro de São Luiz em Lisboa, até outubro a obra é levada a cena em oito cidades do país, num total de dez récitas.</p><p>Esta é a primeira adaptação operática da obra-prima de Sttau Monteiro, eternizando musicalmente o seu grito antifascista e incitando reflexões sobre a importância contínua da democracia.</p><p>Nota do Autor  - Quando o saudoso Joaquim Benite encenou a minha ópera “A Rainha Louca”, em 2011, lançou-me um desafio: queria que eu compusesse uma ópera sobre o meu avô, Humberto Delgado. Mas eu disse-lhe que não era capaz, por ser um assunto demasiado pessoal. (Literalmente: eu tinha cinco meses de gestação quando a minha mãe soube que o pai dela tinha sido assassinado.) Em 2022, o maestro Osvaldo Ferreira lançou-me outro desafio: compor uma ópera sobre o 25 de abril. Também fiquei de pé atrás, desta vez por achar o tema pouco operático e por não querer compor para uma comemoração oficial. Mas lembrei-me de uma peça que podia fazer todo o sentido: “Felizmente Há Luar”. Uma peça sobre a figura histórica do general Gomes Freire, condenado à morte em 1817, nos últimos estertores do regime absolutista. Publicado em 1961, o texto de Luís de Sttau Monteiro era uma metáfora tão evidente do Estado Novo sacudido pelas eleições de 1958, que até os obtusos censores salazaristas a perceberam. Proibida, a peça só pôde ser representada em Portugal depois da revolução. E foi assim que esses dois temas, que antes recusei, me vieram parar às mãos de forma metafórica. Que é como quem diz: operática.</p><p> </p><p><span style="font-weight:bold">&quot;<span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.discogs.com/release/28485148-Alexandre-Delgado-A-Rainha-Louca-%C3%93pera-Em-Dois-Atos target=_blank>A Rainha Louca</a></span></span>&quot; (2011)</span></p><p> </p><p>Esta é a segunda ópera de uma “Trilogia da Loucura” projetada por Alexandre Delgado. Tem dois atos e um libreto inspirado na peça &quot;O Tempo Feminino&quot; de Miguel Rovisco, retratando a loucura da rainha D. Maria I. A soberana vive enclausurada num mundo de demência e alucinações, na companhia da sua criada Rosa e confrontada pela gélida Duquesa de Lafões, D. Henriqueta. Três damas da corte também aparecem traçando um retrato delirante da realidade histórica portuguesa.</p><p>A ópera transita entre situações cómicas e pungentes, com D. Maria I vivendo os seus devaneios num &quot;século XVIII imaginário&quot;, nas palavras do compositor. Este recupera uma harmonia mais tradicional no segundo ato, permeando a partitura com citações que vão Wagner e Bizet e a bandas sonoras de cinema.</p><p>Estreada em 2011 no Centro Cultural de Belém, com encenação de Joaquim Benite, e levada à cena também no Brasil, &quot;A Rainha Louca&quot; é considerada uma das mais importantes óperas portuguesas contemporâneas.</p><p> </p><p><span style="font-weight:bold">Críticas a &quot;A Rainha Louca&quot;</span></p><p> </p><p>“Alexandre Delgado partiu de um texto para teatro de Miguel Rovisco e fez um libreto onde convergem reflexões (e ironias) sobre um país — Portugal —, interrogações sobre a loucura e a condição humana e dados históricos sobre o reinado de D. Maria I. Figura responsável por algumas obras relevantes — a Academia das Ciências ou a Biblioteca Nacional —, D. Maria I é famosa sobretudo pela longa demência dos seus últimos anos de vida, e a extrema religiosidade que a levou a mandar construir a Basílica da Estrela, em Lisboa.</p><p>A ópera de Alexandre Delgado, revendo e resgatando a figura da louca e piedosa D. Maria, viaja por tudo aquilo com assinalável jogo de cintura — a começar pela música, com ‘sons de um século XVIII imaginário’ (das danças de corte à <span style="font-style:italic">Marselhesa</span>) ao lado de citações da cultura popular (da ópera ao cinema), cruzados com uma linguagem própria — tradicional mas consistente — onde há lugar para drama,divertimento e… uma pontinha de loucura. Ainda bem — é refrescante ver como Alexandre Delgado, compositor que toca, músico que dirige, maestro que divulga (e naturalmente se encarregou ele próprio de dirigir a Orchestrutopica), criou uma pequena e bem construída ópera ligeira, pessimista mas bem humorada, despretensiosa mas séria.”</p><p>(Pedro Boléo, in <span style="font-style:italic">Público</span>, 11/07/2011)</p><p>“É inegável o talento de Alexandre Delgado para a ópera. Só lamento que a dispersão necessária para ganhar a vida não lhe permita uma maior dedicação à composição teatral. A primeira peça da sua trilogia operática sobre a loucura, baseada em ‘O Doido e a Morte’ (1923) de Raul Brandão, apareceu nos idos de 1994. Para a segunda, agora estreada no âmbito do Festival de Almada, foi buscar ‘O Tempo Feminino’ — parte da ‘Trilogia Portuguesa’ de Miguel Rovisco (1959-1987) — , cuja protagonista é a nossa rainha louca, D. Maria I. Só desejo que não tenhamos que esperar outros 17 anos pela terceira e última parte, dedicada a El-Rei Dom Sebastião, o causador da nossa desgraça. (…)</p><p>Há muito que D. Maria (1734-1816) era um personagem à procura de um compositor. (…) E é ela — numa criação impressionante de Ana Ester Neves — quem inexoravelmente domina ‘A Rainha Louca’, de Delgado. Diga-se já que a linguagem é eminentemente evocativa e dramática, com apropriadas caracterizações tímbricas e harmónicas das figuras principais (todas femininas): a harpa para a protagonista, o cravo para a sua jovem dama de companhia, Henriqueta (casada com o septuagenário Duque de Lafões, tio da Rainha), e a marimba para a criada preta, Rosa (papel falado), a representante do ‘bom selvagem’, alegre, criativo e energético. O adorável século XVIII é também ilustrado nos ritmos de dança, que permeiam toda a partitura (essencialmente tonal). O ecletismo estende-se às mais variadas citações (eruditas e populares) — da entrada da Rainha da Noite à <span style="font-style:italic">séguidille</span> da ‘Carmen’, às bandas fílmicas e às canções de Beatriz Costa. Com uma orquestra de câmara de uma dúzia de músicos (à maneira de Britten), o todo está muito bem cerzido e a fluência dramática raramente afrouxa.”</p><p>(Jorge Calado in<span style="font-style:italic"> Expresso</span>, 16/07/2011)</p><p> </p><p><span style="font-weight:bold">&quot;<span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://codaxmusic.com/product/o-doido-e-a-morte/ target=_blank>O Doido e a Morte</a></span></span>&quot; (1994)</span></p><p> </p><p>Esta ópera de câmara em um ato é baseada na famosa farsa homónima de Raul Brandão (1923). Com libreto do próprio Delgado, retrata de forma alegórica a condição humana, cruzando o trágico e o cómico num delírio alucinante.</p><p>A trama gira em torno do Governador Civil e do milionário Sr. Milhões. Este último chega com uma caixa que supostamente contém um poderoso explosivo. Pelo meio surge a mulher do Governador, Aninhas. No no final revela-se que a caixa apenas contém algodão e que o Senhor Milhões é um paciente fugido de um hospício.</p><p>Com a duração de apenas 30 minutos, a ópera é um tour-de-force de musicalidade e prosódia exemplar na língua portuguesa. Delgado tira proveito das irregularidades do idioma na linha de canto e confere um forte sentido teatral, com cada instrumento como uma espécie de personagem.</p><p>Muito elogiada pela crítica desde a sua estreia em 1994 no Teatro Nacional de São Carlos, &quot;O Doido e a Morte&quot; tem sido reencenada diversas vezes em Portugal e no estrangeiro.</p><p> </p><p><span style="font-weight:bold">Críticas a &quot;O Doido e a Morte&quot;</span></p><p> </p><p>&quot;A noite de 9 de Novembro no São Carlos deve ficar em lugar glorioso na história do nosso teatro nacional de ópera (...). Alexandre Delgado mostrou-se  capaz de defrontar vitoriosamente de um texto-jóia do teatro português, como é <span style="font-style:italic">O Doido e a Morte.</span>, de Raul Brandão. (...) A música de Delgado é um achado na simbiose da orquestração e do canto ou fala em que não há deslizes do princípio ao fim da partitura.&quot;</p><p>(José Blanc de Portugal, <span style="font-style:italic">in  </span>&quot;Diário de Notícias, 12/11/1994)</p><p>&quot;No descalabro geral de encomendas musicais a compositores portugueses por parte de Lisboa-94, uma única memória fica: &#x27;O Doido e a Morte&#x27;, de Alexandre Delgado, que (...) é caso inédito em mais de 20 anos, de uma ópera que se deseja ver reposta em melhores conduções de produção (...). As soluções instrumentais são assaz interessantes, quando não mesmo brilhantes (...) Um dos aspectos mais salientes da obra é a proeminência e diversidade rítmica (...)&quot;</p><p>(Augusto M. Seabra, <span style="font-style:italic">in  </span>&quot;Público&quot;, 13/11/1994)</p><p>&quot;O mais fascinante é que, enquanto dura, não existem quebras de tensão, não há momentos mortos. Nesse aspecto, em muito conta a natureza incisiva do tratamento do texto, o qual funciona como como polo de atracção onde se conjugam música e encenação. Em termos musicais, a prosódia da vocalidade sustenta-se na imaginativa base instrumental utilizada (...).&quot;</p><p>(Filipe Mesquita de Oliveira, <span style="font-style:italic">in  </span>&quot;Expresso&quot;, 19/11/1994)</p><p>&quot;Não falta, na verdade, a Alexandre Delgado o sentido da gestualidade teatral, tanto mais que a soube servir com economia de meios. (...) Mas o contributo mais inovador ou mais original incide sobretudo na dimensão fonético-musical. Alexandre Delgado observou as correlações entre entoações típicas do português falado e as situações comunicacionais envolvendo interlocutores com diferentes perfis psicológicos e sociais (...) e construiu a partir daí a vocalidade das personagens.&quot;</p><p>(Mário Vieira de Carvalho, <span style="font-style:italic">in  </span>&quot;Jornal de Letras&quot;, 23/11/1994)</p><p>&quot;A farsa homónima de Raul Brandão foi posta em música com particular brilho e sentido de humor. Alexandre delgado prova, além disso, que a língua portuguesa não é assim tão imprópria para o consumo operático como é habitual dizer-se. E, com esta sua primeira incursão no género, prometeu ter capacidade para vir a ser o melhor compositor português de ópera depois (e a par) do seu mestre Joly Braga Santos.&quot;</p><p>(Carlos Pontes Leça, <span style="font-style:italic">in</span>  &quot;Colóquio-Artes nº 104, janeiro/março 1995)</p><p> </p><h3><span style="font-weight:bold">OBRA MUSICAL COMPLETA</span></h3><p> </p><p>PIANO SOLO</p><p><span style="font-style:italic"><span style="font-weight:bold">Prelúdio</span></span> para piano (1982) 5’</p><p><span style="font-style:italic"><span style="font-weight:bold">Três Momentos</span></span> para piano solo (1984) 7’</p><p><span style="font-weight:bold"><span style="font-style:italic">Concertino </span></span>para piano solo<span style="font-weight:bold"> [Concerto para Metais] </span>(1985) 15’</p><p><span style="font-weight:bold"><span style="font-style:italic">Pequena Obsessão Compulsiva</span></span> para piano solo (1995) 1’</p><p><span style="font-weight:bold"><span style="font-style:italic">Meditando </span></span>para piano solo (2000) 1’</p><p><span style="font-style:italic"><span style="font-weight:bold">Bamboleio</span></span> para piano solo (1997-2000) 8’</p><p> </p><p>INSTRUMENTO SOLO</p><p><span style="font-style:italic"><span style="font-weight:bold">Antagonia</span></span> para violoncelo solo (ou violeta) (1990) 8’</p><p><span style="font-weight:bold"><span style="font-style:italic">The Panic Flirt</span></span> para flauta solo (1992) 6’</p><p><span style="font-weight:bold"><span style="font-style:italic">Langará</span></span> para clarinete solo (1992) 6’</p><p><span style="font-weight:bold"><span style="font-style:italic">Suite «A Varanda do Frangipani»</span></span> para violoncelo solo (ou violeta) (1999) 7’</p><p><span style="font-weight:bold"><span style="font-style:italic">Cantilena </span></span>para violino solo (ou violeta) (2000) 1’</p><p><span style="font-style:italic"><span style="font-weight:bold">Deia</span></span> para violino solo (ou violeta) (2000) 1’</p><p><span style="font-weight:bold"><span style="font-style:italic">Ondeando</span></span> para violoncelo solo (2000) 1’</p><p><span style="font-weight:bold"><span style="font-style:italic">São Rock </span></span>para violoncelo solo (2000) 1’</p><p><span style="font-weight:bold"><span style="font-style:italic">Trica </span></span>para contrabaixo solo (2000) 1’</p><p><span style="font-style:italic"><span style="font-weight:bold">Quièn me libra... </span></span> para guitarra solo (1996) 2’</p><p><span style="font-weight:bold"><span style="font-style:italic">Rumba Palaciano</span></span> para guitarra solo (2000)</p><p><span style="font-weight:bold"><span style="font-style:italic">Tocarola</span></span> para saxofone solo (2017) 2’</p><p> </p><p>MÚSICA DE CÂMARA</p><p><span style="font-weight:bold"><span style="font-style:italic">Prelúdio </span></span>para quarteto de cordas (1982) 5’</p><p><span style="font-weight:bold"><span style="font-style:italic">Concerto para Metais</span></span> (2 trompetes, 2 trompas, 2 trombones, tuba) (1985<span style="font-style:italic">) </span>15’</p><p><span style="font-style:italic"><span style="font-weight:bold">Quarteto Breve</span></span> para percussão (1987) 4’</p><p><span style="font-weight:bold"><span style="font-style:italic">Duo para Viola e Clarinete </span></span>(1987) 5’</p><p><span style="font-style:italic"><span style="font-weight:bold">Os Nossos Dias</span></span> para flauta, oboé, trompa e fagote (1987) 12’</p><p><span style="font-weight:bold"><span style="font-style:italic">Quarteto para Contrabaixos</span></span>  (1991) 6’</p><p><span style="font-weight:bold"><span style="font-style:italic">Burlesca </span></span> para violoncelo e contrabaixo (1991) 6’</p><p><span style="font-style:italic"><span style="font-weight:bold">Quarteto de Cordas</span></span> (1991) 11’</p><p><span style="font-weight:bold"><span style="font-style:italic">Suite «O Doido e a Morte» </span></span>para flauta e marimba/vibrafone (1995) 7’</p><p><span style="font-weight:bold"><span style="font-style:italic">Dueto para Cravo e Marimba</span></span> (1997) 8’</p><p><span style="font-weight:bold"><span style="font-styl