INSERT IGNORE INTO users (id, email, password, role) VALUES ('1848cbfe-23ca-48b6-98b5-ac014590898a', 'wix-1848cbfe@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('a50d881e-503e-43b1-917a-efc29541b625', '1848cbfe-23ca-48b6-98b5-ac014590898a', 'teste  teste', 'Harshaka Waththegedara', 'Harshaka', '123131313', '2024-09-13', 'Portugal', 'Portugal', 'Fetais', 'Rua cidade viseu Fetais', 'Rua cidade viseu Fetais', '2680-132', 'sasa', 'teste teste teste', 'https://static.wixstatic.com/media/1848cb_c1b5d9072a98478ca4003df794f5a0e8~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Bem-vindo à aba principal do seu perfil de Artista! Sugerimos que use uma letra maior para chamar a atenção do leitor e incentivá-lo a explorar as outras abas e galerias.  Dicas:</p><p>a)  Ao navegar pelos perfis de outros Artistas SMART, você encontrará inspiração e novas ideias.</p><p>b)  Ao criar seu perfil, sugerimos iniciar com uma frase impactante que valorize sua arte e carreira. Pode ser um depoimento de um crítico ou uma frase autoral que destaque sua singularidade.</p><p>c)   Em seguida, inclua até quatro parágrafos breves que apresentem sua trajetória e destaquem seus pontos fortes. Lembre que esta aba é apenas uma visão geral, então deixe os detalhes para as abas “História” e “Carreira”.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 16: Ana Paula  Russo
INSERT IGNORE INTO users (id, email, password, role) VALUES ('41f19643-e397-4ed7-9c57-628f69f34fef', 'wix-41f19643@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('ce7c4e3c-561c-4086-8ed4-c375f41e9f8a', '41f19643-e397-4ed7-9c57-628f69f34fef', 'ana-paula-russo', 'Ana Paula  Russo', 'Ana Paula', '919844188', '1959-04-04', 'Portugal', 'Portugal', 'Amadora', 'Rua Maria Alda Barbosa Nogueira, 7-7o dir', 'Rua Maria Alda Barbosa Nogueira, 7-7o dir', '2700-969', 'Soprano', 'Toda a minha vida tem sido ligada à Música, especificamente ao Canto; é o meu destino e não será agora que irá mudar.', 'https://static.wixstatic.com/media/41f196_d6b6d5ca11914bb4b7ccaba7ecb36ee9~mv2.jpg', 'wix:document://v1/41f196_3ede83e9e7174f5d800d45d8311fc38d.pdf/pdf%20curriculumlongo.pdf', 'https://www.facebook.com/aprusso', NULL, NULL, NULL, 'https://www.youtube.com/@JoseManuelRusso', 'https://static.wixstatic.com/mp3/7b859e_809c4852c0bf405db08cd319b98ffccb.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=fPWZcPNVxJw', 'https://www.youtube.com/watch?v=IYbUsXk-cn4', 'https://www.youtube.com/watch?v=5NEuIw17JiE', 'https://www.youtube.com/watch?v=f5Avtsmxw0I', 'https://www.youtube.com/watch?v=rd3uV6DzSfs', 'https://youtu.be/Erx3kC2YTSY?si=cYyvn7UMm8fXINH9&mibextid=xfxF2i', 'https://www.youtube.com/watch?v=_bEPhnc4pkE', 'https://www.youtube.com/watch?v=Mo7m6qsDbrU', 'https://www.youtube.com/watch?v=rPEk9CL1HDw', 'https://www.youtube.com/watch?v=TJJh_M0kuKE&t=3s', '<p><span style="font-weight:bold">Ana Paula Russo</span> é uma soprano portuguesa reconhecida pela sua <span style="font-weight:bold">voz potente</span> e capacidade natural de atingir <span style="font-weight:bold">notas agudas</span>. Nascida em <span style="font-weight:bold">Beja</span>, cresceu num ambiente musical proporcionado pelo seu pai, um <span style="font-weight:bold">músico de jazz</span> com uma voz extraordinária. Embora tenha iniciado estudos em <span style="font-weight:bold">Línguas e Literaturas Modernas</span>, a sua paixão pela música levou-a a ingressar no <span style="font-weight:bold">Coro da Gulbenkian</span>, marcando o início de uma brilhante carreira no <span style="font-weight:bold">canto lírico</span>.</p><p> </p><p>Formou-se em <span style="font-weight:bold">Canto</span> no <span style="font-weight:bold">Conservatório Nacional de Lisboa</span> e licenciou-se pela <span style="font-weight:bold">Escola Superior de Música de Lisboa</span> com distinção. Aperfeiçoou a sua técnica com mestres conceituados, tornando-se uma das <span style="font-weight:bold">sopranos mais requisitadas</span> da sua geração, vencendo vários <span style="font-weight:bold">concursos nacionais e internacionais</span>.</p><p> </p><p>Conhecida pela sua <span style="font-weight:bold">integridade artística</span>, Ana Paula Russo recusa papéis que não se adequam à sua voz, preservando a sua <span style="font-weight:bold">saúde vocal</span>. Além dos palcos, dedica-se ao <span style="font-weight:bold">ensino do canto</span>, transmitindo aos seus alunos a importância da <span style="font-weight:bold">técnica</span>, <span style="font-weight:bold">paciência</span> e <span style="font-weight:bold">resiliência</span>. É também uma defensora da <span style="font-weight:bold">cultura portuguesa</span>, promovendo o <span style="font-weight:bold">repertório nacional</span> através de diversos projetos.</p><p> </p><p>Para Ana Paula Russo, a <span style="font-weight:bold">música</span> é uma <span style="font-weight:bold">extensão do seu ser</span>. Com uma carreira sólida, continua a <span style="font-weight:bold">encantar plateias</span> e a <span style="font-weight:bold">inspirar novas gerações</span>, afirmando-se como uma das <span style="font-weight:bold">grandes vozes da ópera portuguesa contemporânea</span>. A sua trajetória é um testemunho de <span style="font-weight:bold">paixão</span> e <span style="font-weight:bold">dedicação inabalável</span> à arte.<br/></p><p><br/></p>', '<p>Nasci na pitoresca cidade de <span style="font-weight:bold">Beja</span>, no coração do <span style="font-weight:bold">Alentejo</span>, e cresci envolvida por <span style="font-weight:bold">melodias e harmonias</span> que ecoavam na minha família. A música era uma presença constante; o meu pai, um talentoso <span style="font-weight:bold">músico de jazz</span> que cantava e tocava bateria, tinha uma voz extraordinária que preenchia os espaços da minha infância. Embora as árias de ópera não fossem comuns em nossa casa, eu frequentemente imitava as grandes <span style="font-weight:bold">divas líricas</span>, fechando-me na sala para explorar a minha voz, acreditando que ninguém me ouvia.</p><p> </p><p>Apesar dessa <span style="font-weight:bold">paixão latente</span>, o canto lírico não estava inicialmente nos meus planos. Com um talento natural para as <span style="font-weight:bold">línguas</span>, decidi seguir o curso de <span style="font-weight:bold">Línguas e Literaturas Modernas</span>, especializando-me em <span style="font-weight:bold">inglês</span> e <span style="font-weight:bold">alemão</span>. Contudo, o destino tinha outros planos. A minha madrinha, percebendo o meu <span style="font-weight:bold">potencial vocal</span>, inscreveu-me, sem que eu soubesse, nas audições para o <span style="font-weight:bold">Coro da Gulbenkian</span>. Surpreendida, mas encorajada, participei e fui seleccionada, iniciando assim uma jornada que mudaria a minha vida.</p><p> </p><p>No <span style="font-weight:bold">Coro da Gulbenkian</span>, sob a orientação do maestro <span style="font-weight:bold">João Valeriano</span>, recebi as primeiras lições formais de formação musical. Descobri um universo que me fascinava e decidi aprofundar os meus conhecimentos. Ingressando no <span style="font-weight:bold">Conservatório Nacional</span>, concluí o <span style="font-weight:bold">Curso Superior de Canto</span> em tempo recorde. A minha voz, naturalmente potente e dotada de uma forte <span style="font-weight:bold">extensão vocal</span>, rapidamente chamou a atenção no meio musical.</p><p> </p><p>Determinada a aperfeiçoar a minha técnica, prossegui os estudos na <span style="font-weight:bold">Escola Superior de Música de Lisboa</span> e, mais tarde, no prestigiado <span style="font-weight:bold">Mozarteum de Salzburgo</span>, onde estudei com a renomada soprano <span style="font-weight:bold">Elisabeth Grümmer</span>. A minha busca pela excelência levou-me a cruzar caminhos com a soprano espanhola <span style="font-weight:bold">Marimí del Pozo</span>, cuja orientação foi crucial para descobrir e dominar a técnica vocal adequada ao meu <span style="font-weight:bold">timbre único</span>.</p><p> </p><p>Aos <span style="font-weight:bold">23 anos</span>, já me destacava nos palcos, interpretando papéis desafiantes que exigiam virtuosismo e notas agudas, como a <span style="font-weight:bold">Rainha da Noite</span> em <span style="font-style:italic">A Flauta Mágica</span>, de Mozart, ou <span style="font-weight:bold">Olympia</span> em <span style="font-style:italic">Os Contos de Hoffmann</span>, de Offenbach. A capacidade de atingir <span style="font-weight:bold">notas extremas</span> com naturalidade tornou-me numa das <span style="font-weight:bold">sopranos mais requisitadas</span> da minha geração.</p><p> </p><p>Mas nem tudo foram facilidades. Enfrentei desafios que testaram os limites da minha técnica e resistência. A interpretação de <span style="font-weight:bold">&quot;Minette&quot;</span> em <span style="font-style:italic">The English Cat</span>, de Hans Werner Henze, foi um desses momentos. Com uma escrita contemporânea complexa e exigindo presença quase constante em palco, este papel marcou-me profundamente, reforçando a minha <span style="font-weight:bold">resiliência</span> e <span style="font-weight:bold">paixão</span> pela ópera.</p><p> </p><p>Ao longo da minha carreira, sempre mantive uma postura íntegra, recusando papéis que não se adequavam à minha voz ou que comprometessem a minha <span style="font-weight:bold">saúde vocal</span>. Acredito firmemente que cada cantor deve respeitar a <span style="font-weight:bold">natureza única da sua voz</span> e não ceder a pressões externas. A <span style="font-weight:bold">integridade artística</span> é fundamental.</p><p> </p><p>Paralelamente à minha atividade nos palcos, dedico-me com entusiasmo ao <span style="font-weight:bold">ensino</span>. Como professora de canto, partilho com os meus alunos não só conhecimentos técnicos, mas também a importância da <span style="font-weight:bold">paciência</span>, da <span style="font-weight:bold">resiliência</span> e da <span style="font-weight:bold">autoconfiança</span>. Encorajo-os a persistirem face às adversidades e a traçarem o seu próprio caminho no mundo da música.</p><p> </p><p>Apaixonada pela <span style="font-weight:bold">cultura portuguesa</span>, tenho-me dedicado à <span style="font-weight:bold">divulgação do repertório nacional</span>, muitas vezes negligenciado. Projetos como <span style="font-weight:bold">&quot;Entre Mulheres&quot;</span>, em parceria com <span style="font-weight:bold">Nuno Dias</span>, e o duo com o guitarrista <span style="font-weight:bold">Carlos Gutkin</span> refletem o meu compromisso em levar a rica <span style="font-weight:bold">herança musical portuguesa</span> ao público nacional e internacional.</p><p> </p><p>Para mim, a <span style="font-weight:bold">música</span> é mais do que uma profissão; é uma <span style="font-weight:bold">extensão do meu próprio ser</span>. Mesmo fora dos palcos, a melodia acompanha-me, cantando espontaneamente onde quer que esteja. No entanto, é na <span style="font-weight:bold">História</span> que encontro outra grande paixão. O fascínio pelo passado complementa a minha visão artística, ajudando-me a contextualizar as obras que interpreto e a enriquecer as minhas performances com profundidade e significado.</p>', '<p><span style="font-weight:bold">🎓 HABILITAÇÕES ACADÉMICAS</span></p><p> </p><ul><li><span style="font-weight:bold">Curso Superior de Canto</span> pelo Conservatório Nacional de Lisboa.</li><li><span style="font-weight:bold">Licenciatura em Canto</span> pela Escola Superior de Música de Lisboa (<span style="font-weight:bold">ESML</span>) com a classificação de <span style="font-weight:bold">19 valores</span>.</li><li><span style="font-weight:bold">Mestrado em Canto (Performance)</span> na ESML, obtendo a <span style="font-weight:bold">classificação máxima</span>.</li><li><span style="font-weight:bold">Mestrado em Ensino de Música (Pedagogia do Canto)</span> na ESML com <span style="font-weight:bold">19 valores</span>.</li><li><span style="font-weight:bold">Licenciatura em Línguas, Literaturas e Culturas</span> pela Faculdade de Letras da Universidade de Lisboa.</li><li>Cursos completos nos Institutos <span style="font-weight:bold">Alemão</span>, <span style="font-weight:bold">Britânico</span> e <span style="font-weight:bold">Italiano</span>.</li><li>Profissionalização no âmbito do <span style="font-weight:bold">Ensino Artístico</span> (2009).</li><li><span style="font-weight:bold">Formadora certificada</span> no âmbito do ensino da Música.</li></ul><p> </p><p><span style="font-weight:bold">📚 CURSOS DE APERFEIÇOAMENTO</span></p><p><br/><span style="font-weight:bold">1984</span>: <span style="font-style:italic">Sommerakademie de Salzburgo</span> com <span style="font-weight:bold">Elisabeth Grümmer</span>.<br/><span style="font-weight:bold">1985</span>: <span style="font-style:italic">Masterclass</span> em Lucerna com <span style="font-weight:bold">Elisabeth Grümmer</span>.<br/><span style="font-weight:bold">1990</span>: <span style="font-style:italic">Masterclass</span> em Lisboa com <span style="font-weight:bold">Regine Resnick</span>.<br/>Trabalhou ainda com <span style="font-weight:bold">Gino Becchi</span>, <span style="font-weight:bold">Claude Thiolass</span> e <span style="font-weight:bold">Marimí del Pozo</span>.</p><p> </p><p> </p><p><span style="font-weight:bold">🏅 PRÉMIOS E CONCURSOS</span></p><p><br/><span style="font-weight:bold">1985</span>: 2.º Prémio no <span style="font-weight:bold">Concurso Internacional de Canto Francisco de Andrade</span>.<br/><span style="font-weight:bold">1988</span>: 1.º Prémio no <span style="font-weight:bold">Concurso Nacional Olga Violante</span> (Prémio Nacional e Prémio Especial do Júri para Ópera).<br/>1.º Prémio nos <span style="font-weight:bold">Concursos Nacionais da Juventude Musical Portuguesa</span> (Canto e Música de Câmara).<br/>Finalista no <span style="font-weight:bold">Concurso Internacional de Canto Francisco Viñas</span> (Barcelona).<br/><span style="font-weight:bold">1989</span>: Representou Portugal no <span style="font-weight:bold">Cardiff Singer of the World</span>.<br/><span style="font-weight:bold">1990</span>: Finalista Laureada no <span style="font-weight:bold">Concurso Internacional de Canto Cidade de Oviedo</span>.<br/>Finalista Laureada no <span style="font-weight:bold">Concurso Internacional de Canto Luísa Todi</span>.<br/><span style="font-weight:bold">2015</span>: Prémio de Excelência na Música Erudita, iniciativa da revista <span style="font-weight:bold">“Mais Alentejo”</span>.</p><p> </p><p> </p><p><span style="font-weight:bold">🎤 ATIVIDADE PROFISSIONAL E COLABORAÇÕES</span></p><p> </p><ul><li>Membro do <span style="font-weight:bold">Núcleo Caravelas</span> da Faculdade de Ciências Sociais e Humanas (<span style="font-weight:bold">FCSH</span>).</li><li>Colaboradora regular do <span style="font-weight:bold">MPMP – Movimento Patrimonial da Música Portuguesa</span>.</li></ul><p> </p><p><span style="font-weight:bold">Júri em concursos internacionais de canto</span>:</p><p> </p><ul><li><span style="font-weight:bold">2015, 2016, 2017, 2018, 2020 e 2022</span>: Responsável e Presidente do Júri do <span style="font-weight:bold">Concurso Internacional de Canto Cidade de Almada</span>, posteriormente <span style="font-weight:bold">CIMTS</span>.</li><li><span style="font-weight:bold">2022 e 2024</span>: Júri do <span style="font-weight:bold">Concurso de Canto de Lousada</span>.</li><li><span style="font-weight:bold">2024</span>: Júri do <span style="font-weight:bold">Concurso de Canto Martín y Soler</span> em Valência.</li><li><span style="font-weight:bold">2023/2024</span>: Júri da <span style="font-weight:bold">World Music Competition</span>.</li><li>Responsável pelo <span style="font-weight:bold">Canto e OperaLab</span> no <span style="font-weight:bold">Bendada Music Festival</span> (2022, 2023, 2024).</li></ul><p> </p><p><span style="font-weight:bold">🎓 Oradora convidada</span>:</p><p> </p><ul><li><span style="font-weight:bold">2015</span>: Convidada para o encerramento do <span style="font-weight:bold">II Congresso de Psicologia Positiva</span> no Instituto Superior de Ciências Sociais e Políticas (<span style="font-weight:bold">ISCSP</span>) da Universidade de Lisboa.</li></ul><p> </p><p><span style="font-weight:bold">🎼 Comissariado e Direção Artística</span>:</p><p> </p><ul><li>Comissária do ciclo de música de câmara <span style="font-weight:bold">“À Tarde no Museu”</span> no <span style="font-weight:bold">Museu Nacional da Música</span>.</li><li><span style="font-weight:bold">2020</span>: Comissária do ciclo <span style="font-weight:bold">“Desconfinando no Museu”</span> (Museu Nacional da Música).</li><li><span style="font-weight:bold">2016</span>: Comissária, juntamente com <span style="font-weight:bold">José Manuel Russo</span>, da exposição <span style="font-weight:bold">“Gravuras de Cantores de Ópera”</span>, inaugurada a 22 de novembro no Museu Nacional da Música.</li><li>Diretora artística da 1.ª edição do <span style="font-weight:bold">Festival Sons com História</span> em <span style="font-weight:bold">Castelo de Vide</span>.</li></ul><p> </p><p><span style="font-weight:bold">📚 TRABALHOS ESCRITOS E INVESTIGAÇÃO</span></p><p> </p><ul><li><span style="font-weight:bold">1999</span>: Projeto de investigação <span style="font-weight:bold">“A Ópera Portuguesa do Século XVIII”</span>, realizado no âmbito da licenciatura em Canto na <span style="font-weight:bold">ESML</span>.</li><li><span style="font-weight:bold">2011</span>: Projeto de investigação <span style="font-weight:bold">“Música do Tempo de D. João VI”</span>, desenvolvido no âmbito do Mestrado em Canto na <span style="font-weight:bold">ESML</span>.</li></ul><p> </p><p><span style="font-weight:bold">🎶 OUTRAS ATIVIDADES</span></p><p><br/>Dedica-se à divulgação do <span style="font-weight:bold">repertório de compositores portugueses</span>, colaborando frequentemente com instituições e projetos que promovem a música nacional.<br/>Participa regularmente em recitais e concertos, destacando-se a sua participação nos projetos:</p><ul><li><span style="font-weight:bold">“Entre Mulheres”</span> com <span style="font-weight:bold">Nuno Dias</span>, explorando a ligação entre a <span style="font-weight:bold">voz feminina</span> e a <span style="font-weight:bold">Guitarra de Coimbra</span>.</li><li>Duo com o guitarrista <span style="font-weight:bold">Carlos Gutkin</span>, com quem gravou o álbum <span style="font-weight:bold">“Melodia Sentimental”</span> em 2005, interpretando repertório de compositores ibero-americanos.</li></ul><p> </p><p><span style="font-weight:bold">📝 NOTAS ADICIONAIS</span></p><p><br/><span style="font-weight:bold">Ana Paula Russo</span> é reconhecida não só pela sua carreira como soprano, mas também pelo seu contributo no ensino e promoção da <span style="font-weight:bold">música erudita</span> em Portugal. Com uma <span style="font-weight:bold">formação académica sólida</span> e uma vasta <span style="font-weight:bold">experiência profissional</span>, tem sido uma figura influente na preservação e divulgação do <span style="font-weight:bold">património musical português</span>, bem como na <span style="font-weight:bold">formação de novas gerações</span> de cantores.</p>', '<p><span style="font-weight:bold">📺 PROGRAMAS PARA A RTP</span></p><p> </p><ul><li>Série de programas sobre a <span style="font-weight:bold">Música Portuguesa</span> desde o séc. XVI até ao séc. XIX</li><li><span style="font-weight:bold">&quot;O LIVRO DOS JARDINS SUSPENSOS&quot;</span> de <span style="font-weight:bold">A. Schöenberg</span></li><li><span style="font-weight:bold">&quot;LES NOCES&quot;</span> de <span style="font-weight:bold">I. Stravinski</span></li><li><span style="font-weight:bold">&quot;MONSIEUR CHOUFLEURI...&quot;</span> de <span style="font-weight:bold">J. Offenbach</span></li><li>Recitais de <span style="font-weight:bold">Canto e Guitarra</span> de diversos autores</li><li>Recital de <span style="font-weight:bold">Duetos de Schumann e Brahms</span> para vozes femininas</li><li><span style="font-weight:bold">&quot;Grande Valsa&quot;</span> (abril de 2015) <span style="font-weight:bold">RTP</span></li></ul><p> </p><p><span style="font-weight:bold">🎙️ PROGRAMAS PARA A ANTENA 2</span></p><p> </p><ul><li>Apresentadora do programa ao vivo <span style="font-weight:bold">“O Despertar dos Músicos”</span></li><li>Apresentadora do programa ao vivo <span style="font-weight:bold">“Acordar a Dois”</span></li><li>Apresentadora do programa ao vivo <span style="font-weight:bold">“Amanhecer”</span></li><li>Comentadora regular de <span style="font-weight:bold">“As Noites de Ópera”</span></li><li>Autora/apresentadora do programa <span style="font-weight:bold">“Cantabile”</span></li><li>Autora/apresentadora do programa <span style="font-weight:bold">“EmCanto”</span></li><li>Apresentadora das <span style="font-weight:bold">Transmissões ao vivo da temporada do MET</span> (2008 até o presente)</li><li>Gravação, como cantora solista, de vários <span style="font-weight:bold">recitais ao vivo</span> (concertos <span style="font-weight:bold">Abertos Ant2</span>)</li></ul><p> </p><p><span style="font-weight:bold">💿 ÁLBUNS</span></p><p> </p><ul><li><span style="font-weight:bold">Canções Tradicionais de Natal</span> (coletânea de canções de Natal para canto e guitarra)</li><li><span style="font-weight:bold">Natal no Paço</span> (peças musicais relacionadas com o Palácio da Ajuda)</li><li><span style="font-weight:bold">“Matutino dei Morti”</span> de <span style="font-weight:bold">J. D. Bomtempo</span></li><li><span style="font-weight:bold">“As Damas Trocadas”</span> de <span style="font-weight:bold">Marcos Portugal</span> (Marco Polo)</li><li><span style="font-weight:bold">“Os Dias Levantados”</span> de <span style="font-weight:bold">António Pinho Vargas</span> (EMI)</li><li><span style="font-weight:bold">“Melodia Sentimental”</span> (obras ibero-americanas, com o guitarrista <span style="font-weight:bold">Carlos Gutkin</span>)</li><li><span style="font-weight:bold">“Requiem de memória às vítimas do Fascismo”</span> de <span style="font-weight:bold">F. Lopes Graça</span> (RDP)</li><li><span style="font-weight:bold">Árias e duetos cantados por Luísa Todi</span> (CD e DVD)</li><li><span style="font-weight:bold">“Missa Grande”</span> de <span style="font-weight:bold">Marcos Portugal</span> (Numérica)</li><li><span style="font-weight:bold">“A Rainha Louca”</span> de <span style="font-weight:bold">Alexandre Delgado</span> (CD e DVD)</li><li><span style="font-weight:bold">&quot;Discoveries&quot;</span> (obras para canto, clarinete e piano, com <span style="font-weight:bold">António Saiote</span> e <span style="font-weight:bold">Nuno V. de Almeida</span>)</li><li><span style="font-weight:bold">Homenagem a Artur Santos</span> (com <span style="font-weight:bold">José Bom de Sousa</span>)</li></ul>', 'https://static.wixstatic.com/media/41f196_382bf35ba32a4d6299b86244e9938849~mv2.jpg', 'recital Antena 2, MNAA, foto Jorge Carmona 2022', 'https://static.wixstatic.com/media/41f196_4587499f44de4ac7ac9adb4d0163c877~mv2.jpg', 'Recital Com Inês Andrade, foto JMRusso 2022', 'https://static.wixstatic.com/media/41f196_e48143ab0a014892843d94144fa30e0b~mv2.jpg', 'Concerto de Orgão em Arouca com Ariana Russo e António Duarte, 2023foto JMRusso', 'https://static.wixstatic.com/media/41f196_5aa444c0621b49a8912736994e29d6c9~mv2.jpg', 'Concerto Antena2 2022MNAA', 'https://static.wixstatic.com/media/41f196_da8dbb02fb404959a7a6a68cbebd9f38~mv2.jpg', 'Projecto Entre Mulheres comNuno Dias,Museu da Musica, 2023 foto JMRusso', 'https://static.wixstatic.com/media/41f196_717020fc3bfe4e24bae57d1f503032d8~mv2.jpg', 'Recital com C. Gutkin, MNAA 2022', 'https://static.wixstatic.com/media/41f196_9befeb3053854145b88279c8721873ba~mv2.jpg', 'Recital com Sergio Silva, Mafra 2019 foto JMRusso', 'https://static.wixstatic.com/media/41f196_0f09a5c0811f45e7ac1e28f6f668e965~mv2.jpg', 'Com Guitarras EmCanto, Almada, 2017', 'https://static.wixstatic.com/media/41f196_728a66d330814810a928c472ebcfacd8~mv2.jpg', 'Concerto de Orgão com Ariana Russo e António Duarte, Algarve, 2019 foto JMRusso', 'https://static.wixstatic.com/media/41f196_d8d07a6c370f41d9821b614ac535f6c1~mv2.jpg', 'recital Sesimbra, Natal de 2022 com Ariana Russo', 'https://static.wixstatic.com/media/41f196_5a3038979dff4cb7a2f9aa99831efc06~mv2.jpg', 'Abril de 21, concerto com Órgão', NULL, NULL, 1, 0, 0);

-- Row 17: João Soares
INSERT IGNORE INTO users (id, email, password, role) VALUES ('0bb3ca54-6252-404c-aa7c-aa62155a9a43', 'wix-0bb3ca54@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('702c8315-780c-48eb-9ac8-091256d3d77f', '0bb3ca54-6252-404c-aa7c-aa62155a9a43', 'joao-soares', 'João Soares', 'João', '''+351914115801', '1990-10-08', 'Brazil', 'Portugal', 'Lisboa', 'Rua Alberto de Oliveira, 20, 2 esquerdo', NULL, '1700-020', 'Pianista', '"Um dos pianistas mais talentosos da nova geração brasileira." (Nelson Freire)', 'https://static.wixstatic.com/media/7b859e_b0eab588d7bf4bf191e9323d552ee099~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.youtube.com/watch?v=G6HUFMycYFQ&pp=ygUQam9hbyBlbGlhcyBwaWFubw%3D%3D', 'https://www.youtube.com/watch?v=gLSyoHZEpfI&pp=ygUQam9hbyBlbGlhcyBwaWFubw%3D%3D', 'https://www.youtube.com/watch?v=PgVKemkvK4s&pp=ygUQam9hbyBlbGlhcyBwaWFubw%3D%3D', 'https://www.youtube.com/watch?v=2ONSOIrptA8&pp=ygUQam9hbyBlbGlhcyBwaWFubw%3D%3D', 'https://www.youtube.com/watch?v=3g8Mei344SE&pp=ygUQam9hbyBlbGlhcyBwaWFubw%3D%3D', 'https://www.youtube.com/watch?v=Z1v59IVjuMc&pp=ygUQam9hbyBlbGlhcyBwaWFubw%3D%3D', NULL, NULL, NULL, NULL, '<p class="font_8">“<em>Um dos pianistas mais talentosos da nova geração brasileira, ele se destaca por sua sensibilidade e virtuosismo empolgante.</em>” (Nelson Freire)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>João Elias Soares</strong> é uma força ímpar no cenário musical brasileiro e internacional. Aclamado pelo seu talento e virtuosismo, tem cativado audiências ao redor do mundo com suas performances. O seu toque cristalino, técnica impecável e interpretações profundamente emotivas colocam-no numa categoria própria entre os melhores pianistas da sua geração.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Ao longo da sua carreira, acumulou um impressionante número de conquistas. Vencedor de prestigiados concursos nacionais e internacionais, como o XVI Concurso Nacional Arnaldo Estrella e o “XIII Concours International de Piano Son Altesse Royale la Princesse Lalla Meryem” (Melhor Intérprete de um Compositor Brasileiro e Melhor Intérprete de um Compositor Russo), tem-se apresentado em algumas das mais importantes salas de concerto e festivais da América do Sul, África e Europa.</p>
<p class="font_8"><br></p>
<p class="font_8">As suas atuações como solista junto a renomadas orquestras têm sido consistentemente elogiadas pela crítica especializada, que destaca a sua excecional musicalidade e a sua capacidade de se conectar com o público.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">O seu repertório abrange uma vasta gama de estilos e períodos, desde os grandes mestres clássicos até aos compositores contemporâneos. A sua abordagem musical é marcada pela atenção ao detalhe, pela compreensão profunda das obras que interpreta e por uma técnica impecável que lhe permite explorar uma ampla gama de cores e subtilezas sonoras. Seja em recitais a solo ou em colaborações de música de câmara, João traz uma perspetiva fresca e envolvente a cada atuação.</p>', '<p>Aos 11 anos, João Elias Soares teve o seu primeiro contacto com o piano, despertando uma paixão que definiria o rumo da sua vida.</p><p>Formou-se no Conservatório Brasileiro de Música em 2009, onde começou a moldar a sua técnica e a sua sensibilidade artística sob a orientação de professores empenhados. Em 2015, concluiu a sua formação na Universidade Federal do Rio de Janeiro, um passo significativo que ampliou as suas perspetivas musicais e o introduziu a novos desafios e estilos.</p><p> </p><p>O desejo de aprofundar ainda mais os seus estudos levou João a atravessar o oceano até Portugal, onde concluiu o seu mestrado em Performance pelo Instituto Politécnico de Castelo Branco em 2021. Durante este período, aprimorou as suas habilidades técnicas e absorveu as ricas influências culturais que a Europa tinha para oferecer, colaborando com músicos de várias nacionalidades e expandindo o seu repertório.</p><p> </p><p>Ao longo da sua formação, participou em masterclasses com eminentes pianistas como Cyprien Katsaris e Nikolai Lugansky, cujas orientações refinaram a sua técnica pianística e ensinaram-lhe a importância de transmitir emoções através da música. Estas experiências foram fundamentais para a sua formação, permitindo-lhe executar peças complexas e interpretá-las com uma profundidade emocional que ressoa com o público.</p><p> </p><p>Os prémios começaram a acumular-se, reconhecendo o seu talento e dedicação. Desde o prestigiado &quot;X Concurso de Piano Villa-Lobos&quot; até competições internacionais na Europa e Marrocos, João provou repetidamente a sua excelência. Cada conquista não era apenas um troféu, mas um passo na sua evolução como músico e uma afirmação da sua paixão pela música.</p>', '<p class="font_8">João Elias Soares rapidamente se afirmou como um destacado pianista brasileiro, reconhecido internacionalmente pela sua técnica refinada e pela capacidade de transmitir profundas emoções musicais. A sua carreira tem sido marcada por uma série de performances em algumas das mais prestigiadas salas de concerto e festivais de música ao redor do mundo.</p>
<p class="font_8"><br></p>
<p class="font_8">Desde cedo na sua carreira, João Elias destacou-se em palcos sul-americanos e europeus, colaborando com renomadas orquestras. As suas atuações com a Orquestra Sinfônica da Universidade Federal do Rio de Janeiro, a Orquestra Sinfônica de Minas Gerais, entre outras, foram amplamente elogiadas, consolidando a sua reputação como solista de excelência. Além disso, João tem uma presença constante em recitais nas principais salas de concerto da América do Sul, África e Europa, sempre recebido com entusiasmo pelo público e crítica.</p>
<p class="font_8"><br></p>
<p class="font_8">A sua versatilidade permite-lhe explorar um extenso repertório, que inclui desde peças clássicas até obras de compositores contemporâneos, mostrando não apenas sua habilidade técnica mas também uma profunda interpretação musical. Este amplo alcance estilístico tornou-o uma escolha frequente para festivais de música de prestígio, onde se destaca tanto em performances solo como em música de câmara.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>PRÉMIOS</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">1º prémio no Concurso de Piano de Munique (2021)</p></li>
  <li><p class="font_8">1º prémio no “XIII Concours International de Piano Son Altesse Royale la Princesse Lalla Meryem” (Marrocos, 2018), com distinções para a Melhor Peça Russa e Melhor Peça Brasileira</p></li>
  <li><p class="font_8">2º prémio no “III Sardoal Young Talent Award” (Portugal, 2018)</p></li>
  <li><p class="font_8">Vencedor do “X Concurso de Piano Villa-Lobos” (2013)</p></li>
  <li><p class="font_8">Vencedor do “XVI Concurso de Piano Arnaldo Estrella” (2010)</p></li>
  <li><p class="font_8">Vencedor do “V Concurso de Jovens Solistas da Orquestra Sinfônica de Minas Gerais” (2016)</p></li>
</ul>
<p class="font_8"><br></p>
<p class="font_8"><strong>MASTERCLASSES</strong></p>
<p class="font_8"><br></p>
<p class="font_8">· <strong>Geir Braaten</strong> (Noruega)</p>
<p class="font_8">· <strong>Richard Raymond</strong> (Canadá)</p>
<p class="font_8">· <strong>Tali Morgulis</strong> (Rússia)</p>
<p class="font_8">· <strong>Thomas Mastroianni</strong> (EUA)</p>
<p class="font_8">· <strong>Cyprien Katsaris</strong> (Grécia)</p>
<p class="font_8">· <strong>Magdalena Lisak</strong> (Polónia)</p>
<p class="font_8">· <strong>Luiz Carlos de Moura Castro</strong> (Brasil)</p>
<p class="font_8">· <strong>Nikolai Lugansky</strong> (Rússia)</p>
<p class="font_8">· <strong>Aquiles Delle Vigne</strong> (Argentina)</p>', '<p class="font_8">&nbsp;</p>
<p class="font_8"><a href="https://www.youtube.com/watch?v=7QeQjZqHrog" target="undefined"><u>FIA – Festival Internacional dos Açores (2021)</u></a> – João Elias Soares (entrevista)</p>
<p class="font_8"><a href="https://www.youtube.com/watch?v=dGwCOdn3EaM&amp;t=1046s" target="undefined"><u>Felipe Blaft (2020)</u></a> – Conversa Pianística: “ Estratégias de compreensão de uma obra.” Com o Pianista João Elias parte 1</p>
<p class="font_8"><a href="https://www.youtube.com/watch?v=MvCjjRNleXk" target="undefined"><u>Felipe Blaft (2020)</u></a> – Conversa Pianística: “ Estratégias de compreensão de uma obra.” Com o Pianista João Elias parte 2</p>
<p class="font_8">&nbsp;&nbsp;</p>
<p class="font_8"><strong>CONCERTOS</strong></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>2018</strong></p>
<p class="font_8">Outubro – Embaixada do Brasil em Roma apresenta “Pianoforte solo”. Palazzo Pamphilj, Sala Palestrina. Obras de Alexander Scriabin, Heitor Villa-Lobos, Claudio Santoro, Franz Liszt e Radamés Gnatalli</p>
<p class="font_8">Outubro – Grandes Concertos por Grandes Pianistas. Sardoal ao Piano. Centro Cultural Gil Vicente. Obras de Beethoven, Scriabin e Litsz.</p>
<p class="font_8">Novembro – 5th International Piano Fest. City Hall of Subotica, Sérvia. Obras de Alexander Scriabin, Heitor Villa-Lobos, Claudio Santoro e Franz Liszt.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>2019</strong></p>
<p class="font_8">Abril – Recital de Piano. Palácio dos Capitães Generais, Angra do Heroísmo. Obras de Bach/Liszt - Gluck - Chopin - Brahms - Carlos Seixas - Scriabin - Rachmaninoff</p>
<p class="font_8">Maio – Recital de Piano de João Elias Soares. Universidade de Varsóvia. Música brasileira e europeia: Scriabin - Liszt - Santoro - Villa-Lobos - Nepomuceno – Rachmaninoff.</p>
<p class="font_8">Maio / Junho – IV Festival de Música de Mafra. Largo Coronel Brito Gorjão, Mafra. Concerto “Esplendor do Piano” com a Orquestra Sinfónica do Festival de Música de Mafra "Filipe de Sousa”. Lígia Moreno e João Elias Soares ao piano, e Armando Mota e José Ferreira Lobo como maestros.</p>
<p class="font_8">Junho – IV Festival de Música de Mafra. Casa de Cultura Jaime Lobo e Silva, Ericeira. Concerto “Mafra e o Brasil”. Obras de Scriabin - Liszt - Santoro - Villa-Lobos – Scriabin – Liszt – Rachmaninoff.</p>
<p class="font_8">Junho – Auditorium de l''Institut Français du Maroc (Rabat, Marrocos). Obras de Franz Liszt - Alexander Scriabin - Heitor Villa-Lobos - Mozart Camargo Guarnieri - Alberto Nepomuceno - Ernesto Nazareth - Cláudio Santoro.</p>
<p class="font_8">Outubro – Evening of Brazilian Classical Music. Croatian Music Institute. Embaixada da República Federativa do Brasil na Croácia.</p>
<p class="font_8">Dezembro – Sala de Concertos FR Pianos. Cruz Quebrada. Recital de Piano: João Elias Soares e Alexey Shakitko. Obras de A. Nepomuceno - H. Villa-Lobos - A. Scriabin - F. Chopin - S. Rachmaninoff</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>2021</strong></p>
<p class="font_8">Maio – Sala de Concertos FR Pianos. Cruz Qubrada. Recital de Piano A. Skriabin - L.V.Beethoven - F.Schubert - G.Gershwin - M.Balakirev. Aniversário Musical com os pianistas João Elias Soares e Alexey Shakitko e as sopranos Patrycja Gabriel e Eunice Foreid. Obras e A. Skriabin - L.V.Beethoven - F.Schubert - G.Gershwin - M.Balakirev.</p>
<p class="font_8">Junho – Convento Convida. Recital de Canto e Piano: “As mais famosas melodias de todos os tempos”. Igreja do Convento de Jesus. João Elias Soares, piano, Patrycja Gabrel, soprano, Carolina Figueiredo, mezzo-soprano. Obras: árias de ópera, peças para piano e duetos de compositores como Chopin, Bizet, Puccini, Mozart, Debussy e Rossini.</p>
<p class="font_8">Junho – V Festival de Música de Mafra. Auditório Municipal Beatriz Costa, Mafra. “Concerto para 2, 4, 6 e 8 mãos” com Adriano Jordão, António Luís Silva, Eduardo Jordão, João Elias Soares e Tiago Nunes.</p>
<p class="font_8">Outubro – Ciclo Escola Romena de Piano. Casa de Cultura Jaime Lobo e Silva, Ericeira. Obras de Lipatti – Mihalovic – Villa-Lobos – Scriabin</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>2022</strong></p>
<p class="font_8">Abril – Recital de Piano. Teatro Municipal de Portimão. Obras de Beethoven – Scriabin – Rachmaninoff – Liszt.</p>
<p class="font_8">Abril / Maio – Duo do Brasil. Plainsance du Gers e Sauveterre. “Les Fantaisies musicales de Sauveterre. Musiques Anciennes, Baroques, Modernes en Val d''Adour”. João Elias Soares ao piano e contratenor Luan Góes.</p>
<p class="font_8">Junho – VI Festival de Música de Mafra. Auditório Municipal Beatriz Costa. “Música no Coração” – As mais famosas melodias de todos os tempos. João Elias Soares ao piano e as sopranos Patrycja Gabrel e Carolina Figueiredo.</p>
<p class="font_8">Junho – Piano Summer Programm. Palácio Nymphenburg, Munique. Dueto Tiago Nunes e João Elias Soares. Obras de Schubert – D’Almeida – Piazolla. Recital a solo com obras de Santoro – Nepomuceno – Miranda – Villa-Lobos – Gnatalli – Nobre.</p>
<p class="font_8">Setembro. Recital de Piano. Festival Internacional Açores. Casa Memória Manuel de Arriaga. Obras de Heitor Villa-Lobos e Scriabin.</p>
<p class="font_8">Outubro – Ciclo Escola Romena de Piano. Casa de Cultura Jaime Lobo e Silva, Ericeira. Obras de Lipatti – Mihalovic – Villa-Lobos – Scriabin</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>2023</strong></p>
<p class="font_8">Março – Duo “Off BaRock” formado por Luan Góes (contratenor) e João Elias Soares (pianista). Círculo Eça de Queiroz, Lisboa. Obras de Dowland - Duparc - Liszt - R. Strauss - Villa-Lobos - Ravel – Rachmaninoff.</p>
<p class="font_8">Março – Concerto de Tributo Dona Maria Bárbara de Bragança. Celebração do Dia Internacional da Mulher. Biblioteca do Palácio Nacional de Mafra. João Elias Soares, piano, Carla Caramujo, soprano e José Carlos Araújo, Cravo.</p>
<p class="font_8">Junho – VII Festival de Música de Mafra. Biblioteca do Palácio Nacional de Mafra. Concerto “Farinelli em Mafra”. João Elias Soares ao piano e Luan Góes contratenor. Obras de Strauss – Lizst – Ravel – Tchaikovsky.</p>
<p class="font_8">Dezembro – Duo “Off BaRock” formado por Luan Góes (contratenor) e João Elias Soares (pianista). Natal Imperial, Casa de Petrópolis, Brasil. Obras de Dowland – Villa-Lobos – Duparc – Ravel – Strauss – Liszt – Rachmaninoff.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

