-- Row 20: Duo Aquaris
INSERT IGNORE INTO users (id, email, password, role) VALUES ('886434fc-3d62-4cda-be41-723a0a144117', 'wix-886434fc@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('57af7310-e619-4387-9d51-a6000a8cad15', '886434fc-3d62-4cda-be41-723a0a144117', 'duo-aquaris', 'Duo Aquaris', 'Duo Aquaris', '''+351938622300', NULL, 'Portugal', 'Portugal', 'Amadora', 'Av Camilo Castelo Branco 30-5.ºesq', NULL, '2610-031', 'Duo de Voz e Guitarra/Arquialaúde', NULL, 'https://static.wixstatic.com/media/886434_7c59a0c2c8614f90ae3b50e626e851a8~mv2.jpg', 'wix:document://v1/886434_5b11ab7300bd4c3aa4f39342664397c8.pdf/Duo%20Aquaris%20-%20nota%20biogr%C3%A1fica.pdf', NULL, NULL, NULL, NULL, 'https://www.youtube.com/@vanessayansoprano', 'https://static.wixstatic.com/mp3/886434_fc0a637695b243049455ee0bc9c1e258.wav', NULL, NULL, 'https://www.youtube.com/watch?v=u8QN_9RPXok', 'https://www.youtube.com/watch?v=WPD9hYr3ykE', 'https://www.youtube.com/watch?v=eRjUOffljRU', 'https://www.youtube.com/watch?v=-fJVQfEUSzc', 'https://www.youtube.com/watch?v=YzSu713TvTo', 'https://www.youtube.com/watch?v=kul2fjrD3_k', 'https://www.youtube.com/watch?v=QZ5o7TI7ZXo', NULL, NULL, NULL, '<p>O <span style="font-weight:bold">Duo Aquaris</span> iniciou a sua atividade na temporada 2023/2024, tendo já atuado em diversas salas da região da Grande Lisboa e também em Leiria e em direto para a Antena 2. Num diálogo de proximidade e familiaridade, Vanessa Yan (soprano) e Maria Correia (cordas dedilhadas) apresentam uma seleção de repertório baseado em épocas e estilos variados, com destaque para o Barroco, Classicismo e Romantismo, bem como arranjos musicais da sua autoria e contando com o apoio da musicóloga Inês Thomas de Almeida.</p><p> </p><p>Em 2024, o Duo Aquaris estreou-se com o programa <span style="font-weight:bold"><span style="font-style:italic">Amores e Desamores,</span></span> composto por peças de compositores do século XVI ao século XIX, para Voz e Guitarra. Já em 2025, foi convidado por Paula Castelar para participar no Ciclo de Música MIMA - Música escrita por mulheres, tocada por todos, com o programa <span style="font-weight:bold"><span style="font-style:italic">Compositoras virtuosas: Uma viagem do Barroco ao Romantismo,</span></span> um concerto tocado ao vivo no Audidório Carlos Paredes e transmitido em direto pela RTP-Antena 2 (https://antena2.rtp.pt/em-antena/mais-concertos/duo-aquaris-6-maio-19h00/). A seleção do repertório contou com o apoio da musicóloga Inês Thomas de Almeida.</p><p> </p><p>Nos meses de junho e agosto, apresentou-se com o programa,<span style="font-weight:bold"><span style="font-style:italic"> Dolcissimo Sospiro - Ao sabor do Renascimento e do Barroco</span></span>, tendo estado no Paço dos Ribafria, a convite da CulturSintra, para dois recitais de Voz e Guitarra/Arquialaúde, e também na Quinta do Sanguinhal, a convite de Manuela Gouveia, diretora artística do Ciclo de Concertos Comentados, integrado no SIPO - Semana Internacional de Piano de Óbidos. Ainda este ano, voltará a estar em Sintra, na Quinta da Regaleira, sempre a convite da CulturSintra, com dois programas originais, para guitarra e arquialaúde, respetivamente: <span style="font-weight:bold"><span style="font-style:italic">Anseios d&#x27;Alma</span></span> e um programa de Natal <span style="font-weight:bold"><span style="font-style:italic">O Menino Barroco</span></span>. Para além destes concertos, também tem sido convidado para eventos institucionais, como a comemoração dos 83 anos da ANA (Aeroportos de Portugal), com dois concertos ao vivo nos Terminais de Lisboa.</p>', '<p><span style="font-weight:bold">Vanessa Yan (Soprano)</span></p><p><br/>Natural de Lisboa, iniciou os seus estudos musicais em Canto com a cantora lírica Maria Cristina de Castro, com aulas particulares e na Escola de Música do Conservatório Nacional. Mais tarde, prosseguiu o Curso de Música na Academia de Amadores de Música, terminando o 8.º grau em Canto na classe de Margarida Marecos, com quem mantém o trabalho vocal, com a classificação máxima de 20 valores. Trabalhou com outros professores como Graziela Lé, Carlos Monteiro, Carla Simões e Orlanda Velez Isidro. Frequentou masterclasses com Mercè Obiol (AAM), Margarida Natividade (Academia Vocal Lisboa Cantat), Ana Paula Russo (Academia de Música de Óbidos) e James Newby (Fundação Calouste Gulbenkian). Durante o seu percurso musical, fez parte e colaborou com vários agrupamentos, destacando-se o Coro e o Ensemble Vocal da Universidade de Lisboa, o Coro de Câmara e o Coro Sinfónico Lisboa Cantat, o Coro de Câmara de Lisboa, o Coro Ricercare, o Ensemble do Sintra Estúdio de Ópera, o Octeto Anima Voces (do qual é fundadora), o Coro Appassionato, o Ensemble Corteto e como Cantora Profissional da Schola Cantorum de Santarém e da Schola Cantorum de São Nicolau. Atualmente, apresenta-se regularmente com o Duo Aquaris, cofundado em 2024 com a guitarrista e arquialaudista Maria Correia. De destacar o programa <span style="font-style:italic">Compositoras virtuosas: Uma viagem do Barroco ao Romantismo</span>, integrado no <span style="font-style:italic">Ciclo de Música MIMA, Música escrita por Mulheres</span>, transmitido em direto pela RTP-Antena 2 e com o apoio da musicóloga Ines Thomas Almeida, bem como quatro recitais de Voz e Guitarra/Arquialaúde no Paço dos Ribafria e Quinta da Regaleira, a convite da CulturSintra. </p><p> </p><p>Tem participado como coralista e solista em diversos concertos, destacando-se <span style="font-style:italic">Oratória de Natal</span> (Bach), com a Orquestra Metropolitana de Lisboa, direção de Leonardo García Alarcón; <span style="font-style:italic">Oratória de Ascensão</span> (Bach), com a Orquestra Metropolitana de Lisboa, direção de Hans-Christoph Rademann; <span style="font-style:italic">O Messias</span> (Händel), com Os Músicos do Tejo, direção de Marcos Magalhães. Como solista Soprano, destaca-se a <span style="font-style:italic">Missa Brevis em Ré menor K65</span>(Mozart), com a Orquestra de Câmara da AAM, direção de Jorge Lée e, mais recentemente, com o Pie Jesu do <span style="font-style:italic">Requiem</span> de Fauré, com o organista Daniel Nunes e direção de Alexandra Neves Fortes e com a Banda EMEB, com direção de Manuel Vigário.</p><p> </p><p><span style="font-weight:bold">Maria Correia (Guitarra clássica e Arquialaúde)</span></p><p> </p><p>Iniciou os seus estudos musicais aos dez anos de idade, em Azambuja, tendo ingressado posteriormente na classe de guitarra clássica do Conservatório Regional Silva Marques (Alhandra), com o professor Vasco Abranches. Concluiu a Licenciatura em Música no ISEIT – Instituto Piaget de Almada, em 2010, como aluna de Dejan Ivanovic e Ricardo Barceló.</p><p> </p><p>No âmbito da Música Antiga, desenvolve uma aprendizagem independente, sob a orientação de Rafael Bonavita, com quem estuda baixo contínuo, arquialaúde, guitarra barroca e tiorba. Frequentou aulas de técnica vocal com Orlanda Velez Isidro. Foi também aluna de António Carrilho (música de conjunto), apresentando-se em palco com diversos agrupamentos de câmara, a solo e em orquestra barroca. Participou ativamente em cursos de aperfeiçoamento musical, workshops e aulas privadas com músicos de renome internacional. Com Paula Pina, dinamizou recitais de poesia e música para crianças. Em 2015 apresentou-se, como solista, na cidade catalã de Lleida e obteve o 3º prémio da categoria de Música Barroca na 29ª edição do Prémio Jovens Músicos. Colaborou na gravação do CD “Scarlatti Sonatas &amp; Fandango”, com o cravista Cristiano Holtz, para a prestigiada editora Hortus. Atualmente, desenvolve a sua atividade através de projetos artísticos variados, tanto a solo como em grupos, dos quais se destaca o Duo Aquaris (com a soprano Vanessa Yan).</p><p> </p><p>Enquanto docente de Guitarra Clássica, iniciou a sua atividade pedagógica, entre 2008 e 2013, no Conservatório de Caldas da Rainha e no Conservatório Regional Silva Marques. De 2017 a 2024 foi professora e coordenadora artística e pedagógica na Escola de Música Duarte Costa (Lisboa), onde se dedicou ao estudo, recuperação e divulgação da obra do compositor português José Duarte Costa. Com base na experiência adquirida e na sua marcada paixão pelo ensino da música, dedica-se hoje em dia ao desenvolvimento do seu próprio método pedagógico, com especial ênfase nas componentes de criatividade, harmonia e improvisação.</p>', '<p><span style="font-weight:bold">Salão Tomás Borba, Academia de Amadores de Música (18/07/2024)</span></p><p><span style="font-style:italic">Programa Amores e Desamores </span></p><p> </p><p><span style="font-weight:bold">Espaço Lisboa Cantat, Associação Musical Lisboa Cantat. Integrado no &quot;Música às Quintas&quot; (03/10/2024)</span></p><p><span style="font-style:italic">Programa Amores e Desamores </span></p><p> </p><p><span style="font-weight:bold">Biblioteca Palácio Galveias. Integrado no ciclo Guitarras do Grácio &amp; Convidados (25/10/2024)</span></p><p><span style="font-style:italic">Programa Amores e Desamores </span></p><p> </p><p><span style="font-weight:bold">Auditório Municipal Maestro César Batalha. A convite do Centro Cultural de Oeiras (30/04/2025)</span></p><p><span style="font-style:italic">Programa Compositoras Virtuosas: Uma viagem do Barroco ao Romantismo</span></p><p> </p><p><span style="font-weight:bold">Auditório Carlos Paredes. Integrado no Ciclo de Música MIMA, Música escrita por Mulheres, tocada por todos (06/05/2025)</span></p><p><span style="font-style:italic">Programa Compositoras Virtuosas: Uma viagem do Barroco ao Romantismo</span></p><p> </p><p><span style="font-weight:bold">Concerto de Música Antiga pelos professores e alunos da Academia de Amadores de Música (23/05/2025)</span></p><p><span style="font-style:italic">Repertório barroco</span></p><p> </p><p><span style="font-weight:bold">Quinta do Sanguinhal. Ciclo de Concertos Comentados, integrado no SIPO - Semana Internacional de Piano de Óbidos (21/06/2025)</span></p><p><span style="font-style:italic">Programa Compositoras Virtuosas: Uma viagem do Barroco ao Romantismo</span></p><p> </p><p><span style="font-weight:bold">Paço dos Ribafria. A convite da CulturSintra (22/06/2025)</span></p><p><span style="font-style:italic">Programa Compositoras Virtuosas: Uma viagem do Barroco ao Romantismo</span></p><p> </p><p><span style="font-weight:bold">Paço dos Ribafria. A convite da CulturSintra (30/08/2025)</span></p><p><span style="font-style:italic">Programa Dolcissimo Sospiro - Ao sabor do Renascimento e do Barroco</span></p>', '<h2><span style="font-weight:bold">Próximos concertos:</span></h2><p> </p><p><span style="font-weight:bold">Cultursintra - Quinta da Regaleira</span></p><p>26 de outubro de 2025, às 16h00</p><p>28 de dezembro de 2025, às 16h00 (Recital de Ano Novo)</p><p> </p><p> </p><h2><span style="font-weight:bold">Contactos:</span></h2><p>duoaquaris@gmail.com</p><p>https://www.youtube.com/@vanessayansoprano</p><p>938 622 300 (Vanessa) | 968 106 683 (Maria)</p><p> </p>', 'https://static.wixstatic.com/media/886434_49bb6552c1c342c5a41bfa5c38765e5e~mv2.jpg', 'Jorge Carmona / RTP', 'https://static.wixstatic.com/media/886434_f85332c0f67d4c519f2d4c107d5944f3~mv2.jpg', 'João Barata / CML', 'https://static.wixstatic.com/media/886434_948f912cb325480dbf877bac772e26ea~mv2.jpg', 'João Barata / CML', 'https://static.wixstatic.com/media/886434_240a6d554fdc4369b133db62dabbb4d1~mv2.jpg', 'João Barata / CML', 'https://static.wixstatic.com/media/886434_9e6381d2e6d1424abca0ff9d6c150894~mv2.jpeg', 'João Barata / CML', 'https://static.wixstatic.com/media/886434_75a3af08303e426ab63bfc5f820bf960~mv2.jpeg', 'João Barata / CML', 'https://static.wixstatic.com/media/886434_2e73c5419cb9480caf75b55684cee32d~mv2.jpeg', 'João Barata / CML', 'https://static.wixstatic.com/media/886434_e64df14eb4d84e059ae8c0dda45da814~mv2.jpg', 'Show Doutor / CulturSintra', 'https://static.wixstatic.com/media/886434_b6ac43d1c7494411880031a385bb72f2~mv2.jpg', 'Show Doutor / CulturSintra', 'https://static.wixstatic.com/media/886434_96a6368382e041cdb8a0f3c0c4a8f353~mv2.jpg', 'Show Doutor / CulturSintra', 'https://static.wixstatic.com/media/886434_0bfc40e086eb41609a517b386ec0dc47~mv2.jpg', 'Show Doutor / CulturSintra', 'https://static.wixstatic.com/media/886434_008fb1a28ae44131b4e3567c988a3e96~mv2.jpeg', 'Evaristo Mendes', 1, 0, 1);

-- Row 21: Sofia Bagulho
INSERT IGNORE INTO users (id, email, password, role) VALUES ('8ae9c4db-af4f-4165-b270-8dab02932ac3', 'wix-8ae9c4db@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('ac941b5f-f1ef-4393-b0bb-eb2b6cea0fde', '8ae9c4db-af4f-4165-b270-8dab02932ac3', 'sofia-bagulho', 'Sofia Bagulho', 'Sofia', '935873744', '2001-02-13', 'Portugal', 'Lisboa', 'Loures, Lisboa, Portugal', 'Rua Barbosa de Resende, n20 3 andar', 'Rua Barbosa de Resende, n20 3 andar', '2670-420', 'Soprano', '"As histórias são compartilhadas através de emoções. O nosso trabalho como artistas é levar o público em uma jornada."', 'https://static.wixstatic.com/media/7b859e_f1f7b386dfe74ef6b3b72ac4bafb9036~mv2.jpg', 'wix:document://v1/8ae9c4_6658f2f035884b3480211568b33ec36e.pdf/Sofia_BAGULHO_Bio_ENG.pdf', 'https://www.facebook.com/SofiaBagulhoSoprano/', 'https://www.instagram.com/sofiabagulhosoprano/?locale=ru&hl=am-et', 'https://www.sofiabagulho-soprano.com/', NULL, 'https://www.youtube.com/@sofiabagulho9230', NULL, NULL, NULL, 'https://youtu.be/kf0TceiGOrA', 'https://youtu.be/1KmTYiMRzEQ', 'https://youtu.be/K6MpJTnHIUA', 'https://youtu.be/0FiXWE9ouJA', 'https://youtu.be/xq4c01j9syE', 'https://youtu.be/DNwqT6t3zeI', NULL, NULL, NULL, NULL, '<p>&quot;<span style="font-weight:bold">A bela e envolvente voz de Sofia Bagulho abraça o público de forma radiosa. É uma voz lírica, com uma certa leveza e virtuosismo próprios da juventude, e que tenderá para um soprano lírico no sentido mais glorioso dessa Fach</span>.” - Ana Paula Russo</p><p> </p><p><span style="font-weight:bold">Sofia Bagulho</span> iniciou os seus estudos musicais no Conservatório de Música D. Dinis e no Conservatório de Lisboa, onde estudou flauta com Ricardo Alves e canto com Ângela Silva. A jovem soprano está a tirar o Mestrado em Canto no Royal College of Music em Londres, com a professora Amanda Roocroft, Rafaela Albuquerque e o vocal coach Sebastian Wybrew, sendo a Sussex Scholar desta instituição.</p><p> </p><p>Em 2019, foi admitida no <span style="font-weight:bold">Trinity Laban Conservatoire of Music and Dance</span>, em Londres, onde concluiu a licenciatura sob a orientação de Joan Rodgers, Jon Christos e Robert Bottriell concluindo o curso com Distinção, tendo sido premiada com a Medalha de Prata do Trinity Laban do Departamento Vocal. Nos últimos anos, tem participado em diversas masterclasses com Rafaela Albuquerque, Lynn Eustis, Elisabete Matos, Ana Paula Russo, Rafaela Albuquerque, Aylish Tynan, Susan Bullock e Fiona Kimm, entre outros.</p><p><br/>Foi premiada com o 1º prémio no Bendada International Music Festival Concert Competition e Terras de Santiago, e com o 2º prémio no Medici International Music Competition, Euterpe Music Awards e Birmingham International Music Competition. Já deu recitais nos EUA, Portugal e Reino Unido. Sofia foi Semi-finalista na competiçao Prémio Jovens Músicos 2024 e nesse verão, ela fez parte da Ópera Don Pasquale com o Festival Longhope Opera como coro e cover de Norina.</p><p> </p><p>  “<span style="font-weight:bold">She is a hugely talented singer who has enormous potential and is already equipped with all the necessary skills and aptitudes that will enable her to have a successful career as a professional performer</span>.” - Robert Bottriell, vocal coach at Guidhall School of Music and Drama and Trinity Laban Conservatoire</p><p> </p><p>“<span style="font-weight:bold">Sofia´s voice is beautifully resonant and she has a very good breath control</span>” - Joan Rodgers, singing teacher</p><p> </p><p> </p>', '<p>“<span style="font-weight:bold">Sofia is a natural performer who thrives on the stage and concert platform and is already garnering international experience and enjoying a good deal of success both at home and abroad</span>.” - Robert Bottriell, vocal coach da Guidhall School of Music and Drama e Trinity Laban Conservatoire</p><p> </p><p>A soprano <span style="font-weight:bold">Sofia Bagulho</span> iniciou os seus estudos musicais aos 9 anos no Conservatório de Música D. Dinis com flauta, sob a orientação de Ricardo Alves. Mais tarde, aos 16 anos, iniciou os estudos de canto no Conservatório de Lisboa com Ângela Silva. Sofia é agora estudante de mestrado no Royal College of Music de Londres, estudando canto com Amanda Roocroft, Rafaela Albuquerque e Jo Ramadan. É uma bolsista de Sussex.</p><p> </p><p>Nas últimas temporadas, Sofia foi selecionada para atuar com o <span style="font-weight:bold">coro Participativo da Fundação Calouste Gulbenkian</span>, interpretando algumas das mais famosas obras corais, como <span style="font-style:italic">Messias </span>de Haendel e o <span style="font-style:italic">Requiem </span>de Mozart. Sofia cantou com <span style="font-weight:bold">Frédéric Chaslin</span>, <span style="font-weight:bold">Vitor Pablo Pérez</span>, <span style="font-weight:bold">Ed Garner</span>, <span style="font-weight:bold">Nathalie Schutzman</span>, <span style="font-weight:bold">Sakari Oramo</span>, <span style="font-weight:bold">Dominic Ellis-Peckam</span>, <span style="font-weight:bold">Paulo Lourenço</span> e <span style="font-weight:bold">Hillary Campbell</span>. Participou também em várias gravações para a BBC Sounds com o ORNCTLCC e cantou como solista em sociedades corais por todo o <span style="font-weight:bold">Reino Unido</span>. É um membro ativo do <span style="font-weight:bold">BBC Symphony Chorus</span> e <span style="font-weight:bold">Phillarmonia Chorus</span> atuando regularmente no Southbank Festival Hall, Barbican, Royal Albert Hall, entre outros.</p><p> </p><p>Com apenas um ano a cantar, garantiu um lugar no <span style="font-weight:bold">Trinity Laban Conservatory of Music</span> <span style="font-weight:bold">and Dance</span> e uma bolsa de coral no <span style="font-weight:bold">Old Royal Naval College Trinity Laban Chapel Choir</span> dirigido por Ralph Allwood. Fez também parte do Coro de Câmara de TL. Aí completou o bacharelato em Vocal Performance sob a orientação de Joan Rodgers, Jon Christos e Robert Bottriell, graduando-se com Primeiras Honras, sendo premiada com a Medalha de Prata TL do Departamento Vocal. Participou em várias masterclasses com músicos ilustres como Lynn Eustis, Ana Paula Russo, Aylish Tynan, Susan Bullock, Rafaela Albuquerque e Fiona Kimm.</p><p> </p><p>Sofia foi <span style="font-weight:bold">galardoada com vários prémios e distinções</span> de renome. Foi vencedora do primeiro prémio do Concerto Competition do Bendada International Music Festival e do Concurso Internacional de Música Terras de Santiago. Foi também premiada no Medici Music Competition, a Birmingham International Music Competition e Euterpe Music Awards Em Fevereiro de 2023 Sofia foi convidada pelo Bendada International Music Festival para actuar em Boston no Goethe-Institute e na Universidade de Boston. Sofia no Verão de 2024 participou nas meias-finais do Prémio Jovens Músicos e fez parte da Ópera Don Pasquale com o Festival Longhope Opera como cover de Norina e coro. Sofia dá também aulas de flauta e canto em paralelo com os estudos e colabora com o Bendada International Music Festival.</p>', '<p><span style="font-weight:bold">🎭 Experiência Operática</span></p><p> </p><p>Cenas de ópera * cover **</p><ul><li>Susana*, Barbarina* | Le nozze di figaro | Mozart - Circolo della Lirica di Padova 2024</li><li>Norina** - Don Pasquale | Donizetti - Longhope Opera Summer 2024</li><li>Armida* - Armida | Haydn - RCM Cenas de ópera 2024</li><li>Marzellina* - Fidelio| Beethoven - RCM Cenas de ópera 2024</li><li>Iris* - Handel - TL Cenas de óperas 2023</li><li>Katherine of Aragon -Try me, Good King (jukebox opera by Jennifer Hamilton) -TL Cenas de ópera 2023</li><li>Laura,  Clara, Donna Maria, Patrizia, Perdita -Barbara Strozzi (jukebox opera by Jennifer Hamilton) - TL Cenas de ópera 2022</li></ul><p> </p><p><span style="font-weight:bold">🎶Experiência Coral</span></p><p> </p><ul><li>Don Pasquale | Donizetti - Longhope Opera Summer 2024</li><li>Try me, Good King | (jukebox opera by Jennifer Hamilton) - TL Opera 2023</li><li>Anna Bolena | Donizetti - TL Opera 2022</li><li>La Bohéme | Puccini - TL Opera 2022</li><li>A Christmas Carol | Musgrave - TL Opera 2022</li><li>Barbara Strozzi | Barbara Strozzi; (jukebox opera by Jennifer  Hamilton) -TL Opera 2022</li><li>Semele | Purcell -TL Opera 2022</li><li>La Bohéme | Puccini - TL Opera 2021</li><li>Peter Grimes | Britten - TL Opera 2021</li><li>Eugene Onegin | Tchaikovsky - TL Opera 2021</li></ul><p> </p><p><span style="font-weight:bold">🎼 Experiência em Concertos</span></p><p> </p><ul><li>Coro - Missa de  St Cecilia | Garcia -BBC Symphony Chorus | 2024</li><li>Coro - Fiat Lux | Sir James Macmillan -BBC Symphony Chorus | 2024</li><li>Coro - Magnificat | Wigglesworth - BBC Symphony Chorus | 2023</li><li>Coro - The Planets | Holst - Trinity Laban Symphony Orchestra</li><li>Coro - Trois Nocturnes | Debussy; Mass in D | Smyth - BBC Symphony Chorus | 2022</li><li>Coro - Songs of Travel | Brahms - BBC Symphony Chorus | 2022</li><li>Coro - Requiem | Brahms - Old Royal Naval College Trinity Laban Chapel Choir | 2022</li><li>Coro - Messiah | Handel - Old Royal Naval College Trinity Laban Chapel Choir | 2021</li><li>Coro - The Creation | Haydn - The Sirius Orchestra | 2021</li><li>Coro - Requiem | Mozart - Calouste Gulbenkian Foundation | 2018</li><li>Coro - 9th Symphony| Beethoven - Orquestra  do Festival Coral de Verão |2018</li><li>Coro - Carmina Burana | Orff - Conservatório D. Dinis</li><li>Coro - La Damnation de Faust | Berlioz - Orquestra Filarmónica Portuguesa | 2018</li><li>Coro - Messiah | Handel - Calouste Gulbenkian Foundation | 2016</li><li>Coro - 9th Symphony| Beethoven - Orquestra  de Câmara de Cascais e Oeiras |2015</li><li>Soprano Solista - Obras Portuguesas- Bendada International Music Festival e Orquestra Sem Fronteiras | 2023</li><li>Soprano Solista - Gloria |  Vivaldi; Magnificat  | Leonarda; Dixit  Dominus | Handel - Northampton Bach Choir | 2023</li><li>Soprano Solista - Mass in C | Beethoven; Jesu, meine freude | Bach; Southend Bach Choir | 2023</li><li>Soprano Solista - Dixit Dominus | Handel; Dido’s lament | Handel; My heart is inditing | Purcell - ORNCTLCC with Ralph Allwood | 2023</li><li>Recital com Harpista Lucia Foti - Várias árias e canções; Queen Mary’s house; Morden College; Royal Hospital of  London</li><li>Quel guardo il cavaliere (Norina) | Don Pasquale - Bendada International Music Festival, Lisbon | 2024 Recital parte de NEST - (Tourism Portugal)</li><li>Meine Lippen sie Küssen e Me llaman la primorosa - Bendada International Music Festival, Lisbon | 2024</li><li>Solo Recital - Várias árias e canções - Bendada International Music Festival, Lisbon | 2023</li><li>Solo Recital - Várias árias e canções - Bendada International Music Festival, Boston | 2023</li><li>Soprano Solista - Missa Brevis | Haydn; Feltham Choral Society | 2022</li><li>Soprano Solista - Quel  guardo il cavaliere (Norina) | Don Pasquale; Bendada International Music Festival e Orquestra Sem Fronteiras | 2022</li></ul><p> </p><p><span style="font-weight:bold">💿 Gravações</span></p><p> </p><ul><li>Obras Corais</li><li>Viscount Organs</li><li>Broadcast</li><li>BBC Radio 3</li><li>ORNCTLCC with Ralph Allwood | 2022</li><li>BBC Sounds</li><li>ORNCTLCC recordings with Ralph Allwood | 2019</li></ul><p> </p><p><span style="font-weight:bold">🏆 Competições</span></p><p> </p><p>1º Prémio no Bendada Music Festival Concerto  Competition, Bendada, Portugal 2022</p><p>1º Prémio no Competição Música de Terras de Santiago, Almada, Portugal, 2022</p><p>2º Prémio em Euterpe International Music Awards Competition, 2022</p><p>2º Prémio em Birmingham International Music Competition, 2022</p><p>2º Prémio em Medici International Music Competition, 2022</p><p>Semi-finalista em English Song Competition at Trinity Laban  Conservatoire, 2022</p><p>Semi-finalista em Concurso de Canto de Lousada, Lousada, Portugal 2023</p><p>Semi-finalista em Prémio Jovens Músicos, Lisboa, Portugal, 2024</p>', NULL, 'https://static.wixstatic.com/media/8ae9c4_ca0cbfeca00f47dead417b1bb29691e1~mv2.jpg', 'Donna Maria in Barbara Strozzi, 2022', 'https://static.wixstatic.com/media/8ae9c4_b025f597586949a1b4eb6e05d769974e~mv2.jpg', 'Armida in "Armida" by Haydn, RCM Opera Scenes 2024 | Richard Smith', 'https://static.wixstatic.com/media/8ae9c4_d538a7ad579943c98cb8cfb7d5d7bf23~mv2.jpg', 'Armida in "Armida" by Haydn, RCM Opera Scenes 2024 | Richard Smith', 'https://static.wixstatic.com/media/8ae9c4_263224b5bd1a444ca49c4a5193f4dc17~mv2.jpg', 'CIMTS, 1st Prize, 2022. | José Russo', 'https://static.wixstatic.com/media/8ae9c4_40013ebd2adb4049936a8931e30268ac~mv2.jpg', 'Concert with Bendada International Music Festival | April 2024', 'https://static.wixstatic.com/media/8ae9c4_0fa8ab9d1d884a31ba74fe86fcf82ee8~mv2.jpg', 'Concert with Bendada International Music Festival | April 2024', 'https://static.wixstatic.com/media/8ae9c4_b7c7c1ec39ac4937acef7ebf2a82bfe9~mv2.jpg', 'Concert with Bendada International Music Festival | April 2024', 'https://static.wixstatic.com/media/8ae9c4_9540974ec6a84a70b875ff187237d2b2~mv2.jpg', 'Concert with Bendada International Music Festival | April 2024', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

