-- Row 25: Carla Frias
INSERT IGNORE INTO users (id, email, password, role) VALUES ('12a9d7f0-1073-47af-9fa8-e93f9887cb0e', 'wix-12a9d7f0@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('0ddc3850-69c0-4a46-bea2-2e832df63cef', '12a9d7f0-1073-47af-9fa8-e93f9887cb0e', 'carla-frias', 'Carla Frias', 'Carla', '964069328', '1995-05-09', 'Portugal', 'Portugal', 'Moita do Norte, Vila Nova da Barquinha', 'Rua Das Rosas N6', 'Rua das rosas', '2260-376', 'Soprano', '“A música é uma extensão da minha alma.”', 'https://static.wixstatic.com/media/12a9d7_2d87b44f3beb41f3b59e6255968f0c2c~mv2.jpeg', 'wix:document://v1/12a9d7_cded960216504232824ec23ef1d50db7.pdf/Carla%20Frias%20-%20Curr%C3%ADculo.pdf', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.youtube.com/watch?v=sfnptpixpGc', 'https://www.youtube.com/watch?v=sfnptpixpGc', 'https://www.youtube.com/watch?v=sfnptpixpGc', 'https://www.youtube.com/watch?v=sfnptpixpGc', 'https://www.youtube.com/watch?v=sfnptpixpGc', 'https://www.youtube.com/watch?v=sfnptpixpGc', 'https://www.youtube.com/watch?v=sfnptpixpGc', 'https://www.youtube.com/watch?v=sfnptpixpGc', 'https://www.youtube.com/watch?v=sfnptpixpGc', 'https://www.youtube.com/watch?v=sfnptpixpGc', '<p><span style="font-weight:bold">“Adoro a experiência de encarnar um personagem, vestir o papel e realmente mergulhar na performance operística. Viver o personagem em palco é o que verdadeiramente me fascina.”</span></p><p> </p><p>Carla Frias é uma talentosa soprano lírica, com uma voz excecional e uma presença cativante em palco.</p><p>Ao longo do seu percurso, Carla teve a oportunidade de aperfeiçoar a sua técnica vocal com alguns dos mais renomados professores de canto lírico em masterclasses, incluindo com a conceituada soprano russa Anna Samuil e com a aclamada soprano americana Melody Moore, entre outros.</p><p> </p><p>O seu talento tem brilhado tanto na oratória como na ópera. Na oratória, foi solista em obras como o &quot;Requiem&quot; de Fauré, &quot;Gloria&quot; de Vivaldi, &quot;Stabat Mater&quot; de Pergolesi e &quot;Missa da Coroação&quot; de Mozart, entre outras grandes obras do repertório. Na ópera, deu vida a personagens como Belinda em &quot;Dido e Eneas&quot; de Purcell, Berta em &quot;O Barbeiro de Sevilha&quot; de Rossini, Gianetta em &quot;L&#x27;elisir d&#x27;amore&quot; de Donizetti e Elle na ópera &quot;La voix humaine&quot; de Poulenc.</p><p> </p><p>Foi bolseira da Fundação Gestão dos Direitos dos Artistas em 2017 e ganhou o 2º Prémio no Festival Verão Clássico de Lisboa em 2021.</p><p>Desde 2017, integra também o prestigiado Coro Gulbenkian. Com uma técnica sólida, musicalidade expressiva e uma voz luminosa, Carla Frias é uma soprano a não perder de vista, prometendo elevar a arte do canto lírico a novos patamares.</p>', '<p>Carla Frias, natural de Vila Nova da Barquinha, descobriu cedo a sua paixão pela música, que fez sempre parte da sua vida. Em criança cantarolava canções tradicionais portuguesas com a sua família e aos quatro anos iniciou os seus estudos de piano, marcando o início de um percurso que a levaria a tornar-se numa das mais promissoras sopranos líricas portuguesas da atualidade.</p><p> </p><p>O seu interesse pela música vocal despertou ao entrar para o Conservatório de Música do Choral Phydellius. Aqui, além de completar o quinto grau em flauta transversal, começou os estudos de canto na classe da professora Manuela Moniz. Sob a orientação desta professora, Carla deu os primeiros passos na técnica vocal e descobriu o seu amor pelo canto lírico.</p><p> </p><p>Prosseguiu depois os estudos na Escola Artística de Música do Conservatório Nacional, na classe de canto da professora Filomena Amaro. Esta fase foi fundamental na sua formação, permitindo-lhe aprofundar os conhecimentos técnicos e interpretativos.</p><p> </p><p>O seu percurso académico culminou na Escola Superior de Música de Lisboa, onde obteve a Licenciatura e o Mestrado em Canto Lírico, sempre com classificações elevadas. No Mestrado, alcançou a classificação máxima com a sua interpretação da exigente ópera &quot;La voix humaine&quot; de F. Poulenc, evidenciando o seu talento e dedicação.</p><p> </p><p>Ao longo do seu percurso, Carla teve a oportunidade de aprender com alguns dos mais destacados professores de canto lírico em masterclasses, incluindo a conceituada soprano russa Anna Samuil, a aclamada soprano americana Melody Moore e a renomada soprano Helen Lawson. Estas experiências foram cruciais para o aperfeiçoamento da sua técnica vocal e para o seu crescimento como artista.</p><p> </p><p>O talento de Carla Frias tem sido reconhecido através de prémios e bolsas. Em 2017, foi bolseira da Fundação GDA (Gestão dos Direitos dos Artistas), em 2021 ganhou o 2º Prémio no Festival Verão Clássico de Lisboa e em Junho 2025 o 1° Prémio no Gabriel Fauré Music World Competition.</p><p> </p><p>Hoje, Carla Frias é um nome a reter no panorama da música clássica portuguesa, com uma carreira promissora pela frente. O seu percurso é um testemunho da sua dedicação, paixão e talento, desde as suas primeiras notas ao piano aos 4 anos até aos palcos onde hoje brilha como soprano lírica.</p>', '<p>Carla Frias já conta com uma carreira notável como cantora lírica, tendo protagonizado papéis em óperas como &quot;Dido e Eneias&quot; de Purcell, &quot;Il Barbieri di Siviglia&quot; de Rossini, &quot;L&#x27;elisir d&#x27;amore&quot; de Donizetti e &quot;La voix humaine&quot; de Poulenc. Tem sido também presença regular em concertos e oratórias, interpretando obras de Handel, Fauré, Pergolesi, Mahler, entre outros grandes compositores.</p><p>Desde 2017, faz parte do prestigiado Coro Gulbenkian, uma experiência que tem sido fundamental para o seu crescimento como artista.</p><p> </p><p><span style="font-weight:bold">Prémios</span>:</p><p>• 2025: 1° Prémio, Gabriel Fauré Music World Competition </p><p>• 2021: 2º Prémio, Festival Verão Clássico de Lisboa, Portugal</p><p>Bolsas:</p><p>• 2017: Bolsa da Fundação GDA (Gestão dos Direitos dos Artistas)</p><p> </p><p><span style="font-weight:bold">Ópera:</span></p><p>- 2023: &quot;Elle&quot; em &quot;La voix Humaine&quot; de F. Poulenc</p><p>- 2020: &quot;Giannetta&quot; em &quot;L&#x27;elisir D&#x27;amore&quot; de G. Donizetti</p><p>- 2018: &quot;Berta&quot; em &quot;Il Barbiere di Siviglia&quot; de G. Rossini</p><p>- 2017: &quot;Belinda&quot; em &quot;Dido and Aeneas&quot; de H. Purcell</p><p> </p><p><span style="font-weight:bold">Concerto/Oratória:</span></p><p>- 2022: &quot;Messias&quot; de G. F. Handel</p><p>- 2022: &quot;Requiem&quot; de G. Fauré</p><p>- 2022 e 2019: &quot;Stabat Mater&quot; de G. B. Pergolesi</p><p>- 2019: 4ª Sinfonia de G. Mahler</p><p>- 2017: &quot;Magnificat&quot; de John Rutter</p><p>- 2016: &quot;Missa da Coroação&quot; de W. A. Mozart</p><p>- 2013: &quot;Gloria&quot; de A. Vivaldi</p>', '<p><span style="font-weight:bold">Notícias &amp; Entrevistas</span></p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://cm-torresnovas.pt/index.php/comunicacao/agenda/musica/rhi-showcases-m%C3%BAsica,-espet%C3%A1culos-de-artistas-locais target=undefined>Câmara Municipal de Torres Novas - RHI showcases música, espetáculos de artistas locais-Música</a></span> </span></span></p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://rhi-think.com/activity/754/Showcase-Torres-Novas target=undefined>RHI - Showcase Torres Novas</a></span></span> - Think Arts, Talk Business, Make Culture</span></p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://omirante.pt/sociedade/2024-05-17-cinema-em-concerto-no-palacio-dos-desportos-em-torres-novas-29ee935e target=null>O Mirante (2024)</a></span></span> - Cinema em concerto no Palácio dos Desportos em Torres Novas</span></p><p><br/></p><p><br/></p><p><br/></p>', 'https://static.wixstatic.com/media/12a9d7_cca1894bbb134fc494a4a9e9422deee9~mv2.jpg', NULL, 'https://static.wixstatic.com/media/12a9d7_c01e5199701c47a2b0d05f67b6baa355~mv2.jpg', NULL, 'https://static.wixstatic.com/media/12a9d7_6a739a615720403782c8e675c22fc0b4~mv2.jpg', NULL, 'https://static.wixstatic.com/media/12a9d7_386b84d4489e410e8aedef0b443143c3~mv2.jpg', NULL, 'https://static.wixstatic.com/media/12a9d7_18c1ea4357354b12923b9ad94812358f~mv2.jpeg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 26: Duo Tágide
INSERT IGNORE INTO users (id, email, password, role) VALUES ('cdd0013a-a16d-4636-9775-4d144c83569d', 'wix-cdd0013a@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('5e7d3252-3341-482d-a5ae-ec41f75b4ef5', 'cdd0013a-a16d-4636-9775-4d144c83569d', 'duo-tagide', 'Duo Tágide', 'Inês', '0049 17660120137', '1984-03-02', 'Portugal', 'Alemanha', 'Berlin', 'Kanzowstrasse 13 C', NULL, '10439', 'Duo de canto e piano', 'Queremos envolver o público com obras únicas, provocantes, de grande beleza e suscitar curiosidade pelo género da canção lírica.', 'https://static.wixstatic.com/media/cdd001_e6e5cb2c01a44e26aa7a5fedf1f1d242~mv2.jpg', 'wix:document://v1/cdd001_36e5312ef8984d9a915313baca387c4e.pdf/Bio%20Duo%20T%C3%A1gide%20PT.docx.pdf', NULL, NULL, 'https://www.inessimoessoprano.com/duo-tagide', NULL, 'https://youtube.com/playlist?list=PLqF4oAqtO4v4vV95pxOHqccbHaRoY0OoL&si=uf2LGt7iVyYHlaQU', 'https://static.wixstatic.com/mp3/cdd001_903f2728d82e497e97a7e10f5c8bdece.wav', NULL, NULL, 'https://youtu.be/f30GgGVaU7Q?si=hyXSYo7MptQyBqXR', 'https://youtu.be/IKA7uAGHH5M?si=rjAFIEkIe2476zRc', 'https://youtu.be/cR-Hh3jMh9w?si=XTrZJuqZLUk9fdBE', 'https://youtu.be/62EGhjf_Zx0?si=fwNgkq7njYNZMGm5', 'https://youtu.be/SolAYfTjgVs?si=B0qY0YbpyV47hxju', 'https://youtu.be/dHkM52ows7Y?si=IUaU8o5jmCBKIQly', 'https://youtu.be/e_6qXEEGm3w?si=LmuUnQijFhMKxler', 'https://youtu.be/p2KMqtQLDT4?si=cagdqMjdkEekDbng', 'https://youtu.be/6UZ9cbk6Cb0?si=EBy10wR4UQkrWfct', 'https://youtu.be/qrtbGaOq4Y4?si=6gOYZr066yszpzwr', '<p class="font_8">Com quase duas décadas de colaboração, o Duo Tágide conta com um impressionante corpo de trabalho, abrangendo pérolas do barroco a composições contemporâneas, numa variedade de línguas desde o alemão ao finlandês. Apresenta-se regularmente nas mais prestigiadas salas e festivais portugueses bem como em concertos para a rádio Antena 2. A sua programação arrojada abarca, em cada recital, repertório do passado e do presente, mantedno sempre um espaço dedicado à canção erudita portuguesa.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">O Duo Tágide concebeu um projeto especial intitulado ‘Alma Ibérica'', cujo objetivo é divulgar a canção ibérica. O primeiro álbum Alma Ibérica (2014) obteve o apoio da Fundação Gestão dos Direitos dos Artistas. Para além das performances de recitais Alma Ibérica, o Duo Tágide criou uma Videoteca de Canção Ibérica para que o público geral possa descobrir e desfrutar de forma gratuita este repertório: <a href="https://youtube.com/playlist?list=PLqF4oAqtO4v58CGjb5e-w1GzmDQVnuRzv"><u>clique aqui</u></a>.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Em dezembro de 2024, o Duo Tágide reitera o seu compromisso com a música erudita contemporânea, lançando o álbum digital ‘Outonalma’ dedicado a ciclos de canções de compositores portugueses do século XXI, com o apoio da Fundação GDA.</p>', '<p style="text-align:justify">Nós somos o Duo Tágide: soprano Inês Simões e o pianista Daniel Godinho.</p><p style="text-align:justify"> </p><p style="text-align:justify">Conhecemo-nos enquanto jovens estudantes na Academia Nacional Superior de Orquestra, em Lisboa, onde descobrimos um amor mútuo pelo género da canção lírica. A procura de um som conjunto, bem como uma estética e forma de nos apresentarmos em público, levou-nos à exploração do repertório para esta formação em masterclasses com Rudolf Jansen, David Selig e Udo Reinemann em Amesterdão, com Eugene Asti e Sarah Walker em Londres e ainda Axel Bauni em Berlim.</p><p style="text-align:justify"> </p><p style="text-align:justify">Ao participarmos num dos maiores concursos internacionais  - &#x27;Franz Schubert und die Musik der Moderne&#x27; - o mundo da canção contemporânea abriu-se para nós, assim como as infinitas possibilidades de combinação desse novo repertório com obras mais conhecidas do público. Nasce então o nosso Duo Tágide e a nossa missão: envolver o público através da apresentação de obras que se cruzam entre si e tocar esse mesmo público pelo incentivo à imaginação e à criatividade. </p><p style="text-align:justify"> </p><p style="text-align:justify">Durante o processo de busca de um repertório variado, começámos a sentir necessidade de irmos às raízes e desenvolver um sentido de  identidade nacional. Pesquisámos um vasto património cultural, de uma beleza única e invulgar, e descobrimos um tesouro de obras menos conhecidas e de grande valor artístico na canção erudita Ibérica. Acreditamos que o projeto Alma Ibérica pode contribuir para a afirmação mundial da cultura ibérica e para o estabelecimento de um diálogo intercultural entre Portugal e Espanha. Adoptámos uma abordagem inovadora na escolha do repertório, comparando e contrastando as caraterísticas do repertório português e espanhol, profundamente enraizadas na sua identidade e carácter nacionais.</p><p> </p><p>Hoje em dia, o Duo Tágide têm com principal objetivo combinar e brincar com peças de três temas principais:</p><p>- o &#x27;Grande Repertório&#x27; - e sim, a música do século XX faz parte dele!</p><p>- Música contemporânea com ênfase em obras de compositores vivos e encomendas</p><p>- Canção Lírica ou Canção de Arte Portuguesa</p><p> </p><p style="text-align:justify">O mais recente programa &#x27;A Place of Our Own&#x27;, com a sua estreia em maio de 2025, é mais do que nunca um reflexo da missão do Duo Tágide: um apanhado de obras desde Purcell a Paulo Bastos que dá a conhecer todas as canções preferidas do duo num mesmo recital.</p>', '<p class="font_8"><strong>LINHA DO TEMPO</strong></p>
