-- Row 27: Vasco Dantas
INSERT IGNORE INTO users (id, email, password, role) VALUES ('6135c00e-51bd-4238-bd38-1c48fec77e6e', 'wix-6135c00e@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('2e8a6235-f53d-4cfe-8b7f-dd79572ef76b', '6135c00e-51bd-4238-bd38-1c48fec77e6e', 'vasco-dantas', 'Vasco Dantas', 'Vasco', '999999999', '1993-07-15', 'Portugal', 'Portugal', 'Porto', 'xxxxxxxx', NULL, 'xxxxx', 'Pianista', 'Ser músico é transformar ideias em sons e provocar emoções infinitas nas pessoas que a ouvem.', 'https://static.wixstatic.com/media/6135c0_9f6d5edc29d54d9597f4f6220ea40172~mv2.jpg', 'wix:document://v1/6135c0_cd571aface4a4b98a2e1127acf07cb83.pdf/Vasco%20Dantas%20-%20Biografia.pdf', NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/6135c0_02dad76d95ac4a8e9d911fb5decfd606.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=E7vmGonU52Y', 'https://www.youtube.com/watch?v=E7vmGonU52Y', 'https://www.youtube.com/watch?v=de3q-ba2-fg', 'https://www.youtube.com/watch?v=rlR2DB6dDUo', 'https://www.youtube.com/watch?v=dCfIldk1mpo', 'https://www.youtube.com/watch?v=8Qlz7tKRi1A', 'https://www.youtube.com/watch?v=TicOL4nex2U', 'https://www.youtube.com/watch?v=l_uhY9TSxS4', 'https://www.youtube.com/watch?v=_HS92jRAqO0', 'https://www.youtube.com/watch?v=dCfIldk1mpo', '<h2><span style="font-style:italic">“A sua mestria técnica e o seu grande poder emocional transformam as suas actuações em experiências impressionantes.” </span>MDR Klassik</h2><h2> </h2><p>Vasco Dantas é um pianista português de renome internacional que desde muito cedo evidenciou uma personalidade cativante e um <span style="font-weight:bold">talento prodigioso</span> através da força das suas interpretações ao piano.</p><p> </p><p>Destaca-se pela sua <span style="font-weight:bold">musicalidade profunda</span> e <span style="font-weight:bold">técnica primorosa</span>. As suas interpretações cativam pela conexão emocional, vigor e elegante contraste de paletas sonoras.</p><p>O seu vasto repertório, do romantismo ao nacionalismo russo, revela um especial apreço pelos desafiadores &quot;Grandes Estudos&quot; de <span style="font-weight:bold">Liszt </span>e <span style="font-weight:bold">Rachmaninoff</span>, que executa com reconhecido virtuosismo.</p><p> </p><p>A crítica exalta a sua <span style="font-weight:bold">sensibilidade inteligente</span> e leituras de intenso lirismo poético, conjugando uma técnica deslumbrante a um <span style="font-weight:bold">sofisticado sentido estético</span>. Com uma impressionante maturidade artística, Vasco Dantas imprime uma personalidade arrebatadora às obras que interpreta, desvendando novas camadas de beleza em cada performance, seja nos grandiosos concertos românticos ou delicadas miniaturas impressionistas.</p>', '<h3>Vasco Dantas é um pianista português cuja trajetória revela um talento verdadeiramente prodigioso. Nascido no Porto em 1992, a sua habilidade musical manifestou-se de forma quase fortuita, quando, aos quatro anos, começou a &quot;adivinhar&quot; as notas tocadas num ensaio de coro em que estava a acompanhar o pai, que era coralista. Foi o maestro José Manuel Pinheiro, impressionado, quem identificou o seu talento e potencial ouvido absoluto, aconselhando-o a ingressar nos estudos musicais.</h3><p> </p><p>Assim, iniciou os seus estudos de piano ainda aos quatro anos de idade na <span style="font-weight:bold">Escola Valentim de Carvalho</span>, dando a sua primeira apresentação pública aos seis anos, na RTP. Embora os seus professores por vezes o fizessem exibir a sua rara habilidade de ouvido absoluto, identificando notas de olhos fechados, Vasco contrariava a noção de que era um mero talento nato, treinando incansavelmente essa capacidade em casa com a família.</p><p> </p><p>Em 2000, ingressou no <span style="font-weight:bold">Conservatório de Música do Porto</span>, onde estudou durante uma década sob a orientação da reputada professora <span style="font-weight:bold">Rosgard Lingardsson</span>. O seu aprimoramento foi constante, conquistando mais de 15 primeiros prémios em importantes concursos nacionais e internacionais.</p><p> </p><p>Ao completar o curso Complementar de Piano com nota máxima em 2010, Vasco decidiu arriscar numa carreira internacional. O seu inegável talento abriu-lhe as portas do <span style="font-weight:bold">Royal College of Music de Londres</span>, onde se formou com distinção sob a orientação dos mestres <span style="font-weight:bold">Dmitri Alexeev</span> e <span style="font-weight:bold">Niel Immelman</span>. Prosseguiu os seus estudos obtendo o <span style="font-weight:bold">Mestrado em Performance</span> com nota máxima na <span style="font-weight:bold">Universidade de Münster com Heribert Koc</span>h, onde foi aceite para o Doutoramento Konzertexamen.</p><p> </p><p>A partir de então, a sua ascensão foi meteórica. Conquistou dezenas de prémios em concursos por toda a Europa, consolidando o seu nome entre as novas gerações mais promissoras do pianismo mundial. As suas estreias em importantes palcos como o Hong Kong City Hall, a Grande Sala do Conservatório Tchaikovsky em Moscovo e o lendário Carnegie Hall de Nova Iorque foram verdadeiros marcos, celebrados pela crítica internacional.</p><p>Vasco Dantas também obteve o <span style="font-weight:bold">grau de mestre em Ensino da Música pela Universidade de Aveiro e o diploma Art of Teaching pelo Royal College of Music de Londres</span>.</p><p> </p><p> </p>', '<p>Com uma formação musical de excelência e um talento genuinamente prodigioso, Vasco Dantas rapidamente se projetou no cenário internacional, construindo uma carreira de concertista aclamada globalmente.</p><p> </p><h2><span style="font-weight:bold">PRÉMIOS</span></h2><p> </p><p>Conquistou mais de mais de 50 prémios e distinções em concursos nacionais e internacionais, incluindo os seguintes:</p><ul><li>Grand Prix no Valletta International Piano Competition (Malta)</li><li>Prix Spécial no Concours International de Piano SAR La Princesse Lalla Meryem (Marrocos)</li><li>3º Prémio no Münster Steinway &amp; Sons Piano Competition</li><li>Bolsa de Viagem para o Festival de Bayreuth da Fundação Richard Wagner (2016)</li><li>Medalha de Mérito Dourada da Câmara Municipal de Matosinhos (Portugal)</li><li>Prémio da Fundação Eng. António de Almeida</li><li>Melhor Prémio Português no Concurso Internacional de Viseu</li><li>Prémio Esther Fisher como melhor aluno de graduação do Royal College of Music (2013)</li><li>Prémio Antena 2 da Rádio Nacional Portuguesa</li><li>Henry Wood Trust Prize (2011 e 2012)</li><li>Prémio Casa da Música (2009)</li><li>1º Prémio no Concurso Internacional de Piano Santa Cecília do Porto</li><li>1º Prémio no Concurso de Interpretação do Estoril</li><li>1º Prémio no Concurso Internacional de Piano Ría de Vigo (Espanha)</li><li>1º Prémio no Concurso Internacional de Piano do Alto Minho</li><li>1º Prémio no Concurso Internacional de Piano do Fundão</li><li>1º Prémio no Concurso Internacional de Piano Florinda Santos</li><li>1º Prémio no Concurso de Música de Câmara Maestro Ivo Cruz</li></ul><p> </p><h2><span style="font-weight:bold">ATUAÇÕES MEMORÁVEIS</span></h2><p> </p><ul><li>Hong Kong City Hall (2015): Vasco Dantas interpretou o Concerto nº 1 de Liszt com a Hong Kong Symphonia. Esta performance destaca-se por sua escolha de repertório e pela interação com o público, mostrando sua habilidade em transitar entre diferentes estilos musicais com fluidez;</li><li>Grande Sala do Conservatório Tchaikovsky, Moscovo (2017): Numa das salas mais prestigiadas do mundo, Vasco apresentou-se com a renomada Chamber Orchestra Kremlin. Recebeu elogios pela sua técnica impecável e interpretação apaixonada, destacando-se em um palco mundialmente famoso;</li><li>Carnegie Hall, Nova Iorque (2019): A estreia de Vasco Dantas neste lendário palco foi um momento definidor na sua carreira. Realizou um recital solo, consolidando sua reputação internacional e realizando o sonho de muitos pianistas.</li></ul><p>Clique <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.google.com/maps/d/viewer?mid=1UKaLSCjSPu8Xo-QgXICHE6PVveo&g_ep=CAISDTYuMTEzLjAuNTcwMjAYACDdYipRLDk0MjIxMTM3LDQ3MDcxNzA0LDQ3MDY5NTA4LDk0MjE0MTcyLDk0MjE4NjM1LDk0MjAzMDEzLDQ3MDg0MzA0LDk0MjA4NDU4LDk0MjA4NDQ3QgJQVA%3D%3D&g_st=ic&ll=19.5642592046097%2C18.196636457812474&z=2 target=_blank>aqui </a></span></span>para aceder ao mapa de atuações de Vasco Dantas.</p><p> </p><p> </p><h2><span style="font-weight:bold">COLABORAÇÕES E PARCERIAS</span></h2><p> </p><ul><li>É Diretor Artístico dos vários Music Series Festivals: Algarve Music Series, Sezim Music Series, The Piano Concerto Festival e “Teatro del Lago Music Series”, que se realizará em dezembro de 2024, na Patagónia do Chile;</li><li>Leciona regularmente em masterclasses e festivais internacionais;</li><li>Tem sido apoiado pela AVA Musical Editions e AMMFoundation.</li></ul><p> </p><h2><span style="font-weight:bold">LINHA DO TEMPO</span></h2><p> </p><p><span style="font-weight:bold">2024 </span>- É diretor artístico da 1ª Edição do Sezim Music Series.</p><p><span style="font-weight:bold">2023</span></p><ul><li>Organização e direção artística do “The Piano Concerto Festival”, no Algarve.</li><li>Concluiu o Doutoramento Konzertexamen na Universidade de Münster.</li></ul><p><span style="font-weight:bold">2022 </span>- Estreia a solo no Théâtre des Champs-Elysées em Paris com a Orquestra Filarmónica Portuguesa. É diretor artístico do Avis Music Series.</p><p><span style="font-weight:bold">2021 </span>- Lança o aclamado álbum &quot;Departure&quot; pela KNS Classical.</p><p><span style="font-weight:bold">2019 </span>- Estreia em recital solo no Carnegie Hall em Nova Iorque.</p><p><span style="font-weight:bold">2018 </span>- Junta-se como diretor artístico ao Algarve Music Series.</p><p><span style="font-weight:bold">2017 </span>- Estreia na Rússia na Grande Sala do Conservatório Tchaikovsky em Moscovo com a Chamber Orchestra Kremlin.</p><p><span style="font-weight:bold">2016</span></p><ul><li>Estreia-se na Alemanha com as orquestras de Jülich e Aachen tocando Rachmaninoff;</li><li>Recebe a Bolsa de Viagem para o Festival de Bayreuth da Fundação Richard Wagner;</li><li>Forma-se com Mestrado em Performance com nota máxima na Universidade de Münster com Heribert Koch;</li><li>É aceite para o Doutoramento Konzertexamen na Universidade de Münster.2015 - Estreia na Ásia com a Hong Kong Symphonia interpretando o Concerto nº1 de Liszt no Hong Kong City Hall.</li></ul><p><span style="font-weight:bold">2014 </span>- Estreia nas Américas com a Orquestra Sinfónica do Espírito Santo em Vitória, Brasil.</p><p><span style="font-weight:bold">2013 </span>- Recebe o Prémio Esther Fisher como melhor aluno de graduação do Royal College of Music.</p><p><span style="font-weight:bold">2012 </span>- Recebe o Henry Wood Trust Prize.</p><p><span style="font-weight:bold">2011 </span>- Recebe o Henry Wood Trust Prize.</p><p><span style="font-weight:bold">2011 </span>- Estreia em recital a solo na Sala Suggia da Casa da Música no Porto.</p><p><span style="font-weight:bold">2010 </span>- Ingressa no Royal College of Music em Londres para estudar com Dmitri Alexeev e Niel Immelman.</p><p><span style="font-weight:bold">2010 </span>- Conclui o Curso Complementar de Piano no Conservatório do Porto com nota máxima.</p><p><span style="font-weight:bold">2009 </span>- Recebe o Prémio Casa da Música.</p><p><span style="font-weight:bold">2006 </span>- Primeira apresentação pública aos seis anos no Museu do Carro Elétrico do Porto.</p>', '<p> </p><p> </p><p>A sua discografia inclui cinco álbuns. &quot;<span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://vascodantas.com/order-cd-form/ target=_self>Departure</a></span></span></span>&quot; pela KNS Classical é o mais recente, lançado em 2021.</p><p> </p><h2><span style="font-weight:bold">DISCOGRAFIA</span></h2><p> </p><p>A sua discografia inclui <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://vascodantas.com/order-cd-form/ target=_blank>cinco álbuns</a></span></span>:</p><ul><li>Promenade (2015)</li><li>Golden Liszt (2016)</li><li>Freitas Branco | Sonatas (2020, nomeado para &quot;Melhor Álbum Clássico&quot; pelos Prémios Play)</li><li>Poetic Scenes (2020, nomeado para &quot;Artista Revelação do Ano&quot; pela Opus Klassik)</li><li>&quot;<span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://vascodantas.com/order-cd-form/ target=_self>Departure</a></span></span></span>&quot; pela KNS Classical é o mais recente, lançado em 2021.</li></ul><p> </p><h2><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h2><p> </p><p><span style="text-decoration:underline"><a href=https://www.smartx.art/post/vasco-dantas-a-ascens%C3%A3o-de-um-pianista-portugu%C3%AAs-de-excel%C3%AAncia target=undefined>Entrevista SMARTx (2024)</a></span>- Vasco Dantas: a ascensão de um pianista português de excelência</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://comunidadeculturaearte.com/reportagem-o-amigavel-duelo-dos-pianistas-raul-da-costa-e-vasco-dantas-no-festival-de-sintra/ target=_top>Comunidade Cultura e Arte (2023)</a></span></span> - Reportagem. O amigável duelo dos pianistas Raúl da Costa e Vasco Dantas no Festival de Sintra</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.rtp.pt/play/palco/p9244/e566023/vasco-dantas-rocha target=_blank>RTP (2021)</a></span></span> - Vasco Dantas Rocha | Cistermúsica</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=3uGVnTiGMTw target=_blank>Entrevista InMusic (2021)</a></span></span> - Vasco Dantas Rocha no Teatro Miguel Franco em Leiria</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://visao.pt/atualidade/sociedade/2020-12-09-album-do-pianista-vasco-dantas-e-primeira-escolha-do-ano-da-revista-alema-orchestergraben/ target=_blank>Visão (2020)</a></span></span> - Álbum do pianista Vasco Dantas é “primeira escolha do ano” da revista alemã Orchestergraben</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.rtp.pt/noticias/cultura/pianista-vasco-dantas-nos-eua-para-atuar-no-arkansas-antes-de-estreia-no-carnegie-hall_n1142863 target=_blank>RTP Notícias (2019)</a></span></span> - Pianista Vasco Dantas nos EUA para atuar no Arkansas antes de estreia no Carnegie Hall</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://xmusic.pt/entrevista/1508-vasco-dantas-rocha target=_blank>Entrevista XpressingMusic (2013)</a></span></span> - Vasco Dantas Rocha. Juventude e empreendedorismo rumo a uma carreira consistente...</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.meloteca.com/portfolio-item/vasco-dantas-rocha-entrevista/ target=_blank>Entrevista Meloteca</a></span></span> - Vasco Dantas Rocha</p><p> </p><h2>Quer saber mais?</h2><h2>Entre em contacto connosco!</h2>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

