INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('03196696-3fc3-49ab-b89e-79ff5e30990f', 'ec2ddd60-3c4f-4309-8b33-7594793922c3', 'eunice-abranchesaguiar', 'Eunice Abranches d''Aguiar', 'Eunice Isabel', '''+351912878097', '1998-05-03', 'Portugal', 'Portugal', 'Arcozelo, V.N.Gaia', 'Rua da Pedreirinha, n.52', NULL, '4410-323', 'Soprano', 'Soprano
Early Music Specialized
Currently on the Master in Advanced Vocal Ensemble Studies', 'https://static.wixstatic.com/media/ec2ddd_0cf655739566409fa4828b1d050a36b4~mv2.jpg', 'wix:document://v1/ec2ddd_40bb790661b2432c9a5569363eb3aed3.pdf/short%20bio%20set%202024.pdf', 'https://www.facebook.com/EuniceAbranchesAguiar98', 'https://www.instagram.com/niceaaguiar/', 'https://euniceaguiar.wixsite.com/soprano/', NULL, 'https://www.youtube.com/@euniceabranchesdaguiar3304', NULL, NULL, NULL, 'https://www.youtube.com/watch?v=DK7j8N0V4wc', NULL, 'https://www.youtube.com/watch?v=RhMfoYT8_EY', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Licenciada em Música Antiga pela ESMAE, iniciou os estudos musicais em 2008 na Academia de Música de Vilar do Paraíso, na classe de violino de Luís Trigo, iniciando, mais tarde, o estudo na área da voz com Patrícia Quinta. Frequentou outras instituições de ensino artístico como a A. de Música de Espinho e o CNSMD de Lyon. Actualmente estuda no Mestrado em Estudos Avançados em Música Vocal de Ensemble na Schola Cantorum Basiliensis (Suíça).</p><p>Participou em masterclasses com Jean-Denis Monory, Rafael Muñoz, entre outros. Interpretou obras como a ‘Paixão S. São Mateus’ (J.S.Bach), com Concerto Ibérico; ‘Dido &amp; Aeneas’ (H.Purcell) – Dido; ‘Ein Deutsches Requiem’ (J. Brahms), com o coro do CNSMDL; Marcou presença em festivais como Temporada de Música em São Roque, Festival Antena 2, FeMAUB (Esp.), Na Rota do Peregrino – II encontro de Mús. Medieval de Ponte de Lima, e muitos outros. É membro efectivo d’O Bando de Surunyo e Coro do Distrito de Braga. Colabora, ainda, com a Banda do Exército Português – Dest. Porto, Capella Joanina, Divino Sospiro, entre outros agrupamentos. Recentemente integrou a Jeune Orchestre Baroque Européen.</p>', '<p> </p>', '<p>2024 – Festival Inspiration d’Ardèche (Fr) – com JOBE – “La Susanna” de A. Stradella;  - FeMASE (Festival de Música Antiga da Serra da Estrela), com O Bando de Surunyo; - Festival de Música da Primavera de Viseu – com O Bando de Surunyo; - Festival “Lisboa Música Antiga”, com Divino Sospiro; - Recitais do Duo Semper Florens; - Concerto final do projecto Bridging Musical Heritage (vencedor de prémio REMA), numa parceria entre O Bando de Surunyo, Capella Sanctae Crucis e Ensemble La Danserye; - Semana Santa de Braga, com Coro e Orquestra do Distrito de Braga; - “As sete Mulheres do Minho”, no Theatro Circo em Braga, com o Coro do Distrito de Braga; </p><p>2023 – Festival de Música Antigua de Úbeda y Baeza (FeMAUB), com O Bando de Surunyo e Divino Sospiro; - Festival Nuits Musicales d’Uzès e Festival de L’Abbaye de Sylvanès (Fr), com a Jovem Orquestra Barroca Europeia (JOBE), “La Susanna” de A. Stradella; - “Sons de outros tempos” – O Bando de Surunyo; - Residência artística com O Bando de Surunyo e Los Afectos Diversos, aquando do projecto Bridging Musical Heritage, em Valladolid (Esp); - “Engagement Prize – Oper Köln” em Innsbruck Festwochen – Cesti Competition; - Ciclo Mundos e Fundos da U. Coimbra – com O Bando de Surunyo; - Ciclo de Concertos de Natal do Município de Ílhavo, com O Bando de Surunyo; - Festival Província Sonora, com O Bando de Surunyo, em Macedo de Cavaleiros; - Celebrações dos 25 anos da Procissão da Burrinha (Braga), com o Coro do Distrito de Braga; - Semana Santa de Braga, com o Coro e Orquestra do Distrito de Braga;</p><p>2022 – Residência Artística na Associação Fogo Lento, sob direção de Henrique</p><p>Apolinário;</p><p>– Festival Antena 2, com O Bando de Surunyo;</p><p>– Festival de Música Religiosa das Canárias, com O Bando de Surunyo;</p><p>– TEMPORADA CRUZADA FRANÇA-PORTUGAL, concerto de Páscoa em Castelo Branco e Oeiras, com os ensembles Stradivaria e Flores de Mvsica;</p><p>– “Ũa enselada ibérica”, com O Bando de Sununyo em Bragança;</p><p>– Concerto Solidário com a Orquestra do Distrito de Braga (Reguiem de G.Fauré – solista);</p><p>– Residência Artística “Susana, un dia”, com O Bando de Surunyo, no Mosteiro de Tibães;</p><p>– Dani Barokne Musik (com O Bando de Surunyo);</p><p>– Temporada de Música em São Roque (com O Bando de Surunyo);</p><p>2021 – Festival Internacional de Música da Primavera de Viseu, con O Bando de Surunyo;</p><p>– PORTO LIBERAL “Pessoas, Espaços e Memórias” – Exéquias a D. Pedro IV, com a Banda do Exército Português – Destacamento do Porto (Igreja da Lapa, Porto);</p><p>– FIOMS (Festival de Órgão e Música Sacra, Porto);</p><p>– Jornadas Europeias do Património, com Spirito dell’Anima (Chamusca);</p><p>– VIII Encontro de Música Coral da Póvoa de Varzim, com O Bando de Surunyo;</p><p>– Temporada de Música em São Roque, com O Bando de Surunyo;</p><p>– Orphika/Mundos e Fundos, com o Bando de Surunyo e O.C.C. (Coimbra);</p><p>– Residência artística com O Bando de Surunyo, no Mosteiro de Tibães (Braga) e Igreja do Bonfim (Porto);</p><p>2020 - VI Festival de Música Barroca de Faro, com Capella Joanina – Dir. Musical: João Paulo Janeiro</p><p>- 400 anos da publicação de Flores de Música de Manuel Rodrigues Coelho, com Spirito Dell’Anima</p><p>- Ópera Dido &amp; Aeneas (interpretanto Dido), H. Purcell - ESMAE;</p><p>- Dark Natures, estreia da peça contemporânea de Gonçalo Mota;</p><p>- Festival Fora do Lugar, com O Bando de Surunyo;</p><p>- XIII West Coast Early Music Festival (Oeiras), com Concerto Ibérico e Duo</p><p>Arparla;</p><p>- Árias do Messias, J.F.Haendel, com Concerto Ibérico (Oeiras)</p><p>- Ciclo de música ORPHIKA, com O Bando de Surunyo e O.C.C.</p><p>2019 - Ópera-Ballet L&#x27;Europe Galante, by A. Campra - Dir.: Benjamin Chénier</p><p>- Paixão Segundo S. Mateus, J.S.Bach - Concerto Ibérico – Dir. Musical.: João Paulo Janeiro; Concertino: Florian Deuter; Solistas: Magna Ferreira, Carlos Mena, Daniel Issa, Tiago Mota, Benjamin Glaubitz;</p><p>- Le Nuove Musique, &quot;Lagrime mie, a che vi trattenete?&quot; - Recital em honra às mulheres compositoras do barroco - Paraninfo de la Universidad de Santiago de Compostela;</p><p>- Recital: Soprano e órgão, com António Pedrosa (Grijó, V.N.Gaia);</p><p>- Recital – ópera Contemporânea: O tempo tudo acaba, de Rúben Borges</p><p>- III Ciclo de Música de São Francisco, com a Banda do Exército Português – Destacamento do Porto;</p><p>- Encontros de Música Antiga de Loulé, com O Bando de Surunyo (dir.: Hugo Sanches);</p><p>- Temporada de Música de São Roque, com Capella Joanina;</p><p>- Ein Deutches Requiem, Brahms - CNSMD, Lyon;</p><p>- Participação no CD/Projecto &quot;Ai Dina, Dina, Dana&quot;, d’O Bando de Surunyo;</p><p>2018 - Opera Rodrigo, J.F.Haendel – Dir. Musical: Ana Mafalda Castro;</p><p>- Fables of La Fountain, musica de Michel-Richard Delaland – Dir. musical.: Magna Ferreira;</p><p>- II Encontro de Música Medieval em Ponte de Lima – Dir.: Maurício Molina;</p><p>- Recital: Soprano e órgão, com António Pedrosa (Grijó, V.N.Gaia);</p><p>- Recital: Soprano, órgão e violino, em Miranda do Douro, com Jacinto Neves e Salvatore Pronestí;</p>', NULL, 'https://static.wixstatic.com/media/ec2ddd_0d0c93bf33284794a8a331dd8f9758be~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_22f8c16c743b472bad7446ebd68f464b~mv2.png', NULL, 'https://static.wixstatic.com/media/ec2ddd_0c0a2d2c8cf141b4862d3177c240e5f1~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_af9f348cb2034f4aad91519ff1c35c0f~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_a223ee9ca48a48789f6dad827f850d22~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_41fe404c50ab49e4b5f2b33cea260fb0~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_11156f14efbe4bfaae30da1ae093aefe~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_99703ef5a2bc476ea50c92f508503498~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_17c6a458ccf24ff5bee3aa03507e53aa~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_95ddac01a6ea4d19a983a72a28c07364~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_1d7ec79b3fe6438299bca0ac03ac4529~mv2.jpg', NULL, 'https://static.wixstatic.com/media/ec2ddd_12284184939546a3b04c2b77ced9a6dd~mv2.jpg', NULL, 1, 0, 0);

