-- Row 32: Ángela Lorite
INSERT IGNORE INTO users (id, email, password, role) VALUES ('d395c12f-a78e-4ebe-b5c6-a8efde724a1e', 'wix-d395c12f@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('89375d26-0768-4c6c-8482-be33dda133f4', 'd395c12f-a78e-4ebe-b5c6-a8efde724a1e', 'angela-lorite', 'Ángela Lorite', 'Ángela', '''+34616233096', '1978-08-02', 'Spain', 'Spain', 'Barcelona', 'Passeig Mare de Déu del Coll, 110. Bajo.', NULL, '08023', 'Mezzo-Contralto', 'Mezzo, Contralto y  Actriz apasionada, con 4 octavas de gran flexibilidad y volumen que abarca un amplio repertorio', 'https://static.wixstatic.com/media/d395c1_6f18b5de70e749b79e32c564a2984a8b~mv2.jpg', 'wix:document://v1/d395c1_b10ae493f4a44b3da0054ee805903624.pdf/CV.%20LORITE-2024.pdf', 'https://www.facebook.com/angelaloritemezzo', NULL, NULL, NULL, 'https://www.youtube.com/@angelaloritemezzosoprano7566?app=desktop', 'https://static.wixstatic.com/mp3/7b859e_3aeb092bac9f4cc1b939932e677fda30.mp3', NULL, NULL, 'https://youtu.be/nx3zOBGoRYk?feature=shared', 'https://youtu.be/v3SRLWGdgKk?feature=shared', 'https://youtu.be/Vrqi21SpmPE?feature=shared', 'https://youtu.be/3oiIvYIqhvY?feature=shared', 'https://youtu.be/tCp1sC8hnDc?feature=shared', 'https://youtu.be/ohKVSFgjTxg?feature=shared', 'https://youtu.be/JQClHqXAkPU?feature=shared', 'https://youtu.be/ATV_NAB3nCA?feature=shared', 'https://youtu.be/-G9pppTTtnY?feature=shared', 'https://youtu.be/obe7pvzA-_g?feature=shared', '<p class="font_8">Soy Ángela Lorite, mezzosoprano y contralto, andaluza de nacimiento, con una naturaleza prodigiosa que abarca casi cuatro octavas de extensión vocal, una técnica depurada que me permite cantar desde el repertorio barroco de agilidades, con una gran flexibilidad y musicalidad en todo el repertorio escrito para ambos registros, hasta la música contemporánea, tanto en ópera como en oratorio, lied, y canción. También disfruto de un amplio volumen vocal y un especial color con gran personalidad que hace única e inconfundible! Un crítico dijo "cuando alguien la escucha por primera vez nunca la olvida"</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Especialista en roles como ''''<strong>Carmen</strong>'''', donde bailo y toco las castañuelas, o roles del repertorio verista como "<strong>Dalila</strong>" o "<strong>Santuzza</strong>", y verdianos como ''''<strong>Ulrica</strong>'''', ''''<strong>Azucena</strong>'''', y ''''<strong>Ebolí</strong>'''' de Don Carlo. Disfruto cantando un amplio repertorio de zarzuela y cancion española, de compositores como: Falla, Turina, Mompou, Mont- Salvatge, Chueca, Chapi, Sorozabal....</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">En roles de Contralto adoro los roles bufos de Rossini "<strong>Isabella</strong>" de Italiana de Argel o ''''<strong>La Marquise de la Fille</strong>'''' de Regiment, y siento un gran amor por ''''<strong>La Cieca</strong>'''' de la Gioconda , ''''<strong>La Zia Principesa</strong>'''', sin olvidar los roles dramáticos de ''''<strong>Tancredi</strong>'''' o el bel canto de Donizetti como <strong>"Leonora</strong>", de La Favorita, "<strong>Orsini</strong>", de Lucrecia Borgia o "<strong>Smeton</strong>" de Anna Bolena, ...</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Mi pasión por el teatro me convierte en una actriz comprometida, capaz de transmitir emociones fuertes y profundas a través de cada interpretación. Vivo en el escenario, donde cada nota es una oportunidad para contar historias y conectar con el público. Mi enfoque creativo me impulsa a explorar nuevos repertorios y a colaborar con otros artistas, siempre buscando la excelencia y la autenticidad en cada actuación. La ópera es mi vida, y cada función es un viaje que quiero compartir.</p>', '<p><span style="font-weight:bold">&quot;Cantar es Vivir&quot;</span>, ese es mi lema, creo que nací para cantar. Los que me recuerdan de niña, dicen que siempre estaba cantando con una gran sonrisa. Es mi esencia, la música y el canto nacen de mi ¡Así soy feliz!.</p><p> Además disfruto al compartirlo y sentir ese feedback y complicidad con el público,  porque siento que tambien les hace felices.</p><p> </p><p>Crecí escuchando cantantes de copla, Lola Flores, Rocio Jurado, pero un día en la radio escuché a Maria Callas, y allí me quedé ipnotizada por su voz, su fuerza, su interpretación.... A partir de ese día comencé a escuchar todas sus óperas e imitar su canto, sobre todo en Rosina del Barbero de Sevilla, adoraba sus giros y agilidades !</p><p> </p><p>Más tarde cantaba en el coro de &quot;Amics de l&#x27;Opera de Maó&quot;, donde Javier P. Batista, director de Orquesta del Liceu y el famoso barítono Joan Pons, al escucharme en el coro de la &quot;cantoria&quot; de la ópera Tosca,  me miraron y comentaron, &quot;esta niña tiene una gran voz, debe estudiar canto&quot;. Esto cambió mi vida, significaba dejarlo todo, mi família, amigos, mi hogar y marcharme sóla a buscarme la vida y mi futuro. Así que decidí trasladarme a Barcelona,  donde superé las pruebas de acceso para entrar a estudiar en el Conservatorio del Liceu.</p><p>Comenzaba mi gran aventura,  una vida muy difícil &quot;Quijotesca&quot;,  diria yo,  ya que ni mi família ni yo poseíamos medios económicos para pagar mis estudios. Lo que sí tenía y tengo  es una &quot;voluntad ferrea&quot;, para conseguir lo que quiero. </p><p>Llegué a Barcelona y a la semana ya trabajaba en una pastelería de 6h a 16h para poder vivir y pagar mis estudios.</p><p> </p><p>Me considero una mujer que ha conseguido uno de sus sueños, era una niña que soñaba cantar en grandes teatros y así ha sido. </p><p>He disfrutado cantando con grandes cantantes, dirigida bajo la batuta de maravillosos maestros musicales, en escenarios emblemáticos como: el Gran Teatro del Liceu, El Palau de la Música de Barcelona, el Teatro de la Zarzuela, La Plaza Mayor de Valladolid con 7000 personas,... El canto me ha llevado a escenarios de diferentes paises como Italia, Francia, Alemania y Portugal.</p><p> </p><p> Doy gracias a Dios y a la vida que tengo porque sigo &quot;viviendo en el escenario&quot;, y quiero cantar en los teatros del mundo</p><p>Así que... ¿Se podría mejorar?</p><p> </p>', '<p>Nacida en Granada, se traslada a Menorca donde encuentra su  vocación y carrera cantando en “Amics de l’Ópera Mahón”.   Posteriormente obtiene la  Licenciatura Superior de Canto en el  Conservatorio Superior de Música del Liceu. Completó su  formación con cantantes : <span style="font-weight:bold">Tatiana Menoti, Ileana  Cotrubas, Raquel Pierotti, E. Giménez, G. di Rocco y con Cynthia  Sanner de la The Juliard School  de New York.</span> </p><p> </p><p> Debutó en Francia  becada por <span style="font-weight:bold">Josep Carreras </span>en el “<span style="font-weight:bold">Festival des Deux Catalognes</span>”. </p><p> </p><p> Debuta en el <span style="font-weight:bold">Gran Teatro del Liceu </span>en el “<span style="font-weight:bold">CONCIERTO INAUGURAL TEMPORADA 2017</span>” cantando<span style="font-weight:bold"> Azucena del  Trovatore</span>, <span style="font-weight:bold">Maddalena de Rigoletto</span>, compartiendo escenario con <span style="font-weight:bold">Sara Blach, Carlos Pachon y Beñat Eigiarte</span>.  </p><p> </p><p>Desde 2017  canta en el Ciclo de Ópera en el “<span style="font-weight:bold">PALAU DE LA MÚSICA CATALANA</span>” los roles de <span style="font-weight:bold">Carmen, Flora  de Traviata,</span> entre otros.  En 2019 fue nombrada directora  del Master Class “ <span style="font-weight:bold">Ópera Studio Carmen al Palau</span> ”.  </p><p> </p><p> Por sus  características especiales de <span style="font-weight:bold">flexibilidad, color,  squillo y extenso registro vocal de casi 4 octavas</span>,  ha disfrutado de un amplio repertorio operístico, trabajando en diferentes teatros y producciones Los roles de:  <span style="font-weight:bold">Amneris de Aida, Fenena de Nabucco, Maddalena de Rigoletto, Éboli  de Don Carlo, Azuzena  del Trovatore,  Preciosilla de Forza del Destino, Ulrica de Un Ballo in Maschera, Carmen de Carmen,  Leonora de La Favorita,  Adalgisa de Norma, Santuzza, Lola y Mamma Lucia de Cavalleria Rusticana,  Suzuki de Madama Buterfly,  Principessa Bouillon de Andrea Lecouvreur, Charlotte de Werter, Dalila de Sanson and Dalila, Isabella  de Italiana in  Argel, Rossina del Barbieri di Siviglia,  Orlofsky de Die Fledermaus</span>. Contando  con la asesoria del Maestro <span style="font-weight:bold">Miguel  Ortega</span>.  </p><p> </p><p>Es poseedora de una gran experiencia en Zarzuela y Música Española. Desde 2005 ha cantado en España las  Zarzuelas más conocidas del repertorio de  Mezzosoprano como<span style="font-weight:bold"> La Beltrana de Doña Francisquita</span> estrenada en  <span style="font-weight:bold">Fundación Opera Cataluña</span>, y algunos roles de Soprano Dramática como <span style="font-weight:bold">Adriana  de Los Gavilanes.</span> </p><p> </p><p>Desde  2014 canta en el  <span style="font-weight:bold">FESTIVAL D’ÒPERA I BALLET NITS</span> <span style="font-weight:bold">AL PORT</span>,  interpretando conciertos de zarzuela, cançó catalana, canción española,  además de los roles protagonistas de <span style="font-weight:bold">Carmen, Tosca, Amor Brujo y Cavalleria  Rusticana,</span>  pasando a ser la directora artistica de “<span style="font-weight:bold">Nits d’Ópera</span>” desde 2017.  </p><p> </p><p>Su experiencias en Oratorio son: <span style="font-weight:bold">Requiem de Verdi y Requiem de Mozart en el Palau de la Música y Sevilla,  Messiah de Haendel en Auditorium Palma, Requiem y Missa Coronation de Mozart, en la red de teatros de la  Mancha y Madrid. El Gloria de Vivaldi, Stabat Matter de L. Boccherini, Oratori de Nadal de Erisard Sala, Missa  Solemnis de Rossini</span>, en Auditorios de toda la geografía española.</p><p> </p><p>Ha cantado en producciones del: <span style="font-weight:bold">Teatro de la Zarzuela, Teatro Fernan Gómez, Auditorio Nacional de Madrid,   Auditorio RTVE de Madrid</span>, en la mayor parte de los teatros de Cataluña<span style="font-weight:bold"> incluido el Auditorio Nacional ,  Palau de la  Música, Euskalduna de Bilbao, Kursal de San Sebastian, Forum de la Rioja,  El Vitoria Gasteiz, Caem Salamanca,  Principal Maó</span> y gran parte de teatros de España.</p><p>Ha realizado giras en teatros de <span style="font-weight:bold">Portugal </span>como el <span style="font-weight:bold">Coliseu dos Recreios de Lisboa</span>, <span style="font-weight:bold">Casino de Estoril, </span>en el sur de <span style="font-weight:bold">Francia,</span> norte de<span style="font-weight:bold"> Italia</span> y <span style="font-weight:bold">Viena</span>. </p><p>Dirigida por batutas como la de:  <span style="font-weight:bold">J. Perez Batista </span>y <span style="font-weight:bold">G. Voronkov</span> en el<span style="font-weight:bold">  Teatre del Liceu</span>, <span style="font-weight:bold">Javier Corcuera dir</span>. <span style="font-weight:bold">Orquestra y  coro de RTVE</span>, <span style="font-weight:bold">Miguel Roa y Manuel Coves</span> del teatro de la <span style="font-weight:bold">Zarzuela</span>, <span style="font-weight:bold">Xavier Puig i Josep Mindan </span>en el  <span style="font-weight:bold">Palau, Toni  Pons</span> en el <span style="font-weight:bold">Principal de Mahón, Elio Orciuolo y Daniel Martinez </span>en  <span style="font-weight:bold">Amics Opera Sabadell</span>, <span style="font-weight:bold">Tulio Gagliardo </span>en  <span style="font-weight:bold">Euskalduna de Bilbao</span>,<span style="font-weight:bold"> C. Diederich,  E. Colomer, A. Backlan</span>...  </p><p> </p><p>Y dirección escénica de maestros como: <span style="font-weight:bold">Giampaolo Zennaro, Angel Montesinos, Diego Monjo, Stefano Poda, Pau  Monterde</span>, el director de cine <span style="font-weight:bold">Juanma Bajo Ulloa, Antonio Ramallo, Antonio Amengual, Carles Ortiz, Humberto  Fernández, Ricardo Campelo</span>…  Fundadora de la <span style="font-weight:bold">1ª Gala Lírica In Memoriam  Onofre Janer </span>en Menorca y del<span style="font-weight:bold"> TRIO S’AUBA</span> en Barcelona. </p><p> </p><p> Autora e interprete de sus obras representadas en 2019-20: “<span style="font-weight:bold">Dos Divas y un Destino</span>”  representada  con gran éxito durante 2 meses en el <span style="font-weight:bold">Teatre Gaudi de Barcelona.</span> Y otras cómo “<span style="font-weight:bold">Anecdotas de una Diva”</span>, “<span style="font-weight:bold">El cuento de la Ópera</span>”, “<span style="font-weight:bold">la  Carmencita</span>” ópera infantil interactiva, y el show más reciente &#x27;&#x27;<span style="font-weight:bold">Improlíric Show</span>&#x27;&#x27;</p>', '<h3><span style="font-weight:bold">REPERTORIO ACTUAL</span></h3><h3> </h3><h3><span style="font-weight:bold"><span style="text-decoration:underline">Ópera</span></span></h3><h3><span style="font-weight:bold">Carmen </span>Carmen</h3><h3><span style="font-weight:bold">Cavalleria Rusticana </span>Santuzza, Lola, Mamma Lucia.</h3><h3><span style="font-weight:bold">Aida </span>Amneris</h3><h3><span style="font-weight:bold">Rigoletto </span>Maddalena</h3><h3><span style="font-weight:bold">Ballo in Maschera </span>Ulrica</h3><h3><span style="font-weight:bold">Il Trovatore </span>Azucena</h3><h3><span style="font-weight:bold">Don Carlo: </span>Éboli</h3><h3><span style="font-weight:bold">La Traviata </span>Flora</h3><h3><span style="font-weight:bold">Nabucco </span>Fenena</h3><h3><span style="font-weight:bold">Madama Butterfly </span>Suzuki</h3><h3><span style="font-weight:bold">Suor Angelica </span>Zia Principessa</h3><h3><span style="font-weight:bold">Il Tabarro </span>La Frugola</h3><h3><span style="font-weight:bold">la Fille de Regiment </span>La Marquise de Berkenfield</h3><h3><span style="font-weight:bold">Die Zauberflöte </span>Dritte Frau</h3><h3><span style="font-weight:bold">Italiana in Argel </span>Isabella</h3><h3><span style="font-weight:bold">Tancredi </span>Tancredi</h3><h3><span style="font-weight:bold">Sanson et Dalila </span>Dalila</h3><h3><span style="font-weight:bold">Werter </span>Charlotte</h3><h3> </h3><h3> </h3><h3><span style="font-weight:bold"><span style="text-decoration:underline">Zarzuela</span></span></h3><h3><span style="font-weight:bold">Doña Francisquita </span>La Beltrana</h3><h3><span style="font-weight:bold">Amor Brujo</span> Candela</h3><h3><span style="font-weight:bold">La Dolorosa </span>Dolores</h3><h3><span style="font-weight:bold">La Gran Via </span>La Menegilda</h3><h3><span style="font-weight:bold">Los Claveles </span>Rosa</h3><h3><span style="font-weight:bold">La Revoltosa </span>Mari Pepa y Soledad</h3><h3><span style="font-weight:bold">Verbena de la Paloma </span>Seña Rita y La Cantaora</h3><h3><span style="font-weight:bold">Barberillo de Lavapies</span>: Paloma</h3><h3><span style="font-weight:bold">Agua, Azucarillos....... </span>Pepa y Manuela</h3><h3><span style="font-weight:bold">La Alegría de la Huerta </span>Carola</h3><h3><span style="font-weight:bold">Manojo de Rosas </span>Ascensión</h3><h3><span style="font-weight:bold">Rosa del Azafrán </span>Sagrario</h3><h3><span style="font-weight:bold">El Dúo de la Africana </span>La Antonelli</h3><h3><span style="font-weight:bold">Los Gavilanes </span>Adriana</h3><h3><span style="font-weight:bold">La Corte del Faraón </span>Reina</h3><h3><span style="font-weight:bold">Sueño de Gloria: </span>Carmen</h3><h3><span style="font-weight:bold">Soto del Parral </span>Aurora</h3><h2> </h2><h2> </h2><h3><span style="font-weight:bold">En oratorio: </span></h3><h3>Requiem de Mozart</h3><h3>Missa Coronation de Mozart</h3><h3>Requiem de Verdi    </h3><h3>Requiem Dvorack, </h3><h3>Messiah de Haëndel </h3><h3>Gloria de   Vivaldi</h3><h3> Stabat Matter de L. Boccherini</h3><h3> Missa Solemnis de Rossini.</h3><h3> </h3><h3><span style="font-weight:bold">Compositores españoles de Canción :  </span>Garcia Lorca, Falla, Turina, Halfter, Montsalvatge, Mompou, Granados, Toldrá, Obradors...</h3>', 'https://static.wixstatic.com/media/d395c1_c78a5528c07b4c8da2830ecd0b3dca0d~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_99765954affb42bc95b13af75ad2b00d~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_978efb293ec44cc89b016f72d4470987~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_f4ce089669f3457f808ed8e8f646ac06~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_577c2adf650e47f986ac66de2b417fc4~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_7050da9b59b34e438f4c9f1d70a783fa~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_c789dc29b8504e479ebedef5666b9c1d~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_524b39bd9c9047cd8dffdfda715ab7f2~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_3aba0c21eb0e467daa1ac11ce022f7c2~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_f11eb5c303a54ea7a974aba86df7224c~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_8cbee8ba44394544b3cc86b18aefb5f0~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d395c1_59be9e33273b4f63946043fb93efd84a~mv2.jpg', NULL, 1, 0, 0);

-- Row 33: Osvaldo Ferreira
INSERT IGNORE INTO users (id, email, password, role) VALUES ('ae449ccf-bdd1-403f-aaf9-e70a7f06566f', 'wix-ae449ccf@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('d2603d9a-4739-402d-a246-21b264c5a288', 'ae449ccf-bdd1-403f-aaf9-e70a7f06566f', 'osvaldo-ferreira', 'Osvaldo Ferreira', 'Osvaldo', '999999999', '2024-07-12', 'Portugal', 'Portugal', 'Lisboa', 'xxxxxx', NULL, '1111', 'Maestro e Diretor Artístico', 'Uma orquestra é um universo onde a coexistência e fusão se conjugam para produzir uma beleza sublime', 'https://static.wixstatic.com/media/ae449c_501bdfb8ee6146b1b610999e99d436f7~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/ae449c_f4350bc80a824eb1b110378879be1c36.mp3', NULL, NULL, 'https://youtu.be/Hgxg3NRGfL4', 'https://youtu.be/B9Luz2SJs38', 'https://youtu.be/49UcN_IB_v8', 'https://youtu.be/ftim6btdHik', 'https://youtu.be/1-Tg98vm4Nc', 'https://youtu.be/zdn75ojTfg0', 'https://www.youtube.com/watch?v=2MXVzFxGiNs', NULL, NULL, NULL, '<p class="font_8" style="text-align: justify">Osvaldo Ferreira é um dos mais representativos chefes de orquestra nacionais da atualidade.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Osvaldo Ferreira, considerado um dos maestros portugueses mais eminentes e respeitados da sua geração, é uma figura central no panorama da música clássica contemporânea. Atualmente é o <strong>Diretor Artístico da Orquestra Filarmónica Portuguesa</strong>, que considera ser o grande projeto da sua vida.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Embora tenha começado a sua carreira na música como violinista, foi nos Estados Unidos que descobriu a sua verdadeira vocação - a direção de orquestra. Desde então, dedicou-se incansavelmente a aperfeiçoar esta arte exigente, estudando e aprendendo com alguns dos mais conceituados maestros do século XX como <strong>Victor Yampolsky</strong>, <strong>Ilya Mussin</strong> e <strong>Claudio Abbado</strong>.</p>
<p class="font_8" style="text-align: justify">Com uma carreira consolidada como diretor de orquestra, empreendedor, produtor e manager, atualmente, o seu grande objetivo é deixar um legado para que novos músicos e compositores mostrem as suas obras, o que demonstra um claro compromisso com a <strong>valorização da cultura musical portuguesa</strong> que norteia seus esforços visionários à frente da <strong>Orquestra Filarmónica Portuguesa</strong>.</p>', '<h3 style="text-align:justify">&quot;</h3><p style="text-align:justify">Osvaldo Ferreira, que nasceu em 1964 em Paços de Brandão, distrito de Aveiro, foi influenciado desde cedo pela música. A sua mãe, que cantava frequentemente durante as tarefas diárias, e uma tia, que após uma temporada no Brasil numa ordem religiosa regressou com conhecimentos em órgão e pedagogia musical, foram figuras centrais na sua iniciação musical.</p><p style="text-align:justify">Começou a estudar violino aos 11 anos, na escola de música da <span style="font-weight:bold">Tuna Musical Brandoense</span>. Aos 19 anos, formou-se no <span style="font-weight:bold">Conservatório de Música do Porto</span>. Embora dividisse os seus interesses musicais com outras paixões, como o futebol e a filosofia, a integração na <span style="font-weight:bold">Orquestra Portuguesa da Juventude</span> e o facto de ter sido o primeiro violinista português a fazer parte das escolas da <span style="font-weight:bold">Orquestra da União Europeia</span> revelaram que a música faria parte do seu futuro profissional. Mais tarde, entrou na <span style="font-weight:bold">Orquestra do Porto</span>, já depois da reforma de 1989 pelo maestro inglês Jan Latham-Koenig e a &quot;Regie Sinfónia Cooperativa&quot;, primeiro como estagiário e depois como efetivo.</p><p style="text-align:justify">Prosseguiu com os seus estudos na <span style="font-weight:bold">Bienen School of Music da Northwestern University</span> em Chicago, inicialmente em violino e depois em direção de orquestra sob a orientação de <span style="font-weight:bold">Victor Yampolsky</span>. Este período foi crucial, marcando a transição de Osvaldo para a regência de orquestras, que se tornaria sua verdadeira vocação.</p><p> </p><p style="text-align:justify">Fez uma pós-graduação no <span style="font-weight:bold">Conservatório de São Petersburgo sob a tutela de Ilya Mussin</span> e foi laureado em 1999 no <span style="font-weight:bold">Concurso Sergei Prokofiev</span>, na Rússia, consolidando a sua reputação como um maestro de talento excecional. Posteriormente, recebeu o <span style="font-weight:bold">“Fellowship” do Festival de Música de Aspen</span>, onde frequentou a <span style="font-weight:bold">American Conductors Academy</span>. Foi <span style="font-weight:bold">assistente do maestro Claudio Abbado</span> em Salzburgo e Berlin. Estudou ainda com <span style="font-weight:bold">Jorma Panula</span> e <span style="font-weight:bold">David Zinman</span>, foi bolseiro do Ministério da Cultura de Portugal e da Fundação Calouste Gulbenkian.</p><p> </p><p style="text-align:justify">A sua carreira como diretor convidado é extensa, tendo liderado orquestras em cidades como Berlim, Viena e São Petersburgo, e abrangendo trabalhos em importantes orquestras como a Orquestra Gulbenkian e a Orquestra Sinfónica de Nuremberga.</p><p> </p><p style="text-align:justify">Além disso, desempenhou papéis significativos como <span style="font-weight:bold">diretor artístico</span> da <span style="font-weight:bold">Orquestra do Algarve</span> e do Festival Internacional de Música do Algarve, <span style="font-weight:bold">diretor e administrador</span> do <span style="font-weight:bold">Teatro Municipal do Faro</span>, <span style="font-weight:bold">diretor artístico</span> da <span style="font-weight:bold">Sociedade de Concertos de Brasília</span>, <span style="font-weight:bold">diretor musical e maestro titular da Orquestra Sinfónica do Paraná</span> e <span style="font-weight:bold">diretor da Oficina de Música de Curitiba</span>.</p><p> </p><p style="text-align:justify">De regresso a Portugal em 2015, fundou a <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.ofp.pt/pt/inicio/ target=_blank>Orquestra Filarmónica Portuguesa</a></span></span></span> no ano seguinte com o concertino <span style="font-weight:bold">Augusto Trindade</span>. Este projeto, sob a sua direção artística, tem-se consolidado como uma referência, um sucesso que decorre dos altos padrões de exigência estabelecidos desde o início e que atrai músicos de elevada competência técnica e artística.</p><p> </p><p style="text-align:justify">Além disso, a orquestra lidera o projeto “<span style="font-weight:bold">Sounds of Change</span>”, que envolve parcerias com a Alemanha, Espanha, Eslovénia e Sérvia, o que reflete uma ambição internacional; foi um dos vinte projetos que foram apoiados entre centenas de candidatos pelo programa Europa Criativa da União Europeia; e conta com o apoio da Direção-Geral das Artes.</p><p> </p><p style="text-align:justify">Gravou vários CDs com obras de autores portugueses e um CD duplo com sinfonias de Mozart, demonstrando não apenas sua habilidade técnica mas também seu compromisso em promover a música portuguesa. A sua dedicação à música contemporânea também é notável, com a apresentação de obras de compositores renomados mundialmente, tais como, K. Penderecki, L. Auerbach, Jean-Luc Ponty, B. Sassetti, H. Rosenschoon, ou G. Ligeti, entre muitos outros.</p><p> </p><h3 style="text-align:justify">Aprendi com os melhores. Sou muito disciplinado e sempre tive objetivos traçados. Tenho uma capacidade de trabalho muito elevada e sou multifuncional.&quot;</h3><p style="text-align:justify">Osvaldo Ferreira</p>', '<h3 style="text-align:justify">O seu percurso inclui mais de 600 concertos, cerca de 70 apresentações de ópera e bailado e ainda a direção integral das missas e do Requiem de Mozart.</h3><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">PRINCIPAIS INFLUÊNCIAS</span></h3><h3> </h3><ul><li style="text-align:justify">Victor Yampolsky</li><li style="text-align:justify">Claudio Abbado</li><li style="text-align:justify">Ilya Mussin</li><li style="text-align:justify">Jorma Panula</li><li style="text-align:justify">David Zinman</li></ul><h3 style="text-align:justify"> </h3><h3><span style="font-weight:bold">PRÉMIOS</span></h3><h3> </h3><ul><li style="text-align:justify">Prémio &quot;Academy Conductor&quot; em 2001 na American Conductors Academy de Aspen.</li><li style="text-align:justify">&quot;Fellowship&quot; do Aspen Music Festival, concedido pelo maestro David Zinman.</li><li style="text-align:justify">Laureado no Concurso Sergei Prokofiev em 1999, na Rússia.</li><li style="text-align:justify">Prémio de melhor aluno pela Fundação Engenheiro António Almeida ao concluir o Curso Superior de Violino no Conservatório do Porto (década de 1980).</li></ul><h3 style="text-align:justify"> </h3><h3><span style="font-weight:bold">COLABORAÇÕES</span></h3><h3> </h3><ul><li style="text-align:justify">Regência de orquestras como São Petersburgo, Roma, Gulbenkian, Brasil, Praga, Lodz, Silésia, Nuremberga, Rádio Renana, Porto, São Carlos, Vicenza, Catalunha, Chicago, Aspen, Venezuela</li><li style="text-align:justify">Gravações para RTP, RDP e Editora Numérica</li><li style="text-align:justify">Direção do concerto dos laureados do Concurso Jovens Músicos da RDP</li><li style="text-align:justify">Camerata de Musica Antiqua de Curitiba (Weinacht Oratorium de Bach)</li><li style="text-align:justify">Regência de óperas como &quot;La Donna de Genio Volubile&quot;, &quot;Don Giovanni&quot;, &quot;Il Impresario&quot; e &quot;Madama Butterfly&quot;</li></ul><h3 style="text-align:justify"> </h3><h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><h3> </h3><h2> </h2><p style="text-align:justify"><span style="font-weight:bold">2024 </span>- Em maio, estreou a ópera &quot;Felizmente Há Luar!&quot; em Lisboa sob sua direção. Esta foi uma encomenda da Orquestra Filarmónica Portuguesa no âmbito das comemorações dos 50 anos do 25 de Abril.</p><p style="text-align:justify"><span style="font-weight:bold">2022 </span>- Estreia internacional da OFP no Théâtre des Champs Élysées (Paris).</p><p style="text-align:justify"><span style="font-weight:bold">2016-2017</span> - Ministrou masterclasses no Luxemburgo e em Castelo Branco.</p><p style="text-align:justify"><span style="font-weight:bold">2016 </span>- Fundou a Orquestra Filarmónica Portuguesa com Augusto Trindade. Mantém-se como Diretor Artístico da Sociedade de Concertos de Brasília.</p><p style="text-align:justify"><span style="font-weight:bold">2011-2014</span> - Diretor musical e maestro titular da Orquestra Sinfônica do Paraná (Brasil). Diretor da Oficina de Música de Curitiba.</p><p style="text-align:justify"><span style="font-weight:bold">2010 </span>- É escolhido como programador musical do Festival Allgarve.</p><p style="text-align:justify">A partir de 2008 - Regência de orquestras como São Petersburgo, Roma, Gulbenkian, Brasileira, Praga, Lodz, Silésia, Nuremberga, Rádio Renana, Porto, São Carlos, Vicenza, Catalunha, Chicago, Aspen, Venezuela, entre outras. Também foi Diretor e administrador do Teatro Municipal de Faro.</p><p style="text-align:justify"><span style="font-weight:bold">2007 </span>- Tornou-se diretor artístico do Festival Internacional de Música do Algarve.</p><p style="text-align:justify"><span style="font-weight:bold">2006 </span>- Gravou CD duplo com obras de Mozart com a Orquestra do Algarve. Realizou concertos em Bruxelas e Viena com a Orquestra do Algarve.</p><p style="text-align:justify"><span style="font-weight:bold">2005-2007</span> - Foi maestro titular da Orquestra do Algarve.</p><p style="text-align:justify"><span style="font-weight:bold">2003 </span>- Tornou-se maestro titular da Orquestra da Povoa de Varzim</p><p style="text-align:justify"><span style="font-weight:bold">2000-2002</span> - Obteve uma bolsa da Fundação Gulbenkian e tornou-se assistente de Claudio Abbado em Berlim e Salzburgo.</p><p style="text-align:justify">Anos 2000 - Conquistou o &quot;Fellowship&quot; do Festival de Música de Aspen. Frequentou a American Conductors Academy. Conquistou o prémio &quot;Academy Conductor&quot; em 2001.</p><p style="text-align:justify"><span style="font-weight:bold">1999 </span>- Foi laureado no Concurso Prokofiev (Rússia).</p><p style="text-align:justify"><span style="font-weight:bold">1998-1999</span> - Fez a pós-graduação no Conservatório de São Petersburgo com Ilya Mussin.</p><p style="text-align:justify">Desde 1997 - Exerceu diversas atividades ligadas a importantes festivais, tais como, fundador e diretor artístico do Festival de Música de Santa Maria da Feira e diretor da Orquestra do Festival Internacional de Música de Viana do Castelo, entre outros.</p><p style="text-align:justify"><span style="font-weight:bold">1995-1997</span> - Realizou o mestrado em direção de orquestra em Chicago.</p><p style="text-align:justify">Anos 90 - Foi fazer o mestrado em violino na Northwestern University (Chicago) Entretanto, descobriu a vocação para a regência orquestral com Victor Yampolsky.</p><p style="text-align:justify"><span style="font-weight:bold">1989 </span>- Ingressou na Orquestra do Porto após reforma de Jan Latham-Koenig.</p><p style="text-align:justify">Década de 1980 - Concluiu o Curso Superior de Violino pelo Conservatório de Música do Porto. Recebe prémio de melhor aluno pela Fundação Engenheiro António Almeida.</p><p style="text-align:justify"><span style="font-weight:bold">1975 </span>- Iniciou estudos de violino na escola da Tuna Musical Brandoense.</p>', '<h3><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.ofp.pt/pt/inicio/ target=_blank>Orquestra Filarmónica Portuguesa</a></span></span></span></h3><h3> </h3><p>Fundou, em 2016, juntamente com Augusto Trindade, a Orquestra Filarmónica Portuguesa,  reconhecida hoje como uma das mais aclamadas orquestras sinfónicas nacionais. Os elevados padrões de excelência artística e a exigência impressos desde a sua génese, levam-na a integrar um conjunto de músicos de elevado nível técnico e artístico das mais variadas nacionalidades, como sejam instrumentistas premiados em concursos nacionais e internacionais, ex-integrantes da Orquestra Jovem da União Europeia e músicos estrangeiros residentes em Portugal.</p><p> </p><h3><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h3><p> </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/maestro_osvaldo_ferreira target=_blank>PorART Entrevista</a></span></span>: Osvaldo Ferreira - Um visionário na vanguarda da Direção Artística e Musical de orquestras</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=3F4frREsaE8 target=_blank>Sounds of Change (2023)</a></span></span>: Interview with Maestro Osvaldo Ferreira in Novi Sad, Serbia</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://arquivos.rtp.pt/conteudos/entrevista-a-osvaldo-ferreira/ target=_blank>RTP (2017)</a></span></span>: Entrevista a Osvaldo Ferreira</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://arquivos.rtp.pt/conteudos/maestro-osvaldo-ferreira-na-orquestra-de-sao-petersburgo/ target=_blank>RTP (2017)</a></span></span>: Maestro Osvaldo Ferreira na Orquestra de São Petersburgo</p><p> </p><h3>Quer saber mais?</h3><h3>Entre em contacto connosco!</h3>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 34: Agostinho Sequeira
INSERT IGNORE INTO users (id, email, password, role) VALUES ('2556c07b-874c-4741-9d3d-82b9143cca3a', 'wix-2556c07b@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('7eadb4d3-c672-42c0-9446-eac5cb907482', '2556c07b-874c-4741-9d3d-82b9143cca3a', 'agostinho-sequeira', 'Agostinho Sequeira', 'Agostinho', '1111111111111', '1982-07-01', 'Portugal', 'Alemanha', 'Lisboa', 'xxxx xxxx', NULL, '1800107', 'Percussionista', '"A percussão pode ser encontrada em todos os cantos do mundo e tem um poder primordial a todos nós"', 'https://static.wixstatic.com/media/2556c0_2a02c34ec4764c62ac191ef49cd3ba94~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/2556c0_2c964ba83abc4a7e93a0f96cfe7e2a69.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=tb0E2LBDD8E', 'https://www.youtube.com/watch?v=O53CIZav2FY', 'https://www.youtube.com/watch?v=LupXAyXFMsY', 'https://www.youtube.com/watch?v=dKKVUbKIQNY', NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8" style="text-align: center"><strong>"</strong><em><strong>Há uma sensação de magia na sua atuação, e um empenho absoluto.</strong></em><strong>"</strong></p>
<p class="font_8" style="text-align: center"><strong>Júri do Concurso Tromp em 2020</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify"><strong>Agostinho Sequeira</strong>, um mago dos ritmos que eleva a música a uma viagem sublime e espiritual, é um virtuoso da percussão cuja habilidade excecional o transformou num fenómeno artístico aclamado internacionalmente. É um artista exímio que usa os ritmos como linguagem universal para contar histórias profundas e cativar plateias ao redor do mundo.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">O que torna Agostinho tão especial é a sua <strong>capacidade de combinar harmoniosamente tradição e inovação</strong>, estabelecendo uma ligação profunda e instintiva com o público. Nas suas interpretações, explora os aspetos mais contemplativos e primordiais da percussão para alcançar a essência humana.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">As suas atuações, tanto energéticas como delicadas, são verdadeiros rituais onde os ritmos se fundem numa experiência hipnótica e catártica.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">Em 2020, foi o vencedor do <strong>Concurso de Percussão Tromp</strong>, recebendo também o prémio do público e o prémio de imprensa Jan Pustjens.</p>', '<p style="text-align:justify"> </p><p style="text-align:justify">Agostinho Sequeira cresceu imerso no mundo da música, uma presença constante na sua vida dado que o seu pai era músico. Possuidor de uma aptidão natural para a bateria, o jovem Agostinho rapidamente se apaixonou pelo universo da percussão erudita.</p><p> </p><p style="text-align:justify">Em 2008, com 10 anos, iniciou os estudos musicais no <span style="font-weight:bold">Conservatório de Música da Metropolitana</span>, em Lisboa, com os professores Tatiana Martins e Fábio Dias.</p><p> </p><p style="text-align:justify">Mais tarde, aos 15 anos, ingressou na conceituada <span style="font-weight:bold">Escola Profissional Metropolitana</span>, onde teve a oportunidade de estudar com mestres renomados como Marco Fernandes, Andreu Rico e Miguel Herrera. Já naquela época, o seu talento precoce era evidente, mas Agostinho sempre procurou superar-se a si mesmo.</p><p> </p><p style="text-align:justify">Assim, em 2016, aos 18 anos, deu um passo decisivo na sua carreira e deixou Portugal para estudar no prestigiado <span style="font-weight:bold">Conservatorium Van Amsterdam</span>, reputada instituição holandesa onde aprimorou as suas habilidades únicas sob a orientação de professores lendários como <span style="font-weight:bold">Nick Woud, Arnold Marinissen e Peter Prommel</span>.</p><p> </p><p>Incessante na sua busca por desenvolvimento, Agostinho aproveitou todas as oportunidades formativas que pôde. Realizou períodos de intercâmbio no <span style="font-weight:bold">Conservatoire National Supérieur de Musique et Danse de Lyon</span> e na <span style="font-weight:bold">Hochschule für Musik Hanns Eisler em Berlim</span>. A sua dedicação total culminou na sua graduação com distinção máxima pelo Conservatorium em 2021 e na obtenção do grau de mestre em 2023, também com distinção máxima. Atualmente, dá aulas no Conservatório de Amesterdão e continua a elevar a sua arte a novos patamares, explorando a diversidade e energia da percussão. </p><p> </p><p style="text-align:justify">Um dos momentos mais altos da sua carreira foi a conquista o prestigiado concurso “<span style="font-weight:bold">Tromp International Percussion Competition - 2020</span>”, em Eindhoven, tendo também recebido o prémio da imprensa e do público.</p><p> </p><p style="text-align:justify">&quot;Ficarão surpreendidos com o que este instrumento oferece: diversidade, surpresa, energia, delicadeza e uma relação muito primária com a nossa existência enquanto humanos&quot;.</p><p style="text-align:justify">Agostinho Sequeira</p>', '<p style="text-align:justify">Enquanto solista, apresentou recitais em salas como a Muziekgebouw Amsterdam, Muziekgebouw Eindhoven, Centro Cultural de Belém e em diversos festivais com destaque para o IPEA festival Shanghai, Wonderfeel Festival e o Bach Festival Dordrecht. O seu foco são sobretudo projetos de percussão solo e música de câmara.</p><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">PRÉMIOS</span></h3><p style="text-align:justify"> </p><ul><li>Vencedor do Tromp Percussion Competition (2020), incluindo prêmios da imprensa e público.</li><li style="text-align:justify">1º lugar no Concurso Internacional de Percussão de Gondomar (2018)</li><li style="text-align:justify">Prémio Maestro Silva Pereira - Jovem Músico do Ano (2016)</li><li style="text-align:justify">1º lugar no Concurso Internacional de Percussão da Beira Interior (2016)</li><li style="text-align:justify">1º lugar no 21st Century Art Competition for Young Performers (2015)</li><li style="text-align:justify">2º lugar no Concurso Tomarimbando - Categoria Marimba (2015)</li><li style="text-align:justify">1º lugar no Prémio Jovens Músicos - Categoria Percussão, Nível Médio (2014)</li></ul><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">COLABORAÇÕES E PARCERIAS</span></h3><h3> </h3><ul><li style="text-align:justify">Solista com Orquestra Gulbenkian, Orquestra Metropolitana, Het Ballet Orkest Amsterdam;</li><li style="text-align:justify">Colaborações com Toonzetters Ensemble, Amsterdam Sinfonietta, Ereprijs Ensemble e ICK Dans Amsterdam.</li></ul><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p> </p><p style="text-align:justify"><span style="font-weight:bold">2024 </span>- Atualmente, reside em Berlim e está focado em repertório solo, música de câmara e projetos freelance.</p><p style="text-align:justify"><span style="font-weight:bold">2023</span></p><ul><li style="text-align:justify">Recital na Muziekgebouw Amsterdam;</li><li style="text-align:justify">Lançamento do álbum &quot;Relief Party&quot;;</li><li style="text-align:justify">Lançamento do álbum &quot;Toonzetters&quot;.</li><li style="text-align:justify">Obtenção do metrado com distinção máxima no Conservatorium Van Amsterdam.</li></ul><p style="text-align:justify"><span style="font-weight:bold">2022 </span>- Recital Muziekgebouw Eindhoven.</p><p style="text-align:justify"><span style="font-weight:bold">2021 </span>- Solista com a Het Ballet Orkest Amsterdam.</p><p style="text-align:justify"><span style="font-weight:bold">2021 </span>- Obteve a licenciatura com distinção máxima no Conservatorium Van Amsterdam.</p><p style="text-align:justify"><span style="font-weight:bold">2020 </span>- Venceu o prestigiado Tromp International Percussion Competition, incluindo prémios da imprensa e público.</p><p style="text-align:justify"><span style="font-weight:bold">2019 </span>- Admitido na 2ª fase do Concurso ARD na Alemanha.</p><p style="text-align:justify"><span style="font-weight:bold">2018</span></p><ul><li style="text-align:justify">Venceu o Concurso Internacional de Percussão de Gondomar;</li><li style="text-align:justify">Fez um recital a solo no Centro Cultural de Belém, em Lisboa.</li></ul><p style="text-align:justify"><span style="font-weight:bold">2017</span></p><ul><li style="text-align:justify">Tornou-se bolseiro da Fundação Jan Pustjens;</li><li style="text-align:justify">Atuou a solo com a Orquestra Sinfónica do Conservatório de Amesterdão no TivoliVredenburg, em Utrecht, e na Muziekgebouw em Amsterdão;</li><li style="text-align:justify">Atuou como solista com a Orquestra Gulbenkian.</li></ul><p style="text-align:justify"><span style="font-weight:bold">2016</span></p><ul><li style="text-align:justify">Ingressou no Conservatorium Van Amsterdam;</li><li style="text-align:justify">Conquistou o 1º lugar no Concurso Internacional de Percussão da Beira Interior;</li><li style="text-align:justify">Atuou a solo com a Orquestra Metropolitana Lisboa.</li></ul><p style="text-align:justify"><span style="font-weight:bold">2015</span></p><ul><li style="text-align:justify">1º lugar no 21st Century Art Competition for Young Performers como membro do Trio de Percussões Metropolitana;</li><li style="text-align:justify">2º lugar no Concurso Tomarimbando na categoria de Marimba.</li></ul><p style="text-align:justify"><span style="font-weight:bold">2014 </span>- Venceu o Prémio Jovens Músicos em Portugal como membro do Duo de Percussão Metropolitana.</p><p style="text-align:justify"><span style="font-weight:bold">2013 </span>- Iniciou os estudos de percussão na Escola Profissional Metropolitana em Lisboa.</p><p style="text-align:justify"><span style="font-weight:bold">2008 </span>- Iniciou os estudos musicais no Conservatório de Música da Metropolitana em Lisboa.</p>', '<p><span style="font-weight:bold">PROJETOS</span></p><p> </p><p>&quot;<span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.toonzetters.nl/ target=_blank>Toonzetters Ensemble</a></span></span></span>&quot;</p><p>Este é um projeto da Stichting Pelgrimsjaren em coprodução com o Festival Oranjewoud e a November Music. Em 2022, os pianistas Ramon van Engelenhoven e Shane van Neerden e os percussionistas Agostinho Sequeira e Arjan Jongsma apresentaram-se na estreia de <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.oranjewoudfestival.nl/en/programma/toonzetters-ensemble/ target=_blank>Toonzetters no Festival de Oranjewoud</a></span></span></span>. Este projeto do compositor Primo Ish-Hurwitz incluía vinte composições curtas de outros tantos compositores holandeses. O concerto marcou o início de uma série de concertos amplamente aclamada que recebeu muita atenção dos meios de comunicação social e chegou até Itália. </p><p> </p><p>Devido ao sucesso da digressão e à proximidade entre eles, os músicos decidiram continuar a sua colaboração.</p><p>Em 2022, receberam o <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://nieuwgeneco.nl/ target=_blank>New Geneco Fair Practice Award 2022</a></span></span></span>, através do qual a Sociedade de Compositores Neerlandeses chama a atenção para as boas práticas como directrizes justas em matéria de honorários, boas práticas de encomenda de música nova, espaço artístico livre, desenvolvimento sustentável do público e impacto na vida musical neerlandesa. Em 2023, lançaram o<span style="text-decoration:underline"><a href=https://www.toonzetters.nl/voorverkoop-cd target=_blank> <span style="font-weight:bold"><span style="text-decoration:underline">álbum &quot;Toonzetters&quot;</span></span></a></span> com as vinte composições <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.7mntn.com/toonzetters/ target=_blank>7 Mountain Records</a></span></span></span>.</p><p> </p><p><span style="font-weight:bold">Opiniões</span></p><p>&quot;Toonzetters pode vir a ser um projeto histórico no futuro, uma visão única da vida musical dos anos 20. Mais de uma hora de música fascinante e atmosférica.&quot; - NRC <span style="text-decoration:underline"><a href=https://www.nrc.nl/nieuws/2023/01/27/beuken-op-een-parketvloer-als-begeleiding-bij-een-rijke-muzikale-collage-a4155548 target=_blank>★★★★☆</a></span></p><p>&quot;Com o seu entusiasmo, delicadeza e concentração, os intérpretes mostram a individualidade dos compositores no seu melhor.&quot; - Allegiance <span style="text-decoration:underline"><a href=https://www.trouw.nl/cultuur-media/nieuwe-muziek-van-twintig-twintigers-met-veel-finesse-uitgevoerd~b2b3c523/ target=_blank>★★★★☆</a></span></p><p> </p><p><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/entrevista_agostinho_sequeira target=_blank>PorART Entrevista</a></span></span> </span>- Agostinho Sequeira - O jovem virtuoso que transforma a percussão em magia</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://atpercussion.podbean.com/e/percussion-273-agostinho-sequeira/ target=_top>The @Percussion Podcast (2021)</a></span></span></span> - Ep. 273 Agostinho Sequeira</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.conservatoriumvanamsterdam.nl/en/news/2020/11/agostinho-sequeira-wins-tromp-international-percussion-competition/ target=_blank>Conservatorium van Amsterdam (2020)</a></span></span></span> - Agostinho Sequeira wins Tromp International Percussion Competition</p><p> </p><h3>Quer saber mais?</h3><h3>Entre em contacto connosco!</h3>', 'https://static.wixstatic.com/media/2556c0_a47d41eead7e42f69a3c1587d778f297~mv2.jpeg', '''@Daniel Delang', 'https://static.wixstatic.com/media/2556c0_a475634c3b074ba2a734db6dffc9a1f1~mv2.jpeg', '''@Han Ernest', 'https://static.wixstatic.com/media/2556c0_0e54e7228ada4791931b501e67b85e72~mv2.jpeg', '''@Han Ernest', 'https://static.wixstatic.com/media/2556c0_1fb1d8ac810b4b4da975f5384fceb453~mv2.jpeg', '''@Jorge Carmona', 'https://static.wixstatic.com/media/2556c0_ff3bdb9592564d71a3bdc01158dc4809~mv2.jpeg', '''@Daniel Delang', 'https://static.wixstatic.com/media/2556c0_968b42faffc24e5181bad3a56e993c25~mv2.jpeg', '''@Han Ernest', 'https://static.wixstatic.com/media/2556c0_6b8b9278b78945f99268919b199aefa2~mv2.jpeg', 'Han Ernest', 'https://static.wixstatic.com/media/2556c0_2d16a53c4e854b29b0969c296d4c4396~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/2556c0_ccb94de2b2ed44de8e05eed2ff04912b~mv2.jpeg', '''@Daniel Delang', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 35: Luís Rendas Pereira
INSERT IGNORE INTO users (id, email, password, role) VALUES ('f81ac172-bcf1-4633-b4c8-4b528874b2c5', 'wix-f81ac172@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('20541ce4-95f7-40c5-9099-476bbd31df70', 'f81ac172-bcf1-4633-b4c8-4b528874b2c5', 'Luis-rendas-pereira', 'Luís Rendas Pereira', 'Luís', '''+351916076193', '1990-08-14', 'Portugal', 'Portugal', 'Aveiro', 'R. José Luciano de Castro, nr. 23 R/C dto', NULL, '3800-206', 'Barítono, Professor de Canto', NULL, 'https://static.wixstatic.com/media/7b859e_328d3d5d2cb84ef19d0a32ed1b1c5cd2~mv2.jpg', NULL, 'https://www.facebook.com/share/17wCDP2PiG/', 'https://www.instagram.com/luisrendaspereira?igsh=a3d5MHJiOTJ4M2Rq', NULL, NULL, NULL, NULL, NULL, NULL, 'https://youtu.be/G6wtMYcYIRQ?si=BGIgNUWTN_-czh5G', NULL, 'https://youtu.be/BVyrv3Wv2MU?si=89bC3UP00luzsnXO', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p>O barítono português Luís Rendas Pereira tem-se apresentado regularmente como solista no âmbito da ópera, oratória e canção.</p><p>No repertório operático, destacam-se as suas participações como protagonista em diversas obras de Mozart, Donizetti, Menotti, Bizet e Pergolesi, bem como em várias estreias de compositores portugueses.</p><p>Colaborou com maestros conceituados como Lawrence Cummings, Paul Hillier e Brian Mackay, e com encenadores de renome como António Durães, Mário Moutinho e Claudio Hochman.</p><p>Apresentou-se com orquestras prestigiadas, nomeadamente a Orquestra Filarmonia das Beiras, a Filarmónica Portuguesa, a Orquestra do Norte, a Orquestra Barroca da Casa da Música, o Remix Ensemble e a Orquestra Clássica do Centro.</p><p>No domínio da oratória e concerto, tem um vasto repertório que inclui obras como o <span style="font-style:italic">Te Deum</span> de Charpentier, <span style="font-style:italic">A Criação</span> de Haydn, cantatas e oratórias de Bach, o <span style="font-style:italic">Requiem</span> de Mozart, a <span style="font-style:italic">9ª Sinfonia</span> de Beethoven, entre outras obras de compositores como Saint-Saens, Fauré, Duruflé e Delius. Interpreta repertórios que abrangem diversas épocas, desde a Idade Média até ao século XXI, incluindo música de câmara e sinfónica</p><p>Atualmente, aperfeiçoa-se com a professora Abbie Furmansky, destacando-se no seu percurso o trabalho regular com professores como Susan Waters e Pierre Mak. Tem participado em inúmeras masterclasses de canto a nível nacional e internacional, destacando-se a sua participação em 2024 no <span style="font-style:italic">International Opernwerkstatt</span> no qual teve oportunidade de se apresentar nas principais cidades da Suíça e Wiesbaden na Alemanha.</p><p>Para além da sua atividade performativa, é professor de canto, dirige o Coro Magnus D&#x27;Om desde 2013 e leciona em instituições como o Conservatório de Música e Artes do Dão e o Zêzere Festival Arts. Orienta masterclasses e <span style="font-style:italic">workshops</span> de técnica vocal em vários conservatórios e para diversos coros em Portugal.</p>', '<p>Desde cedo, Luís Rendas Pereira demonstrou uma afinidade natural pela música que moldaria a trajetória da sua vida. Aos oito anos, motivado por um encontro fortuito com um piano antigo, iniciou os seus estudos musicais com aulas particulares. Aos 10 anos, continuou os seus estudos musicais e pianísticos no Instituto Gregoriano de Lisboa, onde mais tarde descobriu a sua verdadeira paixão: o canto.</p><p>Fez os seus estudos superiores na Universidade de Aveiro, onde concluiu a Licenciatura em Música na classe da soprano Isabel Alcobia e o Mestrado em Ensino de Música. Prosseguiu com uma Pós-Graduação em Ópera na ESMAE, onde se especializou ainda mais no repertório operático.</p><p>O seu percurso formativo inclui um Vocal Performance Certificate pela A2DV, onde trabalhou com Patricia MacMahon e Carla Caramujo. Tem desenvolvido o seu repertório de Lieder com Wolfgang Holzmair e atualmente aperfeiçoa-se com Abbie Furmansky, tendo também trabalhado regularmente com Susan Waters e Pierre Mak. O seu desenvolvimento artístico inclui masterclasses com nomes reconhecidos do panorama lírico internacional como Nelly Miriciou, Brian Gill, Verena Keller, Peter A. Wilson, Håkan Hagegård, Stephen Robertson, António Salgado, Lina Maria Akerlund e Ulrika Sonntag, complementando a sua formação na área da interpretação com João Paulo Santos, Enza Ferrari e Miquel Ortega Pujol.</p><p>No campo das distinções, foi vencedor do 1º prémio (ex-aequo) no Concurso Internacional de Santa Cecília em 2013 e conquistou o 3º prémio no XV Concurso Internacional Cidade do Fundão, em 2014 e 2016. Mais recentemente, foi finalista dos 11º e 12º Concurso de Canto da Fundação Rotária, onde obteve o prémio de &#x27;melhor interpretação de canção estrangeira&#x27; (2021) e o Prémio Círculo Richard Wagner (2023). Em 2021, alcançou ainda o 2º prémio no Concurso José Augusto Alegria, em Évora.</p><p>Em 2024, participou no prestigiado <span style="font-style:italic">International Opernwerkstatt</span>, um programa intensivo de formação operática que lhe proporcionou preparação técnica e artística especializada, culminando em várias apresentações na Suíça e na Alemanha.</p>', '<p>O barítono Luís Rendas Pereira tem-se destacado no cenário lírico com uma extensa carreira na ópera, desempenhando papéis principais em obras de Mozart (Conde em Le Nozze di Figaro, Guglielmo em Cosi fan tutte, Masetto em Don Giovanni e Buff em Der Schauspieldirektor), Donizetti (Enrico em Il campanello e Gasparo em Rita), Menotti (Bob em The Old maid and the thief e Ben em O telefone), Bizet (Zuniga em Carmen) e Pergolesi (Uberto em La Serva Padrona). No repertório contemporâneo português, participou nas estreias de &quot;Ainda não vi-te as mãos&quot; de Edward Luiz d&#x27;Abreu, &quot;Geraldo e Samira&quot; de Amílcar Vasques Dias e &quot;π&quot; de João Pedro Oliveira, além de &quot;Não há machado que corte&quot; (Jornalista) de Luís Soldado. Trabalhou com encenadores de renome como Mário Moutinho, Claudio Hochman, António Durães, Cláudia Marisa, Paulo Lapa, Kevin Phela, Roberto T. Vecchia, Leandro Alves e José Rui Martins.</p><p>Na área da oratória e concerto, o seu repertório abrange obras como o &quot;Te Deum&quot; de Charpentier, &quot;A Criação&quot; de Haydn (no papel de Adão), diversas obras de Bach (cantatas BWV 6, 36, 62 e 133, Paixão S. Mateus, Oratória de Natal - 4ª, 5ª e 6ª cantatas, Magnificat - gravado para a RTP - e Missa em Si menor), a Oratória de Natal de Saint Saens, a Missa de Santa Cecília de F. J. Schubert e as Vésperas de Monteverdi. Interpretou também os Requiem de Mozart, Fauré, Duruflé e Delius, foi barítono solista em &quot;Das Berliner Requiem&quot; de Kurt Weil, na 9ª sinfonia de Beethoven e na Cantata Gnóstica de Jorge Salgueiro.</p><p>Tem colaborado com inúmeras orquestras portuguesas, incluindo a Orquestra Filarmonia das Beiras, Filarmónica Portuguesa, Orquestra ESMAE, Orquestra do Zêzere Festival Arts, Orquestra da Ópera Joven de Badajoz, Orquestra Clássica da Madeira, Orquestra Barroca da Casa da Música, Orquestra Clássica de Espinho, Remix Ensemble, Ludovice Ensemble, Bonne Corde, Orquestra do Norte, Orquestra Clássica do Centro e Orquestra ESART. Trabalhou sob a direção de maestros como A. Vassalo Lourenço, A. Saiote, J. Ferreira Lobo, Brian Mackay, Mauricio Sotelo-Romero, Martin Lutz, Hervé Niquet, Lawrence Cummings, Martin Andre, Paul Hillier, Sofi Jeanin, Sergio Alapont, Cesário Costa, Miguel Jaloto, Baldur Brönnimann e Diana Vinagre.</p><p>Desde 2011, é membro do Coro da Casa da Música, onde interpreta repertórios desde a idade média até ao século XXI, tendo trabalhado com maestros como Christoph König, Paul Hillier, Simon Carrington, Philip Pickett, Laurence Cummings, Martin Andre, Michail Jurowsky, Olari Elts, Paul McCreesh e Sofi Jeannin.</p><p>Em recitais, tem-se apresentado desde 2014 com a pianista Rita Seara em diversos espaços de referência, incluindo o Teatro do Campo Alegre, Casa da Música (Porto), Pavilhão Centro de Portugal (Coimbra) e Casa de Fralães (Barcelos), também para a fundação Richard Wagner, além de atuações internacionais no Festival de Mesnil Saint Martin em França. Realizou projetos especiais como o recital &quot;Perdido e Amado&quot; com a soprano Susana Vieira e &quot;Biscoitos cantados&quot; com o pianista Pedro Costa, participando também em diversas Galas de Ópera.</p><p>Na vertente pedagógica, é professor de Canto, Coro e Classes de Conjunto no Conservatório de Música e Artes do Dão, onde tem preparado diversos alunos premiados em concursos de canto e candidatos bem-sucedidos ao ensino superior em Portugal e no estrangeiro. Dirige o Coro Magnus D&#x27;Om desde 2013 e é professor residente de Técnica Vocal no Zêzere Festival Arts desde 2015. Tem orientado masterclasses em diversos conservatórios portugueses, incluindo a Escola de Música de Esposende (2019), Orfeão de Leiria (2019, 2022 e 2023), Conservatório Regional de Ponta Delgada (2022), Conservatório de Guimarães (2023 e 2024), Conservatório de Amarante e Conservatório Vale do Sousa (2024), além de <span style="font-style:italic">workshops</span> de Técnica Vocal para Coros em várias cidades portuguesas.</p><p> </p><p><span style="font-weight:bold">PRÉMIOS</span>:</p><p>2023: Prémio Círculo Richard Wagner (12º Concurso de Canto da Fundação Rotária)</p><p>2021: </p><p>- 2º prémio - Concurso José Augusto Alegria (Évora)</p><p>- Finalista e prémio &#x27;melhor interpretação de canção estrangeira&#x27; - 11º Concurso de Canto da Fundação Rotária</p><p>2016: 3º prémio - XV Concurso Internacional Cidade do Fundão</p><p>2014: 3º prémio - XV Concurso Internacional Cidade do Fundão</p><p>2013: 1º prémio (ex-aequo) - Concurso Internacional de Santa Cecília</p><p> </p><p><span style="font-weight:bold">PAPÉIS OPERÁTICOS</span>:</p><ul><li>W. A. Mozart</li><ul><li>Le Nozze di Figaro (Conde)</li><li>Cosi fan tutte (Guglielmo)</li><li>Don Giovanni (Masetto)</li><li>Der Schauskspieldirektor (Buff)</li></ul><li>G. Donizetti</li><ul><li>Il campanello (Enrico)</li><li>Rita (Gasparo)</li></ul><li>G. C. Menotti</li><ul><li>The Old maid and the thief (Bob)</li><li>O telefone (Ben)</li></ul><li>G. Bizet: Carmen (Zuniga)</li><li>G. B. Pergolesi: La Serva Padrona (Uberto)</li><li>Estreias:</li><ul><li>&quot;Ainda não vi-te as mãos&quot; (Homem) - Edward Luiz d&#x27;Abreu</li><li>&quot;Geraldo e Samira&quot; (Omar Youssef) - Amílcar Vasques Dias</li><li>&quot;π&quot; (Miguel) - João Pedro Oliveira</li></ul></ul><p><span style="font-weight:bold">REPERTÓRIO DE ORATÓRIA E CONCERTO:</span></p><ul><li>J. S. Bach</li><ul><li>Cantatas BWV 6, 36, 62, e 133</li><li>Paixão S. Mateus</li><li>Oratória de Natal (4ª, 5ª e 6ª cantatas)</li><li>Magnificat</li><li>Missa em Si menor</li></ul><li>Requiem</li><ul><li>W. A. Mozart</li><li>G. Fauré</li><li>M. Duruflé</li><li>F. Delius</li></ul><li>Outras obras</li><ul><li>M. A. Charpentier: Te Deum</li><li>G. F. Handel: Messias</li><li>F. J. Haydn: A Criação (Adão)</li><li>Saint Saens: Oratória de Natal</li><li>F. Schubert: Missa de Santa Cecília</li><li>C. Monteverdi: Vésperas</li><li>Kurt Weil: Das Berliner Requiem</li><li>L. V. Beethoven: 9ª sinfonia</li><li>Jorge Salgueiro: Cantata Gnóstica</li></ul></ul><p><span style="font-weight:bold">COLABORAÇÕES</span>:</p><ul><li>Filarmonia das Beiras</li><li>Filarmónica Portuguesa</li><li>Orquestra ESMAE</li><li>Orquestra do Zêzere Festival Arts</li><li>Orquestra da Ópera Joven de Badajoz</li><li>Orquestra Clássica da Madeira</li><li>Orquestra Barroca da Casa da Música</li><li>Orquestra Clássica de Espinho</li><li>Remix Ensemble</li><li>Ludovice Ensemble</li><li>Bonne Corde</li><li>Orquestra do Norte</li><li>Orquestra Clássica do Centro</li><li>Orquestra ESART</li></ul><p> </p>', '<p><span style="font-weight:bold">PRÉMIOS</span>:</p><p>2023: Prémio Círculo Richard Wagner (12º Concurso de Canto da Fundação Rotária)</p><p>2021:</p><ul><li>2º prémio - Concurso José Augusto Alegria (Évora)</li><li>Finalista e prémio &#x27;melhor interpretação de canção estrangeira&#x27; - 11º Concurso de Canto da Fundação Rotária</li></ul><p>2016: 3º prémio - XV Concurso Internacional Cidade do Fundão</p><p>2014: 3º prémio - XV Concurso Internacional Cidade do Fundão</p><p>2013: 1º prémio (ex-aequo) - Concurso Internacional de Santa Cecília</p><p><span style="font-weight:bold">PAPÉIS OPERÁTICOS</span>:</p><ul><li>Mozart</li><ul><li>Le Nozze di Figaro (Conde)</li><li>Cosi fan tutte (Guglielmo)</li><li>Don Giovanni (Masetto)</li><li>Der Schauskspieldirektor (Buff)</li></ul><li>Donizetti</li><ul><li>Il campanello (Enrico)</li><li>Rita (Gasparo)</li></ul><li>Menotti</li><ul><li>The Old maid and the thief (Bob)</li><li>O telefone (Ben)</li></ul><li>Bizet: Carmen (Zuniga)</li><li>Pergolesi: La Serva Padrona (Uberto)</li><li>Estreias</li><ul><li>&quot;Ainda não vi-te as mãos&quot; (Homem) - Edward Luiz d&#x27;Abreu</li><li>&quot;Geraldo e Samira&quot; (Omar Youssef) - Amílcar Vasques Dias</li><li>&quot;π&quot; (Miguel) - João Pedro Oliveira</li></ul></ul><p><span style="font-weight:bold">REPERTÓRIO DE ORATÓRIA E CONCERTO:</span></p><ul><li>J. S. Bach</li><ul><li>Cantatas BWV 6, 36, 62, e 133</li><li>Paixão S. Mateus</li><li>Oratória de Natal (4ª, 5ª e 6ª cantatas)</li><li>Magnificat</li><li>Missa em Si menor</li></ul><li>Requiem</li><ul><li>W. A. Mozart</li><li>G. Fauré</li><li>M. Duruflé</li><li>F. Delius</li></ul><li>Outras obras</li><ul><li>M. A. Charpentier: Te Deum</li><li>F. J. Haydn: A Criação (Adão)</li><li>Saint Saens: Oratória de Natal</li><li>F. Schubert: Missa de Santa Cecília</li><li>C. Monteverdi: Vésperas</li><li>Kurt Weil: Das Berliner Requiem</li><li>L. V. Beethoven: 9ª sinfonia</li><li>Jorge Salgueiro: Cantata Gnóstica</li></ul></ul><p><span style="font-weight:bold">COLABORAÇÕES</span>:</p><ul><li>Filarmonia das Beiras</li><li>Filarmónica Portuguesa</li><li>Orquestra ESMAE</li><li>Orquestra do Zêzere Festival Arts</li><li>Orquestra da Ópera Joven de Badajoz</li><li>Orquestra Clássica da Madeira</li><li>Orquestra Barroca da Casa da Música</li><li>Orquestra Clássica de Espinho</li><li>Remix Ensemble</li><li>Ludovice Ensemble</li><li>Bonne Corde</li><li>Orquestra do Norte</li><li>Orquestra Clássica do Centro</li><li>Orquestra ESART</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 36: Nani Medeiros
INSERT IGNORE INTO users (id, email, password, role) VALUES ('78d195c7-c5e4-4b69-83e2-09d554962928', 'wix-78d195c7@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('efe7e8bb-1c0d-403d-b7bc-6bf81a024426', '78d195c7-c5e4-4b69-83e2-09d554962928', 'nani-medeiros', 'Nani Medeiros', 'Nani', '912240404', '1992-07-16', 'Brasil', 'Portugal', 'Lisboa', 'Lisboa, Portugal', NULL, '1800107', 'Cantora de Música Brasileira e Fado', 'A música é o meu caminho para a liberdade e a conexão com o divino.', 'https://static.wixstatic.com/media/78d195_502d657ac9d94fdfa3557a9aa81e15da~mv2.jpg', 'wix:document://v1/78d195_2dfba650706d47639184f4cc16c0dc9f.pdf/Biografia%20de%20Nani%20Medeiros.pdf', NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/78d195_63a93faf2ae742a4abb4d340f5aaafd8.mp3', NULL, NULL, 'https://youtu.be/1QMygKGNaRs', 'https://youtu.be/2rPyqPgRUDA', 'https://youtu.be/C5oybmqPJ1c', 'https://youtu.be/hVM-BtyqGSQ', 'https://youtu.be/hR8UiGtCcC4', 'https://youtu.be/E1S3xUtPZuA', 'https://youtu.be/8Z-pdJqR8No', 'https://youtu.be/irvFxOGLtV4', 'https://youtu.be/FfraUyVYsvU', NULL, '<p class="font_8" style="text-align: center">"<em><strong>Nani Medeiros é uma artista.</strong></em></p>
<p class="font_8" style="text-align: center"><em><strong>É mais que cantora.</strong></em></p>
<p class="font_8" style="text-align: center"><em><strong>É mais que atriz.</strong></em></p>
<p class="font_8" style="text-align: center"><em><strong>Mais que intérprete.</strong></em></p>
<p class="font_8" style="text-align: center"><em><strong>Ela é mais</strong></em>."</p>
<p class="font_8" style="text-align: center"><strong>Artur José Pinto - Ator, diretor de teatro e dramaturgo</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Nani Medeiros é uma talentosa <strong>cantora brasileira</strong> que, com uma voz emocionante e uma presença cativante, traz a brasilidade e a versatilidade musical para os palcos.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">A música de Nani Medeiros reflete a sua herança brasileira, com <strong>influências do samba, bossa nova e MPB</strong>. A sua <strong>voz é calorosa e expressiva</strong>, capaz de transmitir as emoções e a intensidade das suas letras. O seu<strong> estilo é uma fusão de elementos tradicionais e modernos</strong>, criando um repertório único.</p>', '<p style="text-align:justify">Nani Medeiros descobriu a sua paixão pelas artes, especialmente pela música, ainda na infância. A sua casa tinha um ambiente muito musical e eclético, influenciado pelos seus irmãos mais velhos que também se aventuravam na música. Esta atmosfera musical teve um grande impacto nela e, em breve, começou a <span style="font-weight:bold">participar em pequenos concursos de canto</span> na sua cidade natal, Porto Alegre, no sul do Brasil. Um dos momentos de destaque foi quando interpretou o clássico <span style="font-weight:bold">“Non, je ne regrette rien” de Édith Piaf</span> num <span style="font-weight:bold">concurso da Aliança Francesa</span>.</p><p style="text-align:justify"> </p><p style="text-align:justify">Após esse evento, não parou mais e continuou a procurar o seu caminho. Começou por <span style="font-weight:bold">estudar artes cênicas</span> com vários atores, incluindo <span style="font-weight:bold">Zé Adão Barbosa</span> no TEPA (Teatro Escola Porto Alegre). Nessa fase, também começou a trabalhar com jingles e locuções para diversas produtoras de áudio.</p><p style="text-align:justify"> </p><p style="text-align:justify">Em 2012, decidiu realizar o seu <span style="font-weight:bold">primeiro concerto</span>, um <span style="font-weight:bold">tributo à cantora Elis Regina</span>, intitulado “<span style="font-weight:bold">Elis, Essa Mulher</span>”, que foi um grande sucesso. Desde então, Nani entrou na cena musical da cidade, conhecendo muitos músicos, compositores e cantores. Aproximou-se muito do universo da <span style="font-weight:bold">música brasileira tradicional</span>, particularmente do <span style="font-weight:bold">choro </span>e do <span style="font-weight:bold">samba</span>, o que levou ao convite para o seu <span style="font-weight:bold">primeiro grande projeto</span>: um musical sobre a vida e obra de um dos principais compositores brasileiros, Lupicínio Rodrigues. “<span style="font-weight:bold">Lupi, o Musical - Uma Vida em Estado de Paixão</span>” estreou em 2014 no icónico Theatro São Pedro, e também foi exibido no principal canal de TV do estado.</p><p style="text-align:justify"> </p><p style="text-align:justify">Após este ponto de viragem na sua carreira, Nani foi atraída pelas linguagens musicais tradicionais, um caminho que a levou ao <span style="font-weight:bold">Fado </span>anos mais tarde, influenciando profundamente o seu estilo de canto.</p><p style="text-align:justify"> </p><p style="text-align:justify">Nani Medeiros reside em Lisboa desde 2019, e o seu trabalho está profundamente ligado à música brasileira através de géneros originários como a <span style="font-weight:bold">canção</span>, o <span style="font-weight:bold">choro</span>, o <span style="font-weight:bold">samba </span>e a <span style="font-weight:bold">bossa nova</span>, e à forma como estas linguagens se entrelaçam com o <span style="font-weight:bold">fado</span>. De maneira orgânica, estas linguagens fundem-se no seu canto e nos seus projetos, que também incluem a preocupação de apresentar novos compositores e temas inéditos, evidenciando a contemporaneidade destes géneros e linguagens.</p>', '<p style="text-align:justify">Nani Medeiros é uma cantora que demonstra extremo cuidado na interpretação das canções e das obras dos compositores a quem dedica o seu canto. <span style="font-weight:bold">O seu principal objetivo é servir a música, a melodia e o poema</span>.</p><p style="text-align:justify"> </p><p style="text-align:justify">A expressão musical de Nani Medeiros está estreitamente associada à tradição musical brasileira, envolvendo <span style="font-weight:bold">géneros fundamentais como a canção, o choro, o samba e a bossa nova, que se entrelaçam harmoniosamente com o fado</span>. De maneira natural, estas vertentes musicais são integradas no seu canto e influenciam os seus projetos, destacando-se pelo seu compromisso em introduzir novos compositores e músicas originais, ilustrando a evolução contemporânea destes géneros e formas de expressão.</p><p style="text-align:justify"> </p><p style="text-align:justify">Nani já <span style="font-weight:bold">partilhou palcos com diversos artistas</span>, incluindo <span style="font-weight:bold">Fito Paez</span>, o<span style="font-weight:bold"> maestro João Carlos Martins, Vanessa da Mata, Tito Paris, Maria João, Kátia Guerreiro e Raquel Tavares</span>, entre outros. Apresentou-se em vários países, além de diversos estados do Brasil, incluindo Espanha, Itália, Alemanha, Grécia e China.</p><h2 style="text-align:justify"> </h2><h3 style="text-align:justify"><span style="font-weight:bold">LINHA DO TEMPO</span></h3><h2> </h2><p style="text-align:justify"><span style="font-weight:bold">2024 </span>- Lançou em maio seu mais recente álbum, o EP “Travessia”;</p><p style="text-align:justify"><span style="font-weight:bold">2024 </span>- Apresentou-se no Instituto Cultural Guimarães Rosa – Embaixada do Brasil em Roma (Itália);</p><p style="text-align:justify"><span style="font-weight:bold">2023 </span>- Apresentou o concerto &quot;Travessia&quot; no salão principal do Consulado de Portugal em Sevilha (Espanha);</p><p style="text-align:justify"><span style="font-weight:bold">2023 </span>- Participou no Festival Lusofonia em Macau (China), integrando o projeto &quot;A Gafieira&quot;;</p><p style="text-align:justify"><span style="font-weight:bold">2023 </span>- Apresentou o concerto &quot;Nos Horizontes do Mundo - A música de Paulinho da Viola&quot; no Centro Cultural São Paulo;</p><p style="text-align:justify"><span style="font-weight:bold">2023 </span>- Estreou com lotação esgotada na Casa de Francisca em São Paulo – Brasil o concerto Fado Tropical com participação de Felipe Catto;</p><p style="text-align:justify"><span style="font-weight:bold">2022 </span>- Participou do concerto em comemoração aos 55 anos de carreira do fadista João Braga que foi apresentado no teatro São Luiz em Lisboa;</p><p style="text-align:justify"><span style="font-weight:bold">2022 </span>- Apresentou o concerto de Samba e Choro na Associação Cultural Chorinho de Nuremberg (Alemanha);</p><p style="text-align:justify"><span style="font-weight:bold">2022 </span>- Apresentou o concerto &quot;Travessia | Fado, Choro e outras brasilidades&quot; na abertura do Samos Young Artists Festival, organizado pela Schwarz Foundation na ilha de Samos (Grécia);</p><p style="text-align:justify"><span style="font-weight:bold">2022 </span>– Estreou o espetáculo “Travessia” no Festival MUP (Musica Urbana Portuguesa) em Lisboa;</p><p style="text-align:justify"><span style="font-weight:bold">2021 </span>– Passou a integrar o elenco da casa de fados Fama de Alfama, onde apresenta o projeto “Fado &amp; Choro”;</p><p style="text-align:justify"><span style="font-weight:bold">2021 </span>- Participou do concerto em homenagem ao Dia Mundial da Língua Portuguesa &quot;Sons</p><p style="text-align:justify">Lusófonos&quot; ao lado dos fadistas Rodrigo Costa Félix e Cristina Clara, que foi realizado no Consulado de Portugal em Sevilha (Espanha);</p><p style="text-align:justify"><span style="font-weight:bold">2020 </span>- Participou da reabertura do Coliseu dos Recreios de Lisboa com o concerto do coletivo Rua das Pretas ao lado de Maria João e Tito Paris;</p><p style="text-align:justify"><span style="font-weight:bold">2020 </span>– Estreou o concerto “Saudades do Brasil em Portugal” com participação da fadista Ana Sofia Varela na Casa Museu Amália Rodrigues;</p><p style="text-align:justify"><span style="font-weight:bold">2020 </span>– Gravou o álbum “Um copo de Fado dois de Bossa” do coletivo Rua das Pretas;</p><p style="text-align:justify"><span style="font-weight:bold">2020 </span>– Estreou o concerto “Fado &amp; Samba Canção” no projeto Real Fado;</p><p style="text-align:justify"><span style="font-weight:bold">2019 </span>– Apresentou o concerto Valentia no Casino Estoril em Lisboa;</p><p style="text-align:justify"><span style="font-weight:bold">2019 </span>- Já residente na cidade de Lisboa, participou do Festival SuperBock em Stock “Rua das Pretas convida Nani Medeiros”;</p><p style="text-align:justify"><span style="font-weight:bold">2019 </span>- Foi indicada para o Prémio Açorianos de Música de Porto Alegre na categoria melhor intérprete de MPB pelo seu álbum de estreia &quot;Valentia&quot;;</p><p style="text-align:justify"><span style="font-weight:bold">2018 </span>– Participou da 2ª “A mostra Canção Presente – Alma Feminina” com participação especial da cantora Fátima Guedes, apresentado no teatro Glauce Rocha no Rio de Janeiro;</p><p style="text-align:justify"><span style="font-weight:bold">2018 </span>- Iniciou o projeto “Bailinho da Nani”, apresentando-se em diversas casas de shows da cidade de Porto Alegre e também no Bar Semente no Rio de Janeiro;</p><p style="text-align:justify"><span style="font-weight:bold">2018 </span>- Esteve em temporada no Instituto Ling na cidade de Porto Alegre compondo a trilha musical do “Sarau Psicanarte” apresentado pela jornalista Thaís Furtado;</p><p style="text-align:justify"><span style="font-weight:bold">2018 </span>- Idealizou ao lado dos músicos Mathias Pinto e João Pita o concerto “À Flor da Pele” que percorreu diversos teatros do SESC por diversas cidades do estado do Rio Grande do Sul;</p><p style="text-align:justify"><span style="font-weight:bold">2017 </span>- Esteve pela primeira vez em Portugal com o concerto do álbum “Valentia”</p><p style="text-align:justify"><span style="font-weight:bold">2016 </span>- Começou a tocar fado e teve projeção nacional, cantando nos estados de São Paulo, Mato Grosso do Sul, Goiás, Teresina, Sergipe, e Rio Grande do Sul.</p><p style="text-align:justify"><span style="font-weight:bold">2015 </span>- Participou do musical &quot;Estação Brasil – A música brasileira na era do rádio&quot; com roteiro e direção de Artur José Pinto que estreou no Teatro Bourbon Country. Foi uma das apresentadoras do canal OCTO da RBS TV (afiliada à Rede Globo) criado pela renomada cineasta Flávia Moraes, que estreou em novembro desse ano. No canal OCTO dirigiu a quadra Acústico OC, onde entrevistou músicos do Porto Cena musical alegre e brasileira.</p><p style="text-align:justify"><span style="font-weight:bold">2014 </span>- Estreou como atriz no antológico Teatro São Pedro, integrando o elenco dos musicais &quot;Lupi, O Musical – Uma vida em estado de paixão&quot; e &quot;O Maestro, o Malandro e o Poeta – Tom, Chico e Vinícius&quot;, ambos com roteiro e direção de Artur José Pinto, tendo o primeiro sido apresentado como programa especial pela RBS TV.</p><p style="text-align:justify"><span style="font-weight:bold">2013 </span>- Criou o espetáculo &quot;É Luxo Só&quot; com repertório apenas de grandes cantores brasileiros, estreando no clássico Ocidente Bar, em Porto Alegre/RS.</p><p style="text-align:justify"><span style="font-weight:bold">2012 </span>- Criou uma homenagem a Elis Regina intitulada &quot;Essa Mulher&quot; que estreou na Casa de Cultura Mário Quintana e foi um grande sucesso.</p><p style="text-align:justify"><span style="font-weight:bold">2011 </span>- Acompanhada pelo Maestro João Carlos Martins no Bourbon Country Theatre na conferência da marca.</p><p style="text-align:justify"><span style="font-weight:bold">2010 </span>- Destacou-se cantando e interpretando a música &quot;Me Faz Bem&quot; de Jorge Drexler, com versão de Paulinho Moska, no videoclipe de uma campanha publicitária.</p>', '<p class="font_8" style="text-align: justify"><strong>ÁLBUNS</strong></p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">"<a href="https://open.spotify.com/intl-pt/album/11Shro6LEaVFzDUnL92P9Y?si=hXZKIOylTbGydX3Tcc8UoA&amp;nd=1&amp;dlsi=e829ade969764417" target="_blank"><u>Travessia</u></a>" (2024)</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">É um EP gravado ao vivo em Lisboa, que oferece uma seleção cuidada de temas que resgatam composições esquecidas no vasto arquivo da música brasileira. Além destas, o álbum "Travessia" inclui também músicas inéditas de novos autores, destacando-se o choro-fado "Mil Pessoas" de Maurício Carrilho e Roberto Didio, uma homenagem a Fernando Pessoa.</p>
<p class="font_8" style="text-align: justify">O arranjo instrumental deste trabalho funde as sonoridades típicas da música brasileira com o fado, contando com André Dias na guitarra portuguesa, Daniel Pinto na viola baixo, e João Pita no violão de 7 cordas sob a direção musical. Nani Medeiros, com a sua voz, integra este conjunto, apresentando um repertório que evoluiu ao longo dos anos através da sua experiência musical entre o Brasil e Portugal.</p>
<p class="font_8" style="text-align: justify">Estes temas brasileiros, frequentemente interpretados por Nani em tertúlias fadistas e casas de fado, e acompanhados por destacados músicos de fado, contribuíram para uma troca musical intensa, funcionando como um verdadeiro laboratório que influenciou tanto a concepção artística como os arranjos do projeto.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">"<a href="https://open.spotify.com/intl-pt/album/2TfTVlyUuYAzfdBOpCPt1m?go=1&amp;nd=1&amp;dlsi=8aa63f52497945d3" target="_blank"><u>Valentia</u></a>" (2017)</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">Este trabalho apresenta um repertório inédito, composto maioritariamente por novos compositores brasileiros, como Mathias Pinto, Alexandre Susin, Luis Barcelos e João Camarero, além da colaboração do consagrado poeta Paulo César Pinheiro. O álbum reflete a versatilidade musical de Nani, explorando diferentes gêneros da música brasileira, como o afro-samba em faixas vibrantes, ao lado de canções mais intimistas e introspectivas. "Valentia" consolidou Nani Medeiros como uma voz de destaque no cenário musical, trazendo à tona suas influências e referências, desde grandes nomes como Elizeth Cardoso e Clara Nunes, até artistas contemporâneos que inspiram sua criatividade.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify"><strong>OPINIÃO</strong></p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">"Nani Medeiros é uma artista. Mais do que cantora, atriz ou intérprete, ela é uma força inspiradora que transcende os rótulos." - Artur José Pinto, ator, diretor de teatro e dramaturgo.</p>
<p class="font_8" style="text-align: justify">"Com uma voz emocionante e uma presença cativante, Nani Medeiros traz a brasilidade e a versatilidade musical para os palcos." - <a href="https://gauchazh.clicrbs.com.br/cultura-e-lazer/musica/noticia/2017/10/video-nani-medeiros-lanca-primeiro-album-cheio-de-brasilidade-cj8fzhvkl005n01oydlxk3s63.html" target="_blank"><u>GZH</u></a></p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify"><strong>PROJETOS</strong></p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify"><strong>“Travessia”</strong></p>
<p class="font_8" style="text-align: justify">Trata-se de uma parceria entre Nani Medeiros e o violonista Junior Pita para explorar o encontro entre a música brasileira e o fado. Neste projeto único, o choro, o samba-canção e a bossa nova juntam-se ao fado, criando uma verdadeira travessia musical. O repertório das canções reflete sobre a escolha de transitar, atravessar, mudar-se, mover-se e seguir em frente, deixando-se influenciar por diferentes sonoridades.</p>
<p class="font_8" style="text-align: justify">Do antigo ao contemporâneo, "Travessia" acentua as semelhanças e diferenças entre esses universos musicais lusófonos, numa viagem que enriquece e inspira o público. A voz emocionante de Nani Medeiros é acompanhada por André Dias (guitarra portuguesa), Daniel Pinto (viola baixo) e João Pita (viola de 7 cordas), criando uma sinergia única entre as culturas brasileira e portuguesa.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify"><strong>NOTÍCIAS &amp; ENTREVISTAS</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><a href="https://www.smartx.art/post/nani-medeiros-uma-voz-que-atravessa-fronteiras" target="undefined"><u>Entrevista SMARTx (2024)</u></a> - Nani Medeiros: uma voz que atravessa fronteiras</p>
<p class="font_8"><a href="https://eltrapezio.eu/es/portugal/nani-medeiros-a-cultura-ibero-americana-esta-me-mesmo-no-sangue_40881.html" target="_blank"><u>O Trapézio (2023)</u></a> - Nani Medeiros: “A cultura ibero-americana está-me mesmo no sangue”</p>
<p class="font_8" style="text-align: justify"><a href="https://www.publico.pt/2023/10/28/culturaipsilon/noticia/nani-medeiros-canta-clara-nunes-80-anos-nascimento-sambista-2068251" target="_blank"><u>Público (2023)</u></a> - Nani Medeiros canta Clara Nunes nos 80 anos do nascimento da sambista</p>
<p class="font_8" style="text-align: justify"><a href="https://gauchazh.clicrbs.com.br/cultura-e-lazer/musica/noticia/2017/10/video-nani-medeiros-lanca-primeiro-album-cheio-de-brasilidade-cj8fzhvkl005n01oydlxk3s63.html" target="_blank"><u>GZH Música (2017)</u></a> - Nani Medeiros lança primeiro álbum cheio de brasilidade</p>
<p class="font_8">Quer saber mais?</p>
<p class="font_8" style="text-align: justify">Entre em contacto connosco!</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 37: Ivo Silva
INSERT IGNORE INTO users (id, email, password, role) VALUES ('a230cbe0-ea15-4e6c-8487-fd5f5928c4e2', 'wix-a230cbe0@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('f0368df6-4796-4724-85b4-13a7d292e9d9', 'a230cbe0-ea15-4e6c-8487-fd5f5928c4e2', 'ivo-silva', 'Ivo Silva', 'Ivo', '351933608436', '1990-04-04', 'Portugal', 'Portugal', 'Porto', 'Rua do Buçaco', 'Bl.19 Casa 44', '4300-083', 'Maestro', 'Envolvido em reviver o sentimento de cada composição, ausento-me de experienciar qualquer sensação.', 'https://static.wixstatic.com/media/7b859e_add02d40b7284fc2aa0253667c8cdeda~mv2.jpg', 'wix:document://v1/a230cb_c27a00852c294881b686da42b146afb4.pdf/Biografia%20Ivo%20Silva.pdf', 'https://www.facebook.com/ivo.silva.1829', NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/a230cb_c124b05039ac4c97a392c67971004a76.mp3', NULL, NULL, 'https://youtu.be/VPc8HqnQxvo', 'https://youtu.be/9Bvs0fSvmgM', 'https://www.youtube.com/watch?v=uyFotko9G_k', 'https://youtu.be/8YgdiFJNYvo', 'https://www.youtube.com/watch?v=E3hCVMl4LNM', 'https://youtu.be/FxDHq3Sc6GQ', 'https://youtu.be/Fc8YO4Gx0ns', 'https://youtu.be/IFmSgAXrqpk', NULL, NULL, '<p>“Ivo creates a good, pleasant atmosphere in the orchestra and has a serious approach. Speaks little but well and gains the musician´s attention.” <span style="font-weight:bold">Douglas Bostock </span>(Adjudication Report - <span style="font-style:italic">WMC Kerkrade International Conductors Contest</span>)</p><p> </p><p><span style="font-weight:bold">(PT) </span></p><p>Ivo Silva é um jovem maestro português, natural do Porto. Alcançou algum reconhecimento internacional, especialmente após ter conseguido o <span style="font-weight:bold">3º Prémio (bronze baton) </span>no concurso internacional de direção <span style="font-style:italic">World Music Contest- Conducting Competition</span>, em 2022, na Holanda. Em Portugal obteve o <span style="font-weight:bold">2º Prémio</span> (Ex aequo) na <span style="font-style:italic">II Academia Internacional e Concurso de Direção Orquestral</span>, realizado pela <span style="font-style:italic">Orquestra de Câmara de Cascais e Oeiras</span>. Recentemente obteve o o <span style="font-weight:bold">1º Prémio</span> no <span style="font-style:italic">III Concurso de Dirección Orquestral - Reveriano Soutullo</span> (2025).</p><p> </p><p>Elogiado pela sua &quot;<span style="text-decoration:underline">atitude confiante</span> e <span style="text-decoration:underline">elegância em palco&quot;</span>, acabou por adquirir a sua &quot;<span style="text-decoration:underline">própria identidade na direção&quot;</span>. É valorizado pela &quot;<span style="text-decoration:underline">excelente atenção aos detalhes&quot;</span> e pela sua &quot;<span style="text-decoration:underline">elevada musicalidade&quot;</span>. &quot;<span style="text-decoration:underline">Assertivo durante o ensaio&quot;</span> cria um &quot;<span style="text-decoration:underline">ambiente agradável e descontraído&quot;</span> durante a semana de trabalho. A sua &quot;<span style="text-decoration:underline">humildade e autenticidade&quot;</span> captam o respeito dos músicos com quem partilha a sua arte.</p><p> </p><p>A sua habilidade em comunicar com os músicos levou-o a colaborações de sucesso com orquestras de prestígio, como a <span style="font-weight:bold">Orquestra do Norte, <span style="font-style:italic">Orquestra de Câmara de Cascais e Oeiras</span> </span>e <span style="font-weight:bold">Banda Sinfónica Portuguesa (Ensemble de Metais)</span>, bem como com um vasto leque de solistas, como <span style="font-weight:bold">Jorge Almeida</span>, <span style="font-weight:bold">Ekaterine Richter</span> e <span style="font-weight:bold">Nuno Pinto</span>. Além das suas atuações, é diretor artístico da <span style="font-weight:bold">Banda Musical de Arouca</span> e fundador do <span style="font-weight:bold">Septentrionalium Ensemble</span>, projeto criado com o intuito de proporcionar ao público uma viagem cultural e temporal pela história da música.</p><p> </p><p>Tem como principais professores os maestros: <span style="font-weight:bold">Fernando Marinho,</span> <span style="font-weight:bold">Jean-Marc Burfin</span> e <span style="font-weight:bold">Jose Rafael Pascual Vilaplana</span>.</p><p> </p><p><span style="font-weight:bold">(EN)</span></p><p>Ivo Silva is a young Portuguese conductor, a native of Porto. He has achieved some international recognition, particularly after securing <span style="font-weight:bold">3rd Prize</span> (the Bronze Baton) in the <span style="font-style:italic">World Music Contest-Conducting Competition</span> in the Netherlands in 2022. In Portugal, he won <span style="font-weight:bold">2nd Prize</span> (ex aequo) at the <span style="font-style:italic">II International Academy and Competition of Orchestral Conducting</span>, organised by the Cascais and Oeiras Chamber Orchestra. Most recently, he was awarded <span style="font-weight:bold">1st Prize</span> at the <span style="font-style:italic">III Concurso de Dirección Orquestral - Reveriano Soutullo</span> (2025).</p><p> </p><p>Complemented for his <span style="font-style:italic"><span style="text-decoration:underline">“confident attitude and elegance on stage,”</span></span> he has cultivated his <span style="font-style:italic"><span style="text-decoration:underline">“own identity in conducting.” </span></span>Ivo Silva is valued for his <span style="font-style:italic"><span style="text-decoration:underline">“excellent attention to detail”</span></span> and his <span style="font-style:italic"><span style="text-decoration:underline">“elevated musicality.”</span></span> Being <span style="font-style:italic"><span style="text-decoration:underline">“assertive during rehearsal,”</span></span> Ivo creates a <span style="font-style:italic"><span style="text-decoration:underline">“pleasant and relaxed atmosphere”</span></span> throughout the working week. His <span style="font-style:italic"><span style="text-decoration:underline">“humility and authenticity”</span></span> earn him the respect of the musicians with whom he shares his art.</p><p> </p><p>His ability to communicate with musicians has led to successful collaborations with prestigious orchestras, such as the <span style="font-weight:bold">Orquestra do Norte</span>, <span style="font-weight:bold">Orquestra de Câmara de Cascais e Oeiras</span> and <span style="font-weight:bold">Banda Sinfónica Portuguesa (Brass Ensemble)</span>, as well as with a wide range of soloists, including <span style="font-weight:bold">Jorge Almeida</span>, <span style="font-weight:bold">Ekaterine Richter</span> and<span style="font-weight:bold"> Nuno Pinto</span>. In addition to his performances, he is the artistic director of the <span style="font-weight:bold">Banda Musical de Arouca</span> and the founder of the <span style="font-weight:bold">Septentrionalium Ensemble</span>, a project created with the aim of providing the public with a cultural and temporal journey through the history of music.</p><p> </p><p>His main teachers include conductors <span style="font-weight:bold">Fernando Marinho</span>, <span style="font-weight:bold">Jean-Marc Burfin</span> and <span style="font-weight:bold">Jose Rafael Pascual Vilaplana</span>.</p><p> </p>', '<p>“Congrats with your confident performance! You presented yourself with your own style of conducting.” <span style="font-weight:bold">Pieter Jansen</span> (Adjudication Report - <span style="font-style:italic">WMC Kerkrade International Conductors Contest</span>)</p><p> </p><p>Depois de ter assistido a um concerto juntamente com o seu pai, numa romaria local, Ivo Silva decidiu iniciar os seus estudos musicais, aos 9 anos de idade, na <span style="font-style:italic">Banda São Cristóvão de Rio Tinto</span>. Ingressou, um ano mais tarde, no <span style="font-style:italic">Conservatório de Música do Porto</span>, na classe do professor <span style="font-weight:bold">Rui Brito</span>. Licenciou-se na variante Sopros- Metais- Trompete, na <span style="font-style:italic">Escola Superior de Música, Artes e Espectáculo do Porto</span>, na classe do professor <span style="font-weight:bold">Kevin Wauldron</span>.</p><p> </p><p>Enquanto trompetista colaborou com a <span style="font-style:italic">Orquestra Sinfónica Portuguesa</span> e com a <span style="font-style:italic">Orquestra Clássica do Sul</span>. Foi vencedor do <span style="font-style:italic">Concurso Interno de Sopros-Metais</span> do <span style="font-style:italic">Conservatório de Música do Porto</span> em 2008. Premiado com uma Menção Honrosa (2013) e 3º prémio (2014) no <span style="font-style:italic">Concurso de Trompete da Póvoa de Varzim</span> e, em 2016, laureado com o 3º prémio do escalão sénior no <span style="font-style:italic">Concurso Internacional de Instrumentos de Sopro “Terras De La Salette”.</span> Em 2018 foi orientador da secção dos metais do <span style="font-style:italic">8º Estágio de Orquestra de Sopros da Banda Musical de Arouca, </span>tendo nesse mesmo ano orientado a secção dos metais do <span style="font-style:italic">VI Estágio de Orquestra de Sopros e Percussão da Escola de Música da Sociedade Filarmónica Sta. Cruz de Alvarenga</span>.</p><p> </p><p>Durante a sua formação académica enquanto instrumentista, despertou o interesse pela direção orquestral, começando por formar e dirigir pequenos grupos corais que se apresentavam em concertos com pequenos ensembles. Em 2014 organizou, e dirigiu um ciclo de concertos com a obra “Requiem” de <span style="font-weight:bold">G. Fauré</span>, onde conseguiu reunir quatro coros e uma orquestra sinfónica. A direção coral impulsionou o seu gosto pela direção de orquestra, tendo-o levado, em 2016, à primeira eliminatória presencial do <span style="font-style:italic">Prémio Jovens Músicos - Categoria Direção de Orquestra</span>. Nesta experiência teve a oportunidade de trabalhar com a <span style="font-style:italic">Orquestra Sinfónica Portuguesa</span>, tornando-se este o ponto de partida para o início da aventura sem termo do estudo de direção orquestral.</p><p> </p><p>Começou por estudar direção com o maestro <span style="font-weight:bold">Fernando Marinho</span> e, em 2020, concluiu o mestrado em <span style="font-style:italic">Direção Orquestral na Escola Superior de Música de Lisboa</span>, na classe do professor <span style="font-weight:bold">Jean-Marc Burfin</span>. Desde então tem frequentado cursos com os maestros <span style="font-weight:bold">Douglas Bostock</span>, <span style="font-weight:bold">Ernst Schelle</span>, <span style="font-weight:bold">José Eduardo Gomes</span>, <span style="font-weight:bold">Peter Rundel</span>, <span style="font-weight:bold">Michalis Economou</span>, <span style="font-weight:bold">José Rafael Pascual Vilaplana</span>, <span style="font-weight:bold">Baldur Brönnimann </span>e <span style="font-weight:bold">Jorma Panula</span>.</p><p> </p><p>Em 2021 gravou a <span style="font-style:italic">premiére </span>da obra <span style="font-style:italic">Noturno &quot;in Memoriam&quot; </span>de <span style="font-weight:bold">Victor Gomes</span> com a <span style="font-style:italic">Orquestra António Fragoso</span> e o violinista <span style="font-weight:bold">Eliseu Silva</span>. No final desse mesmo ano dirigiu o <span style="font-style:italic">Remix Ensemble</span> em contexto da sua <span style="font-style:italic">Academia de Verão</span>, trabalhando a obra <span style="font-style:italic">“Pierrot Lunaire”</span>, de Arnold Schoenberg, com a soprano <span style="font-weight:bold">Marianne Pousseur</span>. Inserido no concurso <span style="font-style:italic">Prémio Jovens Músicos - Direção de Orquestra</span>, agora em 2022, teve a oportunidade de trabalhar com a com a <span style="font-style:italic">Orquestra Metropolitana de Lisboa</span>.</p><p>Nesse ano participou <span style="font-style:italic">II Academia Internacional de Direção</span>, com a <span style="font-style:italic">Orquestra de Cascais e Oeiras</span>, e obteve o 2º lugar (ex aequo) no concurso de direção realizado durante a academia.</p><p> </p><p>Paralelamente ao percurso com orquestra sinfónica, dedica-se também a orquestras de sopros e percussão. Foi maestro da <span style="font-style:italic">Banda Musical Leverense</span> (2016-2018) e é desde 2018 diretor artístico/maestro da <span style="font-style:italic">Banda Musical de Arouca</span>. Neste âmbito, em janeiro de 2023, foi semifinalista no <span style="font-style:italic">VII Encontro de Direção Orquestral em Bilbao</span> onde trabalhou com a <span style="font-style:italic">Banda Municipal de Música de Bilbao</span> e, em julho desse ano, participou no <span style="font-style:italic">III Curso de Direção da Banda Municipal de Barcelona</span>. </p><p> </p><p>Em setembro de 2022 retomou os estudos de direção, na “Royal Birmingham Conservatoire”, na classe de direção do professor <span style="font-weight:bold">Daniele Rosina</span>. Um ano mais tarde, foi selecionado para a <span style="font-style:italic">1ª Masterclass/ concurso de direção da Roménia</span>, onde dirigiu a <span style="font-style:italic">Orquestra Filarmónica de Pitesti</span>. Em junho de 2024 foi selecionado para a 3ª Masterclass Internacional, em Kecskemét (HU), com o maestro <span style="font-weight:bold">Jorma Panula</span>, onde pôde aprender com uma lenda viva do ensino da direção de orquestra a nível mundial. Recentemente dirigiu o <span style="font-style:italic">Ensemble de metais da Banda Sinfónica Portuguesa</span>, a <span style="font-style:italic">Orquestra de Câmara de Cascais e Oeiras</span> e a <span style="font-style:italic">Orquestra do Norte</span>.</p><p> </p><p>É fundador e diretor artístico do <span style="font-style:italic">Septentrionalium Ensemble</span>, um projeto criado com o intuito de desafiar alguns músicos profissionais da zona Norte a interpretarem repertório extremamente desafiante, e proporcionar ao público, para lá do concerto em si, uma viagem temporal e histórica pela história da música.</p>', '<h3><span style="font-weight:bold">Depoimentos/ Testimonials </span></h3><p><span style="text-decoration:underline">2024</span></p><p>“Ivo is a dedicated, hard working musician, who showed remarkable talent in conducting and great musical and communication skills with the orchestra.” <span style="font-weight:bold">Huba Hollókői</span>, Maestro titular da <span style="font-style:italic">Kecskeméti Szimfonikus Zenekar.</span></p><p> </p><p><span style="text-decoration:underline">2022</span></p><p>“Great attention to details and phrasing. Love it. Also the energy you are bringing on the podium.” <span style="font-weight:bold">Bjorn Sagstad </span>(Adjudication Report - <span style="font-style:italic">WMC Kerkrade International Conductors Contest</span>)</p><p> </p><p>“This was really very good rehearsing, persuasively done with charm, and got a good response from the musicians.” <span style="font-weight:bold">Mark Heron</span> (Adjudication Report - <span style="font-style:italic">WMC Kerkrade International Conductors Contest</span>)</p><p> </p><p>“Wonderful performance tonight!” <span style="font-weight:bold">Shizuo Kuwahara</span> (Adjudication Report - <span style="font-style:italic">WMC Kerkrade International Conductors Contest</span></p><p> </p><p><span style="font-weight:bold">(PT)</span></p><h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><h3><span style="font-weight:bold">Concursos</span> </h3><p>2025 - <span style="font-weight:bold">1º Prémio </span>&quot;III Concurso de Dirección Orquestral - Reveriano Soutullo&quot;</p><p>2024 - <span style="font-weight:bold">Semi-finalista</span> &quot;Frederick Fennell Conducting Competition&quot;</p><p>2023 - <span style="font-weight:bold">Semi-finalista</span> <span style="font-style:italic">“Premio Internacional de Dirección “Bilbao Musika”” </span></p><p>2022 - <span style="font-weight:bold">Fase final - Presencial</span> <span style="font-style:italic">&quot;Prémio Jovens Músicos - Direção Orquestral&quot;</span></p><p>2022 - <span style="font-weight:bold">3º Prémio</span> <span style="font-style:italic">&quot;WMC Kerkrade - International Conductor Contest&quot;</span></p><p><span style="font-style:italic">2021 - </span><span style="font-weight:bold">2º Prémio </span>(Ex aequo) &quot;<span style="font-style:italic">II Academia Internacional de Direção</span>, com a <span style="font-style:italic">Orquestra de Cascais e Oeiras&quot;</span></p><p>2016 - <span style="font-weight:bold">Fase final - Presencial </span><span style="font-style:italic">&quot;Prémio Jovens Músicos - Direção Orquestral&quot;</span></p><p> </p><h3><span style="font-weight:bold">Experiência Profissional e Académica</span></h3><p>2024 - <span style="font-style:italic">Orquestra Sinfónica da Academia de Música de Costa Cabral</span></p><p>2023 - <span style="font-style:italic">Orquestra do Norte</span></p><p>2023 - Início do projeto <span style="font-style:italic">Septentrionalium Ensemble</span></p><p>2022 - <span style="font-style:italic">Orquestra de Câmara de Cascais e Oeiras; Premiére </span>da obra <span style="font-style:italic">Cocolle (Mimos) </span>de <span style="font-weight:bold">Alesio Velotti</span></p><p>2021 - Gravação da <span style="font-style:italic">premiére</span> <span style="font-style:italic">Noturno &quot;in Memoriam&quot; </span>de <span style="font-weight:bold">Victor Gomes</span></p><p>2020 - Finalizou Mestrado na <span style="font-style:italic">ESML</span></p><p>2018 - Inicía funções de maestro/ diretor artístico da <span style="font-style:italic">Banda Musical de Arouca</span></p><p>2018 - Ingressa na <span style="font-style:italic">Escola Superior de Música de Lisboa (ESML)</span>, na classe do professor <span style="font-weight:bold">Jean-Marc Burfin</span></p><p>2017 - Compos e gravou a banda sonora da premiada curta metragem <span style="font-style:italic">&quot;A instalação do medo&quot;</span></p><p>2016 - Inicía funções como maestro/ diretor artístico da <span style="font-style:italic">Banda Musical Leverense</span></p><p> </p><h3><span style="font-weight:bold">Cursos/ Masterclasses</span></h3><p>2025 - V<span style="font-style:italic"> Curso de Direção da Banda Municipal de Barcelona (Maestro <span style="font-weight:bold">Jose Rafael Pascual Vilaplana</span>)</span></p><p>2024 - <span style="font-style:italic">The 3rd International Masterclass with Jorma Panula (Maestro <span style="font-weight:bold">Jorma Panula</span>)</span></p><p>2023 - <span style="font-style:italic">Romania International Conducting Masterclass and Competition (Maestro <span style="font-weight:bold">Michalis Economou</span>)</span></p><p>2023 - <span style="font-style:italic">III Curso de Direção da Banda Municipal de Barcelona (Maestro <span style="font-weight:bold">Jose Rafael Pascual Vilaplana</span>)</span></p><p><span style="font-style:italic">2021 - International Conducting Masterclass (Maestro <span style="font-weight:bold">Alex Shillings</span>)</span></p><p><span style="font-style:italic">2021 - XXVI Curso Nacional de Direção BSP (Maestro <span style="font-weight:bold">Baldur Bronnimann</span>)</span></p><p><span style="font-style:italic">2021 - Remix Ensemble Summer Academy (Maestro <span style="font-weight:bold">Peter Rundel</span>)</span></p><p><span style="font-style:italic">2021 - Academia Internacional de Interpretação Musical para Orquestra Sinfónica (Maestro <span style="font-weight:bold">Ernst Schelle</span>)</span></p><p><span style="font-style:italic">2019 - </span>XXIII Curso Nacional de Direção BSP (Maestro <span style="font-weight:bold">Baldur Bronnimann</span>)</p><p>2018 - <span style="font-style:italic">I Curso de direção (Maestro <span style="font-weight:bold">Fernando Marinho</span>)</span></p><p><span style="font-style:italic">2017 - Wind Band Conducting Workshop (Maestro <span style="font-weight:bold">José Eduardo Gomes</span>)</span></p><p><span style="font-style:italic">2017 - Masterclasse de Direção de Orquestra (Maestro <span style="font-weight:bold">Jean-Marc Burfin</span>)</span></p><p> </p><h3><span style="font-weight:bold">Atuações Memoráveis</span></h3><p>2025 - Concerto com <span style="font-style:italic">Banda Musical de Arouca</span> e <span style="font-weight:bold">Tiago Nacarato</span></p><p>2024 - Concerto com <span style="font-style:italic">Banda Musical de Arouca</span> e <span style="font-weight:bold">Fernando Tordo</span></p><p>2024 - Musical &quot;Lion King&quot; com <span style="font-style:italic">Academia de Música de Costa Cabral</span></p><p><span style="font-style:italic">2024 - </span>Concerto com Ensemble de Metais da <span style="font-style:italic">Banda Sinfónica Portuguesa e solista </span><span style="font-weight:bold">Nuno Costa </span>(Eufónio)</p><p>2023 - Concerto com <span style="font-style:italic">Banda Musical de Arouca</span> e <span style="font-weight:bold">Cuca Roseta</span></p><p>2019 - Concerto com <span style="font-style:italic">Banda Musical de Arouca</span> e <span style="font-weight:bold">Ala dos Namorados</span></p><p>2018 - Concerto com <span style="font-style:italic">Banda Musical de Arouca</span> e os artistas <span style="font-weight:bold">Sofia Escobar </span>e <span style="font-weight:bold">FF</span></p><p>2016 - Concerto de encerramento do <span style="font-style:italic">I Ciclo de Masterclasses da Banda Musical Leverense</span>, com os solistas <span style="font-weight:bold">Jorge Almeida</span> (Trompete), <span style="font-weight:bold">Nuno Martins</span> (Trombone) e <span style="font-weight:bold">Nuno Pinto</span> (Clarinete)</p><p> </p><p><span style="font-weight:bold">(EN)</span></p><h3><span style="font-weight:bold">TIMELINE</span></h3><h3><span style="font-weight:bold">Competitions</span></h3><p>2025 - <span style="font-weight:bold">1st Prize</span> “III Orchestral Conducting Competition - Reveriano Soutullo”</p><p>2024 - <span style="font-weight:bold">Semi-finalist</span> “Frederick Fennell Conducting Competition”</p><p>2023 - <span style="font-weight:bold">Semi-finalist</span> “Bilbao Musika International Conducting Prize”</p><p>2022 - <span style="font-weight:bold">Final phase - In person </span>“Young Musicians Prize - Orchestral Conducting”</p><p>2022 - <span style="font-weight:bold">3rd Prize</span> “WMC Kerkrade - International Conductor Contest”</p><p>2021 - <span style="font-weight:bold">2nd Prize</span> (Ex aequo) “II International Conducting Academy, with the Cascais and Oeiras Orchestra”</p><p>2016 - <span style="font-weight:bold">Final phase - In person</span> “Young Musicians Award - Orchestral Conducting”</p><p> </p><h3><span style="font-weight:bold">Professional and Academic Experience</span></h3><p>2024 - <span style="font-style:italic">Costa Cabral Music Academy Symphony Orchestra</span></p><p>2023 - <span style="font-style:italic">Orquestra do Norte</span></p><p>2023 - Start of the <span style="font-style:italic">Septentrionalium Ensemble </span>project</p><p>2022 - <span style="font-style:italic">Cascais and Oeiras Chamber Orchestra</span>; Premiere of the work <span style="font-style:italic">Cocolle (Mimos)</span> by <span style="font-weight:bold">Alesio Velotti</span></p><p>2021 - Recording of the premiere of <span style="font-weight:bold">Victor Gomes&#x27;</span> <span style="font-style:italic">Noturno “in Memoriam”</span></p><p>2020 - Completed Master&#x27;s degree at <span style="font-style:italic">ESML</span></p><p>2018 - Began working as conductor/artistic director of the <span style="font-style:italic">Banda Musical de Arouca</span></p><p>2018 - Admitted at the <span style="font-style:italic">Lisbon School of Music (ESML)</span>, in the class of Prof. <span style="font-weight:bold">Jean-Marc Burfin</span></p><p>2017 - Composed and recorded the soundtrack for the award-winning short film <span style="font-style:italic">“A instalação do medo”</span></p><p>2016 - Began working as conductor/artistic director of the <span style="font-style:italic">Banda Musical Leverense</span></p><p> </p><h3><span style="font-weight:bold">Courses/ Masterclasses</span></h3><p><span style="font-style:italic">2025 - V Conducting Course of the Banda Municipal de Barcelona (Maestro <span style="font-weight:bold">Jose Rafael Pascual Vilaplana</span>)</span></p><p><span style="font-style:italic">2024 - The 3rd International Masterclass with Jorma Panula (Maestro <span style="font-weight:bold">Jorma Panula</span>)</span></p><p><span style="font-style:italic">2023 - Romania International Conducting Masterclass and Competition (Maestro <span style="font-weight:bold">Michalis Economou</span>)</span></p><p><span style="font-style:italic">2023 - III Conducting Course of the Banda Municipal de Barcelona (Maestro <span style="font-weight:bold">Jose Rafael Pascual Vilaplana</span>)</span></p><p><span style="font-style:italic">2021 - International Conducting Masterclass (Maestro <span style="font-weight:bold">Alex Shillings</span>)</span></p><p><span style="font-style:italic">2021 - XXVI National Conducting Course BSP (Maestro <span style="font-weight:bold">Baldur Bronnimann</span>)</span></p><p><span style="font-style:italic">2021 - Remix Ensemble Summer Academy (Maestro <span style="font-weight:bold">Peter Rundel</span>)</span></p><p><span style="font-style:italic">2021 - International Academy of Musical Interpretation for Symphony Orchestra (Maestro <span style="font-weight:bold">Ernst Schelle</span>)</span></p><p><span style="font-style:italic">2019 - XXIII BSP National Conducting Course (Maestro <span style="font-weight:bold">Baldur Bronnimann</span>)</span></p><p><span style="font-style:italic">2018 - I Conducting Course (Maestro <span style="font-weight:bold">Fernando Marinho</span>)</span></p><p><span style="font-style:italic">2017 - Wind Band Conducting Workshop (Maestro<span style="font-weight:bold"> José Eduardo Gomes</span>)</span></p><p><span style="font-style:italic">2017 - Masterclass in Orchestral Conducting (Conductor <span style="font-weight:bold">Jean-Marc Burfin</span>)</span></p><p> </p><h3><span style="font-weight:bold">Memorable Performances</span></h3><p><span style="font-style:italic">2025 - Concert with the Banda Musical de Arouca and <span style="font-weight:bold">Tiago Nacarato</span></span></p><p><span style="font-style:italic">2024 - Concert with the Banda Musical de Arouca and <span style="font-weight:bold">Fernando Tordo</span></span></p><p><span style="font-style:italic">2024 - Musical “Lion King” with the Symphonic Orchestra of Costa Cabral Music Academy</span></p><p><span style="font-style:italic">2024 - Concert with the Brass Ensemble of the Banda Sinfónica Portuguesa and soloist <span style="font-weight:bold">Nuno Costa</span> (Euphonium)</span></p><p><span style="font-style:italic">2023 - Concert with the Banda Musical de Arouca and <span style="font-weight:bold">Cuca Roseta</span></span></p><p><span style="font-style:italic">2019 - Concert with the Banda Musical de Arouca and <span style="font-weight:bold">Ala dos Namorados</span></span></p><p><span style="font-style:italic">2018 - Concert with the Arouca Music Band and artists <span style="font-weight:bold">Sofia Escobar</span> and <span style="font-weight:bold">FF</span></span></p><p><span style="font-style:italic">2016 - Closing concert of the 1st Cycle of Masterclasses of the Banda Musical Leverense, with soloists <span style="font-weight:bold">Jorge Almeida</span> (trumpet), <span style="font-weight:bold">Nuno Martins</span> (trombone), and <span style="font-weight:bold">Nuno Pinto</span> (clarinet)</span></p>', '<h2><span style="font-weight:bold">Entrevistas</span></h2><p>2023</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.rtp.pt/play/p2378/e725215/imperio-dos-sentidos target=undefined>Entrevista à Antena 2 - Septentrionalium Ensemble</a></span></span> (Minuto: 1:21:09)</p><p> </p><p>2022 </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=http://www.youtube.com/watch?v=RYLSrfQsUok&t=280s target=undefined>Chat with the 3 conductors in the final of the International Conductors Contest</a></span></span></p><p> </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://youtu.be/jp8_HZaeLeA?si=23y8GBIY2r5SfOnY target=undefined> Interview Ivo Silva - Kerkrade World Music Competition</a></span></span></p><p> </p><h2> <span style="font-weight:bold">Repertório</span></h2><h3><span style="text-decoration:underline"><a href=https://drive.google.com/file/d/1VmhgRlkdbrzP5o4XwTS6O5brAJzZH8Td/view?usp=drive_link target=undefined>Lista de repertório</a></span></h3>', 'https://static.wixstatic.com/media/a230cb_c9eeeb01929c4f28846726d4d05dc95f~mv2.jpg', 'Kecskeméti Szimfonikus Zenekar (HU) 2024
Photo Credit: www.mannaphoto.hu', 'https://static.wixstatic.com/media/a230cb_1233927eb7fc4dc5a85ac1fe533f33a5~mv2.jpg', 'Orquestra do Norte (PT) 2023', 'https://static.wixstatic.com/media/a230cb_cd865c82cc754a409eb37b44e33c280d~mv2.jpg', 'Symphonic Orchestra of Pitesti Philharmonia (RO) 2023', 'https://static.wixstatic.com/media/a230cb_9fa46a6bb8fb4c36b5b4ee1434356d99~mv2.jpg', 'Orquestra Sinfónica AMCC (PT) 2024', 'https://static.wixstatic.com/media/a230cb_3e0bb909f9704a1c9cb0de3da7c0a168~mv2.jpg', 'Secção Metais BSP (PT) 2023', 'https://static.wixstatic.com/media/a230cb_fa89fac98e95495784bd31d4edf9eccb~mv2.jpg', 'Orquestra de Câmara de Cascais e Oeiras (PT) 2023', 'https://static.wixstatic.com/media/a230cb_f51d5d575fbb4d7d9fdd71a5b10b3a2b~mv2.jpg', 'Symphonic Orchestra of Pitesti Philharmonia (RO) 2023', 'https://static.wixstatic.com/media/a230cb_467d142d284e48c9a8320887d78b2471~mv2.jpg', 'PJM - Orquesta Metropolitana de Lisboa (PT) 2022', 'https://static.wixstatic.com/media/a230cb_3cbed37e8fb949cc9b8f6c5e13ce061d~mv2.jpg', 'PJM - Orquesta Sinfónica Portuguesa (PT) 2016', 'https://static.wixstatic.com/media/a230cb_2f884994359440339e474f626099f244~mv2.jpg', '(NL) Kerkrade WMC - Banda Musical de Arouca (PT) 2022', NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 38: Allex Aguilera
INSERT IGNORE INTO users (id, email, password, role) VALUES ('5ec14793-e0f6-4e82-b6ee-c708c5bee0df', 'wix-5ec14793@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('40fe64a9-40b1-4ec0-8dc1-96a0dd33acc5', '5ec14793-e0f6-4e82-b6ee-c708c5bee0df', 'allex-aguilera', 'Allex Aguilera', 'Allex', '999999999', '1981-07-02', 'Brasil', 'Espanha', 'Valencia', 'xxxx xxxx', NULL, '1800101', 'Encenador e Cenógrafo', '"O meu objetivo é levar o público a uma viagem emocional, transformando a vivência de ver uma ópera"', 'https://static.wixstatic.com/media/5ec147_7d85e8ba3e67438581348441f7fef5bc~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/5ec147_fce6bfb7ec6f47768affd8dc56004865.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=FWoytblwjUg&embeds_referring_euri=https%3A%2F%2Fnovaproartart.wixstudio.io%2F&embeds_referring_origin=https%3A%2F%2Fnovaproartart.wixstudio.io&feature=emb_imp_woyt', 'https://www.youtube.com/watch?v=4IciUNpt3-c&embeds_referring_euri=https%3A%2F%2Fnovaproartart.wixstudio.io%2F&embeds_referring_origin=https%3A%2F%2Fnovaproartart.wixstudio.io', 'https://www.youtube.com/watch?v=6pZ8zpyOR_g', 'https://www.youtube.com/watch?v=vMTMdoRpQdk', 'https://www.youtube.com/watch?v=XS9GIwUTH0Q', NULL, NULL, NULL, NULL, NULL, '<p class="font_8" style="text-align: justify">Aclamado como um <strong>visionário dos palcos operáticos</strong>, Allex Aguilera pertence ao círculo dos encenadores mais respeitados da atualidade, conhecido pelo seu trabalho ímpar que alia a <strong>sobriedade clássica à inovação cénica</strong>. As suas produções destacam-se pela <strong>cenografia conceptual e elegância estética</strong>, que as transformam em experiências de grande beleza e equilíbrio.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">A arte de Aguilera reside na habilidade de traduzir a essência dramática da ópera numa <strong>linguagem visual coesa e impactante</strong>. Valendo-se de cenários depurados, simbologias eloquentes e uma precisa direção de atores, confere uma nova dimensão às obras, transformando-as num "<strong>espetáculo total</strong>", como pretendiam os grandes compositores.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">A crítica louva as suas encenações, considerando-as <strong>pontos altos de felicidade lírica</strong>. Estas destacam-se pela coerência cromática e pelo cuidado meticuloso com os detalhes, realçando a subtileza e a expressividade dos artistas.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">"A coerência cromática, o simbolismo das paisagens ou a definição precisa das posições das personagens, elevadas através da iluminação a uma categoria icónica, são alguns dos êxitos do encenador Allex Aguilera." Gonzalo Roldán sobre a ópera "Tristão e Isolda"</p>', '<p style="text-align:justify">Nas produções de Allex Aguilera, a ópera é elevada a uma experiência catártica e emocionalmente arrebatadora.</p><p> </p><p style="text-align:justify">Allex Aguilera descobriu a sua <span style="font-weight:bold">paixão pela música clássica</span> ainda muito jovem, quando recebeu o seu primeiro leitor de cassetes e ficou fascinado ao ouvir a Dança Húngara No. 5 de Brahms. Essa experiência despertou a sua curiosidade, levando-o a explorar obras de grandes compositores como Beethoven e Mozart. Ao ouvir pela primeira vez a Nona Sinfonia de Beethoven, encantou-se especialmente com a parte coral, despertando o seu interesse pelo canto lírico.</p><p> </p><p style="text-align:justify">Nascido em São Paulo, Brasil, Aguilera mudou-se para a <span style="font-weight:bold">Suíça </span>aos 16 anos, motivado pelo desejo de conhecer novas realidades e aprimorar os seus conhecimentos linguísticos. Inicialmente foi estudar francês em Genebra, mas rapidamente se fascinou pelo mundo da ópera após conhecer um amigo estudante de canto no Conservatório local. Encorajado, Aguilera preparou-se e fez uma <span style="font-weight:bold">audição para o Conservatório</span>, surpreendendo-se ao ser aceite para <span style="font-weight:bold">estudar musicologia e canto lírico</span>.</p><p> </p><p style="text-align:justify">A transição para a carreira de encenador aconteceu em 1993, quando participou como figurante na ópera &quot;Boris Godunov&quot; no Grand Théâtre de Genève, para ter a oportunidade de ver o seu ídolo, Samuel Ramey. Fascinado pelos bastidores, percebeu que a sua <span style="font-weight:bold">vocação era trabalhar no teatro</span>, não como cantor. Iniciou-se, então, na <span style="font-weight:bold">direção de palco no Grand Théâtre de Genève</span>, aprendendo todos os aspetos da produção operística ao lado de grandes profissionais.</p><p> </p><p style="text-align:justify">Dois anos depois, em 1995, Aguilera mudou-se para Barcelona para <span style="font-weight:bold">estudar Direção Cinematográfica</span>, procurando expandir os seus horizontes culturais além do universo operístico. Embora tenha trabalhado no teatro de prosa dirigindo algumas peças, a ópera sempre o acompanhou, com trabalhos como <span style="font-weight:bold">assistente de encenação na Ópera Bastille e no Théâtre du Châtelet em Paris</span>.</p><p> </p><p style="text-align:justify">O regresso definitivo ao mundo da ópera ocorreu em 2005, quando foi convidado para integrar a <span style="font-weight:bold">equipa fundadora do Palau de les Arts Reina Sofia em Valência </span>como <span style="font-weight:bold">coordenador de produção e responsável pela direção de cena</span>. Ao implementar o modelo de gestão de palco que aprendeu em Paris, Aguilera consolidou a sua reputação, trabalhando com grandes nomes como <span style="font-weight:bold">Lorin Maazel</span>, <span style="font-weight:bold">Plácido Domingo</span> e <span style="font-weight:bold">Zubin Mehta</span>, entre outros.</p><p> </p><p style="text-align:justify">Desde então, a sua carreira como encenador de ópera ganhou impulso, com produções aclamadas como <span style="font-weight:bold">Turandot</span>, <span style="font-weight:bold">Tristão e Isolda</span>, <span style="font-weight:bold">Pagliacci</span>, <span style="font-weight:bold">Otello </span>e muitas outras em renomadas casas de ópera pelo mundo. Tendo colaborado com artistas de elite, Aguilera procura tornar a ópera mais acessível a todos os públicos, com projetos lúdicos e educativos.</p>', '<p style="text-align:justify">Allex Aguilera consolidou-se como <span style="font-weight:bold">um dos mais respeitados e prolíficos encenadores operísticos da atualidade</span>. Celebrado por produções aclamadas de obras-primas como &quot;<span style="font-weight:bold">Tristão e Isolda</span>&quot;, &quot;<span style="font-weight:bold">Otello</span>&quot;, &quot;<span style="font-weight:bold">Turandot</span>&quot; e &quot;<span style="font-weight:bold">Carmen</span>&quot;, alia uma visão arrojada à maestria na direção de cenários, movimentos e simbologias cénicas. As montagens cénicas ímpares, que capturam a essência dramática e transcendem o convencional, elevam Aguilera ao patamar dos grandes renovadores da linguagem operística contemporânea.</p><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p style="text-align:justify"> </p><p><span style="font-weight:bold">2024 </span>- Encenou a ópera &quot;Felizmente Há Luar!&quot; em Lisboa; &quot;I Capuleti e I Montecchi&quot; na Opéra Royal de Wallonie; &quot;Otello&quot; no Teatro dell&#x27;Opera di Roma; e desenha a iluminação para Salome no Palau de la Música.</p><p style="text-align:justify"><span style="font-weight:bold">2023 </span>- Encenou nova produção de Tristão e Isolda no Teatro da Maestranza, Sevilha.</p><p style="text-align:justify"><span style="font-weight:bold">2022 </span>- Encenou Tosca em L&#x27;Eliana, Espanha.</p><p style="text-align:justify"><span style="font-weight:bold">2019 </span>- Encenou &quot;Otello&quot; na Ópera de Monte Carlo; &quot;La Favorite&quot; no Teatro Massimo de Palermo; e o espetáculo &quot;The Opera Scientist&quot; com a ABAO Bilbao.</p><p style="text-align:justify"><span style="font-weight:bold">2018 </span>- Encenou &quot;La Clemenza di Tito&quot; no Palau de les Arts; e Turandot (reposição) no Palau.</p><p style="text-align:justify"><span style="font-weight:bold">2017 </span>- Encenou &quot;O Navio Fantasma&quot; em Valência; e &quot;La Traviata&quot; em Andorra.</p><p style="text-align:justify"><span style="font-weight:bold">2015 </span>- Encenou &quot;Pagliacci&quot; em Monte Carlo; &quot;Lucia di Lammermoor&quot; em Lima; e &quot;Don Giovanni&quot; em Trieste.</p><p style="text-align:justify"><span style="font-weight:bold">2014 </span>- Encenou e assinou a cenografia de &quot;Carmen&quot; no Teatro Municipal do Rio. Dirige &quot;Turandot&quot; com Mehta em Valência.</p><p style="text-align:justify"><span style="font-weight:bold">2013 </span>- Encenou &quot;Otello&quot; em Gênova; e &quot;Die Walküre&quot; com Zubin Mehta em Valência.</p><p style="text-align:justify"><span style="font-weight:bold">2012 </span>- Encenou &quot;Tosca&quot; com Plácido Domingo. Cria o espetáculo musical &quot;Opérame&quot; com José Manuel Zapata em Valência. Encena a nova produção de &quot;Tristão e Isolda&quot; com Zubin Mehta.</p><p style="text-align:justify"><span style="font-weight:bold">2011-2012</span> - Encenou &quot;Die Walküre e Siegfried&quot; de Wagner com La Fura dels Baus em Sevilha.</p><p style="text-align:justify"><span style="font-weight:bold">2010 </span>- Encenou a nova produção de &quot;Yerma&quot; de Villa-Lobos no Festival de Manaus.</p><p style="text-align:justify"><span style="font-weight:bold">2009 </span>- Encenou &quot;Turandot&quot; no Festival de Ópera de A Coruña e na Ópera de Monte Carlo; e &quot;Die Walküre&quot; de Wagner com Plácido Domingo e Zubin Mehta, transmitida ao vivo. Colabora na encenação de &quot;Les Troyens de Berlioz&quot; com La Fura dels Baus e Valery Gergiev.</p><p style="text-align:justify"><span style="font-weight:bold">2008 </span>- Encenou &quot;Turandot&quot; de Puccini com produção de Chen Kaige e Maazel.</p><p style="text-align:justify"><span style="font-weight:bold">2007 </span>- Encenou &quot;Madama Butterfly&quot; de Puccini com direção musical de Lorin Maazel.</p><p style="text-align:justify"><span style="font-weight:bold">2005-2022</span> - Em 2005, foi convidado para o Palau de les Arts Reina Sofía em Valência como coordenador de produção e responsável pela direção de cena. Esteve associado a este projeto como encenador até 2022.</p><p style="text-align:justify"><span style="font-weight:bold">2003-2005</span> - Trabalhou como assistente de encenação na Opéra National de Paris em óperas como &quot;Guillaume Tell&quot;, &quot;Le Nozze di Figaro&quot;, &quot;Die Fledermaus&quot;, entre outras. Também no Théâtre du Châtelet em &quot;La Grande Duchesse de Gerolstein&quot;.</p><p style="text-align:justify"><span style="font-weight:bold">2002 </span>- Dirigiu a peça &quot;Gaviotas Subterráneas&quot; de A. Vallejo no Teatro Can Felipa e Sala Beckett, Barcelona.</p><p style="text-align:justify"><span style="font-weight:bold">2001 </span>- Trabalhou como assistente de direção no filme operístico &quot;Amahl and the Night Visitors&quot; da BBC, dirigido por Francesca Zambello.</p><p style="text-align:justify"><span style="font-weight:bold">2000 </span>- Estudou língua e literatura alemã no Goethe Institut Berlin. Dirige a peça &quot;Torrijas de Cerdo&quot; no Teatro Llantiol, Barcelona.</p><p style="text-align:justify"><span style="font-weight:bold">1995-1998</span> - Estudou Direção Cinematográfica no CECC.</p><p style="text-align:justify"><span style="font-weight:bold">1995 </span>- Mudou-se para Barcelona, Espanha.</p><p style="text-align:justify">Até 1995 - Estudou canto lírico e musicologia no Conservatório de Música de Genebra. Trabalha como encenador e assistente de direção no Grand Théâtre de Genève.</p><p style="text-align:justify">Década de 1980 - Mudou-se do Brasil para Genebra, Suíça, para estudar francês.</p><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">ENCENAÇÕES DE ÓPERAS</span></h3><h3> </h3><ul><li style="text-align:justify">&quot;Otello&quot; de Verdi - 2024</li><li style="text-align:justify">&quot;I Capuleti e I Montecchi&quot; de Bellini - 2024</li><li style="text-align:justify">&quot;Felizmente Há Luar&quot; (prod. Orquestra Filarmónica Portuguesa e ProART) - 2024</li><li style="text-align:justify">&quot;Salome&quot; de Strauss - iluminação - 2024</li><li style="text-align:justify">&quot;Tristão e Isolda&quot; de Wagner - 2023</li><li style="text-align:justify">&quot;Tosca&quot; de Puccini - 2022</li><li style="text-align:justify">&quot;The Opera Scientist&quot; (várias peças) - 2019</li><li style="text-align:justify">&quot;Otello&quot; de Verdi - 2019</li><li style="text-align:justify">&quot;La Favorite&quot; de Donizetti - 2019</li><li style="text-align:justify">&quot;I Masnadieri&quot; de Verdi - iluminação - 2019</li><li style="text-align:justify">&quot;Turandot&quot; de Puccini - 2018, 2014, 2009, 2008</li><li style="text-align:justify">&quot;O Navio Fantasma&quot; de Wagner - 2017</li><li style="text-align:justify">&quot;Don Giovanni&quot; de Mozart - 2015</li><li style="text-align:justify">&quot;Lucia di Lammermoor&quot; de Donizetti - 2015</li><li style="text-align:justify">&quot;Carmen&quot; de Bizet - 2014</li><li style="text-align:justify">&quot;Siegfried&quot; de Wagner - 2012</li><li style="text-align:justify">&quot;Tristão e Isolda&quot; de Wagner - 2012</li><li style="text-align:justify">&quot;A Valquíria&quot; de Wagner - 2013, 2011</li><li style="text-align:justify">&quot;Yerma&quot; de Villa-Lobos - 2010</li><li style="text-align:justify">&quot;Les Troyens&quot; de Berlioz - assistente - 2009</li><li style="text-align:justify">&quot;Die Walküre&quot; de Wagner - prod. La Fura dels Baus - 2009</li><li style="text-align:justify">&quot;Madama Butterfly&quot; de Puccini - 2007</li><li style="text-align:justify">&quot;Tosca&quot; de Puccini - 2012</li><li style="text-align:justify">&quot;La Vida Breve&quot; de Falla - 2012</li><li style="text-align:justify">&quot;Fidelio&quot; de Beethoven - 2006</li><li style="text-align:justify">Peças/Musicais&quot;Torrijas de cerdo&quot; - Teatro Llantiol, Barcelona - 2000<br/>&quot;Gaviotas Subterráneas&quot; de A. Vallejo - Barcelona - 2002<br/>&quot;Opérame&quot; com J.M. Zapata, Valência - 2012, 2013</li></ul><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">COLABORAÇÕES</span></h3><h3> </h3><ul><li>Com Robert Lepage, Daniel Schmid, Robert Carsen, Benno Besson e Francesca Zambello como assistente de direção no Grand Théâtre de Genève (1993-1995)</li><li style="text-align:justify">Com Francesca Zambello como assistente de direção no filme operístico &quot;Amahl and the Night Visitors&quot; para a BBC (2001)</li><li style="text-align:justify">Com Laurent Pelly na ópera &quot;La Grande Duchesse de Gerolstein&quot; no Théâtre du Châtelet, Paris (2003-2005)</li><li style="text-align:justify">Com Carlos Saura na ópera &quot;Carmen&quot; no Palau de les Arts (2005+)</li><li style="text-align:justify">Com Chen Kaige na ópera &quot;Turandot&quot; no Palau de les Arts (2008)</li><li style="text-align:justify">Com Werner Herzog na ópera &quot;Parsifal&quot; no Palau de les Arts (2005+)</li><li style="text-align:justify">Com La Fura dels Baus nas óperas:&quot;Die Walküre&quot; com Plácido Domingo (2009)<br/>&quot;Les Troyens&quot; com Valery Gergiev (2009)<br/>&quot;Die Walküre&quot; e &quot;Siegfried&quot; em Sevilha (2011-2012)</li><li style="text-align:justify">Com Zubin Mehta nas óperas:&quot;Die Walküre&quot; com transmissão ao vivo (2009)<br/>&quot;Tristão e Isolda&quot; (2012)<br/>&quot;Die Walküre&quot; (2013)<br/>&quot;Turandot&quot; (2014, 2018)</li><li style="text-align:justify">Com o &quot;Centre de Perfeccionament Plácido Domingo&quot; em Valência</li></ul>', '<h3 style="text-align:justify"><span style="font-weight:bold">CRÍTICAS</span></h3><h3> </h3><p style="text-align:justify"><span style="font-weight:bold">TRISTÃO E ISOLDA, R. Wagner</span></p><p style="text-align:justify">Teatro de la Maestranza</p><p style="text-align:justify">A produção própria, dirigida pelo brasileiro Allex Aguilera com uma excelente equipa composta por Jesús Ruiz no design de vestuário, Luis Perdiguero no design de iluminação, e Arnaud Pottier no design de vídeo, foi um sucesso retumbante. Optou-se pela sobriedade, seriedade e coerência. Recorreu-se a vídeos bem dosados para dar mais vida às cenas. O vestuário criativo e a iluminação cuidada conseguem que tudo o que acontece no palco e na orquestra se funda nesse espetáculo total que o compositor pretendia.</p><p style="text-align:justify">Jacobo Cortines, Scherzo</p><p> </p><p style="text-align:justify"><span style="font-weight:bold">LA FAVORITE, G. Donizetti</span></p><p style="text-align:justify">Teatro Massimo di Palermo</p><p style="text-align:justify">Allex Aguilera dirigiu a peça e provou que sabe trabalhar com o coro, algo que no “Regietheater” é muito raro. Ele também guiou os protagonistas de forma competente e segura através da ação.</p><p style="text-align:justify">Elena Habermann, Online Merker</p><p> </p><p style="text-align:justify"><span style="font-weight:bold">OTELLO, G. Verdi</span></p><p style="text-align:justify">Opéra de Monte-Carlo</p><p style="text-align:justify">A engenhosa encenação de Allex Aguilera aumenta a densidade dramática enquanto dedica uma forma de unidade de lugar que se adapta perfeitamente a este discurso musical contínuo onde já nada separa os recitativos das árias.</p><p style="text-align:justify">Jean-Luc Vannier, <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=http://musicologie.org/ target=_self>Musicologie.org</a></span></span></p><p> </p><p style="text-align:justify"><span style="font-weight:bold">LA CLEMENZA DI TITO, W. A. Mozart</span></p><p style="text-align:justify">Palau de Les Arts</p><p style="text-align:justify">Uma reivindicação do detalhe e da medida, daquilo que dizia o grande Walter Felsenstein de que o “movimento do dedo mindinho de um cantor pode ter mais força em cena que mil acrobacias e efeitos”.</p><p style="text-align:justify">Justo Romero, Beckmesser</p><p> </p><p style="text-align:justify"><span style="font-weight:bold">PAGLIACCI, R. Leoncavallo</span></p><p style="text-align:justify">Opéra de Monte-Carlo</p><p style="text-align:justify">Resultado teatral ainda mais surpreendente para Pagliacci, que a iluminada direção de Allex Aguilera [...] Tudo isto é realizado com uma precisão direcional portentosa, onde cada gesto, estudado até ao mínimo detalhe, envolve e galvaniza cada intérprete num perfeito mix de cómico e trágico.</p><p style="text-align:justify">Alessandro Mormile, L´Opera</p><p> </p><p style="text-align:justify"><span style="font-weight:bold">YERMA, H. Villalobos</span></p><p style="text-align:justify">Ópera de Manaus</p><p style="text-align:justify">A montagem de «Yerma», sob a responsabilidade de Allex Aguilera, associou balé à conceção cénica de maneira arriscada. Um casal de bailarinos representava também, junto com os cantores, o casal protagonista. Havia, portanto, duas Yermas, dois Juans, um par que canta, outro que dança. Tal solução permitiu harmonizar a dualidade entre realismo e símbolo, própria ao texto de Lorca. Com os cantores, o desespero se arranca do ventre com violência. Com os bailarinos, ele se espiritualiza. O resultado de tudo isso junto, música, dança, canto, drama, brilharia em qualquer grande teatro do planeta.</p><p style="text-align:justify">Jorge Coli, Folha de São Paulo</p><p> </p><p style="text-align:justify"><span style="font-weight:bold">OTELLO, G. Verdi</span></p><p style="text-align:justify">Um cume de felicidade lírica (...) parecia impossível fazer algo mais extraordinário em termos de produção lírica. No entanto, é isso que acontece com o &quot;Otello&quot; de Verdi apresentado desde domingo. Aqui está a apoteose da temporada. Atinge-se um cume de felicidade lírica. Na história do Salle Garnier, falar-se-á do &quot;Otello de 2019&quot;. (...) A encenação de Alex Aguilera, de um classicismo muito apreciado, não é menos refinada e detalhada. Situa-se em dois níveis, utilizando em altura uma passarela entre dois pisos do palácio. Coloca-nos fogo no primeiro ato, acendendo um verdadeiro incêndio no centro do palco. Transforma a tradicional cama de morte de Desdémona numa piscina, trazendo o poder purificador da água que salpica a personagem.</p><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">NOTÍCIAS e ENTREVISTAS</span></h3><p> </p><p style="text-align:justify"><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/allex_aguilera target=_blank>ProART Entrevista</a></span></span> </span>- Allex Aguilera - A beleza e o equilíbrio na ópera contemporânea</p><p style="text-align:justify"><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://operawire.com/teatro-sao-luiz-2024-felizmente-ha-luar/?fbclid=IwZXh0bgNhZW0CMTEAAR18YwQ6e9-YAbCJ-4v_h5q2evMu-Zlg_2JlLP_-Srq1YFEdr7etCdgRAvo_aem_AZbyLoMPaCFDrbJBE0CI-JwRo75mHQReNeqFvkrWKRUuwaCuvkW6z5qt9UkNJ4TUy6ty7DvrLb9RMGis4fzShh8h#google_vignette target=_blank>Opera Wire (2024)</a></span></span></span> - Teatro São Luiz 2024: Felizmente Há Luar [crítica de Ching Chang]</p><p style="text-align:justify"><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.publico.pt/2024/05/12/culturaipsilon/critica/felizmente-ha-luar-teatro-opera-2090124 target=_blank>Público (2024) </a></span></span></span>- Felizmente há luar! — do teatro à ópera [crítica de Manuel Pedro Ferreira]</p><p style="text-align:justify"><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.operaworld.es/entrevista-al-director-de-escena-allex-aguilera/ target=_blank>Opera World (2024)</a></span></span></span> - Entrevista al director de escena Allex Aguilera</p><p style="text-align:justify"><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.premiereloge-opera.com/artiste/2024/01/26/allex-aguilera-metteur-en-scene-biographie-projets/ target=_blank>Première Loge (2024)</a></span></span></span> - Allex AGUILERA, diretor</p>', 'https://static.wixstatic.com/media/3a4106_f8ebc22524b941208ee4819e4d0198a0~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 39: Reisen Trio
INSERT IGNORE INTO users (id, email, password, role) VALUES ('cdd94f53-5f6a-41a9-8e81-0a3f85f80f48', 'wix-cdd94f53@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('1838255d-0beb-4c47-a7d6-79e9088817d8', 'cdd94f53-5f6a-41a9-8e81-0a3f85f80f48', 'reisen-trio', 'Reisen Trio', 'Reisen Trio', '931713746', '2021-03-17', 'Portugal', 'Portugal', 'Oliveira de Azeméis', 'Rua Padre Joaquim Aguiar nº 626, 3720-012 Carregosa', 'Rua Padre Joaquim Aguiar nº 626, 3720-012 Carregosa', '3720-012', 'Trio de Canto, Piano e Clarinete', 'Nas notas de uma composição musical, encontramos o ritmo da vida, a tensão do conflito e a beleza da superação.', 'https://static.wixstatic.com/media/cdd94f_6477a7828f354f70aff768655522505b~mv2.jpg', 'wix:document://v1/cdd94f_5b3c3722f1334b5d93bbfe7044e3ee42.pdf/bibliografia.pdf', 'https://www.facebook.com/profile.php?id=100089704641867', NULL, NULL, NULL, 'https://www.youtube.com/@trioreisen-yk7dq', 'https://static.wixstatic.com/mp3/cdd94f_ec780bf79fb8483aaaa2b2831c304a1d.m4a', NULL, NULL, 'https://www.youtube.com/watch?v=-vit8ErCS8c', 'https://www.youtube.com/watch?v=ADpYvsZSjy4', 'https://www.youtube.com/watch?v=wg1fbemmYDo', 'https://www.youtube.com/watch?v=-vit8ErCS8c', 'https://www.youtube.com/watch?v=ADpYvsZSjy4', 'https://www.youtube.com/watch?v=wg1fbemmYDo', 'https://www.youtube.com/watch?v=-vit8ErCS8c', NULL, NULL, NULL, '<p class="font_8" style="text-align: justify">O <strong>Reisen Trio</strong>, formado em 2021, rapidamente se destacou no cenário musical português pela sua formação única, composta por clarinete, voz e piano. A estreia do grupo, realizada com casa cheia, marcou o início de uma carreira promissora, evidenciando a capacidade do trio de atrair e cativar o público com uma sonoridade diferenciada e cativante.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Composto por Tiago Oliveira (clarinete), Marta Magalhães (voz) e Sofia Rodrigues (piano), todos músicos com uma carreira individual de sucesso e reconhecidos por prémios nacionais e internacionais, o Reisen Trio traz uma combinação instrumental e vocal que, embora rara, tem raízes históricas significativas. A dedicação do grupo em explorar essa formação pouco conhecida reflete o seu compromisso com a inovação e a revitalização de repertórios esquecidos.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">O Reisen Trio também é conhecido pelas estreias de obras de compositores renomados, como Fernando Lopes Graça e Alberto Caeiro, que confiaram ao grupo a primeira execução das suas composições. Este aspecto do trabalho do trio destaca a sua capacidade de interpretar tanto o repertório clássico quanto de contribuir para a evolução da música contemporânea.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Atuando em palcos variados, desde pequenas salas de concerto até os grandes palcos internacionais, o Reisen Trio tem como missão levar a sua música a um público diversificado. A combinação de talento individual, inovação e respeito pela tradição faz do grupo uma presença singular e indispensável no panorama musical atual.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">"A combinação de virtuosismo e sensibilidade artística do Reisen Trio transforma cada performance numa experiência única e inesquecível."</p>
<p class="font_8">&nbsp;</p>', NULL, NULL, NULL, 'https://static.wixstatic.com/media/cdd94f_9dae684b1011498fab3c51e187511904~mv2.jpg', 'Reisen Trio', 'https://static.wixstatic.com/media/cdd94f_48427954b39d4f8497edf6f8931d77b3~mv2.jpg', 'Momentos antes', 'https://static.wixstatic.com/media/cdd94f_83d3dd976da84133a7e86f7446124169~mv2.jpg', 'Tiago Oliveira', 'https://static.wixstatic.com/media/cdd94f_05fcf0785b3e4b1e8ec5ab124dbe167e~mv2.jpg', 'Marta Magalhães', 'https://static.wixstatic.com/media/cdd94f_604a98b54ee744d1887bb5a7a9ae3428~mv2.jpg', 'Sofia Rodrigues', 'https://static.wixstatic.com/media/cdd94f_f98dfe6d2c894d64803018f3586b9482~mv2.jpg', 'Respira', 'https://static.wixstatic.com/media/cdd94f_c71677d23a214ff89398a4492d817c09~mv2.jpg', 'Encore', 'https://static.wixstatic.com/media/cdd94f_88e79052bf374e668433a725bd6e9858~mv2.jpg', 'Memorável', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 40: Mariana Fernandes
INSERT IGNORE INTO users (id, email, password, role) VALUES ('8366d9a4-b2ef-4a63-a8f5-c7c772f509ac', 'wix-8366d9a4@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('3090193d-69a0-415a-85ee-8f78ecd7ba09', '8366d9a4-b2ef-4a63-a8f5-c7c772f509ac', 'Mariana-fernandes', 'Mariana Fernandes', 'Mariana', '''+4407402136065', NULL, 'Portugal', 'United Kingdom', 'Lewes', 'Gibson Court', '60 Spences Lane', 'BN7 2HE', 'Soprano', '"Cantar é a forma mais honesta e poderosa que conheço de me exprimir e de me ligar aos outros."', 'https://static.wixstatic.com/media/8366d9_0176d0f16fe24d029ee07645b86d2b62~mv2.jpg', NULL, 'https://www.facebook.com/marianafernandes.soprano', 'https://www.instagram.com/marianafernandes.soprano/', 'https://www.mariana-fernandes.com', NULL, NULL, NULL, NULL, NULL, 'https://youtu.be/CRueckXpKXc', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8" style="text-align: justify">No início da sua carreira, <strong>Mariana Fernandes</strong> já se afigura como uma das vozes mais promissoras do panorama lírico atual. Com um talento vocal deslumbrante, uma técnica impecável e uma presença cénica carismática, tem vindo a acumular distinções em competições de prestígio e a brilhar em papéis exigentes, deixando antever uma carreira fulgurante nos principais palcos líricos mundiais.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">O seu talento excecional foi recentemente reconhecido com o Prémio Susan Longfield de 2024 e a sua participação como finalista nos renomados 69º Prémios Kathleen Ferrier.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Com um repertório que abrange papéis líricos e lírico-spinto de Mozart a Puccini, incluindo Mimì, Micaëla e Donna Anna, Mariana revela uma voz versátil e expressiva, capaz de transitar com elegância entre o lirismo delicado e a intensidade dramática. A sua capacidade de interpretar obras contemporâneas, como demonstrado na sua atuação em "Jeremy Fisher", realça ainda mais a sua flexibilidade vocal e artística.</p>', '<p style="text-align:justify"><span style="font-weight:bold">Mariana Fernandes</span> começou a cantar ainda antes de começar a andar. Com um talento precoce, começou a estudar música com quatro anos na Academia de Música de Almada. Escolheu o piano como instrumento, mas a sua paixão sempre foi o canto.</p><p style="text-align:justify">Com oito anos, juntou-se ao recém-criado <span style="font-weight:bold">Coro Infantil da Universidade de Lisboa</span>, e descobriu a paixão pela performance. A partir dai, soube que o seu lugar era em cima do palco, onde se sente verdadeiramente em casa. Fez várias digressões pela Europa e acumulou anos de experiência em repertório coral, em várias línguas.</p><p style="text-align:justify"> </p><p style="text-align:justify">Decidida a fazer do canto a sua profissão, a partir dos 14 anos, prosseguiu os seus estudos musicais no <span style="font-weight:bold">Conservatório de Lisboa</span>, onde fez o curso integrado em canto. Terminada essa etapa, inscreveu-se no Taster Course da reputada <span style="font-weight:bold">Guildhall School of Music &amp; Drama (GSMD)</span>, onde conheceu a sua atual professora de canto – a aclamada <span style="font-weight:bold">Marilyn Rees</span>. Depois de prestar provas e de ter sido aceite, fez a sua formação superior nesta escola, incluindo um Master em Performance e um Artist Diploma, entre 2016 e 2022. Em 2023 passou a integrar o Opera Course na mesma instituição, sob a tutela de Marilyn Rees.</p><p style="text-align:justify"> </p><p style="text-align:justify">Mariana Fernandes tem construído um impressionante repertório operático, destacando-se recentemente em papéis principais como Mimì em &quot;La Bohème&quot; e Micaela em &quot;Carmen&quot; na GSMD em 2023. A sua versatilidade vocal é evidente em performances marcantes como Donna Anna em &quot;Don Giovanni&quot; e Leonora em &quot;Fidelio&quot;.</p><p style="text-align:justify"> </p><p style="text-align:justify">Em julho de 2023, Mariana expandiu seu repertório verista com participações em &quot;Cavalleria Rusticana&quot; de Mascagni e &quot;Pagliacci&quot; de Leoncavallo na West Green House Opera. Além de seu trabalho em óperas clássicas, também já demonstrou a sua adaptabilidade ao estrear-se como Jody em &quot;Jeremy Fisher&quot; no OperaFest Lisboa 2022. Complementando sua experiência operática, Mariana tem participado em recitais prestigiosos e performances corais, incluindo apresentações no LSO St. Luke&#x27;s e no Barbican Centre, abrangendo um repertório diversificado que vai do barroco ao contemporâneo.</p>', '<p>A soprano portuguesa Mariana Fernandes destaca-se pela sua versatilidade, presença cênica e profundidade expressiva. Formada pela Guildhall School of Music &amp; Drama, onde concluiu o <span style="font-style:italic">Master of Performance</span> com Distinção, é atualmente <span style="font-style:italic">Jerwood Young Artist</span> na Glyndebourne Festival Opera (2025), participando no festival em <span style="font-style:italic">Parsifal</span>, <span style="font-style:italic">Saul</span>, <span style="font-style:italic">Falstaff</span> e <span style="font-style:italic">Kat’a Kabanova</span>, e cobrindo o papel de Helena em <span style="font-style:italic">A Midsummer Night’s Dream </span>no Autumn Festival.</p><p> </p><p>Vencedora do <span style="font-weight:bold">Susan Longfield Award</span> e do <span style="font-weight:bold">Worshipful Company of Chartered Surveyors Vocal Prize (2024)</span>, foi também finalista do <span style="font-weight:bold">69th Kathleen Ferrier Awards</span>, do <span style="font-weight:bold">Concurso Internacional de Canto Lírico de Lousada</span> e do <span style="font-weight:bold">Concurso de Canto Fundação Rotária Portuguesa</span>.</p><p> </p><p>O seu repertório inclui papéis como <span style="font-weight:bold">Magda</span>, <span style="font-weight:bold">Arabella</span>, <span style="font-weight:bold">Tatyana</span>, <span style="font-weight:bold">Leonora</span>, <span style="font-weight:bold">Micaëla</span>, <span style="font-weight:bold">Fiordiligi</span>, <span style="font-weight:bold">Donna Anna</span>, <span style="font-weight:bold">Contessa Almaviva</span>, <span style="font-weight:bold">Erste Dame</span>, <span style="font-weight:bold">Suor Angelica</span>, <span style="font-weight:bold">Mimì</span> e <span style="font-weight:bold">Nedda</span>, destacando-se pela expressividade e elegância vocal.</p><p> </p><p><span style="font-weight:bold">Prémios e Reconhecimentos</span></p><p>·  Vencedora do 2024 Susan Longfield Award (GSMD, 2024)</p><p>·  Vencedora do 2024 Worshipful Company of Chartered Surveyors Vocal Prize (GSMD, 2024)</p><p>·  Finalista no 69th Kathleen Ferrier Awards (Wigmore Hall, 2024)</p><p>·  Finalista no Concurso Internacional de Canto Lírico de Lousada (Lousada, 2022and 2024)</p><p>·  Finalista do 13º Concurso de Canto Lírico Fundação Rotária Portuguesa (Centro Cultural de Belém, 2023)</p><p> </p><p><span style="font-weight:bold">Educação</span></p><p>Opera Course – GSMD (2023-2025)</p><p>Artist Diploma – GSMD (2022-2023)</p><p>Guildhall Artist Master’s – Performance, GSMD (2020-2022)</p><p>BA (Hons) – Classical (Vocal Studies), GSMD (2016-2020)</p>', '<p><span style="font-weight:bold">Opera</span></p><p>Helena - cover (A Midsummer Night&#x27;s Dream, Glyndebourne 2025)</p><p>Aunt Norris (Mansfield Park, GSMD 2025)</p><p>Rosalinde (Die Fledermaus, GSMD 2024)</p><p>Magda (La Rondine, GSMD 2024)*</p><p>Suor Dolcina (Suor Angelica, West Green House Opera 2024)</p><p>Arabella (Arabella, GSMD 2024)*</p><p>Donna Anna (Don Giovanni, GSMD 2020, 2021 &amp; 2024)*</p><p>Tatyana (Eugene Onegin, GSMD 2024)*</p><p>Lia (L’enfant prodigue, GSMD 2023)*</p><p>Nedda (I Pagliacci, West Green House Opera 2023)*</p><p>Mimì (La Bohème, GSMD 2023)*</p><p>Micaela (Carmen, GSMD 2023)*</p><p>Jody (Jeremy Fisher, OperaFest Lisboa 2022)</p><p>Suor Angelica (Suor Angelica, GSMD 2021)*</p><p>Leonora (Fidelio, GSMD 2021)*</p><p>Sandman (Hansel und Gretel, GSMD 2021)*</p><p>Erste Dame (Die Zauberflöte, GSMD 2021)*</p><p>Contessa Almaviva (The Marriage of Figaro, GSMD 2019)</p><p>Chorus (Cendrillon by P. Viardot, GSMD 2021)</p><p>Chorus (La fedeltà premiata by Haydn, GSMD 2019)</p><p>Extra (Radamisto by G. F. Handel, GSMD 2017)</p><p> </p><p><span style="font-weight:bold">Recital</span></p><p>Songs of an Immigrant (GSMD, London 2023)</p><p>Creative Minds (GSMD, London 2023)</p><p>LSO Discovery Friday Lunchtime Concert (LSO St. Luke’s, London 2022)</p><p>Říkadla by L. Janáček LSO Discovery Day (LSO St. Luke’s, London 2019)</p><p>Winners’ recital of the GDA scholarship (Museu da Música, Lisbon 2017)</p><p> </p><p><span style="font-weight:bold">Coro</span></p><p>Gurrelieder by A. Schoenberg (Basilique de Saint Denis and Royal Festival Hall,</p><p>conducted by Esa-Pekka Salonen, GSMD, 2018)</p><p>Belshazzar&#x27;s Feast by W. Walton (Barbican Centre, conducted by Adrian Leaper, GSMD, 2016)</p><p>Joan d’Arc au bûcher by A. Honegger (Fundação Calouste Gulbenkian, conducted by SimoneYoung, 2012)</p><p>St. Matthew’s Passion by J. S. Bach (Centro Cultural de Belém, 2007)</p>', 'https://static.wixstatic.com/media/8366d9_fcb1439279124b398acdfcfc8448c001~mv2.jpg', NULL, 'https://static.wixstatic.com/media/8366d9_26cd21975b4f4578824a87fe3fa7e635~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/8366d9_d3d4cd76fa3d4e219850dd0d7aaca30e~mv2.jpg', NULL, 'https://static.wixstatic.com/media/8366d9_d12b538609ce489eb99915c0d627e821~mv2.jpg', NU