INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('d5257d6c-25f7-4fce-b433-6e989214d03c', 'd429ea68-bf79-4f0c-a1b3-31d578765abb', 'leonardo-hilsdorf', 'Leonardo Hilsdorf', 'Leonardo', '935520999', '1987-12-26', 'Brazil', 'Portugal', 'Lisboa', 'Av Conde de Valbom 83', NULL, '1050067', 'Pianista', 'Vejo a música como importante ferramenta de transformação universal, social e individual.
"A beleza salvará o mundo."
Dostoiévski', 'https://static.wixstatic.com/media/7b859e_1c98ad1f252e43f6942fb04a25053ad4~mv2.jpg', 'wix:document://v1/d429ea_15d10b48b995484382bed9169cf2deaf.docx/BioCvPt24.docx', 'https://www.facebook.com/leonardo.hilsdorf/', 'https://www.instagram.com/leonardo_hilsdorf/', NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/d429ea_5c73ff79469244ce9e4a82c54139bb3c.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=w_Mk9t65Dms', 'https://www.youtube.com/watch?v=jGdwoO7GGlg', 'https://www.youtube.com/watch?v=w4Th-UzG5Vk', 'https://www.youtube.com/watch?v=CD1gi4oYEiw', 'https://www.youtube.com/watch?v=JvM0UVH2FYE', 'https://www.youtube.com/watch?v=W9-DsmSc7LY', 'https://www.youtube.com/watch?v=T-8xWCJceX4', 'https://www.youtube.com/watch?v=w_Mk9t65Dms', 'https://www.youtube.com/watch?v=jGdwoO7GGlg', 'https://www.youtube.com/watch?v=w4Th-UzG5Vk', '<p style="text-align:justify"><span style="font-weight:bold">Leonardo Hilsdorf</span> é um pianista brasileiro de excelência que tem vindo a ganhar reconhecimento no cenário musical internacional. Como um dos principais expoentes da nova geração de pianistas brasileiros, tem-se apresentado no Brasil, Estados Unidos, Ásia e Europa, recebendo elogios da crítica especializada pelas suas virtuosas performances.</p><p> </p><p style="text-align:justify">Hilsdorf foi um dos solistas em residência na Capela Musical Rainha Elisabeth da Bélgica, onde trabalhou sob a orientação da pianista Maria João Pires. Foi também premiado em diversos concursos internacionais na Alemanha, França, Itália, Espanha, Portugal, México e Brasil, incluindo o prémio especial da União Europeia de Concursos para Juventude, em San Sebastian, Espanha.</p><p> </p><p style="text-align:justify">O pianista já se apresentou em importantes salas de concerto, como o Concertgebouw de Amesterdão, Flagey e Bozar em Bruxelas, Maison de la Radio em Paris e BeethovenHaus em Bona, além de destacadas salas no Brasil. Hilsdorf também já tocou com orquestras de renome, como a Orquestra Filarmónica da Rádio France, Orquestra Real de Wallonie e todas as principais orquestras brasileiras. Com uma sólida formação musical que incluiu estudos em instituições conceituadas no Brasil, Estados Unidos, França e Alemanha, Leonardo Hilsdorf é um artista que continua a aprimorar a sua arte.</p><p> </p><p style="text-align:justify">Atualmente a residir em Lisboa, concilia atividades artísticas, pedagógicas e de investigação na Universidade Católica, contribuindo para o fomento e desenvolvimento da música clássica.</p>', '<p style="text-align:justify">A história de <span style="font-weight:bold">Leonardo Hilsdorf</span> com a música começou cedo. Ainda bebé, a sua maior incentivadora, a avó materna, conta que ele batia e explorava os ritmos e sons nas panelas da cozinha enquanto ela preparava as refeições. Já criança, enquanto o seu pai, o médico José Roberto, atendia os pacientes no hospital onde trabalhava, Leonardo e o seu irmão ficavam no carro a ouvir sinfonias de Beethoven. Essas experiências iniciais com a música clássica plantaram a semente de uma paixão que cresceria ao longo dos anos.</p><p style="text-align:justify"> </p><p style="text-align:justify">Hilsdorf iniciou os seus estudos de piano na Universidade de São Paulo, no Brasil, onde o seu talento e dedicação logo se destacaram. Procurando aprimorar ainda mais a sua técnica, mudou-se para os Estados Unidos, onde concluiu o mestrado em Performance no renomado New England Conservatory de Boston, estudando com Wha Kyung Byun e Russell Sherman. Obteve a nota máxima e honras académicas. A trajetória de Hilsdorf levou-o em seguida para a Europa. Em Paris, obteve um diploma de Concertista pela prestigiada École Normale de Paris. Depois, na Alemanha, concluiu um segundo mestrado em performance na Escola Superior de Música de Colónia, sob a tutela do eminente professor Claudio Martinez Mehner.</p><p style="text-align:justify"> </p><p style="text-align:justify">Um ponto de viragem na carreira do pianista foi a sua residência na Chapelle Musicale Reine Elisabeth na Bélgica. Durante dois anos, foi um dos poucos solistas selecionados para trabalhar com a lendária pianista Maria João Pires, que se tornou a sua mentora. Essa experiência lapidou ainda mais os seus ouvidos e abriu as portas para novas oportunidades.</p><p style="text-align:justify"> </p><p style="text-align:justify">Ao longo da sua trajetória, Leonardo Hilsdorf colecionou vitórias em concursos internacionais de piano na Alemanha, França, Itália, Espanha, Portugal, México e Brasil. Esses triunfos não apenas confirmaram o seu talento, mas também impulsionaram a sua carreira, levando-o a apresentar-se em algumas das salas de concerto mais prestigiadas do mundo. Entre eles, obteve o prestigiado prémio Nadia e Lili Boulanger em Paris, e o prémio especial da União Europeia de Concursos de Música para a Juventude em San Sebastián/Espanha. Em 2016, venceu por unanimidade o 1o prémio no Concurso Internacional J.J.C Yamaha do México, que lhe rendeu um piano novo de cauda Yamaha bem como uma turnê por diversos países da América Latina. Mais recentemente recebeu o primeiro prémio no Festival Verão Clássico em Lisboa, e em 2020, a medalha de ouro no Concurso Internacional de Roma InMusica.</p><p style="text-align:justify"> </p><p style="text-align:justify">Atualmente reside em Lisboa, onde, paralelamente à sua intensa atividade pedagógica e artística, obteve o grau de Doutor em Estudos da Cultura na Universidade Católica Portuguesa.</p>', '<p style="text-align:justify"><span style="font-weight:bold">Leonardo Hilsdorf</span> é um dos principais representantes da nova geração de pianistas brasileiros, com uma carreira de sucesso no Brasil, Estados Unidos e Europa. A sua performance tem sido aclamada pela crítica especializada, sendo descrita como &quot;fenomenal&quot; (Fuldaer Zeitung) e &quot;encantadora e magistral&quot; (L&#x27;Independent).</p><p style="text-align:justify"> </p><p style="text-align:justify">Um dos momentos marcantes da sua carreira foi a residência como solista na prestigiada <span style="font-weight:bold">Chapelle Musicale Reine Élisabeth</span>, onde foi orientado por Maria João Pires, sua atual mentora. Esta experiência contribuiu decisivamente para o aprimoramento do seu já impressionante talento.</p><p style="text-align:justify"> </p><p style="text-align:justify">Hilsdorf conquistou várias premiações em competições internacionais, recebendo o 1º prémio em eventos na Alemanha, França, Itália, Espanha, Portugal, México e Brasil. Entre os seus triunfos destacam-se o prestigiado prémio Nadia et Lilit Boulanger em Paris, o prémio especial da União Europeia de Concursos de Música para a Juventude em San Sebastián/Espanha, o 1º prémio no Concurso Internacional J.J.C Yamaha do México em 2016, o primeiro prémio no Festival Verão Clássico em Lisboa e a medalha de ouro no Concurso Internacional de Roma InMusica em 2020.</p><p style="text-align:justify"> </p><p style="text-align:justify">Nas temporadas anteriores, realizou apresentações em salas de concerto icónicas, como o Concertgebouw de Amesterdão, Flagey e Bozar em Bruxelas, Maison de la Radio em Paris, BeethovenHaus em Bonn, bem como na Sala São Paulo, Teatro Municipal do Rio de Janeiro e Sala Cecília Meirelles no Brasil. Hilsdorf já se apresentou com orquestras renomadas, como a Filarmónica da Radio France, Royal de Wallonie, Sinfónica de Yucatán e, no Brasil, com a OSESP, Orquestra Sinfónica Brasileira e Filarmónica de Minas Gerais.</p><p style="text-align:justify"> </p><p style="text-align:justify">Além das suas performances, Leonardo Hilsdorf é frequentemente convidado para participar em festivais e masterclasses pelo mundo, incluindo o Ravinia Festival nos Estados Unidos, Festival Emil Gilels na Alemanha, Académie de Villecroze na França e o Festival Campos do Jordão no Brasil. O seu talento também tem sido reconhecido pela mídia especializada, tendo sido entrevistado pela prestigiada revista francesa Pianiste, que lançou um CD com o seu recital ao vivo na Salle Cortot de Paris, e eleito o Jovem Talento do ano pela Revista Concerto em 2016. Hilsdorf já gravou para a France Musique e Musiq3 na Europa, além da Rádio e TV Cultura e Rádio MEC no Brasil.</p><p style="text-align:justify"> </p><p style="text-align:justify">Atualmente, Leonardo Hilsdorf reside em Lisboa, onde, paralelamente à sua atividade artística e pedagógica, aguarda a defesa de uma tese de doutoramento em Estudos da Cultura na Universidade Católica Portuguesa, com o apoio da Fundação para a Ciência e a Tecnologia (FCT). O seu talento, dedicação e paixão pela música fazem dele um dos pianistas mais destacados da sua geração, com uma carreira brilhante que testemunha o poder da perseverança e do amor pela arte.</p><p style="text-align:justify"> </p><p style="text-align:justify"><span style="font-weight:bold">Prémios</span></p><p style="text-align:justify">· Medalha de ouro no Concurso Internacional de Roma InMusica (2020)</p><p style="text-align:justify">· Primeiro prémio no Festival Verão Clássico em Lisboa</p><p style="text-align:justify">· Primeiro prémio no Concurso Internacional J.J.C Yamaha do México</p><p style="text-align:justify">· Prémio Nadia et Lilit Boulanger em Paris</p><p style="text-align:justify">· Prémio especial da União Europeia de Concursos de Música para a Juventude em San Sebastián/Espanha</p><p style="text-align:justify">· Primeiro prémio em diversas competições internacionais na Alemanha, França, Itália, Espanha, Portugal, México e Brasil</p><p style="text-align:justify">· Jovem Talento do ano pela Revista Concerto, em votação dos principais críticos de música do Brasil</p>', '<p>Notícias &amp; Entrevistas</p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><a href=http://www.leonardohilsdorf.com/ target=undefined>Webpage de Leonardo Hilsforf</a></span></span></p><p> </p><p><span style="text-decoration:underline"><a href=https://veja.abril.com.br/coluna/radar/pianista-leonardo-hilsdorf-se-apresenta-no-saraus-classicos-cariocas target=undefined>Veja (2024)</a></span> – Pianista Leonardo Hilsdorf se apresenta no Saraus Clássicos Cariocas</p><p> </p><p><span style="text-decoration:underline"><a href=https://saladanoticia.com.br/noticia/88511/premiado-internacionalmente-o-pianista-leonardo-hilsdorf-faz-apresentacao-unica-no-instituto-brando-barbosa-no-jardim-botanico target=undefined>Sala da Notícia (2024)</a></span> – Premiado internacionalmente, o pianista Leonardo Hilsdorf faz apresentação única no Instituto Brando Barbosa, no Jardim Botânico</p><p> </p><p><span style="text-decoration:underline"><a href=https://cultura.uol.com.br/radio/programas/o-prazer-da-musica/2022/09/02/103_leonardo-hilsdorf-um-dos-principais-pianistas-de-sua-geracao.html target=undefined>Cultura UOL (2022)</a></span> – Leonardo Hilsdorf – Um dos principais pianistas de sua geração</p><p> </p><p><span style="text-decoration:underline"><a href=https://www.concerto.com.br/noticias/musica-classica/pianista-leonardo-hilsdorf-vence-concurso-de-piano-em-roma target=undefined>Redação Concerto (2020)</a></span> – Pianista Leonardo Hilsdorf vence concurso de piano em Roma</p><p> </p><p><span style="text-decoration:underline"><a href=https://epoca.globo.com/vida/noticia/2016/06/leonardo-hilsdorf-o-pianista-que-transforma-redes-sociais-em-palco.html target=undefined>Época (2016)</a></span> – Leonardo Hilsdorf, o pianista que transforma as redes sociais em palco</p><p> </p><p><span style="text-decoration:underline"><a href=https://www1.folha.uol.com.br/guia/co1210200701.shtml target=undefined>Folha de São Paulo (2007)</a></span> – Pianista abre a série Piano Solo no Municipal<br/></p><p> </p>', 'https://static.wixstatic.com/media/d429ea_220213afbe1f4b1aa6dcb7918c66bb71~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_4259ee6ceab64cbfbe5f023ef902c82c~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_727501b635294cb3b3884233af648cde~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_47697658118248bc9fd91f41f6f728d4~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_f5cb97e1c4cb4d0296da52d9e528b68f~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_e90a7f76061143f880c2315062faa356~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_321f6e107ea547078fb37c86d66685c3~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_7a5b06a282f746a0bb9d479f83d3896b~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_5b038aa70874436986c7453e074bad87~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_0a4f6041b7e54945ab97764ea66a4ca4~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_25dbebbd40da4fb696ad6ca9332b1dee~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d429ea_a5a6a3a4e7bd4c0fa6c59c3948e59a99~mv2.jpg', NULL, 1, 0, 0);

-- Row 46: Voice  'n' Combo
INSERT IGNORE INTO users (id, email, password, role) VALUES ('39600f2a-b59c-44ed-a25b-284189ec4f06', 'wix-39600f2a@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('9439b9d4-2dc8-4cd3-a5f8-f58a58067b05', '39600f2a-b59c-44ed-a25b-284189ec4f06', 'voice-n-combo', 'Voice  ''n'' Combo', 'Ariana', '916356987', '2017-07-06', 'Portugal', 'Portugal', 'Amadora', 'Rua Elias Garcia, 73', '2D', '2700-314', 'Quarteto vocal e quarteto instrumental', 'É na fusão perfeita entre as melodias que encontramos a harmonia em cada um de nós.', 'https://static.wixstatic.com/media/7b859e_e826b54afbf0420d9ee9ab6613c8dd44~mv2.jpg', 'wix:document://v1/39600f_14024a952ee440f49eee776779ad709e.docx/Voice%20n''%20Combo%20Standard.docx', 'https://www.facebook.com/voice.n.combo', NULL, NULL, NULL, 'https://www.youtube.com/channel/UCKO-ybNCVRg131tOJJxumPg', NULL, NULL, NULL, 'https://youtu.be/9DIKpoaKhBg?si=gE7U3FaWL8WSQAA8', 'https://youtu.be/aCHv_XxgY4s?si=H6AOl2J-9s8Nw847', 'https://youtu.be/zHmASTmbNxM?si=qo1xND4fUl4WCkIN', 'https://youtu.be/oHiKJvBvyN8?si=3cPCUd3epp_RmYW-', 'https://youtu.be/IsPa1w-owbw?si=ulZU5T2m_Ume8_I0', 'https://youtu.be/mm4ECegAGgY?si=hc1-k5dQtEVyPznS', 'https://youtu.be/mm4ECegAGgY?si=hc1-k5dQtEVyPznS', 'https://youtu.be/mm4ECegAGgY?si=hc1-k5dQtEVyPznS', 'https://youtu.be/mm4ECegAGgY?si=hc1-k5dQtEVyPznS', 'https://youtu.be/mm4ECegAGgY?si=hc1-k5dQtEVyPznS', '<p class="font_8">O Voice''n''Combo é um grupo de música jazz único e inovador, composto por 4 instrumentistas e 4 cantores, que se destaca pela sua interpretação magistral do repertório de jazz vocal e instrumental do século XX. Com um objetivo claro de divulgar e valorizar a herança cultural e musical americana, o grupo apresenta uma visão fresca e original da música jazz.</p>
<p class="font_8"><br></p>
<p class="font_8">Através de uma seleção cuidadosa de temas do cancioneiro americano, o Voice''n''Combo oferece uma experiência musical emocionante e sofisticada, que transporta o público para uma época de grande criatividade e inovação musical. A polifonia e a riqueza harmônica são características marcantes do grupo, tornando cada apresentação uma experiência única e inesquecível.</p>
<p class="font_8"><br></p>
<p class="font_8">Com uma ambição firme de contribuir para a construção de uma identidade "jazzística" própria, o Voice''n''Combo tem apresentado vários concertos de sucesso em locais emblemáticos, como o Museu Nacional da Músicacional da Música, o Centro Cultural da Malaposta, o Teatro Cine de Torres Vedras e o Cineteatro Mouzinho da Silveira – Castelo de Vide. Esses concertos têm sido recebidos com entusiasmo pelo público e pela crítica, consolidando o grupo como uma das principais referências do jazz em Portugal.</p>
<p class="font_8">&nbsp;</p>', '<p class="font_8">As longínquas origens do jazz cantam a dor do homem prisioneiro e a sua esperança de libertação. Nasce nos campos de algodão e nas igrejas, celebra os funerais, difunde-se num vasto território, mas é em New Orleans que encontra o terreno mais fértil para crescer e ser uma arte relevante. Surge das inúmeras diferenças americanas: entre pobres e ricos, felizes e infelizes, o campo e a cidade, negros e brancos, homens e mulheres, entre a velha África e a velha Europa. É uma arte de memória. Uma mistura explosiva de ritmos africanos e de elementos melódicos, harmónicos e formais da tradição europeia. Nesta identidade musical ressoam as relações de raça e o preconceito, o lamento e o protesto contra a opressão, a luta pelos direitos civis, uma mensagem de esperança e afirmação perante as adversidades. Ecoam duas guerras mundiais, a depressão económica e ao mesmo tempo a encarnação do drama da história americana.</p>
<p class="font_8"><br></p>
<p class="font_7"><strong>Os nossos programas permitem fazer um pequeno percurso pela história do jazz, evidenciando as diferenças entre épocas, valorizando as suas especificidades, revelando as permutas e influências que estas estabeleceram entre si.</strong></p>
<p class="font_7">&nbsp;</p>', '<p class="font_8">O Voice''n''Combo busca celebrar a essência da música jazz, uma arte que nasceu da dor e da esperança de libertação do homem prisioneiro. Com raízes nos campos de algodão e nas igrejas, o jazz é uma mistura explosiva de ritmos africanos e elementos melódicos, harmônicos e formais da tradição europeia. É uma arte de memória, que ressoa as relações de raça e o preconceito, o lamento e o protesto contra a opressão, a luta pelos direitos civis e uma mensagem de esperança e afirmação perante as adversidades.</p>
<p class="font_8"><br></p>
<p class="font_8">O objetivo &nbsp;é participar ativamente na construção de uma identidade "jazzística" própria, que seja capaz de refletir a complexidade e a diversidade da música jazz. Com uma formação única que combina 4 instrumentistas e 4 cantores, o grupo apresenta famosos temas do cancioneiro americano em polifonia, criando uma experiência musical emocionante e sofisticada. Os programas do Voice''n''Combo permitem fazer um pequeno percurso pela história do jazz, evidenciando as diferenças entre épocas, valorizando as suas especificidades e revelando as permutas e influências que estas estabeleceram entre si.</p>
<p class="font_8"><br></p>
<p class="font_8">Através da sua música, busca transmitir a mensagem de esperança e afirmação que é característica do jazz. O grupo quer que o seu público sinta a emoção e a paixão que está por trás de cada nota, e que se sinta conectado à história e à cultura que os inspira. O Voice''n''Combo é um grupo que busca manter viva a chama do jazz, e que se esforça para criar uma experiência musical única e inesquecível para todos os que os ouvem.</p>', '<p class="font_7"><strong>Elementos</strong></p>
<p class="font_7"><br></p>
<p class="font_8"><strong>Ariana Russo</strong>, soprano</p>
<p class="font_8"><br></p>
<p class="font_8">Completou o exame de Canto na Escola de Música do Conservatório Nacional e terminou a sua licenciatura na Escola Superior de Música de Lisboa. Frequentou a Escola Superior de Música de Karlsruhe.</p>
<p class="font_8">Como solista interpretou diversas oratórias e ópera tais como «Dido e Aeneas» de Purcell, «L''enfant et les sortilèges» de Ravel, «Il sogno dello Zingano» de Miró, «Il Mondo della Luna» de Avondano, «Il Barbière di Siviglia» de Rossini ou «Le dialogue des Carmélites» de Poulenc. Em 2017 interpretou Maria em «West Side Story» de Bernstein, com a Banda de B. V. de Torres Vedras. Desde 2008 que canta no Coro Gulbenkian e colabora com outros grupos vocais como o Officium Ensemble e Ensemble MPMP.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Rita Tavares</strong>, contralto</p>
<p class="font_8"><br></p>
<p class="font_8">Nasceu em Lisboa e, aos nove anos, iniciou os seus estudos musicais no Instituto Gregoriano de Lisboa, sendo licenciada em canto pela Escola Superior de Música de Lisboa.</p>
<p class="font_8">É membro do Coro Gulbenkian (2011), do Officium Ensemble (2014) do Ensemble MPMP (2015) e do Ensemble Vocal Aura (2020) e é convidada a participar regularmente em projectos com o Polyphonos Ensemble, Voces Caelestes, Cappella Patriarchal, Ensemble São Tomás de Aquino e Alma Ensemble.</p>
<p class="font_8">Desde 2016, colabora com o Nederlands kamerkoor (Holanda) e com o Chamber Choir of Europe (Alemanha).</p>
<p class="font_8">Participou em concertos como solista no Centro Cultural de Belém, Fundação Calouste Gulbenkian, Teatro São Luiz, Teatro Nacional São Carlos, e Unibes Cultural (São Paulo) e actuou em festivais como Festival Terras sem sombra, Festival de Música de São Roque, Festival Cistermúsica, Laus Polyphoniae (Bélgica), Oude Musik Festival (Holanda) e Händel-festspiele (Alemanha).</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Frederico Projecto</strong>, tenor</p>
<p class="font_8"><br></p>
<p class="font_8">Iniciou os seus estudos musicais, aos 8 anos, no Conservatório Regional de Setúbal, transferindo-se posteriormente para a Escola de Música do Conservatório Nacional de Lisboa, onde estudou canto com Filomena Amaro. Frequentou a licenciatura de direção de Orquestra da ANSO. Licenciado em Formação Musical e Direção Coral, na Escola Superior de Música de Lisboa, é presentemente responsável pela classe de orquestra da Escola de Música do Colégio Moderno. É membro do Coro Gulbenkian, desde 2008. Colabora regularmente, como solista e/ou coralista, com grupos nacionais e internacionais, tais como: Ensemble Vocal Introitus, Schola Cantorum da Catedral de Santarém, Ensemble Lusiovoce, Grupo Vocal Officium, Coro Voces Caelestes, Chœur de Chambre de Namur (Bélgica), Capella Sanctæ Crucis (França), entre outros.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Pedro Casanova</strong>, baixo</p>
<p class="font_8"><br></p>
<p class="font_8">Natural de Vilar Formoso.</p>
<p class="font_8">Terminou o Curso Superior de Formação Musical e Direção Coral da Escola Superior de Música de Lisboa, na classe do prof. Vasco Pearce de Azevedo.</p>
<p class="font_8">Além do Curso complementar de Piano do Conservatório, estudou Direção Coral com Vasco Pearce de Azevedo, Paulo Lourenço e Stephen Coocker. Foi maestro do Grupo Coral de Sesimbra.</p>
<p class="font_8">É membro do Coro Gulbenkian no qual já fez concertos em Portugal e no estrangeiro. Atuou com o Grupo Coral Polifónico de Vilar Formoso, com o Coral “Pedras Vivas” da Guarda e com o Orfeão da Covilhã, em diversas atuações em Portugal e Espanha. Atualmente é professor de Formação Musical e Coro na Academia de Amadores de Música e Academia D. Dinis.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Ricardo Correia</strong>, saxofone</p>
<p class="font_8"><br></p>
<p class="font_8">Começa os estudos musicais na Banda Filarmónica dos Bombeiros Voluntários de Torres Vedras. Prosseguiu com os estudos de Saxofone na Escola de Música Luis António Maldonado Rodrigues e posteriormente no Conservatório Nacional, na classe do prof. Rui Gabriel. Em 2009, o jazz despertou a sua atenção e decide iniciar um período de auto-aprendizagem, desenvolvendo o seu conhecimento sobre a arte da improvisação. A sua versatilidade trouxe-lhe participações com várias orquestras filarmónicas, passando por orquestras ligeiras, combos de jazz, colaborações com DJs e atuações a solo. Mais recentemente, participou em colaboração com a Camerata Vocal de Torres Vedras, no “Sacred Concert” de Duke Ellington e em concertos de tributo a de George Gershwin e à música de cinema. É licenciado em Informática e Gestão de Empresas, onde exerce a sua profissão. No entanto, é no meio musical que encontra o escape perfeito à complexidade dos negócios e à rotina do dia a dia.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>João Nogueira</strong>, contrabaixo</p>
<p class="font_8"><br></p>
<p class="font_8">Psicólogo, desde 1983, esteve no Centro Psicotécnico da Força Aérea, de 1984 a 1987. Mestre e Doutor em Ciências da Educação, tem-se dedicado à Psicologia da Educação, apesar da sua formação clínica comportamental-cognitiva. Fez parte da 1ª comissão de estágios e é formador na área da ética da Ordem dos Psicólogos Portugueses. Atualmente, é Professor Auxiliar no Departamento de Ciências Musicais da Faculdade de Ciências Sociais e Humanas da Universidade Nova de Lisboa e coordena o Mestrado em Ensino da Educação Musical para o Ensino Básico. Como músico, tocou contrabaixo ou baixo em diversos estilos da música popular (fado, jazz, choro e samba). Atualmente, toca na Orquestra Libertina de Lisboa e colabora com a Camerata Vocal de Torres Vedras.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Samuel Dias</strong>, bateria</p>
<p class="font_8"><br></p>
<p class="font_8">Começou os seus estudos musicais em 2003 na escola de Jazz de Torres Vedras, começando pelo piano e passando mais tarde para a bateria. Em 2008 ingressou no conservatório de música "Luis Antonio Maldonado Rodrigues" em Torres Vedras, continuando os seus estudos de piano onde estudou com Helder Marques. Em 2012, completando o 5º grau do conservatório, mudou-se para Lisboa, tendo migrado da música clássica para o jazz, ingressando assim na escola de jazz do Hot Club de Portugal no curso de bateria. Começou também o curso de piano jazz na mesma escola. Em 2017 começou a licenciatura em bateria - jazz pela Escola Superior de Música de Lisboa.</p>
<p class="font_8">Profissionalmente já trabalhou com nomes como João Paulo Esteves da Silva, Nelson Cascais, Andy Sheppard, Ramon Galarza, Federico Casagrande e Manuel Freire.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Pedro Ramos</strong>, piano</p>
<p class="font_8"><br></p>
<p class="font_8">Nascido em 1989, Pedro Ramos terminou o curso complementar de Formação Musical na Academia de Música de Santa Cecília. A sua formação continuou nos Estados Unidos, onde concluiu com distinção o curso de Classical Composition, na Manhattan School of Music, em Nova Iorque, em 2012. Pedro Ramos também estudou Piano com a Professora Carla Seixas, a Professora Lisa Yui e o Professor Artur Pizarro. Para além de vários recitais a solo, também integra formações de câmara, como um duo com o clarinetista António Saiote, ou o Trio Tarantella, com quem gravou um CD de Música Francesa, através do apoio da Fundação GDA. Actualmente, trabalha como pianista correpetidor na Fundação Calouste Gulbenkian.</p>
<p class="font_8">No que respeita à Composição, estudou com Pedro Faria Gomes, Nils Vigeland e Susan Botti. As suas peças foram estreadas em Nova Iorque, Lisboa, Badajoz, Bruxelas e Amsterdão. Compõe para várias formações e em vários estilos, tendo já escrito para orquestras sinfónicas, como para publicidade, através da produtora de filmes BRO.</p>
<p class="font_8">Desde Outubro de 2019, é coordenador da Temporada Antena 2.</p>', 'https://static.wixstatic.com/media/39600f_0ac334ec3fc0423a8245d301b85d9955~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_96345378103b4fb0b86ebcbcc6dbd886~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_e29615b0159943739e3110425f477677~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_9c87635bee154a2f9abc2503b3406153~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_0471cfdc9d51454e86f5996c84239212~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_82d24a41592148a7947ad34ea6d2aaa5~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_8d5248a557974024a4124c906a487b72~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_eec915fb866d4fce9910b2f5f93cb74c~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_f534e82326494add8d1c281431cc68ea~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_347c83279c444c228a97709aeadf6f56~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_61cecc7fefd94b23b5a32d6859159ab3~mv2.jpg', NULL, 'https://static.wixstatic.com/media/39600f_67c851c34c044209b5907bf41b851560~mv2.jpg', NULL, 1, 0, 0);

-- Row 47: Nuno Esteves "Blue"
INSERT IGNORE INTO users (id, email, password, role) VALUES ('59313cc2-d569-44d3-abe1-9a3b4a3552d1', 'wix-59313cc2@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('3699647b-327f-4264-9483-258222f30f9c', '59313cc2-d569-44d3-abe1-9a3b4a3552d1', 'blue', 'Nuno Esteves "Blue"', 'Nuno', '999999999', '2005-07-22', 'Angola', 'Portugal', 'Lisboa', 'xxx xxx xxx', NULL, '1800', 'Diretor de Arte', '"Alguém teve um sonho e alguém quer pô-lo de pé. O meu trabalho é fornecer soluções para esse sonho"', 'https://static.wixstatic.com/media/59313c_50059931c5394084b6042856f61ce640~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/59313c_b4959f80dfcb4f8aacaf2900ecf656b6.mp3', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8" style="text-align: justify">Nuno Esteves, o talentoso artista conhecido como "Blue", é uma das maiores referências em <strong>caracterização e direção de arte</strong> cinematográfica em Portugal. O seu trabalho distinto e visionário torna-o verdadeiramente único neste campo.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Enquanto <strong>caracterizador</strong>, é um mestre em transformações visuais impressionantes. Cria universos ricos e simbólicos através da sua <strong>mestria na manipulação de cores, texturas, formas e próteses</strong>.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Como diretor de arte, Blue constrói <strong>cenários e atmosferas visualmente cativantes</strong> que imergem os espetadores na narrativa. O seu olhar estético criterioso e a sua criatividade sem limites permitem-lhe traduzir perfeitamente conceitos abstratos em realidades tangíveis no ecrã.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Distingue-se pela sua <strong>abordagem colaborativa e dedicada</strong>. Trabalhando em estreita parceria com realizadores, atores e equipas, ele esforça-se incansavelmente para realizar as visões criativas de cada projeto com paixão e compromisso totais.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Conquistou <strong>três Prémios Sophia</strong> na categoria de melhor caracterização e efeitos especiais por "Mosquito" (2021), "Peregrinação (2018) e "Cartas da Guerra" (2017).</p>', '<p style="text-align:justify">Nuno Esteves nasceu em África, mas foi no Porto que a sua criatividade inata começou a florescer. Lá frequentou a <span style="font-weight:bold">Escola Artística Soares dos Reis</span>, que lhe permitiu começar a explorar o seu talento para as artes visuais.</p><p> </p><p style="text-align:justify">Sempre audaz e disposto a experimentar, Nuno, com apenas 17 anos, mergulhou de cabeça no mundo do cinema ao <span style="font-weight:bold">trabalhar como caracterizador no controverso filme &quot;O Pecado da Mamã&quot;</span>. Foi uma introdução intensa à indústria, sendo lançado diretamente para o meio dos veteranos do cinema português. No entanto, em vez de se intimidar, absorveu cada lição com entusiasmo juvenil.</p><p> </p><p style="text-align:justify">Durante os seus anos de formação, Nuno já se destacava pela sua personalidade vibrante e estilo inconfundível. Naquela época, chocava ao tingir o cabelo de um azul vibrante e vestir-se em monocromático na mesma tonalidade audaciosa. Esse visual único valeu-lhe o apelido &quot;Blue&quot; entre os seus colegas da escola de dança Balleteatro, que rapidamente se tornou o seu nome artístico.</p><p> </p><p style="text-align:justify">Prosseguiu com os estudos na <span style="font-weight:bold">Faculdade de Belas Artes do Porto</span>, onde se formar em escultura. Em paralelo, explorou as artes cénicas, atuando como bailarino e lecionando caracterização na escola profissional <span style="font-weight:bold">Balleteatro Contemporâneo do Porto</span>. A sua paixão pelas transformações visuais começava a ganhar forma.</p><p> </p><p style="text-align:justify">Ainda antes de ingressar na universidade, a curiosidade de Nuno pelo universo da maquilhagem já era evidente, levando-o a frequentar cursos de forma discreta no Citex (Centro de Formação Profissional da Indústria Têxtil), visto que era muito jovem para se matricular oficialmente. Essa sede de conhecimento apenas se intensificou quando, após se diplomar, partiu para Paris.</p><p> </p><p style="text-align:justify">Na vibrante cena parisiense, Nuno pôde finalmente aprofundar-se na arte da maquilhagem profissional. Durante oito anos, trabalhou na área com os melhores do ofício. O seu talento rapidamente chamou a atenção, levando-o a trabalhar com lendas da alta costura como as <span style="font-weight:bold">prestigiadas casas Dior e Jean Paul Gaultier</span>.</p><p> </p><p style="text-align:justify">No entanto, o ritmo frenético e as longas horas exigidas pela indústria da moda eventualmente levaram Nuno a sentir a necessidade de mais equilíbrio na sua vida e a pensar em mudar de rumo. Ainda assim, a sua passagem por esses bastiões do glamour foi inestimável. Manteve excelentes relações com os seus mentores e colegas, que se tornaram alguns dos seus melhores amigos até hoje.</p><p> </p><p style="text-align:justify">De facto, foi novamente o acaso que reacendeu a sua paixão pela caracterização artística. Convidado para auxiliar num ensaio fotográfico de moda na ausência do maquilhador profissional, Nuno destacou-se ao manipular a maquilhagem de forma natural e talentosa. Esse impulso inicial levou-o a inscrever-se num curso de maquilhagem na Lancôme, que lhe forneceu uma base sólida para o ofício.</p><p> </p><p style="text-align:justify">Desde aí que Nuno Esteves tem <span style="font-weight:bold">consolidado uma carreira distinta, combinando técnicas tradicionais com uma perspetiva arrojada</span>. A sua base clássica faz dele um caracterizador mais &quot;<span style="font-style:italic">old school</span>&quot;, mas é precisamente essa matriz tradicional, combinada com um olhar arrojado e destemido, que torna o seu trabalho tão distinto e único até aos dias de hoje.</p>', '<h3 style="text-align:justify">Nuno Esteves &quot;Blue&quot; é um veterano profissional de caracterízação, figurinos, efeitos especiais e direção de arte. Com um currículo diversificado e sólida reputação, estabeleceu-se como um dos mais respeitados e versáteis profissionais por detrás das câmeras no audiovisual português contemporâneo.</h3><p style="text-align:justify"> </p><h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><h3> </h3><ul><li style="text-align:justify">2024 - Fez a direcção de arte da ópera &quot;Felizmente Há Luar!&quot;.</li><li style="text-align:justify">2016 - Foi Designer de Produção de dois filmes: &quot;Everything&#x27;s OK&quot; e &quot;Menina&quot;. Foi igualmente figurinista desde último.</li><li style="text-align:justify">Entre 2014 e 2016, foi Artista de efeitos visuais em três filmes: &quot;Wolf and Sheep&quot;, &quot;Ponto Morto&quot; e &quot;Gambozinos&quot;.</li><li style="text-align:justify">Entre 2012 e 2019, foi Diretor de Arte de curtas e longas metragens e de uma série de televisão: &quot;Histórias da Montanha&quot;, &quot;Oso&quot;, &quot;Raposa&quot; e &quot;Paixão&quot;.</li><li style="text-align:justify">Estabeleceu-se como caracterizador de renome no cinema português.</li><li style="text-align:justify">Em Paris, teve uma experiência casual com maquilhagem num ensaio fotográfico, o que reacendeu a sua paixão pela área.</li><li style="text-align:justify">Faz formação profissional em maquilhagem na Lancôme.</li><li style="text-align:justify">Trabalhou nas casas de alta costura Dior e Jean Paul Gaultier.</li><li style="text-align:justify">Mudou-se para Paris.</li><li style="text-align:justify">Lecionou caracterização na escola Balleteatro Contemporâneo do Porto.</li><li style="text-align:justify">Atuou como bailarino.</li><li style="text-align:justify">Formou-se em Escultura na Faculdade de Belas Artes do Porto.</li><li style="text-align:justify">Frequentou a Escola Artística Soares dos Reis</li><li style="text-align:justify">1986 - Trabalhou pela primeira vez como caracterizador no filme &quot;O Pecado da Mamã&quot;. Fez cursos de maquilhagem &quot;às escondidas&quot; no Citex.</li></ul><h3 style="text-align:justify"> </h3><h3><span style="font-weight:bold">PRÉMIOS E NOMEAÇÕES</span></h3><p> </p><p style="text-align:justify"><span style="font-weight:bold">Prémios Sophia da Academia Portuguesa de Cinema</span></p><p style="text-align:justify">2021: Vencedor - Melhor Caracterização/Efeitos Especiais por &quot;Mosquito&quot;</p><p style="text-align:justify">2018: Vencedor - Melhor Caracterização/Efeitos Especiais por &quot;Peregrinação&quot;</p><p style="text-align:justify">2017: Vencedor - Melhor Caracterização por &quot;Cartas da guerra&quot;</p><p> </p><p style="text-align:justify"><span style="font-weight:bold">Nomeações Prémios Sophia</span></p><p style="text-align:justify">2023: Nomeado - Melhor Caracterização/Efeitos Especiais por &quot;A Viagem de Pedro&quot;</p><p style="text-align:justify">2021: Nomeado - Melhor Maquiagem e Cabelo por &quot;Mosquito&quot;</p><p style="text-align:justify">2020: Nomeado - Melhor Maquiagem e Cabelo por &quot;Hotel Império&quot;</p><p style="text-align:justify">2019: Nomeado - Melhor Caracterização por &quot;Cabaret Maxime&quot;</p><p style="text-align:justify">2019: Nomeado - Melhor Caracterização/Efeitos Especiais por &quot;Linhas de Sangue&quot; (com Rita de Castro)</p><p style="text-align:justify">2019: Nomeado - Melhor Caracterização/Efeitos Especiais por &quot;Linhas de Sangue&quot;</p><p style="text-align:justify">2018: Nomeado - Melhor Caracterização por &quot;O Divã de Estaline&quot;</p><p> </p><p style="text-align:justify"><span style="font-weight:bold">Nomeações CinEuphoria</span></p><p style="text-align:justify">2023: Melhor Maquiagem - Competição Nacional por &quot;A Viagem de Pedro&quot;</p><p style="text-align:justify">2021: Melhor Maquiagem - Competição Nacional por &quot;Mosquito&quot;</p><p style="text-align:justify">2020: Melhor Maquiagem - Competição Nacional por &quot;Hotel Império&quot;</p><p style="text-align:justify">2019: Melhor Maquiagem - Competição Nacional por &quot;Cabaret Maxime&quot;</p><p style="text-align:justify">2019: Melhor Maquiagem - Competição Nacional por &quot;O Caderno Negro&quot;</p><p style="text-align:justify">2019: Melhor Maquiagem - Competição Nacional por &quot;Como Fernando Pessoa Salvou Portugal&quot;</p><p style="text-align:justify">2018: Melhor Maquiagem - Competição Nacional por &quot;O Divã de Estaline&quot;</p><p style="text-align:justify">2018: Melhor Direção de Arte - Competição Nacional por &quot;Everything&#x27;s OK&quot;</p><p style="text-align:justify">2017: Melhor Desenho de Costura - Competição Nacional por &quot;Menina&quot;</p><p style="text-align:justify">2017: Melhor Maquiagem - Competição Nacional por &quot;Cartas da guerra&quot;</p><p style="text-align:justify">2017: Melhor Maquiagem - Competição Nacional por &quot;Menina&quot;</p>', '<h3 style="text-align:justify"><span style="font-weight:bold">FILMOGRAFIA</span></h3><h3> </h3><ul><li style="text-align:justify">Mãos no fogo (2024) - Hair stylist, Makeup artist</li><li style="text-align:justify">O Bêbado (2023) - Key Makeup Artist</li><li style="text-align:justify">Capitães do Açúcar (2021-2023) - Key Makeup Artist, Makeup Artist, Hair Stylist</li><li style="text-align:justify">1936 - O Ano da Morte de Ricardo Reis (2022) - Makeup Designer: Pre-production</li><li style="text-align:justify">Índia (2022) - Key Hair Stylist, Key Makeup Artist</li><li style="text-align:justify">O Teu Peso em Ouro (2022) - Makeup Artist</li><li style="text-align:justify">Toda a Gente Gosta de Jeanne (2022) - Key Hair Stylist, Key Makeup Artist</li><li style="text-align:justify">A Rainha e a Bastarda (2022) - Makeup Department Head</li><li style="text-align:justify">O Livro Negro do Padre Dinis (2021) - Key Hair Stylist, Key Makeup Artist</li><li style="text-align:justify">A Viagem de Pedro (2021) - Makeup Artist</li><li style="text-align:justify">Naufrágio (2021) - Special Makeup Effects Artist</li><li style="text-align:justify">Boa Noite (2021) - Makeup Artist</li><li style="text-align:justify">Mosquito - A Minissérie (2020) - Key Makeup Artist</li><li style="text-align:justify">O Ano da Morte de Ricardo Reis (2020) - Makeup Designer: Pre-production</li><li style="text-align:justify">Um Animal Amarelo (2020) - Hair Stylist</li><li style="text-align:justify">Mosquito (2020) - Key Makeup Artist</li><li style="text-align:justify">Sul (2019) - Key Makeup Artist</li><li style="text-align:justify">Patrick (2019) - Makeup Artist</li><li style="text-align:justify">Linhas Tortas (2019) - Key Makeup Artist</li><li style="text-align:justify">Hotel Império (2018) - Key Makeup Artist</li><li style="text-align:justify">Mar (2018) - Key Makeup Artist</li><li style="text-align:justify">O Caderno Negro (2018) - Key Hair Stylist, Key Makeup Artist</li><li style="text-align:justify">Linhas de Sangue (2018) - Key Makeup Artist</li><li style="text-align:justify">Como Fernando Pessoa Salvou Portugal (2018) - Hair Stylist, Makeup Artist</li><li style="text-align:justify">Equinócio (2018) - Key Hair Stylist, Key Makeup Artist</li><li style="text-align:justify">Cabaret Maxime (2018) - Key Makeup Artist</li><li style="text-align:justify">Peregrinação (2017) - Key Hair Stylist</li><li style="text-align:justify">Sol Cortante (2017) - Hair Stylist, Makeup Artist</li><li style="text-align:justify">O Divã de Estaline (2016) - Makeup Artist</li><li style="text-align:justify">Até Nunca (2016) - Makeup Artist</li><li style="text-align:justify">Wolf and Sheep (2016) - Makeup Artist</li><li style="text-align:justify">Menina (2016) - Hair Stylist, Makeup Artist</li><li style="text-align:justify">Cartas da guerra (2016) - Makeup Artist</li><li style="text-align:justify">Killies (2015) - Makeup Artist</li><li style="text-align:justify">O Velho do Restelo (2014) - Makeup Artist</li><li style="text-align:justify">Ponto