-- Row 48: Isabel Pereira
INSERT IGNORE INTO users (id, email, password, role) VALUES ('fbd141f8-cee6-4f2a-8567-bc211da6c8c2', 'wix-fbd141f8@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('873ee6a3-21f7-424f-8ba6-3b934fad2609', 'fbd141f8-cee6-4f2a-8567-bc211da6c8c2', 'isabel-pereira', 'Isabel Pereira', 'Isabel', '''+351916417717', '1982-09-22', 'Portugal', 'Portugal', 'Santarém', 'Travessa 15 de Março n.12 2º dto. 2000-128 Santarém', NULL, '2000-128', 'Violetista', '“Poético e vividamente imaginado, Pereira moveu-se entre sons percussivos e uma voz cremosa de intensidade virtuosa" The Strad', 'https://static.wixstatic.com/media/7b859e_063f208ae7d44a839d1ea2c96edb7e39~mv2.jpg', 'wix:document://v1/fbd141_bbb3633b5a7f482680e45ab93eb3d036.pdf/Isabel%20Pereira%20Bio%20PT%2024.pdf', 'https://www.facebook.com/isabel.pereira.9026040', 'https://www.instagram.com/isabel.pereira.viola/', 'https://www.tessitorimusic.com/', NULL, 'https://www.youtube.com/user/TESSITORIMUSIC/videos', 'https://static.wixstatic.com/mp3/fbd141_e30a2502b0054c3d846af58ef6e2f2bb.mp3', NULL, NULL, 'https://youtu.be/p9FQHtGukkE', 'https://youtu.be/6gBB3sGKed0', 'https://www.youtube.com/watch?v=xfPUbWaarW0', 'https://www.youtube.com/watch?v=6Twn7WA_pdg', 'https://www.youtube.com/watch?v=_7C59oXVr24', 'https://www.youtube.com/watch?v=u33tGH8VE_M', 'https://www.youtube.com/watch?v=VHK8KIRBOB4', 'https://www.youtube.com/watch?v=tJbb94vOkl4', 'https://www.youtube.com/watch?v=YuT9cLHqdp0', NULL, '<p>Violetista <span style="font-weight:bold">galardoada </span>a nível nacional e internacional que se destaca pela sua atividade orquestral como freelancer no Reino Unido e Portugal. <span style="font-weight:bold">Liderou</span> as violas da Royal Liverpool Philharmonic, Bournemouth Symphony, Orquestra Sinfónica do Porto, Orquestra XXI, Orquestra Filarmónica Portuguesa e da <span style="font-weight:bold">Orquestra Sinfónica Portuguesa - Teatro Nacional de São Carlos </span>da qual é membro.</p><p> </p><p>Colabora ainda com a Royal Opera House, Philharmonia, Royal Philharmonic Orchestra, London Sinfonietta, Remix Ensemble e foi simultaneamente, entre 2009 e 2020, instrumentista convidada da <span style="font-weight:bold">London Philharmonic Orchestra</span>com a qual realizou inúmeras digressões e festivais por todo o mundo.</p><p> </p><p>Paralelamente, colabora a solo com orquestras e grupos de música de câmara em diversos países de destacar o duo Tessitori com o guitarrista João Loureiro. Foi também convidada a participar nos seguintes festivais: “Brahms and Friends Festival”, no “Lionel Tertis Viola Festival” e no “Berio Festival – Omaggio – SouthBank R.A.M.”. Neste último interpretou a Sequenza VI de Luciano Berio e do concerto a crítica comenta:</p><p> </p><p><span style="font-weight:bold">“Foi poético e tocado com imaginação vívida, Pereira moveu-se entre duros sons percussivos e uma voz cremosa de intensidade virtuosa (in The Strad Julho 2004).</span></p><p> </p><p>Vencedora do <span style="font-weight:bold">1º prémio</span> em viola no <span style="font-weight:bold">Prémio Jovens Músicos </span>Antena 2 RDP em 2000 Isabel foi também bolseira da Fundação Calouste Gulbenkian, enquanto estudante na <span style="font-weight:bold">Royal Academy of Music – Londres</span>, onde conclui a sua Licenciatura (First Class Honours) e a Pós-Graduação (Distinction), ambas com qualificação máxima, recebe ainda um diploma de excelência (Dip-Ram) e o “Hilda Wyme Memorial Award”</p>', '<p><span style="font-weight:bold">Isabel Pereira nasceu em Paris</span> em 1982. Após a mudança da sua família para Portugal aos 7 anos, inicia os seus estudos musicais, inicialmente dedicando-se ao piano e mais tarde à viola d’arco na <span style="font-weight:bold">Artave</span> – Escola Profissional Artística do Vale do Ave com os professores David Lloyd e Linda Green.</p><p> </p><p>No ano 2000 Isabel <span style="font-weight:bold">muda-se para Londres</span> para continuar os seus estudos na <span style="font-weight:bold">Royal Academy of Music</span>. Aqui vence um Dip-Ram (<span style="font-weight:bold">Diploma de Excelência</span>) por um excelente recital final e também o prémio “<span style="font-weight:bold">Hilda Wyme Memorial Award</span>” por melhor recital de viola d’arco. Na RAM estudou com o professor Paul Silverthorne e participou em diversos master-classes de violeta com os professores: Mikael Kugel, Tatjana Masurenko, Hartmut Rohde, Jerzy Kosmala, Gartfield Jackson e Mattew Souter. Consultou ainda com Kim Kashkashian, Ana Bela Chaves, Andryi Vytovich, Rachel Roberts e Yuko Inoue. A convite pessoal do célebre professor Gérard Caussé foi uma das violetistas escolhidas para participar no seu masterclass na célebre <span style="font-weight:bold">Académie Musicale de Villecroze</span> – França.</p><p> </p><p>Apresentou-se em <span style="font-weight:bold">recitais e concertos </span>em Inglaterra, Portugal, Espanha, Japão, Itália e como <span style="font-weight:bold">solista </span>com a Orquestra Gulbenkian e com a Orquestra Artave. Isabel também se tem dedicado à música de câmara nomeadamente em duo: “<span style="font-weight:bold">TESSITORI</span>” com o guitarrista clássico João Loureiro com o qual se tem apresentado regularmente, são de realçar as várias apresentações em Londres: na National Portrait Gallery (especialmente dois concertos integrados na exposição “Picasso Portraits”em 2016), em St. James’s, Picadilly (concerto integrado no Festival Echoes da ILAMS 2017), no National Theatre – Southbank e Rosslyn Hill Chapel; em Portugal: na Fundação Calouste Gulbenkian, Teatro Nacional de São Carlos, Terras Sem Sombra entre outros. Com este mesmo duo grava em 2014 o primeiro disco, do qual a crítica reconhece: “<span style="font-weight:bold">É evidente que estamos perante dois músicos de exceção, cuja filosofia de oferecer à música e ao público, a liberdade de respirar, é apresentada de forma convicta.” (in Classical Guitar Magazine) “Está gravado de forma vívida e apresentado de forma elegante” (in The Strad) </span>Ainda no âmbito de música de câmara Isabel foi membro fundador e 1ªviola do Sexteto de Cordas Shoenberg, com o qual se apresentou em recitais em Portugal e efetuou gravações para a R.D.P. – Antena 2; participou com o Ensemble D’Arcos na interpretação da obra Goldberg Variations de J.S.Bach; tocou no St.David’s Hall, Cardiff com Nephele Ensemble e foi membro do <span style="font-weight:bold">Royal Academy Soloists</span>.</p><p> </p><p>Isabel Pereira desenvolve simultaneamente uma <span style="font-weight:bold">carreira orquestral com grande prosperidade</span>. Colabora frequentemente com a <span style="font-weight:bold">London Philharmonic Orchestra</span>, Royal Opera House Orchestra, Philharmonia Orchestra, Royal Philharmonic Orchestra, London Sinfonietta, Remix Ensemble, Orquestra Gulbenkian, City of Birmingham Orchestra, BBC Scottish Symphony Orchestra entre outras e apresentou-se como chefe de naipe da Bournemouth Symphony Orchestra e da Royal Liverpool Philharmonic Orchestra. Em 2018, após quase duas décadas a viver em Londres, <span style="font-weight:bold">regressa a Portugal onde reside com a sua família</span> e desde então é convidada regularmente como <span style="font-weight:bold">Chefe de Naipe e Solista A na Orquestra Sinfónica do Porto</span> – Casa da Música e como Coordenadora Adjunta na <span style="font-weight:bold">Orquestra Sinfónica Portuguesa</span>, em Junho de 2021 ganha um lugar nesta última orquestra.</p><p> </p><p>Participou em<span style="font-weight:bold"> inúmeras digressões por todo o mundo</span>, apresentando-se nas salas principais, de destacar são: <span style="font-weight:bold">Carnegie Hall</span> em <span style="font-weight:bold">Nova Iorque</span>, Walt Disney Concert Hall em Los Angeles, Royal Festival Hall em Londres, Theatre des Champs Elysées em Paris, Conzertgebouw em Amsterdão, <span style="font-weight:bold">Musikverein</span> em <span style="font-weight:bold">Viena</span>, Palau de la Música em Barcelona, <span style="font-weight:bold">Suntory Hall</span> em <span style="font-weight:bold">Tokyo</span>entre muitas outras. Tocou nos principais festivais do mundo e todos os anos se apresenta nos Concertos Promenade <span style="font-weight:bold">BBC “Proms”</span>no Royal Albert Hall em Londres e no <span style="font-weight:bold">Glyndebourne</span>Opera Festival. Isabel colabora frequentemente com os seguintes maestros: Ricardo Mutti, Sir Colin Davis, Christoph Echenbach, Vladimir Jurovski, Gustavo Dudamel, Antonio Papano, Esa-Pekka Salonen, Kurt Masur, Charles Dutoit e solistas: Brendel, Pires, Argerich, Vengerov, Hahn, Mutter, Bell, Mork, entre muitos outros. Gravou dezenas de <span style="font-weight:bold">discos e bandas sonoras</span>sendo as mais conhecidas: <span style="font-weight:bold">O Hobbit</span> e <span style="font-weight:bold">Iron Man</span>.</p>', '<p><span style="font-weight:bold">FORMAÇÃO ARTÍSTICA</span></p><p> </p><p>- Escola Superior de Música de Lisboa – Mestrado em Ensino de Música 2019-2023 - Royal Academy of Music –Diploma de Pós-Graduação– Distinção (qualificação máxima) e atribuição de um Dip-Ram - Diploma de Excelência /Londres, Inglaterra 2004-2005 - Royal Academy of Music – Licenciatura em Música (BMus Undergraduate Course) - First Class Honours (qualificação máxima) / 2000-2004 - Licentiate Royal Academy of Music – LRAM – Diploma de Professora de Viola / 2003 - ARTAVE - Escola Profissional Artística do Vale do Ave Curso de Instrumentista de Cordas – Portugal / 1997-2000 Curso Básico Instrumentista de Cordas / 1994-1997</p><p> </p><p><span style="font-weight:bold">PRÉMIOS E BOLSAS DE ESTUDO</span></p><p> </p><p>- Hilda Wyme Memorial Award (para melhor Recital Final de Viola - RAM) / 2005 - Moir Carnegie Prize / 2005 - Bolsa de Estudo da Fundação Calouste Gulbenkian / 2000-2004 - Max Gilbert Viola Prize –Recomendação Alta - Royal Academy of Music / 2002 - Théodore Holland Viola Prize - Recomendação Muito Alta (RAM) / 2000-2001 - Bolsa de Estudo da Royal Academy of Music – Londres / 2000 - 1° Prémio em Viola no Prémio Jovens Músicos RDP –Antena 2- Portugal / 2000 - Menção Honrosa em Música de Câmara no RDP Prémio Jovens Músicos RDP / 1999</p><p> </p><p><span style="font-weight:bold">CARREIRA ORQUESTRAL</span></p><p> </p><p>Orquestra Sinfónica Portuguesa – Teatro Nacional de São Carlos – Lisboa – Membro do naipe das violas desde 2021 - Orquestra Sinfónica do Porto – Casa da Música – Chefe de Naipe Convidada /2019 presente - Orquestra Sinfónica Portuguesa – Teatro Nacional de São Carlos – Lisboa - Coordenadora Adjunta convidada /2020-2021 - Royal Liverpool Philharmonic Orchestra – Chefe de Naipe e Solista A convidada / 2013 - 2015 - Bournemouth Symphony Orchestra –Chefe de Naipe Convidada / 2011-2012 - Royal Opera House Orchestra – Música convidada regularmente/ 2015 - presente - Royal Philharmonic Orchestra- Música convidada regularmente/ 2013 - presente - London Philharmonic Orchestra – Viola Solista N°2 e N°4 e convidada regular /2009- presente - London Sinfonietta – Música convidada desde 2006 - Remix Ensemble – Casa da Música – Música convidada /2016 - presente - English National Ballet –Viola N°3 convidada/2008-2010 - Philharmonia Orchestra – / Música convidada regularmente / 2006-2009 - City of Birmigham Symphony Orchestra - Música convidada / 2007 - BBC Scottish Symphony Orchestra - Música convidada / 2006 - Oxford Philharrmonic – Música convidada - Brandenburg Sinfonia – Chefe de Naipe Adjunta convidada - London Concert Orchestra - Chefe de Naipe Adjunta convidada - London Conchord Ensemble - Chefe de Naipe Adjunta convidada - Gulbenkian Orchestra – Música convidada /2006-2006 - Royal Academy Soloists / 2004-2005 - Chefe de Naipe viola da “World Youth Orchestra and Chamber Ensemble / 2003 - Chefe de naipe e chefe de naipe adjunta nas Orquestras da Royal Academy of Music / 2000- 2004</p><p> </p><p><span style="font-weight:bold">CARREIRA A SOLO E MÚSICA DE CÂMARA</span></p><p> </p><p>Gravação e publicação do primeiro álbum discográfico de TESSITORI /2014 – Viola e Guitarra Clássica com João Loureiro Concertos com TESSITORI a destacar nas seguintes salas: São Carlos, Terras Sem Sombra 2023 St. James’s, Piccadilly parte do ILAMS Echoes Festival 2017), National Portrait Gallery (dois recitais incluídos na Exposição Picasso Portraits em 2016), The Forge, Rosslyn Hill Chapel, e National Theatre em Londres, Calouste Gulbenkian Foundation e Fábrica do Braco de Prata em Lisboa / 2003-2017 - Recitais a solo ou com piano em Inglaterra, Japão, Portugal e Espanha/ 2006-2017 - Berio Festival “Omaggio” (RAM – Southbank) intrepretando a Sequenza VI de Luciano Berio: “Isabel Pereira then performed Sequenza VI. It was poetic and vividly imagined, Pereira moving seamlessly from rough-edged percussive sounds to a voice of creamy, virtuosic intensity.” in The Strad July 2004 - Solista na obra Britten’s “Lachrimae” acompanhada pela Orquestra ARTAVE– Portugal. Concerto transmitido na Antena 2 RDP / 2001 - Concerto dos Laureados do Prémio Jovens Músicos como solista acompanhada pela Orquestra Gulbenkian Concerto transmitido na Antena 2 RDP / 2000 - Performance da obra Goldberg Variations by Bach com o Ensemble Darcos Portugal / 2006 - Recitais com um Trio da World Youth Orchestra / 2003 - Concertos integrados no “Brahms Festival” e “Lionel Tertis Viola Festival” na Royal Academy of Music / 2001-2002 - Co-Fundadora e 1ª viola do Sexteto Shoenberg com quem se apresentou várias vezes em Portugal e gravou para a Antena 2 RDP /2000-2001</p>', '<p><span style="font-weight:bold">Projetos:</span></p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.tessitorimusic.com/ target=_blank>tessitorimusic</a></span></span> - website</span></p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.smartx.art/artista/tessitori target=undefined>tessitorimusic </a></span></span>- Página da SMARTx</span></p><p> </p><p> </p><p><span style="font-weight:bold">Colaborações:</span></p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.josefarinha.com/ target=_blank>JOSÉ FARINHA (josefarinha.com)</a></span> </span> - Fotografia</span></p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://vascoduarteabranches.com/ target=_blank>Vasco Duarte Abranches – ARTIST – Filmmaking, Música e Fotografia FineArt</a></span></span></span></p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 49: Inês Vaz
INSERT IGNORE INTO users (id, email, password, role) VALUES ('5b9b7db2-b7e3-4af5-be91-39c24a9fb150', 'wix-5b9b7db2@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('c2f0c9c6-3a24-48d6-85c7-234c2f4c3a4b', '5b9b7db2-b7e3-4af5-be91-39c24a9fb150', 'ines-vaz', 'Inês Vaz', 'Inês', '999999999', '1988-07-10', 'Portugal', 'Portugal', 'xxxxx', 'xxxxxxxx', NULL, 'xxxx', 'Acordeonista', '"A música salva-nos, ligando-nos ao nosso âmago insondável."', 'https://static.wixstatic.com/media/5b9b7d_2e83d9e73a8741b89e9d54b1693f6bb6~mv2.jpg', 'wix:document://v1/5b9b7d_8d2c4545268e438dbdad7c845127d1e9.pdf/Biografia%20de%20In%C3%AAs%20Vaz.pdf', NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/5b9b7d_f565eeb159c94f90a5ec2b218009d341.mp3', NULL, NULL, 'https://youtu.be/Qj5rSGNLWvo', 'https://youtu.be/2asnE7lF62U', 'https://youtu.be/hhHS78iTzaU', 'https://youtu.be/MQlhKIRn1Nk', 'https://youtu.be/0hy9k7c-8DE', 'https://youtu.be/wPB7NiNOwjM', 'https://youtu.be/MuO7MYmS4xc', 'https://youtu.be/FyxVa7pC1og', 'https://youtu.be/rMBQNVu3aAI', NULL, '<p class="font_8" style="text-align: center">"<em><strong>Tenho uma relação de amor e de puro mistério com a música. É algo que se sente e não se explica</strong></em><strong>.</strong>" <strong>Inês Vaz</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Acordeonista de reconhecido talento, Inês Vaz é uma artista que transcende fronteiras, <strong>harmonizando o tradicional com o erudito</strong> numa expressão única que desafia as convenções. As suas melodias criam paisagens sonoras que convidam o ouvinte a embarcar numa viagem para partes desconhecidas da própria alma.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">A sua carreira musical é fruto de um <strong>compromisso profundo com a arte</strong> e a sua mestria abrange diversos estilos, mas é na <strong>música clássica e de câmara</strong> que encontra o seu mais elevado expoente.&nbsp;Divide a sua vida entre o ensino de acordeão e piano, performance e composição.</p>
<p class="font_8"><br></p>
<p class="font_8">Depois de "<a href="https://inesvaz.lojasonlinectt.pt/product/timeless-suite" target="_blank"><u><strong>Timeless Suite</strong></u></a>" em 2021, lançou o seu segundo álbum "<a href="https://emubands.ffm.to/petala?fbclid=IwZXh0bgNhZW0CMTAAAR0Xo0JWQV-59xFkNa4zGMJ4F5617dyb9lz7pphlDV4Kb23qPYwoVpeSNvw_aem_AXb7_I2PjcdrlrjgDnTCbxtxT0qp3iLwnN0hnYs6_R4p34qXk1nqHttLzaxCqxcyiCLRPmt1tK_v8ukjLSQ2_Esg" target="_blank"><u><strong>Pétala</strong></u></a>", em 2024.</p>', '<p class="font_8">Inês Vaz começou a tocar acordeão com apenas seis anos, quando iniciou os estudos musicais com o Professor José António Sousa, na <strong>Escola de Música Semibreve</strong>. A paixão pelo estilo clássico / contemporâneo levou-a a prosseguir os <strong>estudos em Música de Câmara com o Professor Paulo Jorge Ferreira</strong>. Devido ao seu crescente interesse pelo Jazz, também estudou <strong>harmonia e improvisação com os Professores António Palma e Victor Prieto</strong>.</p>
<p class="font_8"><br></p>
<p class="font_8">Apesar de se ter licenciado em Ciências Farmacêuticas, Inês nunca abandonou a música, e, em 2011, decidiu fazer da música a sua única profissão. Desde então, tem-se apresentado ao vivo como solista em palcos nacionais e internacionais e colaborado como solista com a <strong>Orquestra e Coro Gulbenkian</strong> e a <a href="https://camerataatlantica.pt/" target="_blank"><u><strong>Camerata Atlântica</strong></u></a>.</p>
<p class="font_8"><br></p>
<p class="font_8">Atuou como acordeonista e bandoneonista em vários concertos ao vivo de <strong>Donna Maria, Seda e Flor de Lis</strong>, assegurando também a produção e composição musical destes projetos musicais. Fez parte do duo "<a href="https://youtube.com/playlist?list=OLAK5uy_nTksiJNvlsL108JRvlmokM6TFyGSIABzI&amp;si=04IUoebftyYMjw7o" target="_blank"><u><strong>Ciranda</strong></u></a>" com o trompetista Gileno Santana, e participou como acordeonista em vários concertos do aclamado músico português <strong>Vitorino </strong>e do <strong>projeto "Salvador Sobral canta Brel"</strong>, de Salvador Sobral, vencedor do Festival Eurovisão da Canção 2017.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2021, lançou "<a href="https://inesvaz.lojasonlinectt.pt/product/timeless-suite" target="_blank"><u><strong>Timeless Suite</strong></u></a>", o seu primeiro disco a solo, e em 2024 lançou "<a href="https://emubands.ffm.to/petala?fbclid=IwZXh0bgNhZW0CMTAAAR0Xo0JWQV-59xFkNa4zGMJ4F5617dyb9lz7pphlDV4Kb23qPYwoVpeSNvw_aem_AXb7_I2PjcdrlrjgDnTCbxtxT0qp3iLwnN0hnYs6_R4p34qXk1nqHttLzaxCqxcyiCLRPmt1tK_v8ukjLSQ2_Esg" target="_blank"><u><strong>Pétala</strong></u></a>" o seu segundo álbum. É compositora de vários originais, como "Timeless", "Waiting Room" e "Ítaca", cujas partituras estão disponíveis para <a href="https://inesvaz.com/#partituras" target="_blank"><u><strong>compra</strong></u></a>.</p>
<p class="font_8"><br></p>
<p class="font_7" style="text-align: center">"<em><strong>Através da música conseguimos aceder a sensações e emoções que em circunstâncias normais teríamos dificuldade em compreender ou lidar.</strong></em>" <strong>Inês Vaz</strong></p>
<p class="font_7">&nbsp;</p>', '<p style="text-align:justify">Inês já se apresentou ao vivo como solista em concertos em diversos países, como Alemanha, Áustria, Canadá, Espanha, França, Inglaterra, Noruega, Suécia, Polónia, República Checa, Rússia e Taiwan.</p><h2> </h2><h3 style="text-align:justify"><span style="font-weight:bold">PRÉMIOS</span></h3><h2> </h2><p style="text-align:justify">2019 - 1º Lugar no Smooth FM Jazz Contest com a cantora Camila Masiso</p><p style="text-align:justify">2016 - 3º Lugar no Concurso Folefest com &quot;Stormy Duo&quot;</p><p style="text-align:justify">2003 - 1º Lugar no Concurso Nacional de Acordeão em Alcobaça (Categoria Juvenil Concerto)</p><p style="text-align:justify">2000 - 1º Lugar no Concurso Nacional de Acordeão em Alcobaça (Categoria Infantil)</p><h2> </h2><h3 style="text-align:justify"><span style="font-weight:bold">COLABORAÇÕES E PARCERIAS</span></h3><h2> </h2><p style="text-align:justify">- Donna Maria</p><p style="text-align:justify">- Duo Ciranda com Gileno Santana (trompete)</p><p style="text-align:justify">- MOTIV com Múcio Sá (guitarra portuguesa) e Miguel Majer (percussão)</p><p style="text-align:justify"><span style="text-decoration:underline">- <span style="text-decoration:underline"><a href=https://www.facebook.com/velvetquintet target=_blank>Velvet Quintet</a></span></span> com Francisco Ramos (violino), Clara Gomes (violino), João Paulo Gaspar (viola d&#x27;arco) e Joana Correira (violoncelo)</p><p style="text-align:justify">- Concerto &quot;As 4 Estações&quot; de Vivaldi em duo com Pedro Santos (acordeão)</p><h2> </h2><h3 style="text-align:justify"><span style="font-weight:bold">LINHA DO TEMPO</span></h3><h2> </h2><p style="text-align:justify"><span style="font-weight:bold">2024 </span>- Lançamento do segundo disco a solo &quot;Pétala&quot;, com o apoio da Sociedade Portuguesa de Autores (SPA) e Antena 2.</p><p style="text-align:justify"><span style="font-weight:bold">2021 </span>- Lançamento do primeiro trabalho a solo &quot;Timeless Suite&quot;, editado pela Jugular Publishing.</p><p style="text-align:justify"><span style="font-weight:bold">2020</span>-presente</p><p style="text-align:justify">Participação como acordeonista no projeto &quot;Salvador Sobral canta Brel&quot;;</p><p style="text-align:justify">Participação no documentário &quot;In Music&quot; da RTP2.</p><p style="text-align:justify"><span style="font-weight:bold">2019</span></p><p style="text-align:justify">- Co-produção do disco &quot;Plasticidades&quot; com Donna Maria;</p><p style="text-align:justify">- 1º Lugar no Smooth FM Jazz Contest com a cantora Camila Masiso;</p><p style="text-align:justify">- Estreia da peça &quot;Luto&quot; no Prémio de Composição de Acordeão.</p><p style="text-align:justify"><span style="font-weight:bold">2018</span>-presente</p><p style="text-align:justify">- Formou o Velvet Quintet (Acordeão e Bandoneon com quarteto de cordas).</p><p style="text-align:justify">- Participou como acordeonista em concertos do Coro Gulbenkian</p><p style="text-align:justify"><span style="font-weight:bold">2017 </span>- Formou o duo Ciranda (Acordeão e Trompete) com Gileno Santana (trompete).</p><p style="text-align:justify"><span style="font-weight:bold">2016-2017</span></p><p style="text-align:justify">- Participou como solista em vários festivais e concertos;</p><p style="text-align:justify">- Formou o Trio MOTIV (Acordeão, guitarra portuguesa e percussão);</p><p style="text-align:justify">- 3º Lugar no Concurso Folefest com &quot;Stormy Duo&quot;.</p><p style="text-align:justify"><span style="font-weight:bold">2015 </span>- Formou o duo &quot;Stormy Duo&quot; (Acordeão e Fagote).</p><p style="text-align:justify"><span style="font-weight:bold">2013-2019</span> - Participou como acordeonista na Tour Dona Rosa por vários países</p><p style="text-align:justify"><span style="font-weight:bold">2013</span></p><p style="text-align:justify">- Formou a Orquestra Típica Milongueira de Lisboa;</p><p style="text-align:justify">- Fez o Curso Online de Introdução à Improvisação pela Berklee College of Music.</p><p style="text-align:justify"><span style="font-weight:bold">2012</span></p><p style="text-align:justify">- Participou em peças de teatro e co-produziu discos com os projetos Seda e Donna Maria;</p><p style="text-align:justify">- Co-autora do tema &quot;Amor a Preto e Branco&quot; para o Festival da Canção;</p><p style="text-align:justify">- Participou na banda sonora ao vivo da peça &quot;O Fantasma de Chico Morto&quot;.</p><p style="text-align:justify"><span style="font-weight:bold">2011</span></p><p style="text-align:justify">- Concluiu o Mestrado Integrado em Ciências Farmacêuticas pelo Instituto Superior de Ciências da Saúde Egas Moniz;</p><p style="text-align:justify">- Participou como acordeonista na peça de teatro &quot;A Mãe&quot; de Bertolt Brecht no Teatro da Trindade;</p><p style="text-align:justify">- Participou na gravação do disco &quot;Dança do Centro&quot; de Joana Melo;</p><p style="text-align:justify">- Iniciou atividade como professora de acordeão e piano na Academia de Música Desafios, que manteve até 2021.</p><p style="text-align:justify"><span style="font-weight:bold">2010 </span>- Participou como artista convidada na semi-final e final do programa &quot;Aqui há Talento&quot; da RTP.</p><p style="text-align:justify"><span style="font-weight:bold">2009 </span>- Participou na gravação do disco &quot;SEDA&quot; do projeto SEDA.</p><p style="text-align:justify"><span style="font-weight:bold">2008 e 2011</span> - Participou no Festival da Canção da RTP.</p><p style="text-align:justify"><span style="font-weight:bold">2007-2011</span></p><p style="text-align:justify">- Acordeonista/Bandoneonista nos projetos Donna Maria, Seda e Flor de Lis;</p><p style="text-align:justify">- Pianista no Coro Académico Egas Moniz.</p><p style="text-align:justify"><span style="font-weight:bold">2006</span></p><p style="text-align:justify">- Juntou-se aos Donna Maria como acordeonista;</p><p style="text-align:justify">- 11º Lugar na Copa Mundial de Acordeão em Asker, Noruega (Categoria Júnior Concerto);</p><p style="text-align:justify">- Iniciou o Mestrado Integrado em Ciências Farmacêuticas no Instituto Superior de Ciências da Saúde Egas Moniz.</p><p style="text-align:justify"><span style="font-weight:bold">2005</span></p><p style="text-align:justify">- Participou na Coupe Mondiale de Acordeon em Castelo Branco (categoria Junior Concerto);</p><p style="text-align:justify">- Participou no programa &quot;Diver(c)idades&quot; da RTPi, interpretando &quot;Bulgarian Notebook in 8 parts&quot; de Vladimir Zubitsky.</p><p style="text-align:justify"><span style="font-weight:bold">2003</span></p><p style="text-align:justify">- 1º Lugar no Concurso Nacional de Acordeão em Alcobaça (Categoria Juvenil Concerto);</p><p style="text-align:justify">- 9º Lugar na Copa Mundial de Acordeão em Castelo Branco (Categoria Júnior Concerto).</p><p style="text-align:justify"><span style="font-weight:bold">2000</span></p><p style="text-align:justify">- 1º Lugar no Concurso Nacional de Acordeão em Alcobaça (Categoria Infantil);</p><p style="text-align:justify">- Participou no programa &quot;Meninos de Ouro&quot; da TVI, interpretando &quot;Libertango&quot; de Astor Piazzolla.</p><p style="text-align:justify"><span style="font-weight:bold">1994-2006</span> - Estudou Acordeão de Concerto, Formação Musical e outras disciplinas na Escola de Música Semibreve.</p>', '<h3><span style="font-weight:bold">ÁLBUNS</span></h3><h2> </h2><h3>&quot;<span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://inesvaz.lojasonlinectt.pt/product/timeless-suite target=_blank>Timeless Suite</a></span></span>&quot; (2011)</h3><h2> </h2><p>Este trabalho, lançado pela Jugular Publishing, com o apoio da Antena 2 e da Sociedade Portuguesa de Autores, representa a estreia de Inês Vaz como compositora. Mais do que um álbum, &quot;Timeless Suite&quot; é um encontro intemporal que une compositores de diferentes épocas, desde Bach a Camille Saint-Saens, Beethoven, Gismonti, Scarlatti e Rossini. Foi concebido para realçar a riqueza sonora do acordeão e os múltiplos universos musicais que este versátil instrumento pode conter. É o veículo através do qual Inês faz &quot;ouvir a sua voz&quot; e se expressa por meio do acordeão, convidando o ouvinte a viajar por esses mundos distintos.</p><h3> </h3><p>A faixa-título &quot;Timeless&quot; é uma das duas composições originais, juntamente com &quot;Waiting Room&quot;. O processo criativo por trás dessas obras autorais surgiu de forma espontânea e quase inconsciente, impulsionado por inspirações que vagueavam até se materializarem em música, como sugerido pelo seu mentor José Cardoso.</p><p> </p><p>Na faixa &quot;Waiting Room&quot;, Inês foi instigada a imaginar uma sala de espera e tudo o que ela pode evocar em termos de sensações e emoções. Essa capacidade de traduzir abstrações em criações musicais revela a sensibilidade e profundidade artística presentes em &quot;Timeless Suite&quot;.</p><h2> </h2><h3>&quot;<span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://emubands.ffm.to/petala?fbclid=IwZXh0bgNhZW0CMTAAAR0Xo0JWQV-59xFkNa4zGMJ4F5617dyb9lz7pphlDV4Kb23qPYwoVpeSNvw_aem_AXb7_I2PjcdrlrjgDnTCbxtxT0qp3iLwnN0hnYs6_R4p34qXk1nqHttLzaxCqxcyiCLRPmt1tK_v8ukjLSQ2_Esg target=_blank>Pétala</a></span></span>&quot; (2024)</h3><h2> </h2><p>O segundo álbum solo de Inês Vaz, &quot;Pétala&quot;, é uma jornada poética e sensorial através de melodias delicadas que flutuam como pétalas suspensas no ar. Foi apresentado em exclusivo na Antena 2 em 27 de fevereiro de 2024 e foi lançado a 10 de maio. O título &quot;Pétala&quot; tem inspiração no poema de Maria Teresa Horta que termina com os versos &quot;Pétala, após pétala, após pétala, até chegar a mim&quot;. É a partir dessa imagem etérea e frágil que Inês Vaz constrói a narrativa imaginada para o álbum - a descrição da trajetória de uma pétala em seu sentido metafórico. Essa pétala pode ser vista como nós mesmos no mundo, ou então cada uma das camadas mais profundas do nosso interior. O convite é para que cada ouvinte trace seu próprio percurso particular enquanto as pétalas musicais vão se desfolhando uma a uma - &quot;pétala, após pétala&quot;. O albúm promete ser uma experiência singular, flutuando por tempos passados, presentes e futuros através do poder evocativo e onírico da música da acordeonista.</p><h2> </h2><p><span style="font-weight:bold">OPINIÃO</span></p><h3> </h3><p>&quot;A Inês lança uma pétala que quase conseguimos tatear entre os dedos. Sugere-nos uma viagem que nos implica a escapar tanto mais para dentro, enquanto navegamos o que é de fora. Faz brotar distâncias interiores. Lança uma pétala: matéria frágil entre a aspereza dos dias. Convoca cor e forma, para logo de seguida a dissolver, como uma experiência que vivemos e somente a memória – essa frágil membrana de sensações – consegue amparar. Delicada e sensível esta forma de tecer pétalas com a ponta dos dedos, entre uma melodia que é sopro e fogo a esculpir emoções.&quot; <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://antena2.rtp.pt/em-antena/concertos-antena-2/ines-vaz-27-fevereiro-19h00/ target=_blank>Ana Lázaro</a></span></span></p><h2> </h2><h3><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h3><h2> </h2><h3><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/ines_vaz target=_blank>PorART Entrevista</a></span></span>: Inês Vaz - A história de uma acordeonista prestigiada</h3><h3><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.strumentiemusica.com/in-evidenza/la-comunicazione-universale-e-trascendentale-della-musica/ target=_blank>Entrevista Strumenti &amp; Musica (2022)</a></span></span>: La comunicazione universale e trascendentale della musica. Lo spirito di aggregazione musicale secondo Inês Vaz</h3><h3><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.rtp.pt/programa/tv/p39243/e6 target=_blank>Entrevista InMusic / RTP</a></span></span>: Acordeão - Inês Vaz</h3><h3><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://marta-omeucanto.blogs.sapo.pt/a-conversa-com-os-donna-maria-922143 target=_blank>Entrevista Blog &quot;O Meu Canto&quot; (2019)</a></span></span>: À Conversa com os Donna Maria</h3><h3> </h3><h3>Quer saber mais?</h3><h3>Entre em contacto connosco!</h3>', 'https://static.wixstatic.com/media/5b9b7d_617af2c6a4874853887d11e613f8428a~mv2.jpg', 'Créditos Inês Viegas', 'https://static.wixstatic.com/media/5b9b7d_bd1a4fd2b3d342d6a4a8de3a4062ed4c~mv2.jpg', NULL, 'https://static.wixstatic.com/media/5b9b7d_3bcb87fbaca24a4889e548ba856428bb~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 50: Gisela Sachse
INSERT IGNORE INTO users (id, email, password, role) VALUES ('0b297d12-1064-447b-aae7-02af3f78d037', 'wix-0b297d12@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('b5aeb96b-3c27-4f0c-a3b8-a47b0e0e0b5d', '0b297d12-1064-447b-aae7-02af3f78d037', 'gisela-sachse', 'Gisela Sachse', 'Gisela', '917752623', '1982-03-01', 'Portugal', 'Portugal', 'Vila Nova de Gaia', 'Rua de Mariz, 104 Vilar de Andorinho', NULL, '4430-276', 'Mezzo soprano de coloratura', 'O meu corpo é morada de múltiplas personagens. O meu gesto dá-lhes vida e a minha voz alma.', 'https://static.wixstatic.com/media/0b297d_2c59ee4ca2904b108b278893b808e5f2~mv2.jpg', 'wix:document://v1/0b297d_4209c199b78449c79cb257b57bacbd36.docx/curric.%20Gisela%20Sachse.docx', 'https://www.facebook.com/gisela.sachsemezzo', NULL, NULL, NULL, 'https://www.youtube.com/@giselasachsemezzo', 'https://static.wixstatic.com/mp3/7b859e_2f54cde023ad4c7c8eff879bea3d9b57.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=IARax9BzEg4', 'https://www.youtube.com/watch?v=EWejarzSjD0', 'https://www.youtube.com/watch?v=uDYBY_99U04', 'https://www.youtube.com/watch?v=OfC99lbVT1E', NULL, NULL, NULL, NULL, NULL, NULL, '<p><span style="font-weight:bold">Gisela Sachse</span> é uma talentosa <span style="font-weight:bold">meio-soprano</span> <span style="font-weight:bold">portuguesa </span>que tem cativado públicos nos principais palcos de Portugal com a sua voz expressiva e presença magnética no palco.</p><p> </p><p>Com um repertório impressionante que abrange desde os clássicos de Mozart até obras contemporâneas, demonstra uma notável versatilidade vocal e um reconhecido talento interpretativo, que lhe têm permitido brilhar numa ampla gama de papéis, como <span style="font-weight:bold">Dorabella</span> em <span style="font-style:italic">Cosi fan tutte</span>, <span style="font-weight:bold">Rosina </span>em <span style="font-style:italic">Il Barbiere di Siviglia</span>, <span style="font-weight:bold">Suzuki </span>em <span style="font-style:italic">Madama Butterfly</span>, entre muitos outros.</p><p> </p><p>Um dos pontos altos da sua carreira foi a estreia no papel de <span style="font-weight:bold"><span style="font-style:italic">Camen </span></span>na ópera homónima de Bizet no Coliseu do Porto, em 2023.</p><p> </p><p>Caracteriza-se pela sua entrega emocional e pelo refinamento musical. Além das suas aclamadas performances operísticas, Sachse também é uma intérprete de concerto altamente requisitada. Como solista no campo da oratória, fazem parte do seu repertório diversas obras prestigiadas, como Requiem de Mozart, Stabat Mater de Dvorak ou Messias de Handel.</p>', '<p><span style="font-weight:bold">Gisela Sachse</span> é natural de <span style="font-weight:bold">Vila Nova de Gaia</span>, onde deu os seus primeiros passos no mundo da música ao iniciar os seus estudos em 1998 no curso de Viola Dedilhada, sob a orientação do Prof. Ricardo Barceló, tendo concluído o 8º grau.</p><p> </p><p>A sua paixão pela música e pelo canto levou-a a procurar uma formação sólida na área. É licenciada e mestre em Canto Teatral pela Fundação Conservatório Superior de Gaia, onde estudou sob a orientação da Professora Fernanda Correia. Além disso, também possui uma licenciatura em Estudos Europeus e Relações Internacionais pela Universidade Moderna do Porto, demonstrando a sua dedicação não só à arte, mas também ao conhecimento académico.</p><p> </p><p>Sempre em busca de aperfeiçoar a sua técnica e expressão artística, participou em vários cursos e aulas de aperfeiçoamento vocal ao longo da sua carreira. Teve a oportunidade de estudar com professores renomados como <span style="font-weight:bold">Enza Ferrari</span> e <span style="font-weight:bold">Ambra Vespasiani</span> em seminários e masterclasses. Também estudou técnica vocal e repertório com o maestro <span style="font-weight:bold">Marc Tardue</span> e com o tenor <span style="font-weight:bold">Paulo Ferreira</span>, dois nomes respeitados no meio operático. Atualmente, continua o seu desenvolvimento artístico sob a orientação da soprano Palmira Troufa.</p><p> </p><p>O talento de Gisela Sachse começou a ser reconhecido ainda no início da sua carreira. Em dezembro de 2015, foi finalista do concurso Luísa Todi Jovens Músicos, uma importante competição para jovens cantores líricos em Portugal. Além disso, também participou em concursos internacionais de renome, como o Concurso Internacional de Canto Montserrat Caballé e o Concurso Francisco Viñas. Estas experiências foram fundamentais para impulsionar a sua carreira e abrir portas para novas oportunidades.</p>', '<p><span style="font-weight:bold">🎭 Papéis Operísticos:</span></p><p> </p><ul><li>Drei Knabe e Drei Dame em Die Zauberflote (Mozart);</li><li>Cherubino e Marcelina em Le nozze di Figaro (Mozart);</li><li>Dorabella em Cosi fan tutte (Mozart);</li><li>Donna Elvira em Don Giovanni (Mozart);</li><li>Mercedes em Carmen (Bizet);</li><li>Berta e Rosina em Il Barbiere di Siviglia (Rossini);</li><li>Charlotte em Werther (Massenet);</li><li>Orsini em Lucrezia Borgia (Donizetti);</li><li>Flora em La Traviata (Verdi);</li><li>Suzuki em Madama Butterfly (Puccini);</li><li>Dalila em Sansão e Dalila (Saint-Saëns);</li><li>Mamma Lucia e Lola em Cavalleria Rusticana (Mascagni).</li></ul><p> </p><p>🌟 Um destaque especial na sua carreira foi o debut no papel-título de Carmen de Bizet em setembro de 2023 no Coliseu do Porto.</p><p> </p><p><span style="font-weight:bold">🎼 Repertório de Concerto:</span></p><p> </p><ul><li>Missa da Coroação e Requiem de Mozart;</li><li>Gloria de Vivaldi;</li><li>Stabat Mater de Pergolesi;</li><li>Messias de Handel;</li><li>Missa in Augustiis de Haydn;</li><li>9ª Sinfonia de Beethoven;</li><li>Oratório de Natal de Saint-Saëns;</li><li>Stabat Mater de Dvorak;</li><li>Stabat Mater de Karl Jenkins (primeira interpretação em Portugal);</li><li>Requiem de Verdi.</li></ul><p> </p><p><span style="font-weight:bold">🏆 Participações em Concursos:</span></p><p> </p><ul><li>Finalista do Concurso Luísa Todi Jovens Músicos (dezembro de 2015);</li><li>Participou nos Concursos Internacionais de Canto Montserrat Caballé e Francisco Viñas.</li></ul><p> </p><p><span style="font-weight:bold">✨ Outras Realizações:</span></p><p> </p><ul><li>Apresentou-se nas principais salas de espetáculo de Portugal;</li><li>Interpretou a obra Meditazione di Natale de Michele Varriale, pela primeira vez em Portugal, dirigida pelo próprio compositor.</li></ul>', '<p class="font_8"><strong>Notícias &amp; Entrevistas</strong></p>
<p class="font_8"><br></p>
<p class="font_8"><a href="https://www.jn.pt/4141727087/coliseu-porto-estreia-hoje-uma-nova-carmen/"><u>JN (2023)</u></a> - Coliseu Porto estreia hoje uma nova "Carmen"</p>
<p class="font_8"><br></p>
<p class="font_8"><a href="https://expresso.pt/cultura/2021-09-22-Cavalleria-Rusticana-um-drama-siciliano-em-Lisboa-2d22adf4"><u>Expresso (2021)</u></a> - “Cavalleria Rusticana”: um drama siciliano em Lisboa</p>
<h5 class="font_5"><br></h5>', 'https://static.wixstatic.com/media/0b297d_24f6a877937e4259822e51b1c621c1e5~mv2.jpg', 'La Traviata (Flora-2018)', 'https://static.wixstatic.com/media/0b297d_6226000b3c9e47ad924e4d9c3dc1e3b4~mv2.jpeg', 'Madama Butterfly(Suzuki-2019)', 'https://static.wixstatic.com/media/0b297d_fc99227cec684deea6bd97c67bf1e31c~mv2.jpg', 'Cavalleria Rusticana (Lola-2021)', 'https://static.wixstatic.com/media/0b297d_f3f16d5bc9db4c53966d1f472bce97eb~mv2.jpeg', 'Sansão e Dalila(Dalila-2022)', 'https://static.wixstatic.com/media/0b297d_b2c0406032c04cb8b184e6333fe6e968~mv2.jpeg', 'Sansão e Dalila(Dalila-2022)', 'https://static.wixstatic.com/media/0b297d_6d80fafda8f94c7fa840973a0f0d4ac4~mv2.jpg', 'Carmen (Carmen-2023)', 'https://static.wixstatic.com/media/0b297d_3edd16e20d9446208ed7e9d1dd97cce6~mv2.jpg', 'Carmen (Carmen-2023)', 'https://static.wixstatic.com/media/0b297d_2ad3e2671c2945f4b0f695d0a1a56ea5~mv2.jpg', 'Carmen (Carmen-2023)', 'https://static.wixstatic.com/media/0b297d_3f9f8c0940994835ac14197a6da1a644~mv2.jpg', 'Carmen (Carmen-2023)', NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 51: Samuel Marques
INSERT IGNORE INTO users (id, email, password, role) VALUES ('fc8a5273-d65c-459b-befb-3c404996a485', 'wix-fc8a5273@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('9f5ac6c3-7ba9-46b8-960c-2baca824e6a0', 'fc8a5273-d65c-459b-befb-3c404996a485', 'samuel-marques', 'Samuel Marques', 'Samuel', '917055623', '1992-01-24', 'Portugal', 'Portugal', 'Aveiro', 'Travessa Comandante Rocha e Cunha, 2 N', NULL, '3800-136', 'Clarinetista', 'A contribuir com a minha música para a arte de viver, um dia de cada vez.', 'https://static.wixstatic.com/media/7b859e_22c99822311341e7b312a84448ce6f24~mv2.jpg', 'wix:document://v1/fc8a52_dbaf444fc6854a83ad06bf52e49cac78.pdf/Biografia%20(PT).pdf', 'https://www.facebook.com/samuelbrandaomarques', 'https://www.instagram.com/samuelbrandaomarques/', NULL, 'https://open.spotify.com/intl-pt/artist/2CNbrj0b58250Xc6qMaLYv?si=5PuhQEmuTSOXFTpvB6prHw', 'https://www.youtube.com/user/SamuelClarinet', 'https://static.wixstatic.com/mp3/fc8a52_d295fe2e2c244aa984e3f53c1d957ab3.mp3', NULL, NULL, 'https://youtu.be/i0mal-ozu1U?si=YNPBG8DTTaUENURs', 'https://youtu.be/fmpnNkO2C6Q?si=6f0Km52q0WOBW1fE', 'https://www.youtube.com/watch?v=8DmBIYPs4LU', 'https://www.youtube.com/watch?v=Gw6vl6FKZps', 'https://youtu.be/WKNTI6xYAzs?si=qgYYw9q3EbYMjOJK', 'https://youtu.be/GmskcofKxFA?si=PA3G94_vZj2Lxv5X', 'https://youtu.be/4bUDue_N8y0?si=HrcycgDshxRYeZqG', 'https://youtu.be/8EbhydNkQD4?si=ffRQjX8LqYMuw8gX', 'https://youtu.be/iTbJvrENMWc?si=zCO-_LCQOZUXj8-U', 'https://youtu.be/uzj2GKkI2PM?si=u2483dpjS_WLZHvl', '<p class="font_8">Samuel Marques é um clarinetista português que se tem destacado no panorama nacional e internacional pela sua carreira marcada pela diversidade. Desde cedo que a sua curiosidade e aptidão musical se evidenciaram, levando-o a percorrer palcos desde Portugal ao resto da Europa, dos Estados Unidos à China.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Movido pela sua incessante vontade de cativar novos públicos, tem-se multiplicado em concertos, sejam eles a solo, com orquestra ou em formações de música de câmara, evidenciando um especial prazer pelos concertos cujos programas pode construir de raíz, permitindo assim uma contínua e cuidada reflexão acerca da relação entre o músico e o ouvinte.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Não se negando a nenhum desafio, e refletindo a sua versátil e ativa carreira, Samuel pode ser visto e ouvido a interpretar repertório desde o Barroco ao Contemporâneo, com especial interesse em promover a música portuguesa.</p>
<p class="font_8"><br></p>
<p class="font_8"><em><strong>"O Samuel é uma pessoa de bom carácter e talento excecional".</strong></em><strong> (Stanley Drucker, antigo Clarinete Principal da New York Philharmonic)</strong></p>
<p class="font_8"><br></p>', '<p class="font_8"><strong>O INÍCIO</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>1992.</strong> Nascido em Salreu, uma pequena freguesia do concelho de Estarreja, distrito de Aveiro, numa família sem ligações às artes, poder-se-á portanto dizer que a música apareceu na vida de Samuel de uma forma quase <strong>instintiva</strong>. Aos 5 anos de idade, sob nenhuma outra influência que não a da sua força de vontade, iniciou os seus estudos musicais na banda filarmónica local, a Banda Visconde de Salreu.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">A partir daí, seguiram-se os estudos com o professor Nelson Aguiar no Conservatório de Música de Aveiro Calouste Gulbenkian. Desde cedo que o seu trabalho e dedicação produziram frutos, resultando em diversos <strong>prémios em concursos nacionais</strong>, e conquistando a atenção de diversas personalidades do meio musical português. Surgiu assim a oportunidade de estudar com o professor António Saiote, a maior referência do Clarinete em Portugal, na ESMAE - Escola Superior de Música, Artes e Espetáculo do Porto. Isto tudo quando Samuel contava com<strong> apenas 16 anos de idade</strong>.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>A DECISÃO</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Um percurso que, à primeira vista, poderia parecer muito fácil e óbvio, foi na verdade o oposto, já que o jovem Samuel sempre manteve <strong>diversos interesses</strong> e por isso prosseguiu estudos na área das Ciências ao mesmo tempo que construía o seu caminho na Música.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>2009. O ano de todas as decisões.</strong> A concluir o Ensino Secundário na área de Ciências em Estarreja, o 8º Grau do Conservatório em Aveiro, e a frequentar ainda o 1º ano da Licenciatura em Clarinete no Porto, tornou-se crucial optar por apenas um caminho.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>DE AVEIRO A NOVA IORQUE</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>A música falou mais alto</strong>, e é assim que Samuel conclui a Licenciatura e os seus estudos com o professor António Saiote, cuja influência o levou a um <strong>salto inesperado</strong>...para o outro lado do Atlântico.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>2011.</strong> Admitido no Mestrado em Performance Instrumental na Steinhardt School da New York University, <strong>aos 19 anos</strong> Samuel arrisca uma mudança de vida e vai viver para os <strong>Estados Unidos</strong>, movido pela vontade de aprender mais, pela expectativa do desconhecido e pela ânsia em cumprir <strong>novos sonhos</strong> e objetivos. Torna-se deste modo um dos últimos alunos do lendário professor Stanley Drucker, antigo Clarinetista Principal da mítica Orquestra Filarmónica de Nova Iorque (New York Philharmonic) e um músico de renome mundial.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Desde tocar no famoso <strong>Carnegie Hall</strong>, a tocar com a mundialmente reconhecida mezzo-soprano Joyce DiDonato na apresentação do seu CD, a escalar montanhas no Colorado, ou mesmo a sobreviver ao furacão Sandy que abalou Nova Iorque em 2012, muitas foram as aventuras e peripécias na "Cidade que nunca dorme" e nas terras do "Sonho americano".</p>', '<p class="font_8">Samuel Marques é um dos músicos mais versáteis e ativos da sua geração, contando com uma carreira amplamente aclamada e recheada de diversos pontos de interesse, dos quais se destacam os seguintes:</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>PRÉMIOS</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8"><strong>Vencedor</strong>, Grande Prémio do 3º Concurso Internacional José Massarrão</p></li>
  <li><p class="font_8"><strong>1º Prémio</strong>, 6º Concurso Internacional de Sopros do Alto Minho</p></li>
  <li><p class="font_8"><strong>1º Prémio</strong>, VII Concurso Nacional de Jovens Clarinetistas da <em>Associação Portuguesa do Clarinete</em></p></li>
  <li><p class="font_8"><strong>Vencedor</strong>, IMKA Grand Prix Concert Competition (Bósnia e Herzegovina)</p></li>
  <li><p class="font_8"><strong>Vencedor</strong>, II Joven Artista Iberoamericano (Peru)</p></li>
  <li><p class="font_8"><strong>Vencedor</strong>, New York University Winds Concerto Competition (EUA)</p></li>
  <li><p class="font_8"><strong>2º Prémio</strong>, Prémio Jovens Músicos 2011, Categoria Música de Câmara - nível Superior</p></li>
  <li><p class="font_8"><strong>1º Prémio</strong>, High School Competition da <em>International Clarinet Association </em>(EUA)</p></li>
  <li><p class="font_8"><strong>Menção “David Russell”</strong>, Premios Honoríficos “David Russell” para Jovenes Talentos (Espanha)</p></li>
  <li><p class="font_8"><strong>3º Prémio</strong>, 2º Concurso Internacional de Música de Câmara “Cidade de Alcobaça”</p></li>
</ul>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>VIVÊNCIAS MARCANTES</strong>&nbsp;</p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">Vencedor da audição para 2º Clarinete - Solista B da Orquestra Clássica do Centro (2022)</p></li>
  <li><p class="font_8">Gravação a solo com a Royal Scottish National Orchestra, em Glasgow, Escócia (2022)</p></li>
  <li><p class="font_8">Concerto com a mezzo-soprano Joyce DiDonato, no lançamento do seu CD ''Stella di Napoli'' (2014)</p></li>
  <li><p class="font_8">Concertos no Carnegie Hall, com a New York Youth Symphony (2013/2014)</p></li>
  <li><p class="font_8">Digressão pela Alemanha com a International Mahler Orchestra, incluindo concertos nas míticas salas de espetáculo Philharmonie Berlin e Philharmonie Köln</p></li>
</ul>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>COLABORAÇÕES E PARCERIAS</strong></p>
<p class="font_8">&nbsp;</p>
<ul class="font_8">
  <li><p class="font_8"><strong>Colaboração com orquestras e ensembles nacionais: </strong>Orquestra Gulbenkian, Orquestra Sinfónica Portuguesa, Orquestra Sinfónica do Porto Casa da Música, Remix Ensemble Casa da Música, Orquestra Clássica do Centro, Orquestra Filarmonia das Beiras, Orquestra do Algarve, Orquestra Filarmónica Portuguesa, Orquestra de Câmara Portuguesa, Orquestra de Câmara de Cascais e Oeiras, Orquestra XXI, Ensemble Darcos, Ensemble Melleo Harmonia, Americantiga Ensemble</p></li>
  <li><p class="font_8"><strong>Colaboração com orquestras estrangeiras:</strong> Mannheimer Philharmoniker (Alemanha), Höri Musiktage Bodensee Festival Orchester (Alemanha), Ceuta International Symphony Orchestra (Espanha), National Chamber Orchestra of Armenia (Arménia), Atlantic Music Festival Orchestra (EUA), National Repertory Orchestra (EUA), International Mahler Orchestra (Alemanha)</p></li>
  <li><p class="font_8"><strong>Solista com as orquestras:</strong> Orquestra Clássica do Centro, Orquestra Filarmonia das Beiras, Ensemble de Clarinetes da Universidade de Aveiro, National Repertory Orchestra, New York University Symphony Orchestra</p></li>
  <li><p class="font_8"><strong>Masterclasses: </strong>Alexander Arutiunian International Wind Festival (Arménia), Conservatório de Música de S. José da Guarda, Master Classe &amp; Estágio de Orquestra da Guia, Banda Bingre Canelense, União Filarmónica do Troviscal, Festival de Música da Bendada</p></li>
  <li><p class="font_8"><strong>Duo com o pianista Vasyl Tsanko: </strong>concertos em Portugal e Itália, incluindo a Final do concurso ''Premio Amici della Musica di Verona''</p></li>
  <li><p class="font_8"><strong>Prisma Quintet:</strong> concertos e masterclasses por todo o país</p></li>
  <li><p class="font_8"><strong>Jurado de concursos:</strong> XI Concurso Nacional de Jovens Clarinetistas — Associação Portuguesa do Clarinete, Concurso do 1º Festival Online de Clarinete — InMusic, 6º Concurso Nacional de Sopros “Sons de Cabral”</p></li>
</ul>', '<p><span style="font-weight:bold">DISCOGRAFIA</span></p><p> </p><ul><li>2022/2023: Obra &quot;Fantasy on Jazz&quot;, de Barbara Jazwinski, a solo com a Royal Scottish National Orchestra (CD &quot;<span style="text-decoration:underline"><span style="font-weight:bold"><span style="text-decoration:underline"><a href=https://www.navonarecords.com/catalog/nv6519/ target=_blank>SYMPHONIC CHRONICLES VOL I</a></span></span></span>&quot;, editora Navona Records)</li><li>2023: <span style="text-decoration:underline"><span style="font-weight:bold"><span style="text-decoration:underline"><a href=https://open.spotify.com/intl-pt/album/43PSualIjYuAplrazTcVrL target=_blank>XX - Ao Vivo no Coliseu dos Recreios - Volume 1</a></span></span></span> (Tiago Bettencourt &amp; Orquestra Clássica do Centro)</li><li>2023: <span style="text-decoration:underline"><span style="font-weight:bold"><span style="text-decoration:underline"><a href=https://open.spotify.com/intl-pt/album/3MysPtPtGPykcwurlqaPvf target=_blank>XX - Ao Vivo no Coliseu dos Recreios - Volume 2</a></span></span></span> (Tiago Bettencourt &amp; Orquestra Clássica do Centro)</li><li>2017: <span style="text-decoration:underline"><span style="font-weight:bold"><span style="text-decoration:underline"><a href=https://open.spotify.com/intl-pt/album/3Uk8UCrqeLnmGNeeVaxLXu target=_blank>Verdi: Otello</a></span></span></span> (Orquestra e Coro Gulbenkian)</li><li>2016: <span style="text-decoration:underline"><span style="font-weight:bold"><span style="text-decoration:underline"><a href=https://open.spotify.com/intl-pt/album/5rglXuuRg0WbfnJnzibR70 target=_blank>Gustav Mahler: Symphony X</a></span></span></span> (International Mahler Orchestra)</li></ul><p><br/><span style="font-weight:bold">ENTREVISTAS</span></p><p> </p><p>2014: Entrevista para a revista <span style="text-decoration:underline"><span style="font-weight:bold"><span style="text-decoration:underline"><a href=https://www.lasplash.com/publish/Music_107/samuel-marques-profile-extraordinary-sound-from-a-self.php target=_blank>Chicago-Splash</a></span></span></span>, EUA - Samuel Marques Profile: Extraordinary Sound from a Self-described Ordinary Guy</p><p> </p><p><span style="font-weight:bold">SAMUEL MARQUES &amp; VASYL TSANKO </span></p><p> </p><p><span style="text-decoration:underline"><span style="font-weight:bold"><span style="text-decoration:underline"><a href=http://www.samuel-marques.com/ target=_blank>Samuel Marques</a></span></span></span> e <span style="text-decoration:underline"><span style="font-weight:bold"><span style="text-decoration:underline"><a href=https://www.youtube.com/channel/UC_73dJlTC5aGVN1KQTaotQQ target=_self>Vasyl Tsanko</a></span></span></span> formam um duo de clarinete e piano baseado na cidade de Aveiro. Desde 2021 que se têm apresentado por todo o país, em séries de concertos e espetáculos promovidos por entidades públicas (Municípios) e entidades privadas (Fundações e Associações). A internacionalização do duo acontece em 2024, com a atuação na Final do concurso ‘Premio Amici della Musica di Verona 2024’, em Verona (Itália).</p><p>Com o objetivo de proporcionar experiências artísticas diferenciadas, têm promovido a circulação de dois espetáculos aos mais variados públicos:</p><p>Contradança – uma viagem pelas mais belas e elegantes danças europeias, até às danças populares da América do Sul, procurando retratar simultaneamente o ambiente dos bailes elegantes e a alma das festas populares do século XVIII.</p><p>Paisagens Sonoras da <span style="font-style:italic">Belle Époque</span> – vivenciar as paisagens sonoras da era da Arte Nova (movimento artístico fortemente inspirado em formas e estruturas naturais e marcadamente simbólico, que esteve em voga num período conhecido como &#x27;Belle Époque&#x27;), através de obras de importantes compositores europeus como Debussy, Ravel ou Fauré.</p><p> </p><p><span style="font-weight:bold">PRISMA QUINTET</span></p><p> </p><p>O <span style="text-decoration:underline"><span style="font-weight:bold"><span style="text-decoration:underline"><a href=https://www.instagram.com/prismaquintet/ target=_blank>Prisma Quintet</a></span></span></span>, nascido no ano de 2021, resulta da união de cinco músicos ambiciosos que partilham o enorme gosto pela música de câmara. Surgiu assim um quinteto de palhetas constituído por instrumentos de sopro da família das madeiras: clarinete soprano, clarinete baixo, fagote, saxofone alto e oboé. Este é um projeto emergente e inovador em Portugal, por se tratar de um quinteto cuja formação, de forma profissional, é única no país.</p><p> </p><p><span style="font-weight:bold">TRIO DE SOPROS DA ORQUESTRA CLÁSSICA DO CENTRO</span></p><p> </p><p>Este trio de sopros é formado por músicos da <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.orquestraclassicadocentro.org/ target=undefined>Orquestra Clássica do Centro</a></span></span></span>, apresentando as mais importantes obras para a formação de trio, combinando os sons da flauta, do clarinete e do fagote também em duo. Constituído em 2023, apresenta-se no âmbito da temporada de música da Orquestra e da programação do Município de Coimbra, em locais como o Claustro do Colégio da Graça (Coimbra), Convento de São Francisco (Coimbra), Ruínas de Conímbriga, Tribunal da Relação do Porto, entre outros.</p>', 'https://static.wixstatic.com/media/fc8a52_71fa672ee95a4bbdbfcfd3ea7630823e~mv2.jpg', '©SPintoPhotography', 'https://static.wixstatic.com/media/fc8a52_f4aac32f638542e69a7bf5f99d1d02d6~mv2.jpg', '©SPintoPhotography', 'https://static.wixstatic.com/media/fc8a52_b9e0982041b04f4cb12b3323b7df171a~mv2.jpg', '©SPintoPhotography', 'https://static.wixstatic.com/media/fc8a52_0811998c436543409b58c142246809af~mv2.jpg', NULL, 'https://static.wixstatic.com/media/fc8a52_48d2c85c78e740718aad03358459ab6d~mv2.jpg', NULL, 'https://static.wixstatic.com/media/fc8a52_a37cc85b3494472fabf1ab7b1209181a~mv2.jpg', NULL, 'https://static.wixstatic.com/media/fc8a52_9f4efd95d08e417eaf2132d9d953eba4~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

