-- Row 53: Margarida Simões
INSERT IGNORE INTO users (id, email, password, role) VALUES ('05b44d02-fd15-4135-b16f-fe52bd12b88f', 'wix-05b44d02@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('70557132-ee89-40d2-b9f7-6923195c1c30', '05b44d02-fd15-4135-b16f-fe52bd12b88f', 'margarida-simoes', 'Margarida Simões', 'Margarida', '968220855', NULL, 'Portugal', 'Portugal', 'Lisboa', 'Avenida de Roma 97', '6º dtº', '1700-244', 'Soprano', 'A música é expressão da natureza humana e ajuda-nos a conhecer a nossa própria humanidade e a dos outros.', 'https://static.wixstatic.com/media/7b859e_a30f93f5e0ed481d80fce7e81881f65e~mv2.jpg', 'wix:document://v1/05b44d_0358e2250a5640ec9ed7421e7b674f36.pdf/Margarida%20Sim%C3%B5es%20Soprano%20biografia%20setembro%202025%20PT-EN.pdf', NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/05b44d_f3e4cd37888743b18b09ba5dfdfdaf5f.wav', NULL, NULL, 'https://www.youtube.com/watch?v=Y0TEYgvrdJA', 'https://youtu.be/ay5eDvxkFR4?feature=shared', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p>“<span style="font-style:italic">Uma das lições mais valiosas foi ter compreendido a importância de uma interpretação rica e autêntica, atenta nos detalhes e subtilezas emocionais. É isso que traz magia à interpretação</span>.”</p><p> </p><p>Margarida Simões é uma soprano portuguesa que tem cativado o público com a sua voz melodiosa e presença cénica envolvente. Natural de Lisboa, procura aliar o seu domínio técnico a uma profunda musicalidade, destacando-se pelas suas interpretações e versatilidade artística.</p><p> </p><p>Com uma formação sólida que inclui estudos no Conservatório Nacional de Lisboa e na Escola Superior de Música de Lisboa, frequentou ainda <span style="font-style:italic">masterclasses </span>e aulas privadas com artistas de renome como Sandra Medeiros, Lucia Mazzaria, Siphiwe McKenzie, Elena Valdelomar e Ana Quintans.</p><p> </p><p>Os destaques do percurso de Margarida Simões incluem atuações em papéis como Dido, da ópera <span style="font-style:italic">Dido and Æneias</span> de Purcell, Venus na ópera &quot;Venus and Adonis&quot; de Blow, Hänsel em &quot;Hänsel und Gretel&quot; de Humperdinck, e Bastienne em &quot;Bastien und Bastienne&quot; de Mozart. Para além do repertório operático, a soprano também interpretou obras sacras como o &quot;Magnificat&quot; de Bach, o ciclo de canções &quot;Frauenliebe und -Leben&quot; de Schumann e a obra &quot;Ah! Perfido<span style="font-style:italic">&quot; </span>de Beethoven.</p>', '<p>A jornada musical de Margarida Simões começou cedo, quando iniciou os seus estudos de música na Escola de Música da Orquestra Metropolitana de Lisboa aos 5 anos, onde aprendeu a tocar violino. Esse primeiro contacto com a música acendeu uma paixão que só cresceria com o passar dos anos.</p><p> </p><p>Despertou para o canto quando começou a cantar em coro na Escola de Música do Conservatório Nacional, sob a direção da maestrina Teresita Gutierrez Marques.</p><p> </p><p>Ao descobrir a sua verdadeira vocação, ingressou no curso de Canto da Escola de Música do Conservatório Nacional, que concluiu sob a tutela de Ana Paula Russo. Decidida a tornar-se uma artista mais completa, ingressou na Licenciatura em Música da Escola Superior de Música de Lisboa, onde teve o privilégio de estudar com o notável professor Armando Possante. Concluiu a sua Licenciatura em 2023. Atualmente frequenta o Mestrado em Ensino de Música na mesma instituição.</p><p> </p><p>Durante a sua formação, Margarida aproveitou cada oportunidade para aprender com grandes nomes da música. Participou em <span style="font-style:italic">masterclasses </span>e <span style="font-style:italic">workshops </span>com artistas como Susan Waters, João Paulo Santos, Lucia Mazzaria, Siphiwe McKenzie, Elena Valdelomar, James Newby e Ana Quintans.</p><p> </p><p>Paralelamente à sua paixão pela música, Margarida Simões também se dedica à medicina dentária, profissão que exerce desde 2014.</p>', '<p>Margarida Simões tem vindo a construir um percurso <span style="font-weight:bold">versátil </span>como soprano.</p><p> </p><p>O seu repertório abrange desde o período renascentista até composições contemporâneas. Algumas das suas <span style="font-style:italic">performances </span>incluem o ciclo de canções “Frauenliebe und -Leben&quot; de Schumann, a cantata &quot;Tra le Fiamme&quot; de Handel, as Missas &quot;Brevis&quot; KV192 e KV194 e o &quot;Requiem&quot; de Mozart, o &quot;Gloria&quot; RV 589 de Vivaldi, o &quot;Te Deum&quot; e a &quot;Missa em Sib&quot; de Marcos Portugal, o &quot;Magnificat&quot; de Bach, o &quot;Stabat Mater&quot; de Pergolesi e o &quot;Te Deum&quot; de Dvořák.</p><p> </p><p>No campo da ópera, Margarida interpretou Dido, da ópera <span style="font-style:italic">Dido and Æneias</span> de Purcell no Operafest Lisboa 2025, Venus na ópera &quot;Venus and Adonis&quot; de John Blow, Hänsel na ópera &quot;Hänsel und Gretel&quot; de Engelbert Humperdinck, o Rapaz de Bronze na ópera &quot;O Rapaz de Bronze&quot; de Nuno Côrte-Real e Bastienne em &quot;Bastien und Bastienne&quot; de Wolfgang Amadeus Mozart.</p><p> </p><p>Dedica-se igualmente à preservação e divulgação da música luso-brasileira dos séculos XVIII e XIX. Como membro do grupo &quot;<span style="font-weight:bold">Cantos do Sabiá</span>&quot;, interpreta modinhas em diversos eventos de recriação histórica, contribuindo para manter viva essa tradição musical.</p><p> </p><p>O talento de Margarida Simões tem sido reconhecido em concursos e festivais. Em 2023, conquistou o 3º prémio do Concurso de Canto para Jovens Intérpretes José Augusto Alegria (8ª edição) e apresentou-se no belo Teatro Garcia Resende, em Évora, no Concerto dos Laureados.</p><p> </p><p>Além de atuar como solista, Margarida também colabora com grupos corais apreciados, como o <span style="font-weight:bold">Coro Gulbenkian</span>, o <span style="font-weight:bold">Ensemble São Tomás de Aquino</span> e, no passado, com o <span style="font-weight:bold">Coro de Câmara de Lisboa</span>. </p><p> </p><p>Em 2024, protagonizou um <span style="font-weight:bold">concerto especial transmitido ao vivo pela Antena 2</span>. Com um programa de música antiga para voz solista e tiorba intitulado &quot;<span style="font-weight:bold">Udite Amanti</span>&quot;, encantou os ouvintes com a sua interpretação sensível e tecnicamente impecável.</p><p> </p><p>Margarida também atua como <span style="font-weight:bold">professora de Técnica Vocal na Paróquia São Tomás de Aquino</span> desde 2023, partilhando os seus conhecimentos e experiências com cantores dos coros da paróquia.</p><p> </p><p>Margarida Simões tem vindo a consolidar a sua carreira no cenário musical português, destacando-se pelo seu talento e dedicação ao canto lírico.</p>', '<p><span style="font-weight:bold">Notícias &amp; Entrevistas</span></p><p> </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://fb.watch/BX0h4FiJYX/ target=undefined>https://fb.watch/BX0h4FiJYX/ </a></span></span> - Entrevista Dido e Eneais | Operafest 2025</p><p> </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://antena2.rtp.pt/em-antena/concertos-antena-2/margarida-simoes-mariana-santos-tiago-simas-maria-catarino-25-marco-19h00/ target=undefined>Antena 2 (2024)</a></span></span> – Udite amanti com Margarida Simões &amp; Mariana Santos</p><p> </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.rtp.pt/play/palco/p4521/e760601/concertosantena2 target=undefined>RTP (2024)</a></span></span> – Concertos Antena 2 / Margarida Simões &amp; Mariana Santos | 25 março 2024</p>', 'https://static.wixstatic.com/media/05b44d_c18c861687e34ece8c4cdf3a6f78a0c2~mv2.jpg', 'Créditos: Sónia Godinho', 'https://static.wixstatic.com/media/05b44d_f7ee90d2bfc84b1baed795e9ad493fcb~mv2.jpg', 'Créditos: Sónia Godinho', 'https://static.wixstatic.com/media/05b44d_5e2c06b7e48e4d7786bf7b67873330d7~mv2.jpg', NULL, NULL, 'Créditos: Sónia Godinho', NULL, 'Créditos: Sónia Godinho', 'https://static.wixstatic.com/media/05b44d_9ce4dc8220414af3a7196c1843026705~mv2.jpg', NULL, 'https://static.wixstatic.com/media/05b44d_86c8ae3c88b54a9fab60ba1f7f00b8e0~mv2.jpg', 'Créditos: Susana Paiva, Operafest Lisboa 2025', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 1);

