d~mv2.jpg', NULL, NULL, NULL, 0, 0, 1);

-- Row 58: Pedro Santos
INSERT IGNORE INTO users (id, email, password, role) VALUES ('2aeb6e58-3166-481f-a5cc-231481b4f4c4', 'wix-2aeb6e58@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('0ad9d2d3-75d8-458c-9faf-452dcee9941c', '2aeb6e58-3166-481f-a5cc-231481b4f4c4', 'pedrosantos', 'Pedro Santos', 'Pedro', '960427661', '2002-06-16', 'Portugal', 'Alemanha', 'Weimar', 'Trierer Str.4', NULL, '99423', 'Guitarrista', 'Cada nota que toco é uma chance de dar vida à minha visão de música.', 'https://static.wixstatic.com/media/2aeb6e_ef70851c78dd4681af0fa746251a654a~mv2.jpg', 'wix:document://v1/2aeb6e_f79540138f6d46429d5a746cf4c2243c.pdf/BIO%20PT.pdf', NULL, 'https://www.instagram.com/pedrosantosgt/', NULL, NULL, 'https://www.youtube.com/@pedromsantosg', NULL, NULL, NULL, 'https://youtu.be/nNZf0GWOX8M', 'https://www.youtube.com/watch?v=rcfUko-sUBI', 'https://youtu.be/nNZf0GWOX8M', 'https://www.youtube.com/watch?v=rcfUko-sUBI', 'https://www.youtube.com/shorts/NldTiiyFv0Q', NULL, NULL, NULL, NULL, NULL, '<p class="font_8">Pedro Santos é um guitarrista clássico cuja trajetória é marcada por uma fusão de experiências que vão além do repertório tradicional.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Com uma sólida base na guitarra clássica e uma vasta experiência com a guitarra elétrica e a improvisação, Pedro Santos desenvolveu uma abordagem interpretativa que alia liberdade e expressividade. Essa combinação enriquece suas performances, permitindo a exploração de nuances e dinâmicas que se destacam em um repertório que vai de Bach e Tárrega até composições contemporâneas e improvisações solo. A integração desses elementos traz uma dimensão extra às suas apresentações, marcadas pela espontaneidade e adaptação ao momento.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Pedro é reconhecido pela conexão que estabelece com o público, trazendo uma energia envolvente para cada concerto. A sua abordagem à música, sempre em evolução, reflete uma vontade contínua de explorar novas possibilidades dentro da tradição da guitarra clássica, tornando suas performances uma experiência autêntica e memorável.</p>
<p class="font_8"><br></p>
<p class="font_8"><em><strong>"Tecnicamente irrepreensível, musicalmente coerente mas ao mesmo tempo irreverente, inovador e pleno de emoção."</strong></em><strong> -Sónia Leitão</strong></p>
<p class="font_8"><br></p>', '<p class="font_8"><em>"O meu pai tinha uma guitarra que guardava com muita estima em cima de um móvel e eu chorava horas a fio para que ele me deixasse tocar algumas cordas soltas antes de ir dormir. Desde criança que me lembro de ouvir música classica em casa, mas sempre de maneira bastante leviana, era algo muito distante do nosso contexto social."</em></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Embora Pedro Santos tenha começado sua educação formal em guitarra clássica apenas aos 14 anos, no Orfeão de Leiria, ele já carregava consigo uma sólida base ''quasi'' autodidata de guitarra elétrica. A guitarra clássica rapidamente se tornou o centro de sua vida, especialmente sob a influência inspiradora de sua professora Sónia Leitão. Participar de concursos, pequenos concertos e interagir com colegas com sonhos semelhantes criou um ambiente propício para a formação de suas próprias aspirações, incluindo o desejo de estudar com o renomado guitarrista <strong>Ricardo Gallén</strong> em <strong>Weimar</strong>, na Alemanha.</p>
<p class="font_8"><br></p>
<p class="font_8">Após concluir o ensino secundário em música, Pedro ingressou no <strong>Conservatório Superior de Música de Vigo</strong>, onde estudou com a prestigiada guitarrista <strong>Margarita Escarpa</strong>. Após quase dois anos de licenciatura em Vigo, Pedro decidiu seguir seu sonho de estudar em Weimar, no unico departamento de guitarra da alemanha.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Pedro Santos vê a música como uma forma de explorar e expressar o que somos. Misturando elementos da guitarra elétrica e improvisação com a música clássica, acreditando que a arte deve ser uma constante jornada de descoberta e expressão pessoal.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><em>"Durante bastante tempo ressenti o facto de só me ter sido possivel dar inicio à minha formação músical relativamente tarde, para quem ambiciona uma carreira como solista. Pensava sempre no que poderia ou não ter acontecido se tivesse começado mais cedo. Hoje percebo que a versatilidade é uma das características valiosas que um músico pode ter."</em></p>
<p class="font_8"><br></p>
<p class="font_8"><em>"Cada nota que toco é uma chance de dar vida à minha visão de música."</em></p>', '<p class="font_8">Atualmente aluno na Academia de Música Franz Liszt de Weimar, onde estudou sob a orientação do guitarrista <strong>Ricardo Gallén</strong>, Pedro tem uma formação clássica sólida, mas é sua experiência com a guitarra elétrica que verdadeiramente distingue sua abordagem musical.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Influenciado profundamente por músicos como João Barradas, Andrès Segovia, Maria João Pires e Kieth Jarrett, Pedro busca uma conexão autêntica com cada peça que interpreta, explorando tanto a precisão técnica quanto a liberdade expressiva. Esses artistas inspiraram-no a transcender os limites convencionais do seu instrumento, tranzendo a guitarra clássica a um nivel digno de um instrumento solista.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>Formação artistica</strong>:</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2020, concluiu os estudos musicais no Orfeão de Leiria com distinção sobre a orientação de Sónia Leitão. Após a conclusão do ensino secundário, prosseguiu os seus estudos musicais no Conservatório Superior de Música de Vigo, onde estudou com a conceituada guitarrista Margarita Escarpa. Em 2022, foi admitido na Escola Superior de Música Franz Liszt de Weimar (Alemanha), onde prossegue a sua licenciatura em guitarra clássica como aluno do guitarrista Ricardo Gallén.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Teve ainda a oportunidade de participar em masterclasses com Aniello Desiderio, Judicael Perroy, Joaquín Clerch, Thibaut Garcia, entre outros grandes guitarristas</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>Prémios</strong>:</p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">1º prémio na categoria "Jovem Promessa" no Festival de Guitarra de Petrer, na Espanha, em 2018.</p></li>
  <li><p class="font_8">Prémio de melhor interpretação de música portuguesa no Concurso de Música do Montijo em 2021 e 2022.</p></li>
  <li><p class="font_8">2º prémio no Concurso Internacional de Guitarra Cidade de Lagoa em 2023, na sua respetiva categoria)</p></li>
</ul>
<p class="font_8">Entre outros</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>Hightlights:</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">Recital no Festival de Guitarra "José Tomás" 2019</p></li>
  <li><p class="font_8">Estria do "Micro Concerto para Guitarra Solista e Orquestra de Sopros" de Nuno da Rocha no Festival Leiria cidade Criativa de Música 2023</p></li>
  <li><p class="font_8">Concerto de Improvasação com o Ensemble Moment- Weimar (Alemanha) 2024</p></li>
</ul>
<p class="font_8">&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>', NULL, 'https://static.wixstatic.com/media/2aeb6e_e301ac0dc3de4cbabe85248f55e84937~mv2.jpg', NULL, NULL, NULL, 'https://static.wixstatic.com/media/2aeb6e_d581209644a2492a8746eab1b90e56be~mv2.jpg', NULL, NULL, NULL, 'https://static.wixstatic.com/media/2aeb6e_2362854e729f4485b1d25e480610c439~mv2.jpeg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 59: António Luís Silva
INSERT IGNORE INTO users (id, email, password, role) VALUES ('59532e55-ff94-48b1-a4ba-746886b7f08a', 'wix-59532e55@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('0634d8c4-e029-42ce-bbd8-65b4398f0de6', '59532e55-ff94-48b1-a4ba-746886b7f08a', 'antonio-luis-silva', 'António Luís Silva', 'António', '''+351918488688', NULL, 'Portugal', 'Portugal', 'Almargem do Bispo', 'Largo dos Combatentes do Ultramar, 3, Vale de Lobos', NULL, '2715-405', 'Pianista, Compositor, Improvisador', NULL, 'https://static.wixstatic.com/media/59532e_44f24c8848cd4482999de131d0bee604~mv2.jpg', NULL, 'https://www.facebook.com/Antonioluisilva', NULL, 'https://www.antonioluissilvapiano.com/', NULL, 'https://www.youtube.com/@antonioalvesdasilva6905', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Portuguese pianist, composer and improviser, António Luís Silva explores an original repertoire, filled with exotic music from all around the world, like Japan, USA, Siria, Armenia or Argentina, besides playing works by the greatest western composers such as Liszt, Brahms or Rachmaninoff. António Luís Silva was awarded in several<br/>international and national competitions, highlighting the first prizes in the International Competition<br/>Cidade do Fundão, Concurso de Interpretação Frederico de Freitas, Iberian Piano Competition of Alto Minho, and second prize at the Santa Cecília International Competition.<br/>With orchestra, he played Rachmaninoff Piano Concerto No.1 and 2,<br/>with the Filarmonia das Beiras orchestra and West Mexico Symphony Orchestra.<br/>Solo performed in Portugal, México, Spain, Turkey and France, playing on important stages, including Centro Cultural Constituición, Bodrum Antique Theatre, Casa da Música, and festivals such as Festival Internacional dos Açores, Festival Internacional de Piano do Algarve and GumusLuk Muzik Festivali. He also held concerts broadcasted by Antena 2.<br/>In 2019 he started the piano duo “H4nds duo” with the pianist Tiago Nunes, releasing their first album in late 2020.<br/>He was taught by renowned piano teachers, including Carla Seixas, Jill Lawson and Álvaro Teixeira<br/>Lopes, finishing the piano course at the Escola de Música do Conservatório Nacional with distinction and also being awarded with the Ministry of Education&#x27;s merit award, given to the<br/>institution&#x27;s best student. He graduated in Music at the Escola Superior de Música de Lisboa and at<br/>the Escola Superior de Artes Aplicadas, and concluded his Masters in Music in 2016, at the University of Aveiro, always with the highest marks. Throughout his studies, António Luís Silva worked with renowned pianists and teachers such as Caio Pagano (Brazil), Diego Caetano (Brazil/USA), Jeffrey Swan (USA), Michael Bulychev-Okser (USA), Rem Urasin (Russia) and Theódore Paraskivesko (France)</p>', NULL, '<p>Portuguese pianist, composer and improviser, António Luís Silva regularly performs in concert with exotic programs that include works from around the world, especially from Europe, East and Central Asia and the Americas. With an international career full of successes, the first prizes at the Cidade do Fundão International Competition, the Frederico de Freitas Interpretation Competition and the Alto Minho Iberian Piano Competition stand out, as well as the second prize at the Santa Cecília International Competition. He performed numerous solo concerts and with orchestra in different countries such as Portugal, Spain, France, Mexico and Turkey, and performed in important concert halls, such as the Centro Cultural Constituición de Guadalajara, Bodrum Antique Theatre, Centro Cultural de Belém, Casa da Música do Porto, and Fundação Oriente. He frequently performs concerts broadcasted live on national radio. In 2019, together with Tiago Nunes, he founded the H4NDS Duo, a 4-hand piano duo that has enjoyed enormous success, recording a CD in 2020, and participating in several festivals, such as the Mafra Music Festival, Algarve Piano Festival , International Festival of the Azores, among others. He was guided by renowned teachers, including Carla Seixas, Jill Lawson and Álvaro Teixeira Lopes, and held masterclasses with renowned pianists such as Caio Pagano, Jeffrey Swan, Theodore Paraskivesko, Diego Caetano and Michael Bulychev-Okser. In 2010, he completed the piano course at the National Conservatory Music School with the highest distinction. He graduated in Music at the Escola Superior de Música de Lisboa and at the Escola Superior de Artes Aplicadas, and completed his Master&#x27;s in Music Teaching in 2016, at the University of Aveiro, always with the highest marks.</p>', '<p>Portuguese pianist, composer and improviser, António Luís Silva regularly performs in concert with exotic programs that include works from around the world, especially from Europe, East and Central Asia and the Americas. With an international career full of successes, the first prizes at the Cidade do Fundão International Competition, the Frederico de Freitas Interpretation Competition and the Alto Minho Iberian Piano Competition stand out, as well as the second prize at the Santa Cecília International Competition. He performed numerous solo concerts and with orchestra in different countries such as Portugal, Spain, France, Mexico and Turkey, and performed in important concert halls, such as the Centro Cultural Constituición de Guadalajara, Bodrum Antique Theatre, Centro Cultural de Belém, Casa da Música do Porto, and Fundação Oriente. He frequently performs concerts broadcasted live on national radio. In 2019, together with Tiago Nunes, he founded the H4NDS Duo, a 4-hand piano duo that has enjoyed enormous success, recording a CD in 2020, and participating in several festivals, such as the Mafra Music Festival, Algarve Piano Festival , International Festival of the Azores, among others. He was guided by renowned teachers, including Carla Seixas, Jill Lawson and Álvaro Teixeira Lopes, and held masterclasses with renowned pianists such as Caio Pagano, Jeffrey Swan, Theodore Paraskivesko, Diego Caetano and Michael Bulychev-Okser. In 2010, he completed the piano course at the National Conservatory Music School with the highest distinction. He graduated in Music at the Escola Superior de Música de Lisboa and at the Escola Superior de Artes Aplicadas, and completed his Master&#x27;s in Music Teaching in 2016, at the University of Aveiro, always with the highest marks.</p>', 'https://static.wixstatic.com/media/59532e_e97b7bc0c81e413badd54d7611a04bcc~mv2.jpg', NULL, 'https://static.wixstatic.com/media/59532e_edbf8f289cfb4e5e97e84bf1a311af48~mv2.jpg', NULL, 'https://static.wixstatic.com/media/59532e_4dbfd6c09a3f43da810c4aa571c7f1ce~mv2.jpg', NULL, 'https://static.wixstatic.com/media/59532e_671bbbb7cfc741d6981ac5805a06d13c~mv2.jpg', NULL, 'https://static.wixstatic.com/media/59532e_02036e0b02874399b4570713ecc66630~mv2.jpg', NULL, 'https://static.wixstatic.com/media/59532e_aab79481b55b4d908380814f7c22f5cc~mv2.jpg', NULL, 'https://static.wixstatic.com/media/59532e_b79b2331da46472e94d940166bcd2cb6~mv2.jpg', NULL, 'https://static.wixstatic.com/media/59532e_ed2a8ca3afb94b33b3ab4fefca0c67dd~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 0, 1);

-- Row 60: João Loureiro
INSERT IGNORE INTO users (id, email, password, role) VALUES ('b17ec407-2b3e-42ea-9d2e-b432a8fdbbb0', 'wix-b17ec407@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('c146537c-0672-4f57-b237-b44103d3692a', 'b17ec407-2b3e-42ea-9d2e-b432a8fdbbb0', 'joao-loureiro', 'João Loureiro', 'João', '''+351963323126', '1974-02-09', 'Portugal', 'Portugal', 'Santarém', 'Travessa 15 de Março, Nº 12, 2º dto.', 'Travessa 15 de Março, Nº 12, 2º dto.', '2000-128 Santarém', 'Guitarrista e compositor', 'João Loureiro é um guitarrista que encontrou na composição um espaço de liberdade de expressão e criatividade.', 'https://static.wixstatic.com/media/7b859e_9dd2073b254040b8ab70089427ce3ee5~mv2.jpg', 'wix:document://v1/b17ec4_b86d786332e54652ab0cc56011e2f49d.pdf/Jo%C3%A3o%20Loureiro%20bio%20port.pdf', NULL, NULL, 'https://www.tessitorimusic.com/', NULL, 'https://www.youtube.com/@joaoloureiro1974/videos', 'https://static.wixstatic.com/mp3/b17ec4_cb103d17b4734738995ba2edc7075f80.wav', NULL, NULL, 'https://youtu.be/iUG-g5hr8yo?si=PDe9-CcGDRoJOrUt', 'https://youtu.be/fsXzh-IWcLc?si=-kvvL5cguuM4-uGX', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8">João Loureiro gosta de desafios e de ambientes variados, algo que é um catalisador do seu processo criativo.</p>
<p class="font_8"><br></p>
<p class="font_8">Desde sempre sentiu uma atração especial pela figura do intérprete compositor, com quem teve contacto desde o início da sua formação musical nas figuras de Fernando Sor, Francisco Tárrega, Mauro Giuliani e mais tarde Agustin Barrios Mangoré.</p>
<p class="font_8"><br></p>
<p class="font_8">A sua inclinação para a partilha e interação com outros leva-o a procurar a criação de parcerias em que pode aprender e expandir a sua linguagem expressiva. De facto, a música de câmara tem sido uma paixão sua, a julgar pelo número de ensembles a que pertenceu e com quem tocou e gravou.</p>
<p class="font_8"><br></p>
<p class="font_8">A composição, embora sempre tenha sido um interesse forte, só mais tarde se materializou, quando finalmente conseguiu começar a formar e a acreditar na sua voz.</p>', '<p class="font_8"><strong>João Loureiro</strong></p>
<p class="font_8"><br></p>
<p class="font_8">Iniciou os seus estudos com os professores Silvestre Fonseca e Acácio Resende até ao ano de 1997 quando parte para Londres para estudar com a professora Shuko Shibata. A licenciatura em Música, é concluída no London College of Music and Media sob a orientação do professor Carlos Bonell, onde lhe foi atribuído o “British Reserve Strings Prize”. Continua os seus estudos na Royal Academy of Music onde em 2003 conclui a sua Pós Graduação com Mérito. Enquanto solista João Loureiro fez recitais em Portugal, Holanda, Alemanha e Inglaterra.&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">Foi o representante de Portugal no primeiro congresso “UNISSONO INTERNATIONAL” na Alemanha, onde realizou vários recitais e fez uma gravação em direto para a SDF Radio. Outras atividades incluíram espetáculos de poesia música e dança com o grupo “A Phala”, teatro musical, ópera e participações com orquestra tal como a BBC Philarmonic Orchestra.&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">Em agosto de 2009, João apresentou-se com a Britten Sinfonia na estreia da ópera “Yellow Sofa” de Julian Phillips em Glyndebourne tendo voltado a ser solicitado para a temporada e digressão em 2012. A sua devoção à música de câmara levou-o a criar parcerias com a flautista Vicki Tofts e o flautista Efrain Oscher e o guitarrista Steve Smith. Em 2007 lançou com o guitarrista francês Thomas Lavigne (UnoGuitarDuo), o seu primeiro disco que foi recebido e aclamado pela crítica. “Um álbum totalmente convincente de música maravilhosa, magnificamente interpretada.” (in Classical Guitar Magazine).&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2014 lançou o seu segundo álbum com a violetista Isabel Pereira (duo TESSITORI), do qual a critica disse, “É claro que estamos a lidar com músicos de alto calibre cuja decisão de deixar a música e o público respirar livremente é feita com convicção…” em Classical Guitar Magazine, outubro 2014.&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">Com o duo TESSITORI, tocou concertos em Portugal, Espanha, e Inglaterra, de realçar as várias apresentações em Londres: na National Portrait Gallery (especialmente dois concertos integrados na exposição “Picasso Portraits”em 2016), em St. James’s, Picadilly (concerto integrado no Festival Echoes da ILAMS 2017), no National Theatre – Southbank e Rosslyn Hill Chapel; em Portugal: na Fundação Calouste Gulbenkian, Teatro Nacional de São Carlos, Convento de São Francisco – Santarém, Museu Abade Pedrosa – Santo Tirso entre outros; em Espanha na Iglesia de Santa María Mayor integrado no festival Terras sem Sombra.&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">João promove presentemente o seu álbum de música original para guitarra solo intitulado “Familiar Faces”, este é inspirado nos heróis menos celebrados das nossas vidas, a família e os amigos.</p>', '<p class="font_8"><strong>João Loureiro - Guitarrista e Compositor</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">Recitais em Portugal, Inglaterra, Holanda e Alemanha dos quais se podem destacar um recital em representação de Portugal no primeiro congresso “UNISSONO INTERNATIONAL” na Alemanha, onde realizou vários recitais e fez uma gravação em directo para a SDF Radio, Estugarda;</p></li>
  <li><p class="font_8">Espectáculos de poesia música e dança com o grupo “A Phala” em várias cidades portuguesas;</p></li>
  <li><p class="font_8">Solista de Guitarra Clássica na encenação do musical “Days of Hope” de Howard Googall em Hampton Hill Playhouse, Londres;</p></li>
  <li><p class="font_8">Concerto na comemoração V Centenário da Santa Casa da Misericórdia, Santarém;</p></li>
  <li><p class="font_8">Concerto no Festival Internacional de Música de Santarém;</p></li>
  <li><p class="font_8">Concerto no Loyds Private Banking em Londres a solo e com o Tenor Agustin Prunel-Friend;</p></li>
  <li><p class="font_8">Concerto na National Portrait Gallery, Londres, onde interpretou obras de sua autoria.</p></li>
  <li><p class="font_8">Lançamento do álbum “Familiar Faces” com obras originais suas para guitarra solo (2018)</p></li>
</ul>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>ENTENTE (Duo com o guitarrista Steve Smith) 2009 – 2012</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">Concertos em Inglaterra no National Theatre, Londres, Rosslyn Hill Chapel, Londres e St. Peter’s Church, Stutton</p></li>
</ul>
<p class="font_8"><br></p>
<p class="font_8"><strong>UNOGUITARDUO (Duo com o guitarrista Thomas Lavigne) 2002 - 2008</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">Concertos em Inglaterra, França e Portugal dos quais se podem destacar a Royal Academy of Music, Londres, o Centro Cultural de Belém, Lisboa; Latin Quarter, Londres, Wathen Hall, Londres e em Paris.</p></li>
  <li><p class="font_8">Lançamento de um álbum de música Ibérica e Sul Americana do qual a critica disse: “…an altogether totally satisfying album of wonderful music beautifully played. Need I say more?” in Classical Guitar Magazine</p></li>
</ul>
<p class="font_8"><br></p>
<p class="font_8"><strong>Glyndebourne Opera</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">Músico convidado e solista de Guitarra Clássica com a Britten Sinfonia na estreia da ópera “Yellow Sofa” de Julian Phillips sobre um romance de Eça de Queirós intitulado “Alves e Companhia”</p></li>
  <li><p class="font_8">Músico convidado e solista de Guitarra Clássica com a Glyndebourne Tour Orchestra na reencenação e tournée da ópera “Yellow Sofa” de Julian Phillips</p></li>
</ul>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>BBC Philarmonic Orchestra</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">Músico convidado e solista de Guitarra Clássica na interpretaçäo da ópera Otello de Giuseppe Verdi no Bridgewater Hall, Manchester sob a batuta de Gianandrea Noseda.</p></li>
</ul>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>Royal Academy Opera</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">Músico convidado e solista de Guitarra Clássica na interpretaçäo da ópera Falsaff de Giuseppe Verdi no Sir Jack Lyons Theatre Royal Academy of Music, Londres</p></li>
</ul>', NULL, 'https://static.wixstatic.com/media/b17ec4_1eea175bbb3345428c1ecef4780b7aae~mv2.jpg', 'João Loureiro por José Farinha', 'https://static.wixstatic.com/media/b17ec4_15a6b6e1a2c44d23b1485ce9e2b746ee~mv2.jpg', 'João Loureiro por José Farinha', 'https://static.wixstatic.com/media/b17ec4_4eb940fc81e94f06a98207eb5542ae6b~mv2.jpg', 'João Loureiro por José Farinha', 'https://static.wixstatic.com/media/b17ec4_c84178e8367e47d196622244b6f23b91~mv2.jpg', 'João Loureiro por Jorge Moura', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 61: Manuel Teles
INSERT IGNORE INTO users (id, email, password, role) VALUES ('d17a0fc4-ab95-4230-ba26-8468f66a2bef', 'wix-d17a0fc4@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('341845e0-5fe9-4ccc-99cf-d1725033c9ff', 'd17a0fc4-ab95-4230-ba26-8468f66a2bef', 'manuel-teles', 'Manuel Teles', 'Manuel', '912247772', '2002-04-11', 'Portugal', 'Portugal', 'Palmela', 'Rua Fernão de Magalhães 91', NULL, '2955-102', 'Saxofonista', 'A minha arte é livre.', 'https://static.wixstatic.com/media/7b859e_fb4fd35f854e416e824cb6eaa7b6f963~mv2.jpg', 'wix:document://v1/d17a0f_ec6992ad42cc4745aad7a7b6a37c3221.pdf/Manuel%20Teles%20PT.pdf', NULL, 'https://www.instagram.com/manuel.teles_', NULL, 'https://open.spotify.com/intl-pt/artist/5xHw4ydw2UmBiTx5fM3F3d?si=JwqvC8uhT2qQNqzJAymRsg', 'https://www.youtube.com/@manuelteles', NULL, NULL, NULL, 'https://youtu.be/eASPQ6obcAk?si=P9fSMa1_FeAujglg', 'https://youtu.be/sPyNvDcMJ0g?si=hP56UYSDQQiz2Sje', 'https://youtu.be/8pOdmlS3t9E?si=1QRfnM6EPRAt2Qvn', 'https://youtu.be/VNGtKsFvQPM?si=qBmQYVallFNoXlJb', 'https://youtu.be/30bl4Nfkjgw?si=G4Jnl90xYFIM28pD', 'https://youtu.be/pUneGG0YvaA?si=gX4Nvi90ccjMkHE2', 'https://youtu.be/dvsJ0kYtYgM?si=a_mJ__NgpaPTD_re', 'https://youtu.be/R46rEWdEFLQ?si=iTMsDjcTBXFERn1A', NULL, NULL, '<p class="font_8">Manuel Teles (Palmela, 2002) é um saxofonista detentor de mais de vinte prémios nacionais e internacionais.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">A sua versatilidade permite-lhe navegar pelos universos da música moderna, repertório clássico saxofonístico, improvisação e música orquestral, apresentando-se regularmente em prestigiadas salas, como o Centro Cultural de Belém, Teatro Filarmónico de Verona, Casa da Música, Auditorium Parco della Musica Ennio Morricone, MEO Arena, Coliseu do Porto e Gulbenkian.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Exibe-se frequentemente com diversas formações, destaque para a Kansas University Orchestra, Divertimento Ensemble, MLOrK Milan Laptop Orchestra, Orchestra dell’Accademia Nazionale di Santa Cecilia, Ensemble mpmp, Orquestra Metropolitana de Lisboa e o Ensemble Scaligero do Teatro alla Scala.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Manuel Teles tem como missão continuar a colaborar lado a lado com artístas modernos de diferentes backgrounds, promovendo a criação, divulgação e registo de novos repertórios.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">(...) <em>é absolutamente surpreendente a capacidade de Manuel Teles de fazer do seu saxofone um instrumento imprevisível e rico, capaz tanto de saturar o espaço sonoro como de dar voz ao silêncio</em> (...) Amadeus</p>', '<p style="text-align:justify">A sua ligação com a música começa desde cedo no ambiente familiar. Durante a infância, cultivou essa paixão no Colégio de Santa Ana, em Setúbal, onde estudou dos 3 aos 10 anos.</p><p> </p><p style="text-align:justify">Aos 11 anos, descobriu o saxofone, instrumento que rapidamente se tornou parte central da sua vida. Iniciou as aulas na sociedade filarmónica da sua vila. Estudou no Conservatório de Palmela e, mais tarde, na Metropolitana de Lisboa, em ambas acompanhado pelo professor João Pedro Silva.</p><p> </p><p style="text-align:justify">Em 2020, transferiu-se para Itália, onde se licenciou no Conservatório Giuseppe Verdi, sob a orientação de Mario Marzi, tendo terminado o curso com <span style="font-style:italic">Magna Cum Laude e Menzioni d&#x27;Onore</span>. Atualmente, reside em Milão e, para além da sua atividade como intérprete freelancer, frequenta o mestrado na mesma instituição.</p><p> </p><p> </p>', '<p class="font_8" style="text-align: justify">A sua versatilidade permite-lhe navegar pelos universos da música moderna, repertório clássico saxofonístico, improvisação e música orquestral, apresentando-se regularmente em prestigiadas salas, como o Centro Cultural de Belém, Teatro Filarmónico de Verona, Casa da Música, Auditorium Parco della Musica Ennio Morricone, MEO Arena, Coliseu do Porto e Gulbenkian.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Trabalhou com uma vasta gama de artistas, performers, maestros e compositores, como Jacob TV, Mário Laginha, Mikel Urquiza, Luís Tinoco, Pedro Amaral, Daniel Bernardes, António Victorino d''Almeida, Martim Sousa Tavares e Hariprasad Chaurasia.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Exibe-se frequentemente com diversas formações, destaque para a Kansas University Orchestra, Divertimento Ensemble, MLOrK Milan Laptop Orchestra, Orchestra dell’Accademia Nazionale di Santa Cecilia, Ensemble mpmp, Orquestra Metropolitana de Lisboa e o Ensemble Scaligero do Teatro alla Scala.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>
<p class="font_8" style="text-align: justify">Em 2022, em duo com o percussionista Paulo Amendoeira, lançou <em>"Ascolta!"</em>, um álbum que reúne novas composições portuguesas para saxofone e percussão, com música de Daniel Bernardes, João Pedro Oliveira, João Quinteiro, Telmo Marques e Paulo Jorge Ferreira, lançado pelo mpmp - Movimento Patrimonial pela Música Portuguesa.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">Em 2023, publica <em>"Lisboa-Milano"</em>, um CD dedicado a obras para saxofone solo de Luca Francesconi, Vincenzo Parisi, Christopher Bochmann, João Pedro Oliveira e Salvatore Sciarrino, editado pela Stradivarius.</p>', '<p class="font_7"><strong>DISCOGRAFIA</strong></p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Lisboa-Milano (2023)</strong></p>
<p class="font_8">Repertório:</p>
<p class="font_8"><em>E gridare gridare gridare come il mare</em>, Vincenzo Parisi</p>
<p class="font_8"><em>Tracce</em>, Luca Francesconi</p>
<p class="font_8"><em>Essay XIII</em>, Christopher Bochmann</p>
<p class="font_8"><em>Integrais IV</em>, João Pedro Oliveira</p>
<p class="font_8"><em>Notturno</em>, Luca Francesconi</p>
<p class="font_8"><em>L’orologio di Bergson</em>, Salvatore Sciarrino</p>
