-- Row 62: Pedro Leitão
INSERT IGNORE INTO users (id, email, password, role) VALUES ('691d8a4f-6589-442d-81a9-5626f31c5acb', 'wix-691d8a4f@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('44dbe851-0224-42b1-9a53-af4549d5a7ee', '691d8a4f-6589-442d-81a9-5626f31c5acb', 'Pedro-Leitao', 'Pedro Leitão', 'Pedro Afonso', '967928822', '2003-03-07', 'Portugal', 'Portugal', 'Fundão', 'Vale de Canas, rua Conde Ericeira Lote 3', NULL, '6230-481', 'Percussionista', 'A pluralidade do mundo da percussão permite-me expressar a minha verdadeira essência.', 'https://static.wixstatic.com/media/691d8a_ed64556592b145d29a72b72cebe54dab~mv2.jpg', NULL, 'https://www.facebook.com/afonsoleitao99/', 'https://www.instagram.com/leitaoo_1/', NULL, NULL, 'https://www.youtube.com/@pedroleitao1470/featured', NULL, NULL, NULL, 'https://youtu.be/mi1_uEpGFCE', 'https://youtu.be/TCRGO-LTuUk', 'https://youtu.be/CtNVIuJPXME?si=bSImFYnYW1gwN6sL', 'https://youtu.be/o_ZprW5ivMw', 'https://www.youtube.com/watch?v=xo5pvqcEkCY', NULL, NULL, NULL, NULL, NULL, '<p><span style="font-weight:bold">Pedro Leitão</span> é um percussionista nascido e criado no Fundão, Portugal. Os seus primeiros passos na percussão foram dados na <span style="font-weight:bold">Academia de Música e Dança do Fundão</span> que culminou na sua formação secundária em música, sob a orientação do professor Diogo Cabral.</p><p> </p><p>Em 2021, conquistou o <span style="font-weight:bold">segundo lugar</span> no “IV Concurso Nacional de Interpretação de Música Contemporânea”, e em 2024 também conquistou o <span style="font-weight:bold">terceiro lugar </span>“VI Concurso Nacional de Interpretação de Música Contemporânea”, demonstrando-se assim como um músico orientado para a música de agora. Participou em diversas performances ao lado de grupos de música de câmara e orquestras, como o <span style="font-weight:bold">“Clamat - Colectivo Variável”</span>, <span style="font-weight:bold">“Halicos Percussion Group”</span>, <span style="font-weight:bold">“Remix Ensemble Summer Academy”</span> e <span style="font-weight:bold">“Orquestra Clássica do Centro”</span>.</p><p> </p><p>Estreou peças em Portugal e no estrangeiro de compositores como <span style="font-weight:bold">Ângela Lopes</span>, <span style="font-weight:bold">Ricardo Ribeiro</span>, <span style="font-weight:bold">Simon Steen-Andersen</span>, <span style="font-weight:bold">Tiago de Matos</span>, <span style="font-weight:bold">Francisco Ribeiro</span>, <span style="font-weight:bold">Luis Cipriano</span> e <span style="font-weight:bold">Camila Menino</span>, ampliando seu repertório e contribuindo para a divulgação da música contemporânea.</p><p> </p><p>Licenciou-se na <span style="font-weight:bold">Universidade de Aveiro</span> na classe dos professores <span style="font-weight:bold">Nuno Aroso</span>, <span style="font-weight:bold">João Dias</span> e <span style="font-weight:bold">Eduardo Cardinho</span>. A sua versatilidade musical e interesse na exploração sonora e tecnológica impulsionam-o a criar projetos inovadores no campo da música, onde a experimentação e a criatividade são elementos centrais.</p>', '<p><span style="font-weight:bold">Pedro Leitão</span> cresceu no interior do país, na cidade do<span style="font-style:italic"> Fundão</span>, região caracterizada pela sua riqueza natural e paisagística. O Pedro não cresceu num ambiente familiar propício às artes, tendo o seu primeiro contacto com a música na <span style="font-weight:bold">Academia de Música e Dança do Fundão</span> aos seis anos, onde desenvolveu um gosto especial pela música.</p><p> </p><p>Aos 10 anos, entrou no <span style="font-weight:bold">I Grau</span> de <span style="font-weight:bold">Ensino Especializado em Música</span>, mas foi no <span style="font-weight:bold">IV Grau</span>, sob a orientação do novo professor da escola, <span style="font-weight:bold">Diogo Cabral</span>, que o Pedro conheceu um pouco do mundo da Percussão. O novo professor trouxe-lhe novas perspetivas e sonhos, e por isso decide seguir para o ensino secundário especializado em música na <span style="font-weight:bold">AMDF</span>. A escolha não foi fácil, pois as condições oferecidas pela escola não eram de todo as indicadas, mas com o compromisso de trabalho e dedicação, a escola investiu em condições para que o Pedro e mais colegas seguissem os seus sonhos.</p><p> </p><p>Com isto sempre presente no seu pensamento, o Pedro não quis desperdiçar a sua oportunidade e os resultados apareceram, tendo entrado em <span style="font-weight:bold">primeiro lugar</span> na <span style="font-weight:bold">Universidade de Aveiro</span> na classe do professor <span style="font-weight:bold">Nuno Aroso</span>. Além da qualidade do professor regente, encontrou uma equipa de professores de grande relevância no cenário nacional: <span style="font-weight:bold">João Dias</span>, <span style="font-weight:bold">Eduardo Cardinho</span>, <span style="font-weight:bold">Diego Ventoso Fernandez</span> e <span style="font-weight:bold">Mário Teixeira</span>, que o ajudaram a crescer e a tornar um percussionista versátil capaz de enfrentar qualquer desafio artístico.</p><p> </p><p>Pedro é também cofundador da <span style="font-weight:bold">Associação de Criação Artística &quot;Os Moustache&quot;</span>, uma associação criada por colegas das AMDF com o objetivo de proporcionar oportunidades aos jovens da cidade para participarem e ouvirem novos projetos musicais.</p><p> </p><p>A procura incessante pelas novas perspetivas e entendimento artístico, levou-o a participar na <span style="font-weight:bold">Remix Ensamble Summer Academy</span>, a conquistar por duas vezes o <span style="font-weight:bold">2.º lugar no Concurso Nacional de Interpretação de Música Contemporânea</span>, e a participar regularmente com o grupo <span style="font-weight:bold">Clamat-Colectivo Variável</span> orientado pelo professor Nuno Aroso.</p>', '<p>LINHA DO TEMPO </p><p> </p><ol><li><span style="font-weight:bold">2024 </span></li></ol><ul><li>Concluiu a licenciatura com 19 na Universidade de Aveiro, e está inscrito no mestrado em Música.</li><li>Conquistou o 3º. lugar no “VI Concurso Nacional de Interpretação de Música Contemporânea”.</li><li>Apresentou-se no Centro Cultural de de Canals no &quot;CONCERT INAUGURAL XIV edició SOXXI&quot; com Clamat-Colectivo Variável.</li></ul><p>2.    <span style="font-weight:bold">2023</span></p><ul><li>Estreou a peça para septeto de percussão <span style="font-style:italic">&quot;GEOMETRIAS&quot;</span> de <span style="font-weight:bold">Angela Lopes</span>.</li><li>Estreou a peça de <span style="font-weight:bold">Ricardo Ribeiro</span>: &quot;<span style="font-style:italic">Igne Natura Renovatur Integra II [2023]&quot; </span>para trio de percussão.</li><li>Lançou um projeto da Associação de Criação Artistica &quot;Os Moustache&quot; em conjunto com a BigBand da <span style="font-weight:bold">AMDF.</span></li></ul><p>3.<span style="font-weight:bold">    2022</span></p><ul><li>Estreou a peça <span style="font-style:italic">&quot;Composing in real time I (Para os Irmãos Leitão)&quot; </span>de Tiago de Matos, para duo de sax e percussão.</li><li>Estrou a peça &quot;Seatherny&quot; de <span style="font-weight:bold">Carla Branco </span>para duo de percussão.</li><li>Estreou a peça <span style="font-style:italic">&quot;Cinzas de Sisifo for Solo Vibraphone and Percussion quintet&quot;</span> de <span style="font-weight:bold">Francisco Ribeiro.</span></li><li>Co-fundou a Associacção de Criação Artistica &quot;Os Moustache&quot;.</li></ul><p>4.   <span style="font-weight:bold"> 2021</span></p><ul><li>Conquistou o 2º. lugar no &quot;IV Concurso Nacional de Interpretação de Música Contemporânea”</li><li>Concluiu o <span style="font-weight:bold">VIII Grau</span> em música com nota máxima.</li><li>Estreia nacional <span style="font-style:italic">&quot;The Endings of Things from a Distance&quot; </span>de <span style="font-weight:bold">M. Burrit</span>.</li></ul><p> </p><p>DEPOIMENTOS </p><p> </p><p><span style="font-weight:bold">Universidade de Aveiro:</span> https://www.ua.pt/pt/noticias/0/87738</p><p>                                                  https://www.ua.pt/pt/noticias/1/85515</p><p> </p><p> </p><p> </p>', NULL, 'https://static.wixstatic.com/media/691d8a_1ffdde81b4004b9586f0570a788c85b3~mv2.jpg', NULL, 'https://static.wixstatic.com/media/691d8a_bb81a5fd87e447b491dd386210281989~mv2.jpg', 'Casa da Música', 'https://static.wixstatic.com/media/691d8a_0f7767026e1b4329976b05c77b1e751d~mv2.jpg', 'Casa da Música', 'https://static.wixstatic.com/media/691d8a_b582e202e00e416db4379cb2e2bac2bc~mv2.jpg', 'Universidade de Aveiro', 'https://static.wixstatic.com/media/691d8a_218de648f2314b39ac6ed6b71ba5fd90~mv2.jpg', 'Universidade de Aveiro', 'https://static.wixstatic.com/media/691d8a_2e974897180543288073d4c31c64800d~mv2.jpg', 'Universidade de Aveiro', 'https://static.wixstatic.com/media/691d8a_0e3a7b46a49f43afbba57bf7fdc87837~mv2.jpg', NULL, 'https://static.wixstatic.com/media/691d8a_35465f3fbd994f72aea2b57289d619f2~mv2.jpg', 'Universidade de Aveiro', 'https://static.wixstatic.com/media/691d8a_a87abcad6726423a9d929f2973d4d87e~mv2.jpg', 'Universidade de Aveiro', 'https://static.wixstatic.com/media/691d8a_ca8a27e6c8ca4aa9900003dd58c36c2f~mv2.jpg', 'Universidade de Aveiro', 'https://static.wixstatic.com/media/691d8a_1efc14292f58492d834ddc1a3bec64db~mv2.jpg', 'Casa da Música', NULL, NULL, 1, 0, 0);

-- Row 63: Bárbara Barradas
INSERT IGNORE INTO users (id, email, password, role) VALUES ('f9ff5013-9a86-4fc8-b49f-01153f4ea183', 'wix-f9ff5013@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('9833dcf6-5875-415b-9d7a-8c56ff547a8d', 'f9ff5013-9a86-4fc8-b49f-01153f4ea183', 'barbara-barradas', 'Bárbara Barradas', 'Bárbara', '999999999', '1984-07-08', 'Portugal', 'Lisboa, Portugal', 'Lisboa', 'xxxx', NULL, '1800', 'Soprano', NULL, 'https://static.wixstatic.com/media/f9ff50_bf4188ab647a42de9c0bcce74dc49548~mv2.jpg', 'wix:document://v1/f9ff50_2dfc84f9e63f43df96640c0e9918d010.pdf/B%C3%A1rbara%20Barradas%20PT.pdf', NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/f9ff50_835b67130be24b78a53bef7a3d45ade9.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=c_jikvVguG0', 'https://www.youtube.com/watch?v=uugnDnRBunM', 'https://www.youtube.com/watch?v=h3b0O9WBeEs', 'https://www.youtube.com/watch?v=a9xxqVecCi4', 'https://www.youtube.com/watch?v=F7H8uMogyFI', NULL, NULL, NULL, NULL, NULL, '<p class="font_8"><em>"É uma cantora nata, com uma voz redonda e bela e uma presença em palco excecional</em>." Ingo Kolonerics</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Bárbara Barradas é uma das mais cativantes <strong>sopranos líricas</strong> da atualidade. Dona de uma <strong>voz poderosa</strong>,<strong> volumosa</strong> e <strong>vibrante</strong>, tem sido consistentemente aclamada pela crítica e pelo público. A sua técnica impecável, aliada a uma musicalidade ímpar e sensibilidade artística, permitem-lhe brilhar nos mais desafiadores papéis do repertório lírico, especialmente do belcanto.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">O seu <strong>timbre redondo</strong> e <strong>flexível </strong>revela qualidades únicas como o domínio da <strong>messa di voce</strong> e o brilho nos agudos sublimes e cristalinos. É capaz de dar vida de maneira muito própria aos mais desafiadores papéis líricos e é a sua <strong>entrega cénica autêntica e comunicativa</strong> que realmente arrebata as plateias.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Bárbara tem a rara habilidade de fundir <strong>virtuosismo técnico</strong> a <strong>uma presença magnetizante</strong>, o que faz com que suas interpretações sejam uma experiência emotiva e inesquecível.</p>', '<p>A paixão de Bárbara Barradas pela música manifestou-se desde tenra idade e a sua inclinação natural para as artes revelou-se também no amor pela dança, tendo iniciado aulas de ballet aos cinco anos.</p><p> </p><p>O talento precoce para o canto levou-a a ingressar no<span style="font-weight:bold"> Coro Jovens Cantores de Lisboa</span>, onde se destacou como solista e gravou seu primeiro disco de música pop infantil. Aos dez anos, realizou um sonho ao integrar o grupo Onda Choc. Começou a participar em programas de televisão todas as semanas e entre os oito e os 16 anos fez o seu percurso na música pop. Embora tenha feito uma pausa na aprendizagem do ballet aos doze anos, porque a música exigia muito de si, acabou por completar o 8º grau entre os 18 e os 21 anos.</p><p> </p><p>Aos 19 anos, toma uma decisão que seria determinante na sua carreira: prestes a lançar um disco pop, Bárbara decidiu dedicar-se integralmente ao canto lírico. Iniciou os estudos no <span style="font-weight:bold">Conservatório Nacional com José Carlos Xavier</span>. Entretanto, ganhou o <span style="font-weight:bold">Prémio Revelação no Concurso Nacional de Canto Luísa Todi e uma bolsa de estudo da Gulbenkian</span>.</p><p> </p><p>Continuou a sua formação na prestigiada <span style="font-weight:bold">Guildhall School of Music &amp; Drama</span>, em Londres, onde aprimorou exaustivamente sua técnica vocal com mestres como <span style="font-weight:bold">Susan Waters</span>. Terminou o mestrado (Bmus e Mmus em Canto) e fez parte do Flanders Opera Studio e da Wales Academy of Voice &amp; Dramatic Arts. </p><p> </p><p>Participou em Masterclasses com Dame Kiri Te Kanawa, Enza Ferrari, Mara Zampiere, Ann Murray, Graham Johnson, Dennis O&#x27;Neill, Sarah Walker, Nelly Miricioui, Tom Krause (ENOA), entre outros.</p><p> </p><p>Ao 23 anos, estreou-se no seu <span style="font-weight:bold">primeiro grande papel, interpretando Gilda, na ópera &quot;Rigoletto&quot; de e Giuseppe Verdi</span>, no Festival de Ópera de Óbidos, para o qual se preparou com Lúcia Lemos.</p>', '<h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p> </p><p><span style="font-weight:bold">2024 </span>- Lançou os projetos EmpoderArte e BBYOURVOICEMETHOD. Participa em &quot;Requiem pelas vítimas do Fascismo em Portugal de Lopes-Graça&quot; e na cantata em comemoração do Centenário do Nascimento de Joly Braga Santos.</p><p><span style="font-weight:bold">2023 </span>- Criou o projeto &quot;Empodera-te na Voz&quot;.</p><p><span style="font-weight:bold">2022 </span>- Fez o papel de Corinna na ópera &quot;Il Viaggio a Reims&quot; de Gioachino Rossini.</p><p><span style="font-weight:bold">2020-2021</span> - Investiu em desenvolvimento pessoal. Criou a &quot;Masterclass 2 em 1&quot; com a mezzo-soprano Cátia Moreso e o &quot;Art Allurement&quot; com a mezzo-soprano Cátia Moreso, o pianista Vasco Dantas e a atriz e encenadora Sónia Aragão. Começou a dar aulas de canto online.</p><p><span style="font-weight:bold">2019 </span>- Fez audições em Nova York, Viena e Alemanha.</p><p><span style="font-weight:bold">2017 </span>- Regressou a Portugal.</p><p><span style="font-weight:bold">2015 </span>- Fez o papel de Lucia na ópera &quot;Lucia di Lammermoor&quot; no Oper im Berg Festival.</p><p>Formação contínua - Aulas de canto com a Professora Lúcia Lemos em Portugal e Paula Anglin em Londres.</p><p><span style="font-weight:bold">2011/12</span> - Paricipou na Wales International Academy of Voice (Part-time), dirigida por Dennis O&#x27;Neill e patrocinada por Dame Kiri Te Kanawa.</p><p><span style="font-weight:bold">2010/11 </span>- Participou no Flandres Operastudio – Bélgica.</p><p>Julho de 2010 - Terminou o Curso MMus Guildhall Artists em formação vocal, na Guildhall School of Music and Drama.</p><p><span style="font-weight:bold">2006-2009</span> - Terminou o Curso de BMus em Canto na Guildhall School of Music and Drama, com Distinção.</p><p><span style="font-weight:bold">2003-2005</span> - Concluiu o 2º ano do Curso de Design na Universidade de Belas Artes em Lisboa.</p><p><span style="font-weight:bold">1999-2005 </span>- Integrau o grupo Onda Choc.</p><p><span style="font-weight:bold">1994-2002</span> - Estudou na Royal Academy of Dance e termina a formação de oito anos de ballet com Distinção.</p><p><span style="font-weight:bold">1994-2006</span> - Estudou no Conservatório Nacional de Música de Lisboa (Piano – sete anos; Canto – três anos).</p><p>Em concerto e recital, atuou em vários palcos em Portugal e no estrangeiro, incluindo: Fundação Gulbenkian, Centro Cultural de Belém, Fórum Luísa Todi, Ronnie Scott‘s Jazz Club e St. James Theatre (Londres), Henley Festival, Glyndebourne Chorus Opera Festival, Oper im Berg Festival (Salzburgo) e deSingel (Antuérpia).</p><p> </p><p><span style="font-weight:bold">PRÉMIOS</span></p><p> </p><p>Prémio no Concurso Jovens Clássicos no Fórum Luísa Todi – Portugal (2013)</p><p>Prémio Donizetti (Interpretação como Lucia – Lucia di Lammermoor – Donizetti) – Grandi Voci em Salzburgo (2013)</p><p>Prémio e Prémio do Público no 7º Concurso de Canto Lírico da Fundação Rotária Portuguesa no CCB em Lisboa (2013)</p><p>Foi escolhida para competir na final da competição Leyla Gencer (2012)</p><p>3º Prémio, Prémio de Melhor Canção e Prémio do Público no 5º Concurso de Canto Lírico da Fundação Rotária Portuguesa (2011)</p><p>3º Prémio no Concurso Internacional de Ópera Rotary, no Teatro Nacional São Carlos, Lisboa (2010)</p><p>Prémio do Público no 4º Concurso de Canto Lírico da Fundação Rotária Portuguesa (2010)</p><p>2º Prémio no Concurso de Ária da Guildhall (2009)</p><p>Prémio Bocage - Concurso de Canto Lírico Luísa Todi (2005)</p><p> </p><h3><span style="font-weight:bold">FORMAÇÃO</span></h3><p> </p><p><span style="font-weight:bold">Flandres Operastudio </span>– Bélgica (2010-11)</p><p>Wales International Academy of Voice (Part-time) dirigido por <span style="font-weight:bold">Dennis O&#x27;Neill </span>e patrocinado por <span style="font-weight:bold">Dame Kiri Te Kanawa</span> (2010)</p><p><span style="font-weight:bold">MMus Guildhall Artists</span> - curso de formação vocal, Guildhall School of Music e</p><p>Drama   (2006-2009)</p><p><span style="font-weight:bold">BMus Cantando Cours<span style="font-style:italic">e, </span></span>Guildhall Escola de Música e Drama com Distinção</p><p>Bolsa de Estudo - City of London Corporation (2009/10)</p><p>Coaching vocal com a Professora Lúcia Lemos em Portugal e Paula Anglin em Londres.</p><p>Bolsa de Estudo na Fundação Calouste Gulbenkian (2006-2009)</p><p>Bolsa de Estudo - Prémio Vasconcellos (GSMD) (2006-2008)</p><p>Royal Academy of Dance - 8 anos de ballet – com Distinção</p><p>Conservatório Nacional de Música de Lisboa (<span style="font-style:italic">Piano </span>– 7 anos; <span style="font-style:italic">Cantar </span>– 3 anos) (1994-2006)</p><p>Fez diversas masterclasses ao longo da carreira: Tom Krause (ENOA);  Andrzej Dobber (ENOA); Dame Kiri Te Kanawa;  Ann Murray; Dennis O&#x27;Neill; Graham Johnson; Yvonne Minton; Sarah Walker; Mara Zampieri; Walter Moore; Maestro Paolo Olmi; Pamela Bullock; Peter Robinson; Graham Clark; Anthony Legge;  Nelly Miricioui; Claudio Desideri.</p><p> </p><h3><span style="font-weight:bold">LISTA DE PAPÉIS</span></h3><h3> </h3><ul><li>Lucia - &quot;Lucia di Lammermoor&quot; de Donizetti - Oper im Berg Festival - Salzburgo</li><li>Lucia - &quot;Lucia di Lammermoor&quot; de Donizetti - De Nederlandse Opera (ENOA workshop) - Amesterdão</li><li>Bruna - Estreia da ópera &quot;Canção do Bandido&quot; de Nuno Côrte-Real - TNSC/Teatro da Trindade - Lisboa</li><li>Le Feu e Le Roussignol - &quot;L&#x27;enfant et les Sortiléges&quot; de Ravel - Teatro Nacional de São Carlos - Lisboa</li><li>Inês de Castro - &quot;Inês de Castro&quot; de Giuseppe Giordani - Festival de música de Alcobaça (Portugal)</li><li>Gilda - &quot;Rigoletto&quot; de Verdi - Festival de Ópera de Óbidos (Portugal)</li><li>Gilda – Projeto Victor Hugo – Flandres Operastudio – diretor Vicent Van den Elshout</li><li>Rainha da Noite - Projeto Mozart – Flandres Operastudio – diretora Helen Suyderhoud</li><li>Nice 1 - &quot;Peter Grimes&quot; de B. Britten - Teatro Nacional de São Carlos - Lisboa</li><li>Inês de Castro - &quot;Inês de Castro&quot; de Giuseppe Giordani - Festival de música de Alcobaça (Portugal) com a OrquestraSinfónica Portuguesa (OSP) e o maestro João Paulo Santos</li><li>La Fée - &quot;Cendrillon&quot; de Pauline Viardot - Teatro Nacional de São Carlos - Lisboa</li><li>Amore - Serenata &quot;L’Endimione&quot; de N. Jommelli - maestro Massimo Mazzeo - Orquestra Divino Sospiro</li><li>Susanna - &quot;Le Nozze di Figaro&quot; de Mozart - Fundação Calouste Gulbenkian – (projeto ENOA) – Maestro Paul McCreesh</li><li>Barbarina - &quot;Le Nozze di Figaro&quot; de Mozart - Temporada 2014-15 da Fundação Calouste Gulbenkian – Lisboa – Maestro Paul McCreesh</li><li>Dama di Lady Macbeth - &quot;Macbeth&quot; de Verdi - Teatro Nacional de São Carlos – Lisboa</li><li>Andromede - &quot;Perceu&quot; de João Sousa Carvalho - Divino Sospiro - Palácio Nacional de Queluz - Lisboa</li><li>Delia - &quot;Il Viaggio a Reims&quot; de Rossini - Teatro Nacional de São Carlos – Lisboa</li><li>Branca — &quot;Tição Negro&quot; de Augusto Machado - Teatro Aberto - Lisboa</li><li>Frasquita — &quot;Carmen&quot; de Bizet — Woodhouse Summer Opera Festival– Reino Unido</li><li>Princesa — &quot;O Gato das Botas&quot; de Xavier Montsalvatge — Teatro Nacional de São Carlos - Lisboa</li><li>Donna Anna — &quot;Don Giovanni&quot; de Mozart — Festival Zêzere Arts - Portugal</li><li>Lucia (cover) — &quot;Lucia di Lammermoor&quot; de Donizetti, Opera Holland Park</li><li>Emmie (cover) — &quot;Albert Herring&quot; de Britten, G.S.M.D.</li><li>Maria - &quot;West Side Story&quot; de Bernstein, Teatro Politeama - Lisboa</li><li>Belinda - &quot;Dido and Aeneas&quot; de Purcell, G.S.M.D.</li><li>Zerlina - projeto &quot;Ma guarda il Catalogo! Allora capirai!&quot; - música de Mozart, E.M.C.N. – Lisboa</li></ul>', '<h3><span style="font-weight:bold">PROJETOS</span></h3><ul><li>BBYOURVOICEMETHOD®️</li><li><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://barbarabarradassop.wixsite.com/empoderarte target=_blank>EmpoderArte</a></span></span></li><li>Masterclass de Canto 2 em 1 (com a mezzo-soprano Cátia Moreso).</li><li>Art Allurement (com a mezzo-soprano <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://smart.proart.art/artista/c%C3%A1tia-moreso target=_blank>Cátia Moreso</a></span></span>, o pianista <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://smart.proart.art/artista/vasco-dantas target=_blank>Vasco Dantas</a></span></span> e a atriz e encenadora Sónia Aragão).</li></ul><h3><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h3><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/soprano_barbara_barradas target=_blank>PorART Entrevista</a></span></span></span> - Bárbara Barradas - A voz como reflexo da alma</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.facebook.com/provaoral/videos/597789904181455 target=_blank>Prova Oral (2020)</a></span></span></span> - Bárbara Barradas - Soprano</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.publico.pt/2018/11/02/culturaipsilon/noticia/cantando-razao-estado-conquista-amor-1849495 target=_blank>Público (2018)</a></span></span></span> - Cantando a razão de Estado que conquista o amor</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.rtp.pt/programa/tv/p24456/e1 target=_blank>RTP - Bravo</a></span></span> </span>- Bárbara Barradas - Cantora</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://arquivos.rtp.pt/conteudos/barbara-barradas-e-pedro-bargado/ target=_blank>RTP (2009)</a></span></span></span> - Bárbara Barradas e Pedro Bargado</p><p> </p><h3>Quer saber mais?</h3><h3>Entre em contacto connosco!</h3>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

