INSERT IGNORE INTO users (id, email, password, role) VALUES ('05a9d55a-ce0f-459c-ad35-34bfa6d1fea5', 'wix-05a9d55a@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('3e6cb2bf-f70d-44c7-8cca-93dd677b38fe', '05a9d55a-ce0f-459c-ad35-34bfa6d1fea5', 'maria-mendes', 'Maria Mendes', 'Maria', '''+351961373445', '1999-06-05', 'Portugal', 'Portugal', 'Fundão', 'Rua Cidade Castelo Branco', 'Vivenda Isabel', '6230-347', 'Soprano', NULL, 'https://static.wixstatic.com/media/05a9d5_cb95a90a285949d9bfc6c8e6fa3ac92d~mv2.jpeg', 'wix:document://v1/ugd/7b859e_e78263a50459486b9579d2a1d6555468.pdf/Maria%20Mendes%20Bio.pdf', 'https://www.facebook.com/MariadaSilvaMendes', 'https://www.instagram.com/mariamendessoprano/', NULL, NULL, 'https://www.youtube.com/@MariaMendesSoprano', 'https://static.wixstatic.com/mp3/05a9d5_84ef2cc7ab3e4e4a9f043f80e8224ae3.wav', NULL, NULL, 'https://www.youtube.com/watch?v=vtoGBpMMonE', 'https://www.youtube.com/watch?v=7pxL-ityqX8', 'https://www.youtube.com/watch?v=v1vXnMsRNT4', 'https://www.youtube.com/watch?v=szjTZXBkeX0', 'https://www.youtube.com/watch?v=1FJwvILW-R0', 'https://www.youtube.com/watch?v=x4cPNhlSst4', NULL, NULL, NULL, NULL, '<p><span style="font-weight:bold">Maria da Silva Mendes</span> é mestre em Canto pela <span style="font-weight:bold">ESMAE</span> e, atualmente, prepara-se para realizar um Concerto de Novos Intérpretes, inserido no Projeto Canção com o pianista João Sousa. Com quem ganhou o <span style="font-weight:bold">Prémio Helena Sá e Costa</span> no ano 2021. No ano transato, venceu o <span style="font-weight:bold">3º Prémio Jovens Músicos</span>.</p><p> </p><p>Estreou-se no mundo da ópera no <span style="font-weight:bold">Ateliê de Ópera da Metropolitana</span> em 2019/20, interpretando o papel de <span style="font-weight:bold">Adina</span> em <span style="font-style:italic">L&#x27;elisir d&#x27;amore</span>, de <span style="font-style:italic">Donizetti</span>, sob a direção do Maestro <span style="font-weight:bold">Pedro Amaral</span>. </p><p>O seu repertório de ópera inclui os seguintes papéis: <span style="font-weight:bold">Fiordiligi</span>, em <span style="font-style:italic">Così fan tutte </span>de <span style="font-style:italic">Mozart; </span><span style="font-weight:bold">Donna Elvira</span>, em <span style="font-style:italic">Don Giovanni </span>de <span style="font-style:italic">Mozart</span>; <span style="font-weight:bold">Contessa</span>, em<span style="font-weight:bold"> </span><span style="font-style:italic">Le Nozze di Figaro </span>de <span style="font-style:italic">Mozart; </span><span style="font-weight:bold">Leonor</span>, em <span style="font-style:italic">Os Noivos </span>de Sá <span style="font-style:italic">Noronha; </span><span style="font-weight:bold">Rita</span>, em <span style="font-style:italic">Rita </span>de <span style="font-style:italic">Donizetti.</span></p><p>Em concerto com solista, a soprano interpretou obras sacras como o &quot;<span style="font-style:italic"><span style="font-weight:bold">Exultate Jubilate</span></span>&quot; de <span style="font-style:italic">Mozart;</span> &quot;<span style="font-style:italic"><span style="font-weight:bold">Shéhérazade</span></span>&quot; de <span style="font-style:italic">Ravel; &quot;<span style="font-weight:bold">Misa a Buenos Aires</span>&quot; </span>de <span style="font-style:italic">Palmeri; &quot;<span style="font-weight:bold">Missa Partoral</span>&quot; </span>de<span style="font-style:italic"> Kempter</span>.</p><p> </p><p>Maria Mendes também se destaca na área da <span style="font-weight:bold">Música Antiga</span>, apresentando-se regularmente com o grupo <span style="font-weight:bold">Suave Armonia</span>, com quem gravou um CD, e no duo <span style="font-weight:bold">Vozes do Passado</span>, ao lado de <span style="font-weight:bold">Mariana Santos</span>.</p><p> </p><p>Além disso, é frequentemente convidada para concertos como <span style="font-weight:bold">solista</span> com orquestra e recitais de piano. Na vertente coral, apresenta-se regularmente como reforço no <span style="font-weight:bold">Coro do Teatro Nacional de São Carlos</span>.</p>', '<p class="font_8">Desde pequena, a arte sempre fez parte da sua vida. Aos três anos, começou a aprender ballet, na Academia de Música e Dança do Fundão. Mas foi aos cinco que a música entrou definitivamente na sua história, quando inicou as aulas de piano na classe da Prof. Olga Silva com quem terminou o ensino básico de piano.</p>
<p class="font_8"><br></p>
<p class="font_8">Nos seus tempos livres frequentava aulas de teatro na ESTE (Estação Teatral), onde participou nos projetos finais durante 5 anos. O teatro trouxe-lhe novas formas de se expressar e ajudou-a a ganhar confiança em palco, ensinando-lhe o poder da palavra e da emoção.</p>
<p class="font_8"><br></p>
<p class="font_8">O gosto pela dança não se ficou apenas pelo ballet. Aos 8 anos começou a ter aulas de danças de salão, que só deixou passados 10 anos.</p>
<p class="font_8"><br></p>
<p class="font_8">Entretanto, uma nova paixão surgiu: o canto. Através dos coros, descobriu o talento vocal. Como não havia "orquestra de pianos", o coro tornou-se a sua forma de fazer música em conjunto, o que a levou a perceber o quanto gostava de cantar. O canto acabou por unir tudo o que já amava — a música, o teatro e a expressão artística — e tornou-se uma parte essencial da sua vida.</p>
<p class="font_8"><br></p>
<p class="font_8">Essas experiências moldaram a sua personalidade e continuam a guiar o seu caminho artístico.</p>', '<p class="font_8"><strong>Prémios:</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8">Foi galardoada com o terceiro prémio na variante Canto, nível superior no Prémio Jovens Músicos 2024.</p></li>
  <li><p class="font_8">Vencedora do 2º Prémio do Concurso Cidade de Gaia (2023).</p></li>
  <li><p class="font_8">Em 2022 foi galardoada com o primeiro prémio Concurso Lions Clube, onde representou Portugal na final europeia na Croácia.</p></li>
  <li><p class="font_8">Vencedora do Prémio Helena Sá e Costa no ano de 2022.</p></li>
  <li><p class="font_8">Vencedora do 2º Prémio (nível I) variante Canto do Concurso Internacional de Música Cidade de Almada, no ano de 2017.</p></li>
  <li><p class="font_8">Vencedora do 2º Prémio (nível III) variante Canto da XVII edição do Concurso Internacional Cidade do Fundão, no ano de 2016. Na mesma edição foi-lhe ainda atribuido o Prémio de Melhor Candidata da Beira Interior.</p></li>
  <li><p class="font_8">Vencedora da Menção Honrosa (nível Infantil A) variante Piano da VIII edição do Concurso Internacional Cidade do Fundão no ano de 2007.</p></li>
</ul>', '<p><span style="font-weight:bold">AGENDA</span></p><p> </p><p><span style="font-weight:bold">Abril</span></p><p> </p><p>11  | 21h00 </p><p>PAIXÃO SEGUNDO SÃO JOÃO, BWV 245</p><p>CONCERTO IBÉRICO – BAROQUE ORCHESTRA and CHOIR</p><p>Igreja Matriz de Idanha-A-Nova </p><p> </p><p>12  | 21h00 </p><p>PAIXÃO SEGUNDO SÃO JOÃO, BWV 245</p><p>Igreja Matriz de Crato</p><p> </p><p>13  | 21h00 </p><p>PAIXÃO SEGUNDO SÃO JOÃO, BWV 245</p><p>Sé Concatedral de Castelo Branco </p><p> </p><p>26 | 16h30</p><p><span style="font-style:italic">Hoc est enim corpvs mevm</span>, com Schola Cantorum  Colegiada de Cedofeita</p><p>Festival Cistermúsica</p><p>Igreja Paroquial de Nossa Senhora da Conceição de Turquel</p><p> </p><p> </p>', 'https://static.wixstatic.com/media/05a9d5_aebdf4be03844d7d884bbcd82953961b~mv2.jpg', NULL, 'https://static.wixstatic.com/media/05a9d5_788c1d422778444ebea499ed986a96ec~mv2.jpg', '© Ana Rosa', 'https://static.wixstatic.com/media/05a9d5_733191b750cc4a7dae85f9be75419f4a~mv2.jpg', 'L''elisir d''amore, Adina (Donizetti) CCB 2020', 'https://static.wixstatic.com/media/05a9d5_7de2b7cf791649faa64fed0b47e3ec1c~mv2.jpg', 'Rita, Rita (Donizetti) Paços de Brandão 2021', 'https://static.wixstatic.com/media/05a9d5_b3b6ce2ed0a24bd7a3d16e83f36fdc7c~mv2.jpg', 'Rita, Rita (Donizetti) Paços de Brandão 2021', 'https://static.wixstatic.com/media/05a9d5_f7082b3b60d34dfb92a6a6b3a86d85fe~mv2.jpg', 'Suave Armonia, Ecos, Voltas & Negros, Coimbra 2022', 'https://static.wixstatic.com/media/05a9d5_3928897c5d2f4f7bbeadc712daabd87f~mv2.jpg', 'L''elisir d''amore, Adina (Donizetti) Oslo 2023', 'https://static.wixstatic.com/media/05a9d5_4422c674f9854373abafd525680b0150~mv2.jpg', 'L''elisir d''amore, Adina (Donizetti) Oslo 2023', 'https://static.wixstatic.com/media/05a9d5_7d5cb3a6b5f24ddf9f48c8e20a47f507~mv2.jpg', '© Daniela Gil', 'https://static.wixstatic.com/media/05a9d5_c9e21a194abd421fb59c1b2f71c7db01~mv2.jpg', '© Daniela Gil', 'https://static.wixstatic.com/media/05a9d5_b3c08ec4e0b94c5cade8799ac95b49a9~mv2.jpg', '© CORAL', 'https://static.wixstatic.com/media/05a9d5_f261978af95f4fc99c289186a07d9658~mv2.jpg', '© CORAL', 1, 0, 0);

-- Row 67: João Barradas
INSERT IGNORE INTO users (id, email, password, role) VALUES ('cd412d1f-3886-48a6-ba23-f188e88b6daf', 'wix-cd412d1f@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('90b881f5-17a6-44e5-9ef3-b49c2e3341c7', 'cd412d1f-3886-48a6-ba23-f188e88b6daf', 'joao-barradas', 'João Barradas', 'João', '999999999', '1993-07-02', 'Portugal', 'Portugal', 'Lisboa', 'xxxxxxxx', NULL, '1800', 'Acordeonista contemporâneo', '"Adoro criar, compor, imaginar e tocar. A música para mim é a libertação da alma."', 'https://static.wixstatic.com/media/cd412d_be1399cda6df4f6692ad27cc6411e678~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/cd412d_89a515943f9748a8ab384e615aecc718.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=l-WLkVskIFU', 'https://www.youtube.com/watch?v=vtHR74HRNJ8', 'https://www.youtube.com/watch?v=M5_VfEOD0sw', 'https://www.youtube.com/watch?v=NpKOSQZa8NU', 'https://www.youtube.com/watch?v=Y3UhjR0QA4U', 'https://www.youtube.com/watch?v=ylbjICB9OZA', 'https://www.youtube.com/watch?v=l-WLkVskIFU&embeds_referring_euri=https%3A%2F%2Fwww.smartx.art%2F&embeds_referring_origin=https%3A%2F%2Fwww.smartx.art&feature=emb_imp_woyt', 'https://www.youtube.com/watch?v=1cLLJbziabM', 'https://www.youtube.com/watch?v=bpZ1HYxTk84', 'https://www.youtube.com/watch?v=NpKOSQZa8NU', '<p class="font_8">O João Barradas é um dos músicos mais entusiasmantes e inventivos que já conheci. A sua música é uma verdadeira revelação." Edward Gardner, Maestro.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>João Barradas</strong> é um dos mais talentosos e criativos <strong>acordeonistas </strong>da atualidade, alargando as fronteiras do seu instrumento tanto na <strong>música clássica</strong> como no <strong>jazz</strong>. Com uma técnica virtuosística combinada com uma imaginação musical única, ele encanta o público em todo o mundo.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">É aclamado internacionalmente, tendo atuado em espaços icónicos como <strong>Wiener Konzerthaus</strong>, <strong>Fundação Calouste Gulbenkian</strong> e <strong>Festival d''Aix-en-Provence</strong>. É solista de algumas das principais orquestras da Europa, como a <strong>Filarmónica de Londres</strong>, a <strong>Tonhalle-Orchester de Zurique</strong> e a <strong>Orquestra de Câmara de Colónia</strong>.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">No jazz, João expandiu significativamente a presença do acordeão, colaborando com improvisadores lendários como <strong>Mark Turner</strong>, <strong>Greg Osby</strong> e <strong>Gil Goldstein</strong>. A sua música combina virtuosismo técnico, sentido de improvisação e expressividade profunda.</p>', '<p class="font_8">João Barradas começou a estudar acordeão aos seis anos e aos nove já estava no 2º ano do <strong>Conservatório Nacional</strong>, concluindo o curso com a nota máxima.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">A partir dos 17 anos, <strong>estudou com mestres como Frédéric Deschamps, Greg Osby e João Paulo Esteves da Silva</strong>, que ampliaram suas habilidades técnicas e criativas. Muito jovem, em 2011, lançou o seu primeiro álbum "<a href="https://open.spotify.com/intl-pt/album/40rrVCr9ksyG6ueKA8NW41" target="_blank"><u>Surrealistic Discussion</u></a>", marcando o início da sua carreira discográfica.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">João destaca-se pela sua <strong>abordagem única</strong>, explorando as infinitas possibilidades expressivas do acordeão. A sua música transita fluentemente entre a <strong>tradição clássica e a liberdade criativa do jazz</strong>, refletindo as suas diversas influências e talento multifacetado.</p>', '<p>Ao longo da sua carreira, João Barradas ganhou inúmeros prémios e reconhecimentos, incluindo o prestigiado ECHO Rising Star da European Concert Hall Organization (2019). Foi também nomeado Artista em Residência na Casa da Música, no Porto, e recebeu o Prémio Sir Jeffrey Tate (2024), na Alemanha.</p><p> </p><h3><span style="font-weight:bold">DESTAQUES</span></h3><h3> </h3><ul><li>Solista com orquestras de renome como a Filarmónica de Londres, Tonhalle-Orchester Zurique e Orquestra de Câmara de Colónia</li><li>Colaborações com lendários improvisadores do jazz como Mark Turner, Greg Osby, Gil Goldstein e Aka Moon</li><li>Atuações em prestigiados festivais de jazz como o Jazzaldia, Sopot Jazz Festival e EDP Cool Jazz</li><li>Prémios em competições internacionais de acordeão, como o Troféu Mundial de Acordeão (CMA) e a Taça Mundial de Acordeão (CIA)</li><li>Lançamento de álbuns aclamados pela crítica como &quot;Surrealistic Discussion&quot; e &quot;Accordion Dialogues&quot;</li></ul><p>Com a sua técnica virtuosa, imaginação criativa e musicalidade profunda, João Barradas conquistou fãs e admiradores em todo o mundo, consolidando o seu lugar como uma das vozes mais importantes do acordeão na atualidade.</p><p> </p><h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p> </p><p><span style="font-weight:bold">2024</span></p><ul><li>Artista em Residência - Casa da Música</li><li>Prémio Sir Jeffrey Tate da Sinfonia de Hamburgo</li></ul><p><span style="font-weight:bold">2023</span></p><ul><li>Vodafone Prémios Play - Nomeado para Melhor Álbum de Música Clássica</li></ul><p><span style="font-weight:bold">2022</span></p><ul><li>Vodafone Prémios Play - Nomeado para Melhor Álbum de Música Clássica</li></ul><p><span style="font-weight:bold">2021</span></p><ul><li>Vodafone Prémios Play - Nomeado para Melhor Álbum de Jazz</li></ul><p><span style="font-weight:bold">2020</span></p><ul><li>Músico de Jazz Português do Ano - Jazzlogical</li><li>2º Prémio de Composição SPA/Antena 2 para Orquestra Sinfónica</li><li>BBC Music Magazine - Indicado ao Rising Star</li></ul><p><span style="font-weight:bold">2019</span></p><ul><li>ECHO Rising Star 2019/2020 pela Organização Europeia de Salas de Concertos</li></ul><p><span style="font-weight:bold">2018</span></p><ul><li>Melhor Grupo de Jazz - Jazzlogical</li><li>Músico de Jazz Português do Ano - Jazzlogical</li><li>Prémio de Mérito &quot;IPL - Instituto Politécnico de Lisboa&quot;</li></ul><p><span style="font-weight:bold">2017</span></p><ul><li>Nomeado Melhor Álbum do Ano do Downbeat - João Barradas &quot;Directions&quot;</li><li>RTP / Festa do Jazz - Novo Melhor Artista</li><li>RTP / Festa do Jazz - Melhor Grupo</li></ul><p><span style="font-weight:bold">2016</span></p><ul><li>1º Prémio - Prémio Jovem Músico - Jazz</li></ul><p><span style="font-weight:bold">2015</span></p><ul><li>1º Prémio no Concurso de Jazz Made in New York (Todas as Categorias)</li><li>1º Prémio no Concurso de Jazz Made in New York (Categoria Solo Instrumental)</li></ul><p><span style="font-weight:bold">2014</span></p><ul><li>Prémio Melhor Intérprete – Folefest 2014</li><li>1º Prémio Folefest 2014</li></ul><p><span style="font-weight:bold">2013</span></p><ul><li>1º Prémio no 7º V Festival de Acordeão Roland Iberia</li><li>1º Prémio na 11ª Festa do Jazz do Teatro S. Luiz, Lisboa</li><li>Prémio Melhor Intérprete – Folefest 2013</li><li>1º Prémio Folefest 2013</li></ul><p><span style="font-weight:bold">2012</span></p><ul><li>1º Prémio EDP Cool Jazz Talents, Portugal</li></ul><p><span style="font-weight:bold">2010</span></p><ul><li>1º Prémio no 60º Troféu Mundial de Acordeão (CMA), Espanha – Clássico Juvenil</li><li>1º Prémio na 63ª Taça do Mundo de Acordeão (CIA), Croácia, Juvenil Clássico</li><li>1º Prémio no 16º Troféu Nacional de Acordeão, categoria Concerto Juvenil</li><li>1º Prémio Acordeão Internacional &quot;Cidade de Alcobaça&quot;</li><li>Prémio Especial &quot;Acordeões Pigini&quot; no 63º CIA Coupe Mundial (Croácia)</li></ul><p><span style="font-weight:bold">2009</span></p><ul><li>1º Prémio no 15º Troféu Nacional de Acordeão, categoria Concer Juvenil</li></ul><p><span style="font-weight:bold">2008</span></p><ul><li>1º Prémio no 14º Troféu Nacional de Acordeão, categoria Concerto Juvenil</li><li>Menção Honrosa como instrumentista/solista, na 7ª Festa do Jazz de São Luiz.</li></ul><p><span style="font-weight:bold">2007</span></p><ul><li>1º Prémio no 57º Troféu Mundial de Acordeão (CMA), Rússia, Junior Varietté</li><li>Menção Honrosa da Instituição Musical Vitorino Matono</li><li>Medalha de Mérito da Câmara Municipal de Benavente</li><li>Embaixador pela Câmara Municipal de Samora Correia para Portugal e estrangeiro.</li><li>1º Prémio no 13º Troféu Nacional de Acordeão, categoria Ligeiro Juvenil</li><li>1º Prémio no 13º Troféu Nacional de Acordeão, categoria Concerto Juvenil</li><li>1º Prémio 2º Concurso de Acordeão, Acordeons de Vila de Cedeira, Espanha, Junior</li><li>1º Prémio no 4º Troféu Acordeão Ibérico, categoria Ligeiro Juvenil</li><li>1º Prémio no 4º Troféu Acordeão Ibérico, categoria Concerto Juvenil</li></ul><p><span style="font-weight:bold">2006</span></p><ul><li>1º Prémio no 12º Troféu Nacional de Acordeão, categoria Ligeiro Juvenil</li><li>1º Prémio no 12º Troféu Nacional de Acordeão, categoria Concerto Juvenil</li><li>1º Prémio no 3º Troféu Acordeão Ibérico, categoria Ligeiro Juvenil</li><li>1º Prémio no 3º Troféu Acordeão Ibérico, categoria Concerto Juvenil</li><li>1º Prémio em Vila de Cedeira, 1º Concurso de Acordeão, Espanha, categoria Junior Classica</li></ul><p><span style="font-weight:bold">2005</span></p><ul><li>1º Prémio no 11º Troféu Nacional de Acordeão, categoria Juvenil Ligeiro</li></ul><p><span style="font-weight:bold">2004</span></p><ul><li>1º Prémio no 29º Prémio Internacional &quot;Citta di Castelfidardo&quot;, Itália, categoria H</li><li>Prémio Especial &quot;Intermusik Schmulling&quot; (Alemanha)</li><li>Prémio André Thepaz (Itália)</li></ul><p><span style="font-weight:bold">2003</span></p><ul><li>1º Prémio no 36º Concurso Internacional de Acordeão, Croácia, categoria B</li></ul><p><span style="font-weight:bold">2002</span></p><ul><li>1º Prémio no 8º Troféu Nacional de Acordeão, categoria Infantil</li><li>Um dos vencedores do concurso de talentos &quot;Bravo Bravíssimo&quot;, da SIC</li></ul><p><span style="font-weight:bold">2001</span></p><ul><li>1º Prémio no 13º Festival de Acordeão Barra Cheia</li></ul><p><span style="font-weight:bold">2000</span></p><ul><li>1º Prémio no 12º Festival de Acordeão Barra Cheia</li><li>1º Prémio no 6º Troféu Nacional de Acordeão, categoria Iniciado</li></ul>', '<h3><span style="font-weight:bold">PROJETOS</span></h3><h3> </h3><ul><li>Mentor no Programa de Mentoria da Fundação Gulbenkian (desde 2022)</li><li>Curador do Festival Internacional de Acordeão de Lisboa (desde 2020)</li></ul><p> </p><h3><span style="font-weight:bold">ÁLBUNS</span></h3><h3> </h3><p>Poderá encontrar e ouvir todos os álbuns do Artista na sua página do <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://open.spotify.com/intl-pt/artist/275OcE98O0YY37MEZDYKYQ target=_blank>Spotify</a></span></span>.</p><p> </p><h3><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h3><h3> </h3><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=ODqfiEzPxhc target=_blank>Coffeepaste (2024)</a></span></span> - João Barradas e Luís Tinoco em Londres (entrevista)</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://inandout-jazz.es/2024/02/joao-barradas-interview-festival-causa-i-efeito-lisboa/ target=_blank>In&amp;Out JAZZ (2024)</a></span></span> - Joao barradas interview. Festival Causa | Efeito (Lisboa)</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://comunidadeculturaearte.com/reportagem-um-dia-no-festival-de-sintra-com-joao-barradas-jonatan-alvarado-e-filho-da-mae/ target=_blank>Comunidade Cultura e Arte (2023)</a></span></span> - Reportagem. Um dia no Festival de Sintra com João Barradas, Jonatan Alvarado e Filho da Mãe</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://defesadeespinho.sapo.pt/2022/03/04/joao-barradas-estou-muito-entusiasmado-e-espero-que-seja-uma-noite-cheia-de-musica-e-boa-disposicao-em-palco/ target=_blank>Defesa de Espinho (2022)</a></span></span> - João Barradas: “Estou muito entusiasmado e espero que seja uma noite cheia de música e boa disposição em palco”</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://comunidadeculturaearte.com/entrevista-joao-barradas-tenho-uma-relacao-dificil-com-aquilo-que-escrevo/ target=_blank>Comunidade Cultura e Arte (2021)</a></span></span> - Entrevista. João Barradas: “Tenho uma relação difícil com aquilo que escrevo”</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://glosas.mpmp.pt/o-regresso-do-cairo-jazz-com-joao-barradas/ target=_blank>Glosas (2021)</a></span></span> - O regresso do cairo jazz com João Barradas</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://gulbenkian.pt/musica/videos/entrevista-a-joao-barradas/ target=_top>Gulbenkian (2020)</a></span></span> - Entrevista a João Barradas</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=eJtKmL_-fH0 target=_blank>Arte das Musas (2020)</a></span></span> - Na primeira pessoa... João Barradas</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://aformadojazz.com/2020/02/joao-barradas-apresenta-dois-discos-solo-i-e-portrait/ target=_blank>A Forma do Jazz (2020</a></span></span>) - João barradas apresenta dois discos: “Solo i” e “Portrait”</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://gerador.eu/pergunta-da-sorte-com-joao-barradas/ target=_blank>Gerador (2018)</a></span></span> - Pergunta da Sorte com João Barradas</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.publico.pt/2018/02/02/culturaipsilon/noticia/joao-barradas-home-e-um-lar-musical-que-nos-alberga-a-todos-1801632 target=_blank>Público (2018)</a></span></span> - João Barradas: “Home é um lar musical que nos alberga a todos”</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=IJJG9OPB9Rk target=_blank>Coffeepaste (2017)</a></span></span> - João Barradas - Entrevista</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://mutante.pt/2017/10/ojm-convida-acordeonista-joao-barradas/ target=_blank>Mutante (2017)</a></span></span> - OJM convida acordeonista João Barradas</p><p> </p><h3>Quer saber mais?</h3><h3>Entre em contacto connosco!</h3>', 'https://static.wixstatic.com/media/cd412d_22d342dad1ba4e5d814a656198d785ae~mv2.jpg', 'London Philharmonic Orchestra. Foto de Edward Gardner', 'https://static.wixstatic.com/media/cd412d_d6d629e036754d5b8fc4cd3d0ef6333e~mv2.jpg', 'Foto de Alfredo Matos', 'https://static.wixstatic.com/media/cd412d_22c1eeb653a540c1baf9b5435c5972db~mv2.jpg', 'João Barradas Trio by Sebas Ferreia', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 68: Laurence Meikle
INSERT IGNORE INTO users (id, email, password, role) VALUES ('eb7cbfc2-3621-41b2-8547-67836aff9439', 'wix-eb7cbfc2@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('d2db57f8-2cc1-4be1-bddc-711a245349df', 'eb7cbfc2-3621-41b2-8547-67836aff9439', 'laurence-meikle', 'Laurence Meikle', 'Laurence', '930596522', '1986-01-08', 'Portugal', 'Portugal', 'Lisbon', 'Rua Helena Vaz da Silva 38-1A', NULL, '1750-446', 'Baixo', 'Ich leb’ allein in meinem Himmel, in meinem Lieben, in meinem Lied - Rückert', 'https://static.wixstatic.com/media/eb7cbf_be35aa078a424530afdc43bc601f2b9c~mv2.jpg', 'wix:document://v1/eb7cbf_a6a8c5e061c04ccc800761e9875798d3.pdf/bio_Meikle_Portugues_24%20smartx.pdf', NULL, NULL, NULL, 'https://open.spotify.com/artist/3LdcoqEoWmkU2EHEQ2b2Ys', NULL, NULL, NULL, NULL, 'https://www.youtube.com/watch?v=NxwQ0-QID3s', 'https://www.youtube.com/watch?v=piFR8guoAt4', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8" style="text-align: justify">O baixo australiano-português Laurence Meikle canta regularmente em muitos dos principais teatros de ópera e salas de concertos do mundo.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">A sua carreira internacional tem-lhe permitido colaborar regularmente com alguns dos maestros mais proeminentes do mundo, como Fabio Luisi, Diego Fasolis, Sir Charles Mackerras, Richard Bonynge, entre outros.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">As suas interpretações de Don Giovanni e Figaro, de Mozart, além de inúmeros papéis no repertório italiano, tiveram êxitos recentes em grandes teatros italianos, como o Teatro San Carlo em Nápoles, o Teatro La Fenice em Veneza e o Teatro Carlo Felice em Génova.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify"><strong>"</strong><em><strong>Laurence Meikle in the role of Count Horn showed what a fine singer he is. With his dark, resonant bass, he reached terrific results</strong></em><strong>” - Bachtrack 2019 (Un Ballo in Maschera, Teatro San Carlo di Napoli)</strong></p>
<p class="font_8">&nbsp;</p>', '<p style="text-align:justify">A paixão de Laurence pelo canto começou desde muito cedo na Austrália, onde se formou e obteve o seu primeiro diploma como ator. Durante os seus estudos de música, fez a sua estreia principal na Ópera de Sydney com a Opera Australia, com apenas 22 anos.</p><p style="text-align:justify"> </p><p style="text-align:justify">A paixão de Laurence pela técnica vocal levou-o a estudar com cantores de renome como John Tomlinson, Thomas Allen, Teresa Berganza e José Carreras, recebendo orientação de Kiri Te Kanawa e do seu professor, Tom Krause.</p><p style="text-align:justify"> </p><p style="text-align:justify">Sempre apaixonado pelo repertório vocal italiano, Laurence prosseguiu a sua carreira em Itália, onde teve a honra de ser escolhido para cantar os principais papéis de Rossini nas produções do bicentenário do Teatro San Carlo, em Nápoles.</p><p style="text-align:justify"> </p><p style="text-align:justify">Algumas das suas memórias de performance favoritas incluem:</p><p style="text-align:justify"> </p><ul><li style="text-align:justify">Cantar numa atuação “by royal command” para a Rainha Isabel II</li><li style="text-align:justify">Cantar o papel de Osmin em <span style="font-style:italic">Die Entführung aus dem Serail</span> de Mozart na lendária produção de Giorgio Strehler no Teatro San Carlo, em Nápoles</li><li style="text-align:justify">Interpretar o papel de Colline em <span style="font-style:italic">La Bohème</span> de Puccini mais de 90 vezes em produções pelo mundo</li><li style="text-align:justify">Interpretar a 14ª Sinfonia de Shostakovich em Lisboa com a Orquestra de Câmara Portuguesa</li></ul>', '<p style="text-align:justify">O baixo australiano-português Laurence Meikle tem ganho reconhecimento internacional no mundo da ópera e dos concertos. Laurence começou sua carreira aos 22 anos na Sydney Opera House, com a Opera Australia, em papéis como Masetto em <span style="font-style:italic">Don Giovanni</span>, Angelotti em <span style="font-style:italic">Tosca</span>, Guglielmo em <span style="font-style:italic">Così fan tutti</span> e Colline em <span style="font-style:italic">La Bohème</span>. Continuou a sua carreira artística nos principais teatros australianos, antes de aprofundar os seus estudos na Royal Academy of Music de Londres, onde obteve o prémio Opera Rara Bel Canto Prize.</p><p style="text-align:justify"> </p><p style="text-align:justify">Ainda enquanto estava no Reino Unido, cantando com a Opera Holland Park, a Grange Park Opera e no London Handel Festival, assinou um contrato com o Deutsches Nationaltheater und Staatskapelle Weimar. Nesse período, o seu repertório contou com 27 novos papéis, entre os quais se destacam o papel principal em <span style="font-style:italic">Don Giovanni</span>, Figaro em <span style="font-style:italic">Le Nozze di Figaro</span>, Elmiro em <span style="font-style:italic">Otello</span> de Rossini, Astolfo em <span style="font-style:italic">Orlando Furioso</span> de Vivaldi, Colline em <span style="font-style:italic">La Bohème</span> (que interpretou mais de 90 vezes), Escamillo em <span style="font-style:italic">Carmen</span>, Hércules em <span style="font-style:italic">Il Giasone</span> di Cavalli, Hobson em <span style="font-style:italic">Peter Grimes</span>, Aeneas em <span style="font-style:italic">Dido e Aeneas</span>, e o papel principal em <span style="font-style:italic">Saul</span> de Handel. Durante este tempo, actuou também com as companhias de ópera de Theatre Erfurt, Theatre Nordhusen, Landestheater Altenburg e Bühnen der Stadt Gera.</p><p style="text-align:justify"> </p><p style="text-align:justify">Como cantor de concerto, apresentou regularmente as principais obras para baixo-barítono, como o <span style="font-style:italic">Messias</span> de Handel, o Requiem de Mozart, também as Missas em Dó menor e da C<span style="font-style:italic">oroação</span>, a Missa <span style="font-style:italic">Nelson</span> de Haydn, as missas de Requiem de Duruflé e Fauré, <span style="font-style:italic">Elijah</span> de Mendelssohn, Stabat Mater de Dvorak, Stabat Mater e <span style="font-style:italic">Petite Messe Sollenelle</span> de Rossini, <span style="font-style:italic">Ein Deutsches Reqieum</span> de Brahms e outras obras de Vivaldi, Schubert, Mozart e, claro, as principais obras de Bach. De entre outras obras notáveis em concertos com orquestra, destacam-se <span style="font-style:italic">Des Knaben Wunderhorn</span> e <span style="font-style:italic">Rückert Lieder</span> de Mahler, <span style="font-style:italic">Seadrift</span> de Delius, <span style="font-style:italic">Five Mystical Songs</span> de Vaughan Williams e<span style="font-style:italic"> L&#x27;enfance du Christ</span> de Berlioz, em locais como o Wigmore Hall, Royal Albert Hall e Cadogan Hall em Londres, na Sydney Opera House, e no Mozarteum em Salzburg, com, por exemplo, a Royal Scottish National Orchestra, os London Handel Players, a Orquestra Gulbenkian, Staatskapelle Weimar, English Chamber Orchestra e English Concert Orchestra.</p><p style="text-align:justify"> </p><p style="text-align:justify">Nos últimos anos colaborou com os maestros Sir Charles Mackerras, Fabio Luisi, Richard Bonynge, Bruno Campanella, Diego Fasolis, Stefano Ranzani, Dame Jane Glover, Renato Palumbo, Stefano Montanari, Donato Renzetti e Richard Hickox. Como músico de câmara, focou-se em obras de Schumann, Schubert, Mahler, bem como em nova música, colaborando com pianistas como Aura Go, Malcolm Martineau, Christopher Glynn, e Piers Lane.</p><p style="text-align:justify"> </p><p style="text-align:justify">A carreira de Laurence em Itália começou em 2017, quando cantou Guglielmo in <span style="font-style:italic">Cosi fan tuttì </span>com Fabio Luisi para o Festival Valle d’Itria. Estreou-se no Teatro di San Carlo em Nápoles no papel de Osmin em <span style="font-style:italic">Die Entführung aus dem Serail,</span> seguido de Zuniga em <span style="font-style:italic">Carmen</span> no Teatro delle Muse Ancona. Fabio Luisi convidou-o a voltar ao Festival do Valle d&#x27;Itria em 2018 no papel principal de Belmonte em <span style="font-style:italic">Margherita d&#x27;Anjou</span> de Meyerbeer, e a cantar numa série de concertos de Vivaldi com Diego Fasolis e I Barocchisti, enquanto era <span style="font-style:italic">cover</span> de Astolfo em <span style="font-style:italic">Orlando Furioso</span>.</p><p style="text-align:justify"> </p><p style="text-align:justify">Entre 2018 e 2019, Laurence voltou ao Teatro San Carlo em vários papéis, incluindo Colline em <span style="font-style:italic">La Bohème</span>, Faraone in <span style="font-style:italic">Mosè in Egitto</span> di Rossini, Portye em <span style="font-style:italic">Lady Macbeth do distrito de Mtsensk </span>e Grenville em <span style="font-style:italic">La Traviata, </span>ao lado do Leo Nucci. Para abrir a temporada 2019-2020, Laurence cantou o papel principal em <span style="font-style:italic">Don Giovanni</span> para o Teatro Sociale di Rovigo, tendo após isso cantado novamente Colline em <span style="font-style:italic">La Bohème,</span> e Sam em <span style="font-style:italic">Un Ballo in Maschera</span> com Donato Renzetti, ambos no Teatro di San Carlo. Foi também solista no Requiem de Mozart para o Teatro Carlo Felice de Genova.</p><p style="text-align:justify"> </p><p style="text-align:justify">Durante o período da pandemia, Laurence lançou um disco com o Concerto Classics, <span style="font-style:italic">The Complete Psalms of Benedetto Marcello</span> com o Ensemble Salomone Rossi, participou num concerto de <span style="font-style:italic">La Rondine</span> de Puccini no Teatro San Carlo em Nápoles, e continuou a apresentar-se em música de câmara, com obras como <span style="font-style:italic">Schwannengesang </span>de Schubert, e <span style="font-style:italic">Dichterliebe</span> de Schumann.</p><p style="text-align:justify"> </p><p style="text-align:justify">Em Portugal, apresentou-se como solista com a Orquestra Gulbenkian, Orquestra Metropolitana de Lisboa, Orquestra de Câmara Portuguesa, Ensemble Mediterrain, e também no Festival Internacional de Musica de Marvão, o Festival de Sintra, em recitais para a Antena 2, na Fundação Museu do Oriente, no Festival Artis XXI, e regressará este verão ao Festival de Marvão.</p><p style="text-align:justify"> </p><p style="text-align:justify">Os principais professores de Laurence foram Ryland Davies e Tom Krause, e trabalhou extensivamente com cantores notáveis, nomeadamente Sir John Tomlinson, Ruggiero Raimondi, Josè Carreras, Sir Thomas Allen e Dame Kiri te Kanawa.</p>', '<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: center"><strong>DISCOGRAFIA</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">MEYERBEER - Margherita d’Anjou, Naxos</p>
<p class="font_8">Orchestra Internazionale d''Italia, Fabio Luisi diretor, com Giulia de Blasis, Anton Rositskiy e Laurence Meikle</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">ELGAR - The Fringes of the Fleet, Somm Recordings</p>
<p class="font_8">Guildford Philharmonic Orchestra, Tom Higgins diretor, Roderick Williams, e Laurence Meikle</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">GLANVILLE HICKS - Sappho, Toccata Classics</p>
<p class="font_8">Orquestra Gulbenkian, Jennifer Condon diretora, com Deborah Polaski, Roman Trekel, Wolfgang Koch, Sir John Tomlinson e Laurence Meikle</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">MARCELLO - Psalms and Sonatas, Dynamic</p>
<p class="font_8">Ensemble Salomone Rossi, Lydia Cevidalli (líder), com meio-soprano Marta Fumagalli, e baixo Laurence Meikle</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: center"><strong>CRÍTICAS (nas línguas originais)</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Laurence Meikle in the role of Count Horn showed what a fine singer he is. With his dark, resonant bass he reached terrific results- Bachtrack 2019 (Un Ballo in Maschera)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Straordinaria su tutti sono le interpretazioni che ci hanno dato di Leporello il basso baritono Fabio Previati e di Don Giovanni, Laurence Meikle anche lui un basso baritono, vero matador delle scene in caccia di “femmine” - Rovigo Oggi 2019 (Don Giovanni)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Sulla base di una pronuncia italiana perfetta ha sostenuto i recitativi con molto autorità - Operaclick 2019 (Don Giovanni)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// La voix puissante, aux graves solides, de Laurence Meikle, n’est jamais prise en défaut - Forum Opera Magazine (Benedetto Marcello Psalms and Sonatas disk)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Grande direzione di Fabio Luisi, bravissimo Guglielmo, Meikle, l’Orchesta perfetta e sempre in grande presenza… - La Buona Musica 2017 (Così fan tutte)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// ...bel timbro e la pertinenza stilistica del fraseggio... Operaclick 2019 (Don Giovanni)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Laurence Meikle, è un uomo molto giovane e molto bello, un tipo cui è difficile resistere - Operaclick 2019 (Don Giovanni)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// ...una deliziosa interpretazione della serenata, "Deh vieni alla finestra" - Operaclick 2019 (Don Giovanni)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Non ultimo il Basilio del basso Laurence Meikle, che ha confermato ciò che ci si aspettava da un artista di oramai chiara fama: volume e rotondità di suono sono state le frecce al suo arco che gli hanno consentito di mettere a segno un altro successo di artista - Oltrecultura 2018 (Il Barbiere di Siviglia)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Buoni pure tutti i comprimari, tra cui si segnala, per volume di voce ed espressività, quella di Laurence Meikle un Sam o Conte Horn in cui all’importanza della voce si unisce quella scenica - Operaclick 2019 (Un Ballo in Maschera)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Ottima prova per gli altri inquilini della soffitta: molto commovente il Colline di Laurence Meikle… - Oltrecultura 2017 (La Bohème)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Notevole anche la prova vocale e teatrale di Laurence Meikle (Horn/Sam) - GB Opera Magazine 2019 (Un Ballo in Maschera)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Laurence was fresh faced and personable Luiz, making his Opera Australia debut in resplendent voice – Opera Opera 2008 (The Gondoliers)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// … a pilar of strength in the ensembles, with impeccable articulation, essential, since the opera is sung in English - The Australian 2008 (La Bohème)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Laurence Meikle was extremely likeable as the philosopher Colline- Australian Stage 2008 (La Bohème)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Molto bene le numerose parti di fianco: lo Zuniga di Laurence Meikle ha voce di bellissimo timbro e convince come interprete - Operaclick 2017 (Carmen)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">//...sang with clear, focused assurance... a serious contender for this role - Opera Now, 2014 (Don Giovanni)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Il basso baritono australiano Laurence Meikle rende bene il carattere spavaldo ed eversivo di Don Giovanni - Teatro.it 2019 (Don Giovanni)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Laurence Meikle as Colline was outstanding – Daily Express 2013 (La Bohème)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Laurence Meikle shone in the often overlooked role of Colline – What’s On Stage 2010 (La Bohème)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">//… molto interessante la scura voce del Colline di Laurence Meikle, che raccoglie i suoi applausi personali con Vecchia zimarra - Fermata Spettacolo 2019 (La Bohème)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Meikle triumphiert als Guglielmo mit machohaftem Gehabe und virilem Bass-bariton, wenn er Dorabella erobert hat und weiterhin an die Treue seiner Fiordiligi glaubt - Online Musik Magazin 2017 (Così fan tutte)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">//… e un ottimo Laurence Meikle (il Conte Horn) da ascoltare in ruoli piú ampi - Corriere del Mezzogiorno 2019 (Un Ballo in Maschera)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Horn e Ribbïng, corifei, feudatari inquieti che mal sopportano la signoria del principe, hanno avuto rispettivamente la voce dell’ottimo Laurence Meikle e di Cristian Saitta - Oltrecultura 2019 (Un Ballo in Maschera)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">//… sung with considerable aplomb by Laurence Meikle - The Age 2008 (Bach cantata Der Himmel Lacht! BWV31)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Laurence Meikle’s muscular, articulate Colline gets us off to just the right start… Reviewsgate 2011 (La Bohème)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// The lovers were almost outshone by Laurence Meikle as Colline – Herald Sun 2008 (La Bohème)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// All are first class, but I especially liked Laurence Meikle''s Hercules - Daily Mail 2013 (Il Giasone)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Meikle is a commanding bass-baritone who should go far - Reviewsgate 2013 (Il Giasone)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// There was very strong support from Laurence Meikle as an upright Hercules - What’s On Stage 2013 (Il Giasone)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">// Laurence Meikle proved and engaging performer with a clear, powerful bass-baritone – The Age 2008 (Des Knaben Wunderhorn)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">&nbsp;</p>', 'https://static.wixstatic.com/media/eb7cbf_6d39c00d17364a96a77055707239730f~mv2.jpg', 'Portrait', 'https://static.wixstatic.com/media/eb7cbf_93e725a1b13345bfbbcc07724190d436~mv2.jpg', 'Escamillo, Carmen, Deutsches Nationaltheater Weimar', 'https://static.wixstatic.com/media/eb7cbf_3c41feef4669481f843076695ecdec6f~mv2.jpg', 'Hobson, Peter Grimes, Teatro La Fenice Venice. Photo: Fabio Barettin', 'https://static.wixstatic.com/media/eb7cbf_d6d4f0c709d14b078dc7cf9c6efd00f0~mv2.jpg', 'Die Lustige Witwe, Deutsches Nationaltheater Weimar', 'https://static.wixstatic.com/media/eb7cbf_1d383fb19c8b46828050cf88b9bb6f07~mv2.webp', 'Osmin, Die Entführung aus dem Serail, Teatro San Carlo, Naples', 'https://static.wixstatic.com/media/eb7cbf_cfed9237e33d4af3b321752884b91e46~mv2.jpg', 'Belmonte, Margherita de Anjou, Festival della Valle d''Itria. Photo: Davide Ferri', 'https://static.wixstatic.com/media/eb7cbf_7164075ffaea4ab6bdf29a452be93244~mv2.jpg', 'Portrait, Roberto Recanatesi', 'https://static.wixstatic.com/media/eb7cbf_1c2f4a1388cb4aed88a40e10e753f0fb~mv2.jpg', 'Don Giovanni, Teatro Comunale di Rovigo. Photo: David Ferri', 'https://static.wixstatic.com/media/eb7cbf_f5cb3e061f19412683d3fba17dbff050~mv2.jpg', 'Recital, Nice. Photo: D. Vauban', 'https://static.wixstatic.com/media/eb7cbf_2519350369c548f8983f238cde0f9f7f~mv2.jpg', 'Samuel, Un Ballo in Maschera, Teatro San Carlo Naples', NULL, NULL, NULL, NULL, 1, 0, 0);

