INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('33ee16b4-fce3-4a43-9773-3a3c19d1aaff', 'fba781d0-c43b-425d-b1ed-7a5840bd09c9', 'gerardo-rodrigues', 'Gerardo Rodrigues', 'Gerardo', '''+351960072111', '1967-12-23', 'United States', 'Portugal', 'Peniche', 'Rua do Brasil, 6', NULL, '2520-397', 'Pianista/Compositor Neo-Classic / Modern-Classic', 'Aproveitem as coisas simples da vida.
Não queiramos ser melhores que ninguém, sejamos as melhores versões de nós próprios.', 'https://static.wixstatic.com/media/647c58_9f963f25594e419aa88859d4e7761624~mv2.jpg', 'wix:document://v1/647c58_d4a21bdce88446bdb5d6cdb2914b8def.pdf/Gerardo_Rodrigues_Bio_pt.pdf', NULL, NULL, NULL, 'https://open.spotify.com/intl-pt/artist/08RdfH80vtbHebX1sJ9dGc?si=hKWTWuCgRpCtKLtRYZmNvg', NULL, NULL, NULL, NULL, 'https://youtu.be/EYGV0J7MXgA?si=9g9tVDm917IXC7t-', 'https://www.youtube.com/watch?v=NQ2tcqxgO9U', 'https://www.youtube.com/watch?v=6xiCcYz1pgg', 'https://www.youtube.com/watch?v=XKn9uHIRYwE', 'https://www.youtube.com/watch?v=UBePgk10HE4', NULL, NULL, NULL, NULL, NULL, '<p>O pianista português Gerardo Rodrigues lançou, em setembro de 2024, o seu terceiro álbum de originais, “Night&amp;Day”, após o “Estado de Alma” (2021) e “Improvisos” (2020). A transparência, simplicidade e autenticidade das suas composições já são a sua marca, e este segundo álbum não foge à regra, apresentando-se como a história das suas próprias emoções, exploradas numa altura em que Gerardo redefiniu o seu percurso, objetivos e prioridades.Num estilo muito particular, que oscila entre o New-Age, o Neo-Clássico ou o Moderno-Clássico, as suas composições traduzem o seu amor pelo piano, resultando numa obra repleta de emoções.</p><p> </p><p>Este novo álbum, intitula-se &quot;NIGHT&amp;DAY&quot;, e é repartido entre faixas calmas, melancólicas e meditativas, compostas nas suas insónias nocturnas, e faixas mais abertas, de experimentação sonora e de género.</p><p> </p><p>A música de Gerardo Rodrigues é uma explosão de emoções puras e simples, capaz de transportar todos os públicos para um mundo paralelo de paz e harmonia.Agora este novo registo “Night&amp;Day”, ainda chega mais próximo do público em geral, com a mistura de géneros, eletrónico, classico, pop, etc...</p>', NULL, NULL, NULL, 'https://static.wixstatic.com/media/647c58_e1efffc2de014e3797383b92fb868404~mv2.jpg', 'CD "Improvisos" - 2020', NULL, NULL, 'https://static.wixstatic.com/media/647c58_7f24bd1c37f84dee95a1b5d8298406ec~mv2.jpg', 'CD "Estado de Alma" - 2021', NULL, NULL, 'https://static.wixstatic.com/media/647c58_ed86a78a5a1740af9e076fade47edaa8~mv2.jpg', 'CD "Night&Day" - 2024', NULL, NULL, 'https://static.wixstatic.com/media/647c58_9bded7bda8844c218bbf7777915ed603~mv2.jpg', NULL, NULL, NULL, 'https://static.wixstatic.com/media/647c58_7876a875ebac422ba366d9cecc46913e~mv2.jpg', NULL, NULL, NULL, 'https://static.wixstatic.com/media/647c58_e1b9cc1c346746dc912f44b4da3f47f0~mv2.jpg', NULL, NULL, NULL, 1, 0, 0);

