-- Row 72: Cátia Moreso
INSERT IGNORE INTO users (id, email, password, role) VALUES ('6d22c1ac-a5d8-4560-918d-d5e9544749b8', 'wix-6d22c1ac@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('58612607-1851-4dc6-b880-f7aaa46ae67e', '6d22c1ac-a5d8-4560-918d-d5e9544749b8', 'catia-moreso', 'Cátia Moreso', 'Cátia', '999999999', '1983-07-07', 'Portugal', 'Lisboa, Portugal', 'Lisboa', 'xxx xxx xxx', NULL, '180', 'Mezzo-soprano', '"Sou uma mezzo-soprano dramática e aproveito da minha técnica e tessitura vocal para experimentar"', 'https://static.wixstatic.com/media/6d22c1_c41b40b0cb474a10a4602319619b0de4~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/6d22c1_4700bbca8aac4a2a8644628591a6f12f.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=UNVqPKYfrRI', 'https://www.youtube.com/watch?v=eJ3_EKAxOHQ', 'https://www.youtube.com/watch?v=L7bBxsj_Nek&embeds_referring_euri=https%3A%2F%2Fnovaproartart.wixstudio.io%2F&embeds_referring_origin=https%3A%2F%2Fnovaproartart.wixstudio.io', 'https://www.youtube.com/watch?v=SmbLYlaHM4U&embeds_referring_euri=https%3A%2F%2Fnovaproartart.wixstudio.io%2F&embeds_referring_origin=https%3A%2F%2Fnovaproartart.wixstudio.io', 'https://www.youtube.com/watch?v=JivOZx3FYc8', 'https://www.youtube.com/watch?v=9RsOPpfgoq4', 'https://www.youtube.com/watch?v=3VYOqXj-hMw', 'https://www.youtube.com/watch?v=016pGsxIlgw', NULL, NULL, '<p class="font_8">Cátia Moreso é uma <strong>mezzo-soprano</strong> portuguesa amplamente aclamada pela crítica especializada pelas suas interpretações marcantes no universo da ópera.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Detentora de uma <strong>voz poderosa</strong> e <strong>distinta</strong>, rica em nuances e cores, demonstra uma grande <strong>versatilidade vocal</strong>, sendo capaz de transitar com igual maestria entre os mais variados estilos e períodos do repertório operístico.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">A sua <strong>técnica impecável</strong> e <strong>musicalidade</strong> ímpares permitem-lhe representar com profundidade dramática e maturidade interpretativa personagens tão complexas quanto Azucena em "Il Trovatore de Verdi", Carmen na ópera homónima de Bizet, e Mrs. Quickly em "Falstaff" de Verdi, papéis que lhe renderam elogios unânimes da crítica.</p>
<p class="font_8">&nbsp;</p>', '<p class="font_8">Desde a infância que Cátia Moreso tem o canto dentro de si, mas só descobriu essa paixão aos 16 anos, quando ingressou no Conservatório de Música D. Dinis. Embora tenha iniciado os seus estudos universitários primeiro na área da engenharia biotecnológica e, depois, na de Design de Interiores, percebeu que a sua verdadeira vocação era o canto lírico.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Formou-se no <strong>Conservatório Nacional de Lisboa</strong> e depois rumou para a <strong>Guildhall School of Music and Drama</strong>, em Londres, onde obteve a licenciatura em canto e o grau de Mestre. Estudou no <strong>National Opera Studio</strong> com <strong>Susan Waters</strong>&nbsp;e foi <strong>bolseira da Fundação Calouste Gulbenkian</strong> e do <strong>Lionel Anthony Charitable Trust</strong>.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Tem um extenso repertório de ópera, que inclui papéis como Carmen, em "Carmen" de Georges Bizet, Marcellina, em "As bodas de Fígaro" de Mozart e Madame de Croissy, em "Dialogues des Carmélites" de Francis Poulenc.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Em 2023, encarnou Azucena, em "Il Trovatore", de Verdi, que considera ser, até agora, o papel mais significativo da sua carreira, rendendo-lhe rasgados elogios da crítica.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">"Cátia Moreso foi uma Azucena de primeira categoria, tanto a nível vocal como dramático (…). O seu "Stride la vampa" foi apaixonado, com notas graves impressionantes, mas sem notas de peito ingratas."</p>', '<p class="font_8">Cátia Moreso foi bolseira da Fundação Calouste Gulbenkian e do Lionel Anthony Charitable Trust, Moreso aperfeiçoou-se no National Opera Studio com Susan Waters. Conquistou prémios importantes, incluindo o 2º lugar no Concurso de Canto da Fundação Rotária Portuguesa, o Prémio Bocage no Concurso Luísa Todi e o 1º Prémio no Concurso de Canto José Augusto Alegria.</p>
<p class="font_8"><br></p>
<p class="font_8">Moreso tem vindo a construir uma carreira notável, interpretando uma vasta gama de papéis. As suas actuações memoráveis incluem Azucena em "Il Trovatore", Santuzza em "Cavalleria Rusticana", Suzuki em "Madama Butterfly", Madame Flora/Baba em "The Medium", Ulrica em "Un Ballo in Maschera" e o papel principal em "Carmen".</p>
<p class="font_8">Moreso também brilhou como Preziosilla em "La Forza del Destino", Olga em "Eugene Onegin", Jocasta em "Oedipus Rex", Eboli em "Don Carlo", La Marchesa Melibea em "Il Viaggio a Reims", Brizida Vaz e a Morte em "Trilogia das Barcas" e Mrs. Meg Page em "Falstaff".</p>
<p class="font_8"><br></p>
<p class="font_8">O seu repertório abrange ainda papéis como La Cieca em "La Gioconda", Giano em "Il Trionfo d''Amore", Dianora e Elisa em "La Spinalba", Hanna Wilson/Tracy em "The Losers", 3ª Dama em "A Flauta Mágica", 2ª Bruxa e Espírito em "Dido e Eneias", Giovanna em "Rigoletto", Baronesa em "Chérubin", Madame de Croissy em "Dialogues des Carmélites", Zanetto na ópera homónima, Carmella em "La Vida Breve" e Marcellina em "As Bodas de Fígaro".</p>
<p class="font_8"><br></p>
<p class="font_8">Em concertos, Moreso interpretou obras de Vivaldi, Pergolesi, Rossini, Bruckner, Bach, Haydn, Mozart, Duruflé e Verdi. No domínio da música contemporânea, destacam-se as suas interpretações das Canções Populares de Berio, Aventures de Ligeti e a estreia de Cicero Dixit de Bochmann.</p>
<p class="font_8"><br></p>
<p class="font_8">Esta diversidade de personagens, que abrange do barroco ao contemporâneo, demonstra a sua extraordinária versatilidade vocal e dramática e consolida a posição de Cátia Moreso como uma das principais vozes da ópera em Portugal, com reconhecimento internacional.</p>', '<h3><span style="font-weight:bold">PROJETOS<br/></span></h3><p>Masterclass de Canto 2 em 1 (com a soprano <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://smart.proart.art/artista/b%C3%A1rbara-barradas target=_blank>Bárbara Barradas</a></span></span>).</p><p>Art Allurement (com a soprano Bárbara Barradas, o pianista <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://smart.proart.art/artista/vasco-dantas target=_blank>Vasco Dantas</a></span></span> e a atriz e encenadora Sónia Aragão).</p><p> </p><h3><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h3><p><span style="font-weight:bold"><br/><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/catia_moreso target=_blank>ProART Entrevista</a></span></span></span> - Cátia Moreso - Ascensão de um talento natural rumo à consagração no canto lírico</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=msnjyyvu2mQ target=_blank>OperaFest Lisboa (2023)</a></span></span></span> - Cátia Moreso (meio-soprano) no papel de Carmen, &quot;Carmen&quot;, Bizet</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=cQ2GhdVpnCM target=_blank>OperaFest Lisboa (2022)</a></span></span></span> - Cátia Moreso no papel de Ulrica em &quot;Baile de Máscaras&quot;, Verdi</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=mRjjuFSdx64 target=_blank>OperaFest (2021)</a></span></span></span> - Cátia Moreso será Madame Flora numa das óperas mais marcantes do compositor italo-americano, Gian-Carlo Menotti</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.facebook.com/watch/?v=3957898544248553 target=_blank>AC Produções (2021)</a></span></span></span> - Entrevista com Cátia Moreso em &quot;O Fantasma da Ópera&quot;, Leroux</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.facebook.com/watch/?v=398736914398784 target=_blank>TNSC (2019)</a></span></span></span> - Cátia Moreso: mezzo-soprano é Preziosilla/Curra em La Forza del Destino, a ópera de Giuseppe Verdi</p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.facebook.com/watch/?v=10154618207907980 target=_blank>TNSC (2016)</a></span></span> </span>- Cátia Moreso: mezzo-soprano fala-nos sobre a sua personagem em Oedipus Rex</p><p> </p><h3>Quer saber mais?<br/>Entre em contacto connosco!<br/></h3><p> </p>', 'https://static.wixstatic.com/media/7b859e_3b76b20e43ed4b80b340c880516c4563~mv2.png', '©Mara D’Elean', 'https://static.wixstatic.com/media/7b859e_fa33a612d8d044108c3d8a090922fff4~mv2.jpg', '©Mara D’Elean', 'https://static.wixstatic.com/media/7b859e_d0dab80dc4494048ad919a5798bb72bd~mv2.jpg', NULL, 'https://static.wixstatic.com/media/7b859e_a1193bffa77e4e0885ffbdc86de64dbf~mv2.jpg', NULL, 'https://static.wixstatic.com/media/7b859e_1afe613707ea432eab1e90b839f2df2d~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/7b859e_31ca2af6f42e49adb250136ab8aecc88~mv2.jpg', NULL, 'https://static.wixstatic.com/media/7b859e_031a74b740eb4583b6a24b0a4a7f41e0~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 73: Lilia Donkova
