192447b5a73e43~mv2.jpg', NULL, 'https://static.wixstatic.com/media/2dff40_828a68659fd044bd8d6609f958978fab~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/2dff40_68d7cdcab91c496fa060b9b998c33c55~mv2.jpg', NULL, 'https://static.wixstatic.com/media/2dff40_7d3f115148224611bd7da7955b970028~mv2.jpg', NULL, 'https://static.wixstatic.com/media/2dff40_a74b68420fa64c6784d1c6c89ccc8fa7~mv2.png', NULL, 'https://static.wixstatic.com/media/2dff40_e4547e1ec579426096d49de32d9cc708~mv2.png', NULL, 'https://static.wixstatic.com/media/2dff40_9d3b3119f4644bc9aef1e68d2623ddb3~mv2.png', NULL, 1, 0, 0);

-- Row 75: Silvia Sequeira
INSERT IGNORE INTO users (id, email, password, role) VALUES ('0aa7fc8d-4a20-465b-ae10-10de5ca51c87', 'wix-0aa7fc8d@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('239c1736-55ce-4754-b412-506e1e009bca', '0aa7fc8d-4a20-465b-ae10-10de5ca51c87', 'silvia-sequeira', 'Silvia Sequeira', 'Silvia', '999999999', '1993-07-08', 'Portugal', 'Portugal', 'Porto', 'xxxxx', NULL, '1800', 'Soprano', '"A música expressa minhas emoções e conecta com o público. Cada performance compartilha de mim."', 'https://static.wixstatic.com/media/0aa7fc_bd200c35bff5447e88beca8c68769c55~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://youtu.be/GcMIb6nyF4M', 'https://youtu.be/Gk4nmoAygEQ', 'https://youtu.be/2jTZ3v37S80', 'https://youtu.be/yVEPvLWN-Ec', 'https://youtu.be/hAebbJBP41s', 'https://youtu.be/qfZZEpRJO64', 'https://youtu.be/qWgCV3usY1I', 'https://www.youtube.com/watch?v=O1I7rQ6rea8', 'https://www.youtube.com/watch?v=wFTWOFA2mJI', NULL, '<p class="font_8" style="text-align: justify">Sílvia Sequeira é uma jovem talentosa soprano portuguesa que tem conquistado reconhecimento internacional de forma unânime, especialmente após ter ganho o 1º Prémio do Concurso "<strong>ARIA</strong>", em 2022, na Holanda, e ter sido laureada no "<strong>Queen Elisabeth Competition</strong>", onde ganhou o prémio do público, em 2023, na Bélgica.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">Com uma <strong>voz poderosa e rica em nuances</strong>, descrita como "<strong>generosa</strong>" e "a própria música", Sílvia encanta o público com as suas interpretações emocionantes de árias e peças vocais líricas, aliadas a uma presença cénica cativante.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">O seu talento inquestionável foi novamente reconhecido em 2024 com a conquista do Prémio "<strong>Teresa Berganza</strong>" na 1ª edição do Cascais Opera – Concurso Internacional de Canto.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8" style="text-align: justify">"Chega então o momento da soprano portuguesa Silvia Sequeira. A cantora transmite uma generosidade que a consagra como a verdadeira essência da música". Marie Michiels, RTBF, 2023.</p>
<p class="font_8" style="text-align: justify">&nbsp;</p>', '<h3 style="text-align:justify">&quot;<span style="font-style:italic">Ambiciono tocar no coração das pessoas e fazer com que elas se sintam de forma diferente depois de um concerto.</span>&quot; Sílvia Sequeira.</h3><h3> </h3><p style="text-align:justify">Sílvia Sequeira nasceu no Porto e cresceu num lar onde a música era uma constante. O seu pai, um entusiasta da trompa, foi sua maior inspiração. Após estudar no <span style="font-weight:bold">Conservatório de Música do Porto e na ESMAE</span> (Escola Superior de Música e Artes do Espetáculo), Sílvia ingressou no <span style="font-weight:bold">Conservatório de Maastricht em 2020</span> onde aprimorou as suas habilidades com a renomada professora <span style="font-weight:bold">Yvonne Schiffelers</span>.</p><p> </p><p style="text-align:justify">É conhecida por um extenso repertório que vai do <span style="font-weight:bold">classicismo ao verismo italiano dos séculos XIX e XX</span>, e descrita como uma <span style="font-weight:bold">voz lírica de coloratura com agilidade e projeção impressionantes</span>. A sua abordagem versátil permite-lhe transitar com maestria entre o repertório operístico clássico e os papéis mais dramáticos e exigentes. O seu <span style="font-weight:bold">vasto alcance vocal</span> permite-lhe interpretar personagens como Donna Elvira (Don Giovanni), Suor Angelica (Suor Angelica) e Anna Kennedy (Maria Stuarda), entre outras.</p><p> </p><p style="text-align:justify">Entre outros, trabalhou com renomados artistas como Cecilia Fontes, Palmira Troufa, João Henriques, Rui Taveira, António Salgado, Luís Rendas Pereira, Connie de Jogn, Susan Waters, Maestra Mya Besselink, Chelsea Bonagura, entre outros.</p><p> </p><p style="text-align:justify">Atualmente, reside em Amesterdão (Países Baixos) e é membro do <span style="font-weight:bold">Dutch National Opera Studio</span>. Em 2023, estreou-se na Ópera Nacional Holandesa no papel de Anna Kennedy em Maria Stuarda.</p>', '<h3 style="text-align:justify"><span style="font-style:italic">&quot;Vejo possibilidades para uma carreira como soprano dramática (Wagner) no futuro, mas depois de ouvir Puccini, Cilea e Massenet, penso que nós, como amantes da ópera, beneficiaríamos pelo menos tanto deste repertório italiano e francês&quot;. </span>Peter Franken, Place de l&#x27;Opera, Paises Baixos, 2023.</h3><p> </p><h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p> </p><p style="text-align:justify">2016 - Estreia no papel de Fiordiligi em Così fan tutte de Mozart.</p><p style="text-align:justify">2019 - Estreia nos palcos internacionais como Silvia em Zanetto de Mascagni.</p><p style="text-align:justify">2021 - Estreia como Micaela em Carmen em Weikersheim, Alemanha e ganha o 2º prémio no Concurso da Fundação Rotária Portuguesa.</p><p style="text-align:justify">2022 - Vence o Concurso ARIA nos Países Baixos e, assim, uma bolsa para ingressar no Dutch National Opera Studio; conquista o Prémio do Público no concurso &quot;Ciclo Lousada&quot;;  o 2º lugar no Concurso Ebe Stignani; e o 3º lugar no Concurso Vinceró.</p><p style="text-align:justify">2023 - Ganha o Prémio Wagner no &quot;The International Vocal Competition&quot; e é laureada no &quot;Queen Elizabeth Competition&quot;, obtendo também o Prémio do Público Canvas-Klara.</p><p style="text-align:justify">2024 - Em janeiro, vence cinco prémios no &quot;61º Concurs Internacional de Cant Tenor Viñas&quot; - 3º Prêmio &quot;Maria Esperança Salvans Piera&quot;; Prémio Especial &quot;Societat del Gran Teatre del Liceu&quot; para melhor intérprete de Wagner; Prémio Extraordinário &quot;Teatro Real de Madrid&quot;; Prémio Extraordinário &quot;Associació d&#x27;Amics de l&#x27;Òpera de Sabadell&quot;; Prémio mio Extraordinário &quot;Internationale OpernWerkstatt&quot;; e Prémio do Público. Em abril conquista o Prémio &quot;Teresa Berganza&quot; na 1ª edição do Cascais Opera – Concurso Internacional de Canto.</p><p> </p><h3 style="text-align:justify"><span style="font-weight:bold">CONCERTOS MEMORÁVEIS</span></h3><p> </p><p style="text-align:justify">2022 - Theatre aan het Vrijthof - Poéme de l&#x27;amour et de la mer - Chausson, Conservatório de Maastricht, orquestra do Conservatório de Maastricht, Federico Santi</p><p style="text-align:justify">2016 - Coliseu do Porto - Wesendonklieder - R. Wagner, ESMAE, orquestra sinfónica da ESMAE, António Saiote.</p>', '<h3 style="text-align:justify"><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h3><h3> </h3><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.instagram.com/p/C8rNcQogdUo/?img_index=1 target=_blank>Entrevista Concurso Tenor Viñas (2024)</a></span></span> - Sílvia Sequeira</p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.rtp.pt/play/p2378/e762464/imperio-dos-sentidos target=_blank>RTP Play - Império dos Sentidos (2024)</a></span></span> - Adriano Jordão, Alexandra Maurício e Silvia Sequeira: Cascais Ópera - Concurso Internacional de Canto</p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/s%C3%ADlvia-sequeira-triunfa-na-1%C2%AA-edi%C3%A7%C3%A3o-do-cascais-opera target=_blank>ProART Notícia (2024)</a></span></span> - Sílvia Sequeira triunfa na 1ª edição do Cascais Opera</p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/entrevista_silvia_sequeira-1-1 target=_blank>ProART Entrevista (2023) </a></span></span>- Sílvia Sequeira - A emoção e a força de uma jovem soprano com uma voz &quot;generosa&quot;</p><h3> </h3><h3 style="text-align:justify">Quer saber mais?</h3><h3 style="text-align:justify">Entre em contacto connosco!</h3>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 76: André Gago
INSERT IGNORE INTO users (id, email, password, role) VALUES ('119d4890-587f-4cc7-ac0f-ee0e5fd72e4a', 'wix-119d4890@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('3c8e249c-b2cb-455b-ae95-fc61103df209', '119d4890-587f-4cc7-ac0f-ee0e5fd72e4a', 'andre gago', 'André Gago', 'André', '9999999999', '1970-08-21', 'Portugal', 'Portugal', 'xxxxxxx', 'xxxxxxxxxxxxxxxxxxxxxxxxxxxxxx', NULL, '000000000000', 'Ator, Encenador e Autor', NULL, 'https://static.wixstatic.com/media/119d48_c727a42fc25b4cb4a61d921e18de4123~mv2.jpg', 'wix:document://v1/119d48_01a6627812764d4c9a1bb50188fb5d74.pdf/Bio%20Andre%20Gago.pdf', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.youtube.com/watch?v=d-MQf33aC8M', 'https://www.youtube.com/watch?v=Mnjwr9yPOhs', 'https://www.youtube.com/watch?v=YCpJ-_OCJp4', 'https://www.youtube.com/watch?v=1vRhBZKmDnU', 'https://www.youtube.com/watch?v=Va7YT6NSgBM', 'https://www.youtube.com/watch?v=V5JQ2KdtmWI', 'https://www.youtube.com/watch?v=sIJV2UUy2LA', 'https://www.youtube.com/watch?v=A0ybIGXKhd8', 'https://www.youtube.com/watch?v=sIJV2UUy2LA', 'https://www.youtube.com/watch?v=1vRhBZKmDnU', '<p class="font_8">André Gago é um artista multifacetado, que se destaca como actor, encenador, professor e autor. Em 2004, fundou o Teatro Instável, onde desenvolveu e apresentou uma série de espétaculos inovadores, como "A Gargalhada de Yorick", "Hamlet, Heterónimos, Pessoas...", "Noite Antiquíssima", "Acerca de Música" e "Hamlet".</p>
<p class="font_8"><br></p>
<p class="font_8">A sua paixão pela Commedia dell''Arte e pela máscara levou-o a estagiar com o renomado Ferrucio Soleri, no Piccolo Teatro di Milano. Como actor, representou papéis icónicos como Arlequim e Pantalone na companhia Meia Preta. Além disso, tem uma vasta experiência como professor, tendo lecionado a Técnica da Máscara em inúmeros cursos e workshops, incluindo o Cendrev, Citac, Teatro Universitário do Porto, Universidade de Évora e Teatro Instável.</p>
<p class="font_8"><br></p>
<p class="font_8">André Gago também se destacou como autor, adaptando obras de Jorge de Sena e Aquilino Ribeiro para o palco. Traduziu e encenou "A Orquestra", de Jean Anouilh, e "Hamlet", de William Shakespeare. Com o seu espectáculo "O Circo da Lua", recebeu o prémio Revelação da Associação Portuguesa de Escritores, que lhe permitiu criar o espectáculo de Novo Circo "Lua!". Além disso, tem uma vasta experiência como actor em televisão e no cinema.</p>', '<p class="font_8">Nascido em Lisboa, André Gago iniciou sua carreira como ator profissional 20 anos depois, mas sua paixão pelas artes começou muito antes. Desde cedo, ele se envolveu em múltiplas aventuras relacionadas com as artes, cultivando seu gosto por música, desenho, representação, escrita e, sobretudo, pensamento multidisciplinar.</p>
<p class="font_8"><br></p>
<p class="font_8">A passagem pela Escola de Artes Decorativas António Arroio foi um momento em que se considerou uma carreira em arquitetura ou design, mas o teatro acabou por ser sua verdadeira vocação. No teatro, ele aprendeu a apreciar todos os aspectos, desde a montagem até a encenação. A relação com a palavra foi, no entanto, uma constante em sua carreira.</p>
<p class="font_8">Nos primeiros anos, adaptou obras de Aquilino Ribeiro e Jorge de Sena para o palco, e logo descobriu o poder das máscaras e da improvisação. Formou uma coleção de máscaras tradicionais que organizou em exposição e começou a dar aulas de Técnica da Máscara e Commedia dell''Arte.</p>
<p class="font_8"><br></p>
<p class="font_8">Nos anos 90, concebeu e produziu uma série de espetáculos em que foi tradutor, adaptador ou autor. Em Recitália, experimentou pela primeira vez um conceito teatral próprio que iria desenvolver nos anos seguintes. Interpreta Gardel a solo, num texto de José Jorge Letria.</p>
<p class="font_8">Em 2001, publicou o conto O Circo da Lua, que recebeu o Prémio Revelação da Associação Portuguesa de Escritores, e que serviu de base para um espetáculo de circo que dirigiu em 2003. No mesmo ano, traduziu e encenou A Orquestra, de Jean Anouilh.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2004, criou o Teatro Instável, onde continua a criar espetáculos com base em montagens de textos de vários autores e originais seus.&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2006, terminou a tradução de Hamlet, que encenou no ano seguinte. Nos últimos anos, como ator, a palavra poética passou a ocupar um lugar cada vez mais importante nas suas atuações.</p>', '<p class="font_8">André Gago iniciou sua carreira no Teatro da Comuna em 1983, onde recebeu sua formação inicial em teatro. Frequentou vários estágios com nomes como Filipe Crawford, Peter Brook e Colin Egan, o que lhe permitiu desenvolver suas habilidades como ator.</p>
<p class="font_8"><br></p>
<p class="font_8">Sua estreia como ator foi em "Marat" de Peter Weiss, dirigido por João Mota. Trabalhou com vários diretores renomados, incluindo Artur Ramos, Norberto Barroca, Ricardo Pais e Ana Tamen, em peças como "A Castro" de António Ferreira, "Clamor" baseado em textos de Padre António Vieira e Luísa Costa Gomes, e "Grande e Pequeno" de Botho Strauss.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 1987, participou em "O Físico Prodigioso" no Teatro do Triângulo. Junto de Filipe Crawford, dirigiu a companhia Meia Preta, representando Arlequim e Pantalone. Explorou também a commedia dell''arte, realizando trabalhos de investigação e dirigindo diversas ações pedagógicas nessa área. Estagiou com Ferrucio Soleri no Piccolo Teatro di Milano.</p>
<p class="font_8"><br></p>
<p class="font_8">Na década de 1990, participou em vários projetos, incluindo o filme "Non ou a Vã Glória de Mandar" de Manoel de Oliveira, a série de televisão "Pós de Bem-Querer" e o filme "Solo de Violino" da cineasta Monique Rutler. Participou também na telenovela "Cinzas" e em "Milongo" em 1994.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 1995, apareceu no filme "A Comédia de Deus" de João César Monteiro. Em televisão, entrou em "Primeiro Amor" em 1996 e "Vidas de Sal". Participou nas peças "Adiós Muchachos – a Última Noite de Carlos Gardel" em 1997, "Os Comicazes" e "Recitália". Assinou ainda a encenação de "Os Portas", de John Godber.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2001, recebeu o Prémio Revelação da Associação Portuguesa de Escritores, na área da literatura infanto-juvenil, pelo livro "O Circo da Lua". É, desde 2004, diretor da Companhia de Teatro Instável, onde em 2007 encenou e protagonizou "Hamlet" de W. Shakespeare.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2010, André Gago publicou o romance "Rio Homem", que foi finalista do prémio Leya e recebeu o Prémio PEN Clube Portugal para Primeiro Romance. Além disso, colaborou no romance coletivo "A Misteriosa Mulher da Ópera", um projeto que reuniu vários autores portugueses.</p>
<p class="font_8"><br></p>
<p class="font_8">André Gago também é um músico e poeta, e criou várias formações musicais que combinam poesia e música. Entre elas, destacam-se "Beat Hotel", "A Flor do Lácio" (editado em CD) e "Canções para Poetas", onde apresenta composições suas. Além disso, criou o projeto "No Precipício Era o Verbo", que explora a relação entre a poesia e a música.</p>
<p class="font_8"><br></p>
<p class="font_8">Com a soprano Siphiwe McKenzie e o pianista João Paulo Santos, André Gago criou o recital "Flaubert-Colet", que combina música e poesia de forma única. Além disso, dinamizou as "Primas Terças", recitais mensais de poesia que se tornaram um evento cultural importante em Portugal.</p>
<p class="font_8"><br></p>
<p class="font_8">Durante a pandemia Covid-19, André Gago foi um dos impulsionadores da plataforma online "TEIA19", que permitiu que artistas e escritores apresentassem seus trabalhos de forma virtual.</p>
<p class="font_8"><br></p>
<p class="font_8">André Gago também tem uma vasta experiência como ator em televisão e cinema. No cinema, destacam-se seus papéis em "Solo de Violino", de Monique Rutler, e "100 Eyes", de Thijs Bayens. No Centro Cultural de Belém (CCB), foi o narrador de "Lélio", de Hector Berlioz, e criou o ciclo "Jardim de Orfeu".</p>
<p class="font_8"><br></p>
<p class="font_8">Recentemente, André Gago escreveu o libretto para "Marandicui", com música de Álvaro Escalona, que foi apresentado nos Teatros Municipais de Vila Real e Bragança e editado em CD. Além disso, preparou o guião de "Songs for Shakespeare", onde atua ao lado da cantora Maria João</p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>
