INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('9d1d8976-c129-4988-8b43-4f911ccae1b1', '063535be-d5e4-4c89-b6ee-123527cdd66e', 'luis-salome', 'Luís Salomé', 'Luís', '''+351969651062', '1998-06-03', 'Portugal', 'Portugal', 'Guarda', 'Rua Álvaro Gil Cabral n5', 'Rua Álvaro Gil Cabral n5', '6300', 'Saxofonista', NULL, 'https://static.wixstatic.com/media/063535_03ccce72559f4c95b37d794046c6cc08~mv2.jpg', 'wix:document://v1/063535_881dc95ce0ca4e3d937fe71734a2b3a7.pdf/CV%201%20pag%20-%20PT.pdf', NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/063535_3f1fd9f3013540238bd4dd06041b16c3.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=UPcdT7-GOEQ', 'https://www.youtube.com/watch?v=SZnyFtrd2gY', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<h3><span style="font-weight:bold">&quot;A sua interpretação revela um artista sensível, sério e profundo&quot; (Hae-Sun Kang e Philippe Granouvel (Ensemble Intercontemporain))</span></h3><h3> </h3><p style="text-align:justify">Luís Salomé é um jovem e talentoso saxofonista que tem conquistado destaque no cenário internacional, acumulando importantes reconhecimentos. Entre eles, destacam-se o <span style="font-weight:bold">1º prémio</span> no prestigiado &quot;FISP&quot; em Palmela, em 2023, e o <span style="font-weight:bold">2º prémio </span>no &quot;Alpen Classica Festival&quot;, em Trentino, no ano de 2022.</p><p style="text-align:justify"> </p><p style="text-align:justify">Sempre em busca de novas sonoridades e caminhos inovadores, mantém um contacto colaborativo com compositores contemporâneos, contribuindo para a criação de novas obras que desafiam os limites da música tradicional. </p><p style="text-align:justify"> </p><p style="text-align:justify">Paralelamente, dedica-se à exploração da improvisação livre, expandindo as fronteiras do seu instrumento, ao mesmo tempo que interpreta o repertório erudito em concertos marcados por uma abordagem ousada e visionária.</p><p style="text-align:justify"> </p><p style="text-align:justify">Para além de projetos a solo e em duo com piano, colabora ainda com o Merus Ensemble (octeto de saxofones) e a Orquestra de Saxofones do Dão.</p><p> </p><p> </p><p> </p><p> </p>', '<p style="text-align:justify">Nascido na Guarda, Luís Salomé teve contacto com a música desde cedo. Apesar de não ter crescido numa família de músicos, esta arte encontrava-se presente com frequência de uma maneira ou de outra forma. Foi na Banda Filarmónica de Pínzio, uma aldeia próxima da Guarda, que começou a estudar música e que conheceu o saxofone (só depois de ter passado pelo trompete e o trombone). </p><p style="text-align:justify"> </p><p style="text-align:justify">Aos 10 anos começou a estudar saxofone no Conservatório S. José da <span style="font-weight:bold">Guarda</span> com o professor <span style="font-weight:bold">Carlos Canhoto</span>. A decisão de estudar música veio mais tarde, aquando da transição para o ensino secundário. Divido entre as ciências e a música, acabou por escolheu esta última e foi ainda no conservatório que começou o seu fascínio pela música contemporânea alimentado pelo do entusiasmo da professora <span style="font-weight:bold">Diana Ferreira</span>.</p><p style="text-align:justify"> </p><p style="text-align:justify">Em 2016, Luís Salomé seguiu para <span style="font-weight:bold">Braga</span> para realizar a licenciatura em saxofone na classe do professor <span style="font-weight:bold">Luis Ribeiro</span>, onde teve oportunidade de conhecer os membros do Merus Ensemble (grupo de música de câmara composto apenas por saxofone).</p><p style="text-align:justify"> </p><p style="text-align:justify">Sentindo a necessidade de aprofundar o repertório clássico e erudito do saxofone, mudou-se para <span style="font-weight:bold">Bruxelas</span>, em 2019, para realizar um Mestrado em Perfomance com o professor <span style="font-weight:bold">Vincent David </span>no Conservatoire Royal de Bruxelles. Teve ainda aulas com os assistentes <span style="font-weight:bold">Nicolas Arsenijevic, Pieter Pellens e Asagi Ito, </span>terminando esta etapa com a menção &quot;Grand Distintion&quot;. Durante os anos que esteve na Bélgica teve oportunidade realizar variados projetos de música de câmara em quarteto, trio e duo e ainda com um projeto com teatro. Fez parte da Belgian Saxophone Choir, com a qual gravou o disco &quot;Serenade&quot;. Teve ainda a ocasião de interpretar &quot;Troisième Round&quot; de Bruno Mantovani com ensemble contemporâneo.</p><p style="text-align:justify"> </p><p style="text-align:justify">Em 2022, regressou a <span style="font-weight:bold">Portugal</span>, ingressando no mestrado em ensino de música na Universidade do Minho. Paralelamente, mantém um carreira de freelance, através da qual teve a oportunidade de contactar com o compositor <span style="font-weight:bold">João Carlos Pinto</span> e o maestro <span style="font-weight:bold">Nuno Coelho</span> para a estreia do Concerto para Saxofone e orquestra.</p><p style="text-align:justify"> </p><p style="text-align:justify">Igualmente importante, foi o projeto que desenvolveu na Biblioteca Municipal da Guarda, para o qual encomendou obras a <span style="font-weight:bold">Cândido Lima, Pedro Lima e Solange Azevedo</span> sobre poemas realicionados com a sua cidade natal. A obra de Pedro Lima, encontra-se gravada no disco “TALKIN(G) (A)BOUT MY GENERATION”.</p><p> </p><p> </p><p> </p><p> </p>', '<p><span style="font-weight:bold">Prémios</span></p><p> </p><ul><li>1º prémio - Concurso Internacional Cidade do Fundão (2024)</li><li>1º prémio - IX Concurso Internacional de Saxofone “Vitor Santos” Fisp (2023)</li><li>1º prémio - IX Concurso Internacional Alto Minho (2023)</li><li>3º prémio - Concurso Nacional de Interpretação Contemporânea (2023)</li><li>2º prémio - Alpen Classica Saxfest Competition (2022)</li><li>2º prémio - Concours International Leopold Bellan (2020)</li><li>1º prémio - Concurso S. Cecília na Universidade do Minho (2019)</li><li>2º prémio (Categoria C) - Concurso Internacional de Saxofone Buffet Crampon (2017)</li><li>3º prémio (4º Categoria) - IV Concurso de Sons da Cabral na quarta categoria (2016)</li></ul><p> </p><p><span style="font-weight:bold">Destaques</span></p><p> </p><ul><li><span style="font-weight:bold">Concerto Antena 2</span>  - Recital com piano (2024)</li><li>Albúm<span style="font-weight:bold"> “TALKIN(G) (A)BOUT MY GENERATION” de Pedro Lima</span> - gravação de obra para saxofone da sua autoria (2023)</li><li>XIX Congresso Mundial de Saxofone - Concerto solo (2023)</li><li>Festival Síntese - Concerto solo, <span style="font-weight:bold">estreia nacional de obra de Inès Badalo</span> (2023)</li><li><span style="font-weight:bold">Alpen Classica Festival</span> (Trentino) - Recital com piano  (2023)</li><li>Reencontros da Música Contemporânea - <span style="font-weight:bold">Estreia do Concerto para Saxofone e Orquestra de João Carlos Pinto</span> com Orquestra das Beiras e direção de Nuno Coelho (2023)</li><li>Festival Percursos da Música - Recital com piano (2023)</li><li>Guimarães Allegro - com Merus Ensemble (2022)</li><li>5º Estágio da Orquestra de Saxofones do Dão - Formador (2022)</li><li>Festival Síntese - TMG - com Hodiernus Ensemble (2021)</li><li><span style="font-weight:bold">&quot;O saxofone inspirado na poesia Guardense&quot;</span> - concerto com obras estreadas de Cândido Lima, Solange Azevedo e Pedro Lima (2021)</li><li><span style="font-weight:bold">CD &quot;Serenade&quot;</span> - com a Belgian Saxofone Choir (2020)</li><li>“Sente-me, Ouve-me, Vê-me” <span style="font-weight:bold">BoCA</span> - projeto sobre obra de Helena Almeida - Teatro São Carlos, Casa das Artes e Museu D. Diogo de Sousa (2019)</li><li>Aveiro_Síntese - Teatro Aveirense - Concerto solo (2018)</li><li>Orquestra ESPROART sob a direção de <span style="font-weight:bold">Francesco Bellí</span> - Casa da Música (2012)</li><li>Dias da Música em Belém - CCB (2015)</li></ul>', '<h3><span style="font-weight:bold">Agenda</span></h3><h3> </h3><p>17 de outubro | 19h</p><p><span style="font-weight:bold">Antena 2</span> | Transmissão de Concerto com Catarina Trindade (piano)</p><p> </p><p>25 de outubro | 18h</p><p><span style="font-weight:bold">Fimuv </span>(Paços Brandão) | Concerto com Isolda Crespi (piano) (18h)</p><p> </p><p>26 de novembro | 21h30</p><p><span style="font-weight:bold">TMG </span>(Guarda) | Recital com Catarina Trindade (piano)</p><p> </p><p> </p><h3><span style="font-weight:bold">Discografia</span></h3><p> </p><p><span style="font-weight:bold">“TALKIN(G) (A)BOUT MY GENERATION”</span> (2023) com obras de Pedro Lima</p><p> </p><p> <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://open.spotify.com/track/1x1wymW4xo82QgWPYb40sN?si=9GoqZEotQcysWGMUA2-hBg target=undefined>(eu diria que nevava)</a></span></span> - Pedro Lima - para saxofone soprano com reverb</p><p> </p><p> </p><p><span style="font-weight:bold">&quot;Serenade&quot;</span> (2021) - Belgian Saxophone Choir</p><p> </p><p> <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=oNeqJGB9wIw target=undefined>Siegrfried Idyll</a></span></span>, WWV 103 - Richard Wagner</p><p> <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=9KM4aUHTqHM target=undefined>Serenade Op. 7</a></span></span> - Richard Strauss</p><p> <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=f4tL6Z_EXKQ target=undefined> Serenade Op. 44</a></span></span> - Antonín Dvorak</p><p> </p><p> </p><h3><span style="font-weight:bold">Projetos</span></h3><h3> </h3><ul><li><span style="font-weight:bold">Duo Saxofone e Piano com Catarina Trindade</span></li></ul><p> </p><ul><li><span style="font-weight:bold">Criação  solo</span></li></ul><p> </p><ul><li><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.instagram.com/merus.ensemble?utm_source=ig_web_button_share_sheet&igsh=ZDNlZDc0MzIxNw== target=undefined>Merus Ensemble</a></span></span></li></ul><p> </p><ul><li><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.instagram.com/orquestra_saxofones_dao?utm_source=ig_web_button_share_sheet&igsh=ZDNlZDc0MzIxNw== target=undefined>Orquestra de Saxofones do Dão</a></span></span></li></ul><p> </p><h3><span style="font-weight:bold">Quer saber mais?</span></h3><h3><span style="font-weight:bold">Entre em contacto connosco!</span></h3><p> </p><p> </p><p> </p><p> </p><p> </p><p> </p><p> </p><p> </p><p> </p><p> </p>', 'https://static.wixstatic.com/media/063535_fa5bdf1f791947f78843d146dfc208ed~mv2.jpg', NULL, 'https://static.wixstatic.com/media/063535_4e31104a3ff64108b675fc55e5615eda~mv2.jpg', NULL, 'https://static.wixstatic.com/media/063535_e9561ce53ffa4bcdbc7034ea2777dde2~mv2.jpg', NULL, 'https://static.wixstatic.com/media/063535_2e043e5b7a1a4c4fafc77df0458e84ec~mv2.jpg', 'Lançamento de “TALKIN(G) (A)BOUT MY GENERATION"
@ Hugo Sousa', 'https://static.wixstatic.com/media/063535_68275f439a214d4e9eae5e38024e4f6b~mv2.jpg', 'Lançamento de “TALKIN(G) (A)BOUT MY GENERATION"
@ Hugo Sousa', 'https://static.wixstatic.com/media/063535_cef66887ae2c4680aa0bdd79c5813cb0~mv2.jpg', 'FISP 2023', 'https://static.wixstatic.com/media/063535_d3f90ce05c3a41a1b1be565b14a730d2~mv2.jpg', 'Belgian Saxophone Chori', 'https://static.wixstatic.com/media/063535_8f14bfb84a954a03900379a37ac1ee6e~mv2.jpg', 'Percursos da Música 2023', 'https://static.wixstatic.com/media/063535_8676500dcbed4470af7e63fc2da09a3c~mv2.jpeg', '''@Artur Ferreira', 'https://static.wixstatic.com/media/063535_4e0901b605014694b4bd1d3a1a08316d~mv2.jpeg', '''@Artur Ferreira', 'https://static.wixstatic.com/media/063535_b7cef27076cd477fb5168c6d748da2c0~mv2.jpg', '"O saxofone inspirado na poesia Guardense" - Bmel', 'https://static.wixstatic.com/media/063535_b2e585834c2f4e00858017a99ff0b002~mv2.jpg', 'Festival Síntese 2023', 1, 0, 0);

-- Row 78: Sérgio Fontão
INSERT IGNORE INTO users (id, email, password, role) VALUES ('4b51d8d4-e23b-4b2a-9c16-7049d38ce578', 'wix-4b51d8d4@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('a4faccc7-5995-4d55-952c-7a22c1ce065e', '4b51d8d4-e23b-4b2a-9c16-7049d38ce578', 'sergio-fontao', 'Sérgio Fontão', 'Sérgio', '''+351966317847', NULL, 'Portugal', 'Portugal', 'Lisboa', 'Rua dos Lusíadas, 110, 1.º Dto.', NULL, '1300-374', 'Diretor coral', 'Dirigir permite-me partilhar com os outros a minha enorme paixão pela música.', 'https://static.wixstatic.com/media/7b859e_18ae7c7d583e4e8d889a68c1238e0405~mv2.jpg', 'wix:document://v1/4b51d8_22e162af131a45df82c4fdaf09cc872e.pages/S%C3%A9rgio%20Font%C3%A3o%20-%20Portugu%C3%AAs%20.pages', 'https://www.facebook.com/sergio.fontao/?locale=pt_PT', 'https://www.instagram.com/sergiofontao/', NULL, NULL, NULL, NULL, NULL, NULL, 'https://youtu.be/YO6IcIv5qjA?si=RpZYiP3MKGvcIcu4', 'https://youtu.be/2FSjQqGlGag?si=jNmm-eMQSqpywA2a', 'https://youtu.be/YO6IcIv5qjA?si=RpZYiP3MKGvcIcu4', 'https://youtu.be/2FSjQqGlGag?si=jNmm-eMQSqpywA2a', 'https://youtu.be/YO6IcIv5qjA?si=RpZYiP3MKGvcIcu4', 'https://youtu.be/2FSjQqGlGag?si=jNmm-eMQSqpywA2a', 'https://youtu.be/YO6IcIv5qjA?si=RpZYiP3MKGvcIcu4', 'https://youtu.be/2FSjQqGlGag?si=jNmm-eMQSqpywA2a', 'https://youtu.be/YO6IcIv5qjA?si=RpZYiP3MKGvcIcu4', 'https://youtu.be/2FSjQqGlGag?si=jNmm-eMQSqpywA2a', '<p class="font_8">Sérgio Fontão é um dos mais dinâmicos diretores corais em Portugal.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Mestre em Direção Coral pela Escola Superior de Música de Lisboa, dirige as Voces Caelestes, um dos mais aclamados coros portugueses, do qual foi um dos fundadores, em 1997.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Trabalha também com diversas outras formações vocais e instrumentais, como director musical ou maestro convidado.</p>', '<p>Sérgio Fontão é Mestre em Música (área de especialização: Direção Coral) pela Escola Superior de Música de Lisboa. Tendo iniciado os estudos musicais aos cinco anos de idade, sob a orientação de seu pai, frequentou posteriormente a Escola de Música Nossa Senhora do Cabo (Linda-a-Velha) e a Escola de Música do Conservatório Nacional (Lisboa), onde concluiu o Curso Complementar de Canto e o Curso Geral de Piano, depois de estudos de Harpa e Percussão. Paralelamente, concluiu a Licenciatura em Comunicação Social, na Faculdade de Ciências Sociais e Humanas da Universidade Nova de Lisboa, e o Curso de Gestão das Artes, no Centro de Formação do Centro Cultural de Belém.</p><p> </p><p>Frequentou cursos de aperfeiçoamento em Direção Coral com Luc Guilloré (Fundação Calouste Gulbenkian, Lisboa), Tõnu Kaljuste (Sibelius-Akatemia, Helsínquia), David Lawrence e Julian Wilkins (Canford Summer School of Music), Simon Halsey e André Thomas (Eric Ericson Masterclass, Philharmonie, Haarlem), Frieder Bernius (Civico Liceo Musicale, Varese), Peter Broadbent, Colin Durrant e Jo McNally (Association of British Choral Directors, Londres) e Georg Grün (Masterclass Internationale de Direction Chorale, Vaison-la-Romaine); em Direcção de Orquestra com Robert Houlihan; em Canto com Jill Feldman, Marius van Altena, Max von Egmond, Peter Harvey e Tom Krause; e em Música Antiga com Richard Gwilt, Ketil Haugsand, Peter Holtslag, Jonathan Manson, Owen Rees e Rainer Zipperling.</p>', '<p>Como membro ou diretor de diversas formações vocais e instrumentais, Sérgio Fontão tem realizado concertos em Portugal, Espanha, França, Bélgica, Holanda, Reino Unido, Áustria, Itália, Malta, Brasil, Argentina, Uruguai, México, EUA, Canadá, Turquia, Índia, Japão e China. Tem participado, também, em espectáculos de ópera e teatro e efetuado gravações para cinema, rádio, televisão e em disco, para as etiquetas Aria Music, Deutsche Grammophon, Dinemec Classics, EMI Classics, Fnac Music, Milan, Movieplay Classics, Naxos, Numérica, Pentatone Classics, Philips, PortugalSom, Sole Mio, Toccata Classics, Virgin Classics e Virgin Veritas, entre outras.</p><p> </p><p>Actualmente, dirige os coros Voces Caelestes, Polyphonia Schola Cantorum, Coral de Linda-a-Velha, Coro Animato, Coro da Casa da Imprensa, Coro do Grupo Desportivo e Cultural do Banco de Portugal, Coro dos Serviços Sociais da Câmara Municipal de Lisboa e Coral Vértice (grupo vocal masculino fundado em Outubro de 1974 por membros do Coro Gulbenkian).</p><p> </p><p>Dirige ocasionalmente orquestras como a Camerata Alma Mater, Capela Real, Orquestra de Câmara da Guarda Nacional Republicana, Orquestra do Círculo de Música de Câmara, Concentus Musicus de Lisboa, Real Câmara e Orquestra Metropolitana de Lisboa.</p><p> </p><p>Integrou o corpo docente dos Cursos de Direcção Coral e Técnica Vocal promovidos pela Fundação INATEL. No ano lectivo 2009/2010, foi membro do corpo docente da cadeira de Introdução à Técnica de Direcção, no Instituto Piaget (Almada). Entre 2013 e 2023, lecionou Direção e Coro no âmbito da licenciatura em Música na Comunidade (uma parceria entre as Escolas Superiores de Educação e Música de Lisboa). Em 2023, integrou o corpo docente da Lisbon Choral Conducting Masterclass, uma iniciativa do Nova Era Vocal Ensemble.</p><p> </p><p>Dirigiu o Ensemble Femina (grupo vocal e instrumental feminino), o Coral Encontro, o Coro dos Jerónimos, o Coro Cantapiano, o Coral In Vita Musica, o Coral Allegro, o Coro do Mais Sindicato e o Coro da Associação Cultural e Desportiva do Instituto da Habitação e da Reabilitação Urbana. Colaborou, esporadicamente, como assistente de direcção com o grupo Concertus Antiquus e com o Coro Dom Luís I (constituído sob a égide da exposição comemorativa de Dom Luís I, no Palácio Nacional da Ajuda).</p><p> </p><p>Preparou o coro infantil que participou na peça de teatro<span style="font-style:italic"> Inverno de 45</span>, de Michel Deutsch, levada à cena no Teatro da Trindade, e dirigiu os coros infantis e juvenis da ópera <span style="font-style:italic">A Arca de Noé</span>, de Benjamin Britten, produzida pela Academia de Amadores de Música. </p><p> </p><p>Em Outubro de 2005, foi finalista do Concurso Internacional para Diretores de Coro Mariele Ventre, disputado em Bolonha. Em Setembro de 2006, em Londres, dirigiu o coro de câmara inglês Helios Voices na estreia mundial da <span style="font-style:italic">Missa Sine Nomine</span>, de Eurico Carrapatoso.</p><p> </p><p>Foi responsável pela produção musical do CD <span style="font-style:italic">Fernando Lopes-Graça – Música Coral</span>, gravado pelo Coro Gulbenkian (Numérica, 2008). Dirigiu o Coro Gulbenkian na gravação do CD <span style="font-style:italic">O Retiro</span>, de Rodrigo Leão, lançado em Outubro de 2015.</p><p> </p><p>Colaborou na preparação do Coro Participativo (cerca de 250 cantores) que cantou a obra <span style="font-style:italic">Messiah</span>, de George Frideric Handel, com o Coro e a Orquestra Gulbenkian, em Novembro de 2016. Foi o responsável pela preparação dos cerca de 250 coralistas que participaram na ópera comunitária <span style="font-style:italic">The Monster in the Maze</span>, do compositor Jonathan Dove, apresentada na Fundação Calouste Gulbenkian em Setembro de 2017. Em 2024, colaborou na preparação do Coro Participativo que cantou o <span style="font-style:italic">Requiem</span> de Mozart com o Coro e a Orquestra Gulbenkian.</p><p> </p><p>Enquanto diretor musical, colaborou no projecto “Grupos de Canto para Seniores”, um estudo que teve como objetivo avaliar o impacto que a prática musical tem sobre a saúde e o bem-estar da população sénior. Este projeto teve como parceiros a Direcção-Geral das Artes, a Universidade Autónoma de Lisboa, o ISCTE – Instituto Universitário de Lisboa, o OPART – Organismo de Produção Artística (entidade pública empresarial responsável pela gestão da Companhia Nacional de Bailado e do Teatro Nacional de São Carlos) e as Santas Casas da Misericórdia de Almada e Lisboa.</p><p><br/>Tem dirigido um vasto repertório, que se estende da música medieval à criação musical contemporânea. Tem, também, preparado (ou colaborado na preparação de) coros para obras dirigidas por maestros como Leonardo García Alarcón (<span style="font-style:italic">Requiem</span> de Mozart, Cantata BWV 198 de Bach, <span style="font-style:italic">Mattutino de’ Morti</span>, de David Perez, e <span style="font-style:italic">A Criação</span> de Haydn), Alain Altinoglu (<span style="font-style:italic">Ciel à vif</span>, de Michel Petrossian), Pedro Amaral (<span style="font-style:italic">Os Jogadores de Xadrez</span>, de Pedro Amaral, <span style="font-style:italic">Vat 69</span>, de Alain Bioteau, e <span style="font-style:italic">Sinfonia n.º 9</span>, de Beethoven), Giovanni Andreoli (<span style="font-style:italic">Lux Æterna</span>, de Ligeti, e <span style="font-style:italic">De Profundis</span>, de Schoenberg), Stephen Barlow (<span style="font-style:italic">Sonho de uma Noite de Verão</span>, de Mendelssohn), Martyn Brabbins (<span style="font-style:italic">As Bodas de Fígaro</span>, de Mozart), Joana Carneiro (<span style="font-style:italic">Requiem</span>, de António Pinho Vargas, <span style="font-style:italic">Sinfonia dos Salmos</span>, de Stravinsky, <span style="font-style:italic">Seven Last Words from the Cross</span>, de James MacMillan, e <span style="font-style:italic">Salmo CL</span>, de Eurico Carrapatoso), Pedro Carneiro (<span style="font-style:italic">Magnificat</span>, de Bach, <span style="font-style:italic">Sinfonia n.º 9</span>, de Beethoven, A Criação, de Haydn, e <span style="font-style:italic">Sonho de uma Noite de Verão</span>, de Mendelssohn), Michel Corboz (<span style="font-style:italic">Paixão segundo S. João</span> e <span style="font-style:italic">Oratória de Natal</span>, de Bach, e <span style="font-style:italic">Requiem</span> de Mozart), Harry Christophers (<span style="font-style:italic">Platée</span>, de Rameau), Laurence Cummings (<span style="font-style:italic">Dixit Dominus</span>, de A. Scarlatti, e <span style="font-style:italic">Magnificat</span> e <span style="font-style:italic">Tantum ergo</span>, de P. A. Avondano), Christian Curnyn (<span style="font-style:italic">Platée</span>, de Rameau), Gustavo Dudamel (<span style="font-style:italic">Chôros n.º 10, Rasga o Coração</span>, de Villa-Lobos), Peter Eötvös (<span style="font-style:italic">Momente</span>, de Stockhausen), Lawrence Foster (<span style="font-style:italic">Così fan tutte</span>, de Mozart), Alexander Frey (<span style="font-style:italic">Peter Pan</span>, de Bernstein), Thomas Hengelbrock (<span style="font-style:italic">Um Requiem Alemão</span>, de Brahms), Miguel Jalôto (Cantata BWV 147 de Bach), Nicholas Kraemer (<span style="font-style:italic">Oratória de Páscoa</span> e Cantata BWV 31 de Bach), Marcos Magalhães (<span style="font-style:italic">Dido e Eneias</span>, de Purcell, <span style="font-style:italic">Le Carnaval et la Folie</span>, de Destouches, e <span style="font-style:italic">Paride ed Elena</span>, de Gluck), Massimo Mazzeo (<span style="font-style:italic">Credo</span> e <span style="font-style:italic">Magnificat</span>, de Vivaldi, e <span style="font-style:italic">Der Herr ist mit mir</span>, de Buxtehude), Paul McCreesh (<span style="font-style:italic">War Requiem</span> de Britten, <span style="font-style:italic">Requiem</span> de Verdi e <span style="font-style:italic">Missa Solemnis</span> de Beethoven), John Nelson (<span style="font-style:italic">Cenas do Fausto de Goethe</span>, de Schumann, e <span style="font-style:italic">La Damnation de Faust</span>, de Berlioz), Pedro Neves (<span style="font-style:italic">Crioulo</span>, de Vasco Martins, e <span style="font-style:italic">Missa em Sol Maior</span>, de Schubert), Enrico Onofri (<span style="font-style:italic">Magnificats</span> de JS e CPE Bach), Elio Orciuolo (<span style="font-style:italic">La Fille du Régiment</span>, de Donizetti), Zoltán Peskó (<span style="font-style:italic">Requiem</span> de Ligeti e <span style="font-style:italic">Gurrelieder</span> de Schönberg), Mikhail Pletnev (<span style="font-style:italic">Cantatas 1 e 2</span> de Taneyev), Jean-Bernard Pommier (<span style="font-style:italic">A Flauta Mágica</span>, de Mozart), Josep Pons (<span style="font-style:italic">Missa Solene</span>, de Beethoven), Peter Rundel (<span style="font-style:italic">Vislumbre</span>, de Emmanuel Nunes, e <span style="font-style:italic">Circundante Circunstância dos Círculos</span>, de Miguel Azguime), Esa-Pekka Salonen (<span style="font-style:italic">Cantata Profana</span>, de Bartók), Peter Schreier (<span style="font-style:italic">Oratória de Natal</span>, de Bach), Lorenzo Viotti (<span style="font-style:italic">Evgeni Onegin</span>, de Tchaikovsky), Garry Walker (<span style="font-style:italic">Sinfonia n.º 9</span>, de Beethoven), Robert Ziegler (<span style="font-style:italic">Requiem</span> de Ligeti) e Michael Zilm (<span style="font-style:italic">Peer Gynt</span>, de Grieg), entre outros.</p><p> </p><p> </p><p>Como cantor, tem colaborado, entre outros agrupamentos, com o Coro Gulbenkian, Coro de Câmara de Lisboa, Coral Vértice, Voces Caelestes, Vozes Alfonsinas, Ensemble Barroco do Chiado, Ensemble Orphée et Cœtera, Smoking Voices, Concertus Antiquus, Coro Dom Luís I, Cantus Firmus, Syntagma Musicum, Camerata Vocal de Lisboa, Os Músicos do Tejo e Coro do Teatro Nacional de São Carlos.</p><p> </p><p>Paralelamente ao seu trabalho como intérprete, tem desenvolvido atividade nas áreas do jornalismo, da comunicação institucional, da edição de música impressa e da gestão de projectos e instituições culturais. Entre outras atividades, foi colaborador do jornal <span style="font-style:italic">A Capital</span>, na área da música clássica; foi Assistente do Editor na Musicoteca – Edições de Música; desempenhou as funções de Coordenador Artístico-Organizativo da Orquestra Sinfónica Portuguesa e do Coro do Teatro Nacional de São Carlos; ocupou o cargo de Vice-Presidente do Conselho de Administração da Federação Internacional das Juventudes Musicais; foi membro do Comité do World Youth Choir (uma organização conjunta da Associação Coral Europeia, da Federação Internacional para a Música Coral e da Federação Internacional das Juventudes Musicais); e ocupou o cargo de Secretário-Geral da Juventude Musical Portuguesa. Em 2007, foi membro da comissão de apreciação das candidaturas aos apoios financeiros a projetos pontuais atribuídos pela Direcção-Geral das Artes/Ministério da Cultura. Em 2008 e 2010, integrou o júri do Concurso Nacional de Música promovido pela Fundação INATEL. Foi director artístico do ciclo <span style="font-style:italic">Concertos à Conversa | Viagens no Tempo | Música Coral</span>, que decorreu no Centro Cultural de Belém, em Janeiro e Fevereiro de 2011. Em 2018, foi membro do júri do Beira Interior International Choir Competition and Festival. É, desde Novembro de 2017, Vice-Presidente da Coros Portugal – Associação Portuguesa de Música Coral.</p>', '<p>https://www.rtp.pt/play/palco/p12069/da-penitencia-a-redencao-voces-caelestes</p>', 'https://static.wixstatic.com/media/4b51d8_3b8ec677c1914f4fad2605b56ef434fc~mv2.jpg', NULL, 'https://static.wixstatic.com/media/4b51d8_98103707978d45599e101fc360d1341f~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_8b22b25f8d504640a7502d141f6e9aae~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_913c3beb0578470485bb24322ba5e156~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_2f249351eea3427e9a2c56abd962038d~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_fb661c60fe5643cfa7b16d21fd762629~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_925b4a10ecfa4f5ca0cc21113b85666b~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_ff6c955192c44f39bf6b6352c5e17533~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_6bf17571a3a5460b850b17792d851505~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_1e54dc533ba345e987c7dcebeb85d8ca~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_459a16a1b4d54b90b2a0156c5dda2d29~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/4b51d8_136c697afdda4d898c0ec7ce6ab66ddb~mv2.jpeg', NULL, 1, 0, 1);

-- Row 79: Débora Halász
INSERT IGNORE INTO users (id, email, password, role) VALUES ('56951548-4825-4497-9e76-a03530fc7e58', 'wix-56951548@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('93e8cade-0939-463d-8e8c-4467dc461840', '56951548-4825-4497-9e76-a03530fc7e58', 'debora-halasz', 'Débora Halász', 'Débora', '999999999', '1975-07-11', 'Brasil', 'Alemanha', 'Berlim', 'xxxxx', NULL, '1800', 'Pianista', 'A música é a linguagem universal que nos permite expressar as emoções mais profundas da alma humana', 'https://static.wixstatic.com/media/569515_1e0f0552de76444294815bf99b212627~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/569515_c396c46ebee64b229aaadad341bf8dc4.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=iFIy_xQ_I34', 'https://www.youtube.com/watch?v=ckpSJcsL9As', 'https://www.youtube.com/watch?v=gJAeI9VlmtY', 'https://www.youtube.com/watch?v=n5jjxkqA9hs', 'https://www.youtube.com/watch?v=VuyJfz5cpss', 'https://www.youtube.com/watch?v=wdzhf3DyitU', 'https://www.youtube.com/watch?v=gJAeI9VlmtY', NULL, NULL, NULL, '<p class="font_8" style="text-align: justify">Débora Halász é uma <strong>pianista, cravista e compositora brasileira</strong> de renome internacional, elogiada pela crítica pela sua técnica prodigiosa e interpretações repletas de musicalidade e emoção.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">De entre os seus projetos, destaca-se a gravação das obras para piano de <strong>Villa-Lobos</strong>, totalizando quatro álbuns. A convite da Naxos e em parceria com a Bavarian Radio, Halász também registou as composições para cravo de Carlos Seixas, resultando em dois álbuns.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">Em 1993, criou o <strong>Duo Halász</strong>&nbsp;com o seu marido, o violonista Franz Halász, explorando a combinação de piano e guitarra. O seu mais recente projeto é o quinteto ESCUALO5.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">Vencedora do <strong>Grammy Latino em 2015</strong>, é reconhecida por trazer à tona a riqueza da música clássica brasileira através de aclamadas performances e gravações.</p>
<p class="font_8"><br></p>
<p class="font_8" style="text-align: justify">“<em>Não consigo imaginar uma defensora mais poderosa desta música do que Débora Halász. O seu pianismo vívido dá vida a cada nota!</em>”</p>
<p class="font_8" style="text-align: justify">AMERICAN RECORD GUIDE</p>', '<p style="text-align:justify">Nascida em São Paulo, no seio de uma família de imigrantes húngaros, Débora Halász começou sua jornada musical aos seis anos, inspirada pela sua avó pianista. Com apenas 15 anos, apresentou-se com a <span style="font-weight:bold">Orquestra Sinfónica do Estado de São Paulo</span> e foi considrada pela pianista <span style="font-weight:bold">Ingrid Haebler</span> como um dos talentos mais promissores no campo pianístico.  Em 1988, ganhou o <span style="font-weight:bold">Prémio da Crítica (APCA)</span> pela sua aclamada interpretação do 3.º Concerto para Piano de Rachmaninov.</p><p style="text-align:justify"> </p><p style="text-align:justify">Após uma sólida formação no Brasil com mestres como <span style="font-weight:bold">Magdalena Tagliaferro</span> e <span style="font-weight:bold">Beatriz Balzi</span>, Halász mudou-se para a Alemanha, onde completou os seus estudos na prestigiada <span style="font-weight:bold">Musikhochschule de Colónia com com Pavel Gililov</span>. Foi lá que conheceu seu marido, o guitarrista <span style="font-weight:bold">Franz Halász</span>, com quem formou o aclamado <span style="font-weight:bold">Duo Halász</span> em 1993. Atualmente, também faz parte do quinteto &quot;<span style="font-weight:bold">ESCUALO5</span>&quot;.</p><p style="text-align:justify"> </p><p style="text-align:justify">É  convidada em muitos festivais europeus e sul-americanos como Bath-Inglaterra, Brandenburgischer Sommer-Alemanha, Mikkeli-Finlândia, Menton-França, Campos do Jordão-Brasil, etc. e parceira de músicos como Patrick Gallois, Ingolf Turban , Rudens Turku, Lavard Skou Larsen, Sebastian Hess , Sophia Reuter e Wen Sinn Yang.</p><p style="text-align:justify"> </p><p style="text-align:justify">Radicada na Alemanha desde 1989, atualmente, integra o corpo de docentes da Universidade de Música e Teatro de Munique na Alemanha.</p><p style="text-align:justify"> </p><h3 style="text-align:justify">&quot;Débora Halász revela-se notável pela facilidade e musicalidade, compreendendo maravilhosamente esta música ora refinada, lírica, sensual, ora telúrica, arrebatadora.&quot;</h3><p style="text-align:justify">Diapason</p>', '<p style="text-align:justify">Com uma <span style="font-weight:bold">técnica impecável e um profundo entendimento dos diversos períodos da música clássica</span>, Halász é conhecida pelas suas interpretações vibrantes, repletas de nuances e sensibilidade. A sua abordagem única valoriza a expressividade e a conexão emocional com o repertório, revelando camadas de complexidade por trás de cada composição.</p><p style="text-align:justify"><span style="font-weight:bold">PRÉMIOS</span></p><ul><li style="text-align:justify">Grammy Latino de Melhor Álbum de Música Clássica pelo álbum &quot;<span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.discogs.com/release/9874773-Radam%C3%A9s-Gnattali-Franz-Hal%C3%A1sz-D%C3%A9bora-Hal%C3%A1sz-Alma-Brasileira target=_blank>Alma Brasileira</a></span></span>&quot; dedicado à obra de Radamés Gnattali (2015).</li><li style="text-align:justify">Prémio da Associação Paulista de Críticos de Arte (APCA) por melhor solista do ano (1988).</li></ul><p style="text-align:justify">Apresentou-se como solista em vários festivais e séries de concertos em diferentes países da Europa, América Latina e Estados Unidos, como no Festival de Música de Bath (Inglaterra), Festival Santo Tirso (Portugal), Festival de Menton (França), Brandenburgischer Sommer (Alemanha), Festival de Mikkeli (Finlândia) e Séries Dellarte (Rio de Janeiro).</p><p style="text-align:justify"> </p><h2 style="text-align:justify"><span style="font-weight:bold">LINHA DO TEMPO</span></h2><p style="text-align:justify"> </p><p style="text-align:justify">2020-2023 - Grava uma série de álbuns com obras de Beethoven, Astor Piazzolla, Debussy e Bach.</p><p style="text-align:justify">2019 - Cria o quinteto instrumental ESCUALO5 que se destaca com as interpretações de Astor Piazzolla.</p><p style="text-align:justify">2015 - Venceu o Grammy Latino de Melhor Álbum de Música Clássica.</p><p style="text-align:justify">2014 - Gubaidulina Project com gravação e performance na presença da compositora da sua Sonata para piano.</p><p style="text-align:justify">2010 - Começou sua atividade docente na Faculdade de Música de Munique.</p><p style="text-align:justify">2007 - Começou a lecionar na Faculdade de Música de Nuremberg.</p><p style="text-align:justify">2006-2012 - Várias gravações para o selo NAXOS e co-produções com a Bayerische Rundfunk de Munique.</p><p style="text-align:justify">1995-1999 - Gravou uma série de quatro álbuns com obras de Villa-Lobos.</p><p style="text-align:justify">1994 - Primeira gravação para o selo BIS Records na Suécia.</p><p style="text-align:justify">1989 - Iniciou os estudos na Musikhochschule de Colonia, na Alemanha.</p><p style="text-align:justify">1987 - Graduou-se na Universidade de São Paulo.</p><p style="text-align:justify">1980 - Estreou-se com a Orquestra Sinfonica de São Paulo.</p><p style="text-align:justify"> </p><h2 style="text-align:justify"><span style="font-weight:bold">PROJETOS</span></h2><p style="text-align:justify"> </p><p style="text-align:justify"><span style="font-weight:bold">“<span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://escualo5.jimdosite.com/about-us/ target=_blank>ESCUALO5</a></span></span>”</span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://music.apple.com/ca/album/piazzolla-vayamos-al-diablo-escualo5-ep/1527037833 target=_blank>Piazzolla - Vayamos Al Diablo</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://bisrecords.lnk.to/2605 target=_blank>Piazzolla Escualo5</a></span></span></p><p style="text-align:justify">O quinteto ESCUALO5, composto por cinco solistas de cinco países diferentes, reúne um mundo de ideias sob uma paixão comum: a música de Astor Piazzolla. Estes músicos de renome internacional criaram este quinteto em Munique, e entre seus membros estão dois vencedores do Grammy Award: Franz Halász na guitarra e Débora Halász ao piano. O grupo também conta com o talento de Iason Keramidis no violino, Alexander Kuralionok no acordeão e Philipp Stubenrauch no contrabaixo.</p><p style="text-align:justify">Seguindo a tradição do Quinteto Tango Nuevo de Piazzolla, o ESCUALO5 utiliza a sua vasta experiência e formação clássica para explorar esse repertório com absoluta perfeição, criando uma experiência autêntica e original. As suas interpretações ao vivo das obras de Piazzolla levam o público ao êxtase total, uma verdadeira ilusão, impulsionada pela precisão rítmica e temperamento expressivo de seus cinco membros.</p><p style="text-align:justify">Verdadeiros virtuosos nos seus instrumentos, combinam o talento para improvisar, arranjar e compor, o que torna cada performance uma experiência acústica única.</p><p style="text-align:justify">Antes de lançar o álbum &quot;Piazzolla Escualo5&quot; em 2021 pela editora BIS, o grupo já havia marcado sua presença com o EP &quot;Piazzolla - Vayamos Al Diablo&quot; em 2020.</p><p style="text-align:justify"><span style="font-weight:bold">Opiniões</span></p><p style="text-align:justify">&quot;Desde a primeira faixa, fica claro que este quinteto cosmopolita tem a chave para a interpretação “Piazzolliana”: sobriedade, um toque de melodia (o acordeonista Alexander Kuralionok tem o cuidado de não inflar as velas com um lirismo que poderia tornar-se xaroposo) e selvageria, para uma dupla presença no momento, através do timbre (uma verdadeira selva) e do ritmo (sincopação, de todos os ângulos). Uma versão delicada da famosa canção Soledad, uma interpretação indispensável do demasiado raro Fracanapa, anima este programa, que culmina com Adios Nonino, cuja longa introdução ao piano dá o tom errante.  Débora Halász é extraordinária. A sua volta ao mundo improvisada não pode deixar de estimular os seus parceiros.&quot; - Pierre Gervasoni. Le Monde, 2022</p><p style="text-align:justify">&quot;O álbum BIS do quinteto Escualo5 é absolutamente fantástico! Não só as interpretações são infalivelmente elegantes e ardentes, como também são maravilhosamente detalhadas em termos de tom, textura e cor harmónica.” - Gramophone Review</p><p style="text-align:justify">&quot;A interpretação dos cinco «Escualos» demonstrou de forma impressionante o quão emocionante, mas também o quão substancial em termos de composição podem ser estas peças do criador do Tango nuevo. Todos eles, virtuosos no seu instrumento, perfeitos no seu entrosamento, mostraram-se nas suas interpretações de temperamento empolgante.&quot; - Thomas Beaujean, Aachener Nachrichten, 2017</p><p style="text-align:justify"> </p><h3 style="text-align:justify"><span style="font-weight:bold">“<span style="text-decoration:underline"><span style="text-decoration:underline"><a href=http://www.duohalasz.com/ target=_blank>Duo Halász</a></span></span>”</span></h3><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://bisrecords.lnk.to/2086 target=_blank>Alma Brasileira - Chamber Works by Radamés Gnattali</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.amazon.com/Fandango-Debora-Halasz-Franz/dp/B00PZ7AAH6/ref=sr target=_blank>Fandango</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://music.apple.com/us/album/carulli-guitar-and-piano-music-vol-1/307953945 target=_blank>Carulli: Guitar and Piano Music, Vol. 1</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://music.apple.com/nz/album/carulli-guitar-and-piano-music-vol-2/325667401 target=_blank>Carulli: Guitar and Piano Music, Vol. 2</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://bisrecords.lnk.to/717 target=_blank>Shostakovich / Castelnuovo-Tedesco / Santorsola: Music for Guitar and Piano</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://bisrecords.lnk.to/671 target=_blank>Ginastera / Brouwer / Ponce: Piano and Guitar Music</a></span></span></p><p style="text-align:justify">O Duo Halász, formado em 1993 pela pianista brasileira Débora Halász e seu marido, o guitarrista alemão Franz Halász, é celebrado internacionalmente por sua excelência e virtuosismo. Este aclamado duo conquistou o Grammy Latino de 2015 para Melhor Álbum de Música Clássica como álbum &quot;Alma Brasileira&quot; e é frequentemente descrito pela crítica como &quot;magnífico&quot;, &quot;uma dupla emocionante&quot; e &quot;uma experiência fascinante e diversificada&quot;.</p><p style="text-align:justify">&quot;Tocam de forma maravilhosa juntos, irradiando alegria e bom humor.&quot;</p><p style="text-align:justify">American Record Guide</p><p style="text-align:justify">Ao longo dos anos, o Duo Halász lançou seis álbuns, incluindo gravações originais e novos arranjos, explorando um repertório que vai do barroco aos compositores contemporâneos. Eles têm colaborações notáveis com a editora BIS, incluindo obras de Shostakovich, Ginastera, Castelnuovo-Tedesco, Hans Haug, Manuel Ponce e Leo Brouwer. O álbum &quot;Alma Brasileira&quot; foi particularmente laureado, recebendo o título de Melhor Álbum de Música Clássica pela Recording Academy. Além disso, o duo gravou duas obras originais de Ferdinando Carulli para a Naxos, em coprodução com a Bayerische Rundfunk-BR, e um CD com música espanhola para cravo e guitarra, intitulado &quot;Fandango&quot;.</p><p style="text-align:justify"><span style="font-weight:bold">Opiniões</span></p><p style="text-align:justify">&quot;Débora Halász, nascida no Brasil, traz uma expressividade potente e uma autoridade óbvia à música para piano, que, como o guitarrista Fabio Zanon salienta na sua nota de apresentação, tem a influência de Chopin e Bartók - embora haja também ecos de mestres espanhóis como Granados e Albéniz na mistura sem esforço de Gnattali de formas de dança popular e música clássica de salão. Franz Halász está, no entanto, igualmente à vontade com a música para guitarra solo; e se ele e o seu parceiro conseguem realçar com sucesso a riqueza lírica e o ouvido para a cor na soberba sonatina para guitarra e piano de Gnattali, a sua sensibilidade extraordinária para as exigências simultâneas da dança e da canção servem apenas para sublinhar as qualidades superiores de peças para guitarra como a titular Alma brasileira e Saudade.” - Gramophone Review</p><p style="text-align:justify">“Estes dois jovens artistas são fantásticos! Uma gravação inteligente e raramente ouvida”.    - Diapason</p><p style="text-align:justify">&quot;Fandango é um lançamento do mais alto calibre e foi gravado com grande entusiasmo. A música também beneficia da elevada qualidade de som da gravação. Franz e Débora Halász parecem estar completamente absorvidos pela música e oferecem interpretações fascinantes. Um sucesso total!&quot;  - MUSIC AN SICH</p><p style="text-align:justify">“Dois músicos excepcionais apresentam-se aqui, tanto no piano como na guitarra. Longe de qualquer problema técnico, aqui fazem realmente música.&quot; fazem realmente música.” - EGTA - Suíça</p><p style="text-align:justify"> </p><h3 style="text-align:justify"><span style="font-weight:bold">“Obra de Carlos Seixas”</span></h3><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.naxos.com/CatalogueDetail/?id=8.557459 target=_blank>SEIXAS, C. de: Harpsichord Works (Complete), Vol. 1 (D. Halasz)</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.naxos.com/CatalogueDetail/?id=8.570216 target=_blank>SEIXAS, C. de: Harpsichord Works (Complete), Vol. 2 (D. Halasz)</a></span></span></p><p style="text-align:justify">Nos dois álbuns gravados com a NAXOS entre 2006 e 2011, Débora Halász lançou-se no ambicioso projeto de gravar a obra para cravo do compositor barroco português Carlos Seixas (1704-1742). A sua motivação foi trazer a merecida atenção a este criador injustamente negligenciado, cujas cerca de 80 sonatas remanescentes revelam um talento à altura dos seus mais ilustres contemporâneos.</p><p style="text-align:justify">Esta foi a sua estreia no cravo, amplamente elogiada pela crítica, e que trás à tona a riqueza das sonatas de Seixas - obras &quot;lindas e super interessantes&quot;, nas palavras da própria intérprete. Uma verdadeira imersão no barroco ibérico, resgatando um compositor que merece ser celebrado pela sua maestria técnica e originalidade criativa.</p><p style="text-align:justify"><span style="font-weight:bold">Opiniões</span>:</p><p style="text-align:justify">&quot;Aqui temos o primeiro CD de uma série que vai fazer história. Um compositor de génio, uma cravista inspirada e um instrumento com um som fabuloso. A interpretação de Débora Halász é um enorme lucro. A sua técnica, inspiração e inteligência no fraseado e registo são notórias.&quot; - AST - Portugal</p><p style="text-align:justify">&quot;Há aqui uma escrita tecnicamente exigente - mas Seixas era aparentemente também um virtuoso considerável... Débora Halász parece não se envergonhar destas dificuldades e não tem medo de estabelecer alguns tempos muito rápidos. Seixas é - para o seu período - invulgarmente apreciador de tonalidades menores e o seu uso dá uma qualidade distintiva a alguns dos seus movimentos mais lentos, em particular. Em suma, há muito para admirar e apreciar aqui.&quot; - Musicweb Internacional</p><p style="text-align:justify"> </p><h3 style="text-align:justify"><span style="font-weight:bold">“Obra de Villa-Lobos para piano”</span></h3><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://bisrecords.lnk.to/712 target=_blank>Villa-Lobos: Complete Piano Music, Vol. 1</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://bisrecords.lnk.to/812 target=_blank>Villa-Lobos: Complete Piano Music, Vol. 2</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://bisrecords.lnk.to/912 target=_top>Villa-Lobos: Complete Piano Music, Vol. 3</a></span></span></p><p style="text-align:justify"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://bisrecords.lnk.to/1012 target=_blank>Villa-Lobos: Complete Piano Music, Vol. 4</a></span></span></p><p style="text-align:justify">Nos quatro álbuns gravados com a BIS, entre 1995 e 1999, Débora Halász confere uma vitalidade especial à música de Villa-Lobos. Em cada um deles, a versátil pianista capta a essência vital e a grande diversidade da linguagem musical de Villa-Lobos.</p><p style="text-align:justify">A abordagem interpretativa de Halász revela diversas nuances. Em peças como as &quot;Três Danças Características Africanas&quot;, &quot;As Três Marias&quot; e a versão para piano solo do bailado &quot;Amazonas&quot;, a pianista imprime um caráter vibrante, impetuoso, robusto e quase viril. Nessas músicas, sobressai sua abordagem enérgica e marcante, conferindo um toque audacioso e arrebatador, como se a própria selva brasileira transpirasse do teclado. Nas faixas mais introspetivas como &quot;Lembrança do Sertão&quot;, &quot;Poema Singelo&quot; e &quot;Tristorosa&quot;, Halász revela lirismo e delicadeza quando a partitura o exige.</p><p style="text-align:justify"><span style="font-weight:bold">Opiniões</span>:</p><p style="text-align:justify">&quot;O ciclo para piano «Carnaval das Crianças» de Villa-Lobos, uma contrapartida brasileira do Carnaval de Schumann, revelou-se um desfile exuberantemente espirituoso de personagens coloridas, soltas e, no entanto, subtilmente, precisamente e confiantemente executadas, mesmo no mais selvagem matagal de acordes e arpejos frenéticos. Este carnaval é um enriquecimento fascinante do repertório pianístico, muitas vezes excessivamente tocado - especialmente numa interpretação tão brilhante e inspiradora.&quot; - SÜDDEUTSCHE ZEITUNG</p><p style="text-align:justify">&quot;A música de Villa-Lobos é um exemplo feliz da síntese da música brasileira e europeia. Pelas mãos da pianista paulistana de origem húngara Débora Halász, ritmo, motricidade e dinâmica tornam-se vivamente audíveis.&quot; KLASSIK HEUTE</p>', '<h3><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h3><h3> </h3><p><span style="text-decoration:underline"><a href=https://www.smartx.art/post/d%C3%A9bora-hal%C3%A1sz-quando-a-emo%C3%A7%C3%A3o-e-a-t%C3%A9cnica-se-fundem-na-ponta-dos-dedos target=undefined>Entrevista SMARTx (2024)</a></span> - Débora Halász – Quando a emoção e a técnica se fundem na ponta dos dedos</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://keyboardbrasil.blogspot.com/2017/05/debora-halasz-talento-brasileiro-tipo.html target=_blank>Revista Keyboard Brasil (2017)</a></span></span> - Débora halász – Talento brasileiro tipo exportação</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://oglobo.globo.com/cultura/musica/o-brasil-precisa-ver-musica-classica-como-exportacao-diz-debora-halasz-18321004 target=_blank>O Globo Cultura (2015)</a></span></span> - ‘O Brasil precisa ver música clássica como exportação’, diz Débora Halász</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www1.folha.uol.com.br/fsp/ilustrad/fq3003200008.htm target=_blank>Folha de São Paulo Ilustrada (2000)</a></span></span> - Toque áspero de Débora Halász confere vitalidade</p><p> </p><p>Quer saber mais?</p><p> </p><p>Entre em contacto connosco!</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 80: Inês Simões
