INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('cbdf323e-8eb0-4485-8c82-c196e6fc532b', '81da4171-4581-49ed-bdc0-460649e483f9', 'ines-simoes', 'Inês Simões', 'Inês', '''+49 17660120137', '1984-03-02', 'Portugal', 'Germany', 'Berlin', 'Kanzowstrasse', NULL, '10439', 'Soprano', 'O meu canto é um verdadeiro reflexo da minha sensibilidade artística, gosto estético e  de uma paixão por obras do século XX.', 'https://static.wixstatic.com/media/81da41_27d64eb3de6a4471ac5c016adaa1e3d0~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 81: Alejo Alvarez Castillo
INSERT IGNORE INTO users (id, email, password, role) VALUES ('947e9b47-d93c-47d0-9c6a-6edce56b570d', 'wix-947e9b47@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('199f735e-05d5-49b2-b9b5-fea9895282b9', '947e9b47-d93c-47d0-9c6a-6edce56b570d', 'alejo-alvarez-castillo', 'Alejo Alvarez Castillo', 'Alejo', '''+393517258123', NULL, 'Italy', 'Italy', 'ROMA', 'Via Giovanni Stanchi 3', NULL, '00152', 'Barítono', '27 years old. 
Baritone. 
Teatro dell''Opera di Roma', 'https://static.wixstatic.com/media/947e9b_a830a6f5977341c8bc3a1244f0c56a9e~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Alejo Alvarez Castillo (Baritono)</p><p>27 anni, nato a Buenos Aires, Argentina.</p><p>2025/2026 TEATRO DELL&#x27;OPERA DI ROMA</p>', '<p>Come solista ha partecipato a produzioni d’opera al Teatro Avenida, Teatro Colón di Buenos Aires, Teatro Argentino de La Plata, Teatro CC25 de Mayo, Teatro Asturias e altri della Provincia di Buenos Aires e dell’interno dell’Argentina.</p><p>Nel 2020 entra all’Istituto Superiore d’Arte del Teatro Colón.</p><p>Tra le sue recenti produzioni ufficiali: solista nell’Opera da Camera del Teatro Colón in Viva la mamma (2022, 2023) e Gianni Schicchi (2022).</p><p>Debutta in Don Giovanni (ruolo principale) e in Turandot (Mandarino) al Teatro Avenida, ottobre 2023 (Juventus Lyrica e OFEBA).</p><p>Nella stagione 2023/2024 del Teatro Colón, partecipa come solista in cast nazionali e internazionali: Die Lustige Witwe (Kromov), Il Turco in Italia (Prosdocimo), Ariadne auf Naxos (Parrucchiere), Carmen (Morales) e The Consul (Agente segreto).</p><p>Nel 2024 debutta come Escamillo (Carmen) nella Sala d’Onore del Palacio Paz e al Teatro Español di Chubut.</p><p>Programma concerti nei principali teatri di Entre Ríos, Chubut, Jujuy e Mendoza.</p><p>Debutta con ruolo protagonista nella Sala Principale del Teatro Argentino di La Plata nel 2024 come Marcello (La Bohème) e successivamente interpreta Guglielmo in Le Villi (novembre 2024).</p><p> </p>', '<p>Dal 2025 fa parte del programma YAP Fabbrica del Teatro dell’Opera di Roma, dove interpreterà Haly in L’Italiana in Algeri e il Marchese in La Traviata.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 0, 1);

