-- Row 83: Kateryna Avdysh
INSERT IGNORE INTO users (id, email, password, role) VALUES ('7840cf43-3fae-4413-b2ee-eddc5011b8fc', 'wix-7840cf43@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('750b8e95-d9f2-4c07-8302-14f4e9366267', '7840cf43-3fae-4413-b2ee-eddc5011b8fc', 'kateryna-avdysh', 'Kateryna Avdysh', 'Kateryna', '999999999', '1993-07-15', 'Ucrânia', 'Portugal', 'Lisboa', 'xxxxxxxxx', NULL, '1800107', 'Cantora de Jazz', '"Vivo cada momento que estou em palco e canto como se fosse a última vez".', 'https://static.wixstatic.com/media/7840cf_0a30f5451dd14910aa0de82e270c071e~mv2.jpg', 'wix:document://v1/7840cf_5d695de909ad43d89c2ae86f96cb8544.pdf/bio.pdf', NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/7840cf_3f46f5b9dbec4bdebfdbe8eab491786b.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=POP3DOvKNEY', 'https://www.youtube.com/watch?v=RsQY51JLKw4', 'https://www.youtube.com/watch?v=ieNfq9R_1nY', 'https://www.youtube.com/watch?v=_ebrHQJDemQ', 'https://www.youtube.com/watch?v=APw1bS2yTz4', 'https://www.youtube.com/watch?v=ieNfq9R_1nY', NULL, NULL, NULL, NULL, '<p class="font_8">Kateryna Avdysh é uma talentosa vocalista e compositora de jazz da Ucrânia, atualmente à frente do projeto <strong>AVDYSH</strong>. Iniciou a sua carreira musical aos 18 anos em Kyiv, onde se destacou numa das principais casas de jazz da cidade.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Devido ao conflito na Ucrânia, Kateryna mudou-se para Portugal, onde tem continuado a realizar as suas apresentações.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Avdysh cativou o público em várias cidades da Ucrânia, bem como em Itália e na Polónia, e tem sido destaque em prestigiadas estações de rádio e canais de televisão em Portugal.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Reconhecida pela sua capacidade de <strong>incorporar as suas raízes ucranianas nas suas composições</strong>, interligando-as com música jazz moderna, Kateryna cria uma arte contemporânea que verdadeiramente ressoa com o público.</p>', '<p>Kateryna Avdysh nasceu na Ucrânia e desde muito cedo demonstrou seu talento e paixão pela música. Aos 5 anos, começou a aprender piano e, ainda criança, destacou-se em concursos e recitais. Aos 9 anos, ingressou no coro da escola, sendo convidada a se tornar a solista do coro de adultos.</p><p> </p><p>Aos 13 anos, Kateryna tomou uma decisão decisiva ao mudar totalmente sua orientação musical, abandonando a música pop para <span style="font-weight:bold">dedicar-se ao jazz</span>. A sua voz distintamente jazzística e a sua afinidade pelo género foram rapidamente reconhecidas, levando-a a aprofundar seus estudos na escola de jazz e, posteriormente, na academia de música.</p><p> </p><p>Antes do conflito na Ucrânia seu país, Kateryna já se destacava como uma artista renomada, apresentando-se com grandes bandas no seu país natal e em palcos internacionais. Depois do início da guerra, a jovem cantora e compositora mudou-se para Portugal, onde continuou a desenvolver sua carreira artística.</p><p> </p><p>Em Lisboa, iniciou o projeto <span style="font-weight:bold">AVDYSH</span>, que <span style="font-weight:bold">combina jazz contemporâneo com a riqueza dos motivos ucranianos</span>, criando uma experiência musical envolvente e única. As suas composições originais e arranjos de canções ucranianas expressam as suas experiências, as suas emoções e uma profunda ligação com suas raízes.</p><p> </p><h3><span style="font-weight:bold">PRINCIPAIS INFLUÊNCIAS</span></h3><ul><li>Cécile McLorin Salvant</li><li>Tigran Hamasyan</li><li>Yakiv Tsvetinskiy</li><li>Esperanza Spalding</li><li>Cleo Sol</li><li>Kamasi Washington</li></ul><h3><span style="font-weight:bold">FORMAÇÃO</span></h3><ul><li>Vocal performance na Reinhold Glier Kyiv Municipal Academy of Music</li><li>Vocal jazz na Kyiv Municipal Academy of Variety and Circus Arts</li><li>Piano e vocal na Kyiv School of Arts</li><li>FRESH Broadway programa (USA-Ukraine - 2021)</li><li>YES Academy program (USA-Ukraine - 2020)</li><li>Art Jazz School program (2019)</li></ul>', '<p>Com 19 anos, <span style="font-weight:bold">Kateryna Avdysh</span> criou o projeto <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://avdysh.com/about/https://avdysh.com/about/ target=_blank>AVDYSH</a></span></span></span>, que tem sido central de sua trajetória artística.</p><p> </p><p>A jovem cantora e compositora reuniu os melhores músicos de <span style="font-weight:bold">Kyiv </span>para se apresentar no prestigiado <span style="font-weight:bold">Caribbean Club Concert Hall</span>, uma das principais salas de jazz da capital ucraniana.</p><p> </p><p>Em Portugal, tem vindo a consolidar a sua carreira musical, apresentando-se em vários grandes palcos. Atuou no Dragão Arena (Porto), no Castelo de Leiria, no Centro de Artes de Sines, no Castelo de Serpa, no CAE Portalegre e no Festival Lisboa Mistura.</p><p> </p><p>Tem atuado com outros artisticas, como o cantor <span style="font-weight:bold">Salvador Sobral</span>, em concertos no Centro Cultural de Belém (CCB) e na MEO Arena em Lisboa, e Magalí Sare, com a qual cantou em concerto na Sala Luz de Gas, em Barcelona, em ucraniano e espanhol.</p><p> </p><h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p> </p><p><span style="font-weight:bold">2024 </span>- Lançou a campanha de crowdfunding para o seu álbum de estreia.</p><p><span style="font-weight:bold">2022-2023</span></p><ul><li>Lançou as suas primeiras músicas em Portugal, com destaque para as canções &quot;O Meu Mar&quot;, a primeira em português, e &quot;HRYTSYU&quot;, em ucraniano.</li><li>Começou a ganhar reconhecimento na cena musical portuguesa.</li></ul><p><span style="font-weight:bold">2022</span></p><ul><li>Mudou-se para Lisboa;</li><li>Cantou as suas músicas na Rádio Comercial;</li><li>Colaborou com Salvador Sobral no CCB e na MEO Arena.</li></ul><p><span style="font-weight:bold">2021 </span>- Início do projeto AVDYSH</p><p><span style="font-weight:bold">2015-2019</span> - Apresentou-se em várias cidades ucranianas como solista de Big Band.</p><p> </p><h3><span style="font-weight:bold">PERFORMANCES</span></h3><p> </p><p>Kateryna Avdysh já conquistou diversos prémios e reconhecimentos, dentro e fora da Ucrânia. Entre as suas performances memoráveis, destacam-se apresentações no <span style="font-weight:bold">Teatro de Broadway em Rivne</span>, no prestigiado palco do espaço <span style="font-weight:bold">Caribbean Club Concert Hall em Kyiv</span>, com orquestra no <span style="font-weight:bold">Dragão Arena</span> no Porto e no lendário<span style="font-weight:bold"> Jamboree Jazz</span> em Barcelona.</p>', '<h3><span style="font-weight:bold">PROJECTOS</span></h3><p> </p><p>Kateryna está a trabalhar no lançamento do seu álbum de estreia – <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://avdysh.com/ target=_blank>AVDYSH</a></span></span> -, que contará com 11 faixas e será um marco na carreira da jovem artista. Além de contar com participações especiais de músicos portugueses, a gravação da faixa &quot;My Home&quot; será realizada em solo ucraniano em homenagem a Kyiv, a sua cidade natal.</p><p> </p><p>“Estas canções encontrarão um lugar nos corações daqueles que ficam confusos nas suas mentes, que encontram respostas, que amam e esperam, duvidam e procuram a verdade...” Kateryna Avdysh</p><p> </p><p>A artista convida-nos para fazermos parte desta história e a apoiarmos no seu projeto através de uma campanha de <span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://avdysh.com/ target=_blank>crowdfunding</a></span></span>. Com a sua música, ela pretende partilhar a cultura ucraniana com o mundo, oferecendo conforto e inspiração a todos os que a escutam.</p><p> </p><h3><span style="font-weight:bold">MÚSICAS</span></h3><p> </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://open.spotify.com/intl-pt/album/6iaSb4YWvFwCkL4i5PU6jd target=_blank>HRYTSYU</a></span></span></p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=POP3DOvKNEY&pp=ygUWa2F0ZXJ5bmEgYXZkeXNoIHNvYnJhbA%3D%3D target=_blank>O Meu Mar</a></span></span></p><p> </p><h3><span style="font-weight:bold">NOTÍCIAS e ENTREVISTAS</span></h3><h3> </h3><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/porart-entrevista-kateryna-avdysh target=_blank>PorART Entrevista</a></span></span>: Kateryna Avdysh - uma jovem promessa para o jazz</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/porart-entrevista-kateryna-avdysh-1 target=_blank>ProART Notícia</a></span></span>: Álbum de Estreia da ucraniana Kateryna Avdysh no Jazz: apoie este projeto!</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://radiocomercial.pt/artigo/comercial-ucrania-kateryna-avdysh-canta-wave-de-tom-jobim target=_blank>Rádio Comercial</a></span></span> - Kateryna Avdysh canta Wave de Tom Jobim</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://observador.pt/2023/06/08/festival-criajazz-explora-sonoridades-e-espacos-com-concertos-em-leiria-e-batalha/ target=_blank>Observador (2023)</a></span></span> - Festival CriaJazz explora sonoridades e espaços com concertos em Leiria e Batalha</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://radiolisipo.com/kateryna-avdysh-o-meu-mar-2022-single-entrevista/ target=_blank>Rádio Olisipo (2022)</a></span></span> - Kateryna Avdysh “O Meu Mar” (2022) (single + entrevista)</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.youtube.com/watch?v=ZarSUIZUM5M target=_blank>TVI (2023)</a></span></span> - Kateryna Avdysh CANTA &quot;Vnochy&quot;</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://sicnoticias.pt/programas/leste-oeste target=_top>SIC - Menções no &quot;Leste/Oeste&quot; de Nuno Rogeiro</a></span></span> a próposito do seu concerto e do lançamento da música &quot;O Meu Mar&quot;</p><p> </p><h3>Quer saber mais?</h3><h3>Entre em contacto connosco!</h3>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 84: João Paulo Moreira
INSERT IGNORE INTO users (id, email, password, role) VALUES ('3e3f8f2c-5d31-4ec4-b910-1c65896fb01c', 'wix-3e3f8f2c@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('e5748202-2f74-484b-a5f5-cc486661b702', '3e3f8f2c-5d31-4ec4-b910-1c65896fb01c', 'joao-paulo-moreira', 'João Paulo Moreira', 'João', '''+351918668422', '1985-06-26', 'Portugal', 'Portugal', 'Trofa', 'Rua da Espingardeira nº481', 'Rua da Espingardeira nº481', '4785-661', 'Pianista', '“A música encapsula tudo o que normalmente não expresso no dia-a-dia. Ela é sentimento, espiritualidade, e transcendência"', 'https://static.wixstatic.com/media/7b859e_0113ef206621462b9548799a6e0fe60b~mv2.jpg', NULL, 'https://www.facebook.com/joaopaulo.moreira.16940', 'https://www.instagram.com/joaopaulomoreirapianist/?igsh=NTVhbDV4aHFwaDQz', 'https://www.joaopaulomoreira.com/', NULL, 'https://www.youtube.com/@joaomoreira6485', 'https://static.wixstatic.com/mp3/7b859e_8c0c4677381b4f2ebac06787f23e805f.mp3', NULL, NULL, 'https://youtu.be/Eplypw2Rqx0?si=FPPIORL0Go6IYjIH', 'https://youtu.be/40Q45JZAvWU?si=ReONziqhi1kfjdqH', 'https://youtu.be/qAQRwTz_JOs?si=F06aEHFu5W4f5tx6', 'https://youtu.be/J68achbXN8A?si=HaafGqPsHM8sEgMR', NULL, NULL, NULL, NULL, NULL, NULL, '<p><span style="font-weight:bold">João Paulo Moreira</span> é um pianista que combina uma técnica irrepreensível com uma profundidade emocional rara que o distinguem no mundo da música clássica.</p><p><br/></p><p>As suas performances são pautadas por uma sensibilidade inata e uma conexão visceral com a música. O seu som é simultaneamente poderoso e delicado, captando as subtilezas de cada composição com elegância e destreza.</p><p><br/></p><p>O seu repertório inclui quase sempre obras de <span style="font-weight:bold">Liszt </span>nos seus recitais, seja com os virtuosos “<span style="font-style:italic">Transcendental études</span>”, “<span style="font-style:italic">La campanella</span>” ou as desafiantes transcrições e paráfrases de óperas de vários compositores. É detentor de sérias interpretações das últimas sonatas de <span style="font-weight:bold">Beethoven </span>e ainda das “<span style="font-style:italic">Baladas</span>” de <span style="font-weight:bold">Chopin</span>. Frequentemente apresenta também obras como o “<span style="font-style:italic">Islamey</span>” de <span style="font-weight:bold">Balakirev</span>, obra conotada como uma das de mais difícil execução de todo o repertório pianístico.</p><p><br/></p><p>Ao longo da sua carreira, tem somado uma lista impressionante de feitos. Foi agraciado com o prestigiado 2º Prémio no Concurso Internacional de Piano da Calábria em 2023 e alcançou a final no aclamado Festival Internacional de Piano e Orquestra de Guadalajara, no México. Destaca-se o seu recital a solo no Museu Nogueira da Silva em Braga, com lotação esgotada, o Recital de Piano no Museu Romântico – Porto, Casa das Artes de Famalicão e o facto de ter sido selecionado para tocar a solo com a Orquestra do Algarve sob a orientação do maestro italiano Maurizio Colasanti e com a West Symphony Orquestra em Guadalajara – México.</p><p><br/></p><p>Em breve, vai lançar o seu primeiro álbum.</p>', '<p class="font_8">Nascido em 1985 em Santiago de Bougado, Trofa, João Paulo Moreira despertou para sua paixão pela música aos oito anos de idade. Desde pequeno, acompanhava a sua mãe, que tocava órgão na missa, e observava-a atentamente. Este primeiro contacto com a música despertou de imediato a sua curiosidade, levando-o a iniciar a sua formação musical aos oito anos. A sua primeira professora, Antónia Maria Serra, prontamente identificou o seu talento natural e incentivou-o a prosseguir o seu interesse pelo piano. Esses anos iniciais foram decisivos para forjar a dedicação e a disciplina de João Paulo face à sua arte.</p>
<p class="font_8"><br></p>
<p class="font_8">Mais tarde, iniciou os seus estudos com a renomada pianista Maria do Céu Camposinhos, no Centro de Cultura Musical, Caldas da Saúde. Sob sua orientação, aprimorou as suas capacidades e expandiu o seu repertório, culminando na obtenção do 8.º Grau com a nota máxima de 20 valores — um testemunho do seu crescente domínio do instrumento.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2010, atingiu outro marco significativo ao concluir a sua licenciatura em piano na Escola Superior de Música e Artes do Espetáculo (ESMAE), no Porto, onde estudou com Sofia Lourenço. Os anos na ESMAE foram cruciais para consolidar os seus fundamentos técnicos e artísticos, preparando-o para enfrentar os desafios de uma carreira profissional.</p>
<p class="font_8"><br></p>
<p class="font_8">Incansável na sua busca por conhecimento, continuou os seus estudos com Luís Pipa e Sofia Lourenço, alcançando o mestrado em ensino de música pela ESMAE com elevada distinção. Esta fase refinou as suas próprias competências, e despertou uma paixão pela pedagogia que continuaria a influenciar a sua abordagem musical.</p>
<p class="font_8"><br></p>
<p class="font_8">Participou em várias masterclasses e musicais com os Professores e pianistas Jaime Mota, Fátima Travanca, Tsiala Kvernadze, Miguel Borges Coelho, Helena Sá e Costa, Vura Margulis e Maria Céu Camposinhos: Jaime Mota, Fátima Travanca, Tsiala Kvernadze, Miguel Borges Coelho, Helena Sá e Costa, Maria do Céu Camposinhos, Luís de Moura Castro, Jura Margulis, Vitaly Margulis, Jörg Demus, Pedro Burmester, Adriano Jordão, Claudio Martínez Mehner, Christopher Elton e Rixiang Huang.</p>
<p class="font_8"><br></p>
<p class="font_8">Atualmente, encontra-se num novo capítulo da sua jornada académica, fazendo o doutoramento em música na Universidade de Aveiro, onde é investigador do INET-md e desenvolve o seu projeto de investigação sobre obras de J.S. Bach e os 24 Prelúdios para piano de Fernando Lopes-Graça, sob a orientação de Fausto Neves. Também como investigador, participou no Research Summit 2023, tendo sido também selecionado para apresentar no XII ENIM, que teve lugar no Real Edifício de Mafra em outubro de 2023.</p>
<p class="font_8"><br></p>
<p class="font_8">Foi admitido na prestigiada Musikhochschule Münster para o ano letivo de 2023/2024, para o Zertifikatsstudienjahr, com especialização em piano, onde teve a oportunidade de estudar com o pianista e pedagogo Peter von Wienhardt, tendo concluído os seus estudos com elevada classificação.</p>', '<p class="font_8">João Paulo Moreira tem feito várias aparições públicas com recitais a solo em inúmeros locais do país como: Aveiro, Paço dos Duques em Guimarães, Póvoa de Varzim, Vila do Conde, Trofa, Santo Tirso, Fafe, Famalicão, Barcelos e Óbidos, entre outros.</p>
<p class="font_8"><br></p>
<p class="font_8">Iniciou também recentemente a sua carreira internacional, tendo já tocado na Alemanha e no México, no Festival Internacional de Piano e Orquestra de Guadalajara, onde foi um dos três finalistas selecionados e teve a honra de interpretar o icónico Concerto "<em>Imperador</em>" de Beethoven no imponente Teatro Degollado.</p>
<p class="font_8"><br></p>
<p class="font_8">O primeiro grande marco na sua carreira ocorreu em 2005, quando, ao lado do tenor Alberto Costa, estreou a obra "Cecília Lieder" do compositor Nuno Jacinto em dois concertos memoráveis – um na ESMAE, no Porto, e outro no prestigiado Teatro São Luiz, em Lisboa, este último transmitido pela Antena 2.</p>
<p class="font_8"><br></p>
<p class="font_8">Outro momento marcante foi a estreia como solista com a Orquestra Artave, em 2012, interpretando a desafiadora "<em>Totentanz</em>" de Franz Liszt, sob a batuta do maestro Ernst Schelle. Ao longo dos anos, colaborou com diversos agrupamentos musicais, incluindo a aclamada Banda Musical da Póvoa de Varzim.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2015 participou num recital a solo no programa EUROCLASSICAL, apresentado e gravado no Teatro Helena Sá e Costa. Recentemente colaborou com a Banda Musical da Póvoa de Varzim.</p>
<p class="font_8"><br></p>
<p class="font_8">Ao longo dos anos, estabeleceu-se como um pianista solo de renome, apresentando-se em algumas das salas mais prestigiadas do país.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Destacam-se os seguintes concertos</strong>:</p>
<p class="font_8"><br></p>
<p class="font_8">· Recital a solo integrado na 2ª temporada dos Ciclos Lua Nova – Série Internacional de Recitais de Piano e Música de Câmara na Fundação Dionísio Pinheiro e Alice Cardoso Pinheiro (2022);</p>
<p class="font_8">· Salão Nobre do Museu Nogueira da Silva, em Braga (2023);</p>
<p class="font_8">· Concerto "Tons de primavera" na Trofa (2023);</p>
<p class="font_8">· Concerto como solista com a Orquestra do Algarve no Piano Concerto Festival em Faro (2023);</p>
<p class="font_8">· Ateneu Comercial do Porto;</p>
<p class="font_8">· Pavilhão Centro de Portugal, em Coimbra;</p>
<p class="font_8">· Museu do Porto – Extensão do Romantismo (2023);</p>
<p class="font_8">· Casa das Artes em Famalicão (2024);</p>
<p class="font_8">· Teatro Gil Vivente em Barcelos, num concerto de homenagem ao compositor Luiz Costa, inspirado no repertório do outro concerto de homenagem realizado a oito de maio de 1950, no Cinema Júlio Diniz na cidade do Porto (2024).</p>
<p class="font_8">Em breve, vai lançar o seu primeiro álbum.</p>
<p class="font_8"><br></p>
<p class="font_8"><strong>Prémios</strong></p>
<p class="font_8"><br></p>
<p class="font_8">· 2º Prémio no Concurso Internacional De Piano Calabria (2023);</p>
<p class="font_8">· Finalista da primeira edição do Festival Internacional de Piano e Orquestra de Guadalajara, México (2024).</p>', '<p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=http://www.inetmd.pt/index.php/pessoas/integradosnaodoutorados/doutorandos/2427-joao-paulo-moreira target=undefined>Investigador do INET-md – Instituto de Etnomusicologia</a></span></span></p><p><br/></p><p><span style="font-weight:bold">Notícias &amp; Entrevistas</span></p><p>https://mundoclasico.com/articulo/42225 - João Paulo Moreira da concerto em Espanha, Leon. </p><p> </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.onoticiasdatrofa.pt/bougadense-joao-paulo-moreira-da-concerto-na-casa-das-artes-de-famalicao/ target=undefined>Notícias da Trofa (2024)</a></span></span> – Bougadense João Paulo Moreira dá concerto na Casa das Artes de Famalicão</p>', 'https://static.wixstatic.com/media/3e3f8f_998101e7863945a9a73946ed28af5216~mv2.jpeg', NULL, 'https://static.wixstatic.com/media/3e3f8f_08094c864f1f4da69d3076e151b30654~mv2.jpg', NULL, 'https://static.wixstatic.com/media/3e3f8f_c2526f30cf73482c87e7c7d0ecc4de3a~mv2.jpg', NULL, 'https://static.wixstatic.com/media/3e3f8f_6cb45f8083ab4490947c8fbf4e858081~mv2.jpg', NULL, 'https://static.wixstatic.com/media/3e3f8f_1f8c09b461ce48888b972c3c400742f7~mv2.jpg', NULL, 'https://static.wixstatic.com/media/3e3f8f_6b5c2907c3724f66aef4afd360df0093~mv2.jpg', NULL, 'https://static.wixstatic.com/media/3e3f8f_2add31e7b7f94be7956643ce862970da~mv2.jpg', NULL, 'https://static.wixstatic.com/media/3e3f8f_c5dd513a83684369af4c73cb9b9201e8~mv2.jpg', NULL, 'https://static.wixstatic.com/media/3e3f8f_1fdec976af4f453ca0292a69215ab3b3~mv2.jpg', NULL, 'https://static.wixstatic.com/media/3e3f8f_2054ca132d9f4df49184abfda0d62593~mv2.jpg', NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

