INSERT IGNORE INTO users (id, email, password, role) VALUES ('7f54687c-262e-4134-86ea-9364e4cb2aec', 'wix-7f54687c@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('55bf0f53-bfd9-49df-ab61-92b876e25d3e', '7f54687c-262e-4134-86ea-9364e4cb2aec', 'fernando santos', 'PROPOSTAS HARMÔNICAS LDA', 'PROPOSTAS', '97564545', '2024-08-02', 'Brasil', 'Portugal', 'as f', 'asdf', 'RUA CIDADE DE NOVA LISBOA 219 6A', '1800-107', 'Violoncelista', 'asdf asdg asdfg asdfgasdf asdfa sdg erwqry4u57635ywer tewr', 'https://static.wixstatic.com/media/ca4a57_d90bde0528cd4f02bd52dc88dd6c3aa6~mv2.jpg', 'wix:document://v1/ca4a57_b866fa26ada44fe5af03c028a75f0902.pdf/Decreto%20Lei%20SNQ.PDF', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.youtube.com/watch?v=HmOrWAsVXuM', 'https://www.youtube.com/watch?v=6m2Ma8uX74s', 'https://www.youtube.com/watch?v=QDo_GXGuUi0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p>Bem-vindo à aba principal do seu perfil de Artista! Sugerimos que use uma letra maior para chamar a atenção do leitor e incentivá-lo a explorar as outras abas e galerias.  </p><p> </p><p>Dicas:</p><p> </p><p>a)  Ao navegar pelos perfis de outros Artistas SMART, você encontrará inspiração e novas ideias.</p><p> </p><p>b)  Ao criar seu perfil, sugerimos iniciar com uma frase impactante que valorize sua arte e carreira. Pode ser um depoimento de um crítico ou uma frase autoral que destaque sua singularidade.</p><p> </p><p>c)   Em seguida, inclua até quatro parágrafos breves que apresentem sua trajetória e destaquem seus pontos fortes. Lembre que esta aba é apenas uma visão geral, então deixe os detalhes para as abas “História” e “Carreira”.</p><p> </p>', '<p> </p>', '<p>Aqui, deverá destacar a sua trajetória como artista, os seus marcos e os grandes êxitos da sua carreira, com base no seu currículo e biografia.  O tom do texto deve ser informativo: objetivo, claro e direto, focado na transmissão de informações de maneira factual e desapaixonada. Podem ser utilizados subtítulos ou uma estrutura por tópicos para facilitar a organização do texto. Dicas:</p><p>a)   Inicie com um parágrafo que caracterize a sua carreira. Se tivesse de definir-se como artista num único parágrafo, o que diria?</p><p>b)  Poderá organizar seu texto fazendo uso de subtítulos, utilizando letras maiores em negrito, como por exemplo: linha do tempo, prémios, formação artística, colaborações, álbuns, atuações memoráveis, colaborações e parcerias etc.</p>', '<h2>MAIS</h2><p>Nesta sessão, você pode compartilhar informações adicionais que mereçam menção, como hiperlinks para entrevistas, matérias sobre sua arte, álbuns, plataformas de música e projectos <span style="text-decoration:underline"><a href=http://www.uol.com.br target=undefined>especiais</a></span>.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 87: André Baleiro
INSERT IGNORE INTO users (id, email, password, role) VALUES ('3ed1cd2d-e57a-4fa2-a92b-826828fea419', 'wix-3ed1cd2d@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('44b4d017-6712-4b6f-b70d-bfe5f80038db', '3ed1cd2d-e57a-4fa2-a92b-826828fea419', 'andre-baleiro', 'André Baleiro', 'André', '918391451', '1989-05-16', 'Portugal', 'Portugal', 'Lisboa', 'R. 10 do PUAL Nº.4, 2ºB', NULL, '1750-062', 'Barítono', 'Procuro servir a música de forma autêntica e profunda de modo a transmitir o que de mais belo há nas obras que interpreto.', 'https://static.wixstatic.com/media/3ed1cd_585a8decb53b48bdbe3781018017b618~mv2.png', 'wix:document://v1/ugd/7b859e_3460bc1be6a641078c0f2bef28f1d7a2.pdf/Andre%20Baleiro%20PT.pdf', NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/7b859e_089da20014a64a25917a10629a301805.mp3', NULL, NULL, 'https://youtu.be/__H3W2y8snw', 'https://youtu.be/RO9Jcbvf4W0', 'https://youtu.be/aSENstfhqPM', 'https://youtu.be/Vxh4V6w_6bA', 'https://youtu.be/e-7xE3yn-1w', 'https://youtu.be/V9cIqTYkrOY', 'https://youtu.be/MQyWx_IGeKU?si=TjjzdwAicOEonsrI', 'https://youtu.be/y79y35iFPU8?si=_4Mv_ualmK2DeEkx', 'https://youtu.be/cyf6ca9jdxM?si=wXh3-imq4gm9SPxS', 'https://youtu.be/1QizWRe7IXQ', '<p class="font_8">O barítono português <strong>André Baleiro</strong> é reconhecido pela sua voz aveludada e expressiva, que transita com maestria pelos mais diversos géneros e estilos, desde a pureza da música antiga até à complexidade da música contemporânea, consolidando-se como um dos jovens cantores mais promissores da sua geração.</p>
<p class="font_8"><br></p>
<p class="font_8">Aclamado pela crítica e pelo público, foi laureado em importantes competições líricas, como o Concurso "SWR Young Opera Stars" em 2019, o 17º Concurso Internacional R. Schumann (Zwickau), o 9º Concurso de Canto Lírico da Fundação Rotária Portuguesa (Lisboa), o Prémio "Most Promising Talent" no Concurso Internacional DAS LIED (Heidelberg), o Concurso Internacional de <em>Lied</em> “Helmut Deutsch” em Viena e o Concurso Internacional de <em>Lied</em> “Schubert e a música moderna” em Graz, na Áustria.</p>
<p class="font_8"><br></p>
<p class="font_8">No universo operático, André Baleiro tem brilhado em papéis como Pelléas (Pelléas et Mélisande de Debussy), Orphée (Philip Glas), Tarquinius (“The Rape of Lucretia” de Britten), Ned Keen (“Peter Grimes” de Britten), Valentin (“Faust” de Gounod), Don Giovanni (Mozart) e Ford (“Falstaff” de Verdi).</p>
<p class="font_8"><br></p>
<p class="font_8">No repertório coral-sinfónico e de concerto já interpretou diversas oratórias de Bach, Händel e Mozart, os Requiem de Fauré, Duruflé e Brahms, “L''enfance du Christ” de Berlioz, “Carmina Burana” de Orff, os “Gurrelieder” de Schoenberg e os ciclos para voz e orquestra “Lieder eines fahrenden Gesellen” de Mahler e “Don Quichotte à Dulcinée” de Ravel.</p>
<p class="font_8"><br></p>
<p class="font_8">Intérprete apaixonado pelo repertório do <em>Lied</em> (Canção de Câmara), apresenta-se regularmente em recitais de canção em diversos países.</p>', '<p class="font_8">Nascido em Lisboa em 1989, André Baleiro descobriu sua vocação musical aos oito anos, quando pediu aos pais para estudar música. Apoiado pela família, teve suas primeiras lições na Escola Básica nº 24 do Bairro de São Miguel com a professora Teresa Lancastre, que também lecionava no Instituto Gregoriano de Lisboa.</p>
<p class="font_8"><br></p>
<p class="font_8">Aos 10 anos, por indicação de Lancastre, André ingressou no Instituto Gregoriano de Lisboa, onde se apaixonou pela música coral e pela experiência transformadora de fazer música em conjunto, sob a orientação do maestro Armando Possante</p>
<p class="font_8"><br></p>
<p class="font_8">Começou a ter aulas de técnica vocal com Elsa Cortez aos 15 anos e explorou diversos géneros, como a canção portuguesa, francesa e alemã, <em>arie antiche</em> e árias de ópera.</p>
<p class="font_8"><br></p>
<p class="font_8">Entrou para o Coro Gulbenkian com 18 anos, onde assumiu responsabilidades crescentes como coralista e solista, por indicação do maestro Michel Corboz. Decidido a se profissionalizar, abandonou o curso de Física no Instituto Superior Técnico para estudar Direção Coral e Formação Musical na Escola Superior de Música de Lisboa.</p>
<p class="font_8"><br></p>
<p class="font_8">Determinado a aprofundar seus conhecimentos, André Baleiro mudou-se para Berlim em 2011 para estudar canto na conceituada <em>Universität der Künste</em>. Aprendeu com o professor e barítono Siegfried Lorenz, um dos mais renomados intérpretes de <em>Lieder</em> e cantores de ópera alemães.</p>
<p class="font_8"><br></p>
<p class="font_8">Numa imersão total na língua e na cultura alemãs, absorveu a essência do repertório germânico, do barroco ao contemporâneo. Paralelamente, participou de masterclasses com figuras conceituadas como José van Dam, Lorenzo Regazzo, Tom Krause e Ian Bostridge.</p>', '<p class="font_8"><strong>PRÉMIOS</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8"><strong>1º Prémio</strong> no Concurso Internacional Robert Schumann em Zwickau, Alemanha.</p></li>
  <li><p class="font_8"><strong>Prémio "Talento mais promissor"</strong> no Concurso de Internacional "DAS LIED" em Heidelberg, Alemanha.</p></li>
  <li><p class="font_8"><strong>2º Prémio</strong> no Concurso Internacional de Lied "Helmut Deutsch" em Viena, Áustria.</p></li>
  <li><p class="font_8"><strong>2º Prémio</strong> no Concurso Internacional "Schubert e a música moderna" em Graz, Áustria.</p></li>
  <li><p class="font_8"><strong>1º Prémio</strong> no Concurso "SWR Young Opera Stars" em Kaiserslautern, Alemanha.</p></li>
  <li><p class="font_8"><strong>1º Prémio</strong> no Concurso de Canto Lírico da Fundação Rotária Portuguesa em Lisboa, Portugal.</p></li>
</ul>
<p class="font_8"><br></p>
<p class="font_8"><strong>DESTAQUES</strong></p>
<p class="font_8"><br></p>
<ul class="font_8">
  <li><p class="font_8"><strong>Ford</strong> na produção "Falstaff" de Verdi no Teatro Nacional de São Carlos, encenada por Jacopo Spirei e dirigida por Antonio Pirolli.</p></li>
  <li><p class="font_8"><strong>Don Giovanni</strong> na produção Mozart/Saramago na Fundação Calouste Gulbenkian, encenada por Jean-Paul Bucchieri e dirigida por Nuno Coelho.</p></li>
  <li><p class="font_8"><strong>Pelléas</strong> na produção "Pelléas et Melisande" de Debussy no Centro Cultural de Belém, encenada por Kristiina Helin e dirigida por Dinis Sousa.</p></li>
  <li><p class="font_8"><strong>Orphée</strong> na produção "Orphée" de Philip Glas no Centro Cultural de Belém, encenada por Felipe Hirsch e dirigida por Pedro Neves.</p></li>
  <li><p class="font_8"><strong>Tarquinius</strong> na produção "The Rape of Lucretia" de Britten, encenada por Luís Miguel Cintra e dirigida por João Paulo Santos.</p></li>
  <li><p class="font_8"><strong>Valentin</strong> na produção "Fausto" de Gounod no Teatro Nacional de São Carlos, encenada por Alfonso Romero e dirigida por Antonio Pirolli.</p></li>
  <li><p class="font_8"><strong>Kaspar Hauser</strong> na produção "Kaspar Hauser" da Ópera de Câmara de Munique encenada por Dominik Wilgenbus, e dirigida por Nabil Shehata.</p></li>
