3c~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_53dad4bcaaba42d8a084786086f19580~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_414753ce08454564ad4d546f1829cb6f~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_2deea5f6a17d4be3b15152798726b562~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_1072a63cf1bf4ca6ba4d7dec06e7da1e~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_9d29dc35805742229509ed7b29e48382~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_e9159250be2a4af99617560dcacd2419~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_83f82054d89042bd82d5ada2b194f537~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_b5778c5f7e0b4974bf7e5bd7049c861e~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_6ce0a9d840854cc99f7a029ede066f38~mv2.jpg', NULL, 'https://static.wixstatic.com/media/706bc2_fe18f4cabce94ed687ce07c684a59097~mv2.jpg', NULL, 1, 0, 0);

-- Row 89: Isabel Vaz
INSERT IGNORE INTO users (id, email, password, role) VALUES ('f371ed46-392d-4bc1-9128-4d7d9ba25106', 'wix-f371ed46@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('9c0bbb9d-388e-4772-8bd9-18a15b3b4845', 'f371ed46-392d-4bc1-9128-4d7d9ba25106', 'isabel-vaz', 'Isabel Vaz', 'Isabel', '999999999', '1991-07-18', 'Portugal', 'Países Baixos', 'Amsterdão', 'xxx xxxxx', NULL, '88101310', 'Violoncelista', '"Com resiliência e amor pela música, segui um caminho de disciplina e valores."', 'https://static.wixstatic.com/media/f371ed_72a02c0e33844afeb164c92bd6b1552c~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 'https://static.wixstatic.com/mp3/f371ed_f73233c551524b7d8bcb3c609572eed9.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=Lh9V97nxX88', 'https://www.youtube.com/watch?v=qx4lhbPtYVs', 'https://www.youtube.com/watch?v=dFgORtEIS9k', 'https://www.youtube.com/watch?v=V51TgGHTzt0', NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8">"Isabel Vaz é uma violoncelista portuguesa de talento distinto, cuja arte transcende as cordas do seu violoncelo francês do início do século XX." Zdenka Weber</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">As suas interpretações são marcadas por uma <strong>profunda musicalidade e técnica impecável</strong>, duas virtudes que lhe permitem explorar todos os matizes expressivos do violoncelo. Detentora de um <strong>fraseado elegante e imbuído de nobreza</strong>, revela uma <strong>sensibilidade ímpar</strong> na forma como molda cada frase musical, extraindo ricas camadas emocionais das partituras.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Com uma <strong>sólida formação clássica e abordagem criativa</strong>, imprime a sua individualidade artística em cada atuação. Destaca-se pela sua <strong>sonoridade intrínseca</strong>, conectando-se com a música e com a audiência de forma emotiva e significativa, mas também pela sua <strong>versatilidade </strong>em interpretações a solo ou no contexto de música de câmara e orquestral.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">É <strong>Diretora Artística do Algarve Music Series</strong>, criado em 2016, e violoncelista da <strong>Noord Nederlands Orkest</strong> (Holanda) e integra o <strong>Haarlem Piano Trio</strong> (música de câmara).</p>', '<p>Nascida numa família profundamente ligada às artes, Isabel Vaz teve desde cedo contacto com o mundo artístico. O seu pai, Isolino Vaz, um notável pintor e artista plástico, fomentou nela o amor por diversas formas de expressão artística, e a família materna, com fortes laços musicais, cultivou em Isabel um fascínio precoce pela música.</p><p> </p><p>Aos quatro anos, iniciou os seus estudos musicais na <span style="font-weight:bold">Fundação Musical dos Amigos das Crianças</span>, em Lisboa. Neste ambiente estimulante, desenvolveu rapidamente um amor profundo pela música, cativada pela sonoridade única do violoncelo. Aos sete anos, começou a ter <span style="font-weight:bold">lições de violoncelo com os professores Luís Estevão da Silva e Maria José Falcão</span>.</p><p> </p><p>Durante a infância e adolescência, a frequente exposição a concertos de música erudita, tanto sinfónicos como de câmara, e eventos como um recital do violoncelista Yo-Yo Ma e uma atuação do coreógrafo Mikhail Baryshnikov, enriqueceram o seu interesse pelas várias vertentes artísticas.</p><p> </p><p>Aos nove anos, a participação em pequenos ensembles de música de câmara despertou em Isabel a paixão pela partilha musical com outros intérpretes, moldando a sua abordagem tanto à vertente solista como à música de conjunto.</p><p> </p><p>Completou a sua licenciatura na <span style="font-weight:bold">Escola Superior de Música de Lisboa</span>, onde foi orientada por mestres como <span style="font-weight:bold">Clélia Vital</span> e <span style="font-weight:bold">Irene Lima</span>, que lhe permitiram aprofundarar a sua técnica e conhecimentos musicais. Continuou os estudos no <span style="font-weight:bold">Conservatório de Amesterdão</span>, onde obteve o mestrado e foi fortemente influenciada pelo violoncelista <span style="font-weight:bold">Dmitry Ferschtman</span>, desenvolvendo uma relação de mestre-discípulo fundamental.</p><p> </p><p>O seu trajeto académico incluiu ainda períodos enriquecedores na <span style="font-weight:bold">HAMU </span>(Praga), na <span style="font-weight:bold">Manhattan School of Music</span> (Nova Iorque) e na <span style="font-weight:bold">Hochschule für Musik, Theater und Medien Hannover</span> (Alemanha), participando em masterclasses com renomados como <span style="font-weight:bold">Gary Hoffman, Natalia Shakovskaya e Giovanni Sollima</span>.</p><p> </p><h3>&quot;Os músicos que conheci, assim como os amigos que fiz, mudaram a minha maneira de ver a música e a vida.&quot;</h3><p>Isabel Vaz</p>', '<p>Atualmente, Isabel Vaz divide o seu tempo entre atuações a solo com diversas orquestras europeias e o trabalho como violoncelista tutti na <span style="font-weight:bold">Noord Nederlands Orkest</span>. Co-dirige o <span style="font-weight:bold">Algarve Music Series</span> com o pianista <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://smart.proart.art/artista/vasco-dantas target=_blank>Vasco Dantas</a></span></span></span>, um conceituado festival de música de câmara que criou em 2016.</p><p> </p><h3><span style="font-weight:bold">PRÉMIOS</span></h3><h3> </h3><ul><li>1º Prémio no Concurso de Interpretação do Estoril (2016)</li><li>Prémio Especial Discográfico no Concurso Salieri Zinetti (música de câmara, 2015)</li><li>Prémio Jeunesses Musicales Deutschland no Premio Borciani (música de câmara, 2014)</li><li>3º Prémio no Concurso Internacional de Música de Câmara Val Tidone (2014)</li><li>1º Prémio no Concurso Internacional de Música de Câmara Guido Papini (com Quartetto Indaco, 2013)</li><li>3º Prémio e Prémio do Público no Concurso de Interpretação do Estoril (2012)</li><li>1º Prémio no Prémio Jovens Músicos (categoria música de câmara com Quarteto Blanc, 2009)</li></ul><p> </p><h3><span style="font-weight:bold">COLABORAÇÕES E PARCERIAS</span></h3><h3> </h3><ul><li>Quartetto Indaco (2013-2015) - Integrou este quarteto de cordas, realizando recitais em salas e festivais pela Europa sob orientação de Oliver Wille.</li><li>Duo com Vasco Dantas - Tem uma parceria musical em duo com o pianista Vasco Dantas.</li><li>Noord Nederlands Orkest (desde 2015) - Atua como violoncelista tutti nesta orquestra sinfónica holandesa.</li><li>Diversas atuações com a Orquestra Metropolitana de Lisboa, a Orquestra de Cascais e Oeiras, a Kremlin Chamber Orchestra, o Sonor Ensemble, a Zagreb Soloists, entre outras.</li></ul><p> </p><h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p> </p><p>2024 - 9ª Edição do Algarve Music Series programada para Outubro.</p><p>2021 - Lançamento do álbum &quot;Luís de Freitas Branco: Sonatas” com o pianista Vasco Dantas e o violinista Tomás Costa. Nomeação para o Melhor Álbum de Música Clássica/Erudita nos prémios PLAY – Prémios da Música Portuguesa 2020.</p><p>2016 - Vence o 1º Prémio no Concurso de Interpretação do Estoril. Lança o Algarve Music Series (inicialmente FIMCA) com Joaquim Guerreiro e Eduardo Paredes. Frequenta o Mestrado em Quarteto de Cordas na Hochschule Hannover com Oliver Wille.</p><p>2015 - Prémio Especial Discográfico no Concurso Salieri Zinetti. É nomeada violoncelista tutti na Noord Nederlands Orkest. Participa em masterclasses com Gary Hoffman, Márcio Carneiro, entre outros.</p><p>2014 - Prémio Jeunesses Musicales Deutschland no Premio Borciani. 3º Prémio no Concurso Internacional de Música de Câmara Val Tidone.</p><p>2013 - Termina o Mestrado no Conservatório de Amsterdão com Dmitry Ferschtman. Integra o Quartetto Indaco.</p><p>2012 - 3º Prémio e Prémio do Público no Concurso de Interpretação do Estoril.</p><p>2011 - Intercâmbio de um semestre na Manhattan School of Music, Nova Iorque.</p><p>2010 - Intercâmbio de um semestre na HAMU, Praga.</p><p>2009 - Vence o 1º Prémio no Prémio Jovens Músicos na categoria de música de câmara (com Quarteto Blanc).</p><p>2007 - Muda-se para os Países Baixos para estudar no Conservatório de Amesterdão.</p><p>2005 - Ingressa na Escola Superior de Música de Lisboa.</p><p>1993 - Começa as aulas de violoncelo aos sete anos.</p><p>1990 - Inicia os estudos musicais aos quatro anos na Fundação Musical dos Amigos das Crianças.</p>', '<h3><span style="font-weight:bold">ÁLBUNS</span></h3><p> </p><p>&quot;<span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://codaxmusic.com/product/luiz-de-freitas-branco-sonatas/ target=_blank>Luíz de Freitas Branco: Sonatas</a></span></span>”</p><p> </p><h3><span style="font-weight:bold">NOTÍCIAS &amp; ENTREVISTAS</span></h3><p> </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/proart-entrevista-isabel-vaz-uma-vida-entre-as-cordas-do-violoncelo target=_blank>PorART Entrevista</a></span></span>: Isabel Vaz - Uma vida entre as cordas do violoncelo</p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.orquestraxxi.pt/perfis/2016/5/17/isabel-vaz target=_blank>Entrevista Orquestra XXI</a></span></span></p><p> </p><h3>Quer saber mais?</h3><h3>Entre em contacto connosco!</h3>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

