-- Row 91: Maurício Galindo
INSERT IGNORE INTO users (id, email, password, role) VALUES ('f47b7288-ee0c-4816-ab13-8138ac2b5c53', 'wix-f47b7288@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('5c8728e7-f150-4b39-b166-5af55b98491a', 'f47b7288-ee0c-4816-ab13-8138ac2b5c53', 'mauricio-galindo', 'Maurício Galindo', 'Maurício', '351935440931', '1960-09-21', 'Brasil', 'Portugal', 'Vila do Conde', 'Av. Sacadura Cabral 67 RdC - Centro', NULL, '4480-675', 'Diretor de Orquestra', '"Música é um tesouro civilizatório a ser compartilhado com todos."', 'https://static.wixstatic.com/media/7b859e_dae2e49e06864c4d8a689d9ebf86f0e3~mv2.jpg', NULL, 'https://www.facebook.com/maestro.joaogalindo/', 'https://www.instagram.com/maestrojoaomauriciogalindo/', 'https://pergunteaomaestro.com.br/', 'https://open.spotify.com/show/32WOHn2soeILMNmVqdD143', 'https://www.youtube.com/@maestrogalindo', NULL, NULL, NULL, 'https://www.youtube.com/watch?v=_H8DGvKgAig', 'https://youtu.be/-djgAz1QADQ', 'https://youtu.be/KnrW2tI5sG8', 'https://youtu.be/9cn9bBTbwow', 'https://youtu.be/gwyngDzqOLg', 'https://youtu.be/sgY-gzbszP4', 'https://youtu.be/QXh_NNahedU', 'https://youtu.be/nmuTnIYiEnA', 'https://youtu.be/q2JhE30_hH4', 'https://youtu.be/zaB41mhSRUw', '<p class="font_8">João Maurício Galindo é Regente Emérito da <strong>Brasil Jazz Sinfônica</strong>. Com 70 músicos e instalada em São Paulo, a maior cidade da América do Sul, é uma das poucas orquestras sinfônicas do mundo totalmente dedicada à música popular em formato sinfônico, sempre executada arranjos sofisticados.</p>
<p class="font_8"><br></p>
<p class="font_8">Dirigiu concertos com artistas como Paquito de Rivera, Gonzalo Rubalcaba, Dee Dee Briedgewater, Ute Lemper, Stancey Kent, Fred Cole, Stefon Harris, John Pizzarelli, Jane Monheit, Ted Nash, Regina Carter, Ray Lema, Richard Galliano, Philip Catarina, Rosa Passos, César Camargo Mariano, João Bosco, Guinga e muitos outros.</p>
<p class="font_8"><br></p>
<p class="font_8">Trabalhando há mais de vinte anos com a Brasil Jazz Sinfônica, Mauricio Galindo, apesar de ser um música de sólida formação erudita, acabou por especializar-se neste tipo de repertório.</p>
<p class="font_8"><br></p>
<p class="font_8">Durante sua carreira desenvolveu também as habilidades de comunicação com o público. Mantém dois programas de grande aufiência na Rádio Cultura FM de São Paulo, e destaca-se pelos concertos didáticos e comentados, inclusive para público infantil</p>', '<p class="font_8">Minha mãe conta que, desde que eu era um bebé, só dormia se ela colocasse um disco na “vitrola” – como era chamado, nos anos 60, o gira-discos. Assim, quando me dei por gente, já ouvia música.</p>
<p class="font_8"><br></p>
<p class="font_8">Na minha infância, estudei sempre em escola pública, onde cantávamos todos os dias.&nbsp;</p>
<p class="font_8">Isso era herança de um grande projeto de canto orfeônico que Heitor Villa-Lobos conheceu em França nos anos 20 e conseguiu implantar no Brasil logo no início dos anos 30. Essa foi o minha iniciação musical.</p>
<p class="font_8"><br></p>
<p class="font_8">Para mim era fascinante. Adorava chegar à escola e cantar. A gente cantava todos os dias três, quatro músicas do folclore brasileiro, que, aliás, tem muita coisa do folclore português.</p>
<p class="font_8"><br></p>
<p class="font_8">Tive de superar uma educação musical que, embora tenha começado cedo, nunca foi pensada para fazer de mim um músico profissional.</p>
<p class="font_8"><br></p>
<p class="font_8">Na adolescência interessei-me por música popular e fui estudar jazz. Comecei a ter aulas de guitarra neste contexto jazzístico, não de música clássica.</p>
<p class="font_8"><br></p>
<p class="font_8">As aulas de guitarra e jazz eram muito sérias. Tive sorte na escolha do professor, que era muito firme e dedicado. Para além do instrumento, me ensinou muitas coisas mais, como solfejo e harmonia.</p>
<p class="font_8"><br></p>
<p class="font_8">Um dia, quando eu já estava a tocar guitarra razoavelmente bem, um colega me disse que em São Paulo estavam começando um projeto semelhante ao “El Sistema”, da Venezuela [modelo didático musical, idealizado e criado na Venezuela por José Antonio Abreu]. Fui averiguar. Queria experimentar como era aprender um instrumento de orquestra, embora já fosse meio tarde para isso.</p>
<p class="font_8"><br></p>
<p class="font_8">Mas novamente pus-me sob a tutela de um professor de altíssimo nível. Com a boa base que tinha, desenvolvi-me rápido. Assim, em um ano eu já tocava na Orquestra Sinfônica Jovem da Cidade de São Paulo.</p>
<p class="font_8"><br></p>
<p class="font_8">Aos 18 anos ingressei no Curso de Bacharelato de Música na UNESP, Universidade Estadual Paulista. Queria ser compositor.</p>
<p class="font_8"><br></p>
<p class="font_8">Comecei a conviver com gente de altíssimo nível. Inclusive, tínhamos três professores franceses que vieram fundar o departamento de música da escola. Fui aluno do compositor Michel Philippot e do musicólogo francês Roger Cotte. Eram professores incríveis. Foi um salto de qualidade muito grande.</p>
<p class="font_8"><br></p>
<p class="font_8">Aos 24 anos ingressei na Orquestra Sinfônica do Estado de São Paulo. O regente era Eleazar de Carvalho, homem de métodos rigorosos, muito disciplinado, formado sob a tutela de Serguei Koussevitzky em Boston. Aprendi muito com ele.&nbsp;</p>
<p class="font_8"><br></p>
<p class="font_8">Informalmente, foi meu professor de direção de orquestra.</p>
<p class="font_8">Além de tocar na orquestra, dava aulas e comecei a reger uma orquestra de cordas de estudantes. Foi isso que acabou por me levar à regência, onde muitas oportunidades preciosas me foram oferecidas.</p>
<p class="font_8"><br></p>
<p class="font_8">Desisti da composição e aceitei – com muita satisfação - que o que o destino me colocara à frente era a profissão de maestro.</p>
<p class="font_8"><br></p>
<p class="font_8">É o que faço até hoje.</p>', '<p class="font_7"><strong>Maestro</strong></p>
<p class="font_8"><br></p>
<p class="font_8">João Maurício Galindo é Regente Emérito da <a href="https://www.youtube.com/c/BrasilJazzSinf%C3%B4nica"><strong>Orquestra Brasil Jazz Sinfônica</strong></a>, de São Paulo.</p>
<p class="font_8"><br></p>
<p class="font_8">Está associado a esta orquestra desde o ano 2000, tendo sido seu Diretor Artístico de 2005 a 2017.</p>
<p class="font_8"><br></p>
<p class="font_8">Com ela realizou apresentações memoráveis, muitas das quais acompanhando grandes nomes da música popular nacional e internacional, como Paquito de Rivera, Gustavo Rubalcaba, Dee Dee Bridgewater, Ute Lemper, Jane Monheit, Maria João Grancha, Richard Galliano, John Pizzarelli, Ivan Lins, Toquinho, Paulinho da Viola, João Bosco, Dominguinhos, Mônica Salmaso, entre muitos outros.</p>
<p class="font_8"><br></p>
<p class="font_8">Foi também regente da <strong>Orquestra Amazonas Filarmônica</strong>.</p>
<p class="font_8">Criada em 1896, a Amazonas Filarmônica é a orquestra estável do mítico <a href="https://pt.wikipedia.org/wiki/Teatro_Amazonas"><strong>Teatro Amazonas</strong></a>, localizado em Manaus, cidade encravada em meio à gigantesca floresta.</p>
<p class="font_8"><br></p>
<p class="font_8">Como convidado trabalhou com diversas orquestras no Brasil e no exterior.</p>
<p class="font_8"><br></p>
<p class="font_8">No Brasil dirigiu por diversas vezes a Petrobrás Sinfônica do Rio de Janeiro, a Sinfônica da Bahia, de Sergipe, do Paraná, de Campinas.</p>
<p class="font_8"><br></p>
<p class="font_8">No exterior esteve à frente da Sinfônica de Roma, Sinfônica Siciliana, Sinfônica de Bari, Sinfônica de Campobasso, Filarmônica de Belgrado, Orquestra Clássica do Centro de Portugal, Acadêmica de Ancara, Sinfônica de Liepaja, na Letônia, Orquestra Sinfônica Nacional de Havana e Orquestra Nacional da Venezuela, entre outras.</p>
<p class="font_8"><br></p>
<p class="font_7"><strong>Professor</strong></p>
<p class="font_8"><br></p>
<p class="font_8">Além do intenso trabalho como regente, dedica-se também a atividades pedagógicas.</p>
<p class="font_8"><br></p>
<p class="font_8">Trabalhou por mais de duas décadas com ensino de instrumentos de cordas com arco através de método coletivo, tendo criado diversas orquestras de cordas no Estado de São Paulo, Brasil.</p>
<p class="font_8"><br></p>
<p class="font_8">Esta experiência sedimentou-se em seu trabalho de pós graduação, realizado pela USP, Universidade de São Paulo, no ano 2000.</p>
<p class="font_8"><br></p>
<p class="font_8">É autor o método de ensino musical, nível Fundamental II, para a “<a href="https://www.sistemaetapa.com.br/"><strong>Rede Etapa de Ensino</strong></a>”, uma das mais importantes do Brasil.</p>
<p class="font_8"><br></p>
<p class="font_8">Foi co-criador e é o diretor musical da série de concertos didáticos infantis <a href="https://tucca.org.br/musica-pela-cura/aprendiz-de-maestro/"><strong>“O Aprendiz de Maestro"</strong></a>, realizada há 18 anos na Sala São Paulo.</p>
<p class="font_8"><br></p>
<p class="font_7">Rádio</p>
<p class="font_8"><br></p>
<p class="font_8">Desde 2005 Mauricio Galindo faz parte da equipa de comunicadores da Rádio Cultura de São Paulo, onde apresenta dois programas de grande audiência: <a href="https://podcasts.apple.com/br/podcast/pergunte-ao-maestro/id1487664874"><strong>“Pergunte ao Maestro”</strong></a>e <a href="https://cultura.uol.com.br/radio/programas/encontro-com-o-mastro/"><strong>“Encontro com o Maestro”</strong></a>.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2019, a convite da Rádio Antena 2 - RTP, criou e apresentou a série <a href="https://antena2.rtp.pt/em-antena/diversos-especiais/caleidoscopio-i-sabado-22h00-segunda-13h00-quarta-5h00-12/"><strong>“Mundo de Villa-Lobos”</strong></a>, com 13 programas radiofônicos.</p>
<p class="font_8"><br></p>
<p class="font_7"><strong>Livros</strong></p>
<p class="font_8"><br></p>
<p class="font_8">Tem dois livros publicados.</p>
<p class="font_8"><br></p>
<p class="font_8">- <a href="https://www.amazon.com.br/M%C3%BAsica-ouvir-Jo%C3%A3o-Maur%C3%ADcio-Galindo/dp/8506048389"><strong>“Música, Pare para ouvir”</strong></a>, Editora Melhoramentos, São Paulo, 2009.</p>
<p class="font_8">- <a href="https://www.editoracontexto.com.br/beethoven-as-muitas-faces-de-um-genio"><strong>“Beethoven as muitas faces de um gênio”</strong></a>, Editora Contexto,São Paulo, 2019.</p>
<p class="font_8"><br></p>
<p class="font_7"><strong>Condecoração</strong></p>
<p class="font_8"><br></p>
<p class="font_8">Em 2010, por sua atuação na primeira edição do “Ano da França no Brasil”, Maurício Galindo foi conderado pelo governo francês “<strong>Chevalier de l’Ordre des Arts et des Lettres”</strong></p>', '<p><span style="font-weight:bold"><span style="text-decoration:underline"><a href=https://cultura.uol.com.br/radio/programas/pergunte-ao-maestro/ target=undefined>Pergunte ao Maestro</a></span></span>: O maestro João Maurício Galindo responde às perguntas enviadas pelos ouvintes da emissora de maneira clara e objetiva a respeito do mundo da música de concerto.Segunda a sábado, 10h.Segunda a sexta, 15h.</p><p>Apresentador: João Maurício Galindo</p><p>Produção: Felipe Misale</p><p>Ouça em: <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://cultura.uol.com.br/radio/programas/pergunte-ao-maestro/ target=_blank>Radio Cultura</a></span></span></span>, <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://open.spotify.com/show/32WOHn2soeILMNmVqdD143 target=_blank>Spotify</a></span></span></span> e <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.deezer.com/br/show/2237822 target=_blank>Deezer</a></span></span></span>.</p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://cultura.uol.com.br/radio/programas/encontro-com-o-mastro/ target=_blank>Encontro com Maestro</a></span></span></span>: apresentado pelo maestro João Maurício Galindo, vai ao ar todas as segundas-feiras, às 23h, e aos domingos, às 10h, na <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=http://culturafm.cmais.com.br/ target=_blank>Rádio Cultura FM</a></span></span></span> 103,3 MHz, São Paulo, e no aplicativo Cultura no <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://play.google.com/store/apps/details?id=com.tvcoins.prod.culturaplay target=_blank>Google Play</a></span></span></span> e <span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://apps.apple.com/br/app/cultura-play/id6443740652 target=_blank>App Store</a></span></span></span>.</p><p> </p><p><span style="font-weight:bold"><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://amzn.to/3Sjz1Bc target=_blank>Beethoven: as muitas faces de um gênio</a></span></span></span>: Beethoven está mais vivo do que nunca. Suas composições são executadas em orquestras ao redor do mundo e sua popularidade ultrapassa os limites dos apreciadores da música clássica: as quatro notas que abrem sua Quinta Sinfonia são conhecidas por todos e a melodia de Pour Elise tornou-se até símbolo da presença do caminhão de gás. Popular, mas nunca banal: Beethoven é reconhecidamente um gênio. Para celebrá-lo à altura, este livro reúne dois autores: um maestro brasileiro contemporâneo, João Maurício Galindo, e um romancista francês do início do século XX, Romain Roland. Ambos nos situam Beethoven em seu tempo, em sua família, na sua relação com outros músicos, com mecenas, com o público, até com mulheres. Mostram suas idiossincrasias, fraquezas e nos apresentam, enfim, um Beethoven com muitas facetas, desde um ser mitificado, endeusado, até um ser humano – de enormes dimensões, sem dúvida, mas um ser humano como qualquer um de nós.</p>', 'https://static.wixstatic.com/media/7b859e_7b6f754c80a2469ba3f8db6f3a9a3d85~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_d1c8173673c6414489487bdf4e333639~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_95ddd67315a14703802408560163b7ba~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_8d97f58443504ed7a931ce4f69ed97d0~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_d1deab593a5949aabfac8c6c296fe41b~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_7a1546a4f4b04684a31eaa7b76594adc~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_c353b8b8da054b6f92f6be49b3816964~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_8cab8248aeb14dc0a00a53d5a465a647~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_dc3b62cb1e544e5989dc2cd247334521~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_a809371883914c5d8a114a67e24a58de~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_0a751dc98d7f47e3a62748db89d9631a~mv2.jpg', NULL, 'https://static.wixstatic.com/media/f47b72_d522cbf2dea446f98d43635365f990af~mv2.jpg', NULL, 1, 0, 0);

-- Row 92: Beatriz Pereira
INSERT IGNORE INTO users (id, email, password, role) VALUES ('d919c8d3-b0f6-4af9-97a2-0cee33e620f8', 'wix-d919c8d3@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('c08fefa1-d66b-48a1-bb68-9ae5348ef0b4', 'd919c8d3-b0f6-4af9-97a2-0cee33e620f8', 'Beatriz Pereira', 'Beatriz Pereira', 'Beatriz', '''+351927312084', '2000-08-16', 'Portugal', 'Portugal', 'Faro, São Brás de Alportel', 'Sitio do Peral, CX 745B', 'Sitio do Peral, CX 745B', '8150-052', 'Fadista', 'Cantar é a forma mais natural de exprimir aquilo que a nossa alma não consegue dizer a falar.', 'https://static.wixstatic.com/media/d919c8_cde7438f4f154fab84b9c09b32ac6a13~mv2.jpg', NULL, 'https://www.facebook.com/profile.php?id=100064223623750', 'https://www.facebook.com/profile.php?id=100064223623750', NULL, 'https://open.spotify.com/intl-pt/album/0Ne6Tn2lAlCYFE9MUD6KgG?si=JW_KXUDHQVazdQvc55hhLA&nd=1&dlsi=ec5f21666318459c', 'https://music.youtube.com/playlist?list=OLAK5uy_mTmHTB8cZkdctksQurwfwh1TGffYbsCvs', 'https://static.wixstatic.com/mp3/d919c8_9f3845aa5d01426c98f68729a30de14f.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=U0dkIKqsO_s', 'https://www.youtube.com/watch?v=Ld48AU89ZUA', 'https://www.youtube.com/watch?v=RKpVWKbRaTg', 'https://www.youtube.com/watch?v=8s15vlLsrRU', NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8">&nbsp;Beatriz Pereira é uma talentosa fadista, com uma voz marcante e uma presença cativante.</p>
<p class="font_8">Um dos objetivos de Beatriz é o de aperfeiçoar a sua técnica sempre que possível, aproveitando todas as oportunidades para frequentar masterclasses ou workshops. Beatriz já frequentou aulas de canto com professores como Stefan Holmström, Francisco Brazão, Daniela Rodrigues ou António Cruz.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">A flexibilidade da sua voz trazem ao espetaculo uma incrivel dinâmica e satisfação por parte do público, que se sente integrado dentro do espetaculo e capaz de sentir aquilo que a fadista lhes transmite. Beatriz defende que o mais bonito do fado é a capacidade de fazer sentir a quem não fala a nossa língua aquilo que estamos a cantar, quando se canta com sentimento não é necessário compreender o que se diz.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Tem se destacado no meio algarvio contando com diversos espetaculos e ainda a gravação do seu primeiro trabalho discográfico que apresentou em Março de 2024, " O Fado de Ser Fadista".</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">&nbsp;</p>', NULL, NULL, NULL, 'https://static.wixstatic.com/media/d919c8_46fbeb5d13da4661af8d8b07815effef~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d919c8_33e47020daaf4837b041a0bbd942e81a~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d919c8_8f593247835244c6aa191b5792c45353~mv2.jpg', NULL, 'https://static.wixstatic.com/media/d919c8_8f0f83887d254a6bb9fa7aee9c5b25a8~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 93: Miguel Costa
INSERT IGNORE INTO users (id, email, password, role) VALUES ('428be572-5bad-4d6b-aa06-f7c01044b569', 'wix-428be572@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('83654461-f3a3-4e3b-a1da-ddcf10c6b157', '428be572-5bad-4d6b-aa06-f7c01044b569', 'miguel-costa', 'Miguel Costa', 'Miguel', '''+351 961200383', '2024-09-24', 'Portugal', 'Portugal', 'Quinta do Conde', 'Avenida dos Aliados 2005 lote B', 'Avenida dos Aliados 2005 lote B', '2975-310', 'Clarinetista/Professor', 'Com uma abordagem à música invulgarmente completa, Miguel Costa é um dos clarinetistas mais versáteis da sua geração.', 'https://static.wixstatic.com/media/428be5_b72243c778a6411ca4f08abd500a9de4~mv2.jpg', 'wix:document://v1/428be5_e587d774e8744fe0bbf825176564c1fe.docx/bio%20mc.docx', 'https://www.facebook.com/mcclarinete', 'https://www.instagram.com/miguel.costa_clarinet/', 'https://www.miguelcostaclarinete.pt/', 'https://open.spotify.com/user/mcclarinete', 'https://www.youtube.com/@miguelcostaclarinete', NULL, NULL, NULL, 'https://www.youtube.com/watch?v=TJL1OT02h10', 'https://www.youtube.com/watch?v=vQeoZB0tzeU', 'https://www.youtube.com/watch?v=f2sxiYrZrgs', 'https://www.youtube.com/watch?v=icDDHUfruwI&t=53s', 'https://www.youtube.com/watch?v=L5y2nwAiO-A', 'https://www.youtube.com/watch?v=1TYR5GyLPP0', 'https://www.youtube.com/watch?v=pO7AI_-assI', 'https://www.youtube.com/watch?v=_9RMOD_0r8I', 'https://www.youtube.com/watch?v=_rfTBO4wWko', 'https://www.youtube.com/watch?v=8nGriQ3tkEE', '<p class="font_8">Miguel Costa, um clarinetista de exceção, cuja paixão e dedicação ao instrumento o elevaram ao patamar dos mais prestigiados músicos da sua geração.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Com uma técnica irrepreensível e uma sensibilidade artística fora do comum, consegue extrair do clarinete uma riqueza sonora e uma expressividade que capturam a essência de cada peça que interpreta. A capacidade de transcender as notas escritas e transmitir emoções profundas faz dele um intérprete ímpar, cujo talento conquista o público e a crítica em cada atuação.</p>
<p class="font_8"><br></p>
<p class="font_8">Miguel Costa destaca-se, também, pela sua incansável busca pela perfeição, refletida em cada frase musical, em cada nuance, onde a clareza e a precisão se aliam a uma interpretação profundamente pessoal.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Como professor, a sua dedicação à formação de novos talentos é igualmente notável. É um educador comprometido, que partilha o seu vasto conhecimento com generosidade, inspirando as novas gerações a seguir o seu exemplo de excelência e paixão pela música.</p>
<p class="font_8">&nbsp;</p>', '<p class="font_8"><strong>FORMAÇÃO</strong></p>
<p class="font_8"><br></p>
<p class="font_8">● 2017, Mestrado em ensino da música, especialização (clarinete) na Escola Superior de Música de Lisboa, orientador Professor Doutor Paulo Gaspar.</p>
<p class="font_8">● 2006-2012, Licenciatura em instrumentista de orquestra – modalidade de clarinete na Academia Nacional Superior de Orquestra, classe dos Professores Nuno Silva e Etienne Lamaison.</p>
<p class="font_8">● 2000-2006, Curso Profissional de Instrumento, Escola Profissional de Artes da Beira Interior – EPABI – modalidade de clarinete na dos Professores Luís Gomes e Nuno Gonçalves;</p>
<p class="font_8">● 1998 – 2000, 2ºgrau Academia de música Luisa Todi na classe do Professor Francisco Pinto</p>
<p class="font_8">● 1994 – 1998 Iniciou os estudos musicais na Escola de Música da Sociedade Filarmónica Timbre Seixalense, na classe do Professor António Menino.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>MASTERCLASSES/WORKSHOPS&nbsp;</strong></p>
<p class="font_8"><br></p>
<p class="font_8">● <em>2010, 13º Encontro Internacional de clarinetes de Lisboa – Cultivarte – sob a orientação Hakan Rosengren;</em></p>
<p class="font_8">● 2009, <em>12º Encontro Internacional de clarinetes de Lisboa – Cultivarte – sob a orientação Guy Deplus e Michel Portal;</em></p>
<p class="font_8">● 2008, <em>11º Encontro Internacional de clarinetes de Lisboa – Cultivarte – sob a orientação Radovan Cavallin e Pascual Martinez;</em></p>
<p class="font_8">● 2007, <em>10º Encontro Internacional de clarinetes de Lisboa – Cultivarte – sob a orientação Jonhatan Cohler e Ronald Van Spaendonck;</em></p>
<p class="font_8">● <em>2006, 9º Encontro Internacional de clarinetes de Lisboa – Cultivarte</em></p>
<p class="font_8">● <em>2005, Masterclass de clarinete orientada pelo Professor Nuno Antunes – EPABI;</em></p>
<p class="font_8">● 2005, <em>8º Encontro Internacional de clarinetes de Lisboa – Cultivarte – sob a orientação Philippe Cuper, Jonathan Cohler e Carlos Garcia;</em></p>
<p class="font_8">● <em>2004</em>, <em>7º Encontro Internacional de clarinetes de Lisboa – Cultivarte – sob a orientação de Yehuda Gilad, Frabizio Meloni e Venancio Rius Marti;</em></p>
<p class="font_8">● <em>2003, workshop clarinete com Quarteto de clarinetes de Lisboa, IV ciclo internacional de música de Torres Novas;</em></p>
<p class="font_8">● <em>2003, Masterclass de clarinete do Professor Antony Pay – Cultivarte;</em></p>
<p class="font_8">● <em>2003, 6º Encontro Internacional de clarinetes de Lisboa – Cultivarte – sob a orientação de Joaquim Ribeiro, Luís Gomes, Nuno Silva e Rui Martins;</em></p>', '<p class="font_8">Com uma abordagem à música invulgarmente completa, na forma como relaciona os aspetos estilísticos, Miguel Costa é um clarinetista português de destaque no panorama da música erudita em Portugal e um dos músicos mais versáteis da sua geração. Apresentou-se nas maiores salas do país em festivais, concertos de orquestra, a solo, teatro musical, projetos pedagógicos e sociais.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>PRÉMIOS</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">2014, 2º prémio concurso internacional “Terras de La Salette”, Oliveira de</p>
<p class="font_8">Azeméis;</p>
