INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('2fbc0f09-266f-4c16-9ea7-ae5c6ea0c8fb', 'b9be4018-833d-4f22-afe2-d1647cfe4c35', 'luis-macedo', 'Luís Macedo', 'Luís Miguel', '911009875', '1994-07-17', 'Portugal', 'Portugal', 'Porto', 'Rua da Boavista 252', NULL, '4515-484', 'Multi-instrumentista', NULL, 'https://static.wixstatic.com/media/7b859e_fada4c64feee4436943613e5d1a389e7~mv2.jpg', 'wix:document://v1/b9be40_5cb0e995a0664f388eb74abe65ba931c.pdf/Biografia%20PT.pdf', 'https://www.facebook.com/luismiguel.macedo/', 'https://www.instagram.com/luismiguelmacedo/', 'https://seelectronics.com/artists/luis-macedo/', 'https://open.spotify.com/intl-pt/artist/2FfBF6ZV7vU9DErTRjElW8?si=yMyCDlwDQ8mIl9ZCFD1dyw', 'https://www.youtube.com/@Luismacedomusic', 'https://static.wixstatic.com/mp3/b9be40_fa57782d884f4bd08b2e5c6c0fbba15f.mp3', NULL, NULL, 'https://www.youtube.com/watch?v=kN4CKNDKqdc', 'https://www.youtube.com/watch?v=c5MBhgIBRI8&t=6s', 'https://www.youtube.com/watch?v=D19EkioivPU', 'https://www.youtube.com/watch?v=LnjwoMhdBLY&t=8s', NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8">Luis Macedo é um conceituado trompetista e percussionista profissional português, que tem vindo a construir uma sólida carreira no panorama do jazz nacional e internacional. É conhecido por ser um versátil percussionista e baterista de estúdio, bem como o trompetista principal da renomada Orquestra de Jazz de Matosinhos (OJM). Colaborou também com o Remix Ensemble, Lisbon Film Orchestra, Orquestra Sinfónica do Porto - Casa da Música, hR BigBand (Frankfurt Radio) e Andrew Rathbun Large Ensemble e outros</p>
<p class="font_8"><br></p>
<p class="font_8">Ao longo da sua carreira, tem-se apresentado, gravado e colaborado com músicos e orquestras de renome mundial, como Richard Bona, Perico Sambeat, Andrew Rathbun Large Ensemble, Rebecca Martin, Larry Grenadier e a HR Bigband da Rádio de Frankfurt, além de ter trabalhado com a Meinl Ibérica, entre outros.</p>
<p class="font_8"><br></p>
<p class="font_8">Para além da sua notável carreira no jazz, Luis Macedo é também um requisitado percussionista e baterista de estúdio, tendo gravado e colaborado com várias bandas, orquestras e projetos. O seu talento e profissionalismo têm sido reconhecidos por marcas de referência na indústria musical, sendo atualmente um Artista Oficial da Yamaha Music Global, sE Electronics e Denis Wick Products.</p>
<p class="font_8"><br></p>
<p class="font_8">Com uma sólida formação musical, uma técnica apurada e uma abordagem criativa e versátil, Luis Miguel Macedo tem vindo a deixar a sua marca no panorama musical português e internacional, afirmando-se como um músico de excelência e um nome a reter no mundo do jazz e da música improvisada.</p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>', '<p class="font_8">Luis Miguel Macedo nasceu a 17 de julho de 1994, no Porto, no seio de uma família com uma forte tradição musical. É neto do conceituado trompetista, Maestro e Professor José Macedo, e filho do Maestro, percussionista e compositor Luis Fernando Costa Macedo. Desde cedo, Luis cresceu rodeado de música e influências que viriam a moldar o seu percurso artístico.</p>
<p class="font_8"><br></p>
<p class="font_8">Iniciou os seus estudos musicais com o professor José Fernando e, em 2004, ingressou no Conservatório de Música do Porto, tendo como primeiro professor de trompete Francisco Silva. Desde 2005, estudou com o renomado professor Manuel Luis Azevedo, que se tornou uma figura fundamental na sua formação musical.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2010, Luis participou na masterclass do prestigiado professor Pierre Dutot, uma experiência que contribuiu para o seu desenvolvimento técnico e artístico. Nesse mesmo ano, integrou a Orquestra de Jazz do Conservatório de Música do Porto, com a qual atuou em locais como o Centro Cultural de Belém, o Casino de Espinho e no programa da RTP "Verão Total". Com esta orquestra, Luis teve também a oportunidade de gravar para a Antena 2, um marco importante no início da sua carreira.</p>
<p class="font_8"><br></p>
<p class="font_8">A versatilidade de Luis ficou evidente desde cedo, tendo-se apresentado como baterista com a BigBand La Belle Époque, com a qual gravou um CD. Participou também na Orquestra da Praça da Alegria, em dois programas especiais: "Gala Final Dança na Praça".</p>
<p class="font_8"><br></p>
<p class="font_8">Esteve no estágio da Academia de Espinho, onde foi 1º trompete da Orquestra de Sopros, dirigida pelo Maestro Fernando Marinho, e da Orquestra Sinfónica, sob a direção do Maestro Roberto Valdês. Foi ainda trompetista na Banda Musical de Melres e professor de trompete na Academia da mesma.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2012, Luis ingressou na Escola Superior de Música e Artes do Espetáculo (ESMAE), na vertente de trompete jazz, dando continuidade à sua formação académica. Durante este período, foi lead trumpet da Orquestra de Jazz do Conservatório de Música do Porto e da ESMAE BigBand, destacando-se pela sua liderança e técnica.</p>', '<p class="font_8">Após a sua formação académica, Luis Miguel Macedo continuou a desenvolver a sua carreira musical, participando em diversos projetos e colaborando com artistas de renome nacional e internacional. Em 2017, foi nomeado lead trumpet da BigBand das Escolas Superiores Nacionais no Festival S. Luiz em Lisboa, um reconhecimento do seu talento e liderança no meio académico e musical.</p>
<p class="font_8"><br></p>
<p class="font_8">Luis tem sido uma presença constante no prestigiado Festival Guimarães Jazz, tendo sido convidado, em 2019, para lead trumpet do ensemble do compositor e saxofonista canadiano Andrew Rathbun, para a apresentação da sua obra "Atwood Suite". Esta colaboração evidencia o reconhecimento internacional do talento de Luis e a sua capacidade de integrar projetos de elevado nível artístico.</p>
<p class="font_8"><br></p>
<p class="font_8">Ao longo da sua carreira, Luis tem participado em numerosos festivais de jazz e música, como o MUSA Cascais, Festival Porta-Jazz, European Jazz Conference, EDP Live Bands, MEO Marés Vivas, Festival do Crato e Caldas Nice Jazz, entre outros. Nestes eventos, teve a oportunidade de partilhar o palco com figuras proeminentes do jazz internacional, como Seamus Blake, Nils Wogram, Andrew Rathbun, Dana Hall, John O''Gallagher, Peter Evans, Dave Douglas, Tim Hagans, Clark Sommers, Scott Cowan e Aubrey Johnson, bem como com artistas nacionais de referência, como Maria João, Kurt Rosenwinkel, Kiko Freitas, Lluc Casares, Mário Costa e Julian Argüelles.</p>
<p class="font_8"><br></p>
<p class="font_8">Para além do jazz, Luis tem colaborado com diversos artistas portugueses de diferentes géneros musicais, como Tiago Nacarato, César Mourão, Lisbon Film Orchestra e Rádio Comercial, demonstrando a sua versatilidade e capacidade de adaptação a diferentes estilos e contextos.</p>
<p class="font_8"><br></p>
<p class="font_8">Ao longo da sua carreira, Luis tem participado em várias gravações, tanto ao serviço da Orquestra Jazz de Matosinhos, como com outros projetos, deixando assim um legado discográfico significativo.</p>
<p class="font_8"><br></p>
<p class="font_8">Atualmente, Luis Miguel Macedo é considerado uma referência nacional como lead trumpet, tendo sido convidado, em novembro de 2021, para atuar com a prestigiada orquestra de jazz da Rádio de Frankfurt - hr-Bigband, ao lado de Melissa Aldana e Jim McNeely. É também o lead trumpet da conceituada Orquestra Jazz de Matosinhos.</p>
<p class="font_8"><br></p>
<p class="font_8">O seu talento e profissionalismo têm sido reconhecidos por marcas de referência na indústria musical, sendo atualmente artista oficial da sE Electronics, Yamaha Music Global e Denis Wick Products, além de colaborar com outras marcas como Meinl Ibérica e Faina Drums.</p>', '<p class="font_8"><a href="https://pt.yamaha.com/pt/artists/l/LuisMiguelMacedo.html" target="undefined"><u>Yamaha Music Global</u></a></p>
<p class="font_8"><a href="https://seelectronics.com/artists/luis-macedo/" target="undefined"><u>sE Electronics</u></a></p>
<p class="font_8"><a href="https://www.deniswick.com/artist/luis-macedo/" target="undefined"><u>Denis Wick Products</u></a></p>
<p class="font_8"><a href="https://www.instagram.com/luismiguelmacedo/" target="undefined"><u>Instagram</u></a></p>
<p class="font_8"><br></p>
<p class="font_8"><br></p>
<h6 class="font_6"><u>Entrevistas e notícias:</u></h6>
<h6 class="font_6"><br></h6>
<p class="font_8"><a href="https://www.smartx.art/post/lu%C3%ADs-miguel-macedo-um-m%C3%BAsico-multifacetado-em-busca-da-excel%C3%AAncia"><u>Entrevista SMARTx (2024)</u></a> - Luis Miguel Macedo: um músico multifacetado em busca da excelência</p>
<p class="font_8"><a href="https://www.vivacidade.org/edicao/jornal_vivacidade_ed180_jun2021"><u>VivaCidade (junho de 2021)</u></a> – Luis Macedo, o trompetista que, como o seu</p>
<p class="font_8">avô, está a conquistar o carinho internacional</p>
<p class="font_8"><a href="https://ijm.education/winds/brass/trumpet/luis-macedo-interview/"><u>International Journal of Music (2021)</u></a> – Luis Macedo – Transitioning from</p>
<p class="font_8">Classical Trumpeter to Lead of One of Europe’s Premier Big Bands</p>
<p class="font_8"><a href="https://pt.yamaha.com/pt/news_events/2021/20210503_2asMaiores_com_LuisMiguel_Macedo.html"><u>Yamaha Music Waves</u></a> – 2as Maiores – À conversa com Luis Miguel</p>
<p class="font_8">Macedo</p>', 'https://static.wixstatic.com/media/b9be40_a814d6961cd740888d8947add81c81c1~mv2.jpg', NULL, 'https://static.wixstatic.com/media/b9be40_4c23f0b28c8944d4bede4cd8fd46e5e6~mv2.jpg', NULL, 'https://static.wixstatic.com/media/b9be40_4781147c1dab43e8a3e2a3258cb25398~mv2.jpg', NULL, 'https://static.wixstatic.com/media/b9be40_ffd6be2d6b6a48419eceefb1e61358ff~mv2.jpg', NULL, 'https://static.wixstatic.com/media/b9be40_e63be035b5b34c90b51511620dfd28d6~mv2.jpg', NULL, 'https://static.wixstatic.com/media/b9be40_2b380e5b9f8144f5932daac1bb7e09a5~mv2.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0);

-- Row 95: Rita Marques
INSERT IGNORE INTO users (id, email, password, role) VALUES ('d6cc3b9e-72a9-458d-a80f-bf0d0a5d6178', 'wix-d6cc3b9e@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('8779b166-69e5-445d-bb04-28f2cce47935', 'd6cc3b9e-72a9-458d-a80f-bf0d0a5d6178', 'rita-marques', 'Rita Marques', 'Rita', '966431812', '1990-07-16', 'Portugal', 'Portugal', 'Caldas da Rainha', 'Rua Henrique Sales, 28 - 2º esq', NULL, '2500-213-Caldas da Rainha', 'Soprano', '"Não me lembro de mim sem cantar. Faz parte de quem eu sou."', 'https://static.wixstatic.com/media/d6cc3b_02dd1ff5237e4c66aaf11e3784826051~mv2.jpg', 'wix:document://v1/d6cc3b_0d1b71c5952d48e08972a79316b9e83f.pdf/Rita%20Marques%20-%20BIO%20SMART.pdf', NULL, NULL, NULL, NULL, 'http://www.youtube.com/@ritamarques-soprano6263', NULL, NULL, NULL, 'https://www.youtube.com/watch?v=TP_xPZwrJU4&embeds_referring_euri=https%3A%2F%2Fnovaproartart.wixstudio.io%2F&embeds_referring_origin=https%3A%2F%2Fnovaproartart.wixstudio.io', 'https://www.youtube.com/watch?v=JpmDjAxWcvI&embeds_referring_euri=https%3A%2F%2Fnovaproartart.wixstudio.io%2F&embeds_referring_origin=https%3A%2F%2Fnovaproartart.wixstudio.io', 'https://www.youtube.com/watch?v=elfxK-C1Egw&embeds_referring_euri=https%3A%2F%2Fnovaproartart.wixstudio.io%2F&embeds_referring_origin=https%3A%2F%2Fnovaproartart.wixstudio.io', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '<p class="font_8">Rita Marques é uma soprano portuguesa que tem vindo a conquistar o seu lugar no mundo da ópera, destacando-se pela sua <strong>voz poderosa</strong> e <strong>versátil</strong>, capaz de <strong>brilhar em papéis de enorme exigência técnica e expressiva</strong>. A clareza cristalina, expressividade impressionante e exímia técnica vocal são características marcantes do seu talento.</p>
<p class="font_8"><br></p>
<p class="font_8">Com <strong>interpretações discretas e controladas</strong>, mas simultaneamente <strong>vigorosas e cativantes</strong>, Rita tem a capacidade ímpar de transmitir emoções profundas e dar vida, cor e verdade cénica às personagens que interpreta.</p>
<p class="font_8"><br></p>
<p class="font_8">Em 2024, lançou o seu primeiro álbum intitulado "<strong>Belcanto</strong>", que vem confirmar o talento desta soprano que tem vindo a ganhar cada vez mais destaque no mundo operático.</p>
<p class="font_8"><br></p>
<p class="font_8"><em>"Todos os papéis que fiz até agora foram importantes para eu ser quem sou hoje como artista e, atrevo-me a dizer, como pessoa." Rita Marques</em></p>
<p class="font_8">&nbsp;</p>', '<h3>Nascida nas Caldas da Rainha, a paixão de Rita Marques pelo canto surgiu na infância, com a participação em coros e grupos folclóricos. Aos 14 anos descobriu seu amor pela ópera quando fez <span style="font-weight:bold">figuração no Festival de Ópera de Óbidos</span>. Posteriormente, concluiu a licenciatura em <span style="font-weight:bold">Canto na Escola Superior de Música de Lisboa na classe da professora Sílvia Mateus</span>.</h3><h3> </h3><h3>Foi <span style="font-weight:bold">bolseira da Fundação Calouste Gulbenkian/ENOA - European Network of Opera Academies</span> e frequentou o prestigiado <span style="font-weight:bold">Centre de Perfeccionament Plácido Domingo</span>.</h3><h3> </h3><h3>Em maio de 2017 <span style="font-weight:bold">colaborou com Plácido Domingo no seu concerto na MEO Arena</span>, em Lisboa, com direção musical de Eugene Kohn.</h3><h3> </h3><h3>Ao longo da sua carreira, Rita Marques tem dado vida a personagens icónicas do repertório operático, demonstrando a sua versatilidade e talento interpretativo. Alguns dos seus papéis mais marcantes incluem: </h3><ul><li>Rainha da Noite em &quot;Die Zauberflöte&quot; de Mozart (estreia numa grande produção de ópera em Mechelen, Bélgica, 2016); </li><li>Lakmé em &quot;Lakmé&quot; (Valladolid, Espanha, 2020); </li><li>Adina em &quot;L&#x27;elisir d&#x27;amore&quot; (primeiro papel principal no Teatro Nacional de São Carlos, 2022); e </li><li>Lucia em &quot;Lucia di Lammermoor&quot; (Teatro Nacional de São Carlos, Lisboa, 2023).</li></ul><p> </p><h3>&quot;<span style="font-style:italic">O mais importante é cantar bem. Isso inclui respeitar o compositor, a partitura, a técnica, o texto, a personagem, comer bem, descansar bem, exercitar o corpo, manter o equilíbrio mental.</span>&quot; Rita Marques</h3>', '<p>A carreira de Rita Marques é um testemunho da sua dedicação, paixão e talento extraordinário. Com cada performance, ela cativa o público e consolida o seu lugar como uma das mais brilhantes estrelas da ópera portuguesa e internacional.</p><p> </p><h3><span style="font-weight:bold">PRÉMIOS</span></h3><h3> </h3><h3>Venceu o 2º Prémio e Prémio do Público no Concurso de Canto da Fundação Rotária Portuguesa.</h3><ul><li>Recebeu a Medalha Municipal de Caldas da Rainha.</li><li>Foi finalista do Operalia – The World’s Opera Competition.</li></ul><h3> </h3><h3><span style="font-weight:bold">FORMAÇÃO COMPLEMENTAR</span></h3><p> </p><p>Como bolseira da Fundação Calouse Gulbenkian/ENOA – European Network of Opera Academies, frequentou workshops com Claudio Desderi (FCG, Lisboa, Out/2014, Jun/2015, Out/2015), June Anderson e Cecilia Gasdia (Verona, Set/2015) e o workshop “Wiener Operette” na Bayrische Theaterakademie (Munique, Out/2015).</p><p>No ano 2016/2017, frequentou o Centre de Perfeccionament Plácido Domingo, em Valência, onde trabalhou com os maestros Ramón Tebar, Fabio Biondi e Roberto Abbado e com os pianistas Aida Bousselma, Stanislav Angelov e Jose Ramón Martin. Em Workshop, trabalhou com Nacho Fresneda (teatro), Sonia Prina (interpretação), Davide Livermore (interpretação de Monteverdi), e Roger Vignoles (interpretação de “Myrthen” de R. Schumann). Trabalhou ainda com Manuela Custer e Enedina Lloris como preparadoras vocais. Como aluna do CPPD, foi Governess em “The turn of the Screw”, de B. Britten (direcção musical de Christopher Franklin e encenação de Davide Livermore, Jun/2017, Teatre Martín i Soler, Valência) e Roggiero em “Tancredi” de R. Rossini (Direcção musical de Roberto Abbado e encenação de Emilio Sagi, Jun/2017, Palau de Les Arts Reina Sofía, Valência).</p><p> </p><h3><span style="font-weight:bold">LINHA DO TEMPO</span></h3><p> </p><p><span style="font-weight:bold">2010-2013</span> - Concluiu a licenciatura em Canto na Escola Superior de Música de Lisboa, na classe da professora Sílvia Mateus.</p><p><span style="font-weight:bold">2012 </span>- Interpretou o papel de Rainha da Noite em &quot;Die Zauberflöte&quot; de W.A. Mozart.</p><p><span style="font-weight:bold">2014-2015</span> - Como bolseira da Fundação Calouste Gulbenkian/ENOA, frequentou workshops com Claudio Desderi em Lisboa, June Anderson e Cecilia Gasdia em Verona, e o &quot;Wiener Operette Workshop&quot; na Bayrische Theaterakademie em Munique.</p><p>2016 - Interpretou Donna Mercedes em &quot;Colombo&quot; de Gomes no Theatro Municipal de São Paulo.</p><p><span style="font-weight:bold">2016-2017</span> - Frequentou o Centre de Perfeccionament Plácido Domingo em Valência, trabalhando com maestros, pianistas e encenadores; interpretou Governess em &quot;The Turn of the Screw&quot; e Roggiero em &quot;Tancredi&quot;.</p><p><span style="font-weight:bold">2017 </span>- Colaborou com Plácido Domingo em concerto na MEO Arena em Lisboa, interpretou Irmã Alice em &quot;Dialogues des Carmélites&quot; no Teatro Nacional de São Carlos, Baucis em &quot;Philemon und Baucis&quot; no Palau de les Arts Reina Sofia.</p><p><span style="font-weight:bold">2019 </span>- Estreia da obra &quot;El Mar y las Campanas&quot; de Nelson Jesus em recital.</p><p><span style="font-weight:bold">2020 </span>- Interpretou Anna Kennedy em &quot;Maria Stuarda&quot;, Lakmé em &quot;Lakmé&quot;, Fiordiligi em &quot;Così fan tutte&quot;.</p><p><span style="font-weight:bold">2022 </span>- Adina em &quot;L&#x27;elisir d&#x27;amore&quot; no Teatro Nacional de São Carlos, solista em &quot;Symphony No. 2&quot; de Mendelssohn e &quot;Concerto de Primavera&quot;, participou da Gala de Ópera no Teatro Nacional de São Carlos.</p><p><span style="font-weight:bold">2023 </span>- Fez Adele em &quot;Die Fledermaus&quot; no Teatro Nacional de São Carlos, Donna Anna em &quot;Don Giovanni&quot; no Festival de Óbidos, Madama Cortese em &quot;Il viaggio a Reims&quot; e Lucia em &quot;Lucia di Lammermoor&quot; no Teatro Nacional de São Carlos.</p>', '<h3><span style="font-weight:bold">DISCOGRAFIA</span></h3><p> </p><p><span style="text-decoration:underline"><a href=https://eds.b.ebscohost.com/eds/search/advanced?vid=4&sid=4b839489-ba2c-4350-80fd-3d2b50574a5b%40pdc-v-sessmgr03 target=undefined>Belcanto </a></span>(2024)</p><p> </p><h3><span style="font-weight:bold">NOTÍCIAS e ENTREVISTAS</span></h3><p> </p><p><span style="text-decoration:underline"><span style="text-decoration:underline"><a href=https://www.proart.art/not%C3%ADcias/proart-entrevista-rita-marques-uma-soprano-em-ascens%C3%A3o target=_blank>PorART Entrevista</a></span></span>: Rita Marques - Uma soprano em ascensão</p><p> </p><h3>Quer saber mais?</h3><h3>Entre em contacto connosco!</h3>', 'https://static.wixstatic.com/media/d6cc3b_6fa0c5e9b429413f943d6b5fbda7cd5b~mv2.jpg', 'Falstaff - Nannetta - Teatro Nacional de São Carlos - Maio 2024 - Créditos: António Pedro Ferreira/TNSC', 'https://static.wixstatic.com/media/d6cc3b_9dc84cff6467491690e90fe859b9c8e6~mv2.jpg', 'BELCANTO - Lançamento - Releasing at Teatro Armando Cortez - Lisbon May 2024 - Créditos: Sónia Godinho', 'https://static.wixstatic.com/media/d6cc3b_ce363073f03848a692164d42fc5bac68~mv2.jpg', 'créditos: Sónia Godinho', NULL, NULL, 'https://static.wixstatic.com/media/d6cc3b_b110568cbfeb4fc0a0281a34329e00a0~mv2.jpg', 'créditos: Sónia Godinho', NULL, NULL, 'https://static.wixstatic.com/media/d6cc3b_b6e48758a5e7484d85c52a7eaf660ddd~mv2.jpg', 'créditos: Sónia Godinho', NULL, NULL, 'https://static.wixstatic.com/media/d6cc3b_fb16664c853744e89d15ccdeb8acac24~mv2.jpg', 'Lucia di Lammermoor - Teatro Nacional de São Carlos - Março 2023 - Créditos: António Pedro Ferreira/TNSC', NULL, NULL, 'https://static.wixstatic.com/media/d6cc3b_6196549a83484f14b588c1b7bf2645c3~mv2.jpg', 'Lucia di Lammermoor - Teatro Nacional de São Carlos - Março 2023 - Créditos: António Pedro Ferreira/TNSC', NULL, NULL, 1, 0, 0);

-- Row 96: Tessitori
INSERT IGNORE INTO users (id, email, password, role) VALUES ('27573b20-c33f-4178-b8f0-f701f9f32054', 'wix-27573b20@smartx.placeholder', '$2a$04$placeholder_hash_for_imported_users', 'member');
INSERT IGNORE INTO artist_details (id, member_id, slug, artistic_name, full_name, cell_phone, date_of_birth, country_of_birth, country_residence, city, address1, address2, postal_code, how_is_it_defined, profile_text2, profile_image, biography1, facebook, instagram, website, music_spotify_apple, youtube_channel, audio, video_banner_portrait, video_banner_landscape, link_to_video, link_to_video2, link_to_video3, link_to_video4, link_to_video5, link_to_video6, link_to_video7, link_to_video8, link_to_video9, link_to_video10, visao_geral_titulo, historia_titulo, carreira_titulo, mais_titulo, image1, image1_text, image2, image2_text, image3, image3_text, image4, image4_text, image5, image5_text, image6, image6_text, image7, image7_text, image8, image8_text, image9, image9_text, image10, image10_text, image11, image11_text, image12, image12_text, accepted_terms1, accepted_terms2, perfil_completo) VALUES ('92e511a7-e0f2-4be5-b4bb-bc2dfe0e7bbd', '27573b20-c33f-4178-b8f0-f701f9f32054', 'tessitori', 'Tessitori', 'Tessitori', '916417717', '2003-09-01', 'Portugal', 'Portugal', 'Santarém', 'Travessa 15 de Março', 'Travessa 15 de Março', '2000-128', 'Duo de Viola de Arco e Guitarra Clássica', '"Dois músicos de exceção que permitem à música e ao público respirar livremente" Classical Guitar Magazine', 'https://static.wixstatic.com/media/7b859e_30ddaadf129e484b9af430b5690e01f0~mv2.jpg', NULL, 'https://www.facebook.com/TESSITORIVIOLAGUITAR/', 'https://www.instagram.com/tessitorimusic/', 'https://www.tessitorimusic.com/', NULL, 'https://www.youtube.com/user/TESSITORIMUSIC/videos', 'https://static.wixstatic.com/mp3/27573b_c263dc38919443e68e4a9873d33b6aa8.mp3', NULL, NULL, 'https://youtu.be/xfPUbWaarW0?si=_7CnQg3Y4XZaxNz8', 'https://youtu.be/6Twn7WA_pdg?si=eZAU3s__VV6XoMFT', 'https://youtu.be/_7C59oXVr24?si=eQ8y7xcIrd2m_F9J', 'https://youtu.be/u33tGH8VE_M?si=WHoJVRzU7UhLptNg', 'https://youtu.be/VHK8KIRBOB4?si=WnDpzzvps-lEfjKa', 'https://youtu.be/tJbb94vOkl4?si=zqVvCy9YwjVaS7Af', 'https://youtu.be/YuT9cLHqdp0?si=JEemZRZdmq6vZns2', NULL, NULL, NULL, '<p class="font_8"><strong>TESSITORI&nbsp;</strong>é um duo de <strong>Violeta </strong>e <strong>Guitarra Clássica</strong> formado por dois músicos&nbsp; premiados a nível nacional e internacional. <strong>Isabel Pereira</strong> e <strong>João Loureiro</strong>&nbsp; conheceram-se enquanto estudantes na <strong>Royal Academy of Music</strong> – Londres onde&nbsp; criaram o duo Tessitori.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Cativados pela sonoridade única do ensemble começaram por explorar as&nbsp; possibilidades do repertório, criando os seus próprios arranjos de obras celebradas&nbsp; e intrerpretando obras originalmente escritas para esta instrumentação incluindo peças compostas por João Loureiro para o ensemble.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Desde a sua formação TESSITORI apresentou-se em concerto na <strong>National Portrait&nbsp; Gallery</strong> (de destacar dois concertos integrados na exposição “Picasso Portraits”em&nbsp; 2016), <strong>St. James’s, Picadilly </strong>(concerto integrado no Festival Echoes da ILAMS&nbsp; 2017), <strong>National Theatre</strong> – <strong>Southbank e Rosslyn Hill Chapel</strong>; em Portugal:&nbsp; <strong>Fundação Calouste Gulbenkian</strong>, <strong>Teatro Nacional de São Carlos</strong>, <strong>Festival Terras Sem Sombra</strong> em Albarracin, <strong>Convento de São Francisco</strong> – Santarém, <strong>Museu&nbsp; Abade Pedrosa</strong> – Santo Tirso entre outros.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">TESSITORI grava em 2014 o primeiro disco, do qual a crítica reconhece: <strong>“É evidente&nbsp; que estamos perante dois músicos de exceção, cuja filosofia, de oferecer à música&nbsp; e ao público a liberdade de respirar, é apresentada com convicção.”</strong> (in Classical&nbsp; Guitar Magazine) “Está gravado de forma vívida e apresentado de forma elegante”&nbsp; (in The Strad)</p>', '<p class="font_8"><strong>Isabel Pereira</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>Violetista </strong>galardoada a nível nacional e internacional que se destaca pela sua atividade orquestral como freelancer no Reino Unido e Portugal. Liderou as violas da Royal Liverpool Philharmonic, Bournemouth Symphony, Orquestra Sinfónica do Porto, Orquestra XXI, Orquestra Filarmónica Portuguesa e da Orquestra Sinfónica Portuguesa - Teatro Nacional de São Carlos da qual é membro. Colabora ainda com a Royal Opera House, Philharmonia, Royal Philharmonic Orchestra, London Sinfonietta, Remix Ensemble e trabalha com a London Philharmonic Orchestra, desde 2009. Participou em inúmeras digressões por todo o mundo e tocou nos principais festivais do mundo e todos os anos se apresenta nos Concertos Promenade BBC “Proms” no Royal Albert Hall em Londres e no Glyndebourne Opera Festival. Gravou dezenas de discos e bandas sonoras sendo as mais conhecidas: O Hobbit e Iron Man (Homem de Ferro). Em paralelo, colabora a solo e grupos de música de câmara. Participou nos festivais: "Brahms and Friends Festival", "Lionel Tertis Viola Festival" e "Berio Festival - Omaggio - SouthBank Centre/RAM". Neste último interpretou a Sequenza VI de Luciano Berio e do concerto a crítica comenta "Foi poético e tocado com imaginação vívida, Pereira moveu-se entre duros sons percussivos e uma voz cremosa de intensidade virtuosa" (in The Strad). Apresentou-se em recitais e concertos em Inglaterra, Portugal, Espanha, Japão, Itália e como solista com as Orquestras Gulbenkian e Artave. Vencedora do Prémio Jovens Músicos Antena 2 RDP em 2000, Isabel foi também bolseira da Fundação Calouste Gulbenkian, enquanto estudante na Royal Academy of Music – Londres, onde conclui a sua Licenciatura (First Class) e a Pós-Graduação (Distinction), ambas com qualificação máxima, recebe ainda um diploma de excelência (Dip-Ram) e o “Hilda Wyme Memorial Award”.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>João Loureiro</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Iniciou os seus estudos com os professores Silvestre Fonseca e Acácio Resende até ao ano de 1997 quando parte para Londres para estudar com a professora Shuko Shibata. A licenciatura em Música, é concluída no London College of Music and Media sob a orientação do professor Carlos Bonell, onde lhe foi atribuído o “British Reserve Strings Prize”. Continua os seus estudos na Royal Academy of Music onde em 2003 conclui a sua Pós-Graduação com Mérito. Enquanto solista João Loureiro fez recitais em Portugal, Holanda,Alemanha e Inglaterra. Foi o representante de Portugal no primeiro congresso “Unissono International” na Alemanha, onde realizou vários recitais e fez uma gravação em direto para a SDF Radio. Outras atividades incluem espetáculos de poesia música e dança com o grupo “A Phala”, e teatro musical, ópera e participações com orquestra tal como a BBC Philarmonic Orchestra. Em agosto de 2009, João apresentou-se com a Britten Sinfonia na estreia da ópera “Yellow Sofa” de Julian Phillips em Glyndebourne tendo voltado a ser solicitado para a temporada e digressão em 2012.A sua grande devoção à música de câmara levou-o o a criar alianças com os flautistas Vicki Tofts, Efrain Oscher e o guitarrista Steve Smith. Em 2007 lançou com o Uno Guitar Duo o seu primeiro disco que foi recebido e aclamado pela crítica. “Um álbum totalmente convincente de música maravilhosa, magnificamente interpretada.” (in Classical Guitar Magazine). Em 2014 lançou o seu segundo álbum desta vez com o duo TESSITORI. João promove presentemente o seu álbum de música original para guitarra solo intitulado “Familiar Faces”, este é inspirado nos heróis menos celebrados das nossas vidas, a família e os amigos.</p>', '<p class="font_8"><strong>TESSITORI nasceu em Inglaterra na Royal Academy of Music, Londres onde ambos os membros se conheceram e estudaram.</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Durante 13 anos, tendo como base a cidade de <strong>Londres</strong>, o ensemble apresentou-se em concertos na National Portrait&nbsp; Gallery (de destacar dois concertos integrados na exposição “Picasso Portraits”em&nbsp; 2016), St. James’s, Picadilly (concerto integrado no Festival Echoes da ILAMS&nbsp; 2017), National Theatre – Southbank, Jersey Academy of Music, Rosslyn Hill Chapel, St. Peter´s Church, St. Mary Le Bow, St. Edmund´sd Church, The Forge, St. Dunstan In ther West, Fundação Calouste Gulbenkian, Museu&nbsp; Abade Pedrosa – Santo Tirso, Teatro Sá da Bandeira e Convento de São Francisco - Santarém, Fábrica Braço de Prata - Lisboa, entre outros.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">TESSITORI grava em 2014 o primeiro disco, do qual a crítica reconhece:</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>“É evidente&nbsp; que estamos perante dois músicos de exceção, cuja filosofia, de oferecer à música&nbsp; e ao público a liberdade de respirar, é apresentada com convicção.”</strong> (in Classical&nbsp; Guitar Magazine)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8"><strong>“Está gravado de forma vívida e apresentado de forma elegante”</strong>&nbsp; (in The Strad)</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Em 2018, o duo passa a residir em <strong>Portugal </strong>onde tem vindo a apresentar-se em salas e festivais como: Teatro Nacional de São Carlos - Lisboa, Terras Sem Sombra - Espanha, Albarracin, Festival In. Santarém, Festival Onde A Vida Acontece - Cuba, Bienal Internacional de Cerâmica de Aveiro, Museu Diocesano de Santarém, Quinta da Regaleira - Sintra, Festival Internacional de Teatro para a Infancia e Juventude (FITIJ) - Santarém, O Convento ConVida - Setúbal, Sextas às Sete - Conservatório de Vila do Conde, Centro Cultural de Fazendas de Almeirim, entre outros.</p>
<p class="font_8">&nbsp;</p>
<p class="font_8">TESSITORI prepara neste momento a gravação do seu próximo álbum.</p>', '<p class="font_8"><strong>Para mais informações vistem:</strong></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Página</p>
<p class="font_8"><a href="https://www.tessitorimusic.com/" target="undefined"><u>tessitorimusic</u></a></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Canal de YouTube</p>
<p class="font_8"><a href="https://www.youtube.com/user/TESSITORIMUSIC/videos" target="undefined"><u>Tessitori Music - YouTube</u></a></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Página de Facebook</p>
<p class="font_8"><a href="https://www.facebook.com/TESSITORIVIOLAGUITAR/" target="undefined"><u>Facebook</u></a></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">Instagram</p>
<p class="font_8"><a href="https://www.instagram.com/tessitorimusic/" target="undefined"><u>Tessitori (@tessitorimusic) • fotos e vídeos do Instagram</u></a></p>
<p class="font_8">&nbsp;</p>
<p class="font_8">&nbsp;</p>', 'https://static.wixstatic.com/media/27573b_e99998c93ae44a998a61e19a4e357651~mv2.jpg', 'Bruno Simão© TNSC 2023', 'https://static.wixstatic.com/media/27573b_2caa71be84f24cb298f69644e2723b82~mv2.jpg', '© José Farinha 2022', 'https://static.wixstatic.com/media/27573b_5c8a926d6bf940928d935b3f5266163f~mv2.jpg', '©José Farinha 2015', 'https://static.wixstatic.com/media/27573b_4c9c8f4fd35b45238bae6c329dc7d340~mv2.jpg', '© José Farinha 2014', 'https://static.wixstatic.com/media/27573b_8af7d7ee478148e4985831edf6b26ee4~mv2.jpg', '© José Farinha 2014', 'https://static.wixstatic.com/media/27573b_1920c71687dd479aaf3137fbba726ef4~mv2.jpg', '© José Farinha 2022', 'https://static.wixstatic.com/media/27573b_1e155f869775420c8a691c2575a7cfcd~mv2.jpg', 'Bruno Simão© TNSC 2023', 'https://static.wixstatic.com/media/27573b_322900a8da8d4359bce519e3a4fc23fd~mv2.jpg', '© José Farinha 2015', 'https://static.wixstatic.com/media/27573b_ac97d1e934d64e8c9d4f428daa63ea47~mv2.jpg', '© José Farinha 2022', 'https://static.wixstatic.com/media/27573b_ac66bb77cad148a6b7ce38518d13859c~mv2.jpg', '© José Farinha 2015', 'https://static.wixstatic.com/media/27573b_e5bf1e02e6b845f4a40f88fbf86ffcab~mv2.jpg', 'Bruno Simão© TNSC 2023', 'https://static.wixstatic.com/media/27573b_eb86f1e61d274739abe01d9edcb10d7f~mv2.jpg', '© José Farinha 2022', 1, 0, 0);

